gameforge.collect_quest_lv30._60_say = "\191Puedes traerme unos cuantos dientes? Pero[ENTER]necesito dientes especiales. Tr\225eme una muela,[ENTER]pero solo una cada vez, para que pueda[ENTER]examinarla. \161Buena suerte! "
