gameforge.collect_quest_lv85._055_say_title = "Bi\243logo Chaegirab: "
gameforge.collect_quest_lv85._060_say = "Oh, \161aqu\237 est\225s otra vez! No puedo agradecerte lo[ENTER]suficiente que me ayudes de nuevo. Actualmente[ENTER]estoy trabajando en un libro sobre el Bosque[ENTER]Rojo. Por supuesto, deber\237a ir all\237 yo mismo,[ENTER]pero como ya sabes, no soy lo suficientemente[ENTER]fuerte. Tambi\233n necesito tiempo para leer y[ENTER]estudiar. Por favor, ay\250dame. \161Te dar\233 una[ENTER]recompensa muy generosa! "
gameforge.collect_quest_lv85._064_say = "Bi\243logo Chaegirab: "
gameforge.collect_quest_lv85._065_say = "Quiero averiguar m\225s sobre el Bosque Rojo. Sol\237a[ENTER]ser un bosque tranquilo con \225rboles enormes.[ENTER]Pero la influencia de las Piedras Metin lo ha[ENTER]contaminado con energ\237a negativa y se ha[ENTER]convertido en un lugar maldito lleno de esp\237ritus[ENTER]malvados. Para averiguar m\225s sobre este \225rea,[ENTER]necesito algunas Ramas de \193rbol Rojo Fantasma. "
gameforge.collect_quest_lv85._069_say = "Bi\243logo Chaegirab: "
gameforge.collect_quest_lv85._070_say = "\191Podr\237as conseguirme 40 de esas ramas? Aseg\250rate[ENTER]de que no son demasiado delgadas o est\233n rotas.[ENTER]S\243lo puedo usar ramas fuertes y sanas para mi[ENTER]investigaci\243n. Y tr\225emelas individualmente para[ENTER]que pueda comprobar cada una por separado. "
