gameforge.collect_quest_lv85._179_say = "Bi\243logo Chaegirab: "
gameforge.collect_quest_lv85._180_say = "Hm, esta rama es m\225s bien delgada y ligeramente[ENTER]curva. Me temo que no va a servir de mucho para[ENTER]mi investigaci\243n. \161Por favor cons\237gueme otra![ENTER][ENTER]Sin embargo, a\250n le echar\233 un vistazo m\225s[ENTER]profundo e intentar\233 hacer unos cuantos[ENTER]experimentos con ella. No podr\233 examinar la[ENTER]siguiente Rama de \193rbol Rojo Fantasma hasta[ENTER]ma\241ana. "
