gameforge.collect_quest_lv92._050_say_title = "Seon-Pyeong: "
gameforge.collect_quest_lv92._060_say = "\161Hola, valiente guerrero! Has llegado justo a[ENTER]tiempo. Estoy buscando un cierto tipo de gema[ENTER]para realizar mis investigaciones de armas.[ENTER]\191Podr\237as ayudarme a buscarlas?[ENTER]Algunas criaturas en la Gruta del Exilio poseen[ENTER]estas gemas. Pero, yo soy una persona muy[ENTER]importante como para arriesgar mi vida en un[ENTER]lugar tan peligroso como ese. "
gameforge.collect_quest_lv92._070_say = "De momento necesito las Joyas de la Envidia, unas[ENTER]piedras preciosas que s\243lo pueden ser encontradas[ENTER]en las profundidades de esta monta\241a. Se trata de[ENTER]unos diamantes especiales que por largo tiempo[ENTER]han estado expuestos a la poderosa influencia del[ENTER]Dios Malvado Beran-Setaou, y que han absorbido[ENTER]una peque\241a parte del su energ\237a. Necesito 10[ENTER]ejemplares perfectos.[ENTER]\161Mucha suerte y hasta pronto! "
gameforge.collect_quest_lv92._080_say_title = "Joyas para Seon-Pyeong "
gameforge.collect_quest_lv92._090_say = "El herrero e investigador Seon-Pyeong necesita 10[ENTER]Joyas de la Envidia para su investigaci\243n sobre[ENTER]armas. Tr\225elas una tras otra para que las pueda[ENTER]examinar meticulosamente.[ENTER]Puedes obtenerlas de los Hombres de Hielo[ENTER]Infernal y de los Golems de Hielo Infernal. "
