gameforge.collect_quest_lv92._145_npcChat = "Joya de la sabidur\237a (94) "
gameforge.collect_quest_lv92._150_say = "\191T\250, aqu\237? Lo siento, pero a\250n no he podido[ENTER]terminar la investigaci\243n del \250ltimo ejemplar.[ENTER]\161Regresa m\225s tarde! "
gameforge.collect_quest_lv92._160_say = "\191A\250n no has podido encontrar nada? Lo lamento[ENTER]mucho. \191Pero qu\233 est\225s haciendo todav\237a aqu\237?[ENTER]\161Vamos, apres\250rate! \161Regresa cuando hayas[ENTER]encontrado joyas! "
