gameforge.collect_quest_lv94._060_say = "\161Hola! \191O sea que recibiste mi carta?[ENTER]Entonces, ya sabr\225s que necesito ayuda para la[ENTER]investigaci\243n sobre las armas.[ENTER]Desde el redescubrimiento de la Gruta del Exilio[ENTER]han salido a la luz muchos detalles. He llegado a[ENTER]saber que las criaturas que habitan en esa[ENTER]monta\241a son capaces de extraer otro tipo de joyas[ENTER]de las piedras. "
gameforge.collect_quest_lv94._070_say = "Se trata de las Joyas de la Sabidur\237a. Se dice[ENTER]que son unos diamantes claros y puros donde yace[ENTER]la esencia de la reina asesinada Bahar-Taraji.[ENTER]\161Cuando est\233s en la gruta, abre bien los ojos y[ENTER]b\250scalas![ENTER]Necesito 20 ejemplares intactos.[ENTER]\161Te deseo mucha suerte y no me dejes esperar[ENTER]tanto! "
gameforge.collect_quest_lv94._080_say_title = "Joyas para Seon-Pyeong "
gameforge.collect_quest_lv94._090_say = "El herrero de armas y el investigador Seon-Pyeong[ENTER]necesitan 20 Joyas de la Sabidur\237a para su[ENTER]investigaci\243n sobre armas. Tr\225elas una tras otra[ENTER]para que \233l las pueda examinar meticulosamente.[ENTER]Puedes obtenerlas de los Arqueros Setaou y de los[ENTER]Comandantes Setaou. "
gameforge.collect_quest_lv94._100_sayReward = "Has entregado %s joyas hasta ahora. "
gameforge.collect_quest_lv94._110_say = "No puedes utilizar todav\237a el Elixir del[ENTER]Investigador. "
gameforge.collect_quest_lv94._120_say = "\161Ya utilizaste un elixir! "
gameforge.collect_quest_lv94._130_say = "Puedes utilizar el elixir en cuanto hayas[ENTER]encontrado una joya. "
gameforge.collect_quest_lv94._140_send_letter = "Has encontrado una joya "
gameforge.collect_quest_lv94._150_npcChat = "Joya de la sabidur\237a (94) "
gameforge.collect_quest_lv94._160_say = "\191T\250, otra vez? Lo siento, pero a\250n no he podido[ENTER]terminar la investigaci\243n del \250ltimo ejemplar.[ENTER]\161Regresa m\225s tarde! "
gameforge.collect_quest_lv94._170_say = "\191A\250n no has podido encontrar nada? Lo lamento[ENTER]mucho. \191Pero qu\233 est\225s haciendo todav\237a aqu\237?[ENTER]\161Vamos, apres\250rate! \161Regresa cuando hayas[ENTER]encontrado joyas! "
gameforge.collect_quest_lv94._180_say = "\191Has logrado encontrar una Joya? \161Fant\225stico![ENTER]Espera un momento, primero tengo que[ENTER]cerciorarme... "
gameforge.collect_quest_lv94._190_say = "Oh, una joya preciosisima. \191Puedes sentir un[ENTER]calor leve en tu coraz\243n? \191Una sensaci\243n de paz?[ENTER]Es el efecto de esta joya....[ENTER]\161Te agradezco mucho! "
gameforge.collect_quest_lv94._200_say = "Como ya sabes, necesito otros %s ejemplares de la[ENTER]misma calidad. Dame un d\237a para examinar \233sta.[ENTER]a fondo. Cuando termine, podr\225s traerme los[ENTER]pr\243ximos ejemplares. "
gameforge.collect_quest_lv94._210_say = "\161Mucho \233xito! "
gameforge.collect_quest_lv94._230_1_select = "HP +1100 "
gameforge.collect_quest_lv94._230_2_select = "Defensa + 140 "
gameforge.collect_quest_lv94._230_3_select = "Ataque +60 "
gameforge.collect_quest_lv94._240_say = "Hmm... sin duda, un hermoso diamante. Pero al[ENTER]parecer no posee un aura divina. Temo que esto no[ENTER]me ayuda en nada. \161Tr\225eme otra, por favor! Y[ENTER]recuerda que necesitar\233 un poco de tiempo para[ENTER]analizar a fondo la que me acabas de traer. "
gameforge.collect_quest_lv94._250_say = "\161Excelente, lograste conseguir 20 Joyas de la[ENTER]Sabidur\237a! \161Me has impresionado! Lastimosamente,[ENTER]esto no es suficiente. Para poder descifrar todo[ENTER]el contenido del poder de estos diamantes,[ENTER]necesito todav\237a la Piedra Alma, es decir, la[ENTER]Piedra Alma del Drag\243n Beran-Setaou, el Amo de la[ENTER]Gruta. "
gameforge.collect_quest_lv94._260_send_letter = "Petici\243n de Seon-Pyeong "
gameforge.collect_quest_lv94._270_say_title = "La Piedra Alma del Drag\243n "
gameforge.collect_quest_lv94._280_say = "Has logrado apoderarte de la Piedra Alma.[ENTER]Ll\233vasela a Seon-Pyeong, quien se encuentra en la[ENTER]entrada de la Gruta del Exilio. "
gameforge.collect_quest_lv94._290_say_title = "La Piedra Alma del Drag\243n "
gameforge.collect_quest_lv94._300_say = "Has logrado llevarle a Seon-Pyeong 20 Joyas de la[ENTER]Sabidur\237a al Valle de Seungryong. \161Ahora s\243lo le[ENTER]falta la Piedra Alma del Drag\243n! "
gameforge.collect_quest_lv94._310_say = "La obtienes de Beran-Setaou. "
gameforge.collect_quest_lv94._320_send_letter = "Obtener la Piedra del Drag\243n. "
gameforge.collect_quest_lv94._330_npcChat = "\161He obtenido la Piedra del Drag\243n! "
gameforge.collect_quest_lv94._340_say = "Incre\237ble, \161has obtenido la Piedra Alma del[ENTER]Drag\243n! Es para quitarse el sombrero. Ahora podr\233[ENTER]continuar con mis investigaciones. y t\250 obtendr\225s[ENTER]una muy buena recompensa. \161Escoge! "
gameforge.collect_quest_lv94._350_say = "\191Conseguiste la Piedra Alma? \191Yo no veo nada? No[ENTER]intentes darme gato por liebre...[ENTER]S\233 que la misi\243n que te ped\237 es complicada, pero[ENTER]yo estoy seguro de que lo puedes lograr. "
gameforge.couple_ring = {}
gameforge.couple_ring._100_sendLetter = "Derrota a Jin-Hee "
gameforge.couple_ring._10_npcChat = "Venganza del comerciante de anillos "
gameforge.couple_ring._110_sayReward = "La anciana te ha pedido ayuda: Jin-Hee, la \233lite[ENTER]del Juramento Blanco ha acabado con la vida de su[ENTER]amigo, el comerciante de anillos. Venga la muerte[ENTER]del comerciante de anillos eliminando a 30[ENTER]Jin-Hee. "
gameforge.couple_ring._120_sayReward = "N\250mero de Jin-Hees restantes "
gameforge.couple_ring._130_say = "Oh, \191veo que has luchado contra las Jin-Hee?[ENTER]Y obviamente no pudiste derrotarlas a todas.[ENTER]Conozco su fuerza y habilidades. No es un trabajo[ENTER]f\225cil.  "
gameforge.couple_ring._140_say = "\161La familia del comerciante de anillos quiere[ENTER]venganza por su muerte! Si puedes aliviar su[ENTER]dolor con un peque\241o esfuerzo, por favor hazlo. "
gameforge.couple_ring._150_say = "Muy mal que no quieres vengar la muerte del[ENTER]comerciante de anillos. Hmm, por supuesto tu[ENTER]valoras tu propia vida. Digas lo que digas. Cada[ENTER]vida tiene su valor. "
gameforge.couple_ring._160_say = "Puedes ver algo en las manos de la anciana cuando[ENTER]se da la vuelta. Era un objeto brillante.[ENTER](Parec\237a una piedra valiosa). "
gameforge.couple_ring._170_select = "Lo intentar\233 otra vez. "
gameforge.couple_ring._180_say = "No estoy interesado en piedras valiosas. Quiero[ENTER]que la muerte del comerciante de anillos sea[ENTER]vengada, por su familia. Est\225 bien que lo hayas[ENTER]reconsiderado y quieras completar la misi\243n. "
gameforge.couple_ring._190_say = "Lo siento por la familia del comerciante de[ENTER]anillos. Muy mal que no quieras aceptar el reto. "
gameforge.couple_ring._200_sendLetter = "Volver con la anciana. "
gameforge.couple_ring._20_sayTitle = "Anciana "
gameforge.couple_ring._210_say = "Vuelve con la anciana y dile que has vengado la[ENTER]muerte del comerciante de anillos matando a las[ENTER]Jin-Hees. "
gameforge.couple_ring._220_npcChat = "\161Has eliminado a las 30 Jin-Hees! "
gameforge.couple_ring._230_say = "Has derrotado a todas las Jin-Hees. \161Bien hecho![ENTER]El comerciante de anillos debe estar satisfecho[ENTER]desde el cielo. Este es el anillo que me confi\243.[ENTER]Debe ser tuyo. Esta es tu recompensa por vengar[ENTER]su muerte. Estoy segura que \233l querr\237a que fuese[ENTER]as\237. "
gameforge.couple_ring._240_sayReward = "Has recibido un anillo de pareja. "
gameforge.couple_ring._250_sayItem = "Anillo de Compromiso "
gameforge.couple_ring._255_sayItem = "Este anillo simboliza una boda inminente. "
gameforge.couple_ring._30_say = "Ahora eres uno de los guerreros de la aldea.[ENTER]Si s\243lo supiera c\243mo puedes usar tus nuevas[ENTER]habilidades descubiertas. \191Has oido hablar alguna[ENTER]vez de las Jin-Hee? Son un grupo de guerreras de[ENTER]\233lite muy peligroso.[ENTER]Una de ellas mat\243 al mercader de anillos de[ENTER]nuestra aldea. El mercader no s\243lo era un buen[ENTER]amigo m\237o, sino tambi\233n un hombre justo que[ENTER]vend\237a joyer\237a a parejas j\243venes con intenci\243n de[ENTER]casarse. \191Est\225s preparado para vengar su muerte?[ENTER]Para hacerlo tienes que matar a las 30 Jin-Hee... "
gameforge.couple_ring._40_select = "Vengar\233 la muerte del comerciante de anillos "
gameforge.couple_ring._50_select = "No, las Jin-Hees son demasiado fuertes. "
gameforge.couple_ring._60_say = "\161Esa es una decisi\243n muy sabia y honorable! Pero[ENTER]recuerda - tienes que matar 30 Jin-Hee. Aunque[ENTER]ten cuidado, \161son muy astutas y expertas[ENTER]escondi\233ndose! "
gameforge.couple_ring._70_say = "Bueno, esa es una decisi\243n lamentable, pero es[ENTER]cosa tuya. Despu\233s de todo, el exceso de[ENTER]confianza puede ser letal.[ENTER]\161Cu\237date! "
gameforge.couple_ring._75_say = "N\250mero de Jin-Hees restantes "
gameforge.couple_ring._80_sayTitle = "Has derrotado a todas las Jin-Hees "
gameforge.couple_ring._90_say = "Ahora la muerte del comerciante ha sido vengada.[ENTER]Por lo tanto, la misi\243n ha sido completada. "
