gameforge.dragon_soul = {}
gameforge.dragon_soul._010_sayTitle = "\191\161Fragmento de piedra drag\243n!? "
gameforge.dragon_soul._020_say = "En tu mano sujetas el fragmento de una piedra.[ENTER]Reluce misteriosamente y sientes su poder[ENTER]recorrer tu cuerpo.[ENTER]\191Qu\233 tipo de piedra es esta? Ll\233vasela al[ENTER]alquimista. \201l te podr\225 ayudar. "
gameforge.dragon_soul._030_npcChat = "\191\161Fragmento de piedra drag\243n!? "
gameforge.dragon_soul._040_say = "Este es el fragmento de una Piedra drag\243n, un[ENTER]cristal extraordinario y valioso con un gran[ENTER]poder. Se cuenta que es el alma de un drag\243n.[ENTER]\161Precioso![ENTER]\191Sientes su poder recorrer tu cuerpo cuando lo[ENTER]llevas contigo?[ENTER]Tr\225eme diez Fragmentos de Piedra drag\243n en total.[ENTER]Yo te los convertir\233 en una Piedra completa. "
gameforge.dragon_soul._050_npcChat = "Transmutaci\243n de Piedra drag\243n "
gameforge.dragon_soul._060_say = "Paciencia. Para crear una Piedra drag\243n necesito[ENTER]10 fragmentos.[ENTER]\161Sigue buscando! "
gameforge.dragon_soul._070_say = "\161Ah, muy bien! Has encontrado diez Fragmentos de[ENTER]Piedra drag\243n. Espera un momento.[ENTER]...[ENTER]\161Ya est\225! Asombroso... durante el proceso se ha[ENTER]creado un Cor Draconis, un coraz\243n cristalino de[ENTER]drag\243n que rodea y protege la Piedra drag\243n.[ENTER]Para descubrir qu\233 Piedra drag\243n contiene tendr\225s[ENTER]que romperlo. Esta aparecer\225 directamente en el[ENTER]inventarios de la alquimia de las Piedras drag\243n.[ENTER]\191Sab\237as que las Piedras drag\243n se pueden seguir[ENTER]refinando? "
gameforge.dragon_soul._080_say = "\191Quieres otro Cor Draconis?[ENTER]Buf, ya no tengo edad para estas cosas. La[ENTER]creaci\243n de un objeto tan complejo acaba con mis[ENTER]fuerzas.[ENTER]Pero por ti lo intentar\233.[ENTER]Ahora s\237: por mucho que quiera, no puedo hacer[ENTER]m\225s de diez al d\237a. "
gameforge.dragon_soul._090_say = "Ya basta por hoy. M\225s de diez Cor Draconis por[ENTER]d\237a, no puedo.[ENTER]No me quedan fuerzas y tengo que recuperarme.[ENTER]Vuelve ma\241ana. "
gameforge.dragon_soul._100_npcChat = "Abrir tienda "
gameforge.dragon_soul._1010_sendLetter = "La llegada del Fragmento de piedra drag\243n "
gameforge.dragon_soul._1020_say = "El alquimista con los conocimientos m\225s extensos[ENTER]sobre minerales de todo el reino te est\225[ENTER]buscando.[ENTER]\161Ve a verle en seguida! "
gameforge.dragon_soul._1030_npcChat = "\191\161Fragmento de piedra drag\243n!? "
gameforge.dragon_soul._1040_say = "\161Ah, aqu\237 est\225s! He descubierto algo incre\237ble:[ENTER]\161el Fragmento de una piedra drag\243n! Una Piedra[ENTER]drag\243n es un cristal extraordinario y muy valioso[ENTER]de gran poder. Se dice que es el alma de un[ENTER]drag\243n. \161Es impresionante![ENTER]Te voy a otorgar el Poder del ojo de drag\243n para[ENTER]que puedas sentir los Fragmentos de piedra[ENTER]drag\243n.[ENTER]Puedes transmutarlos en una piedra completa. "
gameforge.dragon_soul._1050_sendLetter = "Reunir Fragmentos de piedra drag\243n "
gameforge.dragon_soul._1060_say = "Ll\233vale al alquimista 10 Fragmentos de piedra[ENTER]drag\243n. "
gameforge.dragon_soul._1070_say = "\161Ah, muy bien! Has encontrado diez Fragmentos de[ENTER]piedra drag\243n. Espera un segundo.[ENTER]...[ENTER]\161Asombroso! De la transmutaci\243n ha resultado un[ENTER]Cor Draconis. Se trata de un coraz\243n cristalizado[ENTER]de drag\243n que protege la Piedra drag\243n.[ENTER]Si lo rompes, la Piedra drag\243n que contiene ir\225[ENTER]directamente a tu inventario de la alquimia de[ENTER]Piedras drag\243n.[ENTER]Para encontrar Fragmentos de piedra drag\243n[ENTER]necesitar\225s el Poder del ojo de drag\243n.[ENTER]Te lo puedo otorgar; simplemente ven a verme cada[ENTER]d\237a.[ENTER]\161Entonces t\250 tambi\233n podr\225s transmutar Piedras[ENTER]drag\243n! Hoy ya te he fabricado una, las %d[ENTER]restantes tendr\225s que conseguirlas por tu cuenta. "
gameforge.dragon_soul._1080_say = "\161Hey, no pierdas el tiempo! \161Mejor sal a buscar[ENTER]Fragmentos de piedra drag\243n! "
gameforge.dragon_soul._1090_sendLetter = "Poder del ojo de drag\243n "
gameforge.dragon_soul._1100_say = "Poder del ojo de drag\243n restante: %d "
gameforge.dragon_soul._110_say = "Escoge. "
gameforge.dragon_soul._1110_notice = "Es gibt keine Drachensteinsplitter mehr "
gameforge.dragon_soul._1120_npcChat = "Dame el Poder del ojo de drag\243n "
gameforge.dragon_soul._1130_say = "\161Hola! Hoy ya has recibido el Poder del ojo de[ENTER]drag\243n. El proceso me resulta demasiado agotador,[ENTER]as\237 que solo te puedo ayudar una vez por d\237a.[ENTER]\161Vuelve ma\241ana por aqu\237! "
gameforge.dragon_soul._1140_say = "\161Hola! Apuesto a que vienes a verme por el Poder[ENTER]del ojo de drag\243n. \191Me equivoco? Muy bien, aqu\237[ENTER]lo tienes. \161Suerte con tu b\250squeda! Espero que[ENTER]encuentres suficientes Fragmentos de piedra[ENTER]drag\243n. "
