gameforge.energy_system = {}
gameforge.energy_system._001_npcChat = "\161Una t\233cnica nueva! "
gameforge.energy_system._010_say = "\161Lo he conseguido![ENTER]Por fin he podido desarrollar una t\233cnica[ENTER]totalmente nueva.[ENTER]He logrado procesar objetos para extraer energ\237a[ENTER]pura de ellos.[ENTER]\161Una cosa brillante! "
gameforge.energy_system._020_say = "Si se destruye un objeto con ayuda de mi t\233cnica,[ENTER]se reciben fragmentos de energ\237a.[ENTER]Si se unen 30 de estos fragmentos, se obtiene un[ENTER]potente Cristal de Energ\237a. Energ\237a pura sin[ENTER]filtrar unida en una Gema. Este poder se filtra[ENTER]en todo tu equipamiento.[ENTER]\191Te interesa? "
gameforge.energy_system._030_say = "Tr\225eme objetos de equipamiento, como armas, joyas[ENTER]y ropa, que encuentres en tus viajes. Yo los[ENTER]convertir\233 en fragmentos de energ\237a. El futuro y[ENTER]la esperanza de nuestro reino dependen de esta[ENTER]t\233cnica.[ENTER]\161Seremos invencibles! "
gameforge.energy_system._035_npcChat = "Extraer fragmentos de energ\237a "
gameforge.energy_system._040_say = "\191Ha funcionado? \191Has obtenido fragmentos de[ENTER]energ\237a?[ENTER]Tr\225eme m\225s objetos y yo los descompondr\233 con[ENTER]ayuda de la alquimia. Mi t\233cnica todav\237a no est\225[ENTER]perfeccionada del todo, as\237 que no te puedo decir[ENTER]seguro cu\225ntos fragmentos recibir\225s. "
gameforge.energy_system._050_say = "S\243lo hay una condici\243n: Tanto tu nivel como el[ENTER]del objeto tiene que ser al menos de 35.[ENTER]Bueno, ya veremos... "
gameforge.energy_system._060_say = "\161Todav\237a no eres lo suficientemente fuerte![ENTER]Vuelve cuando hayas alcanzado el nivel 35. "
gameforge.energy_system._070_say = "\161Ah, excelente! Ya eres fuerte y tienes[ENTER]experiencia. Dame el objeto que quieres que[ENTER]trate. "
gameforge.energy_system._080_say = "Todav\237a no eres suficientemente fuerte como para[ENTER]dominar la energ\237a de los fragmentos.[ENTER]Vuelve cuando hayas alcanzado como m\237nimo el[ENTER]nivel 35. "
gameforge.energy_system._090_say = "Este objeto no es compatible con mi t\233cnica.[ENTER]Tr\225eme otra cosa. "
gameforge.energy_system._100_say = "Este objeto no tiene suficiente energ\237a.[ENTER]Tr\225eme uno de nivel 35 como m\237nimo: s\243lo as\237 mi[ENTER]t\233cnica podr\225 extraer su energ\237a. "
gameforge.energy_system._110_say = "\191Quieres que destruya este objeto? "
gameforge.energy_system._120_select = "S\237 "
gameforge.energy_system._130_select = "\161No, todav\237a no! "
gameforge.energy_system._140_say = "He fracasado. Lamentablemente no he podido[ENTER]extraer ning\250n fragmento de energ\237a. Quiz\225s lo[ENTER]logre la pr\243xima vez. "
gameforge.energy_system._150_say = "\161Excelente! He encontrado %d fragmentos de[ENTER]energ\237a. Aqu\237 tienes. "
gameforge.energy_system._160_npcChat = "Crear Cristal de Energ\237a. "
gameforge.energy_system._170_say = "\191Acaso ya has agotado tus reservas de energ\237a? No[ENTER]deber\237as trabajar tan duramente y poner tu vida[ENTER]en riesgo tan a la ligera.[ENTER]Para crear tu Cristal de Energ\237a necesito %d[ENTER]fragmentos de energ\237a. "
gameforge.energy_system._180_say = "Todav\237a no tienes suficientes fragmentos de[ENTER]energ\237a. Con esto no puedo fabricar ning\250n[ENTER]Cristal de Energ\237a.[ENTER]Vuelve cuando hayas reunido al menos %d[ENTER]fragmentos de energ\237a. "
gameforge.energy_system._190_say = "Muy bien, ya tienes los %d fragmentos de energ\237a[ENTER]que necesitaba. Con ellos podr\233 hacer un Cristal[ENTER]de Energ\237a.[ENTER]Espera un segundo. Voy a intentarlo, pero no[ENTER]puedo asegurarte que funcione. "
gameforge.energy_system._200_say = "Todo est\225 listo para unir los fragmentos en un[ENTER]Cristal de Energ\237a.[ENTER]Pero de algo tendr\233 que vivir, \191no? Y mis[ENTER]herramientas no caen del cielo sin m\225s.[ENTER]S\243lo piedo una contribuci\243n por gastos de %d[ENTER]Yang. \191Quieres pagar? "
gameforge.energy_system._210_select = "Faltar\237a m\225s. "
gameforge.energy_system._220_select = "No, a\250n no. "
gameforge.energy_system._230_say = "Est\225 bien, respetar\233 tu decisi\243n.[ENTER]Vuelve cuando hayas cambiado de opini\243n y[ENTER]necesites un Cristal de Energ\237a. "
gameforge.energy_system._240_say = "Lo siento, pero primero tienes que pagar. No soy[ENTER]de ninguna asociaci\243n de caridad.[ENTER]As\237 son los negocios: dame el dinero y luego yo[ENTER]me encargar\233 del trabajo. "
gameforge.energy_system._250_say = "Aqu\237 tienes tu Cristal de Energ\237a. Sin embargo,[ENTER]s\243lo el primer intento es siempre exitoso. La[ENTER]alquimia es una ciencia imprevisible: \161unas pocas[ENTER]diferencias pueden llevar al fracaso! Siempre hay[ENTER]un peque\241o riesgo de que el experimento no salga[ENTER]bien. "
gameforge.energy_system._260_say = "Me temo que el intento ha fallado. No he podido[ENTER]crear un Cristal de Energ\237a. Mi t\233cnica es[ENTER]brillante, pero su ejecuci\243n est\225 llena de[ENTER]riesgos. No siempre sale todo seg\250n lo planeado.[ENTER]\161Seguro que la pr\243xima vez sale mejor! "
gameforge.energy_system._270_say = "\161Lo sab\237a! \161Mi t\233cnica es brillante![ENTER]Aqu\237 tienes tu Cristal de Energ\237a.[ENTER]\161Una maravilla! \191Sientes la energ\237a? "
