gameforge.event_halloween_hair = {}
gameforge.event_halloween_hair._100_say = "Con esta Varita M\225gica puedes transformar una[ENTER]Calabaza de Halloween en un Cofre de Halloween.[ENTER]Las calabazas las dejan caer los monstruos y la[ENTER]Varita M\225gica la he escondido detr\225s de la moneda[ENTER]que da vueltas para que nadie me la robe.[ENTER]\161Int\233ntalo! "
gameforge.event_halloween_hair._10_npcChat = "\161Hey, cabeza de calabaza! "
gameforge.event_halloween_hair._110_say = "Tu Careta de calabaza puede tener una duraci\243n de[ENTER]6 horas, 1 d\237a o 7 d\237as. \161Pero eso se decide al[ENTER]azar! "
gameforge.event_halloween_hair._120_say = "Ah\237 la tienes. Los atributos de tu Careta de[ENTER]calabaza se deciden al azar. Cada careta es[ENTER]diferente. Sencillamente pru\233batela. \161Feliz[ENTER]Halloween! "
gameforge.event_halloween_hair._130_say = "\191Quieres cambiar ahora tu Tarjeta de careta de[ENTER]calabaza por una Careta de calabaza? "
gameforge.event_halloween_hair._140_select_1 = "S\237 "
gameforge.event_halloween_hair._140_select_2 = "No "
gameforge.event_halloween_hair._20_sayTitle = "Jack Calabaza "
gameforge.event_halloween_hair._30_say = "\191D\243nde estoy? \191Y qui\233n eres t\250? "
gameforge.event_halloween_hair._40_say = "\161Ten cuidado con lo que dices! \161No soy un cabeza[ENTER]de calabaza! Mi nombre es Jack Calabaza, y este[ENTER]es solamente mi disfraz. Estoy algo confuso, pues[ENTER]hace un momento estaba en una fiesta de[ENTER]Halloween, y de repente todo comenz\243 a girar a mi[ENTER]alrededor. Y ahora estoy aqu\237... "
gameforge.event_halloween_hair._50_say = "\161Y ahora, d\233jame celebrar Halloween en paz! "
gameforge.event_halloween_hair._60_npcChat = "Canjear Tarjeta de careta de calabaza "
gameforge.event_halloween_hair._70_say = "\161Otra vez t\250! \191Te cuento un secreto? Con un poco[ENTER]de suerte, en el Cofre de Halloween puedes[ENTER]encontrar una Tarjeta de careta de calabaza. "
gameforge.event_halloween_hair._80_say = "Con esta tarjeta puedes conseguir una terror\237fica[ENTER]Careta de calabaza. \191No te apetece tener una[ENTER]careta? "
gameforge.event_halloween_hair._90_say = "\191No tienes ninguna Tarjeta de careta de calabaza?[ENTER]\161Entonces no te llevar\225s ninguna careta! \161Ja, ja! "
gameforge.event_ramadan = {}
gameforge.event_ramadan._010_npcChat = "Historiador: "
gameforge.event_ramadan._020_sayTitle = "Historiador: "
gameforge.event_ramadan._030_say = "\161Aprende del pasado y abraza el futuro! \191En qu\233[ENTER]te puedo ayudar? "
gameforge.event_ramadan._040_say = "Perdona, \191nos conocemos? "
gameforge.event_ramadan._050_say = "Vaya, he olvidado presentarme. Soy uno de los[ENTER]historiadores. Hemos visto mucho mundo, as\237 que[ENTER]si tienes preguntas sobre la historia, no dudes[ENTER]en venir a verme. "
gameforge.event_ramadan._060_say = "Es un honor conocerte. Vendr\233 a visitarte de vez[ENTER]en cuando. "
gameforge.event_ramadan._070_npcChat = "Was S\252\223es "
gameforge.event_ramadan._100_say = "Qu\233 pena, hasta la pr\243xima. "
gameforge.event_ramadan._110_say = "Entonces ya sabes lo que quiero. Tr\225eme Pan y[ENTER]tendr\225s tus Dulces. "
gameforge.event_ramadan._120_say = "Te dar\233 unos Dulces por cada 10 unidades de Pan.[ENTER]\191Te parece bien? "
gameforge.event_ramadan._130_select_1 = "De acuerdo "
gameforge.event_ramadan._130_select_2 = "No hay tiempo "
gameforge.event_ramadan._140_say = "Te dar\233 unos Dulces cada vez que me traigas 10[ENTER]unidades de Pan. "
gameforge.event_ramadan._150_say = "No tienes suficiente Pan, con esto no tengo ni[ENTER]para empezar. "
gameforge.event_ramadan._160_say = "Muy bien, has tra\237do suficiente Pan; aqu\237 tienes[ENTER]tus Dulces. "
gameforge.event_ramadan._170_say = "Si me traes m\225s, te dar\233 m\225s. "
gameforge.event_ramadan._180_npcChat = "Pan delicioso "
gameforge.event_ramadan._180_say = "Ya he comido suficiente Pan del que me has tra\237do. "
gameforge.event_ramadan._190_say = "Aqu\237 hay varios ciudadanos que ayunan. A lo mejor[ENTER]podr\237as traerles alg\250n alimento para el ayuno. "
gameforge.event_ramadan._200_say = "Podr\237as mostrarles tu amabilidad y traerles algo[ENTER]de Pan en un Plato de ofrenda. "
gameforge.event_ramadan._210_say = "\161Gracias por este Pan tan delicioso! Seguro que[ENTER]tu sabidur\237a y misericordia ser\225n recompensadas. "
gameforge.event_ramadan._220_npcChat = "Qu\233 hambre... "
gameforge.event_ramadan._230_sayTitle = "Ciudadano en ayuno: "
gameforge.event_ramadan._240_say = "Tengo mucha hambre. Ten compasi\243n, dame algo para[ENTER]romper el ayuno. Por favor, tr\225eme Alimento para[ENTER]la ofrenda antes de que me muera de hambre. "
gameforge.event_ramadan._250_say = "Qu\233 bien huele el Pan. \191Me lo das? Te lo[ENTER]agradecer\237a mucho. "
gameforge.event_ramadan._260_select_1 = "S\237, aqu\237 tienes "
gameforge.event_ramadan._260_select_2 = "No, me lo quedo "
gameforge.event_ramadan._270_say = "Te pueden la codicia y la crueldad. Si cambias de[ENTER]opini\243n, ya sabes d\243nde encontrarme. "
gameforge.event_ramadan._280_say = "Much\237simas gracias. Tu coraz\243n est\225 lleno de[ENTER]sabidur\237a y misericordia.[ENTER]Seguro que este acto de compasi\243n se ver\225[ENTER]recompensado alg\250n d\237a. "
gameforge.event_ramadan._290_npcChat = "El Fruto de la bendici\243n "
gameforge.event_ramadan._300_say = "Durante mis viajes o\237 hablar sobre el \"Fruto de[ENTER]la bendici\243n\", que recompensa a aquellos que[ENTER]regresan a la misma hora de forma diligente. "
gameforge.event_ramadan._310_say = "Hoy ya nos hemos visto y ya se te ha recompensado.No lo olvides: solo aquel que demuestra ser[ENTER]paciente consigue aquello que busca. "
gameforge.event_ramadan._320_npcChat = "La suerte del que persevera "
gameforge.event_ramadan._330_say = "Te estaba esperando. Ya he terminado aqu\237,[ENTER]regreso al mundo en busca de nuevos sucesos e[ENTER]historias que investigar. "
gameforge.event_ramadan._340_say = "Me has guardado %d Frutos de la bendici\243n. "
gameforge.event_ramadan._350_say = "\191Me los dar\237as para el largo viaje? Seguro que no[ENTER]te hacen falta. "
gameforge.event_ramadan._360_select_1 = "Aqu\237 tienes "
gameforge.event_ramadan._360_select_2 = "No "
gameforge.event_ramadan._370_say = "Pi\233nsatelo bien... todav\237a estar\233 un rato por[ENTER]aqu\237. "
gameforge.event_ramadan._380_say = "\161Gracias por tu dedicaci\243n y por tu generosidad! "
gameforge.event_ramadan._390_sayReward = "Sello del caballo negro "
gameforge.event_ramadan._400_say = "\191Tienes menos de 5? Vaya, me hacen falta m\225s. A[ENTER]lo mejor la pr\243xima vez traes suficientes. "
gameforge.event_ramadan._80_say = "\191Entiendes de dulces? Esto se llama baklava. "
gameforge.event_ramadan._90_select_1 = "S\237, lo conozco. "
gameforge.event_ramadan._90_select_2 = "No, lo siento. "
gameforge.find_brother_article = {}
gameforge.find_brother_article._100_select = "Declinar "
gameforge.find_brother_article._10_npcChat = "\191Por qu\233 lloras? "
gameforge.find_brother_article._110_say = "Claro que te ayudar\233. La misi\243n no es dif\237cil de[ENTER]completar y puedo entender que quieras tener de[ENTER]vuelta el recuerdo. \161Hasta pronto! "
gameforge.find_brother_article._120_say = "Tengo cosas m\225s importantes que hacer, \191por qu\233[ENTER]deber\237a ayudar nada menos que a una hu\233rfana? "
gameforge.find_brother_article._130_sendLetter = "Consigue el Uniforme Negro "
gameforge.find_brother_article._140_sayReward = "El hermano de Mirine est\225 muerto y los Man\237acos[ENTER]Viento Negro han robado el \250nico recuerdo que[ENTER]ten\237a de \233l. Elimina a los Man\237acos Viento Negro[ENTER]hasta que encuentres el Uniforme Negro del[ENTER]hermano de Minine. "
gameforge.find_brother_article._150_npcChat = "A causa del uniforme de tu hermano... "
gameforge.find_brother_article._160_say = "\191Quieres desistir de la b\250squeda? No te he pedido[ENTER]mucho. Me gustar\237a tener nuevamente alg\250n[ENTER]recuerdo de mi hermano.[ENTER]\161Por favor ay\250dame! "
gameforge.find_brother_article._170_select = "Abandonar "
gameforge.find_brother_article._180_sayReward = "Derrotar a 100 miembros del Clan del Viento Negro[ENTER]parece ser m\225s f\225cil que rehusar la petici\243n de[ENTER]la chica. "
gameforge.find_brother_article._190_say = "Lo siento. Lo siento por t\237, pero el Clan del[ENTER]Viento Negro es demasiado fuerte para m\237.[ENTER]Cualquier otro ser\237a una mejor elecci\243n para este[ENTER]trabajo. "
gameforge.find_brother_article._200_say = "Oh no... Ya he pedido ayuda a otros, pero nadie[ENTER]volvi\243. T\250 eres mi \250ltima esperanza. Mira, esto[ENTER]es lo m\225s valioso que poseo. Te lo dar\233 como[ENTER]recompensa. "
gameforge.find_brother_article._205_sayReward = "La muchacha saca un objeto que ha sido envuelto[ENTER]cuidadosamente en un pa\241uelo: una espada.[ENTER]Los adornos en el grifo muestran que se trata de[ENTER]un arma muy valiosa. "
gameforge.find_brother_article._20_sayTitle = "Mirine: "
gameforge.find_brother_article._210_select = "Aceptar el reto "
gameforge.find_brother_article._220_say = "No es por la recompensa, pero voy a aceptar el[ENTER]reto. "
gameforge.find_brother_article._230_say = "Tienes raz\243n. Nadie volvi\243, todos perdieron sus[ENTER]vidas. La vida es m\225s valiosa que cualquier[ENTER]recuerdo. No tendr\237a sentido sacrificar m\225s[ENTER]vidas. \161Adi\243s! "
gameforge.find_brother_article._240_npcChat = "\161He encontrado el Uniforme Negro! "
gameforge.find_brother_article._250_say = "\161Gracias! \161\201l siempre llevaba puesto este[ENTER]uniforme. Nunca quiso ponerse otro traje...[ENTER]Aqu\237, toma. Este es el objeto m\225s valioso que[ENTER]tengo. Ya no lo necesito, por favor ac\233ptalo. "
gameforge.find_brother_article._260_sayReward = "Recompensa de Mirine aceptada. "
gameforge.find_brother_article._270_sendLetter = "Recompensa de Mirine "
gameforge.find_brother_article._280_say = "Desenvuelves la valiosa recompensa de Mirine y[ENTER]encuentras una espada con una empu\241adura[ENTER]maravillosamente adornada. "
gameforge.find_brother_article._290_say = "Un arma excelente. Pero... \191qu\233 es esto? \161La[ENTER]cuchilla est\225 rota![ENTER]Esta hermosa pieza artesanal es demasiado buena[ENTER]como para tirarla. Deber\237a llevarle los pedazos[ENTER]rotos al herrero. "
gameforge.find_brother_article._300_sayReward = "Has recibido una espada rota. Ll\233vasela a un[ENTER]herrero. "
gameforge.find_brother_article._30_say = "Mi hermano, \161te echo tanto de menos! \191\161Oh!?[ENTER]\191Qui\233n eres t\250? "
gameforge.find_brother_article._310_sendLetter = "Ve con el Herrero "
gameforge.find_brother_article._320_say = "Mirine debi\243 haber estado muy agradecida para[ENTER]haberte regalado su tesoro m\225s valioso: una bella[ENTER]espada, pero que desafortunadamente est\225 rota. A[ENTER]primera vista aprecias que se trata de una espada[ENTER]valiosa, por lo que decides llevarla al herrero. "
gameforge.find_brother_article._330_targetVid = "La reparaci\243n de la espada "
gameforge.find_brother_article._340_npcChat = "\191Puedes reparar esta espada? "
gameforge.find_brother_article._350_say = "\161Esta es una espada impresionante! Era de Mirine,[ENTER]\191verdad? O\237 que le ayudaste. Bien hecho, esto te[ENTER]acredita como una persona honesta as\237 que no te[ENTER]cobrar\233 por la reparaci\243n de la espada.[ENTER]Espera un momento... "
gameforge.find_brother_article._360_say = "Aqu\237, la cuchilla se ve ahora como nueva. Un arma[ENTER]verdaderamente fant\225stica. T\243mala, mi amigo. "
gameforge.find_brother_article._370_sayReward = "Has recibido Espada de Plata+3. "
gameforge.find_brother_article._380_sayReward = "Obtienes una Espada de Orqu\237dea +2. "
gameforge.find_brother_article._390_sayReward = "Obtienes una Espada Bastarda +2. "
gameforge.find_brother_article._400_sayReward = "Obtienes una Espada B\225rbara +2. "
gameforge.find_brother_article._40_say = "Pasaba por aqu\237 y te vi llorar. Toma, coge este[ENTER]pa\241uelo. "
gameforge.find_brother_article._50_say = "Oh, no pens\233 que alguien estuviese tan cerca...[ENTER]mi nombre es Mirine. \191Puedo pedirte un favor? Mi[ENTER]hermano mayor ha muerto. \201l fue a buscar medicina[ENTER]pero despu\233s...[ENTER]En mi memoria ha quedado solamente la imagen de[ENTER]su tumba y un solo recuerdo: su Uniforme Negro. "
gameforge.find_brother_article._60_sayTitle = "Mirine: "
gameforge.find_brother_article._70_say = "De repente, el infame Clan del Viento Negro[ENTER]apareci\243. Desafortunadamente, perd\237 mi recuerdo[ENTER]cuando hu\237.[ENTER]No tengo el coraje para volver y buscarlo.[ENTER]\191Puedes buscar mi recuerdo perdido? "
gameforge.find_brother_article._80_sayReward = "Muestra misericordia y ayuda a esta pobre chica.[ENTER]\161Busca el uniforme negro usado que llevaba su[ENTER]hermano! "
gameforge.find_brother_article._90_select = "Aceptar "
