gameforge.find_squareguard._10_targetVid = "Guardi\225n: "
gameforge.find_squareguard._110_sayTitle = "Guardi\225n: "
gameforge.find_squareguard._120_say = "Puedes adquirir la Poci\243n Roja de la Vendedora de[ENTER]la Tienda General. Ella est\225 all\237. Si no la[ENTER]puedes ver, dir\237gete hacia el c\237rculo[ENTER]intermitente en el mapa grande o hacia el punto[ENTER]rojo intermitente en el mini mapa. "
gameforge.find_squareguard._130_sayTitle = "Vendedor general: "
gameforge.find_squareguard._131_targetVid = "Vendedor general: "
gameforge.find_squareguard._140_say = "\161Bienvenido, aventurero![ENTER]Oh, \191as\237 que te env\237a el guardi\225n? \191Necesita una[ENTER]Poci\243n Roja? Te dar\233 cinco.[ENTER]Toma, aqu\237 las tienes. Sirven para regenerar la[ENTER]vitalidad y adem\225s saben bien. "
gameforge.find_squareguard._150_say = "Puede que seas nuevo, pero estoy segura que[ENTER]pronto ser\225s un cliente habitual. Por eso te doy[ENTER]gratis estas pociones. Por favor, vuelve otra[ENTER]vez. "
gameforge.find_squareguard._160_sayReward = "Has recibido 5 pociones rojas del almac\233n general. "
gameforge.find_squareguard._170_sayReward = "Las pociones rojas sirven para regenerar los[ENTER]puntos de salud (HP). "
gameforge.find_squareguard._180_sendLetter = "Vuelve con el guardi\225n "
gameforge.find_squareguard._190_sayReward = "Vuelve con el guardi\225n y dale su poci\243n. "
gameforge.find_squareguard._200_say = "\191No has conseguido la poci\243n roja que te ped\237?[ENTER]\161Qu\233 verg\252enza! Bien, qu\233date el yang por las[ENTER]molestias.[ENTER]Por cierto, los instructores han preguntado por[ENTER]ti.[ENTER]Les gustar\237a conocerte. "
gameforge.find_squareguard._20_sayReward = "Ve a la aldea y habla con el Guardi\225n. \201l te[ENTER]asignar\225 tu primera misi\243n. \201l se encuentra en el[ENTER]centro de la aldea. "
gameforge.find_squareguard._210_say = "\161Gracias por traer la poci\243n! Bien, ahora estoy[ENTER]mejor preparado para realizar mi funci\243n en la[ENTER]aldea.[ENTER]\191Quieres saber cu\225l es mi funci\243n? No soy s\243lo el[ENTER]guardi\225n de la aldea, tambi\233n una valiosa fuente[ENTER]de informaci\243n. Anuncio informaci\243n \250til que todo[ENTER]el mundo tiene que leer. Tambi\233n ofrezco mi ayuda[ENTER]y protecci\243n a aquellos que la necesitan. Y soy[ENTER]el responsable de los asuntos de gremios. Si,[ENTER]alg\250n d\237a, est\225s interesado en fundar tu propio[ENTER]gremio, ven conmigo. "
gameforge.find_squareguard._220_say = "Por cierto, los instructores han preguntado por[ENTER]t\237.[ENTER]Les gustar\237a conocerte.[ENTER]Oh, \161casi lo olvido! Como muestra de mi aprecio,[ENTER]puedes quedarte el cambio de la poci\243n. Nos[ENTER]vemos. "
gameforge.find_squareguard._30_sayTitle = "Guardi\225n: "
gameforge.find_squareguard._40_say = "\161Bienvenido a nuestra aldea aventurero! Espero[ENTER]que puedas llevar a cabo una tarea para m\237. Si te[ENTER]doy 200 yang, \191puedes ir al almac\233n general y[ENTER]comprar una poci\243n roja para m\237?[ENTER]Desafortunadamente, debo permanecer aqu\237. Usa tu[ENTER]mini mapa para localizar el almac\233n general,[ENTER]usando el punto rojo que parpadea. "
gameforge.find_squareguard._50_select = "S\237 "
gameforge.find_squareguard._60_sayReward = "Has recibido 200 yang del guardi\225n. Ve al almac\233n[ENTER]general y compra una poci\243n roja. Puedes usar el[ENTER]yang para comprar objetos y servicios de varios[ENTER]aldeanos. "
