gameforge.fisher._40_say = "\191As\237 que est\225s interesado en saber sobre los[ENTER]secretos para mejorar tu ca\241a de pescar? Para ser[ENTER]honesto, no hay un gran secreto. Si pasas m\225s[ENTER]tiempo pescando, tu ca\241a de pescar reunir\225 m\225s[ENTER]puntos. Cuando tu ca\241a haya llegado al nivel[ENTER]m\225ximo, tr\225emela. Entonces intentar\233 mejorarla.[ENTER]Bien, ahora elige la ca\241a de pescar que quieras[ENTER]mejorar y d\225mela. "
gameforge.fisher._50_say = "\191Y qu\233 hago con esto? Yo solamente puedo mejorar[ENTER]ca\241as de pescar. "
gameforge.fisher._60_say = "Lo siento, pero esta ca\241a de pescar no puede[ENTER]seguir siendo mejorada. "
gameforge.fisher._70_say = "Esta ca\241a de pescar no ha reunido los suficientes[ENTER]puntos. Todav\237a no puedo mejorarla. \161Vuelve[ENTER]cuando tu ca\241a de pescar haya alcanzado el m\225ximo[ENTER]n\250mero de puntos! "
