gameforge.fortune_telling._100_sayTitle = "Anciana "
gameforge.fortune_telling._10_npcChat = "He oido que eres una adivina. "
gameforge.fortune_telling._110_say = "\161Eres demasiado joven para estar suspirando as\237![ENTER]\191Quieres conocer tu fortuna anunciada por una[ENTER]arm\243nica y misteriosa fuerza? "
gameforge.fortune_telling._120_select = "Cu\233ntame mi fortuna "
gameforge.fortune_telling._130_select = "No me cuentes mi fortuna "
gameforge.fortune_telling._140_say = "Est\225 bien. Seguir tu propio camino e intentar[ENTER]hacerlo lo mejor posible es lo m\225s importante en[ENTER]la vida. Buena suerte. "
gameforge.fortune_telling._150_select = "S\237, quiero uno. "
gameforge.fortune_telling._160_select = "No, gracias. "
gameforge.fortune_telling._170_say = "Puede que sea amable, pero no puedo d\225rtelo[ENTER]gratis. Si quieres evitar la mala suerte y la[ENTER]desgracia, tendr\225s que pagar el precio del[ENTER]talism\225n.[ENTER]Cuesta %s Yang. "
gameforge.fortune_telling._180_say = "\191Te vas? Quiz\225 tengas raz\243n. La mala suerte y la[ENTER]tristeza son parte de la vida. Adi\243s y ten[ENTER]cuidado. Si cambias de opini\243n, vuelve conmigo. "
gameforge.fortune_telling._20_say = "Tu rostro me dice que no has vivido mucho. \191Por[ENTER]qu\233 quieres conocer tu destino tan pronto?[ENTER]\191Tienes problemas? Tu destino necesita mucho[ENTER]entrenamiento. Vuelve m\225s tarde. "
gameforge.fortune_telling._30_say = "\191Realmente quieres vivir tu vida del modo que te[ENTER]dijo la adivina? No deber\237as tomar tan en serio[ENTER]las predicciones. Las cosas verdaderamente[ENTER]importantes son tu actitud y la m\237a. Si ambos[ENTER]somos positivos, nada puede ir mal. Si a\250n[ENTER]quieres conocer tu fortuna, vuelve ma\241ana. "
gameforge.fortune_telling._40_sayTitle = "Anciana "
gameforge.fortune_telling._50_say = "Como te he dicho antes, tu predicci\243n para el d\237a[ENTER]de hoy es: "
gameforge.fortune_telling._60_say = "Tendr\225s mala suere y a\250n no has comprado el[ENTER]talisman contra la maldad...[ENTER]\191Est\225s interesado en comprar mi talism\225n de la[ENTER]fortuna? "
gameforge.fortune_telling._70_select = "S\237, lo compro. "
gameforge.fortune_telling._80_select = "No, gracias. "
gameforge.fortune_telling._90_say = "Puedo ser amable, pero no puedo d\225rtelo gratis.[ENTER]Si quieres evitar la mala suerte y la desgracia,[ENTER]tendr\225s que pagar el precio del talism\225n. "
