gameforge.ghost_story = {}
gameforge.ghost_story._010_sayTitle = "Fantasma de un Sura: "
gameforge.ghost_story._020_npcChat = "\191Eres un fantasma? "
gameforge.ghost_story._030_say = "No, soy tu abuela... \161Es evidente que soy un[ENTER]fantasma, \191no crees? \191Te ca\237ste de cabeza cuando[ENTER]eras chico? "
gameforge.ghost_story._040_npcChat = "\161Socorro, un fantasma! "
gameforge.ghost_story._050_say = "\161Mira que guerrero tan valiente soy! \161Buu! "
gameforge.ghost_story._060_npcChat = "\191Qui\233n eres t\250? "
gameforge.ghost_story._070_say = "Me llamo Akuma. Anta\241o fui un gran guerrero,[ENTER]hasta se dice que fui el mejor de mis tiempos.[ENTER]\161Y tambi\233n yo estaba convencido de eso! Pero[ENTER]ahora m\237rame. Mira lo que ha quedado de m\237[ENTER]despu\233s de haber encontrado la Gruta... y haber[ENTER]perecido. "
gameforge.ghost_story._080_npcChat = "\191Conoces la historia de este pueblo? "
gameforge.ghost_story._090_say = "Pero claro que s\233 lo que pas\243 en aquel entonces.[ENTER]En vida me dediqu\233 a investigar para poder[ENTER]descubrir la causas y encontrar la Gruta. Y ya de[ENTER]muerto tuve mucho tiempo para reflexionar sobre[ENTER]eso. \161Ahora dime que te interesa! "
gameforge.ghost_story._100_npcChat = "\191Qu\233 portal es ese? "
gameforge.ghost_story._110_say = "Ese portal conduce a la c\225mara del dios ca\237do[ENTER]Beran-Setaou, el drag\243n de la oscuridad. Puede[ENTER]ser activada con un llave m\225gica, que est\225 en[ENTER]posesi\243n de los l\237deres de las tropas de los[ENTER]Beran-Setaou. "
gameforge.ghost_story._120_npcChat = "Los tres Dioses "
gameforge.ghost_story._130_say = "Antiguamente tres hermanos divinos formaban el[ENTER]pilar de fundamento de la existencia.[ENTER]Bahar-Taraji, la Diosa de la Creaci\243n, era la[ENTER]menor de los tres. Ella se encargaba de la[ENTER]creaci\243n de nuevas cosas. Adondequiera que iba,[ENTER]brotaban las flores y florec\237a la vida. "
gameforge.ghost_story._140_say = "El hermano mayor era Beran-Setaou. \201l se[ENTER]encargaba de la muerte y de la disoluci\243n. Cuando[ENTER]un ciclo de vida estaba por terminar, \233l separaba[ENTER]el cuerpo del esp\237ritu y conduc\237a el alma al m\225s[ENTER]all\225. De este modo estaba garantizado siempre el[ENTER]ciclo de la vida y la muerte, la base de todo ser[ENTER]viviente. "
gameforge.ghost_story._150_say = "Baljit-Elvedin, era el hermano intermedio. Como[ENTER]Dios del Equilibrio mediaba entre sus hermanos y[ENTER]les garantizaba a los seres terrestres un eterno[ENTER]c\237rculo de la vida. Una de sus tareas era el[ENTER]comienzo y t\233rmino de las estaciones del a\241o. "
gameforge.ghost_story._160_npcChat = "La discordia "
gameforge.ghost_story._170_say = "Los humanos rezaban a los tres dioses y les[ENTER]ped\237an ayuda en tiempos malos. S\243lo Beran-Setaou[ENTER]era temido y despreciado por ellos. En su falta[ENTER]de visi\243n, ellos no entend\237an que su presencia[ENTER]era necesaria. \201l era el contraste a la creaci\243n,[ENTER]es decir, como la luz y la sombra. "
gameforge.ghost_story._180_say = "Por mucho tiempo el dios ignor\243 esta situaci\243n,[ENTER]pero a lo largo de los a\241os en \233l fueron[ENTER]creciendo celos hasta convertirse en odio y[ENTER]envidia. Primero se desahog\243 en los humanos[ENTER]llev\225ndoles guerras y enfermedades. No obstante,[ENTER]esto aument\243 el rechazo contra \233l y los humanos[ENTER]intensificaron sus plegarias a Bahar-Taraj, el[ENTER]ama de la vida. De este modo se origin\243 un[ENTER]c\237rculo vicioso que termin\243 en un desastre. "
gameforge.ghost_story._190_say = "Cuando la furia del Dios escal\243 al m\225ximo, paso[ENTER]lo m\225s terrible: \201l mat\243 a su hermana, la Diosa[ENTER]preferida de los humanos. Su acto no necesito[ENTER]ninguna preparaci\243n ni t\225ctica, puesto que aquel[ENTER]d\237a ella se encontr\243 con \233l con la inocencia y[ENTER]confianza de cada encuentro. \201l tuvo que haber[ENTER]visto la ternura de sus ojos, sin embargo, le dio[ENTER]el golpe mortal. "
gameforge.ghost_story._200_npcChat = "Las consecuencias "
gameforge.ghost_story._210_say = "La muerte de Bahar-Taraji tuvo terribles[ENTER]consecuencias en el mundo de los Dioses y en los[ENTER]humanos: Un invierno largo y cruel acab\243 con la[ENTER]vida de muchas criaturas que habitaban en la[ENTER]tierra y en el agua. La tierra se congel\243 a tal[ENTER]punto que las piedras se reventaron y hasta los[ENTER]\225rboles m\225s fuertes y antiguos parecieron. "
gameforge.ghost_story._220_say = "Murieron muchos humanos y animales j\243venes, y[ENTER]cuando empez\243 a hacer calor, el n\250mero de los[ENTER]reci\233n nacidos era m\225s bajo que nunca. La tierra[ENTER]completamente esmirriada no daba los suficientes[ENTER]frutos para alimentar a los adultos y mucho menos[ENTER]para pensar en tener descendientes. La vida y las[ENTER]esperanzas se desvanecieron y las dos necesitaron[ENTER]mucho tiempo para reponerse. "
gameforge.ghost_story._230_say = "Los Dioses tambi\233n sufrieron, aunque su tiempo[ENTER]trascurri\243 m\225s lento que el de los humanos.[ENTER]Beran-Setaou busc\243 soledad al darse cuenta de lo[ENTER]que hab\237a hecho. Su conciencia luchaba con un[ENTER]amargo arrepentimiento y con una profunda[ENTER]satisfacci\243n, hasta que finalmente gan\243 la[ENTER]\250ltima. Su coraz\243n se congel\243 y Beran-Setaou se[ENTER]convirti\243 del Dios de la Disoluci\243n en el Dios[ENTER]del Hielo, del Fr\237o, del Odio y del Miedo. "
gameforge.ghost_story._240_npcChat = "La batalla "
gameforge.ghost_story._250_say = "Baljit-Elvedin, el Dios de la Conservaci\243n, llor\243[ENTER]la muerte de su hermana durante mucho tiempo.[ENTER]Cuando su dolor se alivi\243, fue a buscar a su[ENTER]hermano. Baljit-Elvedin segu\237a siempre su camino[ENTER]con sensatez e inteligencia, pero a pesar de su[ENTER]dolor reconoci\243 que la vida no tiene ninguna[ENTER]oportunidad de seguir existiendo en el mundo de[ENTER]desequilibrio que reina ahora. "
gameforge.ghost_story._260_say = "\201l sigui\243 las huellas de su hermano y finalmente,[ENTER]despu\233s de a\241os de b\250squeda, lo encontr\243 en una[ENTER]cueva de hielo, odio y soledad. Baljit-Elvedin[ENTER]hizo lo que ten\237a que hacer, aunque esto le[ENTER]abriese una herida m\225s en su coraz\243n: \233l le reto[ENTER]a duelo a su hermano. \201ste, en cambio, ya[ENTER]desviado del camino recto, no vacil\243 ni un[ENTER]momento y acept\243. "
gameforge.ghost_story._270_say = "Se dice que el enfrentamiento de los dos hermanos[ENTER]fue atroz. La victoria la obtuvo Baljit-Elvedin,[ENTER]quien debido a su \233tica no fue capaz de matar a[ENTER]su hermano. \201l lo castig\243 quit\225ndole todas sus[ENTER]fuerzas y encerr\225ndolo en esta Gruta. Y es as\237[ENTER]como Beran-Setaou vino a parar a este espantoso[ENTER]lugar lleno de criaturas que \233l ha venido creando[ENTER]en el transcurso de los siglos.. "
gameforge.ghost_story._280_npcChat = "Me basta con eso. "
gameforge.ghost_story._290_say = "Que tu destino se discurra por un sendero[ENTER]diferente al m\237o. \161Te deseo mucha suerte! "
gameforge.ghost_story._300_sayTitle = "Fantasma de un guerrero: "
gameforge.ghost_story._310_npcChat = "\191Por qu\233 eres transparente? "
gameforge.ghost_story._320_say = "\191No ser\225 que necesitas gafas? Claro que soy un[ENTER]fantasma, estoy atrapado en las rocas desde hace[ENTER]miles de a\241os... "
gameforge.ghost_story._330_say = "\161Socorro, un fantasma! "
gameforge.ghost_story._340_say = "Correcto, un fantasma. \161Huye lo m\225s r\225pido que[ENTER]puedas, si no te como! "
gameforge.ghost_story._350_npcChat = "\191Qui\233n eres t\250? "
gameforge.ghost_story._360_say = "Anta\241o fui un mercenario, un hombre sencillo. Mis[ENTER]padres fueron campesinos. Yo, sin embargo, no[ENTER]quise trabajar en el campo toda mi vida, y es por[ENTER]eso que me hice soldado. Esa etapa de mi vida fue[ENTER]dura y cruel, pero no estuvo nada mal. No[ENTER]obstante, al cabo de un tiempo me cans\233 de[ENTER]recibir ordenes de in\250tiles comandantes y[ENTER]desert\233. Y ahora a causa de un accidente me[ENTER]encuentro en este espantoso lugar. "
gameforge.ghost_story._370_npcChat = "\191Conoces la historia de la Gruta? "
gameforge.ghost_story._380_say = "No, no la conozco. Yo solamente tuve mala suerte.[ENTER]Despu\233s de haber desertado, quise esconderme en[ENTER]la monta\241as y me adentr\233 en esta cueva.[ENTER]No me dio buena espina desde un principio, pero[ENTER]estaba cerca y parec\237a estar abandonada. Al paso[ENTER]de unos d\237as fui testigo y victima de una[ENTER]incre\237ble batalla. Si quieres, te cuento lo que[ENTER]vi. "
gameforge.ghost_story._390_npcChat = "El comienzo de la batalla "
gameforge.ghost_story._400_say = "Un buen d\237a estaba reuniendo ra\237ces en las faldas[ENTER]de la monta\241a cuando un drag\243n plateado, sin[ENTER]aviso previo, descendi\243 del cielo. Pens\233 que[ENTER]ven\237a por m\237, pero ni me tom\243 en cuenta, \233l se[ENTER]fij\243 solamente en la entrada a la cueva. Sin[ENTER]disminuir su velocidad vol\243 en direcci\243n al valle[ENTER]y se adentr\243 en la cueva. "
gameforge.ghost_story._410_say = "Durante un rato no se escucho nada y yo no supe[ENTER]que hacer. Todas mis armas estaban en la cueva y[ENTER]\161lo menos que quer\237a era encontrarme con un[ENTER]drag\243n! Pero de repente la tierra empez\243 a[ENTER]temblar y de las profundidades de la cueva surg\237a[ENTER]un ronco rugido, \161pero no era una voz, sino dos[ENTER]voces! Al poco rato salieron disparados dos[ENTER]dragones de la cueva, primero el plateado y[ENTER]despu\233s el azul. "
gameforge.ghost_story._420_say = "Los dos dragones se batieron en un combate atroz[ENTER]que me es dif\237cil describir. Con sus garras se[ENTER]desgarraron mutuamente las alas, lucharon como si[ENTER]se quisieran devorar, fijaron sus enormes dientes[ENTER]en el cuello del enemigo... Llov\237a sangre... Pero[ENTER]nadie de los dos se daba por vencido. "
gameforge.ghost_story._430_npcChat = "El final de la batalla "
gameforge.ghost_story._440_say = "Los dos dragones revoloteaban sobre el valle como[ENTER]una tormenta destruyendo picos de monta\241as. Los[ENTER]rel\225mpagos quemaban el hocico del drag\243n azul y[ENTER]el granizo helado perforaba las alas del drag\243n[ENTER]plateado. La gruesa capa de hielo que cubr\237a la[ENTER]tierra desde hace a\241os, se derriti\243 a causa de[ENTER]esta embestida dejando a su paso r\237os de fango.[ENTER]Detr\225s de las rocas yo observaba todo esto muerto[ENTER]de miedo, pero incapaz de retirar la mirada. "
gameforge.ghost_story._450_say = "No hasta el paso de varias horas parec\237a que sus[ENTER]fuerzas empezaban a disminuir. En este momento[ENTER]aprovech\233 la oportunidad y corr\237 valle a arriba[ENTER]para poder recuperar mis armas. Y eso fue lo que[ENTER]marc\243 mi destino. Ya cuando me encontraba de[ENTER]regreso de la cueva, los dos dragones salieron[ENTER]disparados de las monta\241as, delante el azul, el[ENTER]drag\243n que sufri\243 las peores heridas. "
gameforge.ghost_story._460_say = "Antes de que el drag\243n azul desapareciera en la[ENTER]cueva, el drag\243n plateado lo alcanz\243 y en ese[ENTER]momento paso algo muy extra\241o: la titilaci\243n que[ENTER]inundaba el aire se transform\243 en una corriente[ENTER]de aire hasta convertirse un torbellino de[ENTER]energ\237a; el drag\243n azul se encontraba atrapado en[ENTER]el y rug\237a de dolor y furia... Finalmente se[ENTER]encogi\243, su rugido se volvi\243 cada vez m\225s d\233bil y[ENTER]sus escamas fueron volvi\233ndose opacas y perdiendo[ENTER]su brillo. "
gameforge.ghost_story._470_say = "Finalmente el drag\243n plateado echo al drag\243n azul[ENTER]en la cueva. El perdedor, con las \250ltimas fuerzas[ENTER]que le quedaban, se refugi\243 bajo la oscuridad de[ENTER]la monta\241a. No obstante, el drag\243n azul cre\243 una[ENTER]torre de energ\237a que sell\243 la cueva y caus\243 el[ENTER]derrumbamiento de una parte de la monta\241a. A[ENTER]partir de ese momento el drag\243n de la oscuridad y[ENTER]yo quedamos atrapados. Maldecidos a morir de[ENTER]hambre... "
gameforge.ghost_story._480_npcChat = "Me basta con eso. "
gameforge.ghost_story._490_say = "Gracias por prestarme atenci\243n. Los \250ltimos mil[ENTER]a\241os han estado llenos de soledad... "
gameforge.goldbar = {}
gameforge.goldbar._100_say = "Antes de escapar del Clan del Viento Negro,[ENTER]descubr\237 que su oro est\225 escondido. \161Ten\237an un[ENTER]mont\243n de barras de oro! Ni se dar\237an cuenta si[ENTER]desapareciera una barra. Son tontos. Si est\225s de[ENTER]acuerdo en contratarme, ir\233 y conseguir\233 una[ENTER]barra de oro. Pero no puedo conseguir m\225s de una[ENTER]barra de oro de vez. "
gameforge.goldbar._104_say = "Tiempo "
gameforge.goldbar._108_say = "minuto(s) "
gameforge.goldbar._10_npcChat = "Una v\237ctima del Clan del Viento Negro "
gameforge.goldbar._110_say = "Lleva aproximadamente %s %s traer una barra de[ENTER]oro. "
gameforge.goldbar._120_say = "Dime si est\225s interesado. "
gameforge.goldbar._130_say = "\191De verdad? \191Entonces tenemos un trato?[ENTER]\161T\250 s\243lo dime que lo haga e ir\233 a conseguirte uno! "
gameforge.goldbar._140_npcChat = "Quiero comprar una Barra de Oro. "
gameforge.goldbar._150_say = "\191De qu\233 est\225s hablando? No s\233 de que hablas. "
gameforge.goldbar._160_say = "\191Qu\233? \191Quieres comprar barras de oro? No, \161ahora[ENTER]no! Los guerreros del Clan del Viento Negro[ENTER]parecen estar alerta ahora mismo. Estoy[ENTER]arriesgando mi vida; \161tengo que tener cuidado! Lo[ENTER]intentar\233 de nuevo una vez que se haya calmado la[ENTER]situaci\243n. "
gameforge.goldbar._170_sayReward = "No puedes comprar barras de oro ahora mismo. "
gameforge.goldbar._180_say = "A\250n no ha sido posible conseguir una barra de oro. "
gameforge.goldbar._190_say = "Tenemos que esperar %s %s "
gameforge.goldbar._200_say = "Traje una barra de oro conmigo.[ENTER]Cuesta 2,2 millones de Yang. Los 200.000 Yang son[ENTER]mi paga.[ENTER]\191Qu\233 me dices? \191Quieres comprarla? "
gameforge.goldbar._20_sayTitle = "Balso el traidor: "
gameforge.goldbar._210_say = "Aqu\237 la tienes: una Barra de Oro. \161Has tomado una[ENTER]sabia decisi\243n! Siempre es buena idea hacer este[ENTER]tipo inversiones. "
gameforge.goldbar._220_say = "\161No tienes suficiente Yang! Cuesta 2,2 millones[ENTER]de Yang. "
gameforge.goldbar._230_say = "\191Por qu\233 est\225s aqu\237 si no quieres comprar nada?[ENTER]Me has hecho perder el tiempo; vete de aqu\237. "
gameforge.goldbar._240_npcChat = "GM: restablecer el tiempo para vender una barra de oro. "
gameforge.goldbar._250_say = "El tiempo para vender una barra de oro ha sido[ENTER]restablecido. "
gameforge.goldbar._260_npcChat = "Vender Barra de Oro "
gameforge.goldbar._270_say = "\191De qu\233 est\225s hablando? No s\233 de que hablas. "
gameforge.goldbar._280_say = "\191Qu\233? \191Quieres vender una barra de oro?[ENTER]\191No has oido? Los guerreros del Clan del Viento[ENTER]Negro est\225n alerta en este momento.[ENTER]Si vendes ahora la barra de oro, no vivir\225s por[ENTER]mucho tiempo. Ser\225 mejor si la dejas donde est\225.[ENTER]\161Esc\243ndela bien! "
gameforge.goldbar._290_sayReward = "No puedes vender barras de oro en este momento. "
gameforge.goldbar._300_say = "Si quieres devolver la barra de oro, "
gameforge.goldbar._30_say = "\191Qu\233? \191Una v\237ctima del Clan del Viento Negro?[ENTER]\161Ja, ja, ja! A\250n eres un cr\237o. \191D\243nde has oido[ENTER]eso?[ENTER]\161Ve a jugar con los perros salvajes! "
gameforge.goldbar._310_say = "tienes que esperar aproximadamente %s %s. "
gameforge.goldbar._320_say = "No tienes ninguna barra de oro. Si me das barras[ENTER]de oro, te dar\233 Yang por ellas. "
gameforge.goldbar._330_say = "\191Qu\233? \191Quieres devolver tu barra de oro? Entonces[ENTER]por qu\233 la compraste, \161por el favor de los[ENTER]dioses! Si quieres devolverla de esta manera tan[ENTER]mala, no me voy a meter.[ENTER]El Clan del Viento Negro guarda sus tesoros muy[ENTER]bien; no puedo hacer esto muy a menudo. \191A\250n[ENTER]quieres devolverla? "
gameforge.goldbar._340_select = "Devolver "
gameforge.goldbar._350_select = "No devolver "
gameforge.goldbar._360_say = "Aqu\237 tienes tu Yang. \161Majadero! \161Ahora tengo que[ENTER]devolverla! "
gameforge.goldbar._370_say = "\191No tienes ninguna barra de oro? Estoy muy[ENTER]ocupado. No vengas aqu\237 si no quieres hablar de[ENTER]negocios. "
gameforge.goldbar._40_sayReward = "La misi\243n de la v\237ctima del Clan del Viento Negro[ENTER]s\243lo est\225 disponible para jugadores con nivel 30[ENTER]o superior. "
gameforge.goldbar._50_say = "\161Ten cuidado! Los guerreros del Clan del Viento[ENTER]Negro est\225n muy alerta ahora mismo. Ser\237a mejor[ENTER]estarse quietos. Adi\243s. "
gameforge.goldbar._60_sayReward = "Actualmente, la misi\243n de la v\237ctima del Clan del[ENTER]Viento Negro no est\225 disponible. "
gameforge.goldbar._70_say = "\161Shh![ENTER]Miembros del Clan del Viento Negro pueden estar[ENTER]escondi\233ndose en alg\250n sitio.[ENTER]\191D\243nde has oido sobre esto?[ENTER]No, est\225 bien. Eso no es importante.[ENTER]\191Sabes qu\233 est\225 pasando? "
gameforge.goldbar._80_select = "No, no realmente. "
gameforge.goldbar._90_select = "S\237, lo s\233 todo. "
