gameforge.guild_building._110_say = "Vuelve cuando decidas qu\233 hacer.[ENTER]El primero en venir, el primero en comprar. "
gameforge.guild_building._20_say = "Soy el administrador de tierras y el responsable[ENTER]de venderlas. Antes de que los monstruos ocuparan[ENTER]la regi\243n en el centro del continente, no[ENTER]ten\237amos escasez de tierras y todo el mundo era[ENTER]feliz. Ahora s\243lo estoy vendiendo tierras a los[ENTER]l\237deres de gremios, quienes las usan como tierra[ENTER]para sus gremios. \191Quieres comprar alguna tierra? "
