gameforge.guild_building_npc._10_sayTitle = "Herrero de armas: "
gameforge.guild_building_npc._20_say = "Ah, \161eres miembro de mi gremio! Si quieres[ENTER]mejorar tus armas, no las llevas a ese[ENTER]principiante, mejor tr\225emelas a m\237. Tu[ENTER]probabilidad de \233xito aumentar\225 en un 10% si me[ENTER]dejas mejorar un arma. Y adem\225s los miembros del[ENTER]gremio reciben un 5% de descuento. Solo dame las[ENTER]armas que quieras mejorar. "
gameforge.guild_building_npc._30_say = "Mi nombre es Stanley. Soy el responsable de[ENTER]mejorar armas. \161Soy mucho mejor que el herrero de[ENTER]la aldea! Mi trabajo puede aumentar tu[ENTER]probabilidad de \233xito en un 10%. Solo dame el[ENTER]arma que quieras mejorar. "
gameforge.guild_building_npc._40_sayTitle = "Herrero de armaduras: "
gameforge.guild_building_npc._50_say = "Ah, \161eres miembro de mi gremio! Yo puedo mejorar[ENTER]tus armaduras, escudos, zapatos y cascos. Mi[ENTER]probabilidad de \233xito es 10% m\225s alta que la del[ENTER]herrero de la aldea. Adem\225s los miembros de mi[ENTER]gremio reciben un 5% de descuento. Solo dame las[ENTER]armaduras que quieras mejorar. "
gameforge.guild_building_npc._60_say = "Mi nombre es Stanton, soy el encargo de mejorar[ENTER]armaduras. Adem\225s soy mucho mejor que el herrero[ENTER]de la aldea. Mi trabajo puede aumentar tu[ENTER]probabilidad de \233xito en un 10%. Dame la armadura[ENTER]que quieras mejorar. "
gameforge.guild_building_npc._70_sayTitle = "Joyero: "
gameforge.guild_building_npc._80_say = "Oh, \161eres miembro de mi gremio! Tu probabilidad[ENTER]de \233xito aumentar\225 en un 10% si me dejas mejorar[ENTER]tu joyas. Puedo mejorar brazaletes, pendientes y[ENTER]collares. Solo dame el accesorio que quieres que[ENTER]sea mejorado. "
gameforge.guild_building_npc._90_say = "Mi nombre es Starbuck. Soy el responsable de[ENTER]mejorar accesorios. Puedo mejorar brazaletes,[ENTER]pendientes y collares. \161Soy mucho mejor que el[ENTER]herrero de la ciudad! Mi trabajo puede[ENTER]incrementar tu probabilidad de \233xito en un 10%.[ENTER]\161Dame el accesorio que quieres mejorar! "
