gameforge.guild_manage._120_say = "\191Quieres dejar el gremio al que perteneces?[ENTER]Supongo que no hiciste ning\250n amigo verdadero[ENTER]ah\237. Es tu decisi\243n. \191Realmente deseas abandonar[ENTER]el gremio? "
