gameforge.heavens_cave_keyquest._020_npcChat = "En la Gruta "
gameforge.heavens_cave_keyquest._030_say = "\161Esc\250chame bien, amigo mio! Te contar\233 esta[ENTER]historia una sola vez... "
gameforge.heavens_cave_keyquest._040_say = "\161Esc\250chame bien, amiga m\237a! Te contar\233 esta[ENTER]historia una sola vez... "
gameforge.heavens_cave_keyquest._050_say = "hoy en d\237a, adoramos al Dios Drag\243n, pero en otro[ENTER]tiempo, tres dioses nos vigilaban. Sin embargo,[ENTER]Bahar-Taraji, la Diosa de la Creaci\243n, fue[ENTER]asesinada por su celoso hermano Beran-Setaou. Y[ENTER]el tercer Dios, Baljit-Elvedin, a quien conocemos[ENTER]hoy en d\237a como el Dios Drag\243n, entr\243 en luto[ENTER]profundo por su hermana. "
gameforge.heavens_cave_keyquest._060_say = "Estall\243 una guerra entre los dos hermanos, que[ENTER]gan\243 el Dios Drag\243n. Los rumores cuentan que a\250n[ENTER]pueden encontrarse indicios de la batalla en el[ENTER]lugar de su altercado. Beran-Setau fue encerrado[ENTER]en una cueva tras su derrota, que pas\243 a[ENTER]conocerse entonces como la Gruta del Exilio. "
gameforge.heavens_cave_keyquest._070_say = "La gruta est\225 sellada y custodiada por miembros[ENTER]de la orden de Baljit-Elvedin. Tienes que[ENTER]entregar una Piedra de Sangre para ser autorizado[ENTER]a entrar. S\233 como producir esas piedras, pero no[ENTER]es f\225cil. "
gameforge.heavens_cave_keyquest._080_say = "Todo comenz\243 con las l\225grimas que el Dios Drag\243n[ENTER]derram\243 por su hermana, que entonces se[ENTER]convirtieron en piedras que cayeron sobre la[ENTER]tierra. Todav\237a puedes encontrarlas en la Tierra[ENTER]de Fuego de Doyyumhwan. Consigue siete de esas[ENTER]l\225grimas y cuatro piezas de Obsidiana de las[ENTER]Llamas que viven all\237 y tr\225emelas. "
gameforge.heavens_cave_keyquest._090_say_reward = "Recoge 7 L\225grimas Petrificadas y 4 piezas de[ENTER]Obsidiana en Doyyumhwan. "
gameforge.heavens_cave_keyquest._100_say = "\191Necesitas otra Piedra de Sangre para pasar el[ENTER]Guardi\225n de la Orden? Entonces recoge otras siete[ENTER]L\225grimas Petrificadas y cuatro piezas de[ENTER]Obsidiana en la Tierra de Fuego de Doyyumhwan. "
gameforge.heavens_cave_keyquest._110_say = "\191Necesitas otra Piedra de Sangre? Koe-Pung no es[ENTER]el m\225s listo, pero deber\237as esperar un poco, de[ENTER]otro modo puede que se de cuenta de que no[ENTER]perteneces a su orden. "
