gameforge.heavens_cave_keyquest._300_say = "\161Las l\225grimas de Baljit-Elvedin! Las transformar\233[ENTER]de nuevo a su estado l\237quido y las pondr\233 dentro[ENTER]de la Obsidiana. \161Su poder te permite llamar a la[ENTER]Diosa Bahar-Taraji! "
gameforge.heavens_cave_keyquest._310_say = "Su esp\237ritu todav\237a deambula por la tierra. Su[ENTER]voz te hablar\225 cuando lleves las l\225grimas[ENTER]contigo. \161B\250scala en el Bosque Rojo de Lungsam! "
gameforge.heavens_cave_keyquest._320_say = "Toma, coge este jarr\243n y busca la voz de[ENTER]Bahar-Taraji. "
gameforge.heavens_cave_keyquest._330_say = "Busca la voz de bahar-Taraji en el \225rea del[ENTER]Bosque Rojo en Lungsam. Aunque no puedas ver el[ENTER]fantasma de la diosa, podr\225s sentir la presencia[ENTER]de su esp\237ritu. "
gameforge.heavens_cave_keyquest._335_say = "Un leve susurro silba a trav\233s del viento: Ve a[ENTER]un lugar seguro... No podemos hablar aqu\237...[ENTER]Haz click en el pergamino de misi\243n para hablarle[ENTER]al fantasma. "
gameforge.heavens_cave_keyquest._340_say = "En la distancia suena la voz de la Diosa[ENTER]asesinada Bahar-Taraji... "
gameforge.heavens_cave_keyquest._350_say = "Las l\225grimas de mi hermano... llor\243 por m\237[ENTER]durante tanto tiempo y todav\237a no ha podido[ENTER]castigar a Beran-Setaou por sus actos. "
gameforge.heavens_cave_keyquest._360_say = "No pudo hacer frente a su hermano Beran-Setaou,[ENTER]el destructor, aquel a quien la gente tem\237a. "
gameforge.heavens_cave_keyquest._370_say = "Pero t\250... \191Qui\233n eres? \161Eres diferente! No le[ENTER]tienes miedo. Por el contrario, veo que est\225s[ENTER]buscando pelea. "
gameforge.heavens_cave_keyquest._380_say = "\161%s! Coge esas gotas de mi sangre. Crea una[ENTER]Piedra de Sangre con ellas y haz que Beran-Setaou[ENTER]pague por sus actos. La Gruta del Exilio no est\225[ENTER]lejos de aqu\237. "
gameforge.heavens_cave_keyquest._390_say = "En la distancia suena la voz de la Diosa[ENTER]asesinada Bahar-Taraji... "
gameforge.heavens_cave_keyquest._400_say = "\161%s! \161Te reconozco! "
gameforge.heavens_cave_keyquest._410_say = "Has tra\237do las l\225grimas de mi hermano para[ENTER]consolarme y por tanto recibir\225s mi sangre como[ENTER]recompensa, para que puedas seguir luchando. "
gameforge.heavens_cave_keyquest._420_say = "Vuelve con Seon-Hae con la sangre de Bahar-Taraji. "
gameforge.heavens_cave_keyquest._430_say = "Los ojos de Seon-Hae se ponen vidriosos mientras[ENTER]coge las Gotas de Sangre... "
gameforge.heavens_cave_keyquest._440_say = "\161La sangre de una Diosa verdadera! R\225pido, d\233jame[ENTER]convertirla en una Piedra de Sangre antes de que[ENTER]se seque. "
gameforge.heavens_cave_keyquest._450_say = "El guardi\225n Koe-Pung te dejar\225 usar el portal que[ENTER]conduce a la Gruta del Exilio si tienes una[ENTER]Piedra de Sangre. Sin embargo, s\243lo funcionar\225[ENTER]una vez. Si necesitas m\225s piedras de sangre,[ENTER]vuelve a verme. Por desgracia, s\243lo puedo[ENTER]producir una Piedra de Sangre al d\237a, para no[ENTER]atraer la Furia de la Orden. "
gameforge.heavens_cave_keyquest._460_say_reward = "Seon-Hae puede producir m\225s Piedras de Sangre[ENTER]para ti, pero s\243lo una al d\237a. "
gameforge.heavens_cave_keyquest._470_say = "Voy a convertir la sangre de Bahar-Taraji en una[ENTER]Piedra de Sangre. Puede que te sirva bien. "
gameforge.heavens_cave_keyquest._480_say_reward = "S\243lo puedo hacerte una Piedra de Sangre al d\237a.[ENTER]De otro modo puede que Koe-Pung sospeche. "
