gameforge.horse_guard = {}
gameforge.horse_guard._10_npcChat = "Informaci\243n sobre caballos "
gameforge.horse_guard._20_say = "Para comenzar una misi\243n de caballo, necesitas[ENTER]una medalla de caballo. Puedes conseguir una en[ENTER]la mazmorra de los monos. "
gameforge.horse_guard._30_say = "Hay caballos para tres niveles de jinetes:[ENTER]principiante, intermedio y experto.[ENTER]Si entrenas lo suficiente y quieres alcanzar el[ENTER]siguiente nivel, tienes que pasar una prueba. "
gameforge.horse_guard._40_say = "Los caballos necesitan un tipo distinto de comida[ENTER]dependiendo de su nivel. Los caballos[ENTER]principiantes comen heno, los intermedios comen[ENTER]zanahorias y los expertos ginseng rojo.[ENTER]Puedes dar por seguro que son m\225s exigentes que[ENTER]los humanos. "
gameforge.horse_guard._50_say = "Si el caballo est\225 sano, se muestra con un[ENTER]indicador verde. Si se vuelve amarillo, significa[ENTER]que tu caballo est\225 hambriento. Si est\225 rojo, tu[ENTER]caballo se est\225 muriendo de hambre. Tienes que[ENTER]darle de comer para que vuelva de amarillo o rojo[ENTER]a verde. Un caballo muerto es algo muy serio. "
gameforge.horse_guard._60_say = "Cuando montas tu caballo, su salud se acaba[ENTER]lentamente y se queda exhausto. No puedes montar[ENTER]un caballo sin salud. Por consiguiente, tienes[ENTER]que dejarle descansar ocasionalmente. "
gameforge.horse_guard._70_say = "Hay rumores de que un caballo muerto puede ser[ENTER]resucitado con hierbas solares. Pero esas hierbas[ENTER]est\225n custodiadas por los monos y parece que es[ENTER]dif\237cil conseguirlas. Se dice que si te atrapan[ENTER]los monos, te maldicen y te transformas en uno de[ENTER]ellos. "
gameforge.horse_guard._80_say = "Hay diferentes habilidades de monta. Adem\225s,[ENTER]puedes aumentar el nivel de tu caballo para que[ENTER]se vuelva m\225s fuerte. Pero s\243lo personas con una[ENTER]medalla de caballo pueden aumentar el nivel de[ENTER]sus caballos. "
