gameforge.locale.bookworm.accept_success_say_1 = "Aqu\237 est\225, \161el libro Milgyo! "
gameforge.locale.bookworm.accept_success_say_2 = "\161Aqu\237 est\225 el libro Milgyo! Ll\233vaselo a Soon a la[ENTER]aldea. "
gameforge.locale.bookworm.aranyeo_complete_say = "\191Qu\233 botarate consigui\243 este libro extra\241o para[ENTER]mi marido?[ENTER]Est\225 mirandolo todo el d\237a, aprendiendo c\225nticos[ENTER]extra\241os. \161Ya no hace ni el m\225s m\237nimo esfuerzo![ENTER]\161Romper\233 cada uno de sus huesos si le pongo las[ENTER]manos encima! "
gameforge.locale.bookworm.aranyeo_complete_say2 = "Aranyo: \191Qu\233 pasa? \191A qu\233 vienen esos sudores[ENTER]fr\237os? "
gameforge.locale.bookworm.aranyeo_start_say = "\191D\243nde fue? \161Es tan molesto! Malgasta sus d\237as[ENTER]leyendo libros, \161sin ganar ni un solo Yang! \161Ni[ENTER]siquiera le da verg\252enza hacerlo delante de los[ENTER]ni\241os! "
gameforge.locale.bookworm.aranyeo_start_say2 = "\191Pueden poner comida en tu mesa o conseguirte[ENTER]ropa los libros? \161Le romper\233 los huesos si le[ENTER]cojo! "
gameforge.locale.bookworm.aranyeo_talk = "Hablar. "
gameforge.locale.bookworm.complete_say = "Soon: \161Aja! S\237, lo veo. \161Lo veo! \161Veo el nuevo[ENTER]mundo! "
gameforge.locale.bookworm.do_you_find_the_book = "\191Has encontrado el libro Milgyo? "
gameforge.locale.bookworm.do_you_mean_this_book = "\191Este es el libro? "
gameforge.locale.bookworm.etc_shop_start_say = "Vino ayer. Qu\233 es lo que \233l quer\237a... el libro[ENTER]Milgyo o algo as\237.[ENTER]No ten\237a Yang, pero de todos modos sigui\243[ENTER]preguntando. Milgyo puede estar conectado a ese[ENTER]brutal tipo del valle Seungryong. \161Ni idea de por[ENTER]qu\233 est\225 interesado en monstruosidades como esa[ENTER]tan de repente! "
gameforge.locale.bookworm.etc_shop_start_say2 = "Vendedora: Verdaderamente hay que lamentarse por[ENTER]Aranyo.[ENTER]\191Por qu\233 se hace eso? *suspiro* "
gameforge.locale.bookworm.etc_shop_talk_about_bookworm = "Sobre Soon el rat\243n de biblioteca. "
gameforge.locale.bookworm.order_accept = "\161Bien! \161Voy a conseguirlo para t\237! "
gameforge.locale.bookworm.order_accept_answer = "Soon: \161Gracias! Cuento contigo. "
gameforge.locale.bookworm.order_find_book_label = "\161Mata al disc\237pulo de Milgyo! "
gameforge.locale.bookworm.order_find_book_text_1 = "\161Mata al disc\237pulo de Milgyo! "
gameforge.locale.bookworm.order_find_book_text_2 = "Coge el libro Milgyo del disc\237pulo. "
gameforge.locale.bookworm.order_refuse = "Eso debe ser bastante dif\237cil. "
gameforge.locale.bookworm.order_refuse_answer = "Soon: \191Por qu\233 no lo intentas? \161S\233 que puedes[ENTER]hacerlo! "
gameforge.locale.bookworm.order_say1 = "Soon: \191Quieres escuchar algo divertido?[ENTER]\161Realmente no puedo decir que haya le\237do todos[ENTER]los libros de este mundo! Ahora mismo, estoy[ENTER]estudiando textos sagrados escritos por santos.[ENTER]Se rumorea que pueden ser encontradas[ENTER]informaciones secretas y pistas sobre convertirse[ENTER]en santo en el libro Milgyo. "
gameforge.locale.bookworm.order_say2 = "Soon: \161Quiero tener y leer este libro! \191Qu\233[ENTER]piensas?[ENTER]\191Puedes conseguirlo para m\237? Si lo consigues, te[ENTER]recompensar\233. Incluso si tengo que vender mi[ENTER]casa, \161te recompensar\233! "
gameforge.locale.bookworm.order_too_late = "Soon: Otro ya me trajo el libro Milgyo.[ENTER]Ya no tienes que hacerlo. "
gameforge.locale.bookworm.start_find_bookworm_label = "Ve a ver a Soon "
gameforge.locale.bookworm.start_find_bookworm_text_1 = "Ve a ver a Soon "
gameforge.locale.bookworm.start_find_bookworm_text_2 = "Ve con Soon y preg\250ntale sobre el libro Milgyo. "
gameforge.locale.bookworm.start_say = "\191Puedes ver la sabidur\237a de esta carta? Las[ENTER]palabras forman frases y as\237 es como se hace una[ENTER]historia larga. Tienes que acostumbrarte a esto[ENTER]primero, y no es del gusto de todos. "
gameforge.locale.bookworm.start_say2 = "Cuanto m\225s tienes, m\225s consigues.[ENTER]Cuanto m\225s saber, m\225s diversion obtienes.[ENTER]Ah, si s\243lo pudiera leer libros mi vida entera... "
