gameforge.locale.forked_condition = "Tenemos que encontrar al guardi\225n del portal[ENTER]antes de que lo haga otro de los reinos.[ENTER]\161Tenemos que mostrar y expandir el poder de[ENTER]nuestro reino! "
gameforge.locale.forked_condition2 = "Todo lo que tenemos que hacer ahora es exterminar[ENTER]a aquellos que est\225n violando el terreno santo.[ENTER]\161Al ataque! "
gameforge.locale.forked_enter = "Participar "
gameforge.locale.forked_kill_boss = "\161Ahhhhhh! \161Gusanos! \161Soy Thorr Sarch![ENTER]\161Ahhhhh![ENTER]\161Volver\233 encarnado en huestes diab\243licas! Yo,[ENTER]Thorr Sarch, \161no estoy muerto![ENTER][ENTER]Has finalizado la Batalla de Reinos.[ENTER]Todo el mundo va a ser transportado a la aldea. "
gameforge.locale.forked_man_chat = "Participar en la Batalla de Reinos "
gameforge.locale.forked_man_say = "Administrador de batalla[ENTER]\161Je! Se ha descubierto un nuevo \225rea. Puede[ENTER]conectar todos los reinos. Est\225 abarrotada de[ENTER]monstruos; \161el reino necesita tu ayuda! \191Puedes[ENTER]dirigirte all\237? Derrota a todos los enemigos para[ENTER]devolver la paz a nuestro reino. "
gameforge.locale.forked_man_say_cant = "Administrador de batalla[ENTER]\161Je! Se ha descubierto una nueva \225rea. Puede[ENTER]conectar todos los reinos. Una vez est\233 hecha la[ENTER]investigaci\243n, podr\225s entrar en el \225rea. "
gameforge.locale.forked_no_enter = "No participar "
gameforge.locale.forked_open_gate = "Las puertas, que han estado cerrada hasta ahora,[ENTER]se han abierto. \161Dirij\225monos a tierras nuevas![ENTER]\161Vamos a conquistarlas! Todos los guerreros est\225n[ENTER]siendo transportados al Terreno Sagrado. "
gameforge.locale.forked_rule = "Reglas para entrar a la Batalla de Reinos:[ENTER]1. Todo el que muere en este \225rea es transportado[ENTER]de vuelta a la aldea, pero el Alguacil de Batalla[ENTER]puede traerlo de regreso inmediatamente.[ENTER]2. Una vez que las puertas del Terreno Sagrado[ENTER]hayan sido abiertas, esta \225rea es cerrada.[ENTER]3. Para abrir las puertas que conducen al Terreno[ENTER]Sagrado, se debe encontrar la llave[ENTER]correspondiente. "
gameforge.locale.forked_rule_sungzi = "Reglas de la Batalla de Reinos:[ENTER]1. El reino con el menor n\250mero de victorias[ENTER]contra otro reino, es eliminado primero.[ENTER]2. Aparecer\225n monstruos enemigos. El primer reino[ENTER]que elimine a un determinado n\250mero de monstruos[ENTER]gana. 3. Si se elimina al Nueve Colas despu\233s de[ENTER]eso, la batalla termina.[ENTER]4. No se pueden obtener objetos durante la[ENTER]batalla.[ENTER]5. Quienquiera que muere tres veces en el[ENTER]Terrenos Sagrado, vuelve a la aldea y es[ENTER]eliminado de la Batalla de Reinos. "
gameforge.locale.fortune_words_1_body = "\161Por los Dioses! \161La fortuna te sonr\237e! \161Si\233ntela[ENTER]fluir a trav\233s de tu cuerpo! \161Hoy tienes[ENTER]\"abundancia de buena suerte\"![ENTER]Gracias al flujo de chi arm\243nico, \161hoy te[ENTER]ocurrir\225 algo bueno! "
gameforge.locale.fortune_words_1_title = "\161Una gran suerte! "
gameforge.locale.fortune_words_2_body = "Qu\233 maravilla: como reza el dicho... el que[ENTER]siembra, recoge. \161Hoy tendr\225s \"buena suerte\"! Me[ENTER]alegro mucho por ti. Con poco esfuerzo recibir\225s[ENTER]mucho m\225s que antes. "
gameforge.locale.fortune_words_2_title = "\161Gran suerte! "
gameforge.locale.fortune_words_3_body = "No est\225 mal: hoy tienes \"algo de suerte\".[ENTER]Esto significa que tendr\225s m\225s suerte de lo[ENTER]normal, pero no esperes grandes regalos. "
gameforge.locale.fortune_words_3_title = "Un poco de suerte "
gameforge.locale.fortune_words_4_body = "Nada bueno, \161pero tampoco nada malo! Hoy tendr\225s[ENTER]una \"suerte normal\". Esto no te ayudar\225 tanto,[ENTER]pero al menos no vas a tener mala suerte. Los[ENTER]d\237as normales no est\225n nada mal, \161disfr\250talos! "
gameforge.locale.fortune_words_4_title = "Suerte normal. "
gameforge.locale.fortune_words_5_body = "Hoy la fortuna no te acompa\241a. Si lanzas una red,[ENTER]no cazar\225s muchos peces, pero tampoco morir\225s de[ENTER]hambre. Tienes \"algo de mala suerte\". Eso s\237: no[ENTER]hay nada como estar preparado.[ENTER]Si te interesa, tengo un Talism\225n que alejar\225 lo[ENTER]peor de la mala suerte. \191Quieres comprarlo? "
gameforge.locale.fortune_words_5_title = "Algo de mala suerte "
gameforge.locale.fortune_words_6_body = "Hoy es un mal d\237a. Un d\237a en el que incluso dando[ENTER]lo mejor de ti, no conseguir\225s casi nada. Hoy[ENTER]tienes \"mala suerte\". Has de tener cuidado con lo[ENTER]que haces. No obstante, puedo echarte una mano.[ENTER]Si te interesa, tengo un Talism\225n que alejar\225 lo[ENTER]peor de la mala suerte.[ENTER]\191Quieres comprarlo? "
gameforge.locale.fortune_words_6_title = "Mala suerte "
gameforge.locale.fortune_words_7_body = "Hoy es un d\237a desastroso. Todos los Dioses te han[ENTER]dado la espalda. Nada funcionar\225... Si quieres[ENTER]hacer un fuego, llover\225; si tienes sed, el sol[ENTER]arder\225 como nunca. Trabajar\225s tan duro como los[ENTER]dem\225s, pero no conseguir\225s nada.[ENTER]\161Tendr\225s \"muy mala suerte\"! Sin un Talism\225n, te[ENTER]esperan tiempos dif\237ciles. \191Te interesar\237a[ENTER]comprar uno? "
gameforge.locale.fortune_words_7_title = "Extemada mala suerte "
