gameforge.locale.make_wonso.how_make = "\191C\243mo puedo preparar Bolas de Arroz? "
gameforge.locale.make_wonso.how_make_detail = "Cuando cazas monstruos, puedes encontrar varios[ENTER]ingredientes para las bolas de arroz: Pasta de[ENTER]Alubia, Pasta de Az\250car, Pasta de Fruta y Arroz[ENTER]Dulce. Si me traes estas pastas y una porci\243n de[ENTER]Arroz Dulce, puedo prepararte una Bola de Arroz.[ENTER]Por lo visto, pasa algo especial cuando te la[ENTER]comes... "
gameforge.locale.make_wonso.make_msg1 = "\191Tienes los ingredientes necesarios? Perfecto,[ENTER]necesito la Pasta de Alubia y el Arroz Dulce para[ENTER]prepararte un ... Pastel de Frutas. \161Que[ENTER]aproveche! "
gameforge.locale.make_wonso.make_msg2 = "\191Tienes los ingredientes necesarios? Perfecto,[ENTER]necesito la Pasta de Az\250car y el Arroz Dulce para[ENTER]prepararte un... Pastel de Az\250car.\161Que aproveche! "
gameforge.locale.make_wonso.make_msg3 = "\191Tienes los ingredientes necesarios? Perfecto,[ENTER]necesito la Pasta de Fruta y el Arroz Dulce para[ENTER]prepararte un ... Pastel de Frutas. \161Que[ENTER]aproveche! "
