gameforge.locale.monster_chat = {}
gameforge.locale.monster_chat_1001_1 = "Jeje, \161todo el mundo morir\225! \161Kyaaaa! "
gameforge.locale.monster_chat_1001_2 = "\161Trozos, trozos, trozos, trozos! "
gameforge.locale.monster_chat_1001_3 = "\161No hay forma de escapar! "
gameforge.locale.monster_chat_1001_4 = "El suelo quedar\225 impregnado con tu sangre. \161Muere! "
gameforge.locale.monster_chat_1001_5 = "\161Puedes suplicar, pero eso no te har\225 ning\250n bien! "
gameforge.locale.monster_chat_1001_6 = "\161No puedes esconder tu miedo de m\237! "
gameforge.locale.monster_chat_1002_1 = "\161Muerte! Muerte a todo el mundo... "
gameforge.locale.monster_chat_1002_2 = "\161Cerdos miserables! "
gameforge.locale.monster_chat_1002_3 = "Est\225s empezando a hacerme enfadar... "
gameforge.locale.monster_chat_1002_4 = {}
gameforge.locale.monster_chat_1002_5 = "Habr\225 sangre, humana. "
gameforge.locale.monster_chat_1003_1 = "\161Muerte y Perdici\243n...! "
gameforge.locale.monster_chat_1003_2 = "\191Has visto las heridas que puede hacer una lanza en tu piel? "
gameforge.locale.monster_chat_1003_3 = "S\237, vamos, \161m\225rchate! Veremos hasta donde llegas... "
gameforge.locale.monster_chat_1003_4 = "S\243lo mirar tus manos temblorosas hace que este rato merezca la pena completamente... "
gameforge.locale.monster_chat_1003_5 = "\191T\250, pedazo de escoria, te atreves a desafiarme? "
gameforge.locale.monster_chat_1003_6 = "\161La muerte ser\225 tu \250nica acompa\241ante en el futuro! "
gameforge.locale.monster_chat_1004_1 = "\161Tu alma ser\225 m\237a, humano! "
gameforge.locale.monster_chat_1004_2 = "Ah, \161sangre fresca! "
gameforge.locale.monster_chat_1004_3 = "\161Parece que otra persona va a encontrar su muerte aqu\237! "
gameforge.locale.monster_chat_1004_4 = "Tienes que sufrir y sacar toda tu angustia... "
gameforge.locale.monster_chat_1004_5 = "\191Realmente piensas que esa rid\237cula arma de tu mano ser\225 capaz de protegerte? "
gameforge.locale.monster_chat_1004_6 = "Tu coraje te trajo hasta m\237. Y ahora va a dejarte... "
gameforge.locale.monster_chat_1035_1 = "Si muero, \161mi venganza te seguir\225 por toda la eternidad! "
gameforge.locale.monster_chat_1035_2 = "Har\233 que mueras y sufras despacio, muy despacio... "
gameforge.locale.monster_chat_1035_3 = "Mi placer ser\225 hacerte sufrir. "
gameforge.locale.monster_chat_1035_4 = "\161Tu cuerpo est\225 temblando como el de una vieja bruja senil! "
gameforge.locale.monster_chat_1035_5 = "Puedo oler tu miedo, peque\241o. "
gameforge.locale.monster_chat_1035_6 = "Creo que es tiempo de liberarte de unas cuantas partes de tu cuerpo. "
gameforge.locale.monster_chat_1036_1 = "\161Voy a mandarte a tu propio infierno personal! "
gameforge.locale.monster_chat_1036_2 = "Tu dolor te volver\225 loco, incluso antes de que mueras... "
gameforge.locale.monster_chat_1036_3 = "\161Puedes sollozar! \161Puedes suplicar! Pero eso no te har\225 ning\250n bien. "
gameforge.locale.monster_chat_1036_4 = "Vas a experimentar la peor muerte que puedas imaginar... "
gameforge.locale.monster_chat_1036_5 = {}
gameforge.locale.monster_chat_1036_6 = "Tu poder se est\225 debilitando. Ya est\225s al borde de la muerte... "
gameforge.locale.monster_chat_1037_1 = "\191Est\225s preparado para caminar hacia los pasillos de la muerte por la eternidad? "
gameforge.locale.monster_chat_1037_2 = "Deber\237as acostumbrarte a la idea de recibir oscuridad eterna... "
gameforge.locale.monster_chat_1037_3 = "Bienvenido al infierno (risotada) "
gameforge.locale.monster_chat_1037_4 = "\161Grita tanto como quieras! \161Nadie va a oirte! "
gameforge.locale.monster_chat_1037_5 = "Si crees que puedes matarme as\237... \161eres m\225s ingenuo de lo que pensaba! "
gameforge.locale.monster_chat_1037_6 = "No est\225 mal, pero eso a\250n no podr\225 salvarte de tu muerte. "
gameforge.locale.monster_chat_1038_1 = "Esto es el infierno "
gameforge.locale.monster_chat_1038_2 = "Voy a despellejar la piel de tus huesos. "
gameforge.locale.monster_chat_1038_3 = "Quiero oirte lloriquear antes de que mueras. "
gameforge.locale.monster_chat_1038_4 = "Sabes que no tiene sentido tener esperanza, \191no? "
gameforge.locale.monster_chat_1038_5 = {}
gameforge.locale.monster_chat_1038_6 = "No, a\250n no vas a morir. Primero quiero que sepas cuantos golpes de espada puede soportar tu cuerpo. "
gameforge.locale.monster_chat_1039_1 = "Hasta que venga alguien nuevo... "
gameforge.locale.monster_chat_1039_2 = "\191Realmente piensas que tienes la m\225s m\237nima posibilidad de escapar? "
gameforge.locale.monster_chat_1039_3 = "No es el suelo lo que se mueve... \161son tus rodillas que est\225n estremeci\233ndose de miedo! "
gameforge.locale.monster_chat_1039_4 = "\161Bienvenido al lugar en el que encontrar\225s tu muerte! "
gameforge.locale.monster_chat_1039_5 = "Puedo ver el p\225nico en tus ojos. "
gameforge.locale.monster_chat_1039_6 = "Oh, tan j\243ven y tan indefenso... "
gameforge.locale.monster_chat_1040_1 = "Vemos todos tus movimientos. "
gameforge.locale.monster_chat_1040_2 = "\191Apresurado? \191Realmente quieres morir? "
gameforge.locale.monster_chat_1040_3 = "La muerte ya ha ocupado su lugar a tu lado... "
gameforge.locale.monster_chat_1040_4 = "\191Puedes oir mi campana repicando? \161Ser\225 la \250ltima cosa que oigas! "
gameforge.locale.monster_chat_1040_5 = "Si esta herida no deja de sangrar, ser\225 peligroso para ti... "
gameforge.locale.monster_chat_1040_6 = "Puedes luchar... o puedes dejar que la muerte te abrace... "
gameforge.locale.monster_chat_1041_1 = "\191Por qu\233 est\225s aqu\237 si quieres vivir? "
gameforge.locale.monster_chat_1041_2 = "Ah, \161cuerpos nuevos para destruir! "
gameforge.locale.monster_chat_1041_3 = "\161Fue tu decisi\243n el venir aqu\237, humano! Y ahora tendr\225s que vivir con las consecuencias... "
gameforge.locale.monster_chat_1041_4 = "Resucitamos. \161No podemos morir! "
gameforge.locale.monster_chat_1041_5 = "\161No tiene sentido atacarnos! (risotada) "
gameforge.locale.monster_chat_1041_6 = "Qu\233 conseguir\225s: \191agotamiento o muerte? "
gameforge.locale.monster_chat_1091_1 = "Has llegado hasta aqu\237... y ahora voy a mandarte a tu muerte. "
gameforge.locale.monster_chat_1091_2 = "\161Sacrifica tu alma y convi\233rtete en uno de nosotros! "
gameforge.locale.monster_chat_1091_3 = "\161M\237rate! D\233bil y lento... "
gameforge.locale.monster_chat_1091_4 = "\161Tu cuerpo y tu alma son m\237os! (risotada) "
gameforge.locale.monster_chat_1091_5 = "\191Agotado? Tus piernas est\225n temblando... "
gameforge.locale.monster_chat_1091_6 = "\191Cu\225nto tiempo eres capaz de seguir as\237? (risotada) "
gameforge.locale.monster_chat_1093_1 = "\191Qui\233n hubiera imaginado que hay algo peor que la muerte? "
gameforge.locale.monster_chat_1093_2 = "Bienvenido, hambriento de muerte. "
gameforge.locale.monster_chat_1093_3 = "Pagar\225s por tu indiscreci\243n. Con sangre y tu alma. "
gameforge.locale.monster_chat_1093_4 = "Despu\233s de haber destruido tu cuerpo, \161tu alma ser\225 m\237a! "
gameforge.locale.monster_chat_1093_5 = "\191Cu\225nto tiempo puedes aguantar? \191Uh? "
gameforge.locale.monster_chat_1093_6 = "Eres divertido. Tu miedo y tu prisa me divierten... "
gameforge.locale.monster_chat_11000_1 = "\161Todos aquellos preocupados por su desarrollo deben escuchar! "
gameforge.locale.monster_chat_11000_10 = "Si quieres controlar el poder de la Naturaleza y el rayo, \161recomiendo el entrenamiento de la Fuerza Curaci\243n! "
gameforge.locale.monster_chat_11000_11 = "\161Cada guerrero es diferente en su modo de pelear! \161C\233ntrate en endurecer tu cuerpo! "
gameforge.locale.monster_chat_11000_12 = "La fuerza del Sura es la magia. \161Trabaja en tu inteligencia, velocidad y fuerza corporal! "
gameforge.locale.monster_chat_11000_13 = "\161Usa las habilidades del ninja! \161C\233ntrate en la velocidad y la fuerza corporal! "
gameforge.locale.monster_chat_11000_14 = "Los chamanes usan hechizos de regeneraci\243n, apoyo y combate. \161La inteligencia es vital! "
gameforge.locale.monster_chat_11000_15 = "\161No olvides tu aprendizaje! "
gameforge.locale.monster_chat_11000_16 = "\161Convi\233rtete en aprendiz si quieres entrenar tus habilidades! "
gameforge.locale.monster_chat_11000_17 = "\191Habilidades? Puedes ascender al rango de un maestro, se extiende aleatoriamente entre los niveles 17 y 21. "
gameforge.locale.monster_chat_11000_18 = "\191Quieres convertirte en un gran maestro? \161Entonces necesitas un Manual de Habilidad especial! "
gameforge.locale.monster_chat_11000_19 = "\161En cuanto hayas terminado de leer el Manual de Habilidad, \233ste desaparece! "
gameforge.locale.monster_chat_11000_2 = "\161Todos los guerreros a partir del nivel 5, escuchadme! "
gameforge.locale.monster_chat_11000_20 = "\191Quieres leer el Manual de Habilidad otra vez? Entonces espera un d\237a. "
gameforge.locale.monster_chat_11000_21 = "\161Aumenta tu inteligencia para mejorar tus habilidades Sura! "
gameforge.locale.monster_chat_11000_22 = "\161Experimenta los grandes poderes de un Sura en combate! "
gameforge.locale.monster_chat_11000_23 = "\191Sabes d\243nde est\225 el templo de la secta misteriosa? \161Est\225 en medio del Valle de Seungryong! "
gameforge.locale.monster_chat_11000_24 = "\161Las cuevas de ara\241as han aparecido otra vez! \161Est\225n en el desierto Yongbi! "
gameforge.locale.monster_chat_11000_25 = "\161Finaliza tus misiones y utiliza las recompensas para mejorar! "
gameforge.locale.monster_chat_11000_26 = "\191Pesca? \161Suena genial! \191Ya has conseguido una ca\241a y cebo de un pescador? "
gameforge.locale.monster_chat_11000_27 = "\191Quieres encontrar algo m\225s fuerte para cazar? \161Busca un portal! \161Ve a un \225rea de caza apropiada para tu nivel! "
gameforge.locale.monster_chat_11000_28 = "Ten cuidado de los enemigos de otros reinos. Nunca se sabe cuando te van a dar una pu\241alada por la espalda. "
gameforge.locale.monster_chat_11000_29 = "\191Quieres restaurar tus habilidades? \161Ve con la anciana! \161Aseg\250rate de llevar suficiente Yang! "
gameforge.locale.monster_chat_11000_3 = "\161Ve a entrenar con el maestro asesino si quieres ser conocido como un poderoso guerrero ofensivo! "
gameforge.locale.monster_chat_11000_30 = "\161Aspira al rango de maestro perfecto! \161Es el \250nico modo en el que puedes convertirte en un h\233roe verdadero! "
gameforge.locale.monster_chat_11000_31 = "Si quieres ir a otro campo de batalla o ciudad, busca a los ancianos en el continente. "
gameforge.locale.monster_chat_11000_4 = "Si quieres ser un experto en las habilidades del guerrero, ve y aprende del maestro del arte de la guerra. "
gameforge.locale.monster_chat_11000_5 = "Si quieres ser un Sura capaz de usar espadas m\225gicas, \161elige entrenamiento de armamento! "
gameforge.locale.monster_chat_11000_6 = "\161Elige el entrenamiento de magia negra si quieres ser experto usando hechizos negros! "
gameforge.locale.monster_chat_11000_7 = "\161El entrenamiento arquero est\225 reservado para ninjas que han alcanzado el nivel 5! "
gameforge.locale.monster_chat_11000_8 = "Si quieres convertirte en un ninja secreto, elige el entrenamiento de asesino. "
gameforge.locale.monster_chat_11000_9 = "Si quieres controlar batallas como el guerrero del Dios Drag\243n, \161elige las ense\241anzas del Dios Drag\243n! "
gameforge.locale.monster_chat_11002_1 = "\161Escuchad, todos aquellos que os preocup\225is por vuestra salud! "
gameforge.locale.monster_chat_11002_10 = "Si quieres controlar el poder de la naturaleza y el rayo, \161entra en entrenamiento de la Fuerza Curaci\243n! "
gameforge.locale.monster_chat_11002_11 = "Cada Guerrero es diferente en su modo de luchar. \161Fortalece tu cuerpo! "
gameforge.locale.monster_chat_11002_12 = "La fuerza del Sura es la magia. Trabaja en tu inteligencia, velocidad y fuerza corporal. "
gameforge.locale.monster_chat_11002_13 = "\161Lleva las habilidades del ninja a un nivel superior! \161C\233ntrate en la velocidad y fuerza corporal! "
gameforge.locale.monster_chat_11002_14 = "Los chamanes usan hechizos de regeneraci\243n, apoyo y combate. \161La inteligencia es vital para ello! "
gameforge.locale.monster_chat_11002_15 = "\161No olvides el entrenamiento! "
gameforge.locale.monster_chat_11002_16 = "\161Convi\233rtete en aprendiz si quieres entrenar tus habilidades! "
gameforge.locale.monster_chat_11002_17 = "\191Habilidades? Puedes ascender al rango de un maestro, se extiende aleatoriamente entre los niveles 17 y 21. "
gameforge.locale.monster_chat_11002_18 = "\191Quieres convertirte en un gran maestro? \161Entonces necesitas un Manual de Habilidad especial! "
gameforge.locale.monster_chat_11002_19 = "\161En cuanto hayas terminado de leer el Manual de Habilidad, \233ste desaparece! "
gameforge.locale.monster_chat_11002_2 = "\161Todos los guerreros a partir del nivel 5, escuchadme! "
gameforge.locale.monster_chat_11002_20 = "\191Quieres leer el Manual de Habilidad otra vez? Entonces espera un d\237a. "
gameforge.locale.monster_chat_11002_21 = "\161Aumenta tu inteligencia para mejorar tus habilidades Sura! "
gameforge.locale.monster_chat_11002_22 = "\161Experimenta los grandes poderes de un Sura en combate! "
gameforge.locale.monster_chat_11002_23 = "\191Sabes d\243nde est\225 el templo de la secta misteriosa? \161Est\225 en medio del Valle de Seungryong! "
gameforge.locale.monster_chat_11002_24 = "\161Las cuevas de ara\241as han aparecido otra vez! \161Est\225n en el desierto Yongbi! "
gameforge.locale.monster_chat_11002_25 = "\161Finaliza tus misiones y utiliza las recompensas para mejorar! "
gameforge.locale.monster_chat_11002_26 = "\191Pesca? \161Suena genial! \191Ya has conseguido una ca\241a y cebo de un pescador? "
gameforge.locale.monster_chat_11002_27 = "\191Quieres encontrar algo m\225s fuerte para cazar? \161Busca un portal! \161Ve a un \225rea de caza apropiada para tu nivel! "
gameforge.locale.monster_chat_11002_28 = "Ten cuidado de los enemigos de otros reinos. Nunca se sabe cuando te van a dar una pu\241alada por la espalda. "
gameforge.locale.monster_chat_11002_29 = "\191Quieres restaurar tus habilidades? \161Ve con la anciana! \161Aseg\250rate de llevar suficiente Yang! "
