gameforge.locale.monster_chat_11002_30 = "\161Aspira al rango de maestro perfecto! \161Es el \250nico modo en el que puedes convertirte en un h\233roe verdadero! "
gameforge.locale.monster_chat_11002_31 = "Si quieres ir a otro campo de batalla o ciudad, busca a los ancianos en el continente. "
gameforge.locale.monster_chat_11002_4 = "Si quieres ser un experto en las habilidades del guerrero, ve y aprende del maestro del arte de la guerra. "
gameforge.locale.monster_chat_11002_5 = "Si quieres ser un Sura capaz de usar espadas m\225gicas, \161elige entrenamiento de armamento! "
gameforge.locale.monster_chat_11002_6 = "\161Elige el entrenamiento de magia negra si quieres ser experto usando hechizos negros! "
