gameforge.locale.monster_chat_11004_1 = "\161Escuchad, todos aquellos preocupados por vuestra salud! "
gameforge.locale.monster_chat_11004_10 = "\161Si quieres controlar el poder de la naturaleza y el rayo, entonces participa en el entrenamiento de la Fuerza Curaci\243n! "
gameforge.locale.monster_chat_11004_11 = "Cada guerrero es diferente en su modo de lucha. \161Fortalece tu cuerpo! "
gameforge.locale.monster_chat_11004_12 = "La fuerza del Sura es la magia. \161Trabaja en tu inteligencia, velocidad y fuerza corporal! "
gameforge.locale.monster_chat_11004_13 = "\161Lleva las habilidades del ninja a un nivel superior! \161C\233ntrate en la inteligencia y fuerza corporal! "
gameforge.locale.monster_chat_11004_14 = "Los chamanes usan hechizos de regeneraci\243n, apoyo y combate. \161La inteligencia es vital para ello! "
gameforge.locale.monster_chat_11004_15 = "\161No olvides el entrenamiento! "
gameforge.locale.monster_chat_11004_16 = "\161Convi\233rtete en aprendiz si quieres entrenar tus habilidades! "
gameforge.locale.monster_chat_11004_17 = "\191Habilidades? Puedes ascender al rango de un maestro, se extiende aleatoriamente entre los niveles 17 y 21. "
gameforge.locale.monster_chat_11004_18 = "\191Quieres convertirte en un gran maestro? \161Entonces necesitas un Manual de Habilidad especial! "
gameforge.locale.monster_chat_11004_19 = "\161En cuanto hayas terminado de leer el Manual de Habilidad, \233ste desaparece! "
gameforge.locale.monster_chat_11004_2 = "\161Todos los guerreros a partir del nivel 5, escuchadme! "
gameforge.locale.monster_chat_11004_20 = "\191Quieres leer el Manual de Habilidad otra vez? Para poder hacerlo, debes esperar un d\237a. "
gameforge.locale.monster_chat_11004_21 = "\161Aumenta tu inteligencia para mejorar tus habilidades Sura! "
gameforge.locale.monster_chat_11004_22 = "\161Experimenta el poder de un Sura en combate! "
gameforge.locale.monster_chat_11004_23 = "\191Sabes d\243nde est\225 el templo de la secta misteriosa? \161Est\225 en medio del Valle de Seungryong! "
gameforge.locale.monster_chat_11004_24 = "\161Las cuevas de ara\241as han aparecido otra vez! \161Est\225n en el desierto Yongbi! "
gameforge.locale.monster_chat_11004_25 = "\161Finaliza tus misiones y utiliza las recompensas para mejorar! "
gameforge.locale.monster_chat_11004_26 = "\191Pesca? \161Suena genial! \191Ya has conseguido una ca\241a y cebo de un pescador? "
gameforge.locale.monster_chat_11004_27 = "\191Quieres encontrar algo m\225s fuerte para cazar? \161Busca un portal! \161Ve a un \225rea de caza apropiada para tu nivel! "
gameforge.locale.monster_chat_11004_28 = "Ten cuidado de los enemigos de otros reinos. Nunca se sabe cuando te van a dar una pu\241alada por la espalda. "
gameforge.locale.monster_chat_11004_29 = "\191Quieres restaurar tus habilidades? \161Ve con la anciana! \161Aseg\250rate de llevar suficiente Yang! "
gameforge.locale.monster_chat_11004_3 = "\161Ve a entrenar con el maestro asesino si quieres ser conocido como un poderoso guerrero ofensivo! "
gameforge.locale.monster_chat_11004_30 = "\161Aspira al rango de maestro perfecto! \161Es el \250nico modo en el que puedes convertirte en un h\233roe verdadero! "
gameforge.locale.monster_chat_11004_31 = "Si quieres ir a otro campo de batalla o ciudad, busca a los ancianos en el continente. "
gameforge.locale.monster_chat_11004_4 = "Si quieres ser un experto en las habilidades del guerrero, ve y aprende del maestro del arte de la guerra. "
gameforge.locale.monster_chat_11004_5 = "Si quieres ser un Sura capaz de usar espadas m\225gicas, \161elige entrenamiento de armamento! "
gameforge.locale.monster_chat_11004_6 = "\161Elige el entrenamiento de magia negra si quieres ser experto usando hechizos negros! "
gameforge.locale.monster_chat_11004_7 = "\161El entrenamiento arquero est\225 reservado para ninjas que han alcanzado el nivel 5! "
gameforge.locale.monster_chat_11004_8 = "\161Elige el entrenamiento de asesino si quieres ascender por las categor\237as secretas del Ninja! "
gameforge.locale.monster_chat_11004_9 = "Si quieres controlar batallas como el guerrero del Dios Drag\243n, \161elige el entrenamiento de la Fuerza Drag\243n! "
gameforge.locale.monster_chat_1105_1 = "El estado helado es bueno. "
gameforge.locale.monster_chat_1105_2 = "La monta\241a Sohan es sin duda la mejor. "
gameforge.locale.monster_chat_1105_3 = "Qu\233 buen tiempo. "
gameforge.locale.monster_chat_1105_4 = "Ser\225s exactamente como yo. "
gameforge.locale.monster_chat_1105_5 = "Puedes vivir para siempre, al menos hasta que el hielo se derrita. "
gameforge.locale.monster_chat_1105_6 = "\191C\243mo crees que se sentir\225, cuando lentamente te conviertas en un pedazo de hielo? "
gameforge.locale.monster_chat_1106_1 = "Humanos... \161\191aqu\237?! "
gameforge.locale.monster_chat_1106_2 = "Cansado... pero suficientemente despierto para ti... "
gameforge.locale.monster_chat_1106_3 = "\191Alguien aqu\237, en mi colina?  "
gameforge.locale.monster_chat_1106_4 = "\161No tienes sitio aqu\237! "
gameforge.locale.monster_chat_1106_5 = "\161Mejor retrocede! "
gameforge.locale.monster_chat_1106_6 = "Extra\241o... \191tan solitario? "
gameforge.locale.monster_chat_1191_1 = "Ha pasado mucho tiempo desde que vimos a un luchador experimentado aparecer por aqu\237. "
gameforge.locale.monster_chat_1191_2 = "Nada m\225s que hacer salvo esperar y abrillantar armas... "
gameforge.locale.monster_chat_1191_3 = "\191Tengo que trabajar en ellos? "
gameforge.locale.monster_chat_1191_4 = {}
gameforge.locale.monster_chat_1191_5 = "Falta algo. No estoy entretenida. "
gameforge.locale.monster_chat_1191_6 = "\161Voy a acabar con el \250ltimo dolor que has sentido nunca! "
gameforge.locale.monster_chat_1301_1 = "\161Un cuellolargo...! "
gameforge.locale.monster_chat_1301_2 = "Tu p\225lida piel va a palidecer aun m\225s en un minuto. "
gameforge.locale.monster_chat_1301_3 = "\191Quieres pelear conmibo? \161Bien! "
gameforge.locale.monster_chat_1301_4 = "\161Me has atacado! \161Pweck! \161No se te puede permitir sobrevivir! "
gameforge.locale.monster_chat_1301_5 = "\161D\233bil, humano d\233bil! "
gameforge.locale.monster_chat_1301_6 = "\161Veamos cu\225nto puedes aguantar! "
gameforge.locale.monster_chat_1302_1 = "\191Irte? Ni lo pienses. "
gameforge.locale.monster_chat_1302_2 = "Bien... Ac\233rcate... \161Pwiehk! "
gameforge.locale.monster_chat_1302_3 = "La espada est\225 agit\225ndose en mi mano. \161Pwiehk! "
gameforge.locale.monster_chat_1302_4 = "\161No sobrevivir\225s a este encuentro! "
gameforge.locale.monster_chat_1302_5 = "\161Aqu\237 va mi espada! "
gameforge.locale.monster_chat_1302_6 = "Doloroso, \191no? (risotada) "
gameforge.locale.monster_chat_1303_1 = "Incluso la hierba sobre la que estabas parado, puede matar accidentalmente. "
gameforge.locale.monster_chat_1303_2 = "Ten cuidado con la hierba. "
gameforge.locale.monster_chat_1303_3 = "Bien. Ven a m\237. (risotada) "
gameforge.locale.monster_chat_1303_4 = "\191Osas acercarte a m\237? Bien.. \161entonces puedes vivir con las consecuencias! "
gameforge.locale.monster_chat_1303_5 = "\161Muere! \161Muere! "
gameforge.locale.monster_chat_1303_6 = "\191Te arrepientes de haber venido? "
gameforge.locale.monster_chat_1305_1 = "\191Qui\233n me derrotar\225? "
gameforge.locale.monster_chat_1305_2 = "\191T\250? \191Quieres pelear? "
gameforge.locale.monster_chat_1305_3 = "\161Ven aqu\237 si quieres! "
gameforge.locale.monster_chat_1305_4 = "No est\225s pensando en huir, \191no? "
gameforge.locale.monster_chat_1305_5 = "Has infravalorado el alcance de mi espada. "
gameforge.locale.monster_chat_1305_6 = "\191Asustado? (risotada) "
gameforge.locale.monster_chat_1901_1 = "\191A qui\233n transformar\233 hoy? "
gameforge.locale.monster_chat_1901_2 = "Oh, me gustas... "
gameforge.locale.monster_chat_1901_3 = "\191Qu\233 te parece? Mi querida diversi\243n... "
gameforge.locale.monster_chat_1901_4 = "\161Eh! Hazlo bien y no corras como un cobarde. "
gameforge.locale.monster_chat_1901_5 = "\191La visi\243n de m\237 ha hecho ya que un escalofr\237o recorra tu espina dorsal? "
gameforge.locale.monster_chat_1901_6 = "\191No quieres gritar un poco? (risotada) "
gameforge.locale.monster_chat_20001_1 = "Pareces nervioso... Note preocupes que no explotar\225. "
gameforge.locale.monster_chat_20001_2 = "A veces, s\243lo quiero dar un paseo. "
gameforge.locale.monster_chat_20001_3 = "Es tan aburrido. Incluso mis nietos ya no me visitan. "
gameforge.locale.monster_chat_20001_4 = "Cuando te haces viejo, necesitas a otras personas. "
gameforge.locale.monster_chat_20001_5 = "Mis mejores d\237as se han ido. "
gameforge.locale.monster_chat_20002_1 = "El sol es tan c\225lido. "
gameforge.locale.monster_chat_20002_2 = "Magn\237fico tiempo para conseguir que un trapo mojado se seque, \191no? "
gameforge.locale.monster_chat_20002_3 = "\191D\243nde est\225 ese perezoso bueno para nada de marido? "
gameforge.locale.monster_chat_20002_4 = "Se dice a s\237 mismo padre y no se averg\252enza de sus malos h\225bitos, \161incluso delante de sus ni\241os! "
gameforge.locale.monster_chat_20002_5 = "Los libros son libros. No gana dinero. S\243lo lee libros. "
gameforge.locale.monster_chat_20003_1 = "Oooh, dududu, beb\233. \191Has dormido bien? "
gameforge.locale.monster_chat_20003_2 = "Sonr\237es como un peque\241o \225ngel. "
gameforge.locale.monster_chat_20003_3 = "Tu mam\225 es tan feliz porque est\225s sano. "
gameforge.locale.monster_chat_20003_4 = "\191Otra vez quieres algo de atenci\243n? \191Tienes hambre? "
gameforge.locale.monster_chat_20003_5 = "Buen chico... Duerme, mi ni\241o, duerme. "
gameforge.locale.monster_chat_20004_1 = "Un d\237a cualquiera. "
gameforge.locale.monster_chat_20004_2 = "\191D\243nde voy a conseguir algo de comida hoy? "
gameforge.locale.monster_chat_20004_3 = "Es siempre lo mismo con esos portadores de espada. "
gameforge.locale.monster_chat_20004_4 = "Veamos. Quiz\225 deber\237a ir al restaurante de Octavio. "
gameforge.locale.monster_chat_20004_5 = "Oh, por cierto, parece que que no hay m\225s guerra... "
gameforge.locale.monster_chat_20005_1 = "El alma del maestro alfarero corre por las yemas de sus dedos. "
gameforge.locale.monster_chat_20005_2 = "A\250n cuando el pa\237s era un caos, se pod\237an encontrar luchadores por todas partes. "
gameforge.locale.monster_chat_20005_3 = "Todo el mundo quiere luchar. "
gameforge.locale.monster_chat_20005_4 = "Rezo por un mundo tranquilo y pac\237fico. "
gameforge.locale.monster_chat_20005_5 = "Eh, t\250, t\243mate un minuto para relajarte y pensar... "
gameforge.locale.monster_chat_20006_1 = "Oh Dios m\237o, \191qu\233 debo hacer? "
gameforge.locale.monster_chat_20006_2 = "No puedo encontrar el m\225s m\237nimo indicio de mi hermano, pero \233l promet\237o que estar\237a aqu\237. "
gameforge.locale.monster_chat_20006_3 = "Y ahora, todo lo que veo aqu\237 son luchadores con espadas. "
gameforge.locale.monster_chat_20006_4 = "Echo de menos a mi hermano. "
gameforge.locale.monster_chat_20006_5 = "\191Alguien ha visto a mi hermano? "
gameforge.locale.monster_chat_20007_1 = "Hm, \161es una carne realmente fresca! "
gameforge.locale.monster_chat_20007_2 = "Es bueno que la gente coma m\225s carne ahora. "
gameforge.locale.monster_chat_20007_3 = "Los negocios van bien, pero la carne a\250n es poco frecuente. "
gameforge.locale.monster_chat_20007_4 = "\191Cu\225ndo va a llegar la carne que pedimos? "
gameforge.locale.monster_chat_20007_5 = "Si no llega a tiempo, tendremos que ir a cazar. "
gameforge.locale.monster_chat_20008_1 = "Espero que los clientes vengan en tropel ya que el tiempo es tan bueno... "
gameforge.locale.monster_chat_20008_2 = "Seguro que el perro vago vendr\225 pronto, y querr\225 algo de comer. "
gameforge.locale.monster_chat_20008_3 = "Oh Dios m\237o, \161qu\233 hombre tan pobre! "
gameforge.locale.monster_chat_20008_4 = "Sol\237a ser un gran guerrero. "
gameforge.locale.monster_chat_20008_5 = "Me pregunto por qu\233 no lucha m\225s. "
gameforge.locale.monster_chat_20009_1 = "\161Estos jovenzuelos... tan animados y llenos de dinamismo! "
gameforge.locale.monster_chat_20009_2 = "Los guerreros se ven mucho mejor cuando llevan armas. "
gameforge.locale.monster_chat_20009_3 = "Esta mente asesina es algo que todo el mundo tiene hoy en d\237a. "
gameforge.locale.monster_chat_20009_4 = "Controla tu coraz\243n, enfoca tus pensamientos y tranquiliza tu alma. "
gameforge.locale.monster_chat_20009_5 = "No existe ninguna receta infalible para la felicidad, pero s\237 algunas normas simples que puedes seguir. "
gameforge.locale.monster_chat_20010_1 = "\161Te traje un gran objeto! "
gameforge.locale.monster_chat_20010_2 = "\161Mercanc\237as de pa\237ses lejanos, piezas extraordinarias! "
gameforge.locale.monster_chat_20010_3 = "\161Venid aqu\237! Todo el mundo, \161venid! "
gameforge.locale.monster_chat_20010_4 = "Vamos, gente, \161comprad! \161No tendr\233is la oportunidad otra vez! "
gameforge.locale.monster_chat_20010_5 = "Argh, \191por qu\233 hay tantos ladrones aqu\237? "
gameforge.locale.monster_chat_20011_1 = "Son tan secos estos d\237as... "
gameforge.locale.monster_chat_20011_2 = "La cosecha del cereal no es tan buena como sol\237a ser. "
gameforge.locale.monster_chat_20011_3 = "\191Por qu\233 no florecen m\225s los campos? "
gameforge.locale.monster_chat_20011_4 = "El grano est\225 seco y sabe a podrido. "
gameforge.locale.monster_chat_20011_5 = "Es una mala se\241al. La labranza es la base de nuestra vida. "
gameforge.locale.monster_chat_20012_1 = "\161Pastel de arroz! \161Delicioso pastel de arroz! "
gameforge.locale.monster_chat_20012_2 = "\161Vendo pastel de arroz dulce! "
gameforge.locale.monster_chat_20012_3 = "S\237, los negocios han sido bastante malos \250ltimamente. "
gameforge.locale.monster_chat_20012_4 = "Quiz\225 deba intentarlo en otra ciudad. "
gameforge.locale.monster_chat_20012_5 = "Pero hay tantos tigres... "
gameforge.locale.monster_chat_20013_1 = "En d\237as como esos, estar en un barco es lo mejor que puede pasarte. "
gameforge.locale.monster_chat_20013_2 = "\161Tiempo perfecto para pescar! "
gameforge.locale.monster_chat_20013_3 = "Ahora solo falta un nudo... \161Listo! Ning\250n pez ser\225 capaz de morder este anzuelo. "
gameforge.locale.monster_chat_20013_4 = "\161El maldito oso arruin\243 mi ca\241a! "
gameforge.locale.monster_chat_20013_5 = "Deber\237a remendar otra vez mis redes. "
gameforge.locale.monster_chat_20014_1 = "\161Uh! "
gameforge.locale.monster_chat_20014_2 = "No te preocupes por m\237; as\237 es como soy. "
gameforge.locale.monster_chat_20014_3 = "\161Jaaaaa! "
gameforge.locale.monster_chat_20014_4 = "Qu\233 debo hacer para que ella... Oh no, \191qu\233 acabo de decir? "
gameforge.locale.monster_chat_20014_5 = "Al fin y al cabo, no puedo ser valiente. "
gameforge.locale.monster_chat_20015_1 = "Este hacha me ha servido bien durante 20 a\241os. "
gameforge.locale.monster_chat_20015_2 = "A\250n est\225 afilada, aunque quiz\225 no es tan buena como sol\237a ser. "
gameforge.locale.monster_chat_20015_3 = "Quiero usarla y reforzarla. "
gameforge.locale.monster_chat_20015_4 = "Pero necesito piedras llenas de minerales para eso. "
gameforge.locale.monster_chat_20015_5 = "\191Pero d\243nde deber\237a conseguirlas? "
gameforge.locale.monster_chat_20016_1 = "Los clientes vienen en tropel. "
gameforge.locale.monster_chat_20016_2 = "Espero estar listo a tiempo. "
gameforge.locale.monster_chat_20016_3 = "Golpe tras golpe y no se queja... "
gameforge.locale.monster_chat_20016_4 = "\161As\237 debe sonar un martillo! "
gameforge.locale.monster_chat_20016_5 = "Qu\233 calor hace aqu\237. "
gameforge.locale.monster_chat_20017_1 = "No tengo ganas de tocar un instrumento. "
gameforge.locale.monster_chat_20017_2 = "El estado de mi instrumento es realmente deplorable. "
gameforge.locale.monster_chat_20017_3 = "\191Quiz\225s deber\237a compararme otro instrumento? "
gameforge.locale.monster_chat_20017_4 = "Mi instrumento est\225 viejo y usado... \161Adoro las cosas viejas! "
gameforge.locale.monster_chat_20017_5 = "Tengo que encontrar urgentemente un remplazo para las cuerdas rotas. "
gameforge.locale.monster_chat_20018_1 = "\161Estoy tan ocupado! "
gameforge.locale.monster_chat_20018_2 = "Cada d\237a, tenemos nueva gente herida. "
gameforge.locale.monster_chat_20018_3 = "\161No hay tiempo para la diversi\243n personal! "
gameforge.locale.monster_chat_20018_4 = "Y nos estamos quedando sin medicina. "
gameforge.locale.monster_chat_20018_5 = "Espero que alguien pueda ir y conseguir algunos ingredientes para la medicina. "
gameforge.locale.monster_chat_20019_1 = "Durante 30 a\241os, he estado vagando por las monta\241as con mi arco. "
gameforge.locale.monster_chat_20019_2 = "Con esto, mantuve a mi esposa y cri\233 tres hijos. "
gameforge.locale.monster_chat_20019_3 = "Es una vida dura, pero vale la pena. "
gameforge.locale.monster_chat_20019_4 = "Pero ahora, la cuerda del arco se rompi\243 y no puedo cazar m\225s. \161No puedo alimentar as\237 a mi familia! "
gameforge.locale.monster_chat_20019_5 = "Si no puedo reparar este arco, tendr\233 que comprar uno nuevo. Pero no tengo suficiente dinero para hacerlo. "
gameforge.locale.monster_chat_20020_1 = "Eh, \191qu\233 est\225s mirando? "
gameforge.locale.monster_chat_20020_2 = "\161Vete de aqu\237! "
gameforge.locale.monster_chat_20020_3 = "Oh, \191durante cu\225nto tendr\233 que esconderme? "
gameforge.locale.monster_chat_20020_4 = "\191Morir\233 olvidado en alg\250n sitio? "
gameforge.locale.monster_chat_20020_5 = "Aaaah, espero que alguien me ayude... "
gameforge.locale.monster_chat_20021_1 = "El d\237a de hoy va a acabar exactamente como otro d\237a cualquiera. "
gameforge.locale.monster_chat_20021_2 = "\191Qu\233 pudo hacer ahora, uh? "
gameforge.locale.monster_chat_20021_3 = "Nunca pens\233 que acabar\237a as\237. "
gameforge.locale.monster_chat_20021_4 = "A\250n no puedo creer que ya no est\233 aqu\237 nunca m\225s. "
gameforge.locale.monster_chat_20021_5 = "No se merec\237a eso. "
gameforge.locale.monster_chat_20022_1 = "Otro gran d\237a. "
gameforge.locale.monster_chat_20022_2 = "El marido de Ariyoung ha desparecido. "
gameforge.locale.monster_chat_20022_3 = "Quise ayudar, pero esta tenacidad... "
gameforge.locale.monster_chat_20022_4 = "Si se hubiera casado conmigo, podr\237a haber dejado atr\225s su aburrida vida. "
gameforge.locale.monster_chat_20022_5 = "Quiz\225 deber\237a haber expresado mejor mis sentimientos por ella. "
gameforge.locale.monster_chat_20023_1 = "\161Oh no! \191Qu\233 har\233 si mi mujer lo descubre? "
gameforge.locale.monster_chat_20023_2 = "\161Si tan s\243lo pudiera vivir de leer libros! "
gameforge.locale.monster_chat_20023_3 = "Los libros son tan misteriosos. "
gameforge.locale.monster_chat_20023_4 = "No puedo vivir as\237 para siempre, pero... "
gameforge.locale.monster_chat_20023_5 = "Espero que pueda hacer algo por mi mujer, pero... "
gameforge.locale.monster_chat_20024_1 = "\161Vamos, pon algo de esfuerzo en ello! "
gameforge.locale.monster_chat_20024_2 = "\191Qu\233 est\225s haciendo? \191No puedes darte prisa? "
gameforge.locale.monster_chat_20024_3 = "\161Imag\237nate como un guerrero maneja su espada y hazlo exactamente igual! "
gameforge.locale.monster_chat_20024_4 = "\191D\243nde est\225 este idiota? \191D\243nde est\225 ahora? "
gameforge.locale.monster_chat_20024_5 = "\161Este perro! \161No eres hombre! \161Ja! "
gameforge.locale.monster_chat_2091_1 = "Corta, corta... pelo, cuellos... "
gameforge.locale.monster_chat_2091_2 = "Tengo algo para ti: \161el suelo eterno! "
gameforge.locale.monster_chat_2091_3 = "Respira profundamente. \161No te preocupes, que es solo veneno! "
gameforge.locale.monster_chat_2091_4 = "\161Voy a dejar solo tu cara! \201sta ser\225 un bonito adorno... "
gameforge.locale.monster_chat_2091_5 = {}
gameforge.locale.monster_chat_2091_6 = "Envuelto en seda ser\225s un aperitivo hermoso para m\225s tarde... "
gameforge.locale.monster_chat_2092_1 = "Ya no quedan muchos de nosotros. "
gameforge.locale.monster_chat_2092_2 = "No son las criaturas b\237pedas que se supone que gobiernan aqu\237. "
gameforge.locale.monster_chat_2092_3 = "Oh, parece que alguien fue atrapado en la tela de ara\241a. "
gameforge.locale.monster_chat_2092_4 = "Soy pac\237fico. Pero no me gusta ser molestado. "
gameforge.locale.monster_chat_2092_5 = "\191Eso es todo lo que puedes ofrecer? "
gameforge.locale.monster_chat_2092_6 = "\161Nadie pude medirse conmigo! "
gameforge.locale.monster_chat_2104_1 = "\191Por qu\233 los humanos son tan h\250medos en su interior? Esto hace que mi espada se oxide. "
gameforge.locale.monster_chat_2104_2 = "\191Se ha secado ya el veneno de tu aguij\243n? "
gameforge.locale.monster_chat_2104_3 = "\191Qu\233 te parece luchar? "
gameforge.locale.monster_chat_2104_4 = "\191Agotado ya por el calor? "
gameforge.locale.monster_chat_2104_5 = "Me gusta dejar a la gente atr\225s en el desierto. "
gameforge.locale.monster_chat_2104_6 = "Pobre de t\237, enterrado as\237 en el desierto. "
gameforge.locale.monster_chat_2105_1 = "Voy a contarte un secreto - \161Odio la suciedad! "
gameforge.locale.monster_chat_2105_2 = "Hace mucho calor, \191no? "
gameforge.locale.monster_chat_2105_3 = "Este lugar es peligroso. "
gameforge.locale.monster_chat_2105_4 = {}
gameforge.locale.monster_chat_2105_5 = "\161Voy a golpearte entre los ojos! "
gameforge.locale.monster_chat_2106_1 = "Parece que hay algo por aqu\237 que puedo acribillar. "
gameforge.locale.monster_chat_2106_2 = "Oh s\237, puedo ver a mi siguiente presa. "
gameforge.locale.monster_chat_2106_3 = "(Risotada) Me gusta; \161me gusta mucho! "
gameforge.locale.monster_chat_2106_4 = "Ese de all\237 est\225 bien gordito. \161Es m\237o! "
gameforge.locale.monster_chat_2106_5 = {}
gameforge.locale.monster_chat_2106_6 = "Me gusta el olor de la sangre. "
gameforge.locale.monster_chat_2107_1 = "(Balanceo) No hay mucho que hacer estos d\237as. (balanceo) "
gameforge.locale.monster_chat_2107_2 = "Eh, \161esos est\225n realmente gordos! "
gameforge.locale.monster_chat_2107_3 = "Esto le gustar\225 al l\237der... "
gameforge.locale.monster_chat_2107_4 = {}
gameforge.locale.monster_chat_2107_5 = "Mov\225mos las piernas. "
gameforge.locale.monster_chat_2107_6 = "Esta flecha es s\243lo para ti. "
gameforge.locale.monster_chat_2108_1 = "Si consigo uno, yo... "
gameforge.locale.monster_chat_2108_2 = "Eh, \191por qu\233 miras tras de t\237? "
gameforge.locale.monster_chat_2108_3 = "\191Crees que soy f\225cil de derrotar? \191Hm? "
gameforge.locale.monster_chat_2108_4 = "\161Muy mal que te hayas tenido que topar conmigo en el desierto! "
gameforge.locale.monster_chat_2108_5 = "Ah, este sentimiento; \161lo disfrutar\233 para siempre! "
gameforge.locale.monster_chat_2108_6 = "\161Gracias! "
gameforge.locale.monster_chat_2191_1 = "Huelo humanos - \161taan sabrosos! "
gameforge.locale.monster_chat_2191_2 = "Bien. Ven a m\237, ven a m\237... "
gameforge.locale.monster_chat_2191_3 = {}
gameforge.locale.monster_chat_2191_4 = "\161Soy tan afortunado de que te hayas perdido y hayas acabado aqu\237! "
gameforge.locale.monster_chat_2191_5 = "\161P\225rate! \161Kkkkkk! "
gameforge.locale.monster_chat_2191_6 = "Poco a poco voy a rasgarlo de tu carne... "
gameforge.locale.monster_chat_2202_1 = "Ac\233rcate m\225s para que pueda abrasar tu piel. "
gameforge.locale.monster_chat_2202_2 = "\191Sabes que tipo de dolor puede provocar tanta cantidad de calor? "
gameforge.locale.monster_chat_2202_3 = "Quiz\225 pueda enfriar mis llamas con algo de sangre fresca. "
gameforge.locale.monster_chat_2202_4 = "Tu sangre... d\233jame probarla. "
gameforge.locale.monster_chat_2202_5 = "No tiene sentido soportar una lucha. "
gameforge.locale.monster_chat_2202_6 = "\161S\233 como yo! S\243lo llamas y calor. "
gameforge.locale.monster_chat_2204_1 = "Mientras est\233 yo aqu\237, \161nadie entrar\225! "
gameforge.locale.monster_chat_2204_2 = "Por alguna raz\243n, estas empezando a molestarme. "
gameforge.locale.monster_chat_2204_3 = {}
gameforge.locale.monster_chat_2204_4 = "Kwuuh, \191sabes d\243nde est\225s? "
gameforge.locale.monster_chat_2204_5 = {}
gameforge.locale.monster_chat_2204_6 = "\161Eres un oponente bastante pat\233tico para m\237! "
gameforge.locale.monster_chat_2205_1 = "Una espada s\243lo es \250til a manos de un guerrero. "
gameforge.locale.monster_chat_2205_2 = "Conserva la espada en tu mano. "
gameforge.locale.monster_chat_2205_3 = "La guerra se avecina. "
gameforge.locale.monster_chat_2205_4 = "Y ahora, \161luchamos hasta que alguien muera! "
gameforge.locale.monster_chat_2205_5 = "\191Quieres resistirte a la muerte mucho m\225s? "
gameforge.locale.monster_chat_2205_6 = "S\237, no deber\237as morir demasiado r\225pido. "
gameforge.locale.monster_chat_2206_1 = "La lava es el elixir de la vida. "
gameforge.locale.monster_chat_2206_2 = "\161La lava me mantiene vivo y ser\225 tu muerte! "
gameforge.locale.monster_chat_2206_3 = "\191No es maravilloso este mundo de lava resplandeciente? "
gameforge.locale.monster_chat_2206_4 = "\191Osas molestarme? "
gameforge.locale.monster_chat_2206_5 = "Deber\237as irte si valoras tu vida. "
gameforge.locale.monster_chat_2206_6 = "Puede que lamentes mi presencia aqu\237. "
gameforge.locale.monster_chat_2291_1 = "Hace un bonito d\237a. Todo lo que quiero es tener algo de paz y tranquilidad. "
gameforge.locale.monster_chat_2291_2 = "Nada es comparable al pa\237s de Doyyumhwan. "
gameforge.locale.monster_chat_2291_3 = "Un poco de sangre fresca ser\237a un buen cambio. "
gameforge.locale.monster_chat_2291_4 = "Parece que buscas tu muerte, de otro modo no estar\237as molest\225ndome ahora.  "
gameforge.locale.monster_chat_2291_5 = "\191Ya te est\225s arrepintiendo de haber aparecido? "
gameforge.locale.monster_chat_2291_6 = "Es demasiado tarde para escapar. Afronta tu destino. "
gameforge.locale.monster_chat_301_1 = "Estos momentos tensos me estan poniendo nervioso. "
gameforge.locale.monster_chat_301_2 = "Hace dos d\237as, una chica joven fue apaleada por animales salvajes en el \225rea. "
gameforge.locale.monster_chat_301_3 = "Los animales salvajes se est\225n volviendo m\225s y m\225s agresivos. Deber\237amos intentarlo y matar los m\225s posibles. "
gameforge.locale.monster_chat_301_4 = "No estoy de buen humor hoy. Los extranjeros deber\237an mantenerse alejados de mi camino. "
gameforge.locale.monster_chat_301_5 = "El \250ltimo guerrero que mat\233, suplic\243 por su vida. "
gameforge.locale.monster_chat_302_1 = "Alguien tiene que hacer algo con esas piedras. "
gameforge.locale.monster_chat_302_2 = "No me fio de la tranquilidad de la ma\241ana. "
gameforge.locale.monster_chat_302_3 = "La tensi\243n en el aire me incomoda. "
gameforge.locale.monster_chat_302_4 = "Estas puntas de flecha han sido muy bien forjadas. "
gameforge.locale.monster_chat_302_5 = "Si fuese t\250, tendr\237a cuidado. Esa flecha est\225 apuntando directamente a tu coraz\243n. "
gameforge.locale.monster_chat_302_6 = "Debo ir ah\237 y matar a una de esas bestias. "
gameforge.locale.monster_chat_303_1 = "Un buen entrenamiento en artes marciales es esencial en estos tiempos. "
gameforge.locale.monster_chat_303_2 = "\191Qu\233 pasa si de repente irrumpen soldados? "
gameforge.locale.monster_chat_303_3 = "\191Por qu\233 me est\225s mirando as\237? "
gameforge.locale.monster_chat_303_4 = "Los cobardes tienen una peque\241a posibilidad de sobrevivir. "
gameforge.locale.monster_chat_303_5 = "No te sobreestimes. "
gameforge.locale.monster_chat_303_6 = "Parece que alguien te ha entrenado muy bien. "
gameforge.locale.monster_chat_304_1 = "Incluso mis ancestros consiguieron defenderse en la batalla en estas \225reas. "
gameforge.locale.monster_chat_304_2 = "Tienes que estar alerta y diestro ah\237 fuera. "
gameforge.locale.monster_chat_304_3 = "Ni pienses en hacer perder mi tiempo. "
gameforge.locale.monster_chat_304_4 = "Entonces, \191c\243mo se siente el saber que tu vida est\225 en peligro? "
gameforge.locale.monster_chat_304_5 = "\161Oh no! \191Ya abandonas? "
gameforge.locale.monster_chat_304_6 = "El sufrimiento llega r\225pido. "
gameforge.locale.monster_chat_305_1 = "\161Oh t\237o! Esa espada parece fant\225stica. "
gameforge.locale.monster_chat_305_2 = "\161S\233 m\225s persistente e incrementa tu poder! "
gameforge.locale.monster_chat_305_3 = "\191Crees que puedes ser tan fuerte como yo? "
gameforge.locale.monster_chat_305_4 = "Bien. Pong\225monos serios. "
gameforge.locale.monster_chat_305_5 = "\161Oh Dios! \161Soy s\243lo una d\233bil mujer! "
gameforge.locale.monster_chat_305_6 = "Pareces cansado. \191Por qu\233 no abandonas ya? Jeje. "
gameforge.locale.monster_chat_306_1 = "\191Qu\233 va ha hacer Serangyi hoy, hm? "
gameforge.locale.monster_chat_306_2 = "Estoy tan aburrido. \161Juega conmigo! "
gameforge.locale.monster_chat_306_3 = "Tengo que decir que me gusta m\225s el Sura. "
gameforge.locale.monster_chat_306_4 = "\161Eh! \191Qu\233 me dices a una lucha? "
gameforge.locale.monster_chat_306_5 = "\161No me subestimes solo porque soy una mujer! "
gameforge.locale.monster_chat_306_6 = "El dolor s\243lo dura un momento. "
gameforge.locale.monster_chat_307_1 = "Quiero salir de aqu\237 a toda costa. "
gameforge.locale.monster_chat_307_2 = "\191Cu\225nta seguridad tienen las casas de los miembros solteros? "
gameforge.locale.monster_chat_307_3 = "\161Calla, galones! "
gameforge.locale.monster_chat_307_4 = "D\233jame derrotarte de un solo golpe. "
gameforge.locale.monster_chat_307_5 = "\161Ni pienses en escapar! "
gameforge.locale.monster_chat_307_6 = "As\237 pues, \191por qu\233 no empezamos? "
gameforge.locale.monster_chat_394_1 = "No lo olvides: todos los hombres son enemigos. "
gameforge.locale.monster_chat_394_2 = "Si una persona tiene una cara bonita, podemos ser menos estrictos. "
gameforge.locale.monster_chat_394_3 = "\191Qu\233, quieres luchar? "
gameforge.locale.monster_chat_394_4 = "No durar\225 mucho, pero doler\225. "
gameforge.locale.monster_chat_394_5 = "Oh, realmente pareces dolorido. "
gameforge.locale.monster_chat_394_6 = "Adi\243s; \161vete al infierno! "
gameforge.locale.monster_chat_401_1 = "As\237 pues, \191qu\233 haces en el Juramento Blanco? "
gameforge.locale.monster_chat_401_2 = "\191D\243nde vas? "
gameforge.locale.monster_chat_401_3 = "Eh, \191quieres luchar? "
gameforge.locale.monster_chat_401_4 = "Jeje, esquivas mis ataques. "
gameforge.locale.monster_chat_401_5 = "\191Crees que puedes escapar de m\237? "
gameforge.locale.monster_chat_401_6 = "\161Aqu\237 esta mi golpe! "
gameforge.locale.monster_chat_402_1 = "Dios, \161estoy tan cansado! "
gameforge.locale.monster_chat_402_2 = "Eh, \161bonita armadura! \191Cu\225nto cost\243? "
gameforge.locale.monster_chat_402_3 = "Pero tenemos buen tiempo. "
gameforge.locale.monster_chat_402_4 = "Oh, \161has entrenado mucho! \161Genial! "
gameforge.locale.monster_chat_402_5 = "\191Qu\233 piensas de mis habilidades? Buenas, \191eh? Jeje. "
gameforge.locale.monster_chat_402_6 = "\191Qu\233 pasa? Por supuesto, \161es la velocidad insana! "
gameforge.locale.monster_chat_403_1 = "\191Por qu\233 no voy a cazar? "
gameforge.locale.monster_chat_403_2 = "Nadie est\225 atacando nuestra aldea hoy. "
gameforge.locale.monster_chat_403_3 = "Si quires luchar, entonces lucha, \161bastardo! "
gameforge.locale.monster_chat_403_4 = "Jeje, eres s\243lo un principiante. "
gameforge.locale.monster_chat_403_5 = "\191Qu\233 deber\237a golpear primero, tu brazo o tu pierna? "
gameforge.locale.monster_chat_403_6 = "\161Aqu\237 viene mi flecha! "
gameforge.locale.monster_chat_404_1 = "Pronto tengo que ir a la aldea y entrenar un tiempo. "
gameforge.locale.monster_chat_404_2 = "Me siento tan entumecido. "
gameforge.locale.monster_chat_404_3 = "\191Qu\233 hay hoy para cenar? "
gameforge.locale.monster_chat_404_4 = "Estoy mirando, as\237 que grita tanto como quieras. "
gameforge.locale.monster_chat_404_5 = "\191Has esperado demasiado? \161Qu\233 me dices a balancear esa espada tuya primero! "
gameforge.locale.monster_chat_404_6 = "\161La espada suena apasionante! "
gameforge.locale.monster_chat_405_1 = "\161Esta espada est\225 lista! "
gameforge.locale.monster_chat_405_2 = "Veamos qui\233n ser\225 asesinado primero por esta espada. "
gameforge.locale.monster_chat_405_3 = "Eh, \191qu\233 est\225s mirando? "
gameforge.locale.monster_chat_405_4 = "Primero, \161tu barriga! "
gameforge.locale.monster_chat_405_5 = "Me gustar\237a usarte de vaina. "
gameforge.locale.monster_chat_405_6 = "Me gustar\237a usarte de vaina. "
gameforge.locale.monster_chat_406_1 = "Me muero de hambre. "
gameforge.locale.monster_chat_406_2 = "\191Hay algo para comer ah\237? "
gameforge.locale.monster_chat_406_3 = "\191Por qu\233 estoy todav\237a hambriento despu\233s de toda esta comida? "
gameforge.locale.monster_chat_406_4 = "Aaargh, \161muere! "
gameforge.locale.monster_chat_406_5 = "\161Mi est\243mago determinar\225 esta lucha! "
gameforge.locale.monster_chat_406_6 = "\161Es la elecci\243n entre cielo e infierno! "
gameforge.locale.monster_chat_491_1 = "\161No puedo soportarlo m\225s! Me pica el cuerpo. "
gameforge.locale.monster_chat_491_2 = "Oh s\237. Puedo ver algunos cerdos. "
gameforge.locale.monster_chat_491_3 = "\191En el suelo? "
gameforge.locale.monster_chat_491_4 = "Acabar\233 contigo de un golpe. "
gameforge.locale.monster_chat_491_5 = "\161Ser\225 un bonito recuerdo! "
gameforge.locale.monster_chat_491_6 = "\161Muere! "
gameforge.locale.monster_chat_492_1 = "Mi cuerpo se ha ablandado. "
gameforge.locale.monster_chat_492_2 = "\191Por qu\233 no lo ejercito m\225s? "
gameforge.locale.monster_chat_492_3 = "Asustado, \191eh? "
gameforge.locale.monster_chat_492_4 = "Ah, s\243lo una nueva v\237ctima para mi arma giratoria. "
gameforge.locale.monster_chat_492_5 = "\191Puedes ver el patr\243n de mi ataque? \191No? \161Tu p\233rdida! "
gameforge.locale.monster_chat_492_6 = "\191Lo sab\237as? Incluso el corte m\225s peque\241o no es bueno para tu salud. "
gameforge.locale.monster_chat_493_1 = "\161Es tan inc\243modo tener una mano como esta! "
gameforge.locale.monster_chat_493_2 = "\191Qu\233 est\225s mirando? \191No hab\237as visto nunca a una persona con una mano como esta? "
gameforge.locale.monster_chat_493_3 = "Verdaderamente me irrit\225is. "
gameforge.locale.monster_chat_493_4 = "\191Quieres que te pegue una paliza? Si no, huye. \191Entendido? "
gameforge.locale.monster_chat_493_5 = "\161Te mostrar\233 mi gran golpe! "
gameforge.locale.monster_chat_493_6 = "\161S\233 que estas mirando mi mano! "
gameforge.locale.monster_chat_494_1 = "Eh t\250, si quieres luchar, \161ven aqu\237! "
gameforge.locale.monster_chat_494_2 = "Creo que soy bastante impresionante. "
gameforge.locale.monster_chat_494_3 = "\191Por qu\233 no planeamos algo? "
gameforge.locale.monster_chat_494_4 = "No, no puedes irte todav\237a. \161Lucha! "
gameforge.locale.monster_chat_494_5 = "\161Aqu\237 tienes! "
gameforge.locale.monster_chat_494_6 = "\161Est\225s casi muerto! "
gameforge.locale.monster_chat_501_1 = "\161Juega conmigo! \161No te vayas! "
gameforge.locale.monster_chat_501_2 = "Yo podr\237a esculpir algo bonito de tus huesos... "
gameforge.locale.monster_chat_501_3 = "A\250n no hemos ejercitado. "
gameforge.locale.monster_chat_501_4 = "\161Qu\233 gran armadura! Quiero tenerla. "
gameforge.locale.monster_chat_501_5 = "Desde ahora, encontrar\225s dif\237cil ignorar mis ataques. "
gameforge.locale.monster_chat_501_6 = "Jeje, \191sorprendido? "
gameforge.locale.monster_chat_502_1 = "La belleza no lo es todo. "
gameforge.locale.monster_chat_502_2 = "No mires, \161lucha! "
gameforge.locale.monster_chat_502_3 = "No me gusta el modo en el que me est\225s mirando. \161Lucha! "
gameforge.locale.monster_chat_502_4 = "\161Es un honor morir por mi espada! "
gameforge.locale.monster_chat_502_5 = {}
gameforge.locale.monster_chat_502_6 = "\161Excelente! "
gameforge.locale.monster_chat_503_1 = "Eh, \161no toques! "
gameforge.locale.monster_chat_503_2 = "Parece que la cuerda de mi arco est\225 cortada. "
gameforge.locale.monster_chat_503_3 = "Maldici\243n, esos idiotas estuvieron aqu\237. "
gameforge.locale.monster_chat_503_4 = "No est\225 mal. \161Pero vas a morir de todos modos! "
gameforge.locale.monster_chat_503_5 = "\191Te parece bien? \161Es estupendo! "
gameforge.locale.monster_chat_503_6 = "\161Aqu\237 viene la flecha! "
gameforge.locale.monster_chat_504_1 = "Todo el mundo, \161venid aqu\237! "
gameforge.locale.monster_chat_504_2 = "La, la, la, estoy silbando una canci\243n... "
gameforge.locale.monster_chat_504_3 = "\161Qu\233 gran tiempo! "
gameforge.locale.monster_chat_504_4 = {}
gameforge.locale.monster_chat_504_5 = "Bien, \161quiero que te decidas a luchar! "
gameforge.locale.monster_chat_504_6 = "\161Aqu\237! \161Venid! "
gameforge.locale.monster_chat_601_1 = "\161Me muero de hambre! "
gameforge.locale.monster_chat_601_2 = "Quiero comer algo de fruta. "
gameforge.locale.monster_chat_601_3 = "Bien, el buen pescado lo har\225. \161Al ataque! "
gameforge.locale.monster_chat_601_4 = "\161No corras! \161Qu\233date aqu\237! "
gameforge.locale.monster_chat_601_5 = "Gan\233. \161Es obvio! "
gameforge.locale.monster_chat_601_6 = "\191Ves? \161Fallaste! "
gameforge.locale.monster_chat_601_7 = "Deber\237as tener cuidado, \161Jaja! "
gameforge.locale.monster_chat_602_1 = "\191D\243nde estoy? "
gameforge.locale.monster_chat_602_2 = "Buen tiempo. "
gameforge.locale.monster_chat_602_3 = "\191Vienes a darme caza? \161Absurdo! "
gameforge.locale.monster_chat_602_4 = "Eres mi presa. "
gameforge.locale.monster_chat_602_5 = "Qu\233 tortura, \191no? Bien, acabar\233 contigo en un instante. "
gameforge.locale.monster_chat_602_6 = "Mira lo fuerte que soy: \161puedo balancear este enorme garrote! "
gameforge.locale.monster_chat_603_1 = "\161Aburrido! "
gameforge.locale.monster_chat_603_2 = "Me pica el cuerpo entero. "
gameforge.locale.monster_chat_603_3 = "Quienquiera que sea el primero. "
gameforge.locale.monster_chat_603_4 = "\191Me golpeas primero? \161Voy a sacarte de fuera de aqu\237! "
gameforge.locale.monster_chat_603_5 = "Una vez que entras, nunca saldr\225s. \161No hay escapatoria! "
gameforge.locale.monster_chat_603_6 = "Este ser\225 el \250ltimo golpe. \161Acabar\233 contigo! "
gameforge.locale.monster_chat_604_1 = "He hecho un sabroso veneno nuevo. \191Quieres probarlo? "
gameforge.locale.monster_chat_604_2 = "\161Quiero ver c\243mo funciona! Toma, \161c\243gelo! "
gameforge.locale.monster_chat_604_3 = "\161Eh t\250! Ven aqu\237, \191quieres ser mi conejillo de indias? "
gameforge.locale.monster_chat_604_4 = "\161Te envenenar\233! "
gameforge.locale.monster_chat_604_5 = "Oh genial, \161un conejillo de indias! "
gameforge.locale.monster_chat_604_6 = "\161No hay diversi\243n si te rindes tan r\225pidamente! Vamos, \161defi\233ndete! "
gameforge.locale.monster_chat_631_1 = "Un momento. Estoy buscando algo para cazar. "
gameforge.locale.monster_chat_631_2 = "No sirve para nada que te muevas tan lentamente. \161Mu\233vete! "
gameforge.locale.monster_chat_631_3 = "\161Tengo tanta hambre! "
gameforge.locale.monster_chat_631_4 = "\161Es genial haber encontrado algo para cazar! "
gameforge.locale.monster_chat_631_5 = "\161Deja ir toda esperanza de supervivencia! \161No sobrevivir\225s! "
gameforge.locale.monster_chat_631_6 = "\161Ahora averiguar\225s c\243mo sienta el dolor verdadero! "
gameforge.locale.monster_chat_632_1 = "\161Aburriiiiiiiido! "
gameforge.locale.monster_chat_632_2 = "\191Hay algo utilizable como cebo? "
gameforge.locale.monster_chat_632_3 = "\161Ven y lucha si quieres! "
gameforge.locale.monster_chat_632_4 = "\191Quieres ser un guerrero? \161Entonces mu\233strame lo que tienes! "
gameforge.locale.monster_chat_632_5 = {}
gameforge.locale.monster_chat_632_6 = "\161Escapa de la aldea si quieres vivir! "
gameforge.locale.monster_chat_633_1 = "Es doloroso morir de hambre. "
gameforge.locale.monster_chat_633_2 = "Oh, \161est\225n viniendo justo hacia nosotros! "
gameforge.locale.monster_chat_633_3 = "\191Qu\233 me dices de un duelo? "
gameforge.locale.monster_chat_633_4 = "\161No me compares con esos bastardos! "
gameforge.locale.monster_chat_633_5 = "\161Aqu\237 viene mi golpe de trueno! \161Ja! "
gameforge.locale.monster_chat_633_6 = "\161Aquellos que escapan ahora no son verdaderos guerreros! "
gameforge.locale.monster_chat_634_1 = "Esta vez, \161el veneno deber\237a ser mejor! "
gameforge.locale.monster_chat_634_2 = "Si tienes hambre, los murci\233lagos son realmente sabrosos. "
gameforge.locale.monster_chat_634_3 = "\191Qu\233 me dices a una lucha? "
gameforge.locale.monster_chat_634_4 = "Una vez que mi veneno entre en tu cuerpo, no hay modo alguno de curarlo. "
gameforge.locale.monster_chat_634_5 = "Mi magia consumir\225 todo en llamas, \161jejeje! "
gameforge.locale.monster_chat_634_6 = "\161Arde! \161Ja, ja! "
gameforge.locale.monster_chat_635_1 = "\161Nunca olvides afilar tu espada! La siguiente lucha est\225 m\225s pr\243xima de lo que crees. "
gameforge.locale.monster_chat_635_2 = "\191Oscuro? "
gameforge.locale.monster_chat_635_3 = "\161Muere y despierta en la otra vida! "
gameforge.locale.monster_chat_635_4 = "\191Derrotarme? \191De verdad? "
gameforge.locale.monster_chat_635_5 = "\161Lucha como un guerrero! (balanceo) "
gameforge.locale.monster_chat_635_6 = "Vamos, s\243lo un poco m\225s. "
gameforge.locale.monster_chat_636_1 = "Ja, estoy buscando una buena pelea. "
gameforge.locale.monster_chat_636_2 = "Pelearse es divertido. (risotada) "
gameforge.locale.monster_chat_636_3 = "\161Quiero pelear a todas horas! "
gameforge.locale.monster_chat_636_4 = "\161Ja, muy bien! \161Int\233ntalo otra vez! "
gameforge.locale.monster_chat_636_5 = "\161Mira mi espada girando! "
gameforge.locale.monster_chat_636_6 = "\161Te arrepentir\225s de golpearme! "
gameforge.locale.monster_chat_636_7 = "\161Tan d\233bil! \161Que rid\237culo! "
gameforge.locale.monster_chat_637_1 = "No quiero ser molestado. "
gameforge.locale.monster_chat_637_2 = "Ve a dormir. \161Para siempre! "
gameforge.locale.monster_chat_637_3 = "\191A\250n no est\225s dormido? "
gameforge.locale.monster_chat_637_4 = "\161Hay mucho que hacer! \161Sigamos! "
gameforge.locale.monster_chat_637_5 = "\161No te quedes perplejo por mi poder! "
gameforge.locale.monster_chat_637_6 = "\161Te pulverizar\233! "
gameforge.locale.monster_chat_691_1 = "Bien, \161los oponentes fuertes duran m\225s! \161Defi\233ndete! "
gameforge.locale.monster_chat_691_2 = "\191Qu\233? \191Qu\233 parezco? "
gameforge.locale.monster_chat_691_3 = "\161No me compares con ese principiante! "
gameforge.locale.monster_chat_691_4 = "\161A \233l no le gustas y a m\237 tampoco! "
gameforge.locale.monster_chat_691_5 = "Luchemos. "
gameforge.locale.monster_chat_691_6 = "\161Hasta la muerte! "
gameforge.locale.monster_chat_701_1 = "Mira, \161una mariposa! \161Que bonita! "
gameforge.locale.monster_chat_701_2 = "\191No ves la verdad del cielo y la tierra? "
gameforge.locale.monster_chat_701_3 = "M\225s tarde, ser\225 demasiado tarde para creer. \161Cree ahora! "
gameforge.locale.monster_chat_701_4 = "\161Cree en la doctrina de los esot\233ricos! "
gameforge.locale.monster_chat_701_5 = "\161Aquellos que duden ser\225n asesinados! "
gameforge.locale.monster_chat_701_6 = "\161S\233 inteligente abrazando a la muerte! "
gameforge.locale.monster_chat_702_1 = "La verdad de la creencia esot\233rica est\225 en el entendimiento de la orden del cielo. "
gameforge.locale.monster_chat_702_2 = "\161La filosof\237a de la creencia esot\233rica es la orden celestial! "
gameforge.locale.monster_chat_702_3 = "Verdad esot\233rica; verdad del Dios Tigre; Sabaha Sabaha. "
gameforge.locale.monster_chat_702_4 = "\191Osas dudar de la verdad del cielo y la tierra? "
gameforge.locale.monster_chat_702_5 = {}
gameforge.locale.monster_chat_702_6 = "\161Siente mis garras! "
gameforge.locale.monster_chat_703_1 = "Cuando la verdad del Dios Tigre suene por toda la eternidad, todo el sufrimiento acabar\225. "
gameforge.locale.monster_chat_703_2 = "La verdad de la creencia esot\233rica est\225 en el entendimiento de la orden del cielo. "
gameforge.locale.monster_chat_703_3 = "Sabaha Sabaha. \161Danos conocimiento! "
gameforge.locale.monster_chat_703_4 = "\161No lo dudes! "
gameforge.locale.monster_chat_703_5 = "\161Recibe el trueno del cielo! "
gameforge.locale.monster_chat_703_6 = "\161Golpe del Juicio! "
gameforge.locale.monster_chat_704_1 = "La verdad de la creencia esot\233rica est\225 en el entendimiento de la orden del cielo. "
gameforge.locale.monster_chat_704_2 = "Verdad esot\233rica; verdad del Dios Tigre; Sabaha Sabaha. "
gameforge.locale.monster_chat_704_3 = "Piensas que soy un payaso, \191no? \161No por mucho! "
gameforge.locale.monster_chat_704_4 = "\161El l\237der de esta secta es un santo y est\225 por encima de todos los seres vivos! "
gameforge.locale.monster_chat_704_5 = "\161Recibe las llamas del infierno! "
gameforge.locale.monster_chat_704_6 = "Apuesto a que nunca hab\237as visto un diapas\243n tan grande como este antes, \191eh? "
gameforge.locale.monster_chat_705_1 = "Verdad esot\233rica; verdad del Dios Tigre; Sabaha Sabaha. "
gameforge.locale.monster_chat_705_2 = "La verdad de la creencia esot\233rica est\225 en el entendimiento de la orden del cielo. "
gameforge.locale.monster_chat_705_3 = "\161S\243lo porque soy m\225s peque\241o que mi hermano, no significa que voy a aguantar de todo! "
gameforge.locale.monster_chat_705_4 = "\161Dolor eterno y oscuridad te aguardan! "
gameforge.locale.monster_chat_705_5 = {}
gameforge.locale.monster_chat_705_6 = "Este no es el fin. \161S\243lo va mejor! "
gameforge.locale.monster_chat_706_1 = "\161Pedimos paz y privacidad! \161Por favor! "
gameforge.locale.monster_chat_706_2 = "\161Si reina el miedo, la verdad del Dios Tigre ayuda! "
gameforge.locale.monster_chat_706_3 = "La verdad de la fe esot\233rica es el orden y entendimiento del cielo. "
gameforge.locale.monster_chat_706_4 = "\161Vamos todos al infierno! "
gameforge.locale.monster_chat_706_5 = "\161No te dejar\233 ir! "
gameforge.locale.monster_chat_706_6 = "Te dar\233 todo lo que tengo. "
gameforge.locale.monster_chat_707_1 = "Te lo ruego, \161por favor, s\225lvanos! "
gameforge.locale.monster_chat_707_2 = "La verdad de la creencia esot\233rica est\225 en el entendimiento de la orden del cielo. "
gameforge.locale.monster_chat_707_3 = "Verdad esot\233rica; verdad del Dios Tigre; Sabaha Sabaha. "
gameforge.locale.monster_chat_707_4 = "(Sonora carcajada) Las puertas del infierno est\225n abiertas. \161Muere! "
gameforge.locale.monster_chat_707_5 = "Te lo advierto: \161No me obligues a usar la tabla! "
gameforge.locale.monster_chat_707_6 = "\161Ya he visto tu muerte! "
gameforge.locale.monster_chat_791_1 = "\191C\243mo puedo contarte en unas pocas palabras sobre la verdad del Dios Tigre? "
gameforge.locale.monster_chat_791_2 = "Oigo los c\225nticos de los creyentes. "
gameforge.locale.monster_chat_791_3 = "\161Est\225 bien! \161Si tienes remordimientos, ser\225s rescatado! "
gameforge.locale.monster_chat_791_4 = "\161Sufres un dolor eterno, porque cuestionas la verdad! "
gameforge.locale.monster_chat_791_5 = "D\233jame ense\241arte. "
gameforge.locale.monster_chat_791_6 = "No lo consideres como un dolor - es la instrucci\243n. "
gameforge.locale.monster_chat_901_1 = "Puede que no sea guapo, pero me divierto mucho, \161jijiji! "
gameforge.locale.monster_chat_901_2 = "\161Tienes que ser como nosotros! "
gameforge.locale.monster_chat_901_3 = "Re\250nete con nosotros, \161jiji! "
gameforge.locale.monster_chat_901_4 = "\161Jaaa, jaja! "
gameforge.locale.monster_chat_901_5 = "\161All\225 vamos! "
gameforge.locale.monster_chat_903_1 = "\161Esto es el infierno! "
gameforge.locale.monster_chat_903_2 = "\161Ahhhhh! "
gameforge.locale.monster_chat_903_3 = "\161No podemos hacer esto solos! \161No! "
gameforge.locale.monster_chat_903_4 = "\161Tienes que probar el dolor, tambi\233n! "
gameforge.locale.monster_chat_903_5 = "\191Qu\233 tal un intercambio? \161T\250 me das tu alma y yo te dar\233 mi sufrimiento! "
gameforge.locale.monster_chat_903_6 = "\161Pronto encontrar\225s paz eterna! "
gameforge.locale.monster_chat_904_1 = "\161El dolor! \161El dolor! "
gameforge.locale.monster_chat_904_2 = "\161Aargghh, maldici\243n! \161Mi brazo est\225 ardiendo! "
gameforge.locale.monster_chat_904_3 = "\191Por qu\233 tenemos que sufrir? Oh, \191por qu\233? "
gameforge.locale.monster_chat_904_4 = "\161Sufrir esta enfermedad misteriosa no es tan malo! "
gameforge.locale.monster_chat_904_5 = {}
gameforge.locale.monster_chat_904_6 = "\161Ahhhh! "
gameforge.locale.monster_chat_905_1 = "\161Ahhhhh! "
gameforge.locale.monster_chat_905_2 = "\161Te maaaaaaaaato! "
gameforge.locale.monster_chat_905_3 = "\161No mires simplemente! \161\218nete! "
gameforge.locale.monster_chat_905_4 = "\161Seamos amigos! "
gameforge.locale.monster_chat_905_5 = "Ya est\225s infectado. "
gameforge.locale.monster_chat_905_6 = "Ahora eres mi amigo. "
gameforge.locale.monster_chat_906_1 = "\161Jijiji! "
gameforge.locale.monster_chat_906_2 = "\161Ven y siente mi flecha! "
gameforge.locale.monster_chat_906_3 = "\161Eres realmente molesto! "
gameforge.locale.monster_chat_906_4 = "Voy a infectarte con la enfermedad misteriosa. "
gameforge.locale.monster_chat_906_5 = "Buen olor. "
gameforge.locale.monster_chat_906_6 = "\161Muere! "
gameforge.locale.monster_chat_907_1 = "Y si encuentro otro factor de enfermedad... "
gameforge.locale.monster_chat_907_2 = "(Risotada) \161Ser\225 divertido! "
gameforge.locale.monster_chat_907_3 = "Hmmm, \191l\225tigo o pinza...? "
gameforge.locale.monster_chat_907_4 = "Ahhhhh, \161siiiiiiiii! "
gameforge.locale.monster_chat_907_5 = "\161D\233jame contagiarte la enfermedad! "
gameforge.locale.monster_chat_907_6 = "\161Esta causa tenaz de la enfermedad misteriosa! "
