gameforge.locale.old_pirate.accept_failure_info_label = "Volver a ver al pirata viejo. "
gameforge.locale.old_pirate.accept_failure_info_text_1 = "Vuelve con el pirata viejo. "
gameforge.locale.old_pirate.accept_failure_info_text_2 = "Dile al pirata viejo que no conseguiste la[ENTER]medicina. "
gameforge.locale.old_pirate.accept_failure_say_1 = "Vuelve con el pirata viejo. "
gameforge.locale.old_pirate.accept_failure_say_2 = "\161No puedo encontrar la medicina! \191Qu\233 le voy a[ENTER]decir al pirata viejo? "
gameforge.locale.old_pirate.accept_success_info_label = "Lleva la medicina al pirata viejo. "
gameforge.locale.old_pirate.accept_success_info_text_1 = "Lleva la medicina al pirata viejo. "
gameforge.locale.old_pirate.accept_success_info_text_2 = "Lleva la medicina al pirata viejo y pide tu[ENTER]recompensa. "
gameforge.locale.old_pirate.accept_success_say_1 = "Tengo la medicina. "
gameforge.locale.old_pirate.accept_success_say_2 = "Tengo la medicina para el pirata viejo. Deber\237a[ENTER]llev\225rsela. "
gameforge.locale.old_pirate.baekgo_accept_ask = "Baek-Go:[ENTER]\191A\250n no has encontrado nada?[ENTER]\161Tenemos que detener la enfermedad antes de que[ENTER]se propague por la aldea entera! \161Date prisa! "
gameforge.locale.old_pirate.baekgo_accept_failure_info_label = "Regresar con Baek-Go "
gameforge.locale.old_pirate.baekgo_accept_failure_info_text_1 = "Vuelve con Baek-Go. "
gameforge.locale.old_pirate.baekgo_accept_failure_info_text_2 = "Dile a Baek-Go que no has podido encontrar el[ENTER]pat\243geno de la enfermedad misteriosa. "
gameforge.locale.old_pirate.baekgo_accept_failure_say_1 = "Vuelve con Baek-Go. "
gameforge.locale.old_pirate.baekgo_accept_failure_say_2 = "\161No puedo encontrar el pat\243geno de la enfermedad[ENTER]misteriosa! \191Qu\233 debo decirle a Baek-Go? "
gameforge.locale.old_pirate.baekgo_accept_success_info_label = "Ll\233vale la muestra a Baek-Go. "
gameforge.locale.old_pirate.baekgo_accept_success_info_text_1 = "Lleva una muestra del pat\243geno a Baek-Go. "
gameforge.locale.old_pirate.baekgo_accept_success_info_text_2 = "Lleva una muestra del pat\243geno a Baek-Go y recibe[ENTER]la medicina para el pirata viejo. "
gameforge.locale.old_pirate.baekgo_accept_success_say_1 = "Tengo una muestra del pat\243geno de la enfermedad[ENTER]misteriosa. "
gameforge.locale.old_pirate.baekgo_accept_success_say_2 = "Tengo una muestra del germen pat\243geno de la[ENTER]enfermedad misteriosa. Deber\237a llev\225rsela a[ENTER]Baek-Go. "
gameforge.locale.old_pirate.baekgo_do_you_get_the_virus = "No s\233 que hay detras de esta enfermedad[ENTER]misteriosa. "
gameforge.locale.old_pirate.baekgo_iv_got_the_virus = "Encontr\233 la causa de la enfermedad misteriosa. "
gameforge.locale.old_pirate.baekgo_order_find_virus_label = "Elimina a todas las personas infectadas "
gameforge.locale.old_pirate.baekgo_order_find_virus_text_1 = "\161Mata a todo aquel que haya sido infectado con la[ENTER]enfermedad misteriosa! "
gameforge.locale.old_pirate.baekgo_order_find_virus_text_2 = "Mata a todo aquel que haya sido infectado con la[ENTER]enfermedad misteriosa y ll\233vale una muestra del[ENTER]pat\243geno a Baek-Go. \201l har\225 la medicina para el[ENTER]pirata viejo. "
gameforge.locale.old_pirate.baekgo_order_too_late = "Baek-Go:[ENTER]Otro ya ha entregado una muestra del pat\243geno.[ENTER]Envi\233 la medicina al pirata viejo; \233l debe estar[ENTER]bien ahora. "
gameforge.locale.old_pirate.baekgo_start_say = "Baek-Go:[ENTER]\191\201l tuvo contacto con una persona infectada s\243lo[ENTER]una vez y su herida empez\243 a picar y supurar? "
gameforge.locale.old_pirate.baekgo_start_say2 = "Baek-Go:[ENTER]\161Oh Dios! \161Estoy bastante seguro de que est\225[ENTER]infectado con esta enfermedad misteriosa! \161Si no[ENTER]es tratado, la enfermedad se extender\225 por toda[ENTER]la aldea! "
gameforge.locale.old_pirate.baekgo_start_say3 = "Baek-Go:[ENTER]\201l no debe contagiar a nadie. Debes curarlo de[ENTER]inmediato. Para ello, necesitamos una muestra del[ENTER]germen pat\243geno de esta enfermedad misteriosa.[ENTER]Puedes obtener una muestra de las personas[ENTER]infectadas que viven en Monte Sohan, en el norte. "
gameforge.locale.old_pirate.baekgo_success_say = "Baek-Go:[ENTER]\161Lo hiciste! Espera un momento, har\233 la medicina[ENTER]ahora mismo. [DELAY value;1000] [/DELAY][ENTER] Ten\237a[ENTER]prisa, as\237 que no s\233 si realmente funcionar\225,[ENTER]pero al menos deber\237a sentirse mejor.[ENTER]Ll\233vale la medicina lo antes posible. "
gameforge.locale.old_pirate.baekgo_talk = "El pirata viejo me env\237a. "
gameforge.locale.old_pirate.baekgo_talk_about_old_pirate = "La enfermedad del pirata viejo "
gameforge.locale.old_pirate.complete_say = "Pirata viejo:[ENTER]Todav\237a pica. Pero me siento mejor ahora. Supongo[ENTER]que podr\233 vivir as\237. "
gameforge.locale.old_pirate.do_you_get_the_medicine = "A\250n no tengo la medicina. "
gameforge.locale.old_pirate.do_you_mean_this_medicine = "\161Aqu\237 est\225 la cura! "
gameforge.locale.old_pirate.etc_shop_start_say = "Vendedora:[ENTER]\191El pirata viejo? \161Por supuesto que le conozco![ENTER]Est\225s hablando sobre ese tipo que maldice[ENTER]constantemente y se rasca, \191no? Viene de vez en[ENTER]cuando para comprar medicamento l\237quido. Gasta[ENTER]varios miles de Yang en medicina roja. "
gameforge.locale.old_pirate.etc_shop_start_say2 = "Vendedora:[ENTER]\191De d\243nde demonios saca tanto Yang si ni siquiera[ENTER]trabaja? Ya le he dicho varias veces que vaya a[ENTER]ver a un m\233dico, pero no me escucha.[ENTER]La medicina roja alivia solo los s\237ntomas, pero[ENTER]no cura la enfermedad. Me temo que esto no[ENTER]acabar\225 bien. "
gameforge.locale.old_pirate.etc_shop_talk_about_old_pirate = "\191Conoces al pirata viejo? "
gameforge.locale.old_pirate.order_accept = "Te ayudar\233 "
gameforge.locale.old_pirate.order_accept_answer = "Pirata viejo:[ENTER]\161Genial! \161Buena suerte![ENTER]El m\233dico estar\225 muy probablemente en la ciudad. "
gameforge.locale.old_pirate.order_find_medicine_label = "Medicina para el pirata viejo "
gameforge.locale.old_pirate.order_find_medicine_text_1 = "Consigue la medicina para el pirata viejo. "
gameforge.locale.old_pirate.order_find_medicine_text_2 = "Ve a ver a Baek-Go en la ciudad y preg\250ntale por[ENTER]la medicina para el pirata viejo. "
gameforge.locale.old_pirate.order_refuse = "Lo siento, no puedo hacerlo. "
gameforge.locale.old_pirate.order_refuse_answer = "Pirata viejo:[ENTER]Bien, entonces no tengo nada m\225s que decirte. "
gameforge.locale.old_pirate.order_say1 = "Pirata viejo:[ENTER]Maldici\243n, \191qu\233 quieres de m\237? \161Majadero! La[ENTER]vieja bruja del almac\233n general te habl\243 sobre[ENTER]m\237, \191no?[ENTER]S\237, todo lo que dice es cierto. Pero no tengo[ENTER]tiempo para ir a ver al m\233dico. \161Tengo tantos[ENTER]enemigos! "
gameforge.locale.old_pirate.order_say2 = "Pirata viejo:[ENTER]\161Nunca se sabe si uno de esos bastardos aparecer\225[ENTER]delante tuyo y te apu\241alar\225! Pero el picor es tan[ENTER]terrible; \161no puedo aguantarlo m\225s! \191Qu\233 dices?[ENTER]\191Puedes ir al m\233dico y conseguir la medicina? Si[ENTER]la consigues, te recompensar\233 bien. "
gameforge.locale.old_pirate.order_too_late = "Pirata viejo:[ENTER]Otro ya trajo la medicina. Bueno, \161eso significa[ENTER]que no hay recompensa para ti! "
gameforge.locale.old_pirate.start_find_old_pirate_label = "Ve con el pirata viejo. "
gameforge.locale.old_pirate.start_find_old_pirate_text_1 = "Ve con el pirata viejo. "
gameforge.locale.old_pirate.start_find_old_pirate_text_2 = "Ve con el pirata viejo y preg\250ntale por qu\233 no[ENTER]quiere ir a ver a un m\233dico. "
gameforge.locale.old_pirate.start_say = "Pirata viejo:[ENTER]\161Todo pica! \161No deber\237a haberme chocado con ese[ENTER]tipo! \161Apenas nos rozamos! \161Desde entonces, el[ENTER]lugar que toc\243 ha estado ulcerando y mi cuerpo[ENTER]entero pica! \161Como si me estuviera pudriendo[ENTER]vivo! \161Bastardo! "
gameforge.locale.old_pirate.success_thanks = "Pirata viejo:[ENTER]\191Qu\233? \191Me contagi\233 por una enfermedad misteriosa?[ENTER]\191Y esta es la medicina necesaria? \161Gracias,[ENTER]muchas gracias! \161Me has salvado la vida! Estoy[ENTER]realmente agradecido. "
gameforge.locale.old_pirate.talk = "\191Eres t\250 el pirata viejo? "
gameforge.locale.old_pirate.talk_about_medicine = "\191Por qu\233 no vas a ver a un m\233dico? "
