gameforge.locale.questscroll5.mission_10_hunt = "La marcha de los osos hambrientos "
gameforge.locale.questscroll5.mission_10_mis = "Mata 25 Osos Negros y 25 Osos Pardos. "
gameforge.locale.questscroll5.mission_10_text = "Oh, por favor ay\250danos. \218ltimamente, un creciente[ENTER]n\250mero de osos pardos y osos negros da\241an[ENTER]nuestras colmenas y plantaciones. Por favor,[ENTER]ay\250danos. Sin las abejas ni las frutas, moriremos[ENTER]de hambre. Mata a esas bestias por nosotros. "
gameforge.locale.questscroll5.mission_11_hunt = "La Tormenta de los lobos azules "
gameforge.locale.questscroll5.mission_11_mis = "Mata 35 lobos azules y 25 lobos alfa azules. "
gameforge.locale.questscroll5.mission_11_text = "\191Has oido sobre la tormenta de los lobos azules?[ENTER]Se refiere a todo el caos que causaron los lobos[ENTER]azules las pasadas semanas. Eliminaron todo a su[ENTER]paso, como si fueran una tormenta de piel y[ENTER]colmillos. Guerrero, \191puedes luchar contra esta[ENTER]tormenta? "
gameforge.locale.questscroll5.mission_12_hunt = "Expulsando a la armada blanca "
gameforge.locale.questscroll5.mission_12_mis = "Mata 20 l\237deres del Juramento Blanco. "
gameforge.locale.questscroll5.mission_12_text = "Recientemente, el Juramento blanco ha estado[ENTER]causando un mont\243n de problemas. Capturan a los[ENTER]vendedores ambulantes muy a menudo y da\241an la[ENTER]aldea. Por favor deten a la armada del Juramento[ENTER]Blanco. Elimina a los miembros del Juramento[ENTER]Blanco y a su l\237der. "
gameforge.locale.questscroll5.mission_13_hunt = "Alborotado Viento Negro "
gameforge.locale.questscroll5.mission_13_mis = "Mata 25 Jak-To y 25 To-Su del Clan del Viento[ENTER]Negro. "
gameforge.locale.questscroll5.mission_13_text = "Se dice que el Clan del Viento Negro quiere[ENTER]encargarse del reino. Antes de que puedan[ENTER]fortalecer su armada, deber\237amos eliminar a sus[ENTER]l\237deres. Por favor, hazlo; por favor, elimina a[ENTER]los l\237deres. "
gameforge.locale.questscroll5.mission_14_hunt = "Gran rebeli\243n de los orcos 1 "
gameforge.locale.questscroll5.mission_14_mis = "Mata 30 orcos \233lite y 30 exploradores \233lite orco. "
gameforge.locale.questscroll5.mission_14_text = "La informaci\243n secreta parece mostrar que los[ENTER]l\237deres de los orcos del valle de Seungryong de[ENTER]la zona neutral, planean conquistar el mundo. Te[ENTER]pido que lo examines, guerrero. Y, de todos[ENTER]modos, una vez que est\233s ah\237 - reduce sus filas. "
gameforge.locale.questscroll5.mission_15_hunt = "El ataque de los salvajes "
gameforge.locale.questscroll5.mission_15_mis = "Mata 30 soldados infanter\237a salvajes y 30 siervos[ENTER]salvajes. "
gameforge.locale.questscroll5.mission_15_text = "Obtuvimos informaci\243n importante de un esp\237a[ENTER]salvaje capturado. Los salvajes piensan en[ENTER]invadir el reino. Tenemos que atacar antes de que[ENTER]lo hagan. Demuestra tu lealtad al reino. "
gameforge.locale.questscroll5.mission_16_hunt = "Destruye el Metin de Oscuridad "
gameforge.locale.questscroll5.mission_16_mis = "Destruye 3 Metins de Oscuridad. "
gameforge.locale.questscroll5.mission_16_text = "Recientemente, piedras con un chi malvado han[ENTER]estado cayendo cerca de la ciudad. Las[ENTER]investigaciones muestran que el chi de estas[ENTER]piedras vuelve locos a los animales. Destruye[ENTER]esas piedras. Te lo ruego. Seguro que ser\225s[ENTER]recompensado. "
gameforge.locale.questscroll5.mission_17_hunt = "Destruye el Metin Negro "
gameforge.locale.questscroll5.mission_17_mis = "Destruye 2 Metins de Oscuridad. "
gameforge.locale.questscroll5.mission_17_text = "Recientemente, piedras con un chi malvado han[ENTER]estado cayendo cerca de la ciudad. Las[ENTER]investigaciones muestran que el chi de estas[ENTER]piedras vuelve locos a los animales. Destruye[ENTER]esas piedras. Te lo ruego. Seguro que ser\225s[ENTER]recompensado. "
gameforge.locale.questscroll5.mission_18_hunt = "El ataque de las Se-Rangs "
gameforge.locale.questscroll5.mission_18_mis = "Mata 10 Se-Rangs de la armada del Juramento[ENTER]Blanco. "
gameforge.locale.questscroll5.mission_18_text = "Guerrero, hay nueva informaci\243n sobre la armada[ENTER]del Juramento Blanco. En oposici\243n a la presi\243n[ENTER]que les ofrecimos, las Se-Rangs, l\237deres del[ENTER]Juramento Blanco, han comenzado una[ENTER]contraofensiva. \161Haz algo contra las Se-Rangs[ENTER]ahora mismo! No ayudar\225 matar unos cuantos[ENTER]soldados de a pie. Tenemos que coger a sus[ENTER]l\237deres para detener sus planes. "
gameforge.locale.questscroll5.mission_19_hunt = "Gran rebeli\243n de los orcos 2 "
gameforge.locale.questscroll5.mission_19_mis = "Mata 20 guerreros \233lite orco y 15 hechiceros orco[ENTER]\233lite. "
gameforge.locale.questscroll5.mission_19_text = "La informaci\243n secreta parece mostrar que los[ENTER]l\237deres de los orcos del valle de Seungryong de[ENTER]la zona neutral, planean conquistar el mundo. Te[ENTER]pido que lo examines, guerrero. Y, de todos[ENTER]modos, una vez que est\233s ah\237 - reduce sus filas. "
gameforge.locale.questscroll5.mission_1_hunt = "Destruye el Metin de Combate "
gameforge.locale.questscroll5.mission_1_mis = "Destruye 3 Metins de Combate "
gameforge.locale.questscroll5.mission_1_text = "Recientemente, piedras con un chi malvado han[ENTER]estado cayendo cerca de la ciudad. Las[ENTER]investigaciones muestran que el chi de estas[ENTER]piedras vuelve locos a los animales. Destruye[ENTER]esas piedras. Te lo ruego. Seguro que ser\225s[ENTER]recompensado. "
gameforge.locale.questscroll5.mission_20_hunt = "El secreto de la mazmorra normal de los monos 1 "
gameforge.locale.questscroll5.mission_20_mis = "Mata 30 soldados mono y 30 lanzadores mono. "
gameforge.locale.questscroll5.mission_20_text = "Finalmente hemos descubierto la localizaci\243n de[ENTER]la Mazmorra de Monos normal en el desierto.[ENTER]Normalmente, los monos que viven all\237 son[ENTER]inofensivos, pero cuando se juntan, presentan una[ENTER]gran amenaza para nuestro reino. Ve a la Mazmorra[ENTER]de Monos normal y comprueba la situaci\243n de los[ENTER]monos. "
gameforge.locale.questscroll5.mission_21_hunt = "El secreto de la mazmorra f\225cil de los monos 1 "
gameforge.locale.questscroll5.mission_21_mis = "Mata 30 soldados mono d\233biles y 30 lanzadores[ENTER]mono d\233biles. "
gameforge.locale.questscroll5.mission_21_text = "La localizaci\243n de la mazmorra f\225cil de los monos[ENTER]ha sido finalmente encontrada. Normalmente, esos[ENTER]monos no son una amenaza, pero cuando se juntan,[ENTER]se pueden convertir en una amenaza para nuestro[ENTER]reino. Ve a la mazmorra f\225cil de los monos y[ENTER]descubre qu\233 est\225 pasando. "
gameforge.locale.questscroll5.mission_22_hunt = "Siembran viento y recogen tempestades. "
gameforge.locale.questscroll5.mission_22_mis = "Mata cuatro Chuongs del Clan del Viento Negro. "
gameforge.locale.questscroll5.mission_22_text = "Los Chuongs, l\237deres del Clan del Viento Negro,[ENTER]han empezado a causar problemas. Desde que son[ENTER]maestros en la lucha con espada, han empezado a[ENTER]pelear con guerreros solo por diversi\243n. Detenles[ENTER]antes de que el Clan del Viento Negro entero se[ENTER]les una. "
gameforge.locale.questscroll5.mission_23_hunt = "Destruye el Metin de Celos "
gameforge.locale.questscroll5.mission_23_mis = "Destruye 2 Metins de Celos "
gameforge.locale.questscroll5.mission_23_text = "Recientemente, piedras con un chi malvado han[ENTER]estado cayendo cerca de la ciudad. Las[ENTER]investigaciones muestran que el chi de estas[ENTER]piedras vuelve locos a los animales. Destruye[ENTER]esas piedras. Te lo ruego. Seguro que ser\225s[ENTER]recompensado. "
gameforge.locale.questscroll5.mission_24_hunt = "El secreto de la mazmorra normal de los monos 2 "
gameforge.locale.questscroll5.mission_24_mis = "Mata 15 luchadores mono y 15 generales mono. "
gameforge.locale.questscroll5.mission_24_text = "La localizaci\243n de la mazmorra normal de los[ENTER]monos en el desierto ha sido finalmente[ENTER]encontrada. Normalmente, esos monos no son una[ENTER]amenaza, pero cuando se juntan, se pueden[ENTER]convertir en una amenaza para nuestro reino. Ve a[ENTER]la mazmorra normal de los monos y descubre qu\233[ENTER]est\225 pasando. "
gameforge.locale.questscroll5.mission_25_hunt = "El secreto de la mazmorra f\225cil de los monos 2 "
gameforge.locale.questscroll5.mission_25_mis = "Mata 15 luchadores mono y 15 generales mono[ENTER]d\233biles. "
gameforge.locale.questscroll5.mission_25_text = "La localizaci\243n de la mazmorra f\225cil de los monos[ENTER]ha sido finalmente encontrada. Normalmente, esos[ENTER]monos no son una amenaza, pero cuando se juntan,[ENTER]se pueden convertir en una amenaza para nuestro[ENTER]reino. Ve a la mazmorra f\225cil de los monos y[ENTER]descubre qu\233 est\225 pasando. "
gameforge.locale.questscroll5.mission_26_hunt = "Destruye el Metin de Alma "
gameforge.locale.questscroll5.mission_26_mis = "Destruye 2 Metins de Alma "
gameforge.locale.questscroll5.mission_26_text = "Recientemente, piedras con un chi malvado han[ENTER]estado cayendo cerca de la ciudad. Las[ENTER]investigaciones muestran que el chi de estas[ENTER]piedras vuelve locos a los animales. Destruye[ENTER]esas piedras. Te lo ruego. Seguro que ser\225s[ENTER]recompensado. "
gameforge.locale.questscroll5.mission_27_hunt = "La ira de la ara\241a 1 "
gameforge.locale.questscroll5.mission_27_mis = "Mata 40 cr\237as ara\241a. "
gameforge.locale.questscroll5.mission_27_text = "Recientemente, las ara\241as que normalmente viven[ENTER]pac\237ficamente en el desierto Yongbi han comenzado[ENTER]a atacar y matar viajeros. Esto es malo para los[ENTER]negocios de nuestro reino. Por favor, elimina a[ENTER]esas ara\241as. "
gameforge.locale.questscroll5.mission_28_hunt = "La ira de la ara\241a 2 "
gameforge.locale.questscroll5.mission_28_mis = "Mata 40 ara\241as venenosas "
gameforge.locale.questscroll5.mission_28_text = "Recientemente, las ara\241as que normalmente viven[ENTER]pac\237ficamente en el desierto Yongbi han comenzado[ENTER]a atacar y matar viajeros. Esto es malo para los[ENTER]negocios de nuestro reino. Por favor, elimina a[ENTER]esas ara\241as. "
gameforge.locale.questscroll5.mission_29_hunt = "Disc\237pulos de la Fe Negra 2 "
gameforge.locale.questscroll5.mission_29_mis = "Mata 20 Luchadores Arahan Esot\233ricos y 25 Jefes[ENTER]Arahan Esot\233ricos. "
gameforge.locale.questscroll5.mission_29_text = "Finalmente, hemos recibido la orden de eliminar a[ENTER]la secta m\225s peligrosa del reino entero - la[ENTER]secta de los esot\233ricos oscuros. Les encontrar\225s[ENTER]en el valle de Seunryong. Pon lo mejor de t\237; no[ENTER]son f\225ciles de derrotar. "
gameforge.locale.questscroll5.mission_2_hunt = "Destruye el Metin de Dolor "
gameforge.locale.questscroll5.mission_2_mis = "Destruye 2 Metins de Dolor "
gameforge.locale.questscroll5.mission_2_text = "Recientemente, piedras con un chi malvado han[ENTER]estado cayendo cerca de la ciudad. Las[ENTER]investigaciones muestran que el chi de estas[ENTER]piedras vuelve locos a los animales. Destruye[ENTER]esas piedras. Te lo ruego. Seguro que ser\225s[ENTER]recompensado. "
gameforge.locale.questscroll5.mission_30_hunt = "Disc\237pulos de la Fe Negra 1 "
gameforge.locale.questscroll5.mission_30_mis = "Mata 30 Fan\225ticos Oscuros y 30 Arahan Oscuros. "
gameforge.locale.questscroll5.mission_30_text = "Finalmente, hemos recibido la orden de eliminar a[ENTER]la secta m\225s peligrosa del reino entero - la[ENTER]secta de los esot\233ricos oscuros. Les encontrar\225s[ENTER]en el valle de Seunryong. Pon lo mejor de t\237; no[ENTER]son f\225ciles de derrotar. "
gameforge.locale.questscroll5.mission_31_hunt = "Disc\237pulos de la Fe Negra 3 "
gameforge.locale.questscroll5.mission_31_mis = "Mata 40 torturadores oscuros y 40 requeridores[ENTER]oscuros. "
gameforge.locale.questscroll5.mission_31_text = "Finalmente, hemos recibido la orden de eliminar a[ENTER]la secta m\225s peligrosa del reino entero - la[ENTER]secta de los esot\233ricos oscuros. Les encontrar\225s[ENTER]en el valle de Seunryong. Pon lo mejor de t\237; no[ENTER]son f\225ciles de derrotar. "
gameforge.locale.questscroll5.mission_32_hunt = "Destruye el Metin de Sombra "
gameforge.locale.questscroll5.mission_32_mis = "Destruye 2 Metins de Sombra. "
gameforge.locale.questscroll5.mission_32_text = "Recientemente, piedras con un chi malvado han[ENTER]estado cayendo cerca de la ciudad. Las[ENTER]investigaciones muestran que el chi de estas[ENTER]piedras vuelve locos a los animales. Destruye[ENTER]esas piedras. Te lo ruego. Seguro que ser\225s[ENTER]recompensado. "
gameforge.locale.questscroll5.mission_33_hunt = "Tienen 8 patas 1 "
gameforge.locale.questscroll5.mission_33_mis = "Mata 35 cr\237as ara\241a y 35 ara\241as veneno mortal. "
gameforge.locale.questscroll5.mission_33_text = "El imperio encontr\243 un sistema de cuevas que se[ENTER]supone que es el escondite de las ara\241as del[ENTER]desierto Yongbi. No hay informaci\243n precisa sobre[ENTER]las cuevas de las ara\241as. Lo \250nico que sabemos es[ENTER]que es muy peligroso. \191Podr\237as comprobar ese[ENTER]lugar? Det\233n la propagaci\243n de su poder[ENTER]reduciendo su n\250mero. "
gameforge.locale.questscroll5.mission_34_hunt = "Tienen 8 patas 2 "
gameforge.locale.questscroll5.mission_34_mis = "Mata 35 cr\237as ara\241a y 35 ara\241as veneno mortal. "
gameforge.locale.questscroll5.mission_34_text = "El imperio encontr\243 un sistema de cuevas que se[ENTER]supone que es el escondite de las ara\241as del[ENTER]desierto Yongbi. No hay informaci\243n precisa sobre[ENTER]las cuevas de las ara\241as. Lo \250nico que sabemos es[ENTER]que es muy peligroso. \191Podr\237as comprobar ese[ENTER]lugar? Det\233n la propagaci\243n de su poder[ENTER]reduciendo su n\250mero. "
gameforge.locale.questscroll5.mission_35_hunt = "Tienen 8 patas 3 "
gameforge.locale.questscroll5.mission_35_mis = "Mata 35 Ara\241as Veneno Letal Rojas y 35 Ara\241as[ENTER]Garra Veneno. "
gameforge.locale.questscroll5.mission_35_text = "El imperio encontr\243 un sistema de cuevas que se[ENTER]supone que es el escondite de las ara\241as del[ENTER]desierto Yongbi. No hay informaci\243n precisa sobre[ENTER]las cuevas de las ara\241as. Lo \250nico que sabemos es[ENTER]que es muy peligroso. \191Podr\237as comprobar ese[ENTER]lugar? Det\233n la propagaci\243n de su poder[ENTER]reduciendo su n\250mero. "
gameforge.locale.questscroll5.mission_36_hunt = "Tienen 8 patas 4 "
gameforge.locale.questscroll5.mission_36_mis = "Mata 40 soldados ara\241a venenosos. "
gameforge.locale.questscroll5.mission_36_text = "El imperio encontr\243 un sistema de cuevas que se[ENTER]supone que es el escondite de las ara\241as del[ENTER]desierto Yongbi. No hay informaci\243n precisa sobre[ENTER]las cuevas de las ara\241as. Lo \250nico que sabemos es[ENTER]que es muy peligroso. \191Podr\237as comprobar ese[ENTER]lugar? Det\233n la propagaci\243n de su poder[ENTER]reduciendo su n\250mero. "
gameforge.locale.questscroll5.mission_37_hunt = "Destruye el Metin de Dureza "
gameforge.locale.questscroll5.mission_37_mis = "Destruye 2 Metins de Dureza. "
gameforge.locale.questscroll5.mission_37_text = "Recientemente, piedras con un chi malvado han[ENTER]estado cayendo cerca de la ciudad. Las[ENTER]investigaciones muestran que el chi de estas[ENTER]piedras vuelve locos a los animales. Destruye[ENTER]esas piedras. Te lo ruego. Seguro que ser\225s[ENTER]recompensado. "
gameforge.locale.questscroll5.mission_38_hunt = "Plaga de escorpi\243n "
gameforge.locale.questscroll5.mission_38_mis = "Mata 30 reyes escorpi\243n y 20 hombres escorpi\243n[ENTER]j\243venes. "
gameforge.locale.questscroll5.mission_38_text = "Esas criaturas escorpi\243n est\225n tiranizando a[ENTER]viajeros y mercaderes, lo que es realmente malo[ENTER]para la econom\237a del reino. Por favor, ay\250danos a[ENTER]librarnos de esta plaga. "
gameforge.locale.questscroll5.mission_39_hunt = "Compa\241\237a de la muerte 1 "
gameforge.locale.questscroll5.mission_39_mis = "Mata 30 soldados demonio y 20 arqueros demonio. "
gameforge.locale.questscroll5.mission_39_text = "\191Has o\237do alguna vez de la Torre Demon\237aca?[ENTER]Sectas esot\233ricas invocaron soldados demon\237acos[ENTER]con hechizos poderosos.[ENTER]Lucha con ellos y averigua lo poderosos que son. "
gameforge.locale.questscroll5.mission_3_hunt = "Emergencia de los lobos grises 2 "
gameforge.locale.questscroll5.mission_3_mis = "Mata 30 lobos alfa grises "
gameforge.locale.questscroll5.mission_3_text = "\191Has oido sobre los lobos alfa grises? Sol\237an[ENTER]vagar por su cuenta, pero debido a la influencia[ENTER]del chi malvado de las pasadas semanas, han[ENTER]empezado a cazar viajeros en manadas. \191Podr\237as[ENTER]eliminar a esos lobos alfa grises? Seguro que[ENTER]ser\225s recompensado. "
gameforge.locale.questscroll5.mission_40_hunt = "Compa\241\237a de la muerte 2 "
gameforge.locale.questscroll5.mission_40_mis = "Mata 30 lanceros demonio y 25 chamanes demonio. "
gameforge.locale.questscroll5.mission_40_text = "\191Has o\237do alguna vez de la Torre Demon\237aca?[ENTER]Sectas esot\233ricas invocaron soldados demon\237acos[ENTER]con hechizos poderosos.[ENTER]Lucha contra ellos y averigua lo poderosos que[ENTER]son. "
gameforge.locale.questscroll5.mission_41_hunt = "El secreto de la mazmorra de los monos dif\237cil 2 "
gameforge.locale.questscroll5.mission_41_mis = "Mata 15 soldados mono fuerte y 15 generales mono[ENTER]fuerte. "
gameforge.locale.questscroll5.mission_41_text = "La localizaci\243n de la mazmorra dif\237cil de los[ENTER]monos ha sido finalmente encontrada. Normalmente,[ENTER]esos monos no son una amenaza, pero cuando se[ENTER]juntan, se pueden convertir en una amenaza para[ENTER]nuestro reino. Ve a la mazmorra dif\237cil de los[ENTER]monos y descubre qu\233 est\225 pasando. "
gameforge.locale.questscroll5.mission_42_hunt = "El hielo se derretir\225 alg\250n d\237a "
gameforge.locale.questscroll5.mission_42_mis = "Mata 25 golems de hielo en la monta\241a Sohan. "
gameforge.locale.questscroll5.mission_42_text = "\191Conoces la monta\241a Sohan que est\225 cubierta de[ENTER]hielo? Muchos exploradores y guerreros fueron[ENTER]all\237, pero nunca volvieron. Descubre el motivo de[ENTER]su desaparici\243n y si fueron atacados. Quiz\225[ENTER]puedas descubrir algo m\225s si capturas algunos[ENTER]monstruos all\237. "
gameforge.locale.questscroll5.mission_43_hunt = "El secreto de la mazmorra dif\237cil de los monos 1 "
gameforge.locale.questscroll5.mission_43_mis = "Mata 30 soldados mono fuerte y 30 lanzadores mono[ENTER]fuerte. "
gameforge.locale.questscroll5.mission_43_text = "La localizaci\243n de la mazmorra dif\237cil de los[ENTER]monos ha sido finalmente encontrada. Normalmente,[ENTER]esos monos no son una amenaza, pero cuando se[ENTER]juntan, se pueden convertir en una amenaza para[ENTER]nuestro reino. Ve a la mazmorra dif\237cil de los[ENTER]monos y descubre qu\233 est\225 pasando. "
gameforge.locale.questscroll5.mission_44_hunt = "La mano derecha del Tigre Fantasma Amarillo "
gameforge.locale.questscroll5.mission_44_mis = "Mata 30 generales bullfrog. "
gameforge.locale.questscroll5.mission_44_text = "El Tigre Fantasma Amarillo, rey de todas las[ENTER]criaturas de este continente, ha movilizado a los[ENTER]animales \250ltimamente. El servicio de inteligencia[ENTER]del reino piensa que esta es la raz\243n por la que[ENTER]los animales se han vuelto salvajes. Es necesario[ENTER]reducir las tropas del Tigre Fantasma Amarillo.[ENTER]Elimina a los l\237deres, que son su mano derecha. "
gameforge.locale.questscroll5.mission_45_hunt = "\191El due\241o de la monta\241a Sohan? "
gameforge.locale.questscroll5.mission_45_mis = "Elimina a 35 Hombres de Hielo Glacial y a 30[ENTER]Yetis. "
gameforge.locale.questscroll5.mission_45_text = "Se dice que el zorro de nueve colas, se\241or de la[ENTER]monta\241a Sohan, est\225 reuniendo demonios en torno a[ENTER]el. Antes de que tenga todas las tropas que[ENTER]necesita, tenemos que matar hombres de hielo y[ENTER]yetis, ya que son la columna vertebral de sus[ENTER]tropas. Por favor, ay\250danos. Ser\225s recompensado. "
gameforge.locale.questscroll5.mission_46_hunt = "Chunwa Bong-ki "
gameforge.locale.questscroll5.mission_46_mis = "Mata 45 soldados rana y 35 l\237deres rana. "
gameforge.locale.questscroll5.mission_46_text = "El Tigre Fantasma Amarillo parece que conspira[ENTER]con los monstruos Rana Arbor\237cola. Elimina sus[ENTER]unidades inmediatamente. Si las ignoras, esto[ENTER]causar\225 un mont\243n de problemas al reino. "
gameforge.locale.questscroll5.mission_47_hunt = "\161Monstruos de hielo! Su verdadero car\225cter "
gameforge.locale.questscroll5.mission_47_mis = "Destruye 45 hielos encantados. "
gameforge.locale.questscroll5.mission_47_text = "Sabemos c\243mo se comunican los monstruos de hielo[ENTER]de la monta\241a Sohan entre ellos. Difunden la[ENTER]informaci\243n usando los monstruos de hielo. Es[ENTER]absolutamente necesario debilitar las tropas de[ENTER]la monta\241a Sohan, as\237 que, por favor, mata a los[ENTER]monstruos de hielo de all\237. "
gameforge.locale.questscroll5.mission_48_hunt = "El secreto de la Torre Demon\237aca "
gameforge.locale.questscroll5.mission_48_mis = "Mata 45 Demonios Lanceros Brutales. "
gameforge.locale.questscroll5.mission_48_text = "Se rumorea que los Lanceros Vil Demonio en la[ENTER]Torre Demon\237aca son invencibles. Al parecer,[ENTER]ellos vuelven a resucitar cuando son eliminados.[ENTER]si esto es cierto, nos esperan malos tiempos.[ENTER]\161Por favor descubre m\225s al respecto! "
gameforge.locale.questscroll5.mission_49_hunt = "El Due\241o de la Torre Demon\237aca "
gameforge.locale.questscroll5.mission_49_mis = "Mata 60 Chamanes Demonio Brutales. "
gameforge.locale.questscroll5.mission_49_text = "Despu\233s de una amplia investigaci\243n, hemos[ENTER]descubierto que los soldados fantasma son siempre[ENTER]resucitados. Tenemos que eliminar a los Chamanes[ENTER]Demonio Brutales para detener esto. "
gameforge.locale.questscroll5.mission_4_hunt = "Emergencia de los lobos grises 1 "
gameforge.locale.questscroll5.mission_4_mis = "Mata 35 lobos grises "
gameforge.locale.questscroll5.mission_4_text = "\191Has oido sobre los lobos grises? Sol\237an vagar[ENTER]por su cuenta, pero debido a la influencia del[ENTER]chi malvado de las pasadas semanas, han empezado[ENTER]a cazar viajeros en manadas.[ENTER]\191Podr\237as eliminar a esos lobos grises? Seguro que[ENTER]ser\225s recompensado. "
gameforge.locale.questscroll5.mission_50_hunt = "Explora Doyyumhwan "
gameforge.locale.questscroll5.mission_50_mis = "Mata 45 Siervos Tigre Luchador. "
gameforge.locale.questscroll5.mission_50_text = "Doyyumhwan es un \225rea de lava poblada por[ENTER]monstruos desconocidos.[ENTER]Tenemos que explorar este \225rea. \191Puedes ayudarnos? "
gameforge.locale.questscroll5.mission_51_hunt = "\161Fantasma Llama! Su identidad "
gameforge.locale.questscroll5.mission_51_mis = "Mata 45 fantasmas llama. "
gameforge.locale.questscroll5.mission_51_text = "Un grupo que se supon\237a que iba a derrotar a los[ENTER]tigres luchadores fue eliminado por enemigos[ENTER]desconocidos. Se dice que esos enemigos parecian[ENTER]'ni\241as en llamas'. Descubre la verdad. "
gameforge.locale.questscroll5.mission_52_hunt = "Reduce el numero de tigres luchadores "
gameforge.locale.questscroll5.mission_52_mis = "Mata 60 Siervos Tigre Luchador y 40 Tigres[ENTER]Luchadores. "
gameforge.locale.questscroll5.mission_52_text = "Ahora que podemos luchar contra los fantasmas de[ENTER]llama, tenemos que eliminarlos completamente en[ENTER]campo abierto. Una misi\243n como esta normalmente[ENTER]es llevada a cabo por la milicia, pero para ganar[ENTER]la m\225xima fuerza de batalla para luchar contra[ENTER]los fantasmas de llama, necesitamos una t\233cnica[ENTER]mejor. Por favor aseg\250rate de que los tigres[ENTER]luchadores no se interpongan en nuestro camino. "
gameforge.locale.questscroll5.mission_53_hunt = "Examina las Llamas "
gameforge.locale.questscroll5.mission_53_mis = "Mata 40 Llamas. "
gameforge.locale.questscroll5.mission_53_text = "Las Llamas son incre\237blemente brutales. Disfrutan[ENTER]del dolor de la gente a la que devoran la piel.[ENTER]Aun no sabemos c\243mo matarlos. \191Podr\237as[ENTER]averiguarlo? "
gameforge.locale.questscroll5.mission_54_hunt = "Guerreros Llama "
gameforge.locale.questscroll5.mission_54_mis = "Mata 60 Guerreros Llama "
gameforge.locale.questscroll5.mission_54_text = "No hace mucho tiempo, el hijo de un noble que se[ENTER]adentr\243 en el Tierra de Fuego fue asesinado por[ENTER]un guerrero llama. Si matas a los guerreros[ENTER]llama, ser\225s recompensado. \191Por qu\233 no lo[ENTER]intentas? "
gameforge.locale.questscroll5.mission_55_hunt = "Examina los \225rboles fantasma "
gameforge.locale.questscroll5.mission_55_mis = "Destruye 30 \225rboles fantasma. "
gameforge.locale.questscroll5.mission_55_text = "Normalmente, son como simples \225rboles - y[ENTER]entonces, de repente, atacan animales y humanos.[ENTER]Su n\250mero est\225 incrementando. Descubre c\243mo[ENTER]podemos destruir a los \225rboles fantasma "
gameforge.locale.questscroll5.mission_56_hunt = "El secreto del bosque fantasma "
gameforge.locale.questscroll5.mission_56_mis = "Mata 40 Tocones Fantasma y 30 Dr\237adas. "
gameforge.locale.questscroll5.mission_56_text = "Las investigaciones muestran que el bosque[ENTER]fantasma es un \225rea poblada por tocones fantasma[ENTER]y dr\237adas. Si los eliminas, puedes poner fin a la[ENTER]propagaci\243n de los \225rboles fantasma. "
gameforge.locale.questscroll5.mission_5_hunt = "Preocupados por las aldeas "
gameforge.locale.questscroll5.mission_5_mis = "Mata 40 jabal\237es. "
gameforge.locale.questscroll5.mission_5_text = "En las pasadas semanas, el sufrimiento de las[ENTER]aldeas cercanas a la ciudad, ha empeorado. Los[ENTER]jabal\237es que sol\237an atacar solo a peque\241os[ENTER]animales en las monta\241as, se han vuelto[ENTER]agresivos. Vienen a los campos y atacan a los[ENTER]granjeros. \191Podr\237as ahuyentar a los jabal\237es? "
gameforge.locale.questscroll5.mission_6_hunt = "Tigres y Osos "
gameforge.locale.questscroll5.mission_6_mis = "Mata 25 tigres y 30 osos "
gameforge.locale.questscroll5.mission_6_text = "\191Ya hab\237as escuchado algo sobre esto? Si los[ENTER]tigres y osos comen solo ajos y cebollas durante[ENTER]100 d\237as, pueden convertirse en osos mayores y[ENTER]tigres de fuego. No es del todo seguro, pero no[ENTER]har\225 da\241o comprobarlo de todos modos. Examinalo[ENTER]matando algunos tigres y osos. Ser\225s[ENTER]recompensado. "
gameforge.locale.questscroll5.mission_7_hunt = "Destruye el Metin de Avaricia. "
gameforge.locale.questscroll5.mission_7_mis = "Destruye 2 Metins de Avaricia. "
gameforge.locale.questscroll5.mission_7_text = "Recientemente, piedras con un chi malvado han[ENTER]estado cayendo cerca de la ciudad. Las[ENTER]investigaciones muestran que el chi de estas[ENTER]piedras vuelve locos a los animales. Destruye[ENTER]esas piedras. Te lo ruego. Seguro que ser\225s[ENTER]recompensado. "
gameforge.locale.questscroll5.mission_8_hunt = "Destruye el Metin de Batalla "
gameforge.locale.questscroll5.mission_8_mis = "Destruye 2 Metins de Batalla "
gameforge.locale.questscroll5.mission_8_text = "Recientemente, piedras con un chi malvado han[ENTER]estado cayendo cerca de la ciudad. Las[ENTER]investigaciones muestran que el chi de estas[ENTER]piedras vuelve locos a los animales. Destruye[ENTER]esas piedras. Te lo ruego. Seguro que ser\225s[ENTER]recompensado. "
gameforge.locale.questscroll5.mission_9_hunt = "Preocupaci\243n por las aldeas 2 "
gameforge.locale.questscroll5.mission_9_mis = "Mata 30 jabal\237es rojos. "
gameforge.locale.questscroll5.mission_9_text = "De un tiempo a esta parte, los jabal\237es y sus[ENTER]l\237deres, los jabal\237es rojos, han estado atacando[ENTER]a las aldeas cercanas a la ciudad principal. El[ENTER]gobierno ha ordenado matar a los jabal\237es rojos.[ENTER]Se pide a los guerreros que maten a 30 jabal\237es[ENTER]rojos cada uno. Por favor, ayuda t\250 tambi\233n. "
gameforge.locale.questscroll_10_hunt = "Soldados serpiente "
gameforge.locale.questscroll_10_mis = "Mata a los soldados que son mitad hombre, mitar[ENTER]serpiente. "
gameforge.locale.questscroll_10_text = "No puedes llamarles humanos. Pero tambi\233n es[ENTER]err\243neo decir que no lo son. Parecen humanos pero[ENTER]cabeza, piel y comportamiento son los de[ENTER]serpientes venenosas.[ENTER]Est\225n en el desierto y atacan a vendedores[ENTER]ambulantes.[ENTER]Mata 20 de aquellos que son medio humanos, medio[ENTER]serpientes. Si los matas, obtendr\225s lo siguiente[ENTER]como recompensa: "
gameforge.locale.questscroll_11_hunt = "Arqueros serpiente "
gameforge.locale.questscroll_11_mis = "Mata a los arqueros que son medio humanos, medio[ENTER]serpientes. "
gameforge.locale.questscroll_11_text = "Son tan inteligentes como los humanos. Son[ENTER]retorcidos y saben c\243mo usar armas.[ENTER]Los arqueros, mitad humano, mitad serpiente,[ENTER]atacan a los mercaderes a distancia. Ya han[ENTER]muerto muchos mercaderes.[ENTER][ENTER]Mata 20 de esos arqueros que son medio humanos,[ENTER]medio serpientes. Si completas la misi\243n con[ENTER]\233xito, ser\225s recompensado con lo siguiente: "
gameforge.locale.questscroll_12_hunt = "Bandidos del Desierto "
gameforge.locale.questscroll_12_mis = "Mata a los Bandidos del Desierto. "
gameforge.locale.questscroll_12_text = "Hay seres malvados viviendo en el desierto[ENTER]Yongbi. Son conocidos como vagabundos del[ENTER]desierto e incluso el cielo llora por sus[ENTER]cr\237menes. Roban y asesinan a mercaderes s\243lo por[ENTER]diversi\243n. Tambi\233n destruyeron las aldeas del[ENTER]desierto.[ENTER]Mata 12 vagabundos del desierto. Si los eliminas,[ENTER]ser\225s recompensado con lo siguiente: "
gameforge.locale.questscroll_13_hunt = "Tigres Luchadores "
gameforge.locale.questscroll_13_mis = "Mata a los Tigres Luchadores. "
gameforge.locale.questscroll_13_text = "Hay animales llamados tigres luchadores. Su[ENTER]sangre est\225 hecha de fuego y sus cuerpos fueron[ENTER]formados de granito volc\225nico. \161Son monstruos[ENTER]incre\237blemente poderosos! Se alimentan de lava y[ENTER]el fuego del volc\225n. A veces, bajan del volc\225n,[ENTER]atacan a gente y se los comen...[ENTER][ENTER]Mata a 20 de esos Tigres Luchadores. Cuando los[ENTER]hayas matado, conseguir\225s esto como recompensa: "
gameforge.locale.questscroll_14_hunt = "Hombres de guerra "
gameforge.locale.questscroll_14_mis = "Mata a los hombres de guerra "
gameforge.locale.questscroll_14_text = "El Doyyumhwan es vasto, c\225lido y tiene animales[ENTER]salvajes. All\237 se reunen los guerreros de Chunjo,[ENTER]Jinno y Shinsoo. Temibles y poderosos monstruos[ENTER]esperan a los guerreros. Los hombres de guerra[ENTER]son los que controlan el Doyyumhwan.[ENTER][ENTER]\191Quieres desafiarles? Si matas 20 hombres de[ENTER]guerra, recibir\225s lo siguiente: "
gameforge.locale.questscroll_15_hunt = "Guerreros Taehwa "
gameforge.locale.questscroll_15_mis = "Derrota a los guerreros Taehwa "
gameforge.locale.questscroll_15_text = "Escuchad, \161vosotros que pens\225is que sois[ENTER]valientes y fuertes guerreros! \161Este es el[ENTER]llameante campo de batalla de l\225grimas, dolor,[ENTER]batallas y muerte! \161Vivo aqu\237 con muchas[ENTER]monstruos y villanos! \191Qui\233n es suficientemente[ENTER]valiente para retarme? \191Hay alguien que quiere[ENTER]enfrentarse a m\237 con una espada en la mano?[ENTER][ENTER]Si tienes fe en tus habilidades, \161ven aqu\237 y[ENTER]r\233tame! Si me derrotas a m\237 y a 12 de mis[ENTER]camaradas, conseguir\225s lo siguiente como[ENTER]recompensa: "
gameforge.locale.questscroll_16_hunt = "Osos oscuros "
gameforge.locale.questscroll_16_mis = "Mata a los osos oscuros "
gameforge.locale.questscroll_16_text = "Me temo que este es el fin. Pero d\233jame contarte[ENTER]sobre un incidente importante... Cuando leas esta[ENTER]carta, ya estar\233 muerto o desaparecido. Viv\237 en[ENTER]el valle de Seungryong, donde recog\237a hierbas[ENTER]m\233dicas. Pero monstruos llamados osos oscuros[ENTER]comenzaron a crecer de manera salvaje. Mataron a[ENTER]mi familia.[ENTER][ENTER]Por favor, v\233ngame a m\237 y a mi familia. Si matas[ENTER]25 osos oscuros, recibir\225s: "
gameforge.locale.questscroll_17_hunt = "Osos gigantes oscuros "
gameforge.locale.questscroll_17_mis = "Mata a los osos gigantes oscuros "
gameforge.locale.questscroll_17_text = "Los monstruos oso han creado un nuevo monstruo[ENTER]apare\225ndose con monstruos a\250n m\225s crueles. Estos[ENTER]nuevos monstruos son los osos gigantes oscuros.[ENTER]Son m\225s grandes y m\225s fuertes que los osos[ENTER]oscuros e incre\237blemente malvados.[ENTER]Mientras est\233n en el valle de Seungryong, la[ENTER]gente sufrir\225.[ENTER][ENTER]Mata 20 osos oscuros gigantes. Si tienes \233xito,[ENTER]recibir\225s esto como recompensa: "
gameforge.locale.questscroll_18_hunt = "Soldados padeciendo una enfermedad misteriosa "
gameforge.locale.questscroll_18_mis = "Mata a los soldados que sufren una enfermedad[ENTER]misteriosa "
gameforge.locale.questscroll_18_text = "La aldea parece haber sido erradicada.[ENTER]Aquellos que sufren de una enfermedad misteriosa,[ENTER]atacan a la gente suficientemente desgraciada[ENTER]para pasar por ah\237. Atacan a los vendedores[ENTER]ambulantes y comen gente. Son extremadamente[ENTER]peligrosos.[ENTER]Mata 35 soldados que sufren de la enfermedad[ENTER]misteriosa. Si tienes \233xito, recibir\225s esto como[ENTER]recompensa: "
gameforge.locale.questscroll_19_hunt = "Arqueros padeciendo una enfermedad misteriosa "
gameforge.locale.questscroll_19_mis = "Mata a los arqueros que sufren de una enfermedad[ENTER]misteriosa "
gameforge.locale.questscroll_19_text = "La enfermedad misteriosa es la raz\243n del da\241o[ENTER]causado por aquellos que la padecen.[ENTER]Aunque lo m\225s peligroso son los arqueros[ENTER]infectados por esta enfermedad. Estos arqueros[ENTER]disparan flechas t\243xicas aturdiendo a los[ENTER]viajeros para poder capturarlos y matarlos.[ENTER][ENTER]Mata 25 arqueros que sufren de la enfermedad[ENTER]misteriosa. Si tienes \233xito, conseguir\225s esto[ENTER]como recompensa: "
gameforge.locale.questscroll_1_hunt = "Osos de fuego "
gameforge.locale.questscroll_1_mis = "Mata 25 osos de fuego "
gameforge.locale.questscroll_1_text = "Los osos de fuego pueden ser encontrados a menudo[ENTER]cerca de las ciudades.[ENTER]Vagan por la pradera y los anchos caminos de los[ENTER]humanos. M\225s y m\225s gente se est\225n convirtiendo en[ENTER]sus v\237ctimas. Ya ha sido asesinada mucha gente.[ENTER][ENTER]Caza a esos osos de fuego. Tan pronto como hayas[ENTER]matado 25 osos de fuego, conseguir\225s esto como[ENTER]recompensa: "
gameforge.locale.questscroll_20_hunt = {}
gameforge.locale.questscroll_20_mis = "Mata 4 enemigos "
gameforge.locale.questscroll_20_text = "\161Me temo que estoy acabado! Mi vista ya se est\225[ENTER]nublando... Cuando leas esta carta, mi cuerpo ya[ENTER]estar\225 putrefacto. Esos bastardos me capturaron y[ENTER]me torturaron. Fu\237 capaz de escapar, pero la[ENTER]herida es demasiado profunda, y me descompongo.[ENTER]No te conozco. \161Pero por favor, v\233ngame![ENTER][ENTER]Mata a 4 enemigos en el emplazamiento de la[ENTER]batalla. Si tienes \233xito, conseguir\225s esto como[ENTER]recompensa: "
gameforge.locale.questscroll_2_hunt = "Gran tigre "
gameforge.locale.questscroll_2_mis = "Mata 20 tigres grandes "
gameforge.locale.questscroll_2_text = "El nombre de este malvado ser puede ser escuchado[ENTER]por todas partes: gran tigre. Estos tigres est\225n[ENTER]a menudo cerca de la ciudad principal. Atacan a[ENTER]la gente y devoran los cuerpos de los mercaderes.[ENTER]Sus v\237ctimas son innumerables.[ENTER][ENTER]Caza a los tigres grandes. Tan pronto como hayas[ENTER]matado a 20 de ellos, recibir\225s esto como[ENTER]recompensa: "
gameforge.locale.questscroll_3_hunt = "Dios Perro de la monta\241a "
gameforge.locale.questscroll_3_mis = "Mata al Dios Perro de la monta\241a "
gameforge.locale.questscroll_3_text = "El Dios Perro de la monta\241a lidera una jaur\237a de[ENTER]monstruos perro no muy lejos de aqu\237. Es fuerte y[ENTER]salvaje.[ENTER]No hace mucho tiempo, apareci\243 cerca de la aldea[ENTER]y comenz\243 a atacar a los mercaderes. Este[ENTER]monstruo ya ha causado muchas muertes. Sus[ENTER]cr\237menes no pueden ser ignorados m\225s.[ENTER][ENTER]Mata al Dios Perro de la monta\241a. Si tienes[ENTER]\233xito, recibir\225s esto como recompensa: "
gameforge.locale.questscroll_4_hunt = "Dios Cerdo "
gameforge.locale.questscroll_4_mis = "Mata al Dios Cerdo "
gameforge.locale.questscroll_4_text = "En esta \233poca del a\241o, los campos est\225n llenos de[ENTER]grano. Tiempo de cosecha; tiempo para que los[ENTER]granjeros obtengan aquello por lo que han[ENTER]trabajado duro. Pero el Dios Cerdo y sus[ENTER]compinches se comen todo el grano. Su avaricia[ENTER]amenaza a los granjeros; tenemos que matarlos.[ENTER][ENTER]Mata al Dios Cerdo. Normalmente est\225 cerca de la[ENTER]ciudad principal. Si tienes \233xito, conseguir\225s[ENTER]esto como recompensa: "
gameforge.locale.questscroll_5_hunt = "Dios Oso "
gameforge.locale.questscroll_5_mis = "Mata al Dios Oso "
gameforge.locale.questscroll_5_text = "En su entorno natural, el Dios Oso era siempre[ENTER]bueno. Pero de un tiempo a esta parte, ha estado[ENTER]cerca de la ciudad, atacando a la gente. Es[ENTER]responsable de m\225s y m\225s v\237ctimas. Es imposible[ENTER]decir cuanta gente ha muerto ya. Tiene que[ENTER]desaparecer de aqu\237.[ENTER][ENTER]Mata al Dios Oso. Si te libras realmente de \233l,[ENTER]conseguir\225s esto como recompensa: "
gameforge.locale.questscroll_6_hunt = "Dios Tigre "
gameforge.locale.questscroll_6_mis = "Mata al Dios Tigre "
gameforge.locale.questscroll_6_text = "No puedo creer que el Dios Tigre realmente[ENTER]hiciera algo tan terrible como esto... Soy s\243lo[ENTER]una simple mujer que siempre lo\233 al Dios Tigre[ENTER]que a veces aparec\237a en la senda de la monta\241a.[ENTER]Aunque, un d\237a, \161el Dios Tigre y sus ac\243litos[ENTER]atacaron a mi familia y los mataron a todos![ENTER]Tambi\233n perd\237 mi brazo.[ENTER][ENTER]Por favor, venga a mi familia. Si matas al Dios[ENTER]Tigre, conseguir\225s esto como recompensa: "
gameforge.locale.questscroll_7_hunt = "L\237der de la armada del Juramento Blanco "
gameforge.locale.questscroll_7_mis = "Mata al l\237der de la armada del Juramento Blanco "
gameforge.locale.questscroll_7_text = "La armada del Juramento Blanco es un grupo de[ENTER]mujeres que han sido abandonadas por sus maridos[ENTER]y maltratadas por el mundo. Puede que sean[ENTER]escasas, pero el modo en el que molestan a los[ENTER]aldeanos es simplemente cruel. Una mujer fu\233[ENTER]apedreada hasta la muerte cuando entraba en la[ENTER]aldea. No podemos permitirles que vengan a la[ENTER]aldea y ataquen a la gente.[ENTER][ENTER]Mata a 20 l\237deres de la armada del Juramento[ENTER]Blanco. Si terminas la misi\243n con \233xito,[ENTER]conseguir\225s esto como recompensa: "
gameforge.locale.questscroll_8_hunt = "L\237der del Clan del Viento Negro "
gameforge.locale.questscroll_8_mis = "Mata al l\237der del Clan del Viento Negro "
gameforge.locale.questscroll_8_text = "Los ladrones del Clan del Viento Negro han estado[ENTER]persiguiendo a los vendedores ambulantes durante[ENTER]mucho tiempo. Son tan temibles que nadie es lo[ENTER]suficientemente valiente para devolver el golpe.[ENTER]Pero no puede seguir as\237; realmente han causado[ENTER]una gran cantidad de da\241o.[ENTER][ENTER]Mata 20 l\237deres del Clan del Viento Negro. Si[ENTER]terminas la misi\243n con \233xito, recibir\225s esto como[ENTER]recompensa: "
gameforge.locale.questscroll_9_hunt = "Jefes de los salvajes "
gameforge.locale.questscroll_9_mis = "Mata a los jefes de los salvajes "
gameforge.locale.questscroll_9_text = "Ha pasado un tiempo desde que los cruzaron la[ENTER]frontera y atacaron la aldea. Mataron a cientos[ENTER]de personas.[ENTER]El n\250mero de afectados fue incluso mayor.[ENTER]Esos salvajes malvados son tan brutales que nadie[ENTER]fu\233 lo suficientemente valiente para detenerles.[ENTER]Pero no podemos tolerarlo m\225s.[ENTER][ENTER]Mata a 25 jefes de los salvajes. Si tienes \233xito,[ENTER]conseguir\225s esto como recompensa: "
gameforge.locale.quest_temp_reward_1 = "Recompensa "
gameforge.locale.quest_temp_reward_2 = "Durante el periodo de prueba de las misiones, no[ENTER]pueden obtenerse recompensas. Una vez que ha sido[ENTER]recibida la recompensa, la misi\243n actual puede[ENTER]ser ejecutada de nuevo. "
