gameforge.locale.skeleton_gem.order_accept = "\161Voy a consegu\237rtela! "
gameforge.locale.skeleton_gem.order_accept_answer = "Peddler:[ENTER]Oh, mil gracias. \161Nunca lo olvidar\233! "
