gameforge.locale.skeleton_gem.order_refuse_answer = "Peddler:[ENTER]\161Por supuesto que es una tarea dif\237cil y[ENTER]peligrosa! Si las cosas siguen as\237, \161ser\225 mi fin! "
gameforge.locale.skeleton_gem.order_say = "Peddler:[ENTER]Bienvenido. Ya que no puedo hacer nada nunca m\225s,[ENTER]solo esperar\233 a que venga la muerte. Si los[ENTER]ladrones no me hubieran atacado, no habr\237a[ENTER]perdido mis pertenencias. \191Por qu\233 ha tenido que[ENTER]pasarme a m\237? "
gameforge.locale.skeleton_gem.order_say2 = "Peddler:[ENTER]Por favor, ay\250dame. Si puedes obtener la Gema del[ENTER]demonio+ del mago demon\237aco, te recompensar\233[ENTER]adecuadamente. "
gameforge.locale.skeleton_gem.order_too_late = "Peddler:[ENTER]Otro ya me la consigui\243.[ENTER]No tienes que preocuparte m\225s de esto. "
gameforge.locale.skeleton_gem.start_find_peddler_label = "Ve con Peddler. "
