gameforge.locale.skeleton_gem.start_say = "La carta de Peddler:[ENTER]Ya no s\233 qu\233 hacer.[ENTER]La Gema del Demonio+ ha sido robada[ENTER]y eso me arruina, ya que pagu\233 por ella todo lo[ENTER]que ten\237a...[ENTER]\191Puedes ayudarme, por favor? Realmente necesito[ENTER]tu ayuda. "
