gameforge.locale.skill_group = {}
gameforge.locale.skill_group.board = "El folleto dice:[ENTER]\161Estamos reclutando hombres y mujeres valientes[ENTER]que deseen luchar por la paz del imperio y su[ENTER]gente![ENTER][ENTER]Requerimientos para unirse al ej\233rcito: nivel 5. "
gameforge.locale.skill_group.dialog_assassin_1 = "Aqu\237, entrenamos ninjas que pueden esconderse[ENTER]bien y acechar a sus enemigos. Se centran en el[ENTER]uso de dagas y venenos. S\243lo los ninjas que son[ENTER]aprendices y est\225n en nivel 5 o m\225s pueden[ENTER]participar. Cuando alcanzas este nivel, recibes[ENTER]una carta de reclutamiento. Si est\225s preparado[ENTER]para esconderte por siempre en las sombras como[ENTER]ninja, ven a buscarme. Entonces hablaremos m\225s. "
gameforge.locale.skill_group.dialog_assassin_2 = "Aqu\237, entrenamos ninjas que pueden esconderse[ENTER]bien y acechar a sus enemigos. Se centran en el[ENTER]uso de dagas y venenos. Si est\225s preparado para[ENTER]escabullirte por los oscuros rincones del mundo[ENTER]como un Ninja, ven y b\250scame. Entonces hablaremos[ENTER]m\225s. "
gameforge.locale.skill_group.dialog_assassin_3 = "Aqu\237, son entrenados los ninjas especialistas en[ENTER]arco. Te ense\241an c\243mo disparar una descarga[ENTER]certera de flechas a los enemigos lejanos. S\243lo[ENTER]los ninjas que son aprendices y tienen un nivel[ENTER]m\237nimo de 5 pueden unirse al entrenamiento. Tan[ENTER]pronto como hayas alcanzado el nivel apropiado[ENTER]recibir\225s una carta de reclutamiento. Si est\225s[ENTER]interesado, ven a verme. "
gameforge.locale.skill_group.dialog_assassin_4 = "Aqu\237, son entrenados los ninjas especialistas en[ENTER]arco. Por ejemplo, te ense\241an c\243mo disparar una[ENTER]descarga certera de flechas a los enemigos[ENTER]lejanos. S\237gueme. Te convertir\233 en el mejor[ENTER]arquero de este continente. "
gameforge.locale.skill_group.dialog_assassin_5 = "Elige entre el entrenamiento de asesino y el[ENTER]entrenamiento arquero y obtendr\225s las habilidades[ENTER]que quieres. "
gameforge.locale.skill_group.dialog_shaman_1 = "\201ste es el lugar donde ser re\250nen los Chamanes[ENTER]que quiren seguir el sendero del Dios Drag\243n. Te[ENTER]ense\241an c\243mo utilizar amuletos y tu poder mental,[ENTER]lo que permite a los Chamanes devolver los[ENTER]ataques enemigos. Tambi\233n les permite incrementar[ENTER]su propio valor de defensa a trav\233s de la[ENTER]protecci\243n sagrada y apoyar a sus compa\241eros[ENTER]guerreros. S\243lo los Chamanes que son aprendices o[ENTER]tienen un nivel m\237nimo de 5 pueden participar.[ENTER]Tan pronto como hayas alcanzado este nivel,[ENTER]recibir\225s una carta de reclutamiento. Cuando[ENTER]est\233s listo para las ense\241anzas de la Fuerza[ENTER]Drag\243n, b\250scame. "
gameforge.locale.skill_group.dialog_shaman_2 = "\201ste es el lugar donde ser re\250nen los Chamanes[ENTER]que quiren seguir el sendero del Dios Drag\243n. Te[ENTER]ense\241an c\243mo utilizar amuletos y tu poder mental,[ENTER]lo que permite a los Chamanes devolver los[ENTER]ataques enemigos. Tambi\233n les permite incrementar[ENTER]su propio valor de defensa a trav\233s de la[ENTER]protecci\243n sagrada y apoyar a sus compa\241eros[ENTER]guerreros. \191Crees que est\225s preparado para[ENTER]difundir las ense\241anzas del Dios Drag\243n junto a[ENTER]mi? Un humilde creyente es siempre bienvenido. "
gameforge.locale.skill_group.dialog_shaman_3 = "Aqu\237, los Chamanes rinden culto a las fuerzas de[ENTER]la naturaleza y la luz. Ense\241an habilidades[ENTER]conectadas al rayo, la tormenta y la curaci\243n.[ENTER]Los Chamanes que siguen la doctrina de la[ENTER]curaci\243n a menudo trabajan en grupo para ayudarse[ENTER]unos a otros. S\243lo los Chamanes que son[ENTER]aprendices o que tengan un nivel m\237nimo de 5[ENTER]pueden unirse. Tan pronto como hayas alcanzado[ENTER]este nivel, recibir\225s una carta de reclutamiento.[ENTER]Te estar\233 esperando. "
gameforge.locale.skill_group.dialog_shaman_4 = "Aqu\237, los Chamanes rinden culto a las fuerzas de[ENTER]la naturaleza y la luz. Ense\241an habilidades[ENTER]conectadas al rayo, la tormenta y la curaci\243n.[ENTER]Los Chamanes que siguen la doctrina de la[ENTER]curaci\243n a menudo trabajan en grupo para ayudarse[ENTER]unos a otros. \191Quieres trabajar conmigo para[ENTER]ayudar a otros? Tu apoyo ayudar\237a a todos[ENTER]aquellos que sufren. Por favor, ay\250dame. "
gameforge.locale.skill_group.dialog_shaman_5 = "Elige ente entrenamiento de Fuerza Drag\243n o[ENTER]Fuerza Curaci\243n y obtendr\225s las habilidades que[ENTER]necesitas. "
gameforge.locale.skill_group.dialog_sura_1 = "Ense\241o a aquellos que han sido dotados con la[ENTER]semilla del diablo c\243mo usar sus habilidades[ENTER]m\225gicas. Aprenden c\243mo encantar espadas y[ENTER]armaduras, lo que aumenta la fuerza de ataque y[ENTER]defensa. Tambi\233n aprenden c\243mo evocar esp\237ritus[ENTER]del infierno y as\237 reducir la moral del enemigo.[ENTER]S\243lo los Suras que son aprendices o tienen un[ENTER]nivel m\237nimo de 5 pueden formar parte. Tan pronto[ENTER]como alcances este nivel, recibir\225s una carta de[ENTER]reclutamiento. Si est\225s preparado para[ENTER]enfrentarte a tu legado demon\237aco, ven aqu\237. "
gameforge.locale.skill_group.dialog_sura_2 = "Ense\241o a aquellos que han sido dotados con la[ENTER]semilla del diablo c\243mo usar sus habilidades[ENTER]m\225gicas. Aprenden c\243mo encantar espadas y[ENTER]armaduras, lo que aumenta la fuerza de ataque y[ENTER]defensa. Tambi\233n aprenden c\243mo evocar esp\237ritus[ENTER]del infierno y as\237 reducir la moral del enemigo.[ENTER]\191Est\225s preparado para manejar espadas encantadas[ENTER]y lanzar hechizos oscuros? Puedo asegurarte que[ENTER]el poder que encuentras aqu\237 est\225 sin duda[ENTER]buscando a su gente. "
gameforge.locale.skill_group.dialog_sura_3 = "Si est\225s interesado en este lugar: Aqu\237 s\243lo[ENTER]encontraras a aquellos que se han dedicado a la[ENTER]oscuridad. Aqu\237 aprenden c\243mo tratar con[ENTER]esp\237ritus, demonios y con las llamas del[ENTER]infierno. S\243lo los Suras que son aprendices o[ENTER]tienen un nivel m\237nimo de 5 pueden seguir este[ENTER]entrenamiento. Tan pronto como hayas alcanzado el[ENTER]nivel apropiado, recibir\225s una carta de[ENTER]reclutamiento. Si denominas a la oscuridad como[ENTER]tu hogar, definitivamente encontrar\225s aqu\237 a tus[ENTER]hermanos y hermanas. "
gameforge.locale.skill_group.dialog_sura_4 = "Si est\225s interesado en este lugar: Aqu\237 s\243lo[ENTER]encontraras a aquellos que se han dedicado a la[ENTER]oscuridad. Aqu\237 aprenden c\243mo tratar con[ENTER]esp\237ritus, demonios y con las llamas del[ENTER]infierno. Si est\225s interesado en hacer amigos con[ENTER]esp\237ritus malignos que consumir\225n tu mente poco a[ENTER]poco, \161ven conmigo! \218nete a nuestra orden y deja[ENTER]atr\225s tu humanidad... "
gameforge.locale.skill_group.dialog_sura_5 = "Elige entre Magia Negra o Armamento y obtendr\225s[ENTER]las habilidades que necesitas. "
gameforge.locale.skill_group.dialog_warrior_1 = "\191Sabes d\243nde est\225s? Aqu\237, son entrenados los[ENTER]asaltantes, guerreros que son los m\225s r\225pidos y[ENTER]valientes de los alrededores. Aqu\237 se ense\241an[ENTER]t\233cnicas para efectuar golpes r\225pidos y repetidos[ENTER]y para ataques expertos con espada o lanza.[ENTER]S\243lo guerreros que son aprendices o tienen un[ENTER]nivel m\237nimo de 5 pueden participar en el[ENTER]entrenamiento. Tan pronto como hayas alcanzado el[ENTER]nivel apropiado recibir\225s un carta de[ENTER]reclutamiento. Si quieres descubrir la verdadera[ENTER]fuerza de tu cuerpo, \161ven conmigo! "
gameforge.locale.skill_group.dialog_warrior_2 = "\191Sabes d\243nde est\225s? Aqu\237, son entrenados los[ENTER]asaltantes, guerreros que son los m\225s r\225pidos y[ENTER]valientes de los alrededores. Aqu\237 se ense\241an[ENTER]t\233cnicas para efectuar golpes r\225pidos y repetidos[ENTER]y para ataques expertos con espada o lanza.[ENTER]\191As\237 pues, qu\233 ser\225? \191Quieres entrenar? "
gameforge.locale.skill_group.dialog_warrior_3 = "Ense\241o a los guerreros c\243mo concentrar[ENTER]adecuadamente su Chi. Esto requiere un estilo de[ENTER]lucha pausado y mentalmente exhausto. Sin[ENTER]embargo, a cambio, ser\225s capaz de golpear a[ENTER]varios enemigos al mismo tiempo. Y la[ENTER]impenetrable defensa de los grandes guerreros[ENTER]mentales es completamente legendaria. S\243lo los[ENTER]Guerreros aprendices o Guerreros con un nivel[ENTER]m\237nimo de 5 pueden participar en el[ENTER]entrenamiento. Tan pronto como hayas alcanzado el[ENTER]nivel requerido, recibir\225s una carta de[ENTER]reclutamiento. Si est\225s interesado, ven a verme. "
gameforge.locale.skill_group.dialog_warrior_4 = "Ense\241o a los guerreros c\243mo concentrar[ENTER]adecuadamente su Chi. Esto requiere un estilo de[ENTER]lucha pausado y mentalmente exhausto. Sin[ENTER]embargo, a cambio, ser\225s capaz de golpear a[ENTER]varios enemigos al mismo tiempo. Y la[ENTER]impenetrable defensa de los grandes guerreros[ENTER]mentales es completamente legendaria. \191Qu\233 va a[ENTER]ser? \191Puedes encargarte de la batalla mental? "
gameforge.locale.skill_group.dialog_warrior_5 = "Elige entre el entrenamiento de Fuerza Corporal o[ENTER]el entrenamiento de Lucha Mental y recibir\225s las[ENTER]habilidades que pediste. "
gameforge.locale.skill_group.invite = "Anuncio de reclutamiento por el ej\233rcito: "
gameforge.locale.skill_group.lets_join_skill_group_1 = "[COLOR r;1|g;0.6|b;0.6]Anuncio sobre[ENTER]reclutamiento de Guerreros[/COLOR][ENTER]Si admiras al Guerreros por su velocidad y fuerza[ENTER]de ataque, recomiendo el entrenamiento de Fuerza[ENTER]Corporal. Si quieres volverte invulnerable y[ENTER]eliminar grupos completos de monstruos con un[ENTER]solo golpe, recomiendo el entrenamiento de Lucha[ENTER]Mental. Te estar\233 esperando en la Plaza de la[ENTER]Aldea. "
gameforge.locale.skill_group.lets_join_skill_group_2 = "[COLOR r;1|g;0.6|b;0.6]Anuncio sobre[ENTER]reclutamiento de Ninjas[/COLOR][ENTER]Si quieres crearte un nombre como excepcional[ENTER]arquero, entonces aprende tiro con arco del[ENTER]maestro arquero. Si est\225s preparado para llevar a[ENTER]cabo varias misiones secretas en las sombras de[ENTER]la noche como un Ninja, entonces el entrenamiento[ENTER]de asesino es lo tuyo. Te estar\233 esperando en la[ENTER]Plaza de la Aldea. "
gameforge.locale.skill_group.lets_join_skill_group_3 = "[COLOR r;1|g;0.6|b;0.6]Anuncio sobre[ENTER]reclutamiento de Sura[/COLOR][ENTER]\191Quieres convertirte en un maestro sobrehumano[ENTER]con la espada y hacer que tus enemigos sientan el[ENTER]golpe de tu hoja encantada? Entonces recomiendo[ENTER]que aprendas el arte del armamento m\225gico. Sin[ENTER]embargo, si quieres convertirte en el soberano[ENTER]intimidador de llamas y de maldiciones, entonces[ENTER]debes aprender el arte de la magia negra.[ENTER][ENTER]Te estar\233 esperando en la Plaza de la Aldea. "
gameforge.locale.skill_group.lets_join_skill_group_4 = "[COLOR r;1|g;0.6|b;0.6]Anuncio sobre[ENTER]reclutamiento de Chamanes[/COLOR][ENTER]Si quieres avivar los poderes del dios drag\243n en[ENTER]tus combatientes y usar su fogoso aliento contra[ENTER]tus enemigos, recomiento el aprendizaje de la[ENTER]Fuerza Drag\243n. Sin embargo, si quieres aliviar y[ENTER]curar el dolor de aquellos que sufren, entonces[ENTER]debes buscar al Maestro de la Fuerza Curaci\243n.[ENTER][ENTER]Te estar\233 esperando en la Plaza de la Aldea. "
