gameforge.locale.stamina_food.baekgo_accept_failure_info_text_2 = "Dile a Oakgu que no has podido encontrar la carne[ENTER]de rana verde. "
gameforge.locale.stamina_food.butcher = {}
gameforge.locale.stamina_food.butcher.start_say = "Anciano en el restaurante Suhpyung:[ENTER]Mi cuerpo no es tan \250til como sol\237a ser. Cuando[ENTER]era joven, pod\237a trabajar una semana sin parar,[ENTER]\161y todav\237a ten\237a energ\237a para beber cada noche![ENTER]Ahora, incluso permanecer de pie es duro. En[ENTER]momentos como ese, un taz\243n de sopa de rana verde[ENTER]parece una buena manera de recuperar la energ\237a. "
gameforge.locale.stamina_food.butcher.start_say2 = "Anciano en el restaurante Suhpyung:[ENTER]\191Quieres saber qu\233 es la sopa de rana verde?[ENTER]Si te tomas un taz\243n, \161nunca m\225s te cansar\225s![ENTER]Incluso habiendo trabajado en los campos durante[ENTER]una semana seguida, \161a\250n tendr\237as energ\237a por las[ENTER]noches! Un amigo m\237o llamado Oakgu es el mejor[ENTER]cocinero de sopa verde que conozco.[ENTER]Aunque, por alguna raz\243n, ya no hace m\225s sopa. "
gameforge.locale.stamina_food.butcher.talk = "Hablar. "
gameforge.locale.stamina_food.complete_say = "Oakgu:[ENTER]\191Lo tienes? No le cuentes a nadie acerca de la[ENTER]sopa de rana verde.[ENTER]\161Especialmente a ese bastardo del restaurante[ENTER]Suhpyung! No hay suficiente; si la gente oye[ENTER]sobre la sopa de rana verde, \161vendr\225n todos aqu\237[ENTER]y se la comer\225n! "
gameforge.locale.stamina_food.food_manager = {}
gameforge.locale.stamina_food.food_manager.order_say = "Oakgu:[ENTER]\191Sopa de rana verde? \161S\237! Sol\237a hacerla. Pero[ENTER]cuando era joven. No ten\237a miedo de los monstruos[ENTER]peligrosos y por eso pod\237a cazar ranas verdes. "
gameforge.locale.stamina_food.food_manager.order_say2 = "Oakgu:[ENTER]\191Pero ahora?[ENTER]Ahora soy viejo y no tengo suficiente energ\237a[ENTER]para esto.[ENTER]Me gustar\237a comer sopa de rana ver, pero las[ENTER]ranas verdes no son f\225ciles de matar. Si me traes[ENTER]algo de carne de rana verde, \161podr\233 hacer la[ENTER]mejor sopa de rana verde para ti! "
gameforge.locale.stamina_food.food_manager.talk = "Hablar. "
gameforge.locale.stamina_food.food_manager.talk_about_greeenfrog_soup = "Sobre la sopa de rana verde "
