gameforge.main_quest_flame_lv100 = {}
gameforge.main_quest_flame_lv100._010_sendLetter = "Materia negra "
gameforge.main_quest_flame_lv100._020_say = "Yak-Hwan te est\225 buscando. Ve a verlo. "
gameforge.main_quest_flame_lv100._030_say = "Saludos. Yon-I-Walker ha terminado la[ENTER]investigaci\243n.[ENTER]El fen\243meno que has observado en la Tierra de[ENTER]Fuego se denomina Materia oscura. "
gameforge.main_quest_flame_lv100._040_say = "Emana del interior de la fortaleza y transforma a[ENTER]los demonios de los alrededores. Cuanto m\225s[ENTER]tiempo est\233n bajo su influjo, m\225s fuertes y[ENTER]agresivos se vuelven. \161Tenemos que evitar que la[ENTER]Materia negra se siga expandiendo! "
gameforge.main_quest_flame_lv100._050_say = {}
gameforge.main_quest_flame_lv100._060_say = "No podemos quedarnos de brazos cruzados mientras[ENTER]nuestro Alquimista busca una soluci\243n.[ENTER]Regresa a la Tierra de Fuego y acaba con 300[ENTER]demonios en los alrededores de la fortaleza. "
gameforge.main_quest_flame_lv100._070_say = "Faltar\237a m\225s. "
gameforge.main_quest_flame_lv100._080_say = "Gracias. \161Y ahora date prisa! "
gameforge.main_quest_flame_lv100._090_notice = "Acaba con 300 demonios de la Tierra de Fuego.[ENTER]Se encontrar\225n cerca de la fortaleza y en el[ENTER]lugar donde se hallan las Hierbas del sol. "
gameforge.main_quest_flame_lv100._100_sayTitle = "D\228monenhatz "
gameforge.main_quest_flame_lv100._110_say = "Erledige 300 Feuerland D\228monen in der N\228he der Festung und dem Fundort der Sonnenkr\228uter "
gameforge.main_quest_flame_lv100._120_say = "Me temo que todav\237a no has eliminado suficientes[ENTER]demonios. Vuelve a la Tierra de Fuego y sigue[ENTER]luchando. "
gameforge.main_quest_flame_lv100._130_notice = "Has vencido a todos los demonios.[ENTER]Informa de ello a Yak-Hwan. "
gameforge.main_quest_flame_lv100._140_say = "Acude junto a Yak-Hwan. "
gameforge.main_quest_flame_lv100._150_say = "Muy bien, eso deber\237a frenar la propagaci\243n de la[ENTER]Materia negra. Descansa mientras consulto con el[ENTER]Alquimista. "
gameforge.main_quest_flame_lv100._160_sendLetter = "Tintura de nimbo "
gameforge.main_quest_flame_lv100._170_say = "El alquimista te est\225 buscando. \161Parece urgente! "
gameforge.main_quest_flame_lv100._180_say = "\161Una cat\225strofe! Le dije a Yak-Hwan que hab\237a que[ENTER]tener cuidado. \191Y qu\233 hace \233l? Sembrar el caos[ENTER]espada en mano. La Materia negra crece y se[ENTER]propaga m\225s r\225pido al destruir al hu\233sped en el[ENTER]que anida. \161Y ahora me entero de que se ha[ENTER]eliminado a 300 demonios infectados! Esto no[ENTER]pinta bien... "
gameforge.main_quest_flame_lv100._190_say = "En estas condiciones, mi Tintura de nimbo para[ENTER]disipar los efectos de la Materia negra ya no es[ENTER]suficiente. Necesito ingredientes para producir[ENTER]m\225s de forma inmediata. "
gameforge.main_quest_flame_lv100._200_say = {}
gameforge.main_quest_flame_lv100._210_say = "Tr\225eme 10 Piedras fundaci\243n, 50 Bilis de oso, 10[ENTER]Sacos de veneno de ara\241a y 200 Fragmentos de[ENTER]energ\237a. No es necesario que explique d\243nde[ENTER]encontrar todas estas cosas los combatientes de[ENTER]tu talla, \191no? "
gameforge.main_quest_flame_lv100._220_say = "Ahora mismo voy. "
gameforge.main_quest_flame_lv100._230_say = "Muy bien. Date prisa, pues la Materia negra sigue[ENTER]propag\225ndose cada minuto que pasa sin que hagamos[ENTER]nada. "
gameforge.main_quest_flame_lv100._240_notice = "Besorge die Zutaten mit denen der Alchemist die Nimbustinktur herstellen kann "
gameforge.main_quest_flame_lv100._250_say = "Verbleibende Zutaten "
gameforge.main_quest_flame_lv100._260_sayTitle = "Tintura de nimbo "
gameforge.main_quest_flame_lv100._270_say = "Trae 10 Piedras fundaci\243n, 50 Bilis de oso, 10[ENTER]Sacos de veneno de ara\241a y 200 Fragmentos de[ENTER]energ\237a. Ll\233vale los ingredientes al alquimista. "
gameforge.main_quest_flame_lv100._280_say = "\161Has encontrado todos los ingredientes![ENTER]Excelente, voy a ponerme manos a la obra. Te[ENTER]aviso en cuanto la Tintura de nimbo est\233 lista. "
gameforge.main_quest_flame_lv100._290_say = "Como no detengamos pronto la propagaci\243n de la[ENTER]Materia negra, esto se va a poner feo. Venga,[ENTER]tr\225eme los ingredientes para la Tintura de nimbo. "
gameforge.main_quest_flame_lv100._300_notice = "Has reunido todos los ingredientes necesarios.[ENTER]Vuelve a ver al alquimista. "
gameforge.main_quest_flame_lv100._310_say = "Habla con el alquimista. "
gameforge.main_quest_flame_lv100._320_sendLetter = "Det\233n la Materia negra "
gameforge.main_quest_flame_lv100._330_say = "Menuda... pff... Me he quejado al herrero porque[ENTER]ha molido las Piedras fundaci\243n en grano grueso.[ENTER]\191Y ahora qu\233? Se ha ofendido y se niega a hacer[ENTER]las dem\225s en polvo. \161Ser\225 testarudo! \191Te[ENTER]importar\237a hablar con \233l? "
gameforge.main_quest_flame_lv100._340_say = "Por supuesto. "
gameforge.main_quest_flame_lv100._350_say = "Danke Hier sind die Fundamentsteine Und bringe ihm diesen Korb mit Leckereien als Entschuldigung "
gameforge.main_quest_flame_lv100._360_sayTitle = "Tranquiliza al herrero "
gameforge.main_quest_flame_lv100._370_say = "Calma al herrero y conv\233ncelo para que muela las[ENTER]Piedras fundaci\243n en polvo. "
gameforge.main_quest_flame_lv100._380_say = "Polvo piedra fundaci\243n: 1 unidad "
gameforge.main_quest_flame_lv100._390_say = "\191Qu\233 puedo hacer por ti? \191Quieres que afile tu[ENTER]espada? \191Que saque brillo a tu armadura? "
gameforge.main_quest_flame_lv100._400_say = "No, hoy no. He venido porque el alquimista quiere[ENTER]disculparse por haber sido grosero.[ENTER]Te env\237a esta cesta con dulces. "
gameforge.main_quest_flame_lv100._410_say = "No pienso ayudar a ese pat\225n desagradecido pero,[ENTER]siendo t\250, voy a moler esas Piedras fundaci\243n.[ENTER]Espera un segundo. "
gameforge.main_quest_flame_lv100._420_say = "\161Muchas gracias! "
gameforge.main_quest_flame_lv100._430_say = "\191Se ha puesto cabez\243n el herrero? Dale la cesta y[ENTER]p\237dele ayuda. Seguro que a ti no te dice que no. "
gameforge.main_quest_flame_lv100._440_notice = "El Polvo piedra fundaci\243n est\225 listo. Ll\233vaselo[ENTER]al alquimista. "
gameforge.main_quest_flame_lv100._450_say = "Oh fein wie Babypuder ausgezeichnet Der alte Sturkopf kann es also doch hehe Nun kann ich die Nimbustinktur mischen Ruhe dich etwas aus Ich werde dich rufen wenn sie fertig ist "
gameforge.main_quest_flame_lv101 = {}
gameforge.main_quest_flame_lv101._010_sendLetter = "Fortaleza misteriosa "
gameforge.main_quest_flame_lv101._020_say = "Yak-Hwan te est\225 buscando. Ve a verlo y averigua[ENTER]qu\233 es lo que quiere. "
gameforge.main_quest_flame_lv101._030_say = "El alquimista me ha explicado el error que he[ENTER]cometido. Espero que todav\237a se pueda arreglar. "
gameforge.main_quest_flame_lv101._040_say = "Voy a darle Tintura de nimbo a tu arma. Ahora,[ENTER]cuando mates demonios que est\233n infectados,[ENTER]neutralizar\225s la Materia negra, de modo que no[ENTER]podr\225 seguir expandi\233ndose. "
gameforge.main_quest_flame_lv101._050_say = "Dado que has obtenido el Tique de entrada, ya[ENTER]puedes arriesgarte a penetrar en lo m\225s profundo[ENTER]de la fortaleza misteriosa. Puede que descubras[ENTER]alguna pista para averiguar qu\233 es lo que est\225n[ENTER]maquinando los Servidores de la oscuridad, o[ENTER]quiz\225s encuentres alg\250n indicio sobre el paradero[ENTER]del esp\237a desaparecido. "
gameforge.main_quest_flame_lv101._060_say = {}
gameforge.main_quest_flame_lv101._070_say = "Ahora mismo voy. "
gameforge.main_quest_flame_lv101._080_say = "Danke Ich w\252nsche dir das Beste "
gameforge.main_quest_flame_lv101._090_notice = "Ad\233ntrate en la fortaleza y lucha con los[ENTER]demonios que la habitan. Mant\233n los ojos bien[ENTER]abiertos en busca del esp\237a desaparecido; que no[ENTER]se te escape ninguna pista importante. "
gameforge.main_quest_flame_lv101._100_sayTitle = "Festung erkunden "
gameforge.main_quest_flame_lv101._110_say = "Ad\233ntrate en la fortaleza y lucha con los[ENTER]demonios que la habitan. \161Busca pistas sobre las[ENTER]maquinaciones de los Servidores y sobre el esp\237a[ENTER]desaparecido! "
gameforge.main_quest_flame_lv101._120_sayReward = "Du kannst diesen Dungeon nicht alleine betreten Bilde eine Gruppe um passieren zu d\252rfen Du erh\228ltst keinen weiteren Passierschein "
gameforge.main_quest_flame_lv101._130_say = "\191Ya has estado en el interior de la fortaleza?[ENTER]Debe de haber pistas sobre las maquinaciones de[ENTER]los Servidores de la oscuridad, y tambi\233n sobre[ENTER]el paradero del esp\237a desaparecido. Regresa a la[ENTER]Tierra de Fuego y registra la fortaleza. "
