gameforge.main_quest_flame_lv101._150_notice = "Has encontrado al esp\237a de Yak-Hwan. "
gameforge.main_quest_flame_lv101._160_say = "Hast du Neuigkeiten "
gameforge.main_quest_flame_lv101._170_say = {}
gameforge.main_quest_flame_lv101._180_say = "La expresi\243n de tu cara me dice que no son[ENTER]buenas... Ya me lo tem\237a. \191Y llevaba una carta?[ENTER]Ens\233\241amela. Todav\237a debe de haber pistas sobre[ENTER]las maquinaciones de los Servidores de la[ENTER]oscuridad.[ENTER]Vuelve a la fortaleza y b\250scalas. Ya leeremos la[ENTER]carta m\225s tarde. "
gameforge.main_quest_flame_lv101._190_notice = "Has encontrado un Collar remachado de los[ENTER]Servidores de la oscuridad. Ens\233\241aselo a[ENTER]Yak-Hwan. "
gameforge.main_quest_flame_lv101._200_say = "\161Qu\233 interesante! El Collar remachado pertenece a[ENTER]los Servidores de la oscuridad. \161Puede que[ENTER]contenga pistas sobre sus planes! Pero... \191ni[ENTER]rastro del esp\237a? Por favor, sigue busc\225ndolo.[ENTER]Tiene que estar en esa fortaleza. "
gameforge.main_quest_flame_lv101._210_notice = "Has encontrado al esp\237a y tambi\233n un Collar[ENTER]remachado. Informa de ello a Yak-Hwan. "
gameforge.main_quest_flame_lv101._220_say = "Informa a Yak-Hwan. "
gameforge.main_quest_flame_lv101._230_say = "\161Veo que has tenido \233xito! Este Collar remachado[ENTER]pertenece a los Servidores de la oscuridad.[ENTER]Seguro que oculta pistas sobre sus planes. \191Y eso[ENTER]qu\233 es?[ENTER]\191Una carta del esp\237a? Mu\233stramela. "
gameforge.main_quest_flame_lv101._240_say = {}
gameforge.main_quest_flame_lv101._250_say = "Ein Brief den mir mein Sp\228her hinterlassen hat Ich bin ersch\252ttert Lass uns gemeinsam seine letzten Worte lesen "
gameforge.main_quest_flame_lv101._260_sayTitle = "Escrito de forma apresurada: "
gameforge.main_quest_flame_lv101._270_say = "Yak-Hwan, no regresar\233 vivo, pero espero que te[ENTER]hagan llegar estas palabras. Estoy atrapado en la[ENTER]Tierra de Fuego, en una fortaleza que no aparece[ENTER]en los mapas. La gobierna un poderoso demonio de[ENTER]la Tierra de Fuego, que a su vez est\225 siendo[ENTER]controlado por una extra\241a aura que lo somete a[ENTER]\233l y a todos sus s\250bditos. El demonio profiere un[ENTER]rugido ensordecedor, y parece estar custodiando[ENTER]algo, aunque no he podido averiguar lo que es.[ENTER]Disc\250lpame, he fracasado... "
gameforge.main_quest_flame_lv101._280_say = "Hemos de averiguar qu\233 es lo que se oculta en esa[ENTER]fortaleza. Mira, hay un grabado en el interior[ENTER]del Collar remachado. Voy a pedir consejo a[ENTER]Yon-I-Walker. Si necesita tu ayuda, te lo har\225[ENTER]saber. "
gameforge.main_quest_flame_lv101._290_sendLetter = "Gravur entschl\252sseln "
gameforge.main_quest_flame_lv101._300_say = "Yon-I-Walker pregunta por ti, \191por qu\233 no vas a[ENTER]verlo? "
gameforge.main_quest_flame_lv101._310_say = "Willkommen ich habe dich bereits erwartet Ich brauche etwas Hilfe dabei die Gravur in diesem Nietenhalsband zu entschl\252sseln "
gameforge.main_quest_flame_lv101._320_say = {}
gameforge.main_quest_flame_lv101._330_say = "Los caracteres del interior del Collar remachado[ENTER]pertenecen a una antigua cultura que existi\243 hace[ENTER]mucho tiempo. Para descifrarlos necesito la[ENTER]Sangre del Rey Fuego, que fluye por sus venas[ENTER]ardiente como la lava. "
gameforge.main_quest_flame_lv101._340_say = "Eso est\225 hecho. "
gameforge.main_quest_flame_lv101._350_say = "Wenn du das Blut erhalten hast musst du so schnell wie m\246glich zu mir zur\252ckkehren Denn selbst dieses Gef\228\223 kann seine Hitze nur f\252r eine begrenzte Zeit ohne Schaden \252berstehen "
gameforge.main_quest_flame_lv101._360_notice = "Hazte con la Sangre del Rey Fuego. "
gameforge.main_quest_flame_lv101._370_say = "\161Sin la Sangre del Rey Fuego no podremos leer el[ENTER]grabado! "
gameforge.main_quest_flame_lv101._380_notice = "Has obtenido la Sangre del Rey Fuego. Regresa e[ENTER]informa a Yon-I-Walker. "
gameforge.main_quest_flame_lv101._390_say = "Habla con Yon-I-Walker. "
gameforge.main_quest_flame_lv101._400_say = "Ah, muy bien. Ahora, gracias a la sangre,[ENTER]podremos leer el grabado con claridad, pero[ENTER]necesito algo de tiempo. \191Por qu\233 no vuelves[ENTER]ma\241ana? "
gameforge.main_quest_flame_lv101._410_say = "Todav\237a tienes que esperar %d hora(s) y %d[ENTER]minuto(s). "
gameforge.main_quest_flame_lv101._420_say = "Necesito algo m\225s de tiempo. \161Vuelve m\225s tarde! "
gameforge.main_quest_flame_lv101._430_sendLetter = "El grabado "
gameforge.main_quest_flame_lv101._440_say = "\161Llegas en el momento oportuno! Acabo de[ENTER]descifrar el grabado del Collar remachado. "
gameforge.main_quest_flame_lv101._450_say = "Sie verr\228t uns dass die Diener der Dunkelheit einen der m\228chtigesten Feuerd\228monen entsandt haben um die Siegel der Tore zu schmelzen hinter denen die Sechs Drachen an einem verborgenen Ort gefangen gehalten werden Es wird auch ein spezieller Schmelzofen erw\228hnt Ich habe alles in diesem Schreiben an Yak Hwan festgehalten Bringe es bitte zu ihm "
gameforge.main_quest_flame_lv101._460_say = {}
gameforge.main_quest_flame_lv101._470_notice = "\220berbringe Yak Hwan den Brief von Yon I Walker "
gameforge.main_quest_flame_lv101._480_sayTitle = "Post f\252r Yak Hwan "
gameforge.main_quest_flame_lv101._490_say = "\220berbringe Yak Hwan den Brief von Yon I Walker "
gameforge.main_quest_flame_lv101._500_say = "Konnte Yon I Walker die Gravur lesen Oh ein Brief mit allen Informationen von ihm Sehr gut zeig her "
gameforge.main_quest_flame_lv101._510_say = "El sello del Gran Drag\243n... Aj\225... \161Entonces la[ENTER]fortaleza que hemos descubierto debe de ser la[ENTER]legendaria Fortaleza del Drag\243n Rojo! Se supone[ENTER]que ah\237 permanece cautivo uno de los dragones que[ENTER]los Servidores deben matar para hacerse con las[ENTER]Perlas nocturnas. Toma, un Tique de entrada.[ENTER]Gu\225rdalo bien, seguro lo necesitar\225s pronto... "
gameforge.main_quest_flame_lv101._520_say = "T\246te den Flammenk\246nig und fange sein brennendes Blut auf "
gameforge.main_quest_flame_lv101._530_say = {}
gameforge.main_quest_flame_lv102 = {}
gameforge.main_quest_flame_lv102._010_sendLetter = "Asalta la fortaleza "
gameforge.main_quest_flame_lv102._020_say = "Yak-Hwan pregunta por ti. Quiere ponerte al[ENTER]corriente de los pr\243ximos movimientos. "
gameforge.main_quest_flame_lv102._030_say = "Hemos levantado una barricada para evitar que los[ENTER]demonios infectados sigan avanzando. De esta[ENTER]forma podremos detener la propagaci\243n de la[ENTER]Materia negra. "
gameforge.main_quest_flame_lv102._040_say = "Deine Aufgabe wird es nun sein in die Festung einzufallen so viele D\228monen wie m\246glich unsch\228dlich zu machen und herauszufinden ob darin tats\228chlich der legend\228re Rotdrache gefangen ist "
gameforge.main_quest_flame_lv102._050_say = "De acuerdo. "
gameforge.main_quest_flame_lv102._060_say = "Erledige 30 D\228monen und bringe mir als Beweis daf\252r ihre D\228monenkrallen "
gameforge.main_quest_flame_lv102._070_notice = "Erledige 30 D\228monen und bringe Yak Hwan als Beweis ihre D\228monenkrallen "
gameforge.main_quest_flame_lv102._080_sayTitle = "\161Asalta la Fortaleza del Drag\243n Rojo! "
gameforge.main_quest_flame_lv102._090_say = "Besiege 30 D\228monen in der Rotdrachenfestung und bringe Yak Hwan ihre D\228monenkrallen als Beweis "
gameforge.main_quest_flame_lv102._100_say = "D\228monenkralle des St\252ck D\228monenkralle des St\252ck "
gameforge.main_quest_flame_lv102._110_say = "R\252stungsfragment des St\252ck Waffenfragment des St\252ck "
gameforge.main_quest_flame_lv102._120_say = "Du hast noch nicht gen\252gend D\228monen besiegt Erledige insgesamt 30 St\252ck und bringe mir ihre D\228monenkrallen als Beweis "
gameforge.main_quest_flame_lv102._130_notice = "Ya has vencido a todos los Demonios llamaascua.[ENTER]Informa a Yak-Hwan. "
gameforge.main_quest_flame_lv102._140_say = "Habla con Yon-I-Walker. "
gameforge.main_quest_flame_lv102._150_say = "Has vuelto, \161y veo que has tenido \233xito![ENTER]Cu\233ntame, \191qu\233 ha pasado? "
gameforge.main_quest_flame_lv102._160_say = {}
gameforge.main_quest_flame_lv102._170_say = "\191Un poderoso demonio de fuego, dices? \161Se trata[ENTER]de Arrador, Se\241or del fuego! Si los Servidores lo[ENTER]han enviado a \233l, la fortaleza tiene que ocultar[ENTER]algo importante. \161Posiblemente el legendario[ENTER]Drag\243n rojo! Voy a pedir consejo. Toma este Tique[ENTER]de entrada y gu\225rdalo bien. Seguro que te har\225[ENTER]falta m\225s tarde. "
gameforge.main_quest_flame_lv102._180_sendLetter = "Razador "
gameforge.main_quest_flame_lv102._190_say = "Yon-I-Walker te est\225 buscando. Ve a verlo para[ENTER]saber por qu\233. "
gameforge.main_quest_flame_lv102._200_say = "As\237 que has sobrevivido a un encuentro con el[ENTER]monstruoso Arrador... Me quito el sombrero. "
gameforge.main_quest_flame_lv102._210_say = {}
gameforge.main_quest_flame_lv102._220_say = "Junto con Alastor, el Rey Escarcha, el Se\241or del[ENTER]fuego es una de las criaturas del inframundo m\225s[ENTER]letales e infames que ha conocido la humanidad.[ENTER]De hecho, es posible que el propio Arrador sea el[ENTER]origen de la Materia negra. "
gameforge.main_quest_flame_lv102._230_say = {}
gameforge.main_quest_flame_lv102._240_say = {}
gameforge.main_quest_flame_lv102._250_say = "Eso lo convierte en un enemigo muy poderoso.[ENTER]Ahora ve a la Fortaleza del Drag\243n Rojo y[ENTER]enfr\233ntate a los demonios de bajo rango. Despu\233s,[ENTER]extrae la Materia negra de sus cuerpos; diez[ENTER]unidades ser\225n suficientes. Puede que as\237[ENTER]encontremos un modo de neutralizar la fuerza de[ENTER]Arrador antes de v\233rnoslas con \233l. "
gameforge.main_quest_flame_lv102._260_say = "\161Me pondr\233 en marcha inmediatamente! "
gameforge.main_quest_flame_lv102._270_notice = "Lucha contra los Demonios llamaascua en la[ENTER]Fortaleza del Drag\243n Rojo. "
gameforge.main_quest_flame_lv102._280_sayTitle = "Materie Kugeln "
gameforge.main_quest_flame_lv102._290_say = "Asalta la Fortaleza del Drag\243n Rojo, lucha contra[ENTER]los Demonios llamaascua y extrae 10 unidades de[ENTER]Materia negra. "
gameforge.main_quest_flame_lv102._300_sayReward = "Para entrar en la Fortaleza del Drag\243n Rojo[ENTER]necesitas un grupo y un Tique de entrada. "
gameforge.main_quest_flame_lv102._310_say = "Todav\237a no hay suficiente. Necesito 10 unidades[ENTER]de Materia negra para llevar a cabo mi[ENTER]investigaci\243n. "
gameforge.main_quest_flame_lv102._320_notice = "Has extra\237do 10 unidades de Materia negra.[ENTER]Ll\233vaselas a Yon-I-Walker. "
gameforge.main_quest_flame_lv102._330_say = "\161Solo el aspecto de la Materia negra ya me da[ENTER]escalofr\237os! Bueno, manos a la obra... Te har\233[ENTER]llamar cuando haya averiguado algo. "
gameforge.main_quest_flame_lv102._340_say = {}
gameforge.main_quest_flame_lv102._350_sendLetter = "Neutralizaci\243n de la Materia negra "
gameforge.main_quest_flame_lv102._360_say = "\161Buenas noticias! He averiguado c\243mo neutralizar[ENTER]el poder de la Materia negra. "
gameforge.main_quest_flame_lv102._370_say = {}
gameforge.main_quest_flame_lv102._380_say = "Todas las fuerzas elementales de la naturaleza[ENTER]tienen un contrario: luz y sombra, fuego y agua,[ENTER]bien y mal... La Materia negra tambi\233n tiene su[ENTER]contrario, que es capaz de neutralizarla: \161Lumen[ENTER]puro! "
gameforge.main_quest_flame_lv102._390_say = "Para producir Lumen puro hay que fundir[ENTER]Fragmentos de energ\237a en Agua Mong. \191Podr\237as[ENTER]llevarle a Yu-Hwan 100 Fragmentos de energ\237a y 50[ENTER]botellas de Agua Mong? \161Gracias! "
gameforge.main_quest_flame_lv102._400_say = "\161As\237 se har\225! "
gameforge.main_quest_flame_lv102._410_notice = "Re\250ne 50 botellas de Agua Mong y 100 Fragmentos[ENTER]de energ\237a y ll\233vaselos a Yu-Hwan. "
gameforge.main_quest_flame_lv102._420_sayTitle = "Lumen puro "
gameforge.main_quest_flame_lv102._430_say = "Re\250ne 50 botellas de Agua Mong y 100 Fragmentos[ENTER]de energ\237a y ll\233vaselos a Yu-Hwan. "
gameforge.main_quest_flame_lv102._440_say = "Ah, Yon-I-Walker me hab\237a dicho que vendr\237as.[ENTER]Venga, pues manos a la obra. \191Por qu\233 no[ENTER]descansas un poco mientras tanto? "
gameforge.main_quest_flame_lv102._450_say = "Ah, Yon-I-Walker me dijo que vendr\237as. Quiero[ENTER]ponerme con ello, pero no tengo suficiente[ENTER]material para hacer el Lumen puro. Por favor,[ENTER]re\250ne un poco m\225s. "
gameforge.main_quest_flame_lv102._460_notice = "Has reunido suficientes Fragmentos de energ\237a y[ENTER]botellas de Agua Mong. Ll\233vaselo todo a Yu-Hwan. "
gameforge.main_quest_flame_lv102._470_say = "Ve con Yu-Hwan "
gameforge.main_quest_flame_lv102._480_sendLetter = "Conseguir el Lumen puro "
gameforge.main_quest_flame_lv102._490_say = "Yu-Hwan ha elaborado el Lumen puro. Ve a verlo. "
gameforge.main_quest_flame_lv102._500_say = "\161Llegas en el momento oportuno! El Lumen puro ya[ENTER]est\225 listo. Informa de ello a Yak-Hwan. "
gameforge.main_quest_flame_lv102._510_say = {}
gameforge.main_quest_flame_lv102._520_say = {}
gameforge.main_quest_flame_lv102._530_say = {}
gameforge.main_quest_flame_lv102._540_notice = "Kehre mit dem Reinen Lumen zu Yak Hwan zur\252ck "
gameforge.main_quest_flame_lv102._550_say = "Du bist noch hier Es eilt sehr Bringe das Reine Lumen zu Yak Hwan "
gameforge.main_quest_flame_lv102._560_say = "Ah willkommen Du hast das Reine Lumen bei dir Phantastisch "
gameforge.main_quest_flame_lv102._570_say = {}
gameforge.main_quest_flame_lv102._580_say = "Impresionante. Ahora tenemos un as en la manga[ENTER]para la batalla en la Fortaleza del Drag\243n Rojo.[ENTER]Descansa un poco mientras re\250no a las tropas. "
gameforge.main_quest_flame_lv103 = {}
gameforge.main_quest_flame_lv103._010_sendLetter = "Asalta la Fortaleza del Drag\243n Rojo "
gameforge.main_quest_flame_lv103._020_say = "Yak-Hwan te ha hecho llamar. Quiere darte las[ENTER]\250ltimas indicaciones antes de que te encamines[ENTER]hacia la batalla. "
gameforge.main_quest_flame_lv103._030_say = "Es la hora, la batalla ha comenzado. He enviado a[ENTER]una tropa a la Fortaleza del Drag\243n Rojo. Todos[ENTER]los hombres se han equipado con Lumen puro, y[ENTER]tienen las ideas m\225s claras que nunca. \161El efecto[ENTER]es incre\237ble! "
gameforge.main_quest_flame_lv103._040_say = "Folge ihnen und treffe sie in der Rotdrachenfestung Suche nach dem Kommandanten Er wird dich in den Angriffsplan einweihen "
gameforge.main_quest_flame_lv103._060_say = "Cu\237date. "
gameforge.main_quest_flame_lv103._070_notice = "Folge dem Angriffstrupp in die Rotdrachenfestung und suche nach dem Kommandanten "
gameforge.main_quest_flame_lv103._080_sayTitle = "\161A la fortaleza! "
gameforge.main_quest_flame_lv103._090_say = "Folge dem Angriffstrupp in die Rotdrachenfestung und suche nach dem Kommandanten "
gameforge.main_quest_flame_lv103._100_say = "\191Todav\237a est\225s ah\237? \161Venga, sigue a mis hombres a[ENTER]la Fortaleza del Drag\243n Rojo! "
gameforge.main_quest_flame_lv103._110_say = "Gut dass du hier bist Wir wurden entdeckt und mussten die Festung fr\252her als geplant st\252rmen Zuerst lief es gut doch dann gegen Razador waren wir chancenlos das ganze Bataillon ist gefallen Ich bin der letzte Kannst du Yak Hwan Bericht erstatten Danke "
gameforge.main_quest_flame_lv103._120_say = "Informa a Yak-Hwan sobre lo acontecido en la[ENTER]Fortaleza del Drag\243n Rojo. "
gameforge.main_quest_flame_lv103._130_say = "\191Ya est\225s de vuelta? Que... \191que algo ha salido[ENTER]mal? \161Vamos, habla! "
gameforge.main_quest_flame_lv103._140_say = {}
gameforge.main_quest_flame_lv103._150_say = "\191Que todo el batall\243n ha ca\237do? Oh, no... Es[ENTER]culpa m\237a. Fue un ataque precipitado, y mis[ENTER]hombres lo han pagado con su vida. "
gameforge.main_quest_flame_lv103._160_say = {}
gameforge.main_quest_flame_lv103._170_say = "Tengo que pensar en otra estrategia... Ha de[ENTER]haber otro modo de derrotar a ese demonio.[ENTER]Prep\225rate; te har\233 llamar en cuanto tenga un[ENTER]plan. "
gameforge.main_quest_flame_lv103._180_sendLetter = "Paso a paso "
gameforge.main_quest_flame_lv103._190_say = "Qu\233 bien que est\233s aqu\237. Hemos decidido que lo[ENTER]mejor ser\225 atacar primero a los demonios para[ENTER]debilitarlos. Despu\233s nos enfrentaremos de nuevo[ENTER]a Arrador. "
gameforge.main_quest_flame_lv103._200_say = "W\228hrend meine M\228nner vor den Toren der Rotdrachenfestung Wache halten und alle Gegner erledigen die ins Freie st\252rmen wirst du hinein gehen und die Flammend\228monen im Inneren bek\228mpfen Das Reine Lumen wird dich vor dem Einfluss der Schwarzen Materie sch\252tzen und ihre Kraft neutralisieren "
gameforge.main_quest_flame_lv103._210_say = "Wenn du es schaffst 1000 Flammend\228monen zu besiegen wird die Verteidigungslinien um Razador empfindlich schw\228chen "
gameforge.main_quest_flame_lv103._220_say = "\161A las armas! "
gameforge.main_quest_flame_lv103._230_notice = "Asalta la Fortaleza del Drag\243n Rojo y acaba con[ENTER]1000 demonios de fuego. "
gameforge.main_quest_flame_lv103._240_sayTitle = "Paso 1: 1000 demonios "
gameforge.main_quest_flame_lv103._250_say = "Asalta la Fortaleza del Drag\243n Rojo y acaba con[ENTER]1000 demonios de fuego. "
gameforge.main_quest_flame_lv103._260_sayReward = "Du ben\246tigst eine Gruppe und einen Passierschein "
gameforge.main_quest_flame_lv103._270_say = "Las l\237neas de defensa enemigas son todav\237a muy[ENTER]fuertes. Acaba con m\225s demonios. \161Contamos[ENTER]contigo! "
gameforge.main_quest_flame_lv103._280_notice = "Has vencido a 1000 demonios de fuego. Informa a[ENTER]Yak-Hwan. "
gameforge.main_quest_flame_lv103._290_say = "Gute Arbeit Die Verteidigungslinien der Flammend\228monen wurde durch dich empfindlich geschw\228cht Warte einen Moment w\228hrend ich mich mit meinen Strategen \252ber das weitere Vorgehen berate "
gameforge.main_quest_flame_lv103._300_sendLetter = "Paso 2 "
gameforge.main_quest_flame_lv103._310_say = "Es hora de dar el siguiente paso: hemos de atacar[ENTER]a los demonios de rango alto.[ENTER]Ad\233ntrate de nuevo en la Fortaleza del Drag\243n[ENTER]Rojo y acaba con 50 Reyes llamaascua, 50 Barbas[ENTER]llamaascua, 50 Trols llamaascua, 50 Generales[ENTER]llamaascua y 50 Pr\237ncipes llamaascua. "
gameforge.main_quest_flame_lv103._320_say = {}
gameforge.main_quest_flame_lv103._330_notice = "Ad\233ntrate de nuevo en la Fortaleza del Drag\243n[ENTER]Rojo y acaba con 50 Reyes llamaascua, 50 Barbas[ENTER]llamaascua, 50 Trols llamaascua, 50 Generales[ENTER]llamaascua y 50 Pr\237ncipes llamaascua. "
gameforge.main_quest_flame_lv103._340_sayTitle = "Paso 2 "
gameforge.main_quest_flame_lv103._350_say = "Dringe erneut in die Rotdrachenfestung ein und besiege jeweils 50 Glut Flammenk\246nige Glut Flammenb\228rte Glut Flammengolem Glut Flammengener\228le und Glut Flammenf\252rste "
gameforge.main_quest_flame_lv103._360_say = "Las tropas enemigas son todav\237a muy fuertes; no[ENTER]has derrotado a suficientes Demonios llamaascua[ENTER]de rango alto. \161Regresa a la fortaleza y sigue[ENTER]luchando! "
gameforge.main_quest_flame_lv103._370_notice = "Has derrotado a los Demonios llamaascua de rango[ENTER]alto. Ve a ver a Yak-Hwan e inf\243rmale de tus[ENTER]progresos. "
gameforge.main_quest_flame_lv103._380_say = "\161Fant\225stico! Has debilitado las l\237neas de los[ENTER]Demonios llamaascua y ahora mis hombres pueden[ENTER]asaltar la Fortaleza del Drag\243n Rojo. \161Buen[ENTER]trabajo! Te informar\233 en cuanto reciba noticias. "
gameforge.main_quest_flame_lv103._390_sendLetter = "Razador "
gameforge.main_quest_flame_lv103._400_say = "Mis hombres ya est\225n en la Fortaleza del Drag\243n[ENTER]Rojo y, gracias a tu trabajo, no hemos sufrido[ENTER]m\225s p\233rdidas. Yon-I-Walker te explicar\225 nuestra[ENTER]estrategia, ve a verlo. "
gameforge.main_quest_flame_lv103._410_notice = "Ve a conocer la estrategia de Yon-I-Walker. "
gameforge.main_quest_flame_lv103._420_say = "Ve a conocer la estrategia de Yon-I-Walker. "
gameforge.main_quest_flame_lv103._430_say = "Te estaba esperando. Estamos a punto de[ENTER]desbaratar una vez m\225s los planes de los[ENTER]Servidores de la oscuridad. D\233jame que te[ENTER]explique c\243mo lo vamos a hacer. "
gameforge.main_quest_flame_lv103._440_say = "Gracias a nuestros esp\237as, nos hemos enterado de[ENTER]que Arrador obtiene gran parte de su fuerza del[ENTER]Metin del purgatorio. Ha llevado esa piedra a la[ENTER]Fortaleza del Drag\243n Rojo, y la guarda con[ENTER]recelo.[ENTER]\161Destruye el Metin! Eso facilitar\225[ENTER]considerablemente la batalla contra Arrador. "
gameforge.main_quest_flame_lv103._450_say = {}
gameforge.main_quest_flame_lv103._460_say = "No sabemos con certeza d\243nde se encuentra el[ENTER]Metin del purgatorio, pero tiene que estar en[ENTER]alg\250n lugar de esta fortaleza. Cuando hayas[ENTER]alcanzado tu objetivo, informa a Yak-Hwan. "
gameforge.main_quest_flame_lv103._470_say = {}
gameforge.main_quest_flame_lv103._480_notice = "Destruye el Metin del purgatorio en la Fortaleza[ENTER]del Drag\243n Rojo. "
gameforge.main_quest_flame_lv103._490_sayTitle = "Flammen des Fegefeuers "
