gameforge.main_quest_flame_lv104 = {}
gameforge.main_quest_flame_lv104._010_sendLetter = "Enfr\233ntate a Arrador "
gameforge.main_quest_flame_lv104._020_say = "Ve a conocer la estrategia ofensiva de Yak-Hwan. "
gameforge.main_quest_flame_lv104._030_say = "\161Se acerca el triunfo! Esta vez estamos[ENTER]preparados para acabar con Arrador. "
gameforge.main_quest_flame_lv104._040_say = "\191Todav\237a tienes el Lumen puro? Recuerda que los[ENTER]efectos duran solo una hora, as\237 que util\237zalo[ENTER]justo antes de que comience la batalla. \161A las[ENTER]armas! "
gameforge.main_quest_flame_lv104._050_say = "Entendido. "
