gameforge.main_quest_flame_lv104._070_sayTitle = "Enfr\233ntate a Arrador "
gameforge.main_quest_flame_lv104._080_say = "Asalta la Fortaleza del Drag\243n Rojo y elimina a[ENTER]Arrador, Se\241or del fuego. "
gameforge.main_quest_flame_lv104._090_sayReward = "Du ben\246tigst eine Gruppe und einen Passierschein "
gameforge.main_quest_flame_lv104._100_say = "La lucha contra Arrador no ser\225 f\225cil, pero no[ENTER]hay otro modo de pararles los pies a los[ENTER]Servidores de la oscuridad. \161Re\250ne fuerzas y[ENTER]enfr\233ntate al Se\241or del fuego antes de que sea[ENTER]demasiado tarde! "
gameforge.main_quest_flame_lv104._110_say = "Mortal, \161esc\250chame bien! Disfruta de tu ef\237mera[ENTER]sensaci\243n de triunfo, pues no durar\225 mucho. El[ENTER]Drag\243n rojo romper\225 muy pronto las cadenas que lo[ENTER]mantienen cautivo. Con la ayuda de su poder,[ENTER]\161regresar\233 a vuestro mundo miserable para llevar[ENTER]a cabo mi plan! "
