gameforge.main_quest_flame_lv104._130_say = "Vuelve a ver a Yak-Hwan. "
gameforge.main_quest_flame_lv104._140_say = "\161Menudo triunfo! Nadie hab\237a conseguido derrotar[ENTER]al Se\241or del fuego hasta ahora. Es un d\237a digno[ENTER]de recordar. "
gameforge.main_quest_flame_lv104._150_say = {}
gameforge.main_quest_flame_lv104._160_say = "\191Qu\233 dices? \191Que el Drag\243n rojo traer\225 de vuelta[ENTER]a Arrador? \191C\243mo puede ser? Sabemos muy poco[ENTER]sobre los grandes dragones... Por lo que parece,[ENTER]poseen poderes incre\237bles. "
gameforge.main_quest_flame_lv104._170_sendLetter = "Abortar planes I "
gameforge.main_quest_flame_lv104._180_say = "\161Malas noticias! Arrador ha resucitado gracias al[ENTER]poder del Drag\243n rojo. Ahora es incluso m\225s[ENTER]poderoso, y los efectos de la Materia negra[ENTER]parecen tambi\233n m\225s fuertes. "
gameforge.main_quest_flame_lv104._190_say = "Habla con Yon-I-Walker. \201l sabr\225 c\243mo acabar con[ENTER]Arrador de una vez por todas. "
gameforge.main_quest_flame_lv104._200_notice = "Ve a ver a Yon-I-Walker y averigua c\243mo vencer a[ENTER]Arrador de una vez por todas. "
gameforge.main_quest_flame_lv104._210_sayTitle = "Habla con Yon-I-Walker. "
gameforge.main_quest_flame_lv104._220_say = "Ve a ver a Yon-I-Walker y averigua c\243mo vencer a[ENTER]Arrador de una vez por todas. "
gameforge.main_quest_flame_lv104._230_say = "\191Todav\237a no has hablado con Yon-I-Walker? \191Y c\243mo[ENTER]piensas derrotar a Arrador? \161Venga! \191A qu\233 est\225s[ENTER]esperando? "
gameforge.main_quest_flame_lv104._240_say = "S\237, es cierto. Arrador ha regresado, y est\225 mucho[ENTER]m\225s furioso que antes. Solo nos queda un modo de[ENTER]estropear los planes de los Servidores de la[ENTER]oscuridad... "
gameforge.main_quest_flame_lv104._250_say = "Arrador no se detendr\225 hasta que consiga liberar[ENTER]al Drag\243n rojo y llevar a cabo sus planes. Si[ENTER]desterramos al Drag\243n, podremos pararle los pies. "
gameforge.main_quest_flame_lv104._260_say = {}
gameforge.main_quest_flame_lv104._270_say = "Das Element des Rotdrachen ist das Feuer und Feuer bek\228mpft man am Besten mit Feuer Jeder Flammend\228mon tr\228gt einen Magmakern in sich Beschaffe mir jeweils f\252nf Kerne der folgenden Monster Glut Flammenk\246nig Glut Flammenbart Glut Flammengolem Glut Flammengeneral und Glut Flammenf\252rst "
gameforge.main_quest_flame_lv104._280_notice = "Beschaffe die Magmakerne der Flammend\228monen "
gameforge.main_quest_flame_lv104._290_say = "Beschaffe jeweils f\252nf Magmakerne dieser Gegner Glut Flammenk\246nig Glut Flammenbart Glut Flammengolem Glut Flammengeneral Glut Flammenf\252rst Kehre damit zu Yon I Walker zur\252ck "
gameforge.main_quest_flame_lv104._300_say = "Oh ja du hast schon einige gefunden Bringe noch das sollte dann reichen "
gameforge.main_quest_flame_lv104._310_say = "Bien, ahora ya tengo todos los Anillos magm\225ticos.Antes de trabajar con ellos, tengo que dejarlos[ENTER]enfriar un poco. Te har\233 llamar si necesito tu[ENTER]ayuda. "
gameforge.main_quest_flame_lv104._320_say = "Hm, los Anillos magm\225ticos ya est\225n fr\237os y no[ENTER]sirven de nada. Tr\225eme m\225s. "
gameforge.main_quest_flame_lv104._330_sendLetter = "Abortar planes II "
gameforge.main_quest_flame_lv104._340_say = "Yon-I-Walker pregunta por ti, \191por qu\233 no vas a[ENTER]verlo? "
gameforge.main_quest_flame_lv104._350_say = "Todav\237a necesito algo de tiempo; no puedo[ENTER]trabajar con los Anillos magm\225ticos hasta que se[ENTER]hayan enfriado un poco. Mientras tanto, \191podr\237as[ENTER]traerme Agua Dok para disolverlos? "
gameforge.main_quest_flame_lv104._360_say = "Mit dieser Magmasuspension werden wir den Rotdrachen verbannen k\246nnen Yak Hwan wird dich dann sp\228ter \252ber das genaue Prozedere aufkl\228ren Bitte beschaffe mir nun 100 Flaschen Dok Wasser Ich mache hier so lange weiter "
gameforge.main_quest_flame_lv104._370_notice = "Hazte con 100 botellas de Agua Dok y ll\233vaselas a[ENTER]Yon-I-Walker. "
gameforge.main_quest_flame_lv104._380_say = "Hazte con 100 botellas de Agua Dok y ll\233vaselas a[ENTER]Yon-I-Walker. "
gameforge.main_quest_flame_lv104._390_say = "Nun habe ich alles beisammen und kann den Verbannungszauber herstellen "
gameforge.main_quest_flame_lv104._400_say = "Bald Brauchst du noch etwas "
gameforge.main_quest_flame_lv104._410_say = "Solo me falta un ingrediente, pero tengo[ENTER]concentrarme en el proceso de disoluci\243n para no[ENTER]cometer errores. Te llamar\233 m\225s tarde. "
gameforge.main_quest_flame_lv104._420_say = "Pero si no hay 100 botellas... Por favor, ve a[ENTER]buscar m\225s Agua Dok. "
gameforge.main_quest_flame_lv104._430_notice = "Has reunido 100 botellas de Agua Dok. Ll\233vaselas[ENTER]a Yon-I-Walker. "
gameforge.main_quest_flame_lv104._440_say = "Habla con Yon-I-Walker. "
gameforge.main_quest_flame_lv104._450_sendLetter = "Abortar planes III "
gameforge.main_quest_flame_lv104._460_say = "Ich komme gut voran mir der Suspension Doch ein weiteres Mal bin ich noch auf deine Hilfe angewiesen "
gameforge.main_quest_flame_lv104._470_say = "Nun ben\246tige ich noch ein geeignetes Gef\228\223 f\252r den Verbannungszauber Die Fl\252gelhaut Martyaxwars H\228uptling der Mantikore sollte uns gute Dienste leisten Beschaffe f\252nf St\252cke "
gameforge.main_quest_flame_lv104._480_notice = "Bringe Yon I Walker f\252nf St\252cke aus der Fl\252gelhaut Martyaxwars "
gameforge.main_quest_flame_lv104._490_say = "Bringe Yon I Walker f\252nf St\252cke aus der Fl\252gelhaut Martyaxwars in guter Qualit\228t "
gameforge.main_quest_flame_lv104._500_say = "Estamos tan cerca... \161No podemos darnos por[ENTER]vencidos! Tr\225eme el Cuero mant\237cora. "
gameforge.main_quest_flame_lv104._510_say = "Perfekt Die Fl\252gelhaut ist sehr widerstandsf\228hig Aus ihr kann ich nun Lederbeutel f\252r den Verbannungszauber herstellen Yak Hwan wird dich sp\228ter noch genauer instruieren Aber nun mache ich mich erstmal an die Arbeit "
gameforge.main_quest_flame_lv104._520_notice = "Ya tienes suficientes unidades de Cuero mant\237cora.[ENTER]Ll\233vaselas a Yon-I-Walker. "
