gameforge.main_quest_flame_lv105._050_say = "Ah, estupendo. Luego te explico c\243mo se usa.[ENTER]Primero tenemos que conseguir abrirnos paso a[ENTER]trav\233s de las nuevas defensas de los Demonios[ENTER]Fuego. Regresa a la Fortaleza del Drag\243n rojo y[ENTER]acaba con:[ENTER]10 Reyes llamaascua[ENTER]10 Barbas llamaascua[ENTER]10 Trols llamaascua[ENTER]10 Generales llamaascua[ENTER]10 Pr\237ncipes llamaascua "
gameforge.main_quest_flame_lv105._060_say = {}
gameforge.main_quest_flame_lv105._070_say = "Entendido. "
gameforge.main_quest_flame_lv105._080_notice = "Besiege jeweils 10 Glut Flammenk\246nige Glut Flammenb\228rte Glut Flammengolem Glut Flammengener\228le und Glut Flammenf\252rste "
gameforge.main_quest_flame_lv105._090_sayTitle = "Starte die Offensive "
gameforge.main_quest_flame_lv105._100_say = "\161Asalta la Fortaleza del Drag\243n Rojo! "
gameforge.main_quest_flame_lv105._110_sayReward = "Du ben\246tigst eine Gruppe und einen Passierschein "
gameforge.main_quest_flame_lv105._120_say = "Todav\237a no podemos atravesar las l\237neas de[ENTER]defensa enemiga. Derrota al ej\233rcito de los[ENTER]Demonios llamaascua. "
