gameforge.main_quest_flame_lv105._140_say = "Vuelve a ver a Yak-Hwan. "
gameforge.main_quest_flame_lv105._150_say = "Has hecho un buen trabajo; hemos avanzado un paso[ENTER]m\225s hacia nuestro objetivo. \161El Drag\243n rojo ya no[ENTER]supondr\225 una amenaza por mucho tiempo! "
gameforge.main_quest_flame_lv105._160_sendLetter = "Gunst und Groll "
gameforge.main_quest_flame_lv105._170_say = "Tu archienemigo, Arrador, parece estar resentido[ENTER]porque le mataste. Su bramido retumba m\225s fuerte[ENTER]que nunca en las llanuras de Doyyumhwan. "
gameforge.main_quest_flame_lv105._180_say = "Es hora de volver a pararle los pies. \201l guarda[ENTER]con recelo el port\243n tras el que se encuentra[ENTER]cautivo el Drag\243n rojo. \161Ten cuidado! La derrota[ENTER]le habr\225 ense\241ado que no debe a cometer los[ENTER]mismos errores. "
