gameforge.main_quest_flame_lv105._200_sayTitle = "Juega con fuego "
gameforge.main_quest_flame_lv105._210_say = "Derrota a Arrador, Se\241or del fuego, en la[ENTER]Fortaleza del Drag\243n Rojo. "
gameforge.main_quest_flame_lv105._220_say = "\191Que no has podido con Arrador? No me lo puedo[ENTER]creer. Ya lo conseguiste una vez, \161y ahora[ENTER]tambi\233n lo conseguir\225s! "
gameforge.main_quest_flame_lv105._230_notice = "Arrador ha sido aniquilado. Ve a informar a[ENTER]Yak-Hwan. "
gameforge.main_quest_flame_lv105._240_say = "Ich wusste du w\252rdest es schaffen Gro\223artig Nun werden wir alles f\252r die Verbannung des Rotdrachen vorbereiten Ich lasse dich rufen sobald wir bereit sind "
gameforge.main_quest_flame_lv105._250_sendLetter = "Verbannung des Rotdrachen "
gameforge.main_quest_flame_lv105._260_say = "Es la hora. Ya est\225 todo listo, podemos expulsar[ENTER]de estas tierras al Drag\243n rojo. "
gameforge.main_quest_flame_lv105._270_say = "Meine M\228nner haben bereits bereits zwei Bannkreise aufgestellt Deine Aufgabe ist es nun sie zu entz\252nden Wirf den Bannbeutel auf die Kreise und sie werden sich entflammen Das wird die Verbannung des Rotdrachen vollziehen "
gameforge.main_quest_flame_lv105._280_notice = "Entz\252nde die Bannkreise und schicke den Rotdrachen in die Verbannung "
gameforge.main_quest_flame_lv105._290_say = "Restliche Verbannungsanzahl "
gameforge.main_quest_flame_lv105._300_sayTitle = "Verbannung des Rotdrachen "
gameforge.main_quest_flame_lv105._310_say = "Entz\252nde mithilfe der Bannbeutel die magischen Kreissymbole und schicke den Rotdrachen in die Verbannung "
gameforge.main_quest_flame_lv105._320_say = "L\225pida de Taramor: 1 unidad "
gameforge.main_quest_flame_lv105._330_sayTitle = "Rotdrachen Flammenschauspiel "
gameforge.main_quest_flame_lv105._340_say = "\191Eso es todo, insecto? Casi no me has hecho ni[ENTER]cosquillas, \161as\237 no conseguir\233is desterrarme![ENTER]Traer\233 de vuelta a Arrador del reino de los[ENTER]muertos; \233l me liberar\225 de mi cautiverio, \161y[ENTER]entonces probar\233is mi furia en vuestras propias[ENTER]carnes! "
gameforge.main_quest_flame_lv105._350_notice = "El destierro del Drag\243n rojo ha salido mal.[ENTER]Informa a Yak-Hwan. "
gameforge.main_quest_flame_lv105._360_say = "Die Verbannung ist fehlgeschlagen Wie konnte das passieren "
gameforge.main_quest_flame_lv105._370_say = "Ja Eigentlich wurden die Bannkreise aktiviert und die Entflammung hat auch stattgefunden und die Verbannung hatte begonnen aber der Rotdrache war so m\228chtig dass dies fehlgeschlagen ist Er sagte dass er Yamachun 6091 wiederbeleben wird und er die Versiegelung entfernen wird Aber er hat auch gro\223en Schaden durch unseren Verbannungs Versuch erlitten "
gameforge.main_quest_flame_lv105._380_say = "Ach so Gute Arbeit Dank dir konnten wir es so weit bringen Ich habe bereits mit Yon I Walker 20380 gesprochen und \252berlegt was wir nun tun k\246nnen Meine M\228nner werden weiterhin die Lage beobachten und wir werden ach anderen Methoden suchen wie wir die Verbannung vollziehen k\246nnen Wenn wir eine perfekte Methoe gefunden haben den Rotdrachen zu verbannen werde ich nach dir rufen lassen Gute Arbeit "
gameforge.main_quest_flame_lv99 = {}
gameforge.main_quest_flame_lv99._010_sendLetter = "Hacia el fuego "
gameforge.main_quest_flame_lv99._020_say = "Yak-Hwan te est\225 buscando. Ve a verlo y averigua[ENTER]qu\233 es lo que quiere. "
gameforge.main_quest_flame_lv99._030_say = "\161Te damos la bienvenida de nuevo! Tras una[ENTER]peque\241a tregua, los Servidores de la oscuridad[ENTER]vuelven al acecho. Esto no tiene buena pinta. "
gameforge.main_quest_flame_lv99._040_say = {}
gameforge.main_quest_flame_lv99._050_say = "Mi informaci\243n es, no obstante, muy vaga.[ENTER]Sabemos que se encuentran en la Tierra de Fuego. "
gameforge.main_quest_flame_lv99._060_say = "Acabamos de enviar a un esp\237a.[ENTER]Hemos perdido el contacto recientemente y la[ENTER]situaci\243n me preocupa. Ya que vas hacia la Tierra[ENTER]de Fuego, \191te importar\237a ir en su busca? "
gameforge.main_quest_flame_lv99._070_say = "Por supuesto. "
gameforge.main_quest_flame_lv99._080_say = "Gracias. Te voy a marcar su \250ltima posici\243n[ENTER]conocida en el mapa. \161Que te vaya bien! "
gameforge.main_quest_flame_lv99._090_notice = "Ve en busca del esp\237a perdido en la Tierra de[ENTER]Fuego. Coordenadas: %d,%d "
gameforge.main_quest_flame_lv99._100_sayTitle = "\161Explora la Tierra de Fuego! "
gameforge.main_quest_flame_lv99._110_say = "Viaja a la Tierra de Fuego. Una vez all\237, busca[ENTER]al esp\237a y halla indicios que arrojen algo de luz[ENTER]sobre las maquinaciones de los Servidores de la[ENTER]oscuridad. "
gameforge.main_quest_flame_lv99._120_say = "Tiene que haber algo en este lugar; puede que[ENTER]hayas pasado por alto alg\250n indicio.[ENTER]Sigue buscando. "
gameforge.main_quest_flame_lv99._130_notice = "Dies ist der Ort den Yak Hwan auf der Karte markiert hat Schaue dich um und kehre dann zu Yak Hwan zur\252ck "
gameforge.main_quest_flame_lv99._140_say = "Yak-Hwan espera tu informe en el Pe\241asco del[ENTER]Drag\243n Oscuro. "
gameforge.main_quest_flame_lv99._150_say = "\161Est\225s de vuelta! \191Has averiguado algo? "
gameforge.main_quest_flame_lv99._160_say = "Por desgracia, ni rastro del esp\237a, pero hay una[ENTER]fortaleza que nunca me hab\237a llamado la atenci\243n.[ENTER]Desde el interior de los muros emana un aura muy[ENTER]poderosa que adem\225s afecta al entorno. "
gameforge.main_quest_flame_lv99._170_say = "Hm, esto no me gusta nada. Voy a recopilar m\225s[ENTER]informaci\243n sobre esa fortaleza. En cuanto la[ENTER]tenga, te lo har\233 saber. "
gameforge.main_quest_flame_lv99._180_sendLetter = "Investigar la fortaleza "
gameforge.main_quest_flame_lv99._190_say = "Hm wir tappen im Dunkeln Ich habe rein gar nichts \252ber diese geheimnisvolle Festung herausfinden k\246nnen In diesem Brief habe ich alles zusammengetragen was wir bis jetzt wissen Bitte \252berbringe ihn Yon I Walker Er wird wissen was zu tun ist "
gameforge.main_quest_flame_lv99._200_say = "Habla con Yon-I-Walker. "
gameforge.main_quest_flame_lv99._210_say = "Was kann ich f\252r dich tun Ah ein Brief Yak Hwan bittet also um meine Hilfe Dann werden wir mal versuchen Licht in die Dunkelheit zu bringen "
gameforge.main_quest_flame_lv99._220_say = {}
gameforge.main_quest_flame_lv99._230_say = {}
gameforge.main_quest_flame_lv99._240_say = "Eine geheimnisvolle Aura die aus dem Inneren einer Festung str\246mt Interessant Schaue dich zun\228chst einmal in der n\228heren Umgebung dort um Ich habe da einen Verdacht worum es sich bei dieser Aura handeln k\246nnte Hier nimm dieses Papier und wickel es um deine Waffe Wenn sich mein Verdacht best\228tigt sollte sich das Papier schwarz f\228rben sobald du damit D\228monen t\246test die unter dem Einfluss der dunklen Aura stehen "
gameforge.main_quest_flame_lv99._250_notice = "Acaba con los demonios que vagan junto a la[ENTER]fortaleza. "
gameforge.main_quest_flame_lv99._260_sayTitle = "Caza de demonios "
gameforge.main_quest_flame_lv99._270_say = "Acaba con los demonios de la Tierra de Fuego que[ENTER]vagan por los alrededores de la fortaleza y[ENTER]comprueba que tu arma ha cambiado de color. "
gameforge.main_quest_flame_lv99._280_say = "Hm, seguro que en la Tierra de Fuego hay pistas[ENTER]sobre esa aura. Regresa una vez m\225s a la Tierra[ENTER]de Fuego y elimina a los demonios que se[ENTER]encuentran cerca de la fortaleza. "
gameforge.main_quest_flame_lv99._290_notice = "Tu arma se ha te\241ido de negro. Vuelve a ver a[ENTER]Yon-I-Walker. "
gameforge.main_quest_flame_lv99._300_say = "Ah so wie ich es erwartet hatte Das ist h\246chst bemerkenswert Ich werde dieses Papier etwas n\228her untersuchen Ruhe dich solange aus "
gameforge.main_quest_flame_lv99._310_sendLetter = "Aura erforschen "
gameforge.main_quest_flame_lv99._320_say = "Yon-I-Walker te est\225 buscando. Ve a verlo para[ENTER]saber por qu\233. "
gameforge.main_quest_flame_lv99._330_say = "Ah, \161ah\237 est\225s! Se trata de un aura maliciosa y[ENTER]me est\225 nublando la mente.[ENTER]Necesito Hierbas del sol para despejarme y poder[ENTER]continuar con el an\225lisis.[ENTER]\191Podr\237as traerme unas pocas? "
gameforge.main_quest_flame_lv99._340_say = "Por supuesto. "
gameforge.main_quest_flame_lv99._350_say = "Las Hierbas del sol crecen en lugares c\225lidos y[ENTER]secos. En la Tierra de Fuego las hay durante todo[ENTER]el a\241o. Voy a marcarte en el mapa el \250ltimo sitio[ENTER]donde las encontr\233, aunque ya no recuerdo con[ENTER]certeza si es el lugar correcto... "
gameforge.main_quest_flame_lv99._360_say = "\161Me pondr\233 en marcha inmediatamente! "
gameforge.main_quest_flame_lv99._370_notice = "Ve al lugar marcado en la Tierra de Fuego y busca[ENTER]las Hierbas del sol. "
gameforge.main_quest_flame_lv99._380_sayTitle = "Sonnenkr\228uter besorgen "
gameforge.main_quest_flame_lv99._390_say = "Ve al lugar que te ha marcado en el mapa[ENTER]Yon-I-Walker y busca las Hierbas del sol. "
gameforge.main_quest_flame_lv99._400_say = "\191Vienes con las manos vac\237as? Esto va mal.[ENTER]Siento c\243mo el aura nubla mi mente cada vez m\225s.[ENTER]Por favor, ve a por las Hierbas del sol. "
gameforge.main_quest_flame_lv99._410_notice = "Has encontrado las Hierbas del sol. Ll\233vaselas a[ENTER]Yon-I-Walker. "
gameforge.main_quest_flame_lv99._420_say = "Ah, \161has encontrado las Hierbas del sol![ENTER]Extraordinario. Ahora puedo continuar con mi[ENTER]investigaci\243n. Yak-Hwan compartir\225 los resultados[ENTER]contigo. "
gameforge.main_quest_flame_lv99._430_say = "La aventura contin\250a tan pronto como hayas[ENTER]alcanzado el nivel %d. "
gameforge.main_quest_lv1 = {}
gameforge.main_quest_lv1._10_sendLetter = "Bienvenido a Metin 2 "
gameforge.main_quest_lv1._20_say = "Las excitantes aventuras de Metin 2 est\225n a punto[ENTER]de comenzar. Para empezar, por favor, busca al[ENTER]guardi\225n de la ciudad. Te dar\225 alguna informaci\243n[ENTER]b\225sica y varias tareas para ayudar a que te[ENTER]familiarices con Metin 2. Por favor, vis\237tale; ya[ENTER]te est\225 esperando.[ENTER][ENTER]Si quieres cazar, encontrar\225s animales salvajes[ENTER]justo al salir de la aldea. Estos animales est\225n[ENTER]marcados en rojo en el mini mapa, lo que indica[ENTER]que son enemigos. Ahora mismo, deber\237as cazar[ENTER]perros salvajes, ya que son los objetivos m\225s[ENTER]f\225ciles. \161Buena suerte! "
gameforge.main_quest_lv1._30_targetVid = "Encuentra al Guardi\225n de la Ciudad "
gameforge.main_quest_lv1._40_sayTitle = "Encuentra al Guardi\225n de la Ciudad "
gameforge.main_quest_lv1._50_sayReward = "Habla con el guardi\225n de la ciudad. Encuentra al[ENTER]NPC al que se\241ala la flecha roja. Si no le puedes[ENTER]ver, debes estar demasiado lejos. Sigue los[ENTER]c\237rculos que parpadean en el mapa hasta que[ENTER]llegues al Guardi\225n de la Ciudad. "
gameforge.main_quest_lv1._60_sayTitle = "Guardi\225n de la ciudad: "
gameforge.main_quest_lv1._70_say = "\161Debes ser nuevo en la ciudad! Veo que a\250n no te[ENTER]han convertido en soldado. \191Has recibido alg\250n[ENTER]entrenamiento? \161M\237rate! \191Tienes idea de c\243mo usar[ENTER]un arma? \161Esc\250cha! Tienes que tener cuidado si[ENTER]quieres sobrevivir a esta guerra. Voy a ayudarte[ENTER]hasta que hayas adquirido suficiente experiencia[ENTER]o llegues a nivel 10. \161Soy una persona ocupada[ENTER]as\237 que no me hagas perder el tiempo! \161Mu\233vete! "
gameforge.main_quest_lv1._80_say = "\161Ahora ve y aprende algunas cosas b\225sicas para el[ENTER]combate y la caza! Una vez hayas alcanzado un[ENTER]nivel superior, debes volver a la aldea y hablar[ENTER]conmigo. \191Por qu\233 est\225s todav\237a aqu\237? \161No ganar\225s[ENTER]experiencia ah\237 plantado! "
gameforge.main_quest_lv10 = {}
gameforge.main_quest_lv10._100_sayReward = "Has recibido 50.000 puntos de experiencia.[ENTER]Has recibido 12.000 Yang.[ENTER]Has recibido unos Zapatos Adorno Oro +4.[ENTER]Has recibido 5 Pociones Moradas. "
gameforge.main_quest_lv10._10_sendLetter = "Ve con el Capit\225n. "
gameforge.main_quest_lv10._110_sayTitle = "El entrenamiento del Capit\225n "
gameforge.main_quest_lv10._120_sayReward = "La primera misi\243n del Capit\225n te lleva a la aldea[ENTER]vecina. All\237 debes visitar al m\250sico Yu-Hwan y[ENTER]pedirle los documentos secretos para el Capit\225n. "
gameforge.main_quest_lv10._130_sayTitle = "M\250sico Yu-Hwan: "
gameforge.main_quest_lv10._140_say = "La vida es un sue\241o, al igual que todo lo dem\225s.[ENTER]\191De d\243nde venimos y ad\243nde vamos? El mundo est\225[ENTER]lleno de conflictos. El trabajo honesto nunca[ENTER]amortiza. \191Est\225s aqu\237 para escuchar mi canci\243n? "
gameforge.main_quest_lv10._150_say = "Oh, \161te env\237a el Capit\225n! Psst, baja la voz...[ENTER][ENTER]Nadie en la aldea debe saber mi verdadera[ENTER]identidad. Debes ser de confianza si te env\237a el[ENTER]Capit\225n. Aqu\237 tienes. El documento contiene toda[ENTER]la informaci\243n que fui capaz de recoger.[ENTER]Entr\233gaselo al Capit\225n. "
gameforge.main_quest_lv10._160_sayTitle = "M\250sico Yu-Hwan: "
gameforge.main_quest_lv10._170_say = "\161Date prisa y vete! Si te quedas demasiado por[ENTER]aqu\237, pasar\225 algo malo. \191Qu\233 es la vida? La vida[ENTER]es corta. Disfr\250tala mientas puedas. "
gameforge.main_quest_lv10._180_targetVid = "Regresar con el Capit\225n. "
gameforge.main_quest_lv10._190_sayReward = "El m\250sico Yu-Hwan, quien trabaja en secreto como[ENTER]esp\237a, te ha dado documentos importantes.[ENTER]Ll\233vaselos al Capit\225n en la primera aldea. "
gameforge.main_quest_lv10._200_say = "\191Este es el documento del m\250sico? \161Nada mal para[ENTER]un aventurero nuevo! Espero grandes cosas de ti.[ENTER]Coge esto como recompensa por tu trabajo.[ENTER]\161Continua con el buen trabajo por tu pa\237s! "
gameforge.main_quest_lv10._20_sayReward = "Ahora tienes la experiencia suficiente para[ENTER]servir a tu reino como un completo guerrero.[ENTER]Desde ahora el Capit\225n te dar\225 tareas nuevas. Le[ENTER]encontrar\225s en la primera aldea. Ve a verle; te[ENTER]est\225 esperando. "
gameforge.main_quest_lv10._30_sayTitle = "Capit\225n "
gameforge.main_quest_lv10._40_say = "Me resultas familiar... Oh s\237, creo que he o\237do[ENTER]sobre ti. Eres el nuevo aventurero y lo has hecho[ENTER]bien demostrando tus habilidades. A\250n no se[ENTER]exactamente lo experimentado que eres, pero vas a[ENTER]ser probado en tareas futuras. "
gameforge.main_quest_lv10._50_say = "Hay retos por delante, as\237 que prep\225rate para[ENTER]ellos. \191Conoces la historia de los tres reinos?[ENTER]\191O la historia del continente Para\237so[ENTER]Relampagueante? \191\161No las conoces!? \191Qu\233 ense\241an[ENTER]los instructores estos d\237as? \191Tengo que ense\241arte[ENTER]cosas tan fundamentales? "
gameforge.main_quest_lv10._60_say = "Esto es importante, y voy a resumirlo solo una[ENTER]vez. \161As\237 que esc\250chame! En otro tiempo, hubo un[ENTER]reino unido. Cuando aparecieron las piedras[ENTER]Metin, el reino fue dividido en tres reinos:[ENTER]Shinsoo, el reino del comercio, Chunjo, el reino[ENTER]de la religi\243n y Jinno, el reino del ej\233rcito. "
gameforge.main_quest_lv10._70_say = "Cada reino intenta recobrarse de las revueltas[ENTER]causadas por las piedras Metin. Todo el mundo[ENTER]est\225 tratando de reunir los reinos. \161Tu tambi\233n[ENTER]tienes que trabajar por la uni\243n de los reinos![ENTER]Es importante que no lo olvides nunca. "
gameforge.main_quest_lv10._80_say = "Voy a darte tu primera tarea.[ENTER]Tranquilo, es algo f\225cil. En la siguiente aldea,[ENTER]encontrar\225s a un m\250sico llamado Yu-Hwan. La gente[ENTER]piensa que dej\243 la armada para convertirse en[ENTER]m\250sico. De hecho, es un esp\237a. Hay un documento[ENTER]que necesito de Yu-Hwan. Tr\225emelo. No olvides que[ENTER]esto es una misi\243n secreta. "
gameforge.main_quest_lv10._90_say = "Pulsa la tecla M para averiguar c\243mo llegar a la[ENTER]siguiente aldea. Usa el portal indicado por un[ENTER]punto azul. \161Date prisa! El m\250sico Yu-Hwan es el[ENTER]tipo grande con un instrumento. "
gameforge.main_quest_lv12 = {}
