gameforge.main_quest_lv12._10_sayReward = "El Capit\225n tiene una nueva tarea para ti. Ve a[ENTER]hablar con \233l. "
gameforge.main_quest_lv12._110_say = "\191Quieres abandonar la misi\243n para siempre? "
gameforge.main_quest_lv12._120_say = "\191As\237 que lo hiciste? \161Bien hecho! No has tenido[ENTER]mucho problema, \191no? De todos modos, sigamos con[ENTER]el siguiente paso. "
gameforge.main_quest_lv12._130_targetVid = "Encuentra al Capit\225n "
gameforge.main_quest_lv12._140_sendLetter = "Tarea completada. "
gameforge.main_quest_lv12._150_say = "Tarea completada. "
gameforge.main_quest_lv12._160_sayReward = "Has matado el n\250mero necesario de Lobos Alfa[ENTER]Gris. Ahora vuelve con el Capit\225n e inf\243rmale de[ENTER]tu \233xito. "
gameforge.main_quest_lv12._170_say = "\191Has matado los Lobos Alfa Gris? Buen trabajo.[ENTER]Gracias a ti, ahora es mucho m\225s f\225cil mantener[ENTER]la aldea a salvo. Eso son realmente buenas[ENTER]noticias de cambio en tiempos de guerra como[ENTER]\233stos. "
gameforge.main_quest_lv12._180_sayReward = "Has recibido 40.000 puntos de experiencia.[ENTER]Has recibido 10.000 Yang.[ENTER]Has recibido un Manual de Habilidad. "
gameforge.main_quest_lv12._20_say = "Varios lobos Alfa grises han estado causando[ENTER]da\241os justo en las afueras de la aldea. Han[ENTER]estado corriendo salvajes durante un tiempo,[ENTER]\161pero ahora ha ido demasiado lejos![ENTER]Hace poco, han estado atacando la aldea y a los[ENTER]aldeanos m\225s a menudo. Necesitamos tener la[ENTER]situaci\243n bajo control. Tenemos que matar algunos[ENTER]de esos lobos Alfa grises. Parece que tratas[ENTER]bastante bien este tipo de cosas, as\237 que estoy[ENTER]seguro de que podr\225s manejarlo. Ve y mata 10[ENTER]lobos Alfa grises por nosotros. "
gameforge.main_quest_lv12._30_sayReward = "Como recompensa te esperan 24\160000 puntos de[ENTER]experiencia y 3500 Yang. "
gameforge.main_quest_lv12._40_sendLetter = "Mata 10 Lobos Alfa Gris "
gameforge.main_quest_lv12._50_sayReward = "Los lobos Alfa grises est\225n atacando la aldea.[ENTER]Para mantener la situaci\243n bajo control, tienes[ENTER]que matar 10 de ellos. "
gameforge.main_quest_lv12._60_sayReward = "Hasta ahora, has matado %s lobos Alfa grises. "
gameforge.main_quest_lv12._65_counter = "N\250mero restante "
gameforge.main_quest_lv12._70_sayReward = "Has matado 10 lobos Alfa grises. Vuelve con el[ENTER]Capit\225n. "
gameforge.main_quest_lv12._80_npcChat = "Mata lobos Alfa grises "
gameforge.main_quest_lv12._90_say = "\191Qu\233\191 \191A\250n no has finalizado la tarea?[ENTER]\191Est\225s teniendo problemas para matar a esos lobos[ENTER]Alfa grises? \191Quieres seguir intent\225ndolo? "
gameforge.main_quest_lv14 = {}
gameforge.main_quest_lv14._100_sayTitle = "Tarea completada. "
gameforge.main_quest_lv14._10_sayReward = "El Capit\225n tiene una nueva tarea para ti. Ve a[ENTER]hablar con \233l. "
gameforge.main_quest_lv14._110_sayReward = "Has destruido un Metin de Batalla. Ve con el[ENTER]Capit\225n e inf\243rmale de tu \233xito. "
gameforge.main_quest_lv14._120_say = "\161Buen trabajo! \161Te has convertido en un ayudante[ENTER]de confianza! Ahora se que puedo confiar en ti[ENTER]para cualquier tarea. Estoy orgulloso de tenerte[ENTER]trabajando con nosotros. Aqu\237 est\225 tu recompensa,[ENTER]\161sigue as\237! "
gameforge.main_quest_lv14._130_sayReward = "Has recibido 20.000 puntos de experiencia.[ENTER]Has recibido 20.000 Yang.[ENTER]Has recibido un Terr\243n de Oro. "
gameforge.main_quest_lv14._140_sayReward = "Has recibido 1 %s. "
gameforge.main_quest_lv14._20_say = "S\233 cosas sobre las piedras Metin. El m\250sico[ENTER]Yu-Hwan me ha informado de que las piedras Metin[ENTER]hacen que los animales se vuelvan locos. Adem\225s,[ENTER]difunden enfermedades. "
gameforge.main_quest_lv14._30_say = "Si no hacemos nada con las piedras Metin, los[ENTER]animales atacar\225n otra vez a los aldeanos. O[ENTER]incluso peor; \161la enfermedad se puede propagar[ENTER]por toda la aldea! Oc\250pate de las piedras Metin[ENTER]que est\225n cayendo en el exterior de la aldea.[ENTER]Estoy seguro de que puedes manejarlo, viendo como[ENTER]sacaste a esos lobos Alfa grises. "
gameforge.main_quest_lv14._40_sayReward = "Como recompensa te esperan 48\160000 puntos de[ENTER]experiencia, 10\160000 Yang y una Piedra esp\237ritu[ENTER](+0 a +2). "
gameforge.main_quest_lv14._50_sendLetter = "Destruye el Metin de Batalla "
gameforge.main_quest_lv14._60_sayReward = "Las Piedras Metin son un peligro serio. Ayuda al[ENTER]Capit\225n y destruye un Metin de Batalla. "
gameforge.main_quest_lv14._70_sayTitle = "Tarea completada. "
gameforge.main_quest_lv14._80_sayReward = "Has destruido el Metin de Batalla. Habla con el[ENTER]Capit\225n. "
gameforge.main_quest_lv14._90_sendLetter = "Regresar con el Capit\225n. "
gameforge.main_quest_lv15 = {}
gameforge.main_quest_lv15._100_say = "Jinno: nuestro Reino tiene una tradici\243n militar[ENTER]existente hace mucho tiempo. El rey unific\243 el[ENTER]continente usando su excelente y poderosa[ENTER]caballer\237a. Incluso ahora que estamos divididos a[ENTER]causa de los problemas generados por las piedras[ENTER]Metin, nuestro reino a\250n tiene el poder leg\237timo[ENTER]de Iryung. "
gameforge.main_quest_lv15._10_qSetTitle = "La situaci\243n actual "
gameforge.main_quest_lv15._110_say = "A\250n tenemos la armada m\225s poderosa de los tres[ENTER]reino, aunque no podemos hacer nada ahora mismo[ENTER]con las piedras Metin. Si quisieramos realmente,[ENTER]podr\237amos conquistar f\225cilmente los otros reinos.[ENTER]\161Debes entrenar duro para convertirte en un buen[ENTER]soldado! "
gameforge.main_quest_lv15._120_say = "Voy a darte una nueva tarea. Entrega esta[ENTER]munici\243n a Yu-Hwan en la aldea vecina. Nuestro[ENTER]reino tiene una armada poderosa, pero tenemos que[ENTER]estar seguros de tener suficiente munici\243n. Si[ENTER]entregas esto a Yu-Hwan, ayudar\225s a armar la[ENTER]aldea. "
gameforge.main_quest_lv15._130_sayReward = "Has recibido 36.000 puntos de experiencia.[ENTER]Has recibido 10.000 Yang.[ENTER]Has recibido una Ornamentaci\243n. "
gameforge.main_quest_lv15._140_sayTitle = "La situaci\243n actual "
gameforge.main_quest_lv15._150_sayReward = "El Capit\225n te ha confiado una entrega para[ENTER]Yu-Hwan. Ll\233vasela a la Segunda Aldea. "
gameforge.main_quest_lv15._160_say = "\201rase una vez, una sangrienta batalla entre Sung[ENTER]Mahi y el Dios Drag\243n. Desde entonces, la gente[ENTER]ha estado dividida y compiten contra los otros en[ENTER]guerras interminables... \161T\250 otra vez! \191Necesitas[ENTER]algo? \191El Capit\225n me ha enviado algo importante?[ENTER]Gracias. Y ahora sigue tu camino otra vez - no es[ENTER]bueno que nos vean juntos. "
gameforge.main_quest_lv15._170_makequestbutton = "Habla con el Capit\225n. "
gameforge.main_quest_lv15._175_say = "Has logrado entregarle a Yu-Hwan el encargo del[ENTER]Capit\225n. Ahora vuelve a ver al Capit\225n y recoge[ENTER]tu recompensa. "
gameforge.main_quest_lv15._180_say = "\161Bien hecho! Si sigues as\237, puedes convertirte en[ENTER]un ayudante importante para nuestra aldea.[ENTER]Aqu\237 est\225 tu recompensa. "
gameforge.main_quest_lv15._20_say = "Ve con el Capit\225n. El te dir\225 sobre la situaci\243n[ENTER]actual de los tres reinos. "
gameforge.main_quest_lv15._30_say = "Veo que ya est\225s listo para aprender m\225s sobre la[ENTER]situaci\243n actual. D\233jame comenzar con nuestro[ENTER]reino. Para ganar una guerra, tienes que[ENTER]conocerte a ti mismo antes de que puedas aprender[ENTER]verdaderamente sobre tu enemigo. "
gameforge.main_quest_lv15._40_say = "Shinsoo: nuestro reino ha sido siempre un reino[ENTER]de comercio. Ten\237amos extensas rutas comerciales;[ENTER]por eso el comercia tuvo \233xito en nuestro reino.[ENTER]Desde que las piedras Metin aparecieron, el[ENTER]comercio se ha vuelto malo y los negocios solo[ENTER]van a peor. Al ser un reino de comercio, nunca[ENTER]tuvimos una armada enorme, ya que no ten\237amos[ENTER]necesidad de ello.[ENTER]Gracias a nuestra fortuna, fuimos capaces de[ENTER]contratar muchos mercenarios. Los mercenarios son[ENTER]leales y de confianza... mientras se les pague. "
gameforge.main_quest_lv15._50_say = "Gracias a los mercenarios, nuestro pa\237s ha[ENTER]recuperado su estabilidad. Pero para estar[ENTER]preparados para futuras guerras, necesitamos m\225s[ENTER]mercenarios y una fuerte econom\237a. Esto requiere[ENTER]una gran cantidad de trabajo duro. Y eso te[ENTER]incluye tambi\233n a ti. "
gameforge.main_quest_lv15._60_say = "Voy a darte una nueva tarea. Ll\233vale esta[ENTER]especialidad a Yu-Hwan en la aldea vecina.[ENTER]Nuestro reino es un reino de comercio y estamos[ENTER]comerciando con los art\237culos de varias regiones.[ENTER]Ayudar\225s enormemente a la aldea si le entregas[ENTER]esto a Yu-Hwan. "
gameforge.main_quest_lv15._70_say = "Chunjo: nuestro reino est\225 controlado por el[ENTER]gobernador Yoon Young. Nuestra naci\243n est\225 basada[ENTER]en nuestra religi\243n.[ENTER]Por esto, sab\237amos mejor que nadie de la[ENTER]existencia del Sung Mahi. Nuestros chamanes nos[ENTER]prepararon para la llegada de las piedras Metin.[ENTER]Hoy, nuestros mejores chamanes est\225n trabajando[ENTER]duro por la seguridad de la naci\243n. Los chamanes[ENTER]son muy sabios. Esto es por sus poderes m\237sticos,[ENTER]que son la base de su poder. Sin ellos, ser\237a[ENTER]solo cuesti\243n de tiempo que otro pa\237s nos[ENTER]invadiera y nos derrotase. "
gameforge.main_quest_lv15._80_say = "La gente de nuestro pa\237s tiene una fe muy fuerte[ENTER]y rezan todos los d\237as al Dios Drag\243n. El[ENTER]benevolente Dios Drag\243n nos est\225 protegiendo de[ENTER]la resurrecci\243n de Sung Mahi. Debemos seguir[ENTER]defendi\233ndonos de los ataques b\225rbaros y[ENTER]reunificar el imperio bajo nuestro control. "
gameforge.main_quest_lv15._90_say = "Voy a darte una nueva tarea. Entrega esta estatua[ENTER]de piedra del Dios Drag\243n a Yu-Hwan en la aldea[ENTER]vecina. La religi\243n y nuestra profunda fe en el[ENTER]Dios Drag\243n son muy importantes para nuestro[ENTER]reino. Si le entregas esto a Yu-Hwan, har\225s un[ENTER]gran favor a los aldeanos. "
