gameforge.main_quest_lv2._200_sendLetter = "Tarea del ejercicio completada. "
gameforge.main_quest_lv2._20_say = "Guardi\225n de la Ciudad:[ENTER]Tu inter\233s es admirable pero deber\237as reunir m\225s[ENTER]puntos de experiencia. \161Vuelve una vez hayas[ENTER]alcanzado un nivel superior! "
gameforge.main_quest_lv2._210_say = "\161Eres mejor de lo que me pensaba! Pero cualquiera[ENTER]puede hacer eso. \161Ja ja! En mis tiempos, las[ENTER]tareas eran mucho m\225s dif\237ciles. Prep\225rate para[ENTER]la siguiente.[ENTER]Has ganado algunas pociones y Yang. Te sugiero[ENTER]que te compres algo de equipo. Te ayudar\225 a[ENTER]sobrevivir en el campo. \161Ahora vete! Te llamar\233[ENTER]cuando tenga nuevas tareas para ti. "
