gameforge.main_quest_lv2._50_sayReward = "Has recibido esta carta porque has alcanzado un[ENTER]nivel nuevo. \161Felicidades! \161Ve con el guardi\225n de[ENTER]la ciudad, para que pueda darte tu primera misi\243n[ENTER]de entrenamiento! "
gameforge.main_quest_lv2._60_say = "A\250n te falta disciplina, \161pero al menos has[ENTER]demostrado que puedes llevar un arma! Pru\233bame[ENTER]que no solo tienes suerte. Deja la aldea y mata 9[ENTER]perros salvajes. Una vez hayas acabado, vuelve[ENTER]conmigo para la recompensa. "
gameforge.main_quest_lv2._70_say = "Los perros salvajes no son muy fuertes, as\237 que[ENTER]no deber\237a ser demasiado dif\237cil. Si no puedes[ENTER]con esta tarea, \161no sobrevivir\225s por mucho[ENTER]tiempo! \161\161Vete!! \161Cuanto antes empieces, antes[ENTER]acabar\225s! "
gameforge.main_quest_lv2._80_sayReward = "De vez en cuando, los Aldeanos te dan tareas que[ENTER]te dan puntos de experiencia y Yang. \161Merece la[ENTER]pena buscar gente que te d\233 tareas! "
gameforge.main_quest_lv2._90_sayReward = "Por eliminar a los Perros salvajes te esperan:[ENTER]Puntos de experiencia: 550[ENTER]Yang: 1000[ENTER]Objeto: %s; Cantidad: %s "
