gameforge.main_quest_lv27 = {}
gameforge.main_quest_lv27._100_makequestbutton = "La Piedra Metin ha sido destruida "
gameforge.main_quest_lv27._105_say = "Has logrado destruir un Metin Negro. Ve adonde[ENTER]est\225 el Capit\225n e inf\243rmale sobre tu logro. "
gameforge.main_quest_lv27._10_makequestbutton = "Destruye las Piedras Metin "
gameforge.main_quest_lv27._110_say = "\191Has destruido la piedra Metin? \161Gracias![ENTER]\161La aldea est\225 a savlo! \191De d\243nde vienen las[ENTER]Piedras? Casi no hay informaci\243n sobre ellas.[ENTER]Aunque causan tantos problemas... he oido que[ENTER]Uriel el erudito est\225 investigando las piedras[ENTER]Metin, pero no se que ha descubierto hasta ahora.[ENTER]Has hecho un gran trabajo. "
gameforge.main_quest_lv27._120_sayTitle = "Recompensa: "
gameforge.main_quest_lv27._130_sayReward = "Has recibido 3.300.000 puntos de experiencia.[ENTER]Has recibido 270.000 Yang.[ENTER]Has recibido un Libro Maestro. "
gameforge.main_quest_lv27._140_sayReward = "Recibes %s. "
gameforge.main_quest_lv27._20_say = "La destrucci\243n causada por las Piedras Metin est\225[ENTER]yendo a peor. El pa\237s est\225 sufriendo. \161Las[ENTER]Piedras Metin deben ser destruidas! Ve con el[ENTER]Capit\225n. "
gameforge.main_quest_lv27._30_say = "La destrucci\243n causada por las Piedras Metin est\225[ENTER]yendo a peor. El pa\237s est\225 sufriendo. \161Las[ENTER]Piedras Metin deben ser destruidas! Ve con el[ENTER]Capit\225n. "
gameforge.main_quest_lv27._40_say = "He oido que has trabajado muy duro. La gente[ENTER]habla de tu buen trabajo. Gracias a m\237, \161hemos[ENTER]encontrado el lugar adecuado para ti! \161No te[ENTER]enfades! \161Solo bromeaba! Jajaja. Se que tienes[ENTER]mucho talento.[ENTER][ENTER]Las piedras Metin se est\225n propagando. Eso denota[ENTER]un gran problema. "
gameforge.main_quest_lv27._50_say = "Si el n\250mero de Piedras Metin aumenta, la gente[ENTER]sufre. A veces me pregunto si los Chamanes tienen[ENTER]raz\243n y el malvado Dios Sung Mahi ha resucitado[ENTER]de verdad... Pero primero tenemos que ocuparnos[ENTER]de lo obvio. \161Hazme saber cuando hayas destruido[ENTER]una Piedra Metin! "
gameforge.main_quest_lv27._60_sayTitle = "Tarea: "
gameforge.main_quest_lv27._70_say = "El tipo de piedra Metin que tienes que destruir[ENTER]es llamado Metin Negro. \161Encu\233ntralo! "
gameforge.main_quest_lv27._80_say = "Recientemente se han avistado m\225s y m\225s descensos[ENTER]de Piedras Metin. \161La radiaci\243n malvada tiene que[ENTER]ser detenida! Destruye un Metin Negro. "
gameforge.main_quest_lv27._90_say = "Has destruido el Metin Negro. Vuelve con el[ENTER]Capit\225n. "
gameforge.main_quest_lv3 = {}
gameforge.main_quest_lv3._100_say = "Hola. T\250 debes ser la ayuda que prometi\243 el[ENTER]guardi\225n de la ciudad. Tengo una tarea f\225cil para[ENTER]t\237. Mi padre olvid\243 un libro importante esta[ENTER]ma\241ana. Le hace realmente mucha falta. "
gameforge.main_quest_lv3._10_npcChat = "He completado la primera tarea. "
gameforge.main_quest_lv3._110_say = "\191Podr\237as llevarle este libro a mi padre? Lo har\237a[ENTER]yo misma, pero no puedo dejar desatendida la[ENTER]tienda. Si completas esta tarea por m\237, te[ENTER]recompensar\233 adecuadamente. Mi padre vende[ENTER]armaduras en esta aldea. "
gameforge.main_quest_lv3._120_sayItem = "T\233cnicas de manufactura de armaduras "
gameforge.main_quest_lv3._130_targetVid = "Encuentra al vendedor de la tienda de armaduras "
gameforge.main_quest_lv3._140_sendLetter = "Entrega el libro "
gameforge.main_quest_lv3._150_sayReward = "Entrega el libro del padre de la vendedora del[ENTER]almac\233n general. \201l es el vendedor de la tienda[ENTER]de armaduras de la aldea. "
gameforge.main_quest_lv3._160_sayTitle = "Vendedor de la tienda de armaduras: "
gameforge.main_quest_lv3._170_say = "\161\161Pareces un hombre en una misi\243n!! \161Ah, mi hija[ENTER]te env\237a! Gracias. Necesito este libro para[ENTER]producir una nueva serie de armaduras. "
gameforge.main_quest_lv3._180_say = "Mi hija debe estar muy muy ocupada si te manda a[ENTER]darme el libro. Veamos, \191cual ser\237a una[ENTER]recompensa apropiada? "
gameforge.main_quest_lv3._190_say = "Como recompensa, voy a darte algo de Yang, as\237[ENTER]podr\225s comprarte algo de equipo adecuado. Eso[ENTER]deber\237a ser suficiente, \191no? Gracias. Cuando[ENTER]vuelva a necesitar ayuda probablemente te pida[ENTER]otro favor. Y cuando necesites una armadura[ENTER]nueva, ven a verme. Mi tienda siempre est\225[ENTER]abierta. "
gameforge.main_quest_lv3._200_sayReward = "Recibes 850 puntos de experiencia.[ENTER]Recibes 5000 Yang.[ENTER]Recibes 20 Pociones azules. "
gameforge.main_quest_lv3._20_say = "Supongo que la primera tarea fue divertida.[ENTER]\161Rel\225jate! No tienes que suplicar por tu[ENTER]siguiente tarea. Vuelve una vez hayas ganado m\225s[ENTER]experiencia y te dar\233 tu siguiente tarea. "
gameforge.main_quest_lv3._30_sendLetter = "Novedades del guardi\225n de la ciudad "
gameforge.main_quest_lv3._40_sayReward = "Deja de cazar y ve con el guardi\225n de la ciudad.[ENTER]Tiene m\225s tareas para ti. "
gameforge.main_quest_lv3._50_say = "Me alegro de que hayas venido. Probablemente[ENTER]sabes donde est\225 situado el almac\233n general. El[ENTER]encargado de la tienda ha solicitado ayuda.[ENTER]\191Puedes ir a ayudarle? Estoy seguro que no es[ENTER]nada serio. Cualquier cosa que pida estar\225 bien[ENTER]para tus habilidades. "
gameforge.main_quest_lv3._60_say = "Para tu informaci\243n: La Tienda General vende[ENTER]pociones regenerativas y otros objetos que pueden[ENTER]ser \250tiles en el futuro. \161As\237 que no te vendr\225[ENTER]mal llevarte bien con ella! Ahora ve. "
gameforge.main_quest_lv3._70_targetVid = "Encuentra el almac\233n general "
gameforge.main_quest_lv3._80_sendLetter = "Ayuda a la vendedora del almac\233n general "
gameforge.main_quest_lv3._90_sayReward = "Ve al almac\233n general; la vendedora necesita tu[ENTER]ayuda. "
gameforge.main_quest_lv30 = {}
gameforge.main_quest_lv30._100_say = "Hay inscripciones en el Monumento de Piedra.[ENTER]Haces una copia r\225pidamente. "
gameforge.main_quest_lv30._10_targetVid = "Encuentra a Uriel "
gameforge.main_quest_lv30._110_say = "Uriel tiene raz\243n: verdaderamente hab\237a una[ENTER]inscripci\243n en el Monumento de Piedra. No pudiste[ENTER]leerlo pero al menos hiciste una copia. Lleva tus[ENTER]notas a Uriel. "
gameforge.main_quest_lv30._120_say = "\191Encontraste el Monumento de Piedra Hasun? Oh,[ENTER]incluso tienes una copia. \161Muy bien! \161Es un[ENTER]descubrimiento hist\243rico \250nico! Veamos.[ENTER]Hmm... Parece informaci\243n sobre las Piedras[ENTER]Metin. Sin embargo, no puedo descifrarlo entero.[ENTER]Esta escritura es realmente antigua, algunas de[ENTER]las letras casi parecen arcaicas. \191Qu\233 vamos a[ENTER]hacer ahora? "
gameforge.main_quest_lv30._130_say = "Ah, \161tengo una idea! \191Conoces el Valle de[ENTER]Seungryong? Hay un antiguo lugar misterioso all\237.[ENTER]Si encuentras inscripciones antiguas all\237 puede[ENTER]que sea capaz de sacar conclusiones sobre las[ENTER]letras que faltan. Ve al Valle de Seungryong y[ENTER]busca el Monumento de Piedra Rong Seul. "
gameforge.main_quest_lv30._140_targetVid = "Monumento de Piedra en el Valle de Seungryong "
gameforge.main_quest_lv30._150_say = "Uriel el erudito necesita m\225s textos antiguos[ENTER]para sacar conclusiones sobre algunas de las[ENTER]letras que no conoce.[ENTER]Ve al Valle de Seungryong y busca las[ENTER]inscripciones en el Monumento de Piedra Rong[ENTER]Seul. "
gameforge.main_quest_lv30._160_say = "\191Has encontrado m\225s inscripciones? \161Oh! Gracias a[ENTER]ti, podr\233 averiguar pronto el secreto de las[ENTER]Piedras Metin. Mis investigaciones pueden[ENTER]producir resultados m\225s r\225pidamente de lo que[ENTER]pens\233. \161Gracias, gracias! Te har\233 saber cuando[ENTER]necesite tu ayuda otra vez. Y, por favor, coge[ENTER]esta recompensa por tus esfuerzos. "
gameforge.main_quest_lv30._20_sendLetter = "El secreto de las Piedras Metin "
gameforge.main_quest_lv30._30_say = "Finalmente Uriel ha logrado conseguir m\225s[ENTER]informaci\243n sobre el secreto de las Piedras[ENTER]Metin. Ve y encuentra a Uriel el erudito. "
gameforge.main_quest_lv30._40_sayTitle = "Uriel: "
gameforge.main_quest_lv30._50_say = "El Capit\225n ya te envi\243 conmigo una vez. Parece[ENTER]que tienes mucho talento. Tengo que pedirte un[ENTER]favor. Est\225s al tanto de las piedras Metin, ya[ENTER]que ya has destruido algunas. Las piedras Metin[ENTER]vinieron de los ielos. Poseen energ\237a malvada,[ENTER]difunden plagas y los animales se vuelven[ENTER]salvajes. No sabemos como llegaron a nuestro[ENTER]mundo o lo que contienen. Eso dificulta mi[ENTER]investigaci\243n. Recientemente, he encontrado la[ENTER]clave de los secretos de las piedras Metin. "
gameforge.main_quest_lv30._60_say = "Hay una tabla, un monumento de un reino antiguo,[ENTER]en una cueva en la mazmorra de monos f\225cil. Creo[ENTER]que la informaci\243n en la tabla es acerca de el[ENTER]secreto de las piedras Metin. Si me traes la[ENTER]informaci\243n, puede que sea capaz de descubrir el[ENTER]secreto de las piedras Metin. Por favor, \161tr\225eme[ENTER]la informaci\243n del monumento de piedra Hasun en[ENTER]la Mazmorra de Monos F\225cil! "
gameforge.main_quest_lv30._70_sayReward = "Has recibido 120.000 puntos de experiencia.[ENTER]Has recibido 20.000 Yang.[ENTER]Has recibido un Brazalete de Plata. "
gameforge.main_quest_lv30._80_targetVid = "Monumento de Piedra en la Mazmorra de Monos F\225cil "
gameforge.main_quest_lv30._90_say = "Uriel el erudito cree que ha encontrado una pista[ENTER]que puede ayudarle a resolver el problema de las[ENTER]Piedras Metin.[ENTER]Ve a la Mazmorra de Monos F\225cil y busca el[ENTER]Monumento de Piedra Hasun. "
gameforge.main_quest_lv32 = {}
