gameforge.main_quest_lv32._10_sendLetter = "El libro secreto "
gameforge.main_quest_lv32._110_npcChat = "Las p\225ginas del libro secreto "
gameforge.main_quest_lv32._120_sayTitle = "Peddler: "
gameforge.main_quest_lv32._130_say = "Desde que el mundo entero se ha vuelto[ENTER]turbulento, el comercio se ha vuelto m\225s dif\237cil.[ENTER]\191Qu\233 quieres comprar? Ah, \191Uriel el erudito te[ENTER]env\237a? Es un cliente habitual.[ENTER]Est\225 buscando las p\225ginas antiguas en diferentes[ENTER]lugares. Lo encuentro bastante divertido. Ja Ja[ENTER]Ja. \191Quieres saber algo sobre los libros[ENTER]antiguos? Hmmm. Sobre los libros antiguos... "
gameforge.main_quest_lv32._140_say = "Escuch\233 algo hace unos d\237as, \161pero no puedo[ENTER]decirlo gratis! Si rascas mi espalda, yo rascar\233[ENTER]la tuya, \191eh? El comercio de armas est\225 yendo muy[ENTER]bien estos d\237as, \161pero por desgracia no puedo[ENTER]suministrar cantidades tan enormes! \161He estado[ENTER]desbordado de pedidos! Como t\250 simplemente est\225s[ENTER]dando vueltas por ah\237 sin hacer nada, \191por qu\233 no[ENTER]haces algo \250til para variar y consigues 20[ENTER]Espadas de Plata+0 para m\237? Tan pronto como me[ENTER]las traigas, te dar\233 la informaci\243n que[ENTER]necesitas. "
gameforge.main_quest_lv32._150_targetVid = "Encuentra a Peddler "
gameforge.main_quest_lv32._160_sayTitle = "Tienes 20 espadas de plata +0 "
gameforge.main_quest_lv32._170_say = "Peddler ha oido sobre las p\225ginas antiguas. Dale[ENTER]20 Espadas de Plata +0, entonces te dir\225 lo que[ENTER]sabe. "
gameforge.main_quest_lv32._180_sayTitle = "Consigue 20 espadas de plata +0 "
gameforge.main_quest_lv32._190_say = "Peddler ha oido sobre las p\225ginas antiguas, pero[ENTER]no quiso compartir la informaci\243n gratis.[ENTER]Consigue 20 Espadas de Plata +0 y ll\233vaselas a[ENTER]Peddler a cambio de la informaci\243n. "
gameforge.main_quest_lv32._200_npcChat = "Tengo las espadas "
gameforge.main_quest_lv32._20_targetVid = "Busca a Uriel el erudito "
gameforge.main_quest_lv32._210_say = "Bien. Tienes m\225s talento de lo que pens\233.[ENTER]Gracias a tu ayuda, los negocios van a ir mucho[ENTER]mejor pronto. Por lo que respecta a tu p\225gina...[ENTER]Hace unos d\237as estaba transitando por un pabell\243n[ENTER]y un monumento junto a \233l. Descans\233 all\237 y[ENTER]observ\233 un trozo de papel roto en el pie del[ENTER]Monumento. "
gameforge.main_quest_lv32._220_say = "En ese momento no pens\233 en \233l. Pero ahora creo[ENTER]que puede haber sido una de las p\225ginas antiguas[ENTER]que est\225s buscando. El nombre del monumento,[ENTER]hmmm... \191Era el Monumento Weol? S\237, as\237 se llama.[ENTER]El Momumento Weol cerca de la Aldea Vecina.[ENTER]\161Deber\237as mirar all\237! "
gameforge.main_quest_lv32._230_sayTitle = "Peddler: "
gameforge.main_quest_lv32._240_say = "Tr\225eme 20 espadas de plata +0 y te dar\233 la[ENTER]informaci\243n sobre la p\225gina antigua... "
gameforge.main_quest_lv32._250_sendLetter = "Buscando la primera p\225gina "
gameforge.main_quest_lv32._260_targetVid = "Un monumento cerca del pabell\243n "
gameforge.main_quest_lv32._270_say = "Peddler vi\243 una p\225gina antigua en el pie del[ENTER]Monumento Weol cuando descans\243 en el pabell\243n[ENTER]cerca del monumento.[ENTER]Ve al Monumento Weol cerca de la Primera Aldea y[ENTER]mira si realmente es la p\225gina que est\225s[ENTER]buscando. "
gameforge.main_quest_lv32._280_npcChat = "El monumento Weol "
gameforge.main_quest_lv32._290_say = "Este es el monumento. \161AJA! \161Aqu\237 est\225! \161Tengo la[ENTER]p\225gina! "
gameforge.main_quest_lv32._300_sendLetter = "La primera p\225gina "
gameforge.main_quest_lv32._30_say = "Uriel el erudito te busca. Necesita ayuda con su[ENTER]investigaci\243n de un libro antiguo y secreto. Ve[ENTER]con Uriel y averigua que puedes hacer por \233l. "
gameforge.main_quest_lv32._310_targetVid = "Busca a Uriel el erudito "
gameforge.main_quest_lv32._320_sayTitle = "Has encontrado la primera p\225gina. "
gameforge.main_quest_lv32._330_say = "Has estado siguiendo las pistas de Peddler y has[ENTER]encontrado la primera de las p\225ginas perdidas.[ENTER]Ll\233vasela a Uriel el erudito. "
gameforge.main_quest_lv32._340_say = "\191As\237 que encontraste la primera p\225gina antigua?[ENTER]Oh, la tienes, \161genial! Veamos lo que est\225[ENTER]escrito en ella.[ENTER]Hm... Parece un diario. Escucha "
gameforge.main_quest_lv32._350_sayTitle = "La primera p\225gina del libro: "
gameforge.main_quest_lv32._360_sayReward = "Lee Seop del reino Taejo est\225 conquistando y[ENTER]ampliando su territorio. Quiere conquistar todos[ENTER]los territorios usando sus fuerzas militares.[ENTER]Tenemos que asegurarnos que no toma nuestro pa\237s.[ENTER]Nuestras opciones son limitadas ya que su armada[ENTER]es muy grande y muy fuerte.[ENTER]\161Por eso hemos decidido usar la brujer\237a[ENTER]prohibida! "
gameforge.main_quest_lv32._370_sayTitle = "La primera p\225gina del libro continua: "
gameforge.main_quest_lv32._380_sayReward = "Es nuestra \250nica oportunidad de sobrevivir. No[ENTER]sabemos si tendr\225 \233xito, pero definitivamente[ENTER]debemos intentarlo. Antes de que nos ataquen,[ENTER]tenemos que conseguir la informaci\243n sobre la[ENTER]brujer\237a oscura secreta.[ENTER]De acuerdo con la leyenda, deber\237amos ser capaces[ENTER]de informarnos en el Valle del Drag\243n. "
gameforge.main_quest_lv32._390_say = "De los contenidos veo que existieron creencias[ENTER]antiguas en este pa\237s. Antes de que Lee Seop del[ENTER]reino Taejo unificara todos los paises, cada pa\237s[ENTER]ten\237a sus propias caracter\237sticas especiales.[ENTER]Hasta donde yo se, cada pa\237s ten\237a sus propias[ENTER]creencias religiosas. El autor de este libro,[ENTER]parece haber sido educado bastante bien.[ENTER]Probablemente perteneci\243 a uno de los gremios o[ENTER]incluso pudo ser su capit\225n. Los miembros de[ENTER]gremio eran considerados la \233lite de la sociedad. "
gameforge.main_quest_lv32._400_say = "Se ha hablado mucho sobre las antiguas historias[ENTER]del Valle del Drag\243n. Tambi\233n conozco algunos[ENTER]cuentos sobre \233l. Quiz\225 a\250n seamos capaces de[ENTER]encontrar informaci\243n sobre \233l o averiguar m\225s[ENTER]sobre las p\225ginas del libro. Por desgracia, nunca[ENTER]he encontrado informaci\243n sobre d\243nde se[ENTER]encuentra el valle. Ve con el cazador Yang-Shin[ENTER]en la aldea vecina, conoce muy bien los caminos.[ENTER]Puede que sepa d\243nde se encuentra el Valle del[ENTER]Drag\243n y si hay algo \250til que podamos encontrar[ENTER]ah\237. "
gameforge.main_quest_lv32._40_say = "Saludos.[ENTER]Tu trabajo la \250ltima vez fue de mucha ayuda. Con[ENTER]tu ayuda, fu\237 capaz de hacer verdaderos[ENTER]progresos. Pero ahora tengo un problema. Cuando[ENTER]investigaba la informaci\243n sobre los meteoritos,[ENTER]encontr\233 un libro antiguo.[ENTER]Por lo que puedo entender, hay especulaciones[ENTER]importantes sobre la causa de los cambios que[ENTER]est\225n afectando a nuestro pa\237s. Es muy[ENTER]importante. "
gameforge.main_quest_lv32._410_say = "\161Qu\233 emocionante! Oh, antes de que se me olvide:[ENTER]\161Aqu\237 est\225 tu recompensa por tu primera p\225gina! "
gameforge.main_quest_lv32._420_sayReward = "Recibes 1.000.000 puntos de experiencia. "
gameforge.main_quest_lv32._430_sayReward = "Obtienes 50.000 Yang. "
gameforge.main_quest_lv32._440_sayReward = "Has recibido una L\225grima de Diosa. "
gameforge.main_quest_lv32._450_sendLetter = "Ve con el cazador "
gameforge.main_quest_lv32._460_targetVid = "Encuentra al cazador Yang-Shin "
gameforge.main_quest_lv32._470_sayTitle = "Pregunta a Yang-Shin por el Valle de Drag\243n. "
gameforge.main_quest_lv32._480_say = "En la primera p\225gina del libro secreto se[ENTER]menciona el Valle del Drag\243n. Uriel ha escuchado[ENTER]historias sobre \233l pero no sabe d\243nde est\225. Ve a[ENTER]la Aldea Vecina y pregunta al cazador Yang-Shin[ENTER]si sabe algo m\225s. "
gameforge.main_quest_lv32._490_sayReward = "Pista: El cazador est\225 en la Aldea Vecina. "
gameforge.main_quest_lv32._500_npcChat = "Informaci\243n sobre el Valle del Drag\243n "
gameforge.main_quest_lv32._50_say = "El problema es que el libro es muy viejo y est\225[ENTER]rasgado. El libro ha pasado de mano en mano[ENTER]durante a\241os, raz\243n por la que probablemente est\233[ENTER]tan da\241ado. Se han perdido 13 p\225ginas de este[ENTER]libro. \191Podr\237as hacerte cargo de esto por m\237?[ENTER]Probablemente haya alguna informaci\243n importante[ENTER]sobre c\243mo terminar con la guerra en esas[ENTER]p\225ginas. "
gameforge.main_quest_lv32._510_sayTitle = "Yang-Shin: "
gameforge.main_quest_lv32._520_say = "\191Quieres saber d\243nde est\225 el Valle del Drag\243n?[ENTER]Ese es el nombre que se daba hace mucho al Valle[ENTER]de Seungryong. No hay dragones all\237, pero en[ENTER]cambio hay una gran cantidad de orcos e incluso[ENTER]una secta secreta viviendo ah\237. \191Por qu\233 quieres[ENTER]ir a un lugar tan peligroso? Incluso a m\237, un[ENTER]cazador experto, no me gusta ir all\237. Ser\237a mejor[ENTER]que te mantuvieras alejado de ah\237. "
gameforge.main_quest_lv32._530_say = "\191Qu\233? \191Est\225s buscando las p\225ginas antiguas? \161Hm![ENTER]Una vez escuch\233 de los cazadores que los[ENTER]Hechiceros Orco tienen algunos papeles. Me[ENTER]pregunto si ser\225 verdad.[ENTER]Si tienes tanta curiosidad, entonces ve y[ENTER]aver\237gualo. Ya he dicho que es un lugar[ENTER]peligroso. \161Cu\237date mucho! "
gameforge.main_quest_lv32._540_sendLetter = "Buscando la segunda p\225gina "
gameforge.main_quest_lv32._550_say = "Como ya ha mencionado el cazador, debes encontrar[ENTER]a los Hechiceros Oroc \201lite en el Valle del[ENTER]Drag\243n. Ellos deben tener la segunda p\225gina[ENTER]antigua. Mata a los Hechiceros Orco \201lite y coge[ENTER]la segunda p\225gina. Una vez que tengas la p\225gina,[ENTER]entr\233gasela a Uriel. "
gameforge.main_quest_lv32._560_sendLetter = "La segunda p\225gina "
gameforge.main_quest_lv32._570_sayTitle = "Encontrada la segunda p\225gina "
gameforge.main_quest_lv32._580_say = "Cazar al Hechicero Orco \201lite ha tenido \233xito:[ENTER]has encontrado la segunda p\225gina del Libro[ENTER]Secreto. Ll\233vasela a Uriel el erudito. "
gameforge.main_quest_lv32._590_say = "\191Esta es la segunda p\225gina? D\233jame ver. No es[ENTER]f\225cil descifrarla. Dice: "
gameforge.main_quest_lv32._600_sayTitle = "Segunda p\225gina: "
gameforge.main_quest_lv32._60_say = "Una vez encuentres una de las p\225ginas antiguas,[ENTER]tr\225emelas. Entonces intentar\233 descifrarla.[ENTER]Hmmmm... \191D\243nde debes empezar a buscar? Hace un[ENTER]tiempo, escuch\233 sobre un peddler en la aldea[ENTER]vecina. \201l hab\237a encontrado una p\225gina antigua[ENTER]del libro. Ve con \233l y mira si puedes averiguar[ENTER]algo. "
gameforge.main_quest_lv32._610_sayReward = "Se ha encontrado a los seguidores de la magia[ENTER]oscura. Estaban escondidos en el Valle del[ENTER]Drag\243n. Est\225n muy informados sobre la brujer\237a[ENTER]que ha pasado de generaci\243n en generaci\243n. Cost\243[ENTER]mucho persuadir, algunos tratos y algunos halagos[ENTER]hasta que accedieron a ayudarnos. Y el resultado[ENTER]fue: Necesitas un lugar especial para ejecutar la[ENTER]brujer\237a prohibida. El lugar tiene que estar[ENTER]lleno de energ\237a demon\237aca. El tiempo se acaba,[ENTER]as\237 que tengo que encontrar un lugar adecuado[ENTER]cuanto antes. "
gameforge.main_quest_lv32._620_say = "Hm, necesitamos un lugar lleno de energ\237a[ENTER]negativa para la brujer\237a oscura. Un lugar en el[ENTER]que todo puede ser convertido a energ\237a[ENTER]demon\237aca. Hmm... \191D\243nde podemos encontrar un[ENTER]lugar como ese? Hm... Hm... Lo s\233, \161puede ser el[ENTER]Templo Hwang! La gente no lo llama el templo de[ENTER]la oscuridad por nada. Es un lugar al que nadie[ENTER]de buen coraz\243n quiere ir. Incluso los animales[ENTER]no quieren ir all\237. Y la secta secreta no tiene[ENTER]buenas intenciones. "
gameforge.main_quest_lv32._630_say = "Adem\225s, hay una conexi\243n entre la brujer\237a[ENTER]prohibida y esta secta secreta. Puedes encontrar[ENTER]la clave para eso en el Templo Hwang. \161Descubre[ENTER]qu\233 est\225 pasando en el Templo Hwang y mira si[ENTER]puedes encontrar m\225s p\225ginas del libro ah\237![ENTER]Aqu\237 est\225 tu recompensa por la segunda p\225gina... "
gameforge.main_quest_lv32._640_sayReward = "Recibes 1.000.000 puntos de experiencia. "
gameforge.main_quest_lv32._650_sayReward = "Obtienes 50.000 Yang. "
gameforge.main_quest_lv32._660_sayReward = "Has obtenido 10 banderas blancas "
gameforge.main_quest_lv32._670_sendLetter = "La tercera p\225gina "
gameforge.main_quest_lv32._680_say = "Has llevado las dos primeras p\225ginas del Libro[ENTER]Secreto a Uriel. La siguiente p\225gina puede ser[ENTER]encontrada en el Templo Hwang. "
gameforge.main_quest_lv32._690_sayReward = "Pista: Esta serie de misiones continuar\225 cuando[ENTER]hayas alcanzado el nivel 40. "
gameforge.main_quest_lv32._70_targetVid = "Visita a Peddler "
gameforge.main_quest_lv32._80_sayTitle = "Busca las p\225ginas del libro secreto. "
gameforge.main_quest_lv32._90_say = "Uriel el erudito dijo que hab\237a escuchado algo[ENTER]sobre un peddler con una p\225gina antigua. Ve con[ENTER]Peddler y preg\250ntale sobre ella.[ENTER]Le encontrar\225s en la segunda aldea. "
gameforge.main_quest_lv40 = {}
gameforge.main_quest_lv40._100_sayReward = "Has recibido 2.000.000 puntos de experiencia. "
gameforge.main_quest_lv40._10_sayTitle = "El Templo de la oscuridad "
gameforge.main_quest_lv40._110_sayReward = "Obtienes 50.000 Yang. "
gameforge.main_quest_lv40._120_sayReward = "Obtienes tambi\233n una Bendici\243n de la Vida. "
gameforge.main_quest_lv40._130_sendLetter = "Dentro del desierto de Yongbi "
gameforge.main_quest_lv40._140_targetVid = "La b\250squeda del monumento "
gameforge.main_quest_lv40._150_targetVid = "La b\250squeda del monumento Wha "
gameforge.main_quest_lv40._160_sayTitle = "La b\250squeda de la cuarta p\225gina "
gameforge.main_quest_lv40._170_say = "Uriel el erudito cree que otra p\225gina puede ser[ENTER]encontrada en la mazmorra de los monos en el[ENTER]desierto Yongbi. Hay un monumento donde puede[ENTER]estar localizada la cuarta p\225gina.[ENTER]Ve al desierto Yongbi y busca el monumento en la[ENTER]mazmorra de los monos.[ENTER]Pista: el guardian en el desierto Yongbi puede[ENTER]ayudarte a llegar a las mazmorras de los monos. "
gameforge.main_quest_lv40._180_say = "\161\201se es el Monumento Wha! "
gameforge.main_quest_lv40._190_say = "Pero no se ve ninguna p\225gina de diario.[ENTER]Tengo que continuar y encontrar otro monumento. "
gameforge.main_quest_lv40._200_npcChat = "La b\250squeda del monumento Su "
gameforge.main_quest_lv40._20_say = "Uriel el erudito est\225 buscando las p\225ginas del[ENTER]diario antiguo.[ENTER]Ya le has llevado dos de ellas. Ahora la[ENTER]apasionante b\250squeda del secreto del libro[ENTER]antiguo continua.[ENTER]Los descubrimientos hasta ahora indican que los[ENTER]Fan\225ticos Oscuros Soberbios que viven en el[ENTER]Templo Hwang tienen la siguiente p\225gina.[ENTER]\161Sigue tu camino! "
gameforge.main_quest_lv40._210_say = "\161Este debe ser! El monumento Su. "
gameforge.main_quest_lv40._220_say = "Pero no se ve ninguna p\225gina de diario.[ENTER]Tengo que continuar y encontrar otro monumento. "
gameforge.main_quest_lv40._230_sendLetter = "La cuarta p\225gina "
gameforge.main_quest_lv40._240_sayTitle = "Encontrada la cuarta p\225gina "
gameforge.main_quest_lv40._250_say = "Los monumentos antiguos demuestran ser fieles[ENTER]guardianes de sus tesoros: has encontrado la[ENTER]cuarta p\225gina antigua en Jungsun Dong. Ll\233vasela[ENTER]a Uriel el erudito. "
gameforge.main_quest_lv40._260_npcChat = "La cuarta p\225gina antigua "
gameforge.main_quest_lv40._270_say = "\161Oh! Has encontrado la cuarta p\225gina antigua. Con[ENTER]suerte, sacaremos algo en claro con la nueva[ENTER]informaci\243n del libro. "
gameforge.main_quest_lv40._280_sayTitle = "Cuarta p\225gina: "
gameforge.main_quest_lv40._290_sayReward = "Ahora estoy en la cueva profunda donde viven los[ENTER]monos. Mis compa\241eros estan petrificados, pero la[ENTER]energ\237a maligna que hemos reunido aqu\237 todav\237a es[ENTER]insuficiente. El tiempo pasa demasiado r\225pido y[ENTER]la caballer\237a de Lee Seop se acerca m\225s y m\225s. Me[ENTER]pregunto si lo haremos a tiempo. "
gameforge.main_quest_lv40._300_sayTitle = "La cuarta p\225gina continua: "
gameforge.main_quest_lv40._30_sayTitle = "Encontrada la tercera p\225gina "
gameforge.main_quest_lv40._310_sayReward = "Tengo que encontrar la siguiente localizaci\243n lo[ENTER]antes posible. A\250n no hay nada perdido. Lo[ENTER]intentar\233 en las cuevas de las ara\241as. Esta vez,[ENTER]puede que nuestro deseo se haga realidad... "
gameforge.main_quest_lv40._320_say = "Hm. La mazmorra de los monos no es el lugar que[ENTER]estamos buscando. as\237 que, \161probemos de nuevo! De[ENTER]acuerdo con lo que dice aqu\237, tenemos que ir a la[ENTER]Cueva de la Ara\241a. Pero primero tenemos que[ENTER]atender un asunto m\225s urgente: El Capit\225n est\225[ENTER]muy preocupado porque muchos forasteros han[ENTER]estado dando vueltas cerca de la aldea y haciendo[ENTER]preguntas extra\241as. Deber\237as ir a verle y[ENTER]averiguar qu\233 est\225 pasando. "
gameforge.main_quest_lv40._330_say = "Toda esta situaci\243n me est\225 dejando inquieto.[ENTER]Veamos qu\233 dice el capit\225n. Oh, antes de que se[ENTER]me olvide: Aqu\237 est\225 tu recompensa por la cuarta[ENTER]p\225gina. "
gameforge.main_quest_lv40._340_sayReward = "Has recibido 2.000.000 puntos de experiencia. "
gameforge.main_quest_lv40._350_sayReward = "Tambi\233n obtienes una p\237ldora espiritual "
gameforge.main_quest_lv40._360_sendLetter = "Los forasteros escalofriantes "
gameforge.main_quest_lv40._370_targetVid = "Ve con el Capit\225n "
gameforge.main_quest_lv40._380_sayTitle = "Ent\233rate de algo sobre los extranjeros del[ENTER]Capit\225n. "
gameforge.main_quest_lv40._390_say = "Se dice que muchos forasteros han estado[ENTER]apareciendo en la aldea. Est\225n preguntando una[ENTER]sospechosa cantidad de preguntas sobre los[ENTER]Monumentos. El capit\225n quiere hacer algo con[ENTER]esto. Ve con \233l e inf\243rmate m\225s. "
gameforge.main_quest_lv40._400_npcChat = "Los extranjeros en la aldea "
gameforge.main_quest_lv40._40_say = "Las suposiciones de Uriel el erudito sobre los[ENTER]Fan\225ticos Oscuros Soberbios eran correctas. Has[ENTER]encontrado la tercera p\225gina del diario en su[ENTER]poder. Lleva la p\225gina a Uriel el erudito. "
gameforge.main_quest_lv40._410_say = "Ha habido un incremento en el n\250mero de[ENTER]extranjeros que vienen a nuestra aldea. Continuan[ENTER]preguntando sobre monumentos y libros antiguos.[ENTER]Algunos saben sobre eso, pero no quieren[ENTER]dec\237rselo a los extranjeros. Me temo que eso[ENTER]pueda meternos a todos en problemas. Nadie sabe[ENTER]qui\233n envi\243 a esos extranjeros y lo lejos que[ENTER]pueden llegar para conseguir su informaci\243n. A[ENTER]fin de cuentas, estamos en guerra. "
gameforge.main_quest_lv40._420_say = "Si mis fuentes son correctas, Nakajima de la[ENTER]aldea vecina tiene algo que ver con esto.[ENTER]Por favor, trata de averiguar algo sobre lo que[ENTER]quieren los forasteros pregunt\225ndole. "
gameforge.main_quest_lv40._430_sendLetter = "Ve con Nakajima "
gameforge.main_quest_lv40._440_say = "El Capit\225n cree que hay una conexi\243n entre[ENTER]Nakajima y los forasteros que est\225n preguntando[ENTER]por todas partes en la aldea sobre los[ENTER]monumentos. Ve con Nakajima y averigua lo que[ENTER]sabe. Le encontrar\225s en las afueras de la segunda[ENTER]aldea. "
gameforge.main_quest_lv40._450_npcChat = "\191Conoces a los extranjeros en la aldea? "
gameforge.main_quest_lv40._460_sayTitle = "Nakajima: "
gameforge.main_quest_lv40._470_say = "\191Perd\243n? \191Qu\233 tipo de pregunta es esa? Lo siento.[ENTER]No puedo ayudarte. No tengo ni la menor idea de[ENTER]lo que est\225s hablando. No, no. Ya es[ENTER]suficientemente dif\237cil encontrar trabajo ahora.[ENTER]De qu\233 se supone que voy a vivir, \191eh? "
gameforge.main_quest_lv40._480_say = "Oh, bien, lo admito. Pero s\243lo acced\237 porque me[ENTER]prometieron mucho Yang.[ENTER]No s\233 lo que quer\237an los extranjeros. Pero me han[ENTER]dado una misi\243n: tengo que matar a los Capitanes[ENTER]Bestiales. "
gameforge.main_quest_lv40._490_say = "Probablemente podr\237as averiguar m\225s de los[ENTER]Capitanes Bestiales. Los extranjeros realmente[ENTER]quer\237an que le matase. Oh, tengo una idea: \191por[ENTER]qu\233 no vas y lo matas por m\237? \191Por favor? "
gameforge.main_quest_lv40._500_sendLetter = "Mata a los Capitanes bestiales "
gameforge.main_quest_lv40._50_say = "Oh, \161\191Has encontrado la siguiente pista?! Esta es[ENTER]la tercera p\225gina. Veamos lo que dice. "
gameforge.main_quest_lv40._510_say = "Nakajima ha confesado que los extranjeros quieren[ENTER]matar a los Capitanes Bestiales. Como los[ENTER]extranjeros han estado preguntando sobre las[ENTER]P\225ginas del Diario, obviamente los Capitanes[ENTER]Bestiales tienen con ellos una p\225gina. Para[ENTER]averiguar m\225s, tengo que matar a los Capitanes[ENTER]Bestiales. Se les puede encontrar en las afueras[ENTER]de la segunda aldea. "
gameforge.main_quest_lv40._520_sendLetter = "Has encontrado la quinta p\225gina "
gameforge.main_quest_lv40._530_say = "Llegu\233 all\237 antes que los extranjeros y cog\237 la[ENTER]quinta p\225gina del diario de los Capitanes[ENTER]Bestiales. Estoy seguro de que los extranjeros[ENTER]desaparecer\225n ahora que no les queda nada que[ENTER]encontrar aqu\237. Le llevar\233 la p\225gina a Uriel el[ENTER]erudito para que la pueda descifrar. "
gameforge.main_quest_lv40._540_sayTitle = "La quinta p\225gina "
gameforge.main_quest_lv40._550_sayReward = "Pista: s\243lo puedes llevare la quinta p\225gina a[ENTER]Uriel una vez hayas alcanzado el nivel 47. Guarda[ENTER]la p\225gina hasta entonces. "
gameforge.main_quest_lv40._60_sayTitle = "Tercera p\225gina: "
gameforge.main_quest_lv40._70_sayReward = "Hemos llegado al lugar donde se convierte la[ENTER]energ\237a malvada. Pero no es suficiente... \191D\243nde[ENTER]puedes ejecutar esta brujer\237a? La nueva[ENTER]informaci\243n sugiere que hay un lugar oculto en el[ENTER]desierto Yongbi. Llenos de esperanza, vamos a[ENTER]teletransportarnos al desierto Yongbi. "
gameforge.main_quest_lv40._80_say = "As\237 que no fueron capaces de cumplir su objetivo[ENTER]en el Valle del Drag\243n. Hm... \191El desierto[ENTER]Yongbi? No sueles encontrarte a nadie por all\237 y[ENTER]el \225rea est\225 en gran parte inexplorada. Pero todo[ENTER]esto es muy complicado. \191D\243nde est\225 exactamente[ENTER]el \225rea del que hablan? Supongo que se refieren a[ENTER]la Mazmorra de los Monos Junsun Dong. Es una[ENTER]cueva profunda muy bien equipada para acumular[ENTER]energ\237a malvada. "
gameforge.main_quest_lv40._90_say = "Por favor ve a Jungsun Dong y busca m\225s[ENTER]monumentos de piedra. Con un poco de suerte[ENTER]puedes encontrar m\225s p\225ginas cerca de los[ENTER]monumentos. Oh, y por supuesto no olvidaremos tu[ENTER]recompensa por la tercera p\225gina. "
gameforge.main_quest_lv47 = {}
gameforge.main_quest_lv47._100_sayTitle = "La p\225gina en la mazmorra de la ara\241a "
gameforge.main_quest_lv47._10_sayTitle = "La p\225gina de los capitanes bestiales "
gameforge.main_quest_lv47._110_say = "Uriel piensa que puede ser encontrada informaci\243n[ENTER]adicional sobre la magia secreta en la mazmorra[ENTER]de la ara\241a. Quiz\225 tambi\233n encontremos un[ENTER]monumento all\237 como el de la mazmorra de los[ENTER]monos.[ENTER]Puedes llegar a la mazmorra de la ara\241a a trav\233s[ENTER]del Desierto Yongbi. "
gameforge.main_quest_lv47._120_npcChat = "El monumento Mok "
gameforge.main_quest_lv47._130_say = "\161En efecto! Aqu\237 hay un monumento y tambi\233n una[ENTER]P\225gina de Diario.[ENTER]Vuelve r\225pidamente con Uriel. "
gameforge.main_quest_lv47._140_sayTitle = "Encontrada la sexta p\225gina "
gameforge.main_quest_lv47._150_say = "Has encontrado otro monumento antiguo en el[ENTER]Calabozo de las Ara\241as y tambi\233n la sexta p\225gina[ENTER]del diario que estaba escondida aqu\237. Entr\233gasela[ENTER]a Uriel el erudito. "
gameforge.main_quest_lv47._160_npcChat = "La sexta p\225gina "
gameforge.main_quest_lv47._170_say = "\191C\243mo fue en la mazmorra de la ara\241a?[ENTER]\191Encontraste la sexta p\225gina? \161Eso es estupendo![ENTER]Estaba preocupado porque pudieses llegar[ENTER]demasiado tarde. Uno siempre escucha sobre otras[ENTER]personas que tambi\233n buscan los secretos de la[ENTER]brujer\237a negra. Parece ser una informaci\243n muy[ENTER]importante. Veamos lo que dice esta p\225gina. "
gameforge.main_quest_lv47._180_say = "Oh no, esta p\225gina es muy dif\237cil de leer. Voy a[ENTER]necesitar m\225s tiempo de lo normal para[ENTER]descifrarla. Pero el contenido parece muy[ENTER]importante. Este s\237mbolo significa 'Brujer\237a[ENTER]Negra', as\237 que definitivamente estamos en el[ENTER]camino correcto. Me gustar\237a saber por qu\233 la[ENTER]brujer\237a negra ha sido prohibida. Posiblemente[ENTER]haya una buena raz\243n para ello. "
gameforge.main_quest_lv47._190_say = "Mientras trato de descifrar esta p\225gina, deber\237as[ENTER]ir a ver al m\250sico Yu-Hwan. He oido que tiene[ENTER]alguna informaci\243n interesante para nuestra[ENTER]investigaci\243n. Cuando vuelvas, podr\233 contarte lo[ENTER]que dice esta p\225gina. Pero, por supuesto, tendr\225s[ENTER]ahora tu recompensa. "
gameforge.main_quest_lv47._200_sayReward = "Has recibido 3.000.000 puntos de experiencia. "
gameforge.main_quest_lv47._20_say = "A nivel 40, encontraste la quinta p\225gina del[ENTER]libro secreto cuando mataste al Capit\225n bestial.[ENTER]Deber\237as entregarsela a Uriel tan pronto como sea[ENTER]posible. "
gameforge.main_quest_lv47._210_sayReward = "Yang: 75.000 "
gameforge.main_quest_lv47._220_sayReward = "Has recibido una Bendici\243n del Drag\243n. "
gameforge.main_quest_lv47._230_sendLetter = "Ve con Yu-Hwan "
gameforge.main_quest_lv47._240_targetVid = "Encuentra al m\250sico Yu-Hwan "
gameforge.main_quest_lv47._250_sayTitle = "Las fuerzas secretas "
gameforge.main_quest_lv47._260_say = "El m\250sico Yu-Hwan puede que tenga alguna[ENTER]informaci\243n sobre las p\225ginas del diario[ENTER]antiguas. Ve a verle y preg\250ntale. "
gameforge.main_quest_lv47._270_npcChat = "\191Alguna novedad? "
gameforge.main_quest_lv47._280_say = "\161Disfruta la vida, porque es muy corta![ENTER]Trallalaaa... Ah, aqu\237 est\225s otra vez.[ENTER]Probablemente vienes de parte de Uriel el[ENTER]erudito. Me pidi\243 si pod\237a hacer unas preguntas.[ENTER]He averiguado que en todos los reinos la gente ha[ENTER]estado yendo de un sitio para otro buscando[ENTER]documentos importantes.[ENTER]Por desgracia, nadie pudo decirme exactamente de[ENTER]qu\233 se trata. "
gameforge.main_quest_lv47._290_say = "Es un poco raro que esas extra\241as figuras[ENTER]reptantes est\233n dando vueltas mientras estamos en[ENTER]mitad de una guerra. \161Exceptu\225ndote a ti, claro[ENTER]est\225! Tambi\233n escuch\233 que los Bandidos del[ENTER]Desierto pudieron saquear algunas cosas que[ENTER]podr\237an ser bastante importantes para nosotros.[ENTER]Quiz\225 deber\237as mirar qu\233 puedes conseguir de[ENTER]ellos. "
gameforge.main_quest_lv47._300_say = "Los Bandidos del Desierto son bestias peligrosas,[ENTER]as\237 que ten cuidado. Pero creo que valdr\225 la[ENTER]pena. Voy a dedicarte una canci\243n y encomendar al[ENTER]viento con ella, as\237 que te seguir\225 hacia el[ENTER]desierto. "
gameforge.main_quest_lv47._30_npcChat = "La quinta p\225gina "
gameforge.main_quest_lv47._310_sendLetter = "Los Bandidos del Desierto "
gameforge.main_quest_lv47._320_sayTitle = "La b\250squeda de la informaci\243n secreta "
gameforge.main_quest_lv47._330_say = "Uriel necesita algo de informaci\243n sobre la[ENTER]brujer\237a negra. Yu-Hwan, el m\250sico, dijo que los[ENTER]Bandidos del Desierto robaron algo que podr\237a[ENTER]ayudarnos. Debo irme ahora y matar un par de[ENTER]Bandidos del Desierto. "
gameforge.main_quest_lv47._340_sendLetter = "Encontrada la s\233ptima p\225gina "
gameforge.main_quest_lv47._350_targetVid = "Buscando al m\250sico Yu-Hwan. "
gameforge.main_quest_lv47._360_say = "Gracias a la informaci\243n que te di\243 el m\250sico[ENTER]Yu-Hwan, has podido encontrar la s\233ptima p\225gina[ENTER]del libro secreto entre los Bandidos del[ENTER]Desierto. Ve con Yu-Hwan y dile que su[ENTER]informaci\243n era correcta. "
gameforge.main_quest_lv47._370_say = "Tus ojos son tan bonitos como un lago de monta\241a[ENTER]lalalala... Eh, aqu\237 est\225s de nuevo. \191Has tenido[ENTER]\233xito con los bandidos del desierto? \191Qu\233? \191Eso[ENTER]es todo? \191Un viejo trozo de papel? Esto no me[ENTER]sirve. Pero si te hace feliz... Ll\233vaselo a[ENTER]Uriel. \161Y env\237ale mis mejores deseos! "
gameforge.main_quest_lv47._380_sendLetter = "Ve con Uriel. "
gameforge.main_quest_lv47._390_targetVid = "Ve con Uriel. "
gameforge.main_quest_lv47._400_sayTitle = "La s\233ptima p\225gina "
gameforge.main_quest_lv47._40_say = "\191Tienes la quinta p\225gina? Incre\237ble. Somos[ENTER]realmente afortunados de que esta p\225gina exista[ENTER]incluso despu\233s de todos estos a\241os. Eres[ENTER]verdaderamente competente. Ahora veamos lo que[ENTER]dice. "
gameforge.main_quest_lv47._410_say = "Has encontrado la s\233ptima p\225gina del diario[ENTER]antiguo. Ll\233vasela a Uriel. "
gameforge.main_quest_lv47._420_say = "Hola, \161encantado de verte de nuevo! Tengo buenas[ENTER]noticias: he terminado de descibrar la sexta[ENTER]p\225gina. No est\225 mal, \191eh? Tengo que admitirlo,[ENTER]estoy bastante orgulloso de mi mismo. Porque lo[ENTER]que verdaderamente capt\243 mi atenci\243n, fue este[ENTER]car\225cter... \191Perd\243n? \191Has encontrado otra? \161Dios[ENTER]m\237o! Qu\233 rapidez. Ens\233\241amela. Wow, \191d\243nde la[ENTER]conseguiste? Si no me equivoco, estos son[ENTER]caracteres usados por la familia imperial. "
gameforge.main_quest_lv47._430_say = "Ya que estos caracteres fueron usados por s\243lo[ENTER]unas pocas personas y con muy poca frecuencia, es[ENTER]muy dif\237cil descifrar esto. Pero supongo que un[ENTER]peque\241o desaf\237o no ha hecho nunca mal a nadie,[ENTER]\161jaja! Estoy esperando con ansia. \191Los Bandidos[ENTER]del Desierto robaron esta p\225gina a los forasteros[ENTER]misteriosos? Hmm... \191Eso significa que los[ENTER]extranjeros entiendo estos caracteres?[ENTER]Esto se esta volviendo muy confuso. Tenemos que[ENTER]asegurarnos de no pasar nada por alto. "
gameforge.main_quest_lv47._440_say = "Oh s\237, mira: Antes de que me concentre en las[ENTER]siguientes p\225ginas, deber\237a decirte lo que hab\237a[ENTER]en la sexta p\225gina. Hrm-hrm... "
gameforge.main_quest_lv47._450_sayTitle = "Sexta p\225gina: "
gameforge.main_quest_lv47._460_sayReward = "El tiempo se acaba. Ahora hemos intentado incluso[ENTER]usando la brujer\237a oscura en el Calabozo de las[ENTER]Ara\241as y no funcion\243.[ENTER]\191Qu\233 nos estamos dejando? Algunos de nuestros[ENTER]m\237sticos creen que la brujer\237a oscura requiere[ENTER]mayores sacrificios.[ENTER]Si esto es verdad, entonces debe ser una fuerza[ENTER]inmensamente poderosa. "
gameforge.main_quest_lv47._470_sayReward = "Seg\250n cuentos y leyendas, este tipo de magia[ENTER]siempre requiere sacrificios humanos. Pero si[ENTER]mato a sus allegados en el altar, mi reputaci\243n[ENTER]entre la gente recibir\225 un golpe. Necesitamos un[ENTER]sustituto adecuado. Probemos con los Espadach\237n[ENTER]Serpiente del desierto. "
gameforge.main_quest_lv47._480_say = "Aja. As\237 que como no pod\237an sacrificar humanos,[ENTER]decidieron usar luchadores serpiente. No puedo[ENTER]fingir que me gusta este nuevo desarrollo. Va a[ENTER]terminar mal... Aunque todav\237a tenemos que seguir[ENTER]su rastro. Ve al desierto y mata algunos[ENTER]Espadach\237n Serpiente y Arqueros Serpiente. Qui\233n[ENTER]sabe qu\233 m\225s podemos encontrar ah\237. Por cierto:[ENTER]\161tu recompensa est\225 en este bolso! "
gameforge.main_quest_lv47._490_sendLetter = "Mata a los guerreros serpiente "
gameforge.main_quest_lv47._500_sayTitle = "La octava p\225gina "
gameforge.main_quest_lv47._50_sayTitle = "Quinta p\225gina: "
gameforge.main_quest_lv47._510_say = "El diario describe el intento de sacrificar[ENTER]Espadachines Serpiente y Arqueros Serpiente para[ENTER]llevar a cabo brujer\237a oscura. Ve al Desierto[ENTER]Yongbi y mata Espadachines Serpiente. Busca m\225s[ENTER]informaci\243n. "
gameforge.main_quest_lv47._520_sendLetter = "Encontrada la octava p\225gina "
gameforge.main_quest_lv47._530_targetVid = "Ve con Uriel el erudito "
gameforge.main_quest_lv47._540_say = "Has encontrado la octava p\225gina del diario con[ENTER]los Espadachines Serpiente en el Desierto.[ENTER]Ll\233vasela a Uriel el erudito. "
gameforge.main_quest_lv47._550_say = "Esta es la octava p\225gina. Ya que es muy corta, la[ENTER]descifrar\233 ahora mismo. "
gameforge.main_quest_lv47._560_sayTitle = "Octava p\225gina: "
gameforge.main_quest_lv47._570_sayReward = "Se han encontrado las v\237ctimas necesarias.[ENTER]Tenemos suerte. Me pregunto si es una se\241al.[ENTER]Necesitamos una campana ceremonial. Si recuerdo[ENTER]bien, las ara\241as tienen algo parecido. Saldremos[ENTER]en camino ahora. "
gameforge.main_quest_lv47._580_say = "Ah, el Calabozo de las Ara\225s de nuevo, curioso.[ENTER]Tienes que ir all\237 y buscar la campana. Va a ser[ENTER]un viaje agotador, as\237 que rel\225jate un poco[ENTER]primero y vuelve m\225s tarde. Voy a reflexionar un[ENTER]poco y traducir algunos fragmentos m\225s. Cuando[ENTER]vuelvas, te dar\233 una nueva misi\243n. Y no te[ENTER]preocupes, por supuesto obtendr\225s ahora tu[ENTER]recompensa por la octava p\225gina. "
gameforge.main_quest_lv47._590_sayReward = "Recibes 3\160000\160000 de puntos de experiencia[ENTER]Recibes 70\160000 Yang[ENTER]Recibes 20 Capas de valor[ENTER]Consejo: Para el siguiente encargo necesitas[ENTER]haber alcanzado al menos el nivel 50. "
gameforge.main_quest_lv47._60_sayReward = "Lee Seop ha llegado al reino Taejo con su[ENTER]caballer\237a pero parece querer quedarse all\237 por[ENTER]un tiempo. Mientras tanto meteoritos grandes y[ENTER]peque\241os est\225n cayendo sobre el pa\237s. Est\225n[ENTER]causando caos, destrucci\243n y conflictos. El[ENTER]extenso reino se ha dividido en tres reinos m\225s[ENTER]peque\241os. Tambi\233n est\225n luchando entre ellos, en[ENTER]lugar de enfrentarse juntos al mal. El Dios[ENTER]Drag\243n ya no nos habla tampoco. A veces ayuda a[ENTER]un bando y a veces al otro. As\237 que todos est\225n[ENTER]luchando por sus favores y mientras tanto el[ENTER]desastre s\243lo empeora... "
gameforge.main_quest_lv47._70_sayTitle = "Uriel: "
gameforge.main_quest_lv47._80_say = "Un relato presencial de los primeros d\237as de[ENTER]nuestra era.[ENTER]\161Verdaderamente es incalculable! Oh s\237, la paga.[ENTER]Aqu\237 tienes una recompensa por tu excelente[ENTER]trabajo. Y algo m\225s: alguien m\225s est\225 obviamente[ENTER]abordando las mismas investigaciones que[ENTER]nosotros. As\237 que no tenemos tiempo que perder.[ENTER]Al final de esta p\225gina dice que Lee Seop ha[ENTER]estado buscando energ\237a malvada en el Calabozo de[ENTER]las Ara\241as. Si encuentras algo ah\237, ven a verme[ENTER]inmediatamente.[ENTER]\161No puedo esperar! "
gameforge.main_quest_lv47._90_sendLetter = "La sexta p\225gina "
gameforge.main_quest_lv50 = {}
gameforge.main_quest_lv50._100_say = "Eh, no tan r\225pido, \161impulsivo! \161No olvides tu[ENTER]recompensa por la novena p\225gina! "
gameforge.main_quest_lv50._10_sayTitle = "Mata Ara\241as Soldado Soberbias "
gameforge.main_quest_lv50._110_sayReward = "Recibes 5.000.000 puntos de experiencia. "
gameforge.main_quest_lv50._120_sayReward = "Has recibido 125.000 Yang. "
gameforge.main_quest_lv50._130_sayReward = "Has recibido un S\237mbolo del Rey Sabio. "
gameforge.main_quest_lv50._140_sendLetter = "Indicios en el Desierto Helado "
gameforge.main_quest_lv50._150_targetVid = "La caja vieja con papeles "
gameforge.main_quest_lv50._160_sayTitle = "Buscando la caja vieja con papeles "
gameforge.main_quest_lv50._170_say = "En el Monte Sohan los ej\233rcitos enemigos se[ENTER]encontraron finalmente. Busca m\225s p\225ginas de[ENTER]diario u otra evidencia escrita sobre el progreso[ENTER]de la batalla. "
gameforge.main_quest_lv50._180_npcChat = "\161Una Caja Vieja con Papeles! "
gameforge.main_quest_lv50._190_say = "Esto son planes militares y anotaciones.[ENTER]\161Y aqu\237 hay otra p\225gina de diario![ENTER]Debo llev\225rsela a Uriel. "
gameforge.main_quest_lv50._200_sendLetter = "La d\233cima p\225gina "
gameforge.main_quest_lv50._20_say = "Nuestra investigaci\243n previa indica que hay[ENTER]pistas en el Calabozo de las Ara\241as. Si[ENTER]encuentras otra p\225gina del libro antiguo,[ENTER]ll\233vasela a Uriel el erudito. "
gameforge.main_quest_lv50._210_sayTitle = "Se ha encontrado la d\233cima p\225gina "
gameforge.main_quest_lv50._220_say = "Has encontrado la d\233cima p\225gina del Diario[ENTER]Secreto en la Tierra de Hielo. Estaba en una Caja[ENTER]Vieja con Papeles.[ENTER]Ll\233vasela a Uriel. "
gameforge.main_quest_lv50._230_say = "Ah, \161encontraste la desaparecida d\233cima P\225gina de[ENTER]Diario![ENTER]Genial, nos estamos acercando al final de la[ENTER]historia. Est\225 bien que documentasen todo, de[ENTER]otro modo este conocimiento se habr\237a perdido.[ENTER]Veamos lo que dice la p\225gina. "
gameforge.main_quest_lv50._235_sayTitle = "P\225gina 10: "
gameforge.main_quest_lv50._240_sayReward = "Hemos tenido \233xito repeliendo los primeros[ENTER]ataques. Pero el siguiente vendr\225 pronto. El[ENTER]terreno obstaculizar\225 a los soldados de Lee Seop[ENTER]y nos dar\225 algunas ventajas, pero son demasiados.[ENTER]No podemos ganar. S\243lo tenemos una \250ltima[ENTER]oportunidad, terminar nuestra investigaci\243n de la[ENTER]brujer\237a oscura. Bajo abrigo de la oscuridad[ENTER]penetraremos en las l\237neas enemigas y volveremos[ENTER]a las Cuevas de las Ara\241as. Estoy rezando. No por[ENTER]la victoria, sino por un poco de esperanza... "
gameforge.main_quest_lv50._250_say = "Ooohh. \161Creo que casi hemos llegado! Pronto[ENTER]averiguaremos respecto a la Magia Negra. \161No[ENTER]puedo esperar! Tienes que volver al Calabozo de[ENTER]las Ara\241as una vez m\225s. Con esperanza la und\233cima[ENTER]p\225gina del libro est\225 all\237. "
gameforge.main_quest_lv50._260_say = "Y aqu\237 tienes - una vez m\225s - \161tu merecida[ENTER]recompensa! "
gameforge.main_quest_lv50._270_sayReward = "Has recibido 5.500.000 puntos de experiencia. "
gameforge.main_quest_lv50._280_sayReward = "Has recibido 137.500 Yang. "
gameforge.main_quest_lv50._290_sayReward = "Has recibido un Guante del Rey Sabio. "
gameforge.main_quest_lv50._300_sayTitle = "Mata Ara\241as Garra Veneno "
gameforge.main_quest_lv50._30_sendLetter = "La novena p\225gina "
gameforge.main_quest_lv50._310_say = "La investigaci\243n de la brujer\237a negra va a[ENTER]continuar en las Cuevas de la Ara\241a. Ve all\237 y[ENTER]mata algunas Ara\241as Garra Veneno para conseguir[ENTER]la informaci\243n necesaria. "
gameforge.main_quest_lv50._320_sendLetter = "La und\233cima p\225gina "
gameforge.main_quest_lv50._330_targetVid = "Vuelve con Uriel el erudito. "
gameforge.main_quest_lv50._335_sayTitle = "La p\225gina 11 ha sido encontrada "
gameforge.main_quest_lv50._340_say = "Has encontrado la und\233cima p\225gina del Diario[ENTER]Secreto en el Calabozo de las Ara\241as. Ll\233vasela a[ENTER]Uriel. "
gameforge.main_quest_lv50._350_say = "\191Has encontrado alguna informaci\243n nueva? Aja,[ENTER]\161la und\233cima p\225gina! Veamos...[ENTER]Ah s\237, parece bastante f\225cil. Me he vuelto[ENTER]bastante bueno leyendo estos caracteres. Ahora,[ENTER]\161mira esto! "
gameforge.main_quest_lv50._355_sayTitle = "P\225gina 11: "
gameforge.main_quest_lv50._360_sayReward = "Ha fallado. A pesar de toda nuestra preparaci\243n,[ENTER]ten\237amos que actuar r\225pido. Ahora muchos estamos[ENTER]heridos y otros incluso se han vuelto locos. La[ENTER]brujer\237a oscura es verdaderamente maligna. La[ENTER]caballer\237a de Lee Seop est\225 sobre nosotros, pero[ENTER]ahora eso es irrelevante. No tenemos suficientes[ENTER]hombres para defendernos de \233l y vamos a morir de[ENTER]todas formas. "
gameforge.main_quest_lv50._365_sayTitle = "Continuaci\243n de la p\225gina 11: "
gameforge.main_quest_lv50._370_sayReward = "Un \250ltimo pensamiento est\225 manteniendo unida al[ENTER]resto de la tropa y nos est\225 dando fuerzas:[ENTER]Nuestros informadores del Valle del Drag\243n[ENTER]mintieron. Deliberadamente no nos avisaron de los[ENTER]terribles efectos secundarios de la brujer\237a[ENTER]oscura. Pagar\225n por ello. Ser\225 nuestra \250ltima[ENTER]acci\243n en la tierra. "
gameforge.main_quest_lv50._380_say = "Bueno, al final se volvi\243 un poco diferente a[ENTER]como ellos esperaban. Una historia triste. Pero[ENTER]por desgracia no puedes confiar en nadie[ENTER]relacionado con la brujer\237a negra. Deber\237an[ENTER]haberlo pensado. Es bastante extra\241o que el autor[ENTER]de estas l\237neas se las arreglase incluso para[ENTER]recibir informaci\243n sobre estos proyectos[ENTER]prohibidos. Quien sabe que tipo de objetivo[ENTER]ten\237an sus informadores. Sin embargo, tenemos que[ENTER]terminar este camino, aunque sea peligroso. Ya[ENTER]sabemos mucho, ser\237a una l\225stima dejarlo ahora. "
gameforge.main_quest_lv50._390_say = "Ya has estado en el Valle de Seungryong. No creo[ENTER]que encontremos nada m\225s all\237. Hmm, me pregunto[ENTER]d\243nde m\225s podemos mirar... \161Lo s\233! Los monumentos[ENTER]han jugado un gran papel durante nuestra[ENTER]b\250squeda. Y hay m\225s monumentos por ah\237 que no[ENTER]hemos investigado a\250n. \161Los de los otros reinos![ENTER]Hay mucho peligro ah\237. Seguramente ser\225s atacado[ENTER]constantemente. As\237 que preparate bien y ven a[ENTER]verme cuando est\233s listo. "
gameforge.main_quest_lv50._400_say = "Pero primero, por supuesto, tendr\225s tu recompensa[ENTER]por la und\233cima p\225gina. "
gameforge.main_quest_lv50._40_targetVid = "Ve con Uriel el erudito "
gameforge.main_quest_lv50._410_sayReward = "Has recibido 6.000.000 puntos de experiencia.[ENTER]Has recibido 150.000 Yang.[ENTER]Adem\225s, has recibido una Medalla del Drag\243n.[ENTER]Pista: Para la siguiente tarea, tienes que estar[ENTER]al menos en nivel 55. "
gameforge.main_quest_lv50._50_sayTitle = "Encontrada la novena p\225gina "
gameforge.main_quest_lv50._60_say = "Has encontrado la novena p\225gina en el Calabozo de[ENTER]las Ara\241as. Ll\233vasela a Uriel el erudito. "
gameforge.main_quest_lv50._70_say = "\191Has averiguado algo m\225s sobre la brujer\237a negra?[ENTER]Wow, \161la novena p\225gina! Estoy realmente ansioso[ENTER]por ver si la magia funcion\243 o no.[ENTER]Echemos un vistazo. Hmm, aqu\237 dice... "
gameforge.main_quest_lv50._75_sayTitle = "P\225gina 9: "
gameforge.main_quest_lv50._80_sayReward = "El ataque de Lee Seop ha comenzado. Y todav\237a no[ENTER]sabemos exactamente c\243mo usar la brujer\237a negra.[ENTER]Estoy verdaderamente nervioso. Estamos en la[ENTER]l\237nea de fuego, intentando defender nuestro[ENTER]reino, pero nuestra fuerza es insuficiente. La[ENTER]armada enemiga es demasiado fuerte y si no sucede[ENTER]algo pronto, vamos a perder la batalla. Tenemos[ENTER]que retirarnos. Ser\225 mejor para nosotros[ENTER]retirarnos a una barricada, donde no sean capaces[ENTER]de usar adecuadamente sus caballos: El Desierto[ENTER]Helado. Con un poco de suerte tendremos tiempo[ENTER]suficiente para seguir investigando. Oh, Dios[ENTER]ay\250danos... "
gameforge.main_quest_lv50._90_say = "Hmm... El ataque comenz\243 antes de que fueran[ENTER]capaces de investigar adecuadamente la brujer\237a[ENTER]negra. Han tenido que asentarse en el Desierto[ENTER]Helado. Deben referirse al Monte Sohan, que[ENTER]actualmente es conocido tambi\233n como Tierra de[ENTER]Hielo. Debemos buscar m\225s pistas. Ve al Monte[ENTER]Sohan y mira lo que puedes averiguar. "
gameforge.main_quest_lv55 = {}
gameforge.main_quest_lv55._100_say = "Has encontrado la duod\233cima p\225gina en el \193rea[ENTER]Joan. Ll\233vasela a Uriel en el \193rea Yongan. "
gameforge.main_quest_lv55._10_sendLetter = "Buscando los monumentos "
gameforge.main_quest_lv55._110_say = "Has encontrado la duod\233cima p\225gina en el \193rea[ENTER]Yongan. Ll\233vasela a Uriel en el \193rea Pyungmo. "
gameforge.main_quest_lv55._120_say = "Estoy encantado de verte de nuevo. Siento haber[ENTER]tenido que enviarte aqu\237, all\237 y a todas partes,[ENTER]pero al menos nuestro \233xito ha probado que[ENTER]estamos en lo cierto, \191no crees? Veamos lo que[ENTER]dice. Espero que todo haya valido la pena. "
gameforge.main_quest_lv55._130_sayTitle = "Duod\233cima p\225gina: "
gameforge.main_quest_lv55._140_sayReward = "Encontramos a los informadores y han pagado su[ENTER]enga\241o con sus vidas. Pero lo que es mucho m\225s[ENTER]importante es que a\250n hemos podido exprimirles[ENTER]algo de informaci\243n: No necesitamos las Cuevas de[ENTER]la Ara\241a, sino el Templo de la oscuridad. Aqu\237 es[ENTER]donde los ancianos seguidores de la fe han estado[ENTER]ejecutando sus rituales oscuros desde el[ENTER]principio. "
gameforge.main_quest_lv55._145_sayTitle = "Continuaci\243n de la pagina 12: "
gameforge.main_quest_lv55._150_sayReward = "S\243lo nos queda una v\237a m\225s para detener a Lee[ENTER]Seop. Tenemos que viajar al Templo de la[ENTER]oscuridad para poder ejecutar la brujer\237a negra.[ENTER]No quedamos muchos y el esfuerzo de los \250ltimos[ENTER]meses con seguridad ha tenido efectos negativos.[ENTER]Pero incluso un pu\241ado de hombres cansados puede[ENTER]cambiar el destino del mundo cuando tienen[ENTER]informaci\243n poderosa.[ENTER]No podemos perder de vista nuestro objetivo.[ENTER]Vamos. "
gameforge.main_quest_lv55._160_say = "Ah, as\237 que encontraron el lugar correcto. \161Yo[ENTER]ten\237a raz\243n despu\233s de todo! Realmente es el[ENTER]Templo Hwang. Seguramente recuerdes ese lugar[ENTER]oscuro, que estaba vibrando con energ\237a malvada.[ENTER]Desde lo que puede recordar cualquiera, se han[ENTER]llevado a cabo rituales y ceremonias all\237, de los[ENTER]cuales deben alejarse los aldeanos honestos. "
gameforge.main_quest_lv55._170_say = "Actualmente, los monstruos son las \250nicas cosas[ENTER]viviendo en el Templo, no ha habido humanos all\237[ENTER]durante mucho tiempo. Es muy peligroso, pero[ENTER]estoy seguro de que puedes hacerlo. Ve al Valle[ENTER]de Seungryong y busca la \250ltima p\225gina en el[ENTER]Templo Hwang. La historia que este diario ha[ENTER]estado cont\225ndonos termina all\237. Tengo que[ENTER]averiguar c\243mo termin\243. \161Buena suerte! Oh, espera[ENTER]un momento, aqu\237 est\225 tu recompensa por la[ENTER]duod\233cima p\225gina. "
gameforge.main_quest_lv55._180_sayReward = "Has recibido 26.000 puntos de experiencia.[ENTER]Has recibido 15.000 Yang.[ENTER]Has recibido una Nariz de Cerdo. "
gameforge.main_quest_lv55._190_sayReward = "Has recibido 162.500 Yang. "
gameforge.main_quest_lv55._200_sendLetter = "La \250ltima p\225gina "
gameforge.main_quest_lv55._20_say = "Como ya has encontrado varias p\225ginas del Diario[ENTER]cerca de los monumentos, Uriel piensa que podr\225s[ENTER]encontrar m\225s informaci\243n sobre la brujer\237a negra[ENTER]secreta cerca de los monumentos inexplorados. Ve[ENTER]al Reino Chunjo e investiga el monumento en el[ENTER]\225rea Joan. "
gameforge.main_quest_lv55._210_sayTitle = "Mata Hombres del saco en el Templo "
gameforge.main_quest_lv55._220_say = "Hasta ahora, has encontrado 12 de las 13 p\225ginas[ENTER]del diario. Ahora, s\243lo queda un paso. Uriel dice[ENTER]que la magia negra ha sido lanzada en el Templo[ENTER]Hwang. Debes ir all\237 y encontrar algo m\225s de[ENTER]informaci\243n. Comienza tu b\250squeda matando a los[ENTER]Hombres del saco en el templo. "
gameforge.main_quest_lv55._230_say = "\161Tengo que internarme en el Templo! "
gameforge.main_quest_lv55._240_sendLetter = "El Templo de la oscuridad "
gameforge.main_quest_lv55._250_sayTitle = "La energ\237a mal\233fica del templo "
gameforge.main_quest_lv55._260_sayReward = "Despu\233s de que has pasado un poco de tiempo en el[ENTER]templo, desarrollas un sentimiento por este[ENTER]extra\241o y oscuro lugar: Finas sombras se mueven[ENTER]por cada esquina. La energ\237a oscura rezuma por[ENTER]cada grieta y recodo como aceite. Es obvio que el[ENTER]templo en s\237 mismo en la raz\243n detr\225s de esto.[ENTER]Aqu\237 es donde todo comenz\243... "
gameforge.main_quest_lv55._270_say = "Te das cuenta del hecho de que la maldad que yace[ENTER]en el aire se hace m\225s fuerte, cuanto m\225s te[ENTER]mueves hacia el centro del templo. Debes tratar[ENTER]de encontrar el medio del templo.[ENTER]All\237 es donde debe estar el origen de la[ENTER]oscuridad. "
gameforge.main_quest_lv55._280_npcChat = "El monumento Gum "
gameforge.main_quest_lv55._290_say = "El Monumento Gum est\225 en el coraz\243n del templo.[ENTER]Te acercas lentamente y definitivamente[ENTER]encuentras la \250ltima p\225gina del diario. "
gameforge.main_quest_lv55._300_say = "Has encontrado la \250ltima p\225gina del Diario[ENTER]Secreto en el Templo de la Oscuridad. Ve con[ENTER]Uriel e inf\243rmale de tu descubrimiento. "
gameforge.main_quest_lv55._30_say = "Como ya has encontrado varias p\225ginas del Diario[ENTER]cerca de los monumentos, Uriel piensa que podr\225s[ENTER]encontrar m\225s informaci\243n sobre la brujer\237a negra[ENTER]secreta cerca de los monumentos inexplorados. Ve[ENTER]al Reino Jinno e investiga el monumento en el[ENTER]\193rea Pyungmo. "
gameforge.main_quest_lv55._310_say = "Aqu\237 est\225, \161la decimotercera y \250ltima p\225gina! No[ENTER]puedo expresar lo agradecido que estoy por hacer[ENTER]todo esto. Mira como me tiemblan las manos. Estoy[ENTER]demasiado emocionado incluso para leer la p\225gina.[ENTER]Uf... Ah bien, veamos c\243mo acaba la historia. "
gameforge.main_quest_lv55._320_sayTitle = "Decimotercera P\225gina: "
gameforge.main_quest_lv55._330_sayReward = "Finalmente hemos llegado.[ENTER]Despu\233s de todas nuestras duras experiencias[ENTER]ahora tenemos la siguiente misi\243n: Tenemos que[ENTER]detener la ceremonia y activar la magia de la[ENTER]brujer\237a negra. Tan solo espero que seamos lo[ENTER]suficientemente fuertes. Muchos de nosotros se[ENTER]tambalean ligeramente, porque estamos muy[ENTER]exhaustos del largo viaje y de estar[ENTER]continuamente huyendo de los guerreros de Seop.[ENTER]Sin embargo, todav\237a tenemos que intentarlo o[ENTER]nuestro reino perecer\225. "
gameforge.main_quest_lv55._335_sayTitle = "Continuaci\243n de la p\225gina 13: "
gameforge.main_quest_lv55._340_sayReward = "Somos siete. Nos pusimos nuestra mejor ropa,[ENTER]incluso si ahora parecen harapos. Vamos a[ENTER]reunirnos en c\237rculo y sostener nuestras manos[ENTER]para que las l\237neas de poder sean selladas.[ENTER]Entonces empezaremos a recitar las palabras[ENTER]m\225gicas y esperar que la brujer\237a negra no tome[ENTER]m\225s sacrificios.[ENTER][ENTER]... "
gameforge.main_quest_lv55._350_sayReward = "... Se acab\243...[ENTER]Al principio todo era muy prometedor. La[ENTER]habitaci\243n se llen\243 de energ\237a y canto, pero de[ENTER]repente me sent\237 realmente extra\241o. Mis seis[ENTER]compa\241eros cayeron de rodillas. El templo comenz\243[ENTER]a temblar. Entonces cay\243 un rayo y fuimos[ENTER]lanzados hacia atr\225s. Y entonces las l\237neas de[ENTER]poder se rompieron...[ENTER]Ahora est\225 tranquilo. Mis camaradas yacen muertos[ENTER]en el suelo. La magia no funcion\243.[ENTER]Hemos fallado. "
gameforge.main_quest_lv55._360_say = "\191Qu\233? \191\161\191Eso es todo?!?[ENTER]\161Es una locura! \191Todo ese trabajo para nada? No[ENTER]puedo creerlo. Hemos viajado, luchado, traducido[ENTER]y reflexionado durante horas. \161Todo para nada![ENTER]Sabemos tanto como al principio. Aunque parece[ENTER]mejor mantenernos alejados de la brujer\237a negra,[ENTER]que es lo que yo pensaba desde el principio. Pero[ENTER]saber es mejor que creer, \191no? "
gameforge.main_quest_lv55._370_say = "Vamos a descansar primero. Tengo dolor de cabeza[ENTER]y seguramente tu tambi\233n est\233s bastante cansado.[ENTER]Tengo que procesar todo primero. Cuando haya[ENTER]terminado, hablaremos m\225s. A pesar de todo, me[ENTER]has ofrecido un servicio inestimable. \161No quedar\225[ENTER]sin recompensa! "
gameforge.main_quest_lv55._380_sayReward = "Has recibido 7.000.000 puntos de experiencia. "
gameforge.main_quest_lv55._390_sayReward = "Has recibido 175.000 Yang. "
gameforge.main_quest_lv55._400_sayReward = "Has recibido el Libro del L\237der. "
gameforge.main_quest_lv55._40_say = "Como ya has encontrado varias p\225ginas del Diario[ENTER]cerca de los monumentos, Uriel piensa que podr\225s[ENTER]encontrar m\225s informaci\243n sobre la brujer\237a negra[ENTER]secreta cerca de los monumentos inexplorados. Ve[ENTER]al Reino Shinsoo e investiga el monumento en el[ENTER]\225rea Yongan. "
gameforge.main_quest_lv55._50_npcChat = "\161Ah\237 est\225! "
gameforge.main_quest_lv55._60_say = "Este es el monumento que Uriel estaba buscando.[ENTER]\161Tambi\233n hay una p\225gina doblada! Debo llev\225rsela[ENTER]r\225pidamente a Uriel. "
gameforge.main_quest_lv55._70_sendLetter = "Encontrada la duod\233cima p\225gina "
gameforge.main_quest_lv55._80_targetVid = "Vuelve con Uriel "
gameforge.main_quest_lv55._90_say = "Has encontrado la duod\233cima p\225gina en el \193rea[ENTER]Pyungmo. Ll\233vasela a Uriel en el \225rea Joan. "
gameforge.main_quest_lv6 = {}
gameforge.main_quest_lv6._100_sayReward = "Ve con el herrero. Necesita tu ayuda. "
gameforge.main_quest_lv6._10_targetVid = "Ve con el Guardi\225n de la Ciudad "
gameforge.main_quest_lv6._110_say = "\191Qui\233n eres y qu\233 buscas aqu\237?[ENTER]Estoy muy ocupado as\237 que no me molestes.[ENTER]Oh, \191te env\237a el Guardi\225n de la Ciudad? Pens\233 que[ENTER]no vendr\237a nadie. No es una tarea dif\237cil y no[ENTER]costar\225 mucho tiempo. Justo lo necesario para un[ENTER]joven aventurero como t\250. "
gameforge.main_quest_lv6._120_say = "Esperaba que el encargado del almac\233n me[ENTER]entregase una herramienta especial, pero a\250n no[ENTER]ha llegado. Tr\225eme esa herramienta. Tengo prisa.[ENTER]La necesito para poder seguir trabajando. "
gameforge.main_quest_lv6._130_targetVid = "Pregunta al Encargado del almac\233n "
gameforge.main_quest_lv6._140_sendLetter = "Ve con el Encargado del almac\233n "
gameforge.main_quest_lv6._150_sayReward = "El herrero est\225 esperando una entrega urgente del[ENTER]Encargado del almac\233n. Ve con el Encargado del[ENTER]almac\233n y p\237dele una Nariz de Cerdo para el[ENTER]herrero. "
gameforge.main_quest_lv6._160_sayTitle = "Encargado del almac\233n: "
gameforge.main_quest_lv6._170_say = "Bienvenido. Soy el encargado del almac\233n de esta[ENTER]aldea. Si transportas demasiadas cosas contigo,[ENTER]pueden ser almacenadas en mi almac\233n. Esto puede[ENTER]resultar \250til. "
gameforge.main_quest_lv6._180_say = "Quieres... Ah, \161te env\237a el herrero por la Nariz[ENTER]de Cerdo! "
gameforge.main_quest_lv6._190_say = "Me temo que me estoy volviendo viejo y[ENTER]olvidadizo. En el pasado, algo como eso no habr\237a[ENTER]sucedido. Aqu\237 tienes la Nariz de Cerdo. Por[ENTER]favor, ll\233vasela inmediatamente al Herrero. Nos[ENTER]vemos m\225s tarde. "
gameforge.main_quest_lv6._200_sendLetter = "Vuelve con el Herrero "
gameforge.main_quest_lv6._20_sayReward = "El Guardi\225n de la Ciudad tiene una nueva misi\243n[ENTER]para ti. Ve con \233l y preg\250ntale. "
gameforge.main_quest_lv6._210_sayReward = "El Encargado del almac\233n ha olvidado[ENTER]completamente la entrega. Te ha dado la Nariz de[ENTER]Cerdo. Ll\233vasela r\225pidamente al herrero para que[ENTER]no tenga que esperar m\225s. "
gameforge.main_quest_lv6._220_say = "\161Has vuelto m\225s r\225pido de lo que pensaba![ENTER]Deber\237as mantener esta velocidad, puede ser \250til[ENTER]en el futuro. Y ahora escucha cuidadosamente,[ENTER]tengo informaci\243n importante para ti. "
gameforge.main_quest_lv6._230_say = "\191Sabes algo sobre el refinamiento de objetos?[ENTER]\161Por supuesto que no, todav\237a eres un joven[ENTER]aventurero! Funciona as\237: si me das una pieza de[ENTER]tu equipo, puedo modificarla a cambio de un poco[ENTER]de Yang para mejorar as\237 sus cualidades. "
gameforge.main_quest_lv6._240_say = "El arte del refinamiento puede conseguir[ENTER]diferentes resultados: cuanto m\225s alto aspiras,[ENTER]m\225s dif\237cil es la ejecuci\243n. Para una mejora[ENTER]hasta +3 tan s\243lo necesitas un poco de Yang; para[ENTER]todo lo dem\225s hace falta un objeto adicional como[ENTER]la Nariz de Cerdo que me has tra\237do. Sin embargo,[ENTER]a veces el objeto que te gustar\237a mejorar resulta[ENTER]destruido incluso aunque el proceso lo realice un[ENTER]herrero tan habilidoso como yo. Vuelve por aqu\237[ENTER]si tienes algo de tiempo. \161Puedo forjar armas[ENTER]fant\225sticas! "
gameforge.main_quest_lv6._250_sayReward = "Has recibido %s puntos de experiencia. "
gameforge.main_quest_lv6._260_sayReward = "Has recibido %s Yang. "
gameforge.main_quest_lv6._270_sayReward = "Obtienes una Piel de Lobo+. "
gameforge.main_quest_lv6._30_say = "\161Eh, t\250! \161No pasees por la aldea y digas que no[ENTER]hay nada que hacer! \161Necesitas m\225s entrenamiento![ENTER]\161En estos tiempos problem\225ticos, el entrenamiento[ENTER]es la \250nica manera de aumentar tus posibilidades[ENTER]de sobrevivir! "
gameforge.main_quest_lv6._40_say = "Pero ya que de todos modos est\225s aqu\237, tengo una[ENTER]misi\243n para ti: el Herrero estuvo aqu\237 hace poco[ENTER]y dijo algo sobre cerdos y problemas de entrega.[ENTER]Quiz\225 necesita ayuda. Ve con \233l y dile que te he[ENTER]enviado. \161Ve! "
gameforge.main_quest_lv6._50_sayReward = "Si completas la misi\243n para el Herrero recibir\225s[ENTER]una recompensa. "
gameforge.main_quest_lv6._60_sayReward = "Puntos de experiencia: %s "
gameforge.main_quest_lv6._70_sayReward = "Yang: %d "
gameforge.main_quest_lv6._80_targetVid = "Encuentra al Herrero "
gameforge.main_quest_lv6._90_sendLetter = "La misi\243n del Herrero "
gameforge.main_quest_lv60 = {}
gameforge.main_quest_lv60._100_say = "\191El Monte Sohan? \161All\237 vi una vez una vieja[ENTER]l\225pida! "
gameforge.main_quest_lv60._10_sendLetter = "Una nueva pista "
gameforge.main_quest_lv60._110_say = "\191Y por casualidad no recordar\225s si ten\237a una[ENTER]inscripci\243n?[ENTER]Ya veo que no. Esa L\225pida Antigua podr\237a desvelar[ENTER]mucha informaci\243n importante sobre la Naci\243n[ENTER]Oscura. \191Podr\237as viajar al Monte Sohan y crear[ENTER]una Copia de la Inscripci\243n por m\237? "
gameforge.main_quest_lv60._120_say = "Seg\250n la investigaci\243n de Uriel, las siete[ENTER]Sacerdotisas del Drag\243n proced\237an de la Naci\243n[ENTER]Oscura. Investiga la L\225pida Antigua en el Monte[ENTER]Sohan. Se dice que all\237 se encontraba la capital[ENTER]de la Naci\243n Oscura hace tiempos inmemoriales. "
gameforge.main_quest_lv60._130_say = "\191Y por casualidad no recordar\225s si ten\237a una[ENTER]inscripci\243n?[ENTER]Ya veo que no. Esa L\225pida Antigua podr\237a desvelar[ENTER]mucha informaci\243n importante sobre la Naci\243n[ENTER]Oscura. \191Podr\237as viajar al Monte Sohan y crear[ENTER]una Copia de la Inscripci\243n por m\237? "
gameforge.main_quest_lv60._140_sayReward = "Has encontrado la L\225pida Antigua de los tiempos[ENTER]de la Naci\243n Oscura y has hecho una Copia de la[ENTER]Inscripci\243n. Ll\233vasela a Uriel. "
gameforge.main_quest_lv60._150_say = "Seg\250n la investigaci\243n de Uriel, las siete[ENTER]Sacerdotisas del Drag\243n proced\237an de la Naci\243n[ENTER]Oscura. Investiga la L\225pida Antigua en el Monte[ENTER]Sohan. Se dice que all\237 se encontraba la capital[ENTER]de la Naci\243n Oscura hace tiempos inmemoriales. "
gameforge.main_quest_lv60._160_say = "\161Por fin! D\233jame analizar la inscripci\243n...[ENTER]Dice lo siguiente: la Naci\243n Oscura se consagr\243 a[ENTER]la brujer\237a negra y serv\237a a Sung Mahi, el Dios[ENTER]de los Demonios. "
gameforge.main_quest_lv60._170_say = "Por los cielos... \161Sung Mahi! \191Intentar\237an acaso[ENTER]las siete Sacerdotisas del Drag\243n invocar a Sung[ENTER]Mahi mediante esa magia prohibida? "
gameforge.main_quest_lv60._180_say = "Has hecho un buen trabajo. Por ello deber\237as[ENTER]recibir una recompensa adecuada. "
gameforge.main_quest_lv60._190_sayReward = "Has recibido %s puntos de experiencia. "
gameforge.main_quest_lv60._200_sayReward = "Has recibido %s Yang. "
gameforge.main_quest_lv60._20_say = "Uriel ha encontrado novedades sobre la historia[ENTER]del viejo diario. Busca a Uriel para que te[ENTER]cuente m\225s. "
gameforge.main_quest_lv60._210_sayReward = "Recibes %d. "
gameforge.main_quest_lv60._220_sendLetter = "La Naci\243n Oscura II "
gameforge.main_quest_lv60._230_say = "Seg\250n Uriel, el Bosque Fantasma antes pertenec\237a[ENTER]a la Naci\243n Oscura. Quiz\225s all\237 a\250n se puedan[ENTER]encontrar m\225s pistas.[ENTER]Sin embargo, este bosque est\225 lleno de peligros y[ENTER]las criaturas de la zona se han vuelto furibundas[ENTER]por culpa de las Piedras Metin. Encuentra el[ENTER]\193rbol Diab\243lico para conseguir otro punto de[ENTER]referencia. Despu\233s habla con Uriel. "
gameforge.main_quest_lv60._240_say = "Incontables secretos rodean a la Naci\243n Oscura.[ENTER]Gracias a ti hemos podido desvelar algunos, pero[ENTER]nos sigue faltando informaci\243n importante. Por[ENTER]favor, ve a buscar cierto Documento Antiguo que[ENTER]deber\237a encontrarse en el Bosque Fantasma, cerca[ENTER]del Monte Sohan. "
gameforge.main_quest_lv60._250_counter = "P\225ginas por recopilar: "
gameforge.main_quest_lv60._260_say = "Incontables secretos rodean a la Naci\243n Oscura.[ENTER]Gracias a ti hemos podido desvelar algunos, pero[ENTER]nos sigue faltando informaci\243n importante. Por[ENTER]favor, ve a buscar cierto Documento Antiguo que[ENTER]deber\237a encontrarse en el Bosque Fantasma, cerca[ENTER]del Monte Sohan. "
gameforge.main_quest_lv60._270_sayReward = "Has derrotado al \193rbol Diab\243lico y te has[ENTER]apropiado del Documento Antiguo. Est\225 escrito en[ENTER]un lenguaje extra\241o. Ll\233vaselo a Uriel para que[ENTER]lo traduzca. "
gameforge.main_quest_lv60._280_say = "\161Por fin! Has encontrado el Documento Antiguo.[ENTER]\161Esperemos que arroje un poco de luz sobre este[ENTER]misterio! "
gameforge.main_quest_lv60._290_say = "\161\191Pero qu\233...?! \161Casi no dice nada! El documento[ENTER]deber\237a tener diez p\225ginas. Por favor, vuelve al[ENTER]Bosque Fantasma y encuentra las nueve restantes. "
gameforge.main_quest_lv60._300_say = "A\250n te quedan %d p\225ginas por encontrar. "
gameforge.main_quest_lv60._30_say = "\191Qu\233 tal? \191Recuerdas a\250n el diario y la historia[ENTER]que conten\237a, esa que terminaba abruptamente con[ENTER]la decimotercera y \250ltima p\225gina? "
gameforge.main_quest_lv60._310_say = "Bueno, vamos a ver ahora... Al parecer, la Naci\243n[ENTER]Oscura corrompi\243 mediante una maldici\243n a la gran[ENTER]sacerdotisa del culto del Drag\243n y abus\243 de los[ENTER]poderes sagrados de las siete mujeres para poder[ENTER]emplear el antiguo arte de la brujer\237a negra. "
gameforge.main_quest_lv60._320_say = "Para invocar a Sung Mahi hay que utilizar la[ENTER]brujer\237a negra al mismo tiempo en siete lugares[ENTER]diferentes.[ENTER]Pero Lee Seop y su ej\233rcito consiguieron[ENTER]interrumpir a tiempo el ritual y frustrar el plan[ENTER]imp\237o de la Naci\243n Oscura. "
gameforge.main_quest_lv60._330_say = "Esa era realmente una Naci\243n temible. \161Eran[ENTER]capaces de controlar mentes mediante magia negra! "
gameforge.main_quest_lv60._340_sendLetter = "La pista "
gameforge.main_quest_lv60._350_say = "Uriel ha encontrado menciones al Monumento Gum en[ENTER]los viejos pergaminos. Ve a hablar con \233l para[ENTER]saber m\225s. "
gameforge.main_quest_lv60._360_say = "Vamos a resumir lo que hemos descubierto hasta[ENTER]ahora: Anta\241o hab\237a un pueblo llamado conocido[ENTER]como la Naci\243n Oscura que serv\237a al dios[ENTER]demon\237aco Sung Mahi. Para invocarlo corrompieron[ENTER]a las siete Sacerdotisas del Drag\243n y utilizaron[ENTER]sus poderes sagrados para el arte prohibido de la[ENTER]brujer\237a negra. Pero esta deb\237a emplearse en[ENTER]siete lugares distintos a la vez. "
gameforge.main_quest_lv60._370_say = "Sin embargo, las Sacerdotisas del Drag\243n[ENTER]utilizaron la brujer\237a negra solamente en esta[ENTER]torre, no en sitios diferentes... \161Por eso[ENTER]fracas\243 la invocaci\243n de Sung Mahi! "
gameforge.main_quest_lv60._380_say = "La Naci\243n Oscura debi\243 de darle una informaci\243n[ENTER]falsa a las Sacerdotisas del Drag\243n. "
gameforge.main_quest_lv60._390_say = "O quiz\225s ellas mismas no lo sab\237an...[ENTER]Puede que fuera pura casualidad , pero los[ENTER]pergaminos antiguos relacionan esta torre con el[ENTER]Monumento Gum. Parece que se trata de de la Torre[ENTER]del Demonio del Templo Hwang. "
gameforge.main_quest_lv60._400_say = "\161Finalmente hemos descubierto la pista definitiva[ENTER]de las Sacerdotisas del Drag\243n![ENTER]Descansa un poco y despu\233s discutiremos cu\225l es[ENTER]el siguiente paso. Me temo que te aguarda un[ENTER]viaje a la Torre Demon\237aca... "
gameforge.main_quest_lv60._40_say = "S\237, por supuesto. Siete personas huyeron de Lee[ENTER]Seop y su caballer\237a se refugiaron en el Templo[ENTER]Hwang donde, desesperados, emplearon la brujer\237a[ENTER]negra... Al final, solamente uno de ellos[ENTER]sobrevivi\243. "
gameforge.main_quest_lv60._410_sayReward = "El resto de esta aventura te espera en cuanto[ENTER]hayas alcanzado el nivel 66. "
gameforge.main_quest_lv60._50_say = "Exacto. He continuado mis investigaciones y he[ENTER]descubierto que esas siete personas eran miembros[ENTER]del culto sagrado de las Sacerdotisas del Drag\243n.[ENTER]En antiguos escritos se las relaciona con una[ENTER]teocracia conocida como la Naci\243n Oscura.[ENTER]\191Pertenecer\237an esas siete Sacerdotisas del Drag\243n[ENTER]a la Naci\243n Oscura? Toma, lee este pergamino[ENTER]atentamente y habla conmigo cuando termines. "
gameforge.main_quest_lv60._60_sendLetter = "La Naci\243n Oscura I "
gameforge.main_quest_lv60._70_say = "Seg\250n la investigaci\243n de Uriel, las siete[ENTER]Sacerdotisas del Drag\243n proced\237an de la Naci\243n[ENTER]Oscura. Investiga la L\225pida Antigua en el Monte[ENTER]Sohan. Se dice que all\237 se encontraba la capital[ENTER]de la Naci\243n Oscura. Habla antes con Uriel una[ENTER]vez m\225s. "
gameforge.main_quest_lv60._80_say = "Sus artes m\225gicas extremadamente avanzadas y el[ENTER]hecho de que fueran aniquiladas seg\250n el diario[ENTER]de Lee Seop indican que las siete Sacerdotisas[ENTER]del Drag\243n realmente pertenec\237an a la Naci\243n[ENTER]Oscura. "
gameforge.main_quest_lv60._90_say = "En los antiguos pergaminos hay un mapa. Al[ENTER]examinarlo atentamente se puede ver que la[ENTER]capital de la Naci\243n Oscura realmente se[ENTER]encontraba en el Monte Sohan. "
gameforge.main_quest_lv66 = {}
gameforge.main_quest_lv66._100_say = "\161Es asombroso! \191Te das cuenta de lo que esto[ENTER]implica? En la Torre Demon\237aca antes no hab\237a[ENTER]demonios ni fantasmas. Son el legado de la[ENTER]Sacerdotisa del Drag\243n. En su desesperado intento[ENTER]de acabar con la caballer\237a de Lee Seop, abri\243 a[ENTER]los demonios la puerta a nuestro mundo con ese[ENTER]oscuro ritual maldito. Al final, pag\243 por ello[ENTER]con su vida. "
gameforge.main_quest_lv66._10_sendLetter = "El diario "
gameforge.main_quest_lv66._110_say = "El Segador de la Muerte y sus seguidores[ENTER]demon\237acos accedieron tambi\233n a nuestro mundo de[ENTER]esa manera. Sin embargo, la gran misi\243n de las[ENTER]Sacerdotisas del Drag\243n y de la Naci\243n Oscura[ENTER]fracas\243: la invocaci\243n de Sung Mahi no tuvo lugar[ENTER]y Lee Seop lleg\243 al poder y logr\243 unificar el[ENTER]reino.[ENTER][ENTER]\161Gracias a ti he conseguido desvelar el mayor[ENTER]misterio de toda mi vida! "
gameforge.main_quest_lv66._120_say = "Como recompensa me gustar\237a darte un Pergamino[ENTER]Bendici\243n. \161Por favor, acepta mi regalo, te lo[ENTER]has ganado! "
gameforge.main_quest_lv66._130_sendLetter = "Tienes correo. "
gameforge.main_quest_lv66._140_say = "El guardi\225n del pueblo tiene una carta para ti.[ENTER]L\233ela y descubre qui\233n es el misterioso remitente. "
gameforge.main_quest_lv66._150_say = "\218ltimamente no se te ha visto el pelo, \191eh? Me[ENTER]han dicho que te entregue esta carta. Ni idea de[ENTER]qui\233n te la env\237a; no me dijo su nombre. "
gameforge.main_quest_lv66._160_say = "El papel en el que est\225 escrita la carta parece[ENTER]muy viejo. En ella, alguien ha escrito[ENTER]apresuradamente:[ENTER]Tengo informaci\243n importante sobre las siete[ENTER]Sacerdotisas del Drag\243n y Sung Mahi. Te estar\233[ENTER]esperando en la parte de atr\225s de la Torre del[ENTER]Demonio del Templo Hwang. Podr\225s encontrarme en[ENTER]la sombra del \225rbol. \161Date prisa, el tiempo[ENTER]apremia! "
gameforge.main_quest_lv66._170_sendLetter = "Carta an\243nima "
gameforge.main_quest_lv66._180 = "Ve al Templo Hwang y encu\233ntrate con el[ENTER]misterioso remitente detr\225s de la Torre[ENTER]Demon\237aca. "
gameforge.main_quest_lv66._190_sayTitle = "Lee Chung "
gameforge.main_quest_lv66._200_say = "\161Te doy la bienvenida! Perm\237teme que me presente:[ENTER]mi nombre es Lee Chung. Es muy osado por tu parte[ENTER]seguir las indicaciones de un desconocido. No me[ENTER]he equivocado contigo; y no te arrepentir\225s.[ENTER]\161Escucha lo que tengo que contarte! "
gameforge.main_quest_lv66._20_say = "Uriel tiene novedades sobre la \250ltima[ENTER]superviviente de las Sacerdotisas del Drag\243n. Su[ENTER]diario probablemente se encuentra en la Torre del[ENTER]Demonio. Habla con Uriel si quieres saber m\225s. "
gameforge.main_quest_lv66._210_sendLetter = "Un nuevo mal "
gameforge.main_quest_lv66._220_say = "Escucha lo que tiene que contarte Lee Chung. "
gameforge.main_quest_lv66._230_say = "Hay un motivo por el que te hice venir al Templo[ENTER]Hwang: \250ltimamente est\225n ocurriendo cosas[ENTER]extra\241as aqu\237. \161Adem\225s, hace poco hemos[ENTER]descubierto la entrada a una gigantesca cueva! "
gameforge.main_quest_lv66._240_say = "\191Una cueva gigante? \191Y qu\233 hay dentro? "
gameforge.main_quest_lv66._250_say = "En la cueva nos aguarda un mal inesperado e[ENTER]inimaginable: nuestros exploradores informan de[ENTER]un ser espeluznante capaz de hacerle sombra hasta[ENTER]a los demonios.[ENTER]Su temible aspecto y su sed insaciable de vidas[ENTER]nos hacen pensar que se trata del legendario[ENTER]Agwi: uno de los mayores demonios de su estirpe.[ENTER]Si resulta que tenemos raz\243n, la humanidad corre[ENTER]un grave peligro. "
gameforge.main_quest_lv66._260_say = "M\225s terrible a\250n que los demonios... esa criatura[ENTER]debe de ser realmente poderosa y malvada. "
gameforge.main_quest_lv66._270_say = "As\237 es. Mis hombres y yo hemos intentado varias[ENTER]veces asaltar la Catacumba del Diablo, pero todos[ENTER]y cada uno de nuestros intentos se han visto[ENTER]frustrados tras sufrir graves p\233rdidas.[ENTER]Para un problema de este calibre necesitamos el[ENTER]apoyo de un aut\233ntico guerrero. Por eso te hemos[ENTER]hecho llamar. \191Nos ayudar\225s? "
gameforge.main_quest_lv66._280_say = "S\237, te ayudar\233. "
gameforge.main_quest_lv66._290_say = "\161Oh, nos das nuevas esperanzas![ENTER]Bien, ahora que s\233 que est\225s de nuestra parte, te[ENTER]voy a revelar toda la verdad: Yo, Lee Chung, soy[ENTER]el comandante de los Guerreros de las Sombras.[ENTER]Somos una unidad de \233lite del ej\233rcito de Lee[ENTER]Seop. "
gameforge.main_quest_lv66._300_sayTitle = "Lee Chung "
gameforge.main_quest_lv66._30_say = "Ah, me alegro de verte de nuevo con buena salud.[ENTER]\191Quieres emprender tu pr\243xima aventura? Nos[ENTER]siguen faltando datos importantes sobre la Naci\243n[ENTER]Oscura y las siete Sacerdotisas del Drag\243n. La[ENTER]\250ltima de ellas debi\243 de esconder su diario en la[ENTER]Torre Demon\237aca antes de llevar a cabo la[ENTER]brujer\237a negra. Ponte en marcha y tr\225emelo.[ENTER]Quiz\225s el Rey Demonio lo tenga en su poder. "
gameforge.main_quest_lv66._310_say = "Los Guerreros de las Sombras perseguimos en[ENTER]secreto el objetivo de evitar la resurrecci\243n de[ENTER]Sung Mahi. Esa es nuestra misi\243n.[ENTER]\161Colaboremos para mandar al Agwi de vuelta a su[ENTER]guarida y para descubrir c\243mo pudo introducirse[ENTER]en nuestro mundo! "
gameforge.main_quest_lv66._320_sendLetter = "No hay tiempo "
gameforge.main_quest_lv66._330_say = "Lee Chung, el comandante de los Guerreros de las[ENTER]Sombras, te est\225 buscando. \161Es muy urgente! "
gameforge.main_quest_lv66._340_say = "Tengo una petici\243n urgente. \191Ves ese soldado[ENTER]herido de ah\237? Es uno de mis exploradores.[ENTER]Siguiendo mis \243rdenes estaba explorando la[ENTER]Catacumba del Diablo y el Agwi le atac\243 y le[ENTER]envenen\243. El veneno ya se est\225 extendiendo por su[ENTER]cuerpo y no le queda mucho tiempo. "
gameforge.main_quest_lv66._350_say = "\161Necesita un Ant\237doto, y tan pronto como sea[ENTER]posible! \191Podr\237as procur\225rselo? Puedes[ENTER]encontrarlo en el Bosque Rojo, donde las Dr\237adas[ENTER]Rojas.[ENTER]Es uno de mis guerreros m\225s importantes. Si le[ENTER]salvas la vida te dar\233 %s. "
gameforge.main_quest_lv66._360_say = "\161Te traer\233 el Ant\237doto! "
gameforge.main_quest_lv66._370_say = "\161Te lo agradezco mucho! Por el momento est\225 vivo,[ENTER]pero a cada minuto que pasa se encuentra m\225s[ENTER]d\233bil. \161No tenemos tiempo que perder! "
gameforge.main_quest_lv66._380_notice = "Te quedan %d minutos. "
gameforge.main_quest_lv66._390_sendLetter = "El ant\237doto "
gameforge.main_quest_lv66._400_say = "Lee Chung te ha dicho que puedes encontrar el[ENTER]Ant\237doto en el Bosque Rojo. Para ello, captura %d[ENTER]Dr\237adas Rojas.[ENTER][ENTER]En el Bosque Rojo hay peligros a\250n mayores que en[ENTER]el Bosque Fantasma, as\237 que ten cuidado. "
gameforge.main_quest_lv66._40_say = "Has vencido al Rey Demonio y le has arrebatado el[ENTER]diario de las Sacerdotisas del Drag\243n. Ll\233vaselo[ENTER]al sabio Uriel; \233l lo analizar\225. "
gameforge.main_quest_lv66._410_say = "Se ha terminado el tiempo. El soldado est\225 en su[ENTER]lecho de muerte, as\237 que ll\233vale el Ant\237doto. "
gameforge.main_quest_lv66._420_say = "Te quedan %d minutos. "
gameforge.main_quest_lv66._430_say = "\161Has encontrado el Ant\237doto por fin! Ll\233vaselo[ENTER]sin tardanza a Lee Chung. "
gameforge.main_quest_lv66._440_say = "\161Aqu\237, r\225pido! Creo que has llegado a tiempo. Me[ENTER]quitas un gran peso de encima. Mis hombres y yo[ENTER]te estaremos eternamente agradecidos. "
gameforge.main_quest_lv66._450_say = "Gracias a tu ayuda, mi soldado ha sobrevivido.[ENTER]Aqu\237 tienes tu recompensa por salvarlo. "
gameforge.main_quest_lv66._460_say = "Te ha llevado mucho tiempo. Se est\225 aferrando a[ENTER]su vida con sus \250ltimas fuerzas. Por suerte a\250n[ENTER]has llegado a tiempo. "
gameforge.main_quest_lv66._470_say = "Parece que se est\225 recuperando, pero ha faltado[ENTER]muy poco para que muriera porque tardaste[ENTER]demasiado en encontrar el Ant\237doto.[ENTER]Lo siento mucho, pero esto es todo lo que te[ENTER]puedo dar como recompensa. "
gameforge.main_quest_lv66._480_sendLetter = "El informe "
gameforge.main_quest_lv66._490_say = "Mi explorador ha vuelto en s\237.[ENTER]Escucha lo que tiene que contarte sobre la[ENTER]Catacumba del Diablo. "
gameforge.main_quest_lv66._500_say = "Gracias por salvarme. He visto cosas[ENTER]inimaginables en la Catacumba del Diablo. Pero[ENTER]entonces me descubrieron, y... "
gameforge.main_quest_lv66._50_say = "\161Lo has encontrado! El diario de la \250ltima[ENTER]Sacerdotisa del Drag\243n... mis manos tiemblan de[ENTER]emoci\243n.[ENTER]Voy a necesitar algo de tiempo para revisar todo[ENTER]su contenido. T\243mate un descanso mientras tanto.[ENTER]Te har\233 llamar cuando pueda decirte m\225s. "
gameforge.main_quest_lv66._510_say = "\191Qu\233 es lo que viste? "
gameforge.main_quest_lv66._520_say = "Vi a unos encapuchados con t\250nicas negras. Seg\250n[ENTER]lo que pude o\237r de sus conversaciones, se trata[ENTER]de los Servidores de la oscuridad. Pero eso no es[ENTER]todo: Sobre sus cabezas flotaba un esp\237ritu[ENTER]terrible con aspecto de mujer, al que los[ENTER]Servidores de la oscuridad llamaban Banshee. "
gameforge.main_quest_lv66._530_say = "Es no suena nada mal. \191Qu\233 se propondr\225n los[ENTER]Servidores de la oscuridad y esa Banshee? "
gameforge.main_quest_lv66._540_say = "La Banshee invoc\243 mediante un tenebroso hechizo a[ENTER]los Agwi, criaturas demon\237aca que provienen[ENTER]directamente de las profundidades del infierno.[ENTER]Llamaba Azrael al rey de los Agwi. "
gameforge.main_quest_lv66._550_say = "Iba a informar enseguida al comandante, pero me[ENTER]tropec\233 y fui descubierto.[ENTER][ENTER]Ah, ahora que me acuerdo, Lee Chung quiere[ENTER]comunicarte algo importante. Ser\225 mejor que vayas[ENTER]a hablar con \233l. "
gameforge.main_quest_lv66._560_sendLetter = "Una oscura amenaza "
gameforge.main_quest_lv66._570_say = "Ve con Lee Chung y habla con \233l acerca de la[ENTER]nueva amenaza que acecha en la Catacumba del[ENTER]Diablo. "
gameforge.main_quest_lv66._580_say = "Lo que cuenta mi explorador es aterrador,[ENTER]\191verdad? Los Servidores de la oscuridad, una[ENTER]especie de secta, son los responsables de la[ENTER]aparici\243n de los Agwi. Y tambi\233n han despertado[ENTER]al esp\237ritu de la \250ltima Sacerdotisa del Drag\243n.[ENTER]Ha retornado a este mundo como una Banshee, una[ENTER]manifestaci\243n del mal, y gracias a sus poderes[ENTER]m\225gicos ha invocado al dios demon\237aco Sung Mahi. "
gameforge.main_quest_lv66._590_say = "\191C\243mo? \191Esa Banshee es el fantasma de la \250ltima[ENTER]Sacerdotisa del Drag\243n? "
gameforge.main_quest_lv66._600_say = "Sin duda alguna. Solamente ella, de entre todas[ENTER]sus hermanas del culto del Drag\243n, pose\237a el[ENTER]poder de invocar a los cuatro Guardianes[ENTER]Celestiales sagrados y llevar a cabo la brujer\237a[ENTER]negra. Ahora sabemos qui\233n se encuentra detr\225s de[ENTER]esta nueva amenaza: \161Los Servidores de la[ENTER]oscuridad y la Banshee planean llevar a t\233rmino[ENTER]los tenebrosos planes de la Naci\243n Oscura y[ENTER]despertar a Sung Mahi! "
gameforge.main_quest_lv66._60_sendLetter = "La soluci\243n del enigma "
gameforge.main_quest_lv66._610_say = "Tenemos mucho que agradecerte: Le has salvado la[ENTER]vida a uno de mis mejores hombres y as\237 pudimos[ENTER]enterarnos de todo lo relacionado con la[ENTER]aparici\243n repentina de los Agwi y la nueva[ENTER]amenaza que acecha en la Catacumba del Diablo.[ENTER]Ahora t\243mate un descanso. Despu\233s elaboraremos un[ENTER]plan de ataque. "
gameforge.main_quest_lv66._620_say = "La aventura continuar\225 en cuanto alcances el[ENTER]nivel 72. "
gameforge.main_quest_lv66._70_say = "Uriel te est\225 buscando. Ya ha le\237do el diario. "
gameforge.main_quest_lv66._80_say = "\161Ah, muy bien, has venido![ENTER]Las notas de la \250ltima Sacerdotisa del Drag\243n son[ENTER]realmente asombrosas. Escucha esto: "
gameforge.main_quest_lv66._90_say = "\161Mi destino est\225 sellado! Me he atrincherado en[ENTER]el \250ltimo piso de esta torre, y los hombres de[ENTER]Lee Seop est\225n a punto de echar abajo la puerta[ENTER]de mi prisi\243n final. No hay salida alguna... he[ENTER]perdido.[ENTER][ENTER]\161No, esto no puede terminar as\237! Puede que no[ENTER]todo est\233 perdido. Debo invocar yo sola el poder[ENTER]de la brujer\237a negra, ese poder arcano del mal, y[ENTER]atraer a los poderes de la oscuridad.[ENTER]Eso conllevar\225 sin duda alguna mi muerte, pero me[ENTER]llevar\233 a mis enemigos conmigo... \161aunque sea lo[ENTER]\250ltimo que haga! "
gameforge.main_quest_lv7 = {}
gameforge.main_quest_lv7._100_say = "\191Qu\233? \191No la has entregado todav\237a? La Ca\241a de[ENTER]Pescar es para el Pescador del r\237o. Date prisa,[ENTER]\161la necesita urgentemente! "
gameforge.main_quest_lv7._10_targetVid = "Otro favor "
gameforge.main_quest_lv7._110_npcChat = "\161El Herrero te env\237a esta nueva ca\241a! "
gameforge.main_quest_lv7._120_say = "Gracias. Ahora al fin puedo librarme de mi leal[ENTER]pero bastante usada Ca\241a de Pescar.[ENTER]No s\243lo vivo de la pesca, \161pero es una de las[ENTER]mayores alegr\237as de mi vida![ENTER]\191Sabes algo sobre la pesca? "
gameforge.main_quest_lv7._130_say = "Primero, coge la ca\241a de pescar. Pon un cebo en[ENTER]el anzuelo. Entonces l\225nzalo usando tu habilidad[ENTER]de pesca. Si notas que ha picado un pez (burbuja[ENTER]de pensamiento), usa tu habilidad de nuevo. O[ENTER]funciona o tendr\225s que intentarlo de nuevo. Hay[ENTER]muchos peces que puedes capturar. La pesca es[ENTER]buena para tu salud y, a veces, recoges tesoros[ENTER]valiosos. \161As\237 que int\233ntalo si tienes algo de[ENTER]tiempo libre! "
gameforge.main_quest_lv7._140_say = "Oh s\237, aqu\237 est\225 el pago por la ca\241a de pescar.[ENTER]Por favor, ll\233vaselo al herrero. "
gameforge.main_quest_lv7._150_sayItem = "Pago por la ca\241a de pescar "
gameforge.main_quest_lv7._160_sayReward = "Has entregado la ca\241a de pescar al pescador.[ENTER]Vuelve con el herrero con el pago y obtendr\225s tu[ENTER]recompensa. "
gameforge.main_quest_lv7._170_say = "\191Has encontrado al pescador?[ENTER]Fant\225stico. Bien, has ahorrado mi valioso tiempo[ENTER]haciendo esa entrega. Como recompensa, voy a[ENTER]darte algo de Yang y 1500 puntos de experiencia. "
gameforge.main_quest_lv7._180_sendLetter = "Un vale por una mejora "
gameforge.main_quest_lv7._190_sayReward = "Con este vale, el herrero mejorar\225 gratis una[ENTER]parte de tu armadura. Coge una parte de tu[ENTER]armadura y arr\225strala sobre el herrero para abrir[ENTER]la ventana de mejora. "
gameforge.main_quest_lv7._200_sayItem = "Vale por una mejora gratis "
gameforge.main_quest_lv7._20_sayReward = "Por favor, ve con el herrero. Necesita a alguien[ENTER]para hacer una entrega. "
gameforge.main_quest_lv7._210_sayTitle = "Pista: "
gameforge.main_quest_lv7._220_sayReward = "1) El justificante no se mostrar\225 en el[ENTER]inventario.[ENTER]2) Al igual que con cualquier otro tipo de[ENTER]mejora, no se puede garantizar al 100% el \233xito[ENTER]de un refinamiento. "
gameforge.main_quest_lv7._230_sayTitle = "El vale ya ha sido usado. "
gameforge.main_quest_lv7._240_sayReward = "Ya has usado el vale por un refinamiento[ENTER]gratuito. Solamente es v\225lido para un proceso de[ENTER]refinamiento. "
gameforge.main_quest_lv7._30_say = "\161Eh, aventurero! \191Podr\237as hacerme otro favor?[ENTER]Normalmente, no le pido a otros que hagan las[ENTER]cosas por m\237, pero pareces de confianza. \161Piensa[ENTER]en ello como un honor! "
gameforge.main_quest_lv7._40_say = "Hice una ca\241a de pescar para el pescador pero,[ENTER]desafortunadamente, estoy muy ocupado. No tengo[ENTER]tiempo de llev\225rsela yo mismo. \191Podr\237as hacer eso[ENTER]por m\237? "
gameforge.main_quest_lv7._50_sayItem = "Una ca\241a de pescar muy flexible "
gameforge.main_quest_lv7._60_say = "El pescador debe estar en alguna parte del r\237o.[ENTER]Si entregas la ca\241a de pescar al pescador,[ENTER]mejorar\233 gratis una parte de tu armadura.[ENTER]Es un trato justo, \191no crees? "
gameforge.main_quest_lv7._70_sendLetter = "Encuentra al Pescador "
gameforge.main_quest_lv7._80_sayReward = "El herrero hizo una ca\241a de pescar para el[ENTER]pescador. Encuentra por el r\237o al pescador y dale[ENTER]la nueva ca\241a de pescar. "
gameforge.main_quest_lv7._90_npcChat = "\191Para qui\233n es la Ca\241a de Pescar? "
gameforge.main_quest_lv72 = {}
gameforge.main_quest_lv72._100_say = "El brillo de la L\225grima Celestial se consigue[ENTER]uniendo m\225gicamente Resina Bendecida, Esencia de[ENTER]Cristal Azul y Cuarzo Rojo Infernal.[ENTER]Solo el monarca de la Tierra de hielo puede[ENTER]conseguir la Esencia de Cristal Azul. "
gameforge.main_quest_lv72._10_sendLetter = "Losa Deteriorada "
gameforge.main_quest_lv72._110_say = "Has hecho una copia de esta reveladora[ENTER]inscripci\243n.[ENTER]Informa inmediatamente a Lee Chung acerca de lo[ENTER]que acabas de leer. "
gameforge.main_quest_lv72._120_say = "\161Has regresado, y sin un solo rasgu\241o! Por tu[ENTER]expresi\243n yo dir\237a que has tenido \233xito. \191Me[ENTER]equivoco? "
gameforge.main_quest_lv72._130_say = "\161No, en absoluto! Gracias a la inscripci\243n de la[ENTER]Losa Deteriorada he descubierto que se pueden[ENTER]invocar los poderes sagrados mediante una piedra[ENTER]m\225gica conocida como L\225grima Celestial. "
gameforge.main_quest_lv72._140_say = "La L\225grima Celestial... As\237 que existe de verdad.[ENTER]\191Has podido descubrir c\243mo conseguirla? "
gameforge.main_quest_lv72._150_say = "Para poder fabricar la L\225grima Celestial hace[ENTER]falta Resina Bendecida, Esencia de Cristal Azul y[ENTER]Cuarzo Rojo Infernal. Seg\250n estaba escrito, la[ENTER]Esencia de Cristal Azul se puede conseguir del[ENTER]monarca de la Tierra de hielo. "
gameforge.main_quest_lv72._160_say = "\191El monarca de la Tierra de hielo? Hmmm... Se[ENTER]referir\225 al Monte Sohan.[ENTER]Le voy a mostrar tus notas a los magos de los[ENTER]Guerreros de las Sombras para que me den su[ENTER]opini\243n sobre ellas.[ENTER]\161Te avisar\233 en cuanto sepa m\225s! "
gameforge.main_quest_lv72._170_say = "Toma esto como recompensa por todo lo que has[ENTER]hecho. \161Sigo contando con tu ayuda! "
gameforge.main_quest_lv72._180_sendLetter = "Tesoro g\233lido "
gameforge.main_quest_lv72._190_say = "El comandante Lee Chung te ha comunicado que el[ENTER]primer elemento necesario para fabricar la[ENTER]L\225grima Celestial, la Esencia de Cristal Azul, se[ENTER]debe de tratar del legendario tesoro de Nueve[ENTER]Colas del Monte Sohan.[ENTER]Lo vigilan atentamente Golems de Hielo, Yetis y[ENTER]Hombres de Hielo Glaciales. Da caza a esos[ENTER]monstruos para hacerte con la codiciada Esencia[ENTER]de Cristal Azul.[ENTER]Habla de nuevo con Lee Chung antes de lanzarte a[ENTER]la batalla. "
gameforge.main_quest_lv72._200_say = "Los magos de los Guerreros de las Sombras han[ENTER]descubierto que el temible Nueve Colas del Monte[ENTER]Sohan guarda la Esencia de Cristal Azul como oro[ENTER]en pa\241o. "
gameforge.main_quest_lv72._20_say = "Lee Chung, el comandante de los Guerreros de las[ENTER]Sombras, quiere hablar contigo. Ha descubierto[ENTER]c\243mo vencer a los Agwi de la Catacumba del[ENTER]Diablo. "
gameforge.main_quest_lv72._210_say = "Golems de Hielo, Yetis y Hombres de Hielo[ENTER]Glaciales custodian el tesoro de Nueve Colas.[ENTER][ENTER]Se necesitan 50 Esencias de Cristal Azul para[ENTER]fabricar la L\225grima Celestial. "
gameforge.main_quest_lv72._220_say = "Se cree que el Cuarzo Rojo Infernal se puede[ENTER]encontrar o bien en el Templo Hwang o bien en la[ENTER]Tierra de Fuego.[ENTER]He enviado a un explorador para que investigue[ENTER]m\225s. "
gameforge.main_quest_lv72._230 = "El comandante Lee Chung te ha comunicado que el[ENTER]primer elemento necesario para fabricar la[ENTER]L\225grima Celestial, la Esencia de Cristal Azul, se[ENTER]debe de tratar del legendario tesoro de Nueve[ENTER]Colas del Monte Sohan.[ENTER]Lo vigilan atentamente Golems de Hielo, Yetis y[ENTER]Hombres de Hielo Glaciales. Da caza a esos[ENTER]monstruos para hacerte con la codiciada Esencia[ENTER]de Cristal Azul. "
gameforge.main_quest_lv72._240_notice = "Registras el cad\225ver del monstruo derrotado y[ENTER]descubres una piedra preciosa que refulge con un[ENTER]brillo azulado.[ENTER]Esta debe de ser la Esencia de Cristal Azul. "
gameforge.main_quest_lv72._250_notice = "A\250n tienes que encontrar %d Esencia(s) de Cristal[ENTER]Azul. "
gameforge.main_quest_lv72._260_say = "Por hoy ya has recibido suficiente consejo.[ENTER]Vuelve ma\241ana. "
gameforge.main_quest_lv72._270_say = "Estos cristales no valen para nada. Mira, f\237jate:[ENTER]tienen fisuras. Para poder utilizarlas no pueden[ENTER]tener m\225cula. \161Sigue buscando! "
gameforge.main_quest_lv72._280_say = "Estas son de gran calidad. \161Sigue as\237! Tr\225eme %d[ENTER]m\225s. "
gameforge.main_quest_lv72._290_say = "Has reunido todas las Esencias de Cristal Azul.[ENTER]Puedo sentir el poder de Nueve Colas que[ENTER]contienen. Es incre\237ble... vibran llenas de[ENTER]energ\237a. \161Bien hecho! "
gameforge.main_quest_lv72._300_say = "La aventura continuar\225 en cuanto alcances el[ENTER]nivel 78. "
gameforge.main_quest_lv72._30_say = "A diferencia de los demonios normales, los Agwi[ENTER]no son tan sencillos de matar. Los Guerreros de[ENTER]las Sombras lo hemos intentado todo, pero hasta[ENTER]ahora sin \233xito. "
gameforge.main_quest_lv72._40_say = "Sin embargo, he descubierto que las Sacerdotisas[ENTER]del Drag\243n pose\237an la habilidad de invocar a los[ENTER]poderes sagrados para mantener a raya a los[ENTER]esp\237ritus malignos. "
gameforge.main_quest_lv72._50_say = "En el Bosque Rojo hab\237a anta\241o uno de los templos[ENTER]sagrados de las Sacerdotisas del Drag\243n. Busca[ENTER]all\237 sus ruinas y se\241ales de su culto. Mis[ENTER]exploradores me han hablado de una Losa[ENTER]Deteriorada cubierta de matojos... Quiz\225s nos[ENTER]sirva para encontrar nuevas pistas. "
gameforge.main_quest_lv72._60_sendLetter = "El descubrimiento "
gameforge.main_quest_lv72._70_say = "Lee Chung te ha contado que las Sacerdotisas del[ENTER]Drag\243n eran capaces de invocar a los poderes[ENTER]sagrados; una magia antigua capaz de contener a[ENTER]esp\237ritus malvados.[ENTER]Busca la Losa Deteriorada del Bosque Rojo sobre[ENTER]la que te habl\243 Lee Chung para reunir m\225s pistas. "
gameforge.main_quest_lv72._80_say = "Tras una larga b\250squeda te has topado con una[ENTER]loseta de piedra que parece haber estado aqu\237[ENTER]desde hace siglos. \161Esta tiene que ser la antigua[ENTER]estela de la que hablaba Lee Chung![ENTER]Descifras laboriosamente la desfigurada[ENTER]inscripci\243n. "
gameforge.main_quest_lv72._90_say = "Las L\225grimas Celestiales son el secreto m\225s[ENTER]preciado de las Sacerdotisas del Drag\243n. Desde[ENTER]hace generaciones el arte de su fabricaci\243n se[ENTER]protege celosamente y, si es necesario, con la[ENTER]propia vida.[ENTER]Ni los Agwi ni los demonios se pueden acercar sin[ENTER]m\225s a quien porte una de estas piedras preciosas[ENTER]m\225gicas. Una vez repleta de la energ\237a de los[ENTER]poderes sagrados, los efectos de la L\225grima[ENTER]Celestial son devastadores. Brilla con el fulgor[ENTER]de la Estrella Polar a lo largo de siete soles. "
gameforge.main_quest_lv78 = {}
gameforge.main_quest_lv78._100_say = "\161Ah, fant\225stico! Ha funcionado. Aqu\237 tienes tu[ENTER]Cuarzo Rojo Infernal. "
gameforge.main_quest_lv78._10_sendLetter = "Cuarzo Rojo Infernal "
gameforge.main_quest_lv78._110_sendLetter = "El \250ltimo elemento "
gameforge.main_quest_lv78._120_say = "Lee Chung y el consejo de magos han descubierto[ENTER]que el \250ltimo elemento, la Resina Bendecida, se[ENTER]extrae de los \193rboles Diab\243licos Rojos. Caza unos[ENTER]cuantos en el Bosque Rojo y re\250ne 100 trozos de[ENTER]Resina Bendecida.[ENTER]Antes de nada, habla una vez m\225s con Lee Chung. "
gameforge.main_quest_lv78._130_say = "Lee Chung y el consejo de magos han descubierto[ENTER]que el \250ltimo elemento, la Resina Bendecida, se[ENTER]extrae de los \193rboles Diab\243licos Rojos. Caza unos[ENTER]cuantos en el Bosque Rojo y re\250ne 100 trozos de[ENTER]Resina Bendecida. "
gameforge.main_quest_lv78._140_say = "Este es el \250ltimo paso necesario para fabricar la[ENTER]L\225grima Celestial. \161Ten mucho cuidado, pues el[ENTER]Bosque Rojo est\225 plagado de criaturas mort\237feras! "
gameforge.main_quest_lv78._150_say = "A\250n tienes que conseguir %d trozo(s) de Resina[ENTER]Bendecida. "
gameforge.main_quest_lv78._160_notice = "\161Has encontrado suficiente Resina Bendecida![ENTER]Ll\233vasela al comandante Lee Chung. "
gameforge.main_quest_lv78._170_say = "\191As\237 que esta es la Resina Bendecida? Puedo[ENTER]sentir su enorme poder. \161Fabuloso![ENTER]Por desgracia me he visto obligado a mandar a[ENTER]todos nuestros magos a cumplir una misi\243n y van a[ENTER]estar fuera un tiempo. \191No hay un boticario en tu[ENTER]ciudad llamado Baek-Go? "
gameforge.main_quest_lv78._180_say = "S\237, en efecto. "
gameforge.main_quest_lv78._190_say = "\161Ah, estupendo! Entonces ll\233vale los tres[ENTER]elementos. \201l seguramente sepa elaborar la[ENTER]L\225grima Celestial. "
gameforge.main_quest_lv78._200_say = "Te aguarda un viaje agotador. Por favor, toma[ENTER]esta recompensa por las molestias. "
gameforge.main_quest_lv78._20_say = "Lee Chung, el comandante de los Guerreros de las[ENTER]Sombras, ha descubierto m\225s acerca del Cuarzo[ENTER]Rojo Infernal. Para fabricarlo se necesitan tres[ENTER]sustancias diferentes: Tierra Volc\225nica de[ENTER]Doyyumhwan, Melena Llameante y Piedra Fundaci\243n.[ENTER]Da caza a Llamas, Guerreros Llama y Tigres[ENTER]Luchadores para conseguirlas y crea con ellas 20[ENTER]unidades del Cuarzo Rojo Infernal.[ENTER]Habla de nuevo con Lee Chung antes de lanzarte a[ENTER]la batalla. "
gameforge.main_quest_lv78._210_sendLetter = "L\225grima Celestial "
gameforge.main_quest_lv78._220_say = "Vuelve a tu ciudad natal, busca a Baek-Go y[ENTER]p\237dele en nombre de Lee Chung que fabrique la[ENTER]L\225grima Celestial a partir de los tres elementos. "
gameforge.main_quest_lv78._230_say = "Has estado ausente mucho tiempo. Ya comenzaba a[ENTER]preguntarme si te habr\237a pasado algo. \191Qu\233 te[ENTER]trae hasta aqu\237? "
gameforge.main_quest_lv78._240_say = "Lee Chung me ha pedido que te pida un favor. "
gameforge.main_quest_lv78._250_say = "\161\191Lee Chung?! El comandante de los Guerreros de[ENTER]las So... oh, \161shhhh! \161Silencio! Tienes ante ti a[ENTER]un mago de los Guerreros de las Sombras. Pero eso[ENTER]es un gran secreto, y nadie de aqu\237 puede[ENTER]enterarse. Entonces, \191qu\233 me quiere pedir Lee[ENTER]Chung? "
gameforge.main_quest_lv78._260_say = "Quiere que fabriques una L\225grima Celestial a[ENTER]partir de estos tres elementos. "
gameforge.main_quest_lv78._270_say = "La L\225grima Celestial; vaya, vaya... Con la de[ENTER]magos que tiene, y va y me manda a m\237 siempre las[ENTER]tareas m\225s dif\237ciles.[ENTER]...[ENTER]En fin, vamos all\225. La L\225grima Celestial.[ENTER]\161Maravilloso! Enviar\233 a un mensajero directamente[ENTER]a Lee Chung y \233l te har\225 llamar en cuanto todo[ENTER]est\233 dispuesto.[ENTER]\191Me podr\237as decir para qu\233 la queremos? "
gameforge.main_quest_lv78._280_say = "No puedo darte detalles. Solamente lo siguiente:[ENTER]esta piedra invoca a los poderes sagrados para[ENTER]mantener alejados a demonios y otros seres[ENTER]malvados. "
gameforge.main_quest_lv78._290_say = "Muy interesante. Te deseo mucho \233xito con tus[ENTER]tareas. Como recompensa por el trabajo realizado,[ENTER]aqu\237 tienes dos Cabezas reducidas.[ENTER]Ahora que s\233 c\243mo se hace puedo fabricarte una[ENTER]L\225grima Celestial en cuanto la necesites.[ENTER]Ah, y m\225ndale mis mejores saludos a Lee Chung en[ENTER]cuanto lo veas. "
gameforge.main_quest_lv78._300_say = "La aventura continuar\225 en cuanto alcances el[ENTER]nivel 84. "
gameforge.main_quest_lv78._30_say = "Nuestros magos han descubierto que el Cuarzo Rojo[ENTER]Infernal, necesario para la fabricaci\243n de la[ENTER]L\225grima Celestial, contiene la fuerza del fuego.[ENTER]Ese Cuarzo, por tanto, debe de ser la fuente del[ENTER]incre\237ble poder de las criaturas de la Tierra de[ENTER]Fuego. "
gameforge.main_quest_lv78._40_say = "El Cuarzo Rojo Infernal se fabrica a partir de[ENTER]tres sustancias: Tierra Volc\225nica, Melena[ENTER]Llameante y Piedra Fundaci\243n. Puedes encontrarlas[ENTER]todas en la Tierra de Fuego. "
gameforge.main_quest_lv78._50_say = "\161Lo has conseguido! Por fin tenemos todas las %d[ENTER]unidades del Cuarzo Rojo Infernal que[ENTER]necesitamos. \161Tu valent\237a y tu fuerza no dejan de[ENTER]sorprenderme! "
gameforge.main_quest_lv78._60_say = "Falta una sustancia. Necesitamos Tierra[ENTER]Volc\225nica, Melenas Llameantes y Piedras[ENTER]Fundaci\243n. "
gameforge.main_quest_lv78._70_say = "Lo siento mucho, pero solamente puedo fabricar[ENTER]siete piezas de Cuarzo Rojo Infernal al d\237a. El[ENTER]procedimiento es un aut\233ntico desaf\237o para mis[ENTER]habilidades m\225gicas. \161A fin de cuentas no soy un[ENTER]mago! "
gameforge.main_quest_lv78._80_say = "\161Muy bien! Voy a mezclar las tres sustancias para[ENTER]intentar conseguir un Cuarzo Rojo Infernal. "
gameforge.main_quest_lv78._90_say = "\161Argh! La magia no tuvo efecto. Al parecer me he[ENTER]sobrestimado. La pr\243xima vez seguro que funciona. "
gameforge.main_quest_lv84 = {}
gameforge.main_quest_lv84._100_say = "una vez has derrotado al general T\225rtaro se abre[ENTER]el acceso a un nivel oculto de la Catacumba del[ENTER]Diablo. \161Ah\237 debe de estar Caronte! Telep\243rtate[ENTER]al sexto nivel y enfr\233ntate al temible pr\237ncipe[ENTER]Agwi. Pero cuidado: \161Es taimado como un diablo y[ENTER]incre\237blemente fuerte! "
gameforge.main_quest_lv84._10_sendLetter = "Comienza la batalla "
gameforge.main_quest_lv84._110_say = "A juzgar por la soltura y arrojo con los que te[ENTER]mueves por la Catacumba del Diablo, no puedes ser[ENTER]un mortal normal.[ENTER]El Obelisco de Basalto del quinto nivel sirve de[ENTER]portal al sexto. "
gameforge.main_quest_lv84._120_say = "Desde all\237, el pr\237ncipe Caronte imparte \243rdenes[ENTER]al general Agwi, T\225rtaro.[ENTER]\191A qu\233 esperas? \161Acaba con Caronte y frustra los[ENTER]espantosos planes de la Banshee y los Servidores[ENTER]de la oscuridad! "
gameforge.main_quest_lv84._130_sayReward = "\161Lo has conseguido! Caronte, el pr\237ncipe de los[ENTER]Agwi, ha sido abatido. "
gameforge.main_quest_lv84._140_say = "Te enjugas con alivio el sudor de la frente,[ENTER]fruto de tu extenuaci\243n.[ENTER]Pero s\250bitamente una espeluznante carcajada, tan[ENTER]penetrante que el coraz\243n te da un vuelco,[ENTER]resuena por la Catacumba del Diablo:[ENTER]\161Ja, ja, ja, ja ,ja! \161Demasiado tarde, pat\233ticos[ENTER]humanos! Nuestro se\241or Sung Mahi ya ha despertado[ENTER]y no pod\233is hacer nada para detenerlo.[ENTER]Pronto, Sung Mahi recuperar\225 todo su poder en la[ENTER]isla donde duermen los p\233rfidos dragones.[ENTER]\161Vuestro mundo est\225 condenado! "
gameforge.main_quest_lv84._150_sendLetter = "Un asunto inacabado "
gameforge.main_quest_lv84._160_say = "Ve a informar a Lee Chung sobre el mensaje[ENTER]amenazador de la Banshee. "
gameforge.main_quest_lv84._170_say = "Despu\233s de informar al comandante de tu victoria[ENTER]sobre T\225rtaro y Caronte, le transmites la[ENTER]inquietante advertencia de la Banshee. Frunciendo[ENTER]el ce\241o, comienza a hablar: "
gameforge.main_quest_lv84._180_say = "Esperaba que al vencer al pr\237ncipe de los Agwi[ENTER]lograr\237amos abortar tambi\233n los terribles planes[ENTER]de la Banshee y los Servidores de la oscuridad.[ENTER]Craso error... "
gameforge.main_quest_lv84._190_say = "Es de suponer que la Banshee y Azrael, el[ENTER]terrible rey de los Agwi, han logrado resucitar[ENTER]al dios demon\237aco Sung Mahi. Tiemblo s\243lo de[ENTER]imaginarlo. "
gameforge.main_quest_lv84._200_say = "La isla en la que duermen los p\233rfidos[ENTER]dragones... Hmm, seguramente se refer\237a al[ENTER]Pe\241asco del Drag\243n Oscuro, una isla inexplorada[ENTER]que est\225 muy lejos de aqu\237.[ENTER]Aunque no hayamos logrado lo que nos propon\237amos,[ENTER]te debemos mucho. Sin ti nunca habr\237amos podido[ENTER]descubrir la fuente de la calamidad que se estaba[ENTER]fraguando en las profundidades de la Catacumba[ENTER]del Diablo. "
gameforge.main_quest_lv84._20_say = "Lee Chung ha recibido la L\225grima Celestial y ha[ENTER]preparado todo para tu incursi\243n en la Catacumba[ENTER]del Diablo. Ve a hablar con \233l para saber m\225s. "
gameforge.main_quest_lv84._210_say = "Solamente t\250 habr\237as sido capaz de las incre\237bles[ENTER]haza\241as que has llevado a cabo. Siempre estar\233 a[ENTER]tu lado cuando me necesites. \161Cu\237date! "
gameforge.main_quest_lv84._30_say = "\161Ahora que tenemos en nuestro poder la L\225grima[ENTER]Celestial, derrotar a los Servidores de la[ENTER]oscuridad y expulsar de este mundo a los Agwi[ENTER]solo es cuesti\243n de tiempo![ENTER]Pero su poder completo solamente se libera cuando[ENTER]se activa en un lugar particular de la Catacumba[ENTER]del Diablo. "
gameforge.main_quest_lv84._40_say = "Conocemos cinco niveles en la Catacumba del[ENTER]Diablo. En el quinto y, por lo que sabemos,[ENTER]\250ltimo, te encontrar\225s con T\225rtaro, el despiadado[ENTER]general Agwi y tercero en la l\237nea de mando tras[ENTER]el rey Azrael y el pr\237ncipe Caronte. \161Acaba con[ENTER]\233l con la ayuda de la L\225grima Celestial! "
gameforge.main_quest_lv84._50_say = "\191Pero d\243nde se esconde el pr\237ncipe Caronte? "
gameforge.main_quest_lv84._60_sendLetter = "General T\225rtaro "
gameforge.main_quest_lv84._70_say = "Utiliza la L\225grima Celestial solo cuando hayas[ENTER]alcanzado el quinto nivel de la Catacumba del[ENTER]Diablo. La entrada a la Catacumba del Diablo est\225[ENTER]detr\225s de la Torre Demon\237aca. "
gameforge.main_quest_lv84._80_say = "Los poderes sagrados comienzan a actuar en la[ENTER]L\225grima Celestial. Sientes una energ\237a inmensa[ENTER]fluir por tu cuerpo. \161El poder de esta piedra es[ENTER]extraordinario![ENTER][ENTER]Acaba con el general T\225rtaro. "
gameforge.main_quest_lv84._90_sendLetter = "Pr\237ncipe Caronte "
gameforge.main_quest_lv9 = {}
gameforge.main_quest_lv9._10_targetVid = "Encuentra al Guardi\225n de la Ciudad "
gameforge.main_quest_lv9._20_sendLetter = "Habla con el Guardi\225n de la Ciudad "
gameforge.main_quest_lv9._30_sayReward = "Has dado los primeros pasos en el camino de[ENTER]convertirte en un h\233roe verdadero. Es tiempo para[ENTER]cosas m\225s grandes. Ve con el Guardi\225n de la[ENTER]Ciudad y obt\233n tu \250ltima misi\243n de principiante. "
gameforge.main_quest_lv9._40_say = "Creo que ya est\225s preparado para tareas m\225s[ENTER]duras. No ser\225n tan f\225ciles como las anteriores.[ENTER]Tienes que trabajar duro por el futuro de nuestro[ENTER]reino y vas a luchar en muchas batallas. Puede[ENTER]que a veces sufras, pero recuerda siempre[ENTER]permanecer alerta. Hasta ahora has completado[ENTER]algunas tareas. Como recompensa por tus[ENTER]esfuerzos, mereces un premio. Espero que lo[ENTER]encuentres \250til. "
gameforge.main_quest_lv9._50_say = "Desde ahora, el Capit\225n te guiar\225. Te supervisar\225[ENTER]en el futuro y te dar\225 algunas tareas. Re\250ne[ENTER]algunos puntos de experiencia m\225s y ve con el[ENTER]Capit\225n. \161Buena suerte! "
gameforge.main_quest_lv90 = {}
gameforge.main_quest_lv90._010_sendLetter = "Pe\241asco del Drag\243n Oscuro "
gameforge.main_quest_lv90._020_say = "Tu viaje ha sido largo y arduo. Pero finalmente[ENTER]alcanzaste tu objetivo: el Pe\241asco del Drag\243n[ENTER]Oscuro.[ENTER]Busca al Almirante Angmur. Lo podr\225s encontrar en[ENTER]el Cabo del Drag\243n de Fuego. "
gameforge.main_quest_lv90._030_say = "\161Bienvenido al Pe\241asco del Drag\243n Oscuro,[ENTER]extranjero! \191Has acudido para ayudarnos a luchar[ENTER]contra Sung Mahi? "
gameforge.main_quest_lv90._040_say = "S\237, en efecto. Me env\237a Lee Chung, el comandante[ENTER]de los Guerreros de las Sombras. "
gameforge.main_quest_lv90._050_say = "\161Lee Chung! Nuestra amistad se remonta a muchos[ENTER]a\241os atr\225s. As\237 que \233l te env\237a.[ENTER]De acuerdo, entonces s\233 que puedo confiar en ti. "
gameforge.main_quest_lv90._060_say = "Te lo agradezco. \191C\243mo est\225 la situaci\243n por aqu\237? "
gameforge.main_quest_lv90._070_say = "Los demonios dominan gran parte de la isla.[ENTER]Nada ni nadie est\225n a salvo de ellos. Incluso se[ENTER]devoran mutuamente. El influjo oscuro de Sung[ENTER]Mahi les ha trastornado a todos. "
gameforge.main_quest_lv90._080_say = "Tu ayuda me vendr\237a bien. \191Podr\237as explorar la[ENTER]isla y hacer un informe de la situaci\243n actual? "
gameforge.main_quest_lv90._090_say = "Por supuesto. "
gameforge.main_quest_lv90._1000_say = "De acuerdo. "
gameforge.main_quest_lv90._100_say = "Te lo agradezco. Espera, te mostrar\233 el camino. "
gameforge.main_quest_lv90._1010_say = "Est\225s trabajando mucho, pero desgraciadamente no[ENTER]basta.[ENTER]\161Sigue un poco m\225s! "
gameforge.main_quest_lv90._1020_sayTitle = "Reunir Tejas "
gameforge.main_quest_lv90._1030_say = "Combate contra las Mant\237coras para reunir Tejas. "
gameforge.main_quest_lv90._1040_1_notice = "has reunido suficientes Tejas. "
gameforge.main_quest_lv90._1040_2_notice = "Entr\233gaselas al Almirante Angmur. "
gameforge.main_quest_lv90._1050_say = "Habla con el Almirante Angmur. "
gameforge.main_quest_lv90._1060_say = "Muy bien, gracias a ti ahora tenemos suficientes[ENTER]materiales para reforzar el muro defensivo. En[ENTER]cuanto hayamos terminado te har\233 llamar de nuevo. "
gameforge.main_quest_lv90._1070_sendLetter = "El encargo de Lee Chung "
gameforge.main_quest_lv90._1080_say = "Lee Chung tiene un encargo que hacerte. "
gameforge.main_quest_lv90._1090_say = "Por desgracia, son malas noticias las que nos han[ENTER]reunido: los Servidores de la oscuridad se est\225n[ENTER]acercando a su objetivo. Pronto, Sung Mahi ser\225[ENTER]invencible.[ENTER]\161No hay tiempo que perder! Ve al[ENTER]teletransportador.[ENTER]Desde all\237 un barco te llevar\225 al Pe\241asco del[ENTER]Drag\243n Oscuro. Cuando llegues, busca al Almirante[ENTER]Angmur. Ya he enviado una carta anunciando tu[ENTER]llegada. "
gameforge.main_quest_lv90._1100_say = "Me pondr\233 enseguida en marcha. "
gameforge.main_quest_lv90._110_sayReward = "Explora el Pe\241asco del Drag\243n Oscuro.[ENTER]Ve primero aqu\237: (%d, %d). "
gameforge.main_quest_lv90._1110_sayTitle = "De camino a la isla "
gameforge.main_quest_lv90._1120_say = "Ve al teletransportador. A trav\233s de \233l podr\225s[ENTER]acceder al Pe\241asco del Drag\243n Oscuro. "
gameforge.main_quest_lv90._1160_targetInfo = "La flecha sobre el PNJ te indica que quiere[ENTER]hablar contigo. Si no ves al PNJ en tu pantalla,[ENTER]sigue el punto parpadeante en tu minimapa. "
gameforge.main_quest_lv90._1170_posInfo = "Sigue el punto parpadeante en el minimapa. "
gameforge.main_quest_lv90._1180_say = "(Restantes: %s %s, %s %s) "
gameforge.main_quest_lv90._1180_say_count = "Das Item bekommst du in kills "
gameforge.main_quest_lv90._1190_say = "%s: %d unidad/es "
gameforge.main_quest_lv90._1200_say = "La aventura continuar\225 en cuanto alcances el[ENTER]nivel 91. "
gameforge.main_quest_lv90._120_sayTitle = "Informe de situaci\243n "
gameforge.main_quest_lv90._130_say = "Echa un vistazo por la isla y despu\233s informa al[ENTER]Almirante Angmur. "
gameforge.main_quest_lv90._140_sayReward = "Este es tu primer objetivo: %d, %d "
gameforge.main_quest_lv90._150_sayReward = "Has alcanzado tu primer objetivo. El siguiente se[ENTER]encuentra en: (%d, %d) "
