gameforge.main_quest_lv90._220_sayReward = "Has explorado todas las zonas.[ENTER]Vuelve con el Almirante Angmur. "
gameforge.main_quest_lv90._230_say = "Habla con el Almirante Angmur. "
gameforge.main_quest_lv90._240_say = "Tras explorar toda la isla, algo te ha quedado[ENTER]claro: est\225 repleta de demonios. "
gameforge.main_quest_lv90._250_say = "Has hecho un buen trabajo. Toma esto como[ENTER]agradecimiento por tu ayuda. "
gameforge.main_quest_lv90._260_sendLetter = "Carta de Lee Chung "
gameforge.main_quest_lv90._270_say = "Seg\250n le relatas al Almirante Angmur lo que has[ENTER]descubierto sobre la situaci\243n en el Pe\241asco del[ENTER]Drag\243n Oscuro, su rostro se va ensombreciendo. "
gameforge.main_quest_lv90._280_say = "Me habr\237a gustado traerte mejores noticias. "
gameforge.main_quest_lv90._290_say = "Los demonios de la isla son cada vez m\225s fuertes.[ENTER]Si no podemos detener a Sung Mahi y a los[ENTER]Servidores de la oscuridad, que el Dios Drag\243n se[ENTER]apiade de nosotros. "
gameforge.main_quest_lv90._300_say = "S\237, reconozco que son algo l\250gubres. "
gameforge.main_quest_lv90._310_say = "S\237, t\250 lo has dicho... Lee Chung debe haber[ENTER]descubierto alguna pista decisiva. Me envi\243 una[ENTER]carta con informaci\243n vital, pero nunca me lleg\243.[ENTER]Los Gnoll atacaron al emisario. "
gameforge.main_quest_lv90._320_say = "Tenemos que encontrar esa carta. \191Podr\237as[ENTER]ayudarnos? "
gameforge.main_quest_lv90._330_say = "Por supuesto. Ahora mismo me pongo en camino. "
gameforge.main_quest_lv90._340_say = "Te lo agradezco. Los Gnolls acampan muy cerca de[ENTER]aqu\237. "
gameforge.main_quest_lv90._350_sayTitle = "Encuentra la Carta de Lee Chung. "
gameforge.main_quest_lv90._360_say = "Una de las siguientes criaturas posee la Carta de[ENTER]Lee Chung: Luchador Gnoll, Arquero Gnoll,[ENTER]Defensor Gnoll, Mago Gnoll, General Gnoll, Se\241or[ENTER]Gnoll o Guardia superior Gnoll. "
gameforge.main_quest_lv90._370_say = "\161Si queremos detener a Sung Mahi, necesitamos esa[ENTER]carta! El ladr\243n pertenece a la tribu de los[ENTER]Gnoll. "
gameforge.main_quest_lv90._380_1_notice = "Has encontrado la Carta. "
gameforge.main_quest_lv90._380_2_notice = "Ll\233vasela al Almirante Angmur. "
gameforge.main_quest_lv90._390_say = "Habla con el Almirante Angmur. "
gameforge.main_quest_lv90._400_say = "Has vuelto... \161y traes la carta! S\237, sab\237a que[ENTER]pod\237a confiar en ti. Ens\233\241amela. "
gameforge.main_quest_lv90._410_say = "\161Saludos, Angmur![ENTER]Amigo m\237o, en los campamentos abandonados de Sung[ENTER]Mahi hemos descubierto que los Servidores de la[ENTER]oscuridad les han hecho llegar comunicados[ENTER]secretos a sus aliados de la isla.[ENTER]Una de las cartas estaba dirigida a la tribu de[ENTER]los Gnoll. \161Si pudierais interceptarla le[ENTER]llevar\237amos una ventaja importante a los[ENTER]demonios![ENTER]Os env\237o a %s como apoyo y os deseo mucho valor y[ENTER]fuerzas en estos tiempos sombr\237os.[ENTER]L.C. "
gameforge.main_quest_lv90._420_say = "Mis esp\237as nos dir\225n si los Gnolls ya han[ENTER]recibido la carta. Entretanto, toma esto como[ENTER]agradecimiento. "
gameforge.main_quest_lv90._430_sendLetter = "La carta para los Gnolls I "
gameforge.main_quest_lv90._440_say = "El Almirante Angmur te est\225 buscando.[ENTER]Ve a ver qu\233 necesita. "
gameforge.main_quest_lv90._450_say = "El General gnoll ya ha recibido la carta de los[ENTER]Servidores de la oscuridad. \191Podr\237as[ENTER]arrebat\225rsela? Ten cuidado: los Gnolls son[ENTER]extremadamente agresivos. Atacan primero y[ENTER]despu\233s preguntan. "
gameforge.main_quest_lv90._460_say = "Voy para all\225. "
gameforge.main_quest_lv90._470_say = "Gracias. Sab\237a que pod\237amos confiar en ti. "
gameforge.main_quest_lv90._480_sayTitle = "\161Encuentra la Carta a los gnolls! "
gameforge.main_quest_lv90._490_say = "Encuentra al General Gnoll. \161\201l tiene la Carta! "
gameforge.main_quest_lv90._500_say = "No hay tiempo que perder. Por favor, date prisa y[ENTER]tr\225eme la carta. "
gameforge.main_quest_lv90._510_1_notice = "Has recibido la Carta a los gnolls. "
gameforge.main_quest_lv90._510_2_notice = "Ll\233vasela al Almirante Angmur. "
gameforge.main_quest_lv90._520_say = "Habla con el Almirante Angmur. "
gameforge.main_quest_lv90._530_say = "\161Tienes la Carta! Por fin buenas noticias.[ENTER]Hm...[ENTER]No puedo leer ni una palabra. Parece que la carta[ENTER]est\225 cifrada.[ENTER]Nuestro sabio est\225 versado en criptolog\237a. Voy a[ENTER]llamarle inmediatamente. En cuanto sepa m\225s te[ENTER]avisar\233. "
gameforge.main_quest_lv90._540_say = {}
gameforge.main_quest_lv90._550_say = {}
gameforge.main_quest_lv90._560_sendLetter = "La carta para los Gnolls II "
gameforge.main_quest_lv90._570_say = "El Almirante Angmur te est\225 buscando, y parece[ENTER]que es importante. Ve a ver qu\233 necesita. "
gameforge.main_quest_lv90._580_say = "La carta cifrada tiene dos partes. Solamente se[ENTER]puede descifrar superponiendo ambas. El Se\241or[ENTER]gnoll posee la segunda hoja; \191podr\237as ayudarnos a[ENTER]conseguirla? "
gameforge.main_quest_lv90._590_say = "Por supuesto. "
gameforge.main_quest_lv90._600_say = "Gracias. \161Tu ayuda es inestimable! "
gameforge.main_quest_lv90._610_sayTitle = "La carta para los Gnolls II "
gameforge.main_quest_lv90._620_say = "\161Encuentra la segunda parte de la Carta a los[ENTER]gnolls![ENTER]Se la puedes arrebatar al Se\241or Gnoll. "
gameforge.main_quest_lv90._630_say = "\161Se nos est\225 acabando el tiempo! Date prisa y[ENTER]encuentra la segunda p\225gina de la carta. "
gameforge.main_quest_lv90._640_1_notice = "Has encontrado la segunda p\225gina. Ll\233vasela al[ENTER]Almirante Angmur. "
gameforge.main_quest_lv90._650_say = "Excelente, ahora por fin podremos descifrar el[ENTER]mensaje: Hmm. Habla sobre dragones que duermen en[ENTER]lo profundo del mundo, y de una manera de[ENTER]despertarlos y hacerlos montar en c\243lera.[ENTER]Oh, oh, no suena bien... "
gameforge.main_quest_lv90._660_say = {}
gameforge.main_quest_lv90._670_say = "Al parecer, las Mant\237coras y los Ladrones rojos[ENTER]tambi\233n han recibido sendas cartas. Voy a[ENTER]informarme m\225s y despu\233s te har\233 llamar. "
gameforge.main_quest_lv90._680_say = "El Almirante Angmur tiene un encargo para ti. "
gameforge.main_quest_lv90._690_sendLetter = "Las Mant\237coras "
gameforge.main_quest_lv90._700_say = "El Almirante Angmur tiene un encargo para ti. "
gameforge.main_quest_lv90._710_say = "\161Bien, has venido! La informaci\243n que tenemos[ENTER]sobre las Mant\237coras est\225 anticuada. Tenemos que[ENTER]descubrir c\243mo de fuertes son sus tropas. "
gameforge.main_quest_lv90._720_say = "\191Podr\237as espiarlas? Su campamento no est\225 lejos. "
gameforge.main_quest_lv90._730_say = "Por supuesto. \191Qu\233 debo hacer? "
gameforge.main_quest_lv90._740_say = "Acaba con 50 Luchadores mant\237cora, 40 Soldados[ENTER]mant\237cora, 20 Verdugos mant\237cora y 10 Generales[ENTER]Cora.[ENTER]Despu\233s inf\243rmame de tus progresos. "
gameforge.main_quest_lv90._750_say = "(Restantes: %s %s, %s %s) "
gameforge.main_quest_lv90._760_say = {}
gameforge.main_quest_lv90._770_say = "La informaci\243n no basta. Necesitas averiguar m\225s. "
gameforge.main_quest_lv90._780_1_notice = "Has averiguado lo suficiente sobre las Mant\237coras. "
gameforge.main_quest_lv90._780_2_notice = "Ve a informar al Almirante Angmur. "
gameforge.main_quest_lv90._790_say = "\191has completado tu tarea? Muy bien. Entonces[ENTER]inf\243rmame sobre la situaci\243n. "
gameforge.main_quest_lv90._800_say = "Las fuerzas de las Mant\237coras no son[ENTER]especialmente poderosas. Les sac\225is ventaja en[ENTER]vuestros n\250meros.[ENTER]Sin embargo, sus guerreros est\225n bien entrenados[ENTER]y son realmente pertinaces.[ENTER]Os aconsejar\237a reforzar la muralla y el fuerte;[ENTER]no aguantar\237an un asalto de las Mant\237coras. "
gameforge.main_quest_lv90._810_say = "S\237, ese es el tipo de informaci\243n que necesitamos.Voy a hacer caso de tu consejo y a reforzar la[ENTER]muralla.[ENTER]Toma, acepta esto como recompensa. "
gameforge.main_quest_lv90._820_say = "Habla con el Almirante Angmur. "
gameforge.main_quest_lv90._830_sayTitle = "Las fuerzas de las Mant\237coras "
gameforge.main_quest_lv90._840_say = "Acaba con 50 Luchadores mant\237cora, 40 Soldados[ENTER]mant\237cora, 20 Verdugos mant\237cora y 10 Generales[ENTER]Cora. "
gameforge.main_quest_lv90._850_sendLetter = "Reforzar la muralla I "
gameforge.main_quest_lv90._860_say = "El Almirante Angmur te est\225 buscando, y parece[ENTER]que es importante. Ve a verle enseguida. "
gameforge.main_quest_lv90._870_say = "Ah, aqu\237 est\225s. Ten\237as raz\243n, nuestra muralla no[ENTER]ser\237a capaz de resistir un asalto. Sin embargo,[ENTER]nos falta material para reforzarla. "
gameforge.main_quest_lv90._880_say = "Necesitamos Tejas y Arena fina. \191Puedes[ENTER]conseguirnos esos materiales? "
gameforge.main_quest_lv90._890_say = "Faltar\237a m\225s. "
gameforge.main_quest_lv90._900_say = "Muy bien. Busca primero la Arena fina. Los Gnolls[ENTER]poseen grandes reservas. Con 50 cubos deber\237a[ENTER]bastar. "
gameforge.main_quest_lv90._910_sayTitle = "Arena fina "
gameforge.main_quest_lv90._920_say = "Pelea contra los Gnoll y obt\233n 50 cubos de Arena[ENTER]fina. "
gameforge.main_quest_lv90._930_say = "Por desgracia, esto no nos basta. Necesitamos m\225s[ENTER]Arena fina. Sigue reuni\233ndola. "
gameforge.main_quest_lv90._940_1_notice = "Ya has reunido suficiente Arena fina. "
gameforge.main_quest_lv90._940_2_notice = "Entr\233gasela al Almirante Angmur. "
gameforge.main_quest_lv90._950_say = "Ok. "
gameforge.main_quest_lv90._960_say = "\161Te lo agradezco! Con esta Arena fina por fin[ENTER]podremos reforzar la muralla defensiva.[ENTER]Mis hombres se vana poner a trabajar de inmediato.Te har\233 llamar de nuevo cuando necesite tu ayuda[ENTER]otra vez. "
gameforge.main_quest_lv90._970_sendLetter = "Reforzar la muralla II "
gameforge.main_quest_lv90._980_say = "El Almirante Angmur necesita tu ayuda.[ENTER]Ve a ver qu\233 quiere. "
gameforge.main_quest_lv90._990_say = "Para completar la construcci\243n necesitaremos[ENTER]Tejas.[ENTER]Las Mant\237coras las acaparan como si fueran de oro.Creo que con 100 nos bastar\237a. Por supuesto, tu[ENTER]ayuda se ver\225 recompensada con creces. "
gameforge.main_quest_lv91 = {}
gameforge.main_quest_lv91._010_sendLetter = "La carta para las Mant\237coras "
gameforge.main_quest_lv91._020_say = "El Almirante Angmur tiene un encargo para ti. "
gameforge.main_quest_lv91._030_say = "Ya es hora de hacer frente de nuevo a las[ENTER]maquinaciones de los Servidores de la oscuridad.[ENTER]\161Tenemos que apoderarnos de las cartas que les[ENTER]enviaron a las Mant\237coras y a los Ladrones rojos![ENTER]Hazle primero una visita a las Mant\237coras. "
gameforge.main_quest_lv91._040_say = {}
gameforge.main_quest_lv91._050_say = "De acuerdo. "
gameforge.main_quest_lv91._060_say = "El General Cora lleva consigo la carta y tiene la[ENTER]intenci\243n de entreg\225rsela a Martyaxwar.[ENTER]\161Tienes que evitarlo! "
gameforge.main_quest_lv91._070_sayTitle = "La carta para las Mant\237coras "
gameforge.main_quest_lv91._080_say = "Acaba con el General Cora y encuentra la carta. "
gameforge.main_quest_lv91._090_1_notice = "Has llegado demasiado tarde. Martyaxwar ya[ENTER]recibi\243 la Carta. "
gameforge.main_quest_lv91._090_2_notice = "Ve a informar al Almirante Angmur. "
gameforge.main_quest_lv91._100_say = "Has llegado demasiado tarde. Ya le he entregado a[ENTER]Martyaxwar la Carta. \161El destino de la humanidad[ENTER]est\225 sellado! "
gameforge.main_quest_lv91._110_say = "Ve a informar al Almirante Angmur. "
gameforge.main_quest_lv91._120_say = "Por fin regresaste. \191Tienes la Carta? "
gameforge.main_quest_lv91._130_say = "No, llegu\233 demasiado tarde. El General Cora ya se[ENTER]la hab\237a entregado a Martyaxwar. "
gameforge.main_quest_lv91._140_say = {}
gameforge.main_quest_lv91._150_say = "Vaya, eso complica las cosas...[ENTER]Mis esp\237as descubrir\225n d\243nde se encuentra[ENTER]Martyaxwar.[ENTER]Aqu\237 tienes, toma esta recompensa. En cuanto me[ENTER]informen de algo m\225s, te lo har\233 saber. "
gameforge.main_quest_lv91._160_sendLetter = "Escondite de Martyaxwar "
gameforge.main_quest_lv91._170_say = "El Almirante Angmur te necesita. Ha descubierto[ENTER]el paradero de Martyaxwar. "
gameforge.main_quest_lv91._180_say = "\161Por fin vienes! Sabemos d\243nde se esconde[ENTER]Martyaxwar. Mis esp\237as han descubierto que oculta[ENTER]la carta en un Collar espinoso que nunca se[ENTER]quita. "
gameforge.main_quest_lv91._190_say = "\161Me pondr\233 en marcha inmediatamente! "
gameforge.main_quest_lv91._200_sayTitle = "Derrota a Martyaxwar. "
gameforge.main_quest_lv91._210_say = "Dale a Martyaxwar y arreb\225tale su Collar espinoso. "
gameforge.main_quest_lv91._220_say = "No podemos perder tiempo. \161Date prisa y tr\225eme el[ENTER]Collar espinoso! "
gameforge.main_quest_lv91._230_1_notice = "Has obtenido el Collar espinoso. La misiva se[ENTER]encuentra en un bolsillo interior. "
gameforge.main_quest_lv91._230_2_notice = "Ll\233vasela al Almirante Angmur. "
gameforge.main_quest_lv91._240_say = "Ve a ver al Almirante Angmur. "
gameforge.main_quest_lv91._250_say = "Buen trabajo. Estoy seguro de que no fue un[ENTER]enemigo sencillo. Esperemos que la Carta nos de[ENTER]m\225s informaci\243n sobre los oscuros planes de los[ENTER]demonios. "
gameforge.main_quest_lv91._260_say = "\161Maldici\243n! Justo como me tem\237a: otra vez[ENTER]codificada. Yon-I-Walker, nuestro sabio, tendr\225[ENTER]que echarle un vistazo. Ve a visitarle. "
gameforge.main_quest_lv91._270_sendLetter = "Descifrado "
gameforge.main_quest_lv91._280_say = "Ve con Yon-I-Walker para que descifre la carta. "
gameforge.main_quest_lv91._290_say = "*murmulla* \161Uh, vaya susto![ENTER]\191Qui\233n eres t\250? "
gameforge.main_quest_lv91._300_say = "Me env\237a el Almirante Angmur. "
gameforge.main_quest_lv91._310_say = "\161Ah, s\237! Vienes por la carta. Angmur ya me habl\243[ENTER]de ti. "
gameforge.main_quest_lv91._320_say = "A\250n no he podido descifrar la carta, pero parece[ENTER]que est\225 escrita en el abecedario de los[ENTER]Crustacianos que habitan la Bah\237a de Nephrit. "
gameforge.main_quest_lv91._330_say = "Para poder interpretar estos caracteres[ENTER]necesitar\233 los Caparazones con escrituras de los[ENTER]Crustacianos. \191Podr\237as conseguirme diez de ellos? "
gameforge.main_quest_lv91._340_say = "Por supuesto. "
gameforge.main_quest_lv91._350_sayTitle = "Caparaz\243n con escrituras "
gameforge.main_quest_lv91._360_say = "Combate al clan de los Crustacianos y obt\233n diez[ENTER]Caparazones con escrituras. "
gameforge.main_quest_lv91._370_say = "Por desgracia, este Caparaz\243n con escrituras est\225[ENTER]da\241ado, as\237 que no puedo utilizarlo. Tr\225eme otro. "
gameforge.main_quest_lv91._380_say = "Has conseguido los Caparazones con escrituras.[ENTER]Tienen forma de carapacho de tortuga. "
gameforge.main_quest_lv91._390_say = "Perfecto, ahora ya puedo descifrar la carta.[ENTER]\161Bien hecho! Toma esto como muestra de mi[ENTER]agradecimiento. "
gameforge.main_quest_lv91._400_say = "\161Tr\225eme %d unidades m\225s! "
gameforge.main_quest_lv91._410_1_notice = "Has encontrado un Caparaz\243n con escrituras. "
gameforge.main_quest_lv91._410_2_notice = "Entr\233gaselo a Yon-I-Walker. "
gameforge.main_quest_lv91._420_sendLetter = "La carta de las Mant\237coras, descifrada "
gameforge.main_quest_lv91._430_say = "Yon-I-Walker te est\225 buscando. Ve con \233l y[ENTER]averigua si ya logr\243 traducir la carta. "
gameforge.main_quest_lv91._440_say = "*murmulla* ...\161Ah, aqu\237 est\225s! Gracias a tu ayuda[ENTER]ya he podido descifrar gran parte del mensaje.[ENTER]Sin embargo, no consigo progresar con la \250ltima[ENTER]parte.[ENTER]Me temo que necesito de nuevo tu ayuda. Necesito[ENTER]Polvo de caparaz\243n urgentemente. Podr\225s[ENTER]encontrarlo donde el General langosta o el Rey[ENTER]cangrejo de los Crustacianos. "
gameforge.main_quest_lv91._450_say = "Polvo de caparaz\243n "
gameforge.main_quest_lv91._460_say = "S\237, solamente los Crustacianos lo poseen. \161Solo[ENTER]una peque\241a dosis ya es mortal! Tres dosis[ENTER]deber\237an bastarme. Mucha suerte. "
gameforge.main_quest_lv91._470_say = "Ahora mismo voy. "
gameforge.main_quest_lv91._480_sayTitle = "Polvo de caparaz\243n "
gameforge.main_quest_lv91._490_say = "Enfr\233ntate al General langosta y al Rey cangrejo[ENTER]de los Crustacianos y obt\233n tres dosis de Polvo[ENTER]de caparaz\243n. "
gameforge.main_quest_lv91._500_say = "El Polvo de caparaz\243n es extremadamente t\243xico.[ENTER]Tengo que esperar un d\237a para que su efecto[ENTER]decaiga. Vuelve ma\241ana; seguramente tendr\233 m\225s[ENTER]noticias. "
gameforge.main_quest_lv91._510_say = "\161Tienes el Polvo de caparaz\243n! "
gameforge.main_quest_lv91._520_say = "Bien hecho. Ahora por fin podr\233 descifrar la[ENTER]Carta. Toma esto como recompensa, por favor. "
gameforge.main_quest_lv91._530_say = "\161Tr\225eme %d unidades m\225s! "
gameforge.main_quest_lv91._540_say = "El Polvo de caparaz\243n es impuro. Por favor,[ENTER]tr\225eme otra dosis. "
gameforge.main_quest_lv91._550_1_notice = "Has encontrado una dosis de Polvo de caparaz\243n. "
gameforge.main_quest_lv91._550_2_notice = "Ll\233vasela a Yon-I-Walker. "
gameforge.main_quest_lv91._560_sendLetter = "\161Envenenado! "
gameforge.main_quest_lv91._570_say = "El Almirante Angmur te necesita urgentemente. Ve[ENTER]a ver qu\233 quiere. "
gameforge.main_quest_lv91._580_say = "\161Por fin apareces! Gracias al Dios Drag\243n.[ENTER]Yon-I-Walker se ha envenenado con el Polvo de[ENTER]caparaz\243n. "
gameforge.main_quest_lv91._590_say = "Quer\237a apresurarse y se descuid\243. Para colmo de[ENTER]males, nuestras reservas de plantas curativas se[ENTER]han agotado.[ENTER]Busca la Flor de roca: su ra\237z puede neutralizar[ENTER]el veneno. En este mapa he marcado d\243nde la puede[ENTER]encontrar. "
gameforge.main_quest_lv91._600_say = "Por supuesto. "
gameforge.main_quest_lv91._610_say = "Sab\237a que podr\237a confiar en ti. Por favor, date[ENTER]prisa: \161no nos queda mucho tiempo! "
gameforge.main_quest_lv91._620_sayTitle = "\161Salva a Yon-I-Walker! "
gameforge.main_quest_lv91._630_say = "Encuentra la Ra\237z de flor de roca necesaria para[ENTER]curar a Yon-I-Walker del envenenamiento. "
gameforge.main_quest_lv91._640_1_notice = "Ll\233vale a Yon-I-Walker la Ra\237z de flor de roca. "
gameforge.main_quest_lv91._650_say = "*cof* *cof*[ENTER]Ah, eres t\250. Estoy muy enfermo. \191Has encontrado[ENTER]la Ra\237z de flor de roca? "
gameforge.main_quest_lv91._660_say = "S\237, aqu\237 la tengo. "
gameforge.main_quest_lv91._670_say = "Ah, ya me siento mejor. Se ve que no ha llegado[ENTER]mi hora.[ENTER]Te lo agradezco. Toma esta peque\241a recompensa.[ENTER]Ahora podr\233 terminar mi trabajo. El Almirante[ENTER]Angmur te lo har\225 saber cuando termine de[ENTER]descifrar el mensaje. "
gameforge.main_quest_lv91._680_say = "Yon-I-Walker quiere hablar contigo. "
gameforge.main_quest_lv91._760_say = "(Restantes: %s %s, %s %s) "
gameforge.main_quest_lv91._770_say = {}
gameforge.main_quest_lv91._780_say = "La aventura continuar\225 en cuanto alcances el[ENTER]nivel 92. "
gameforge.main_quest_lv92 = {}
gameforge.main_quest_lv92._010_sendLetter = "La carta para los Ladrones rojos "
gameforge.main_quest_lv92._020_say = "La \250ltima carta que enviaron los Servidores de la[ENTER]oscuridad est\225 en poder de la banda de los[ENTER]Ladrones rojos. El Almirante Angmur tiene m\225s[ENTER]informaci\243n al respecto. "
gameforge.main_quest_lv92._030_say = "La invocaci\243n de los Servidores de la oscuridad[ENTER]se acerca cada vez m\225s. La \250ltima carta se[ENTER]encuentra en manos de la banda de los Ladrones[ENTER]rojos. "
gameforge.main_quest_lv92._040_say = "\191La banda de los Ladrones rojos? "
gameforge.main_quest_lv92._050_say = "Es un grupo de criminales a los que expulsaron al[ENTER]Pe\241asco del Drag\243n Oscuro. Lo extra\241o de este[ENTER]grupo es que humanos se hayan aliado con[ENTER]demonios. "
gameforge.main_quest_lv92._060_say = "\191Demonios que se al\237an con humanos en lugar de[ENTER]com\233rselos? Qu\233 extraordinario. "
gameforge.main_quest_lv92._070_say = "Les une un objetivo com\250n: el oro. El campamento[ENTER]de la banda de los Ladrones rojos no queda lejos.[ENTER]Acaba con el Verdugo ladr\243n rojo y con el General[ENTER]negro. Uno de ellos tiene la Carta. "
gameforge.main_quest_lv92._080_say = "Pero les han avisado con tiempo y han desgarrado[ENTER]la Carta en cuatro trozos. Tenemos que[ENTER]encontrarlos todos. "
gameforge.main_quest_lv92._090_say = "De acuerdo. "
gameforge.main_quest_lv92._100_say = "\161Muchas gracias! "
gameforge.main_quest_lv92._110_sayTitle = "La carta para los Ladrones rojos "
gameforge.main_quest_lv92._120_say = "Lucha contra los Verdugos ladr\243n rojo y el[ENTER]General negro. Encuentra las cuatro partes de la[ENTER]Carta. "
gameforge.main_quest_lv92._130_say = "La carta a\250n no est\225 completa. Encuentra todas[ENTER]sus partes. "
gameforge.main_quest_lv92._140_1_notice = "Has encontrado todos los fragmentos de la Carta a[ENTER]ladrones rojos. "
gameforge.main_quest_lv92._140_2_notice = "Mu\233strasela al Almirante Angmur. "
gameforge.main_quest_lv92._150_say = "Habla con el Almirante Angmur. "
gameforge.main_quest_lv92._160_say = "Buen trabajo. Toma esto como gesto de[ENTER]agradecimiento por mi parte. "
gameforge.main_quest_lv92._170_sendLetter = "La carta para los Ladrones rojos "
gameforge.main_quest_lv92._180_say = "El Almirante Angmur necesita tu ayuda. "
gameforge.main_quest_lv92._190_say = "Me alegro de que hayas venido. Tenemos un[ENTER]problema. "
gameforge.main_quest_lv92._200_say = "\191De qu\233 se trata? "
gameforge.main_quest_lv92._210_say = "Existe una quinta parte de la carta a los[ENTER]Ladrones rojos. Sin ella, el resto no vale nada.[ENTER]Envi\233 a Bae-Yong, uno de mis hombres m\225s[ENTER]valientes, pero creo que le ha ocurrido algo. Ya[ENTER]ten\237a que haber regresado hace mucho.[ENTER]\191Puedes salir a buscarlo? "
gameforge.main_quest_lv92._220_say = "\161Por supuesto! \191Tienes alguna idea de d\243nde[ENTER]podr\237a encontrarse? "
gameforge.main_quest_lv92._230_say = "Tengo una suposici\243n, s\237. Lo \250ltimo que sabemos[ENTER]es que quer\237a ir a la Bah\237a de Nephrit. Pero no[ENTER]se puede asegurar que lograse llegar hasta all\237. "
gameforge.main_quest_lv92._240_say = "\161Me pondr\233 en marcha inmediatamente! "
gameforge.main_quest_lv92._250_sayTitle = "El soldado desaparecido "
gameforge.main_quest_lv92._260_say = "Encuentra el quinto trozo de carta. Para ello,[ENTER]busca a Bae-Yong en la Bah\237a de Nephrit. "
gameforge.main_quest_lv92._270_say = "\191A\250n no encontraste a Bae-Yong?[ENTER]\161Es un asunto de vida o muerte! Por favor, sigue[ENTER]busc\225ndolo. "
gameforge.main_quest_lv92._280_say = "*tose*[ENTER]Gracias por encontrarme. Me han herido de[ENTER]gravedad y temo que no me queda mucho tiempo...[ENTER]Toma, esto se lo arrebat\233 a un Ladr\243n rojo.[ENTER]Ll\233vaselo al Almirante. \161Vamos, vete! Yo voy a...[ENTER](Muere en tus brazos). "
gameforge.main_quest_lv92._290_1_notice = "Justo antes de morir, Bae-Yong te entreg\243 el[ENTER]\250ltimo trozo de la Carta. "
gameforge.main_quest_lv92._290_2_notice = "Ahora, ve con el Almirante Angmur. "
gameforge.main_quest_lv92._300_say = "\161Has vuelto! \191Encontraste a Bae-Yong? "
gameforge.main_quest_lv92._310_say = "S\237, pero... "
gameforge.main_quest_lv92._320_say = "\191Pero...?[ENTER]Oh, no. \191Ha muerto? "
gameforge.main_quest_lv92._330_say = "No pude hacer nada por \233l. Lo siento.[ENTER]Era un hombre valiente: defendi\243 con su vida el[ENTER]\250ltimo trozo de carta. Aqu\237 est\225. "
gameforge.main_quest_lv92._340_say = "La p\233rdida de Bae-Yong nos duele en el alma, pero[ENTER]estoy orgulloso de \233l. Ha cumplido su misi\243n, y[ENTER]ahora tenemos todos los trozos de la Carta. "
gameforge.main_quest_lv92._350_say = "Gracias por todo. Toma, ten esto como recompensa.[ENTER]Ahora voy a encender una varilla de incienso en[ENTER]el templo por Bae-Yong.[ENTER]Me pondr\233 en contacto contigo despu\233s. "
gameforge.main_quest_lv92._360_say = "Ve con el Almirante Angmur. "
gameforge.main_quest_lv92._370_sendLetter = "Descifrando la carta para los Ladrones rojos "
gameforge.main_quest_lv92._380_say = "El Almirante Angmur tiene noticias importantes[ENTER]sobre la carta que enviaron a los Ladrones rojos.[ENTER]Escucha lo que te quiere contar. "
gameforge.main_quest_lv92._390_say = "Ah, aqu\237 est\225s. Los Servidores de la oscuridad me[ENTER]est\225n dando dolor de cabeza. La \250ltima carta[ENTER]tambi\233n est\225 cifrada. Ll\233vasela a Yon-I-Walker,[ENTER]por favor. "
gameforge.main_quest_lv92._400_say = "De acuerdo. "
gameforge.main_quest_lv92._410_say = "Ll\233vale la carta sellada a Yon-I-Walker. "
gameforge.main_quest_lv92._420_say = "\161Uh! \191Por qu\233 siempre tienes que acercarte tan[ENTER]sigilosamente? \191Qu\233 puedo hacer por ti? "
gameforge.main_quest_lv92._430_say = "Aqu\237 est\225 la carta para los Ladrones rojos. Al[ENTER]igual que las otras, est\225 cifrada. "
gameforge.main_quest_lv92._440_say = "D\233jame echarle un vistazo.[ENTER]Hm, estas son marcas de los Tritones. No deber\237a[ENTER]resultar dif\237cil descifrarlas. "
gameforge.main_quest_lv92._450_say = "Excelente. \191Cu\225nto tiempo vas a necesitar? "
gameforge.main_quest_lv92._460_say = "No tengas tanta prisa. Descifrar mensajes no es[ENTER]precisamente complicado. Pero sin algo de ayuda[ENTER]no va a poder ser. "
gameforge.main_quest_lv92._470_say = "Claro que no. Habr\237a sido demasiado sencillo. "
gameforge.main_quest_lv92._480_say = "Veo que no has perdido tu humor, je, je.[ENTER]Para descifrar la carta necesito Escamas de Oin.[ENTER]Solamente el General Kappa y el propio Trit\243n, de[ENTER]la tribu de los Tritones, pueden llevar estas[ENTER]escamas tan singulares. Por favor, tr\225eme diez. "
gameforge.main_quest_lv92._490_say = "Ahora mismo voy. "
gameforge.main_quest_lv92._500_sayTitle = "\161Encuentra Escamas de Oin! "
gameforge.main_quest_lv92._510_say = "Solamente el General Kappa y Trit\243n, el rey de[ENTER]los Tritones, llevan Escamas de Oin. "
gameforge.main_quest_lv92._520_say = "Sin esas escamas no puedo descifrar la carta. Las[ENTER]necesito sin falta. "
gameforge.main_quest_lv92._530_1_notice = "Has encontrado las Escamas de Oin tritonianas. "
gameforge.main_quest_lv92._530_2_notice = "Ll\233vaselas enseguida a Yon-I-Walker. "
gameforge.main_quest_lv92._540_say = "Has hecho un buen trabajo. En cuanto descifre la[ENTER]carta avisar\233 al Almirante Angmur.[ENTER]Deber\237as tomarte un descanso. Toma, qu\233date con[ENTER]esto como muestra de mi gratitud. "
gameforge.main_quest_lv92._550_say = "Yon-I-Walker quiere hablar contigo. "
gameforge.main_quest_lv92._560_sendLetter = "Planes tenebrosos "
gameforge.main_quest_lv92._570_say = "La carta de los Servidores de la oscuridad ya[ENTER]est\225 descifrada. El Almirante Angmur quiere[ENTER]explicarte lo que est\225n tramando. "
gameforge.main_quest_lv92._580_say = "Hemos logrado descifrar el mensaje secreto.[ENTER]\191Recuerdas la carta que enviaron a los Gnolls? En[ENTER]ella ya se hablaba de dragones que habitan las[ENTER]profundidades de la isla y de una manera de[ENTER]despertarlos y enfurecerlos. Ahora hemos[ENTER]descubierto cu\225l es el objetivo de los Servidores[ENTER]de la oscuridad. "
gameforge.main_quest_lv92._590_say = "Si un drag\243n muere justo en el momento en el que[ENTER]su raz\243n es tan negra como las profundidades del[ENTER]infierno, expulsa una Perla nocturna. Con esa[ENTER]Perla nocturna se pueden invocar a nuestro mundo[ENTER]los poderes oscuros de Sung Mahi.[ENTER]\161As\237 que ese es su terrible plan! "
gameforge.main_quest_lv92._600_say = "Tenemos que reflexionar sobre nuestras siguientes[ENTER]acciones. Cuando tenga m\225s informaci\243n que darte[ENTER]te har\233 llamar. Gracias por todo. "
gameforge.main_quest_lv92._610_say = "La aventura continuar\225 en cuanto alcances el[ENTER]nivel 93. "
gameforge.main_quest_lv93 = {}
gameforge.main_quest_lv93._010_sendLetter = "Reponiendo fuerzas I "
gameforge.main_quest_lv93._020_say = "El Almirante Angmur quiere hablar contigo. "
gameforge.main_quest_lv93._030_say = "Le estamos pisando los talones a los Servidores[ENTER]de la oscuridad. "
gameforge.main_quest_lv93._040_say = "Para poder vencerlos tendremos que mejorar tus[ENTER]fuerzas.[ENTER]\191Conoces la Luz interior? Es energ\237a concentrada.[ENTER]Algunos seres y plantas m\237sticos la llevan en su[ENTER]interior. Yon-I-Walker puede fabricar un producto[ENTER]fortificador, as\237 que habla con \233l. "
gameforge.main_quest_lv93._050_say = "De acuerdo. "
gameforge.main_quest_lv93._060_say = "\161Ah, has venido![ENTER]La Luz interior, s\237... Mi elixir fortalecedor te[ENTER]convertir\225 en un rival digno de los Servidores de[ENTER]la oscuridad. "
gameforge.main_quest_lv93._070_say = "Necesitar\233 la Luz interior de los C\237clopes y de[ENTER]los Gigantes. Solamente los l\237deres de sus clanes[ENTER]la llevan.[ENTER]Obt\233n primero la de los C\237clopes. "
gameforge.main_quest_lv93._080_say = "De acuerdo. "
gameforge.main_quest_lv93._090_sayTitle = "La Luz interior I "
gameforge.main_quest_lv93._100_say = "Vence a Polifemo, rey de los C\237clopes, y r\243bale[ENTER]su Luz interior. "
gameforge.main_quest_lv93._110_say = "\191Vienes con las manos vac\237as? As\237 no puedo[ENTER]ayudarte. \161Tr\225eme la Luz interior! "
gameforge.main_quest_lv93._120_1_notice = "Has encontrado la Luz interior.[ENTER]Ll\233vasela a Yon-I-Walker. "
gameforge.main_quest_lv93._130_say = "Habla con Yon-I-Walker. "
gameforge.main_quest_lv93._140_say = "As\237 que esto es la Luz interior... antes de poder[ENTER]trabajar con ella hay que refinarla. Va a durar[ENTER]un tiempo, as\237 que te avisar\233 cuando termine. "
gameforge.main_quest_lv93._150_sendLetter = "Reponiendo fuerzas II "
gameforge.main_quest_lv93._160_say = "Yon-I-Walker te est\225 buscando. "
gameforge.main_quest_lv93._170_say = "Ya he purificado la Luz interior de Polifemo.[ENTER]Lo siguiente que necesitamos es la de los[ENTER]Gigantes, as\237 que derrota al Rey Yabba. "
gameforge.main_quest_lv93._180_say = "Ahora mismo voy. "
gameforge.main_quest_lv93._190_sayTitle = "La Luz interior II "
gameforge.main_quest_lv93._200_say = "Vence al rey de los Gigantes, Yabba, y r\243bale su[ENTER]Luz interior. "
gameforge.main_quest_lv93._210_say = "\191Vienes con las manos vac\237as? No puedo creer que[ENTER]esta tarea no est\233 dentro de tus posibilidades.[ENTER]\161Sal de nuevo y sigue intent\225ndolo! "
gameforge.main_quest_lv93._220_1_notice = "Tienes en tus manos la Luz interior de los[ENTER]Gigantes. "
gameforge.main_quest_lv93._220_2_notice = "Ll\233vasela a Yon-I-Walker. "
gameforge.main_quest_lv93._230_say = "Habla con Yon-I-Walker. "
gameforge.main_quest_lv93._240_say = "La Luz interior del rey Yabba posee un poder[ENTER]inconmensurable. Supongo que tendr\225 que ver con[ENTER]su masa. Esto me va a llevar un buen rato. "
gameforge.main_quest_lv93._250_sendLetter = "Reponiendo fuerzas III "
gameforge.main_quest_lv93._260_say = "Yon-I-Walker te est\225 buscando. "
gameforge.main_quest_lv93._270_say = "Muy bien, has venido. Necesito tu ayuda.[ENTER]Para que mi elixir fortificador pueda desarrollar[ENTER]por completo su efecto necesito un componente[ENTER]m\225s: la Esencia milenaria. "
gameforge.main_quest_lv93._280_say = "\191Esencia milenaria? Nunca he o\237do hablar de ella. "
gameforge.main_quest_lv93._290_say = "Es una mezcla muy eficaz de diferentes esencias[ENTER]de hierbas.[ENTER]\191Conoces a Octavio? Vive en el continente y es el[ENTER]\250nico capaz de fabricar la Esencia milenaria. Ve[ENTER]a verle. Espero que nos ayude. A veces es tan[ENTER]testarudo... "
gameforge.main_quest_lv93._300_say = "De acuerdo. "
gameforge.main_quest_lv93._310_sayTitle = "Habla con Octavio. "
gameforge.main_quest_lv93._320_say = "Busca a Octavio. Vive en el continente y es el[ENTER]\250nico que puede fabricar la Esencia milenaria. "
gameforge.main_quest_lv93._330_say = "\161Hola! \191Qu\233 deseas? \191Unas algas de Samgye? Son la[ENTER]especialidad de la casa; llevan... "
gameforge.main_quest_lv93._340_say = "\161Octavio, no he venido a probar tus delicias![ENTER]Necesito otra cosa: la Esencia milenaria. "
gameforge.main_quest_lv93._350_say = "\161Hey, psssst, no tan alto! La Esencia milenaria...No, no puede ser. \191C\243mo sabes eso? Solamente unos[ENTER]pocos son capaces de manejar el tremendo poder[ENTER]que otorga. No quiero correr el riesgo. Y ahora[ENTER]vete antes de que alguien te escuche. "
gameforge.main_quest_lv93._360_say = "\161Octavio, espera y esc\250chame! Yon-I-Walker, del[ENTER]Pe\241asco del Drag\243n Oscuro, es quien me env\237a.[ENTER]Necesitamos a toda costa la Esencia. Sin ella no[ENTER]tenemos ninguna posibilidad contra los Servidores[ENTER]de la oscuridad. Y el mundo tal y como lo[ENTER]conocemos caer\225 en la perdici\243n. \161Solamente t\250[ENTER]puedes fabricarla, as\237 que ay\250danos! "
gameforge.main_quest_lv93._370_say = "\191Yon-I-Walker, dices? Hm, es un viejo amigo m\237o.[ENTER]Hemos tenido incontables conversaciones sobre una[ENTER]botella de buen vino.[ENTER]Tengo que reflexionar. Vuelve ma\241ana y te dar\233[ENTER]una respuesta. "
gameforge.main_quest_lv93._380_say = {}
gameforge.main_quest_lv93._390_say = "A\250n no me he decidido. Vuelve m\225s tarde. "
gameforge.main_quest_lv93._400_npcChat = "La Esencia milenaria "
gameforge.main_quest_lv93._410_say = "Octavio quiere hablar contigo. "
gameforge.main_quest_lv93._420_say = "Bueno, he reflexionado toda la noche sobre tu[ENTER]petici\243n. Voy a correr un gran riesgo, pero s\233[ENTER]que hago lo correcto. S\237, voy a ayudarte. "
gameforge.main_quest_lv93._430_say = "\161Excelente! "
gameforge.main_quest_lv93._440_say = "Sin embargo, no me queda nada guardada. \191Podr\237as[ENTER]conseguirme algunos ingredientes? As\237 podr\233[ENTER]fabricar la Esencia. "
gameforge.main_quest_lv93._450_say = "Por supuesto. \191Qu\233 necesitas? "
gameforge.main_quest_lv93._460_say = "Me hacen falta Ra\237ces Gango, Fungicida y Rosas[ENTER]alpinas. Necesito 200 unidades de cada uno de los[ENTER]ingredientes. "
gameforge.main_quest_lv93._470_say = "Voy a buscarlas. \191D\243nde puedo encontrarlas? "
gameforge.main_quest_lv93._480_say = "Puedes encontrar esas plantas en los lugares m\225s[ENTER]variados del continente.[ENTER]Mientras est\225s fuera, voy a empezar los[ENTER]preparativos. "
gameforge.main_quest_lv93._490_sayTitle = "La receta milenaria "
gameforge.main_quest_lv93._500_say = "Busca la Ra\237z Gango, el Fungicida y la Rosa[ENTER]Alpina.[ENTER]Necesitas 200 unidades de cada ingrediente. "
gameforge.main_quest_lv93._510 = "Puedes encontrar esas plantas en los lugares m\225s[ENTER]variados del continente.[ENTER]Mientras est\225s fuera, voy a empezar los[ENTER]preparativos. "
gameforge.main_quest_lv93._520_say = "Ah, muy bien, has regresado. Y, por lo que veo,[ENTER]traes todo, as\237 que me voy a poner a trabajar de[ENTER]inmediato. Vuelve ma\241ana a esta misma hora; para[ENTER]entonces, la Esencia deber\237a estar terminada. "
gameforge.main_quest_lv93._530_say = "De acuerdo. Hasta ma\241ana. "
gameforge.main_quest_lv93._540_say = "Entiendo que tengas prisa, pero vas a necesitar[ENTER]algo de paciencia. Vuelve m\225s tarde. "
gameforge.main_quest_lv93._550_say = "Octavio te est\225 buscando. "
gameforge.main_quest_lv93._560_say = "Ah, llegas justo a tiempo: \161la Esencia milenaria[ENTER]est\225 lista! Puedes llev\225rsela a Yon-I-Walker. "
gameforge.main_quest_lv93._570_say = "\161Muchas gracias! "
gameforge.main_quest_lv93._580_sendLetter = "Esencia milenaria "
gameforge.main_quest_lv93._590_say = "Yon-I-Walker te est\225 buscando. "
gameforge.main_quest_lv93._600_say = "\161Tienes la Esencia milenaria![ENTER]Ahora ya dispongo de todos los ingredientes para[ENTER]mi elixir fortalecedor.[ENTER]Te har\233 llamar en cuanto lo termine. "
gameforge.main_quest_lv93._610_say = "De acuerdo. "
gameforge.main_quest_lv93._620_say = "La aventura continuar\225 en cuanto alcances el[ENTER]nivel 94. "
gameforge.main_quest_lv93._630_say = "%s: %d unidad/es, %s: %d unidad/es,[ENTER]%s: %d unidad/es "
gameforge.main_quest_lv93._640_say = "Tengo un mes\243n que administrar y no me sobra el[ENTER]tiempo. Tr\225eme todos los ingredientes que faltan,[ENTER]y date prisa. "
gameforge.main_quest_lv93._650_1_notice = "Has encontrado todos los ingredientes necesarios[ENTER]para la Esencia milenaria. "
gameforge.main_quest_lv93._650_2_notice = "Vuelve con Octavio. "
gameforge.main_quest_lv94 = {}
