gameforge.main_quest_lv94._020_say = "Yon-I-Walker te est\225 buscando. "
gameforge.main_quest_lv94._030_say = "Lo he logrado: he combinado las esencias m\225s[ENTER]eficaces que conocemos. \161Te presento la Perla de[ENTER]Leviat\225n! "
gameforge.main_quest_lv94._040_say = "\161Muchas gracias! "
gameforge.main_quest_lv94._050_say = "Si tomas esta c\225psula puede que no notes cambio[ENTER]alguno. Pero para el ojo experto, como el m\237o o[ENTER]el de Angmur, lo reconocer\225.[ENTER]Angmur quiere hablar contigo. Ve con \233l[ENTER]inmediatamente. "
gameforge.main_quest_lv94._060_sayTitle = "\161Refu\233rzate! "
gameforge.main_quest_lv94._070_say = "Toma las Perlas de Leviat\225n y busca al Almirante[ENTER]Angmur. "
gameforge.main_quest_lv94._080_sendLetter = "Llamada de las Monta\241as Trueno "
gameforge.main_quest_lv94._090_say = "El Almirante Angmur tiene novedades para ti. "
gameforge.main_quest_lv94._1000_say = "Voy a necesitar algo de tiempo para analizar las[ENTER]muestras. Vuelve ma\241ana por aqu\237; con algo de[ENTER]suerte tendr\233 los resultados para entonces. "
gameforge.main_quest_lv94._100_say = "Ah, las Perlas de Leviat\225n muestran sus efectos:[ENTER]puedo reconocer claramente el aura de poder a tu[ENTER]alrededor.[ENTER]Mis esp\237as creen saber d\243nde se encuentra el[ENTER]cuartel general de los Servidores de la[ENTER]oscuridad.[ENTER]Ese lugar est\225 muy vigilado, \191podr\237as echar un[ENTER]vistazo por ah\237? "
gameforge.main_quest_lv94._1010_say = "Le comunicar\233 a Angmur mis resultados. \201l se[ENTER]pondr\225 en contacto contigo despu\233s. "
gameforge.main_quest_lv94._1020_say = "El Almirante Angmur tiene informaci\243n sobre el[ENTER]Oro negro. Habla con \233l. "
gameforge.main_quest_lv94._1030_say = "Ah, est\225s aqu\237. A\250n no hemos terminado de[ENTER]analizar el Oro negro. Espero poder decirte[ENTER]pronto algo m\225s.[ENTER]Toma, ten esta recompensa por las molestias. "
gameforge.main_quest_lv94._1040_say = "No podemos perder el tiempo. \161R\225pido, tr\225eme[ENTER]muestras de Oro negro! "
gameforge.main_quest_lv94._1050_say = "La aventura continuar\225 en cuanto alcances el[ENTER]nivel 95. "
gameforge.main_quest_lv94._1060_say = "(Restantes: %s %s, %s %s) "
