gameforge.main_quest_lv94._1080_say = "Cantidad restante: "
gameforge.main_quest_lv94._1090_say = {}
gameforge.main_quest_lv94._110_say = "Por supuesto. "
gameforge.main_quest_lv94._120_say = "Te lo agradezco. Ven, te mostrar\233 las zonas que[ENTER]tienes que explorar. Inf\243rmame cuando lo hayas[ENTER]hecho. "
gameforge.main_quest_lv94._130_say = {}
gameforge.main_quest_lv94._140_say = "Siguiendo \243rdenes de Angmur tienes que explorar[ENTER]las Monta\241as Trueno. Tu primer objetivo es: (%d,[ENTER]%d) "
gameforge.main_quest_lv94._150_sayTitle = "Las Monta\241as Trueno "
gameforge.main_quest_lv94._160_say = "Explora las Monta\241as Trueno y pres\233ntale tu[ENTER]informe al Almirante Angmur. "
gameforge.main_quest_lv94._170_say = "A\250n no has explorado todos los lugares, \191verdad?[ENTER]Necesitamos sin falta esa informaci\243n, as\237 que[ENTER]lleva a cabo esta misi\243n, por favor. "
gameforge.main_quest_lv94._180_say = "Tu primer objetivo es: %d, %d "
