gameforge.main_quest_lv94._220_say = "Has alcanzado el primer objetivo. El siguiente[ENTER]est\225 en: (%d, %d) "
gameforge.main_quest_lv94._230_say = "Has alcanzado el segundo objetivo. El siguiente[ENTER]est\225 en: (%d, %d) "
gameforge.main_quest_lv94._240 = "Has alcanzado el tercer objetivo. "
gameforge.main_quest_lv94._250_say = "Has logrado hacerte una idea de la situaci\243n en[ENTER]las Monta\241as Trueno.[ENTER]Ahora, informa al Almirante Angmur. "
gameforge.main_quest_lv94._260_say = "Vuelve con el Almirante Angmur. "
gameforge.main_quest_lv94._270_say = "\161Ah, has vuelto! Muy bien, vamos a analizar la[ENTER]informaci\243n que has reunido para elaborar una[ENTER]estrategia. "
gameforge.main_quest_lv94._280_say = "Aqu\237 tienes tu recompensa. "
gameforge.main_quest_lv94._290_sendLetter = "Debilitar a los Ladrones rojos "
gameforge.main_quest_lv94._300_say = "El Almirante Angmur te busca. "
gameforge.main_quest_lv94._310_say = "Un ataque frontal, en las circunstancias[ENTER]actuales, me parece demasiado arriesgado. Antes[ENTER]de lanzarnos a la ofensiva deber\237amos debilitar a[ENTER]las tropas enemigas. "
gameforge.main_quest_lv94._320_say = "Los siguientes grupos habitan las Monta\241as[ENTER]Trueno: los Gigantes, los C\237clopes y los Ladrones[ENTER]rojos.[ENTER]\161En primer lugar vamos a atacar a los Ladrones[ENTER]rojos! "
gameforge.main_quest_lv94._330_say = "\191Cu\225les son los puntos d\233biles de los Ladrones[ENTER]rojos? "
gameforge.main_quest_lv94._340_say = "El General rojo siempre viste una capa especial[ENTER]que simboliza su poder y su invencibilidad.[ENTER]\161Arreb\225tasela! As\237 debilitaremos la moral de los[ENTER]Ladrones rojos. "
gameforge.main_quest_lv94._350_say = "\191El General rojo? No va a resultar f\225cil... "
gameforge.main_quest_lv94._360_say = "Tienes raz\243n, pero si alguien puede quit\225rsela,[ENTER]eres t\250. \161Mucha suerte! "
gameforge.main_quest_lv94._370_sayTitle = "El General rojo "
gameforge.main_quest_lv94._380_say = "Vence al General rojo y arreb\225tale su capa. "
gameforge.main_quest_lv94._390_say = "\191...fallado? No, no lo creo. Arrostra de nuevo al[ENTER]General rojo; estoy seguro de que esta vez lo[ENTER]derrotar\225s. "
gameforge.main_quest_lv94._400_1_notice = "Has vencido al General rojo. "
gameforge.main_quest_lv94._400_2_notice = "Qu\237tale su capa y ll\233vasela al Almirante Angmur. "
gameforge.main_quest_lv94._410_say = "El Almirante Angmur te espera. "
gameforge.main_quest_lv94._420_say = "\161La capa! Sab\237a que lo lograr\237as. El siguiente[ENTER]paso ser\225 colgarla en un lugar visible cerca de[ENTER]su campamento; as\237 confundiremos a los Ladrones[ENTER]rojos.[ENTER]Mis hombres se encargar\225n de eso. As\237 podr\225s[ENTER]descansar un poco. "
gameforge.main_quest_lv94._430_sendLetter = "Debilitar a los C\237clopes "
gameforge.main_quest_lv94._440_say = "El Almirante Angmur quiere hablar contigo. "
gameforge.main_quest_lv94._450_say = "Nuestro plan est\225 dando frutos: ver la capa caus\243[ENTER]el p\225nico entre los Ladrones rojos. Al final,[ENTER]demonios y humanos empezaron a combatir entre s\237,[ENTER]y ahora la banda est\225 completamente[ENTER]desorganizada.[ENTER]Lo siguiente que haremos es ocuparnos de los[ENTER]C\237clopes. "
gameforge.main_quest_lv94._460_say = "\191Y c\243mo vamos a hacerlo? "
gameforge.main_quest_lv94._470_say = "Los C\237clopes veneran a sus l\237deres. Si derrotamos[ENTER]a los peces gordos, sembraremos el p\225nico entre[ENTER]los C\237clopes y se dispersar\225n. Vence %d veces al[ENTER]General Outis, %d veces a Arges y %d veces a[ENTER]Polifemo. "
gameforge.main_quest_lv94._480_say = "Ser\225 un placer. "
gameforge.main_quest_lv94._490_say = "Cu\237date. "
gameforge.main_quest_lv94._500_sayTitle = "\161Lucha contra los C\237clopes! "
gameforge.main_quest_lv94._510_say = "Vence %d veces al General Outis, %d veces a Arges[ENTER]y %d veces a Polifemo. "
gameforge.main_quest_lv94._520 = "No puedo creer que esos C\237clopes lograsen[ENTER]vencerte. \161Vamos, s\233 que puedes lograrlo! "
gameforge.main_quest_lv94._530_1_notice = "Has vencido a los l\237deres de los C\237clopes. "
gameforge.main_quest_lv94._530_2_notice = "Ve a informar al Almirante Angmur. "
gameforge.main_quest_lv94._540_say = "Ve a ver al Almirante Angmur. "
gameforge.main_quest_lv94._550_say = "\161Las noticias de tus haza\241as te preceden! Los[ENTER]C\237clopes se han dado a la fuga.[ENTER]A\250n quedan los Gigantes. Voy a reunir informaci\243n[ENTER]sobre sus debilidades y despu\233s te har\233 llamar. "
gameforge.main_quest_lv94._560_sendLetter = "Debilitar a los Gigantes "
gameforge.main_quest_lv94._570_say = "El Almirante Angmur te ha hecho llamar. "
gameforge.main_quest_lv94._580_say = "Mis esp\237as han descubierto el punto d\233bil de los[ENTER]Gigantes. "
gameforge.main_quest_lv94._590_say = "\161A ver, cuenta! "
gameforge.main_quest_lv94._600_say = "Los Gigantes poseen un T\243tem de gran valor[ENTER]espiritual. Si logramos sustra\233rselo podr\237amos[ENTER]desmoralizarlos. "
gameforge.main_quest_lv94._610_say = "\191D\243nde podemos encontrar ese T\243tem? "
gameforge.main_quest_lv94._620_say = "El T\243tem tiene la forma de una gran pieza de[ENTER]\225mbar. Para protegerla contra ladrones lo[ENTER]dividieron en %d trozos.[ENTER]El Rey Yabba y sus oficiales los llevan consigo. "
gameforge.main_quest_lv94._630_say = "Entendido. "
gameforge.main_quest_lv94._640_sayTitle = "T\243tem de los gigantes "
gameforge.main_quest_lv94._650_say = "Apod\233rate de todos los trozos del T\243tem. "
gameforge.main_quest_lv94._660_say = "Los Gigantes son enemigos formidables, \161pero[ENTER]tienes que vencerlos y traerme ese T\243tem! "
gameforge.main_quest_lv94._670_say_1_notice = "Has obtenido todos los trozos del T\243tem. "
gameforge.main_quest_lv94._670_say_2_notice = "Vuelve con el Almirante Angmur. "
gameforge.main_quest_lv94._680_say = "\161Ay, ya empezaba a preocuparme! Realmente lo has[ENTER]conseguido. Ahora poseemos el sagrado T\243tem de[ENTER]los gigantes. Te mereces una recompensa. "
gameforge.main_quest_lv94._690_sendLetter = "Ir a las Monta\241as Trueno "
gameforge.main_quest_lv94._700_say = "El Almirante Angmur te busca. "
gameforge.main_quest_lv94._710_say = "Mis esp\237as han observado que los C\237clopes est\225n[ENTER]reuniendo algo en las Monta\241as Trueno. "
gameforge.main_quest_lv94._720_say = "Descubre qu\233 se proponen los C\237clopes. Seguro que[ENTER]no es nada bueno... y dudo que vayan a desvelar[ENTER]su secreto. "
gameforge.main_quest_lv94._730_say = "Entendido. "
gameforge.main_quest_lv94._740_sayTitle = "\191Qu\233 se traen los C\237clopes entre manos? "
gameforge.main_quest_lv94._750_say = "Descubre qu\233 est\225n reuniendo los C\237clopes en las[ENTER]Monta\241as Trueno. "
gameforge.main_quest_lv94._760_say = "Descubre qu\233 se traen los C\237clopes entre manos.[ENTER]Seguro que no es nada bueno... y dudo que vayan a[ENTER]desvelar su secreto. "
gameforge.main_quest_lv94._770_1_notice = "Sostienes en tus manos una piedra negra brillante[ENTER]y una nota. "
gameforge.main_quest_lv94._770_2_notice = "Mu\233strale al Almirante Angmur lo que has[ENTER]encontrado. "
gameforge.main_quest_lv94._780_say = "Ve con el Almirante Angmur. "
gameforge.main_quest_lv94._790_say = "\191Has descubierto qu\233 est\225n haciendo los C\237clopes[ENTER]en las Monta\241as Trueno? "
gameforge.main_quest_lv94._800_say = "Los C\237clopes no estaban precisamente dispuestos a[ENTER]hablar, pero finalmente logr\233 convencerlos de que[ENTER]me dieran esto: una piedra negra y una nota. "
gameforge.main_quest_lv94._810_say = "Hemos localizado las vetas de Oro negro en las[ENTER]Monta\241as Trueno y estamos explot\225ndola. Como[ENTER]acordamos, para la entrega nos encontraremos en[ENTER]el interior de las Monta\241as Trueno. "
gameforge.main_quest_lv94._820_say = "Oro negro... es un mineral que solamente se puede[ENTER]encontrar en las Monta\241as Trueno. \191Para qu\233 las[ENTER]necesitar\225n los Servidores de la oscuridad? "
gameforge.main_quest_lv94._830_say = "Tenemos que descubrir qu\233 pretenden hacer. "
gameforge.main_quest_lv94._840_say = "Aqu\237 pone: "
gameforge.main_quest_lv94._850_sendLetter = "Oro negro "
gameforge.main_quest_lv94._860_say = "El Almirante Angmur quiere hablar contigo sobre[ENTER]el Oro negro. "
gameforge.main_quest_lv94._870_say = "El alquimista no ha logrado analizar el Oro[ENTER]negro; la pieza es demasiado peque\241a.[ENTER]\161Tenemos que averiguar cu\225les son sus propiedades[ENTER]y por qu\233 los Servidores de la oscuridad lo[ENTER]codician! \191Puedes volver a las Monta\241as Trueno y[ENTER]obtener m\225s muestras de Oro negro? "
gameforge.main_quest_lv94._880_say = "Vuelve con el alquimista. \201l sabr\225 decirte[ENTER]cu\225ntas muestras necesita. "
gameforge.main_quest_lv94._890_say = "Habla con el alquimista. "
gameforge.main_quest_lv94._900_say = "Saludos. \191Angmur te explic\243 ya tu misi\243n? "
gameforge.main_quest_lv94._910_say = "S\237. \191Cu\225ntas muestras de Oro negro vas a[ENTER]necesitar? "
gameforge.main_quest_lv94._920_say = "Hmm, d\233jame pensar. Creo que %d muestras bastar\225n[ENTER]para el an\225lisis. "
gameforge.main_quest_lv94._930_say = "Entendido. "
gameforge.main_quest_lv94._940_sayTitle = "El oro de las Monta\241as Trueno "
gameforge.main_quest_lv94._950_sayTitle = "Ve con el alquimista. "
gameforge.main_quest_lv94._960_say = "Busca muestras de Oro negro en las Monta\241as[ENTER]Trueno. "
gameforge.main_quest_lv94._970_1_notice = "Has encontrado una veta de Oro negro de la que[ENTER]has extra\237do una muestra del mineral. "
gameforge.main_quest_lv94._970_2_notice = "Ll\233vasela al alquimista. "
gameforge.main_quest_lv94._980_say = "Ah, has encontrado algo de Oro negro.[ENTER]\161Mu\233stramelo! Hm, ni una fisura, buen tama\241o...[ENTER]S\237, puedo utilizarla para mis an\225lisis. Ahora[ENTER]solamente necesito %d m\225s. "
gameforge.main_quest_lv94._990_say = "Desgraciadamente, con esta muestra no basta.[ENTER]Es demasiado ligera para un an\225lisis adecuado.[ENTER]\161Tr\225eme otra! "
gameforge.main_quest_lv95 = {}
gameforge.main_quest_lv95._010_sendLetter = "Fiebre del oro "
gameforge.main_quest_lv95._020_say = "El Almirante Angmur te est\225 buscando. Tiene m\225s[ENTER]informaci\243n sobre el Oro negro. "
gameforge.main_quest_lv95._030_say = "El Oro negro es capaz de extraer la energ\237a de[ENTER]los seres vivos a su alrededor y liberarla en[ENTER]otro cuerpo. \161De este modo, los Servidores de la[ENTER]oscuridad pretenden infundir en Sung Mahi fuerzas[ENTER]robadas! El gigante Capit\225n Karfio acapara[ENTER]enormes reservas de Oro negro en las Monta\241as[ENTER]Trueno.[ENTER]\161R\243baselas! "
gameforge.main_quest_lv95._040_say = "\161As\237 se har\225! "
gameforge.main_quest_lv95._050_say = {}
gameforge.main_quest_lv95._060_say = {}
gameforge.main_quest_lv95._070_sayTitle = "El gancho: Capit\225n Karfio "
gameforge.main_quest_lv95._080_say = "\161Vence al Capit\225n Karfio y obt\233n el Oro negro! "
gameforge.main_quest_lv95._090_say = "No hay tiempo que perder. \161Vence al Capit\225n[ENTER]Karfio y obt\233n el Oro negro! "
gameforge.main_quest_lv95._100_1_notice = "No hay ni rastro del Oro negro. En su lugar, el[ENTER]Capit\225n Karfio llevaba una carta. "
gameforge.main_quest_lv95._100_2_notice = {}
gameforge.main_quest_lv95._110_say = "Ve a informar al Almirante Angmur. "
gameforge.main_quest_lv95._120_say = "Ah, as\237 que lograste prevalecer contra el Capit\225n[ENTER]Karfio. \191Qu\233 es eso, una carta? \161D\233jame ver! "
gameforge.main_quest_lv95._130_say = {}
gameforge.main_quest_lv95._140_say = "Maldita sea. El Capit\225n Karfio ya le ha enviado a[ENTER]la Banshee el Oro negro.[ENTER]La \250ltima frase me tiene intrigado: La Maldici\243n[ENTER]de la vida traer\225 al ej\233rcito de la oscuridad a[ENTER]trav\233s de las nieblas del tiempo. "
gameforge.main_quest_lv95._150_say = "\161Tenemos que evitar la entrega! Creemos que el[ENTER]escondite de la Banshee se encuentra en el[ENTER]Acantilado de Gautama, al oeste. Se trata de un[ENTER]lugar olvidado, siempre cubierto por densas[ENTER]nieblas. Ogros y Lemures viven all\237. "
gameforge.main_quest_lv95._160_say = {}
gameforge.main_quest_lv95._170_say = "En cuanto sepa por qu\233 ruta llevar\225n el Oro negro[ENTER]a la Banshee te lo har\233 saber. "
gameforge.main_quest_lv95._180_sendLetter = "Capturar el env\237o "
gameforge.main_quest_lv95._190_say = "Ve con el Almirante Angmur. Tiene m\225s informaci\243n[ENTER]sobre el env\237o del Oro negro. "
gameforge.main_quest_lv95._200_say = "Mis esp\237as han averiguado que el Capit\225n Shrak,[ENTER]comandante de los Ogros, es quien transportar\225 el[ENTER]Oro negro al Acantilado de Gautama. Lo llevar\225 en[ENTER]una bolsa que cuelga de su cintur\243n. \161Qu\237tasela! "
gameforge.main_quest_lv95._210_say = {}
gameforge.main_quest_lv95._220_say = "Entendido. Voy a buscarlo enseguida. "
gameforge.main_quest_lv95._230_sayTitle = "\161Interrumpe el env\237o! "
gameforge.main_quest_lv95._240_say = "Localiza al Capit\225n Shrak y consigue la bolsa[ENTER]donde lleva el oro negro antes de que se lo[ENTER]entregue a la Banshee. "
gameforge.main_quest_lv95._250_say = "El Capit\225n Shrak es un peso pesado. \161Pero t\250[ENTER]puedes vencerlo! Int\233ntalo de nuevo. "
gameforge.main_quest_lv95._260_1_notice = "Has obtenido la bolsa. "
gameforge.main_quest_lv95._260_2_notice = "Ll\233vasela al Almirante Angmur. "
gameforge.main_quest_lv95._270_say = "Ll\233vale el bot\237n al Almirante Angmur. "
gameforge.main_quest_lv95._280_say = "\191El Oro negro est\225 en esta bolsa? \161Vamos a verlo![ENTER]\191Pero qu\233...? Solamente hay una nota. "
gameforge.main_quest_lv95._290_say = "El env\237o del Oro negro se llevar\225 a cabo cuando[ENTER]est\233 completamente refinado. "
gameforge.main_quest_lv95._300_say = "Maldici\243n, el Oro negro sigue estando en las[ENTER]manos equivocadas. Por lo menos ahora sabemos que[ENTER]hay que refinarlo antes de que la Banshee lo[ENTER]pueda utilizar para sus designios. "
gameforge.main_quest_lv95._310_say = "A\250n no es demasiado tarde. Voy a averiguar qui\233n[ENTER]posee ahora mismo el oro negro y si ya lo han[ENTER]refinado. Te har\233 llamar en cuanto sepa algo m\225s.[ENTER]Toma esto como recompensa. \161Hasta pronto! "
gameforge.main_quest_lv95._320_sendLetter = "Detener el proceso de refinamiento "
gameforge.main_quest_lv95._330_say = "Ve a ver al Almirante Angmur. Tiene novedades[ENTER]sobre el Oro negro. "
gameforge.main_quest_lv95._340_say = "Hemos descubierto que el Gran ogro controla en[ENTER]persona el proceso de refinamiento del Oro negro[ENTER]y tambi\233n se encarga de entreg\225rselo a la[ENTER]Banshee. "
gameforge.main_quest_lv95._350_say = "Ahora mismo se encuentra en el Acantilado de[ENTER]Gautama.[ENTER]Evita que el Oro negro llegue a su objetivo.[ENTER]\161Date prisa, hazlo antes de que sea demasiado[ENTER]tarde! "
gameforge.main_quest_lv95._360_say = {}
gameforge.main_quest_lv95._370_sayTitle = "El Gran ogro "
gameforge.main_quest_lv95._380_say = "Vence al l\237der de los Ogros y evita que refinen[ENTER]el Oro negro. "
gameforge.main_quest_lv95._390_say = "\161Cada minuto cuenta! \161Det\233n al Gran ogro! "
gameforge.main_quest_lv95._400_notice = "Has derrotado al Gran ogro. "
gameforge.main_quest_lv95._410_say = "\161No pod\233is detenernos! La Banshee ya ha recibido[ENTER]el Oro negro. \161Demasiado tarde, necios! "
gameforge.main_quest_lv95._420_say = "El lazo se est\225 estrechando. Vuelve con el[ENTER]Almirante Angmur e inf\243rmale. "
gameforge.main_quest_lv95._430_say = "Habla con el Almirante Angmur. "
gameforge.main_quest_lv95._440_say = "\161Qu\233 r\225pido! \191Tienes el Oro negro? "
gameforge.main_quest_lv95._450_say = "No, llegu\233 demasiado tarde. Ya est\225 en manos de[ENTER]la Banshee. "
gameforge.main_quest_lv95._460_say = "Que el Dios Drag\243n no proteja. \161Pero no nos vamos[ENTER]a dar por vencido! Voy a enviar a mis esp\237as para[ENTER]que descubran d\243nde se encuentra la Banshee. En[ENTER]cuanto lo sepa te lo har\233 saber. Descansa un poco[ENTER]y toma esto como recompensa. "
gameforge.main_quest_lv95._470_sendLetter = "La Maldici\243n de la vida "
gameforge.main_quest_lv95._480_say = "El Almirante Angmur tiene m\225s informaci\243n.[ENTER]Ve a verlo. "
gameforge.main_quest_lv95._490_say = "Solamente sabemos a qu\233 se refiere eso de la[ENTER]Maldici\243n de la vida y lo del ej\233rcito de la[ENTER]oscuridad. Anta\241o viv\237a en el Pe\241asco del Drag\243n[ENTER]Oscuro un mago perverso. Ansiaba dominar todo el[ENTER]continente, y se dedicaba a ese empe\241o sin[ENTER]contemplaciones: gracias a un oscuro conjuro[ENTER]llamado la Maldici\243n de la vida logr\243 despertar a[ENTER]los muertos y enviarlos a la batalla. "
gameforge.main_quest_lv95._500_say = {}
gameforge.main_quest_lv95._510_say = "Invocar a los muertos... tiemblo solamente de[ENTER]imaginarlo. Los Servidores de la oscuridad[ENTER]pretenden crear un ej\233rcito de muertos gracias al[ENTER]Oro negro. \161Tenemos que detenerlos! "
gameforge.main_quest_lv95._520_say = "Busca al mago de los Lemures en las antiguas[ENTER]ruinas del Acantilado de Gautama. Quiz\225s sepa[ENTER]algo sobre esa maldici\243n. Seguro que te dir\225 todo[ENTER]lo que sabe si se lo pides con... educaci\243n. "
gameforge.main_quest_lv95._530_say = "Ped\237rselo con educaci\243n, claro. Entendido. "
gameforge.main_quest_lv95._540_sayTitle = "La Maldici\243n de la vida "
gameforge.main_quest_lv95._550_say = "Vence al mago Lemur y re\250ne informaci\243n sobre la[ENTER]Maldici\243n de la vida y la invocaci\243n de los[ENTER]muertos. "
gameforge.main_quest_lv95._560_say = "No podemos perder ni un segundo. Vence al mago[ENTER]Lemur y hazle cantar todo lo que sepa sobre la[ENTER]maldici\243n de la vida. "
gameforge.main_quest_lv95._570_1_notice = "Has derrotado al mago Lemur y has encontrado una[ENTER]placa de piedra con una inscripci\243n. "
gameforge.main_quest_lv95._570_2_notice = "Mu\233strasela al Almirante Angmur. "
gameforge.main_quest_lv95._580_say = "Ve a informar al Almirante Angmur. "
gameforge.main_quest_lv95._590_say = "Ah, \191el mago Lemur llevaba esta Tabla consigo?[ENTER]D\233jame ver. "
gameforge.main_quest_lv95._600_sayReward = "Son necesarias tres cosas para despertar a los[ENTER]muertos:[ENTER]1) Un cuerpo humano[ENTER]2) ...[ENTER]La Tabla lem\250rida est\225 rota en esta parte. Falta[ENTER]el resto de la inscripci\243n. "
gameforge.main_quest_lv95._610_say = "Me temo que tendr\225s que volver a salir;[ENTER]necesitamos el resto de esta inscripci\243n. Tienen[ENTER]que existir dos trozos m\225s de la Tabla lem\250rida. "
gameforge.main_quest_lv95._620_say = "Aqu\237 tienes una recompensa por todo lo que has[ENTER]hecho hasta ahora. \161Y ahora, sal a buscar las[ENTER]otras Tablas lem\250ridas! "
gameforge.main_quest_lv95._630_sendLetter = "La inscripci\243n "
gameforge.main_quest_lv95._640_sayTitle = "\161Encuentra las Tablas lem\250ridas! "
gameforge.main_quest_lv95._650_say = "Vence al mago Lemur y encuentra los fragmentos[ENTER]restantes de la Tabla lem\250rida. "
gameforge.main_quest_lv95._660_say = "Por favor, necesitamos saber qu\233 pone en la[ENTER]inscripci\243n. \161Ve a averiguarlo! "
gameforge.main_quest_lv95._670_say = "Ll\233vale al Almirante Angmur los dos trozos[ENTER]restantes de la Tabla lem\250rida. "
gameforge.main_quest_lv95._680_say = "\161Ah, has vuelto! Vamos a reconstruir la Tabla[ENTER]lem\250rida para poder leer la inscripci\243n. "
gameforge.main_quest_lv95._690_sayReward = "Son necesarias tres cosas para despertar a los[ENTER]muertos:[ENTER]1) Un cuerpo humano[ENTER]2) Oro negro[ENTER]3) La corteza de \193rboles demon\237acos[ENTER]Solamente un mago que disponga de la habilidad[ENTER]necesaria podr\225 invocar y mantener la maldici\243n[ENTER]de la vida. Y cuando muera, todo el ej\233rcito de[ENTER]muertos vivientes caer\225 con \233l. "
gameforge.main_quest_lv95._700_say = "As\237 que por esto \250ltimamente han estado[ENTER]profanando nuestros cementerios y robando[ENTER]cad\225veres.[ENTER]Pretenden despertarlos y lanzar un ej\233rcito de[ENTER]muertos vivientes contra nosotros.[ENTER]\161Qu\233 perspectiva tan terrible! "
gameforge.main_quest_lv95._710_say = "\161Tenemos que detener este sacrilegio! "
gameforge.main_quest_lv95._720_say = "S\237, pero el tiempo juega en nuestra contra.[ENTER]Solamente la Banshee es lo suficientemente[ENTER]poderosa como para invocar una maldici\243n[ENTER]semejante, pero no sabemos d\243nde se esconde. Voy[ENTER]a enviar a m\225s de mis hombres a encontrar el[ENTER]escondite de la gran sacerdotisa oscura. En[ENTER]cuanto sepa m\225s te har\233 llamar. "
gameforge.main_quest_lv95._730_say = {}
gameforge.main_quest_lv95._740_say = "La aventura continuar\225 en cuanto alcances el[ENTER]nivel 96. "
gameforge.main_quest_lv95._750_say = "Ve a informar al Almirante Angmur. "
gameforge.main_quest_lv95._760_say = "(Restantes: %s %s, %s %s) "
gameforge.main_quest_lv95._770_sayReward = {}
gameforge.main_quest_lv96 = {}
gameforge.main_quest_lv96._010_sendLetter = "Evitar la maldici\243n "
gameforge.main_quest_lv96._020_say = "El Almirante Angmur quiere hablar contigo. "
gameforge.main_quest_lv96._030_say = "Me alegro de que est\233s aqu\237. hemos encontrado una[ENTER]manera de sabotear los planes de los Servidores[ENTER]de la oscuridad y de la Banshee. "
gameforge.main_quest_lv96._040_say = {}
gameforge.main_quest_lv96._050_say = {}
gameforge.main_quest_lv96._060_say = "Se necesita un m\233dium para que las almas de los[ENTER]muertos abandonen su cad\225ver. Aparentemente se[ENTER]trata de tierra bendecida que los Gigantes[ENTER]guardan en sacos. Si consigues obtener 100 de[ENTER]ellos podr\237amos detener la Maldici\243n de la vida. "
gameforge.main_quest_lv96._070_say = "\161Me pondr\233 en marcha inmediatamente! "
gameforge.main_quest_lv96._080_sayTitle = "Tierra bendita "
gameforge.main_quest_lv96._090_say = "Vence a los Gigantes y obt\233n 100 sacos llenos de[ENTER]Tierra bendita. "
gameforge.main_quest_lv96._100_say = "El tiempo est\225 en nuestra contra. \161R\225pido, date[ENTER]prisa y apr\243piate de los sacos llenos de Tierra[ENTER]bendita! "
gameforge.main_quest_lv96._110_1_notice = "Has conseguido todos los sacos llenos de Tierra[ENTER]bendita. "
gameforge.main_quest_lv96._110_2_notice = "Ll\233vaselas al Almirante Angmur. "
gameforge.main_quest_lv96._120_say = "Ve a informar al Almirante Angmur. "
gameforge.main_quest_lv96._130_say = "\161Siempre se puede confiar en ti! Muchas gracias.[ENTER]Toma esto a modo de recompensa. "
gameforge.main_quest_lv96._140_sendLetter = "Evitar la maldici\243n "
gameforge.main_quest_lv96._150_say = "El Almirante Angmur tiene otro encargo para ti. "
gameforge.main_quest_lv96._160_say = "Los Ogros tambi\233n custodian un medio para la[ENTER]invocaci\243n de los muertos. Pero no sabemos qu\233[ENTER]aspecto tiene. Visita a los Ogros y trae[ENTER]cualquier cosa que te parezca sospechosa. "
gameforge.main_quest_lv96._170_say = {}
gameforge.main_quest_lv96._180_say = {}
gameforge.main_quest_lv96._190_say = "Entendido. "
gameforge.main_quest_lv96._200_sayTitle = "El medio de los Ogros "
gameforge.main_quest_lv96._210_say = "Derrota a lo Ogros y descubre qu\233 aspecto tiene[ENTER]su medio. "
gameforge.main_quest_lv96._220_say = "S\233 que no tienes muchos indicios, \161pero algo[ENTER]encontrar\225s, seguro! "
gameforge.main_quest_lv96._230_1_notice = "Has encontrado una Bolsa de monedas y una[ENTER]Insignia dorada. "
gameforge.main_quest_lv96._230_2_notice = "Ll\233vale ambos objetos al Almirante Angmur. "
gameforge.main_quest_lv96._240_say = "Ve a informar al Almirante Angmur. "
gameforge.main_quest_lv96._250_say = "\161Bien hecho! Le pedir\233 a Yon-I-Walker que analice[ENTER]estos objetos. "
gameforge.main_quest_lv96._260_say = "Busca a Yon-I-Walker para que te revele el[ENTER]resultado de sus an\225lisis. "
gameforge.main_quest_lv96._270_say = "\161Ah, has vuelto! Ya les he echado un vistazo a[ENTER]los objetos que encontraste donde los Ogros. "
gameforge.main_quest_lv96._280_say = {}
gameforge.main_quest_lv96._290_say = "De las monedas que hay en la bolsa emana una[ENTER]fuerte energ\237a oscura.[ENTER]Ellas son el medio.[ENTER]Informa de ello a Angmur. "
gameforge.main_quest_lv96._300_sendLetter = "Evitar la maldici\243n "
gameforge.main_quest_lv96._310_say = "Ve a ver al Almirante Angmur. "
gameforge.main_quest_lv96._320_say = "Toma, ten esta Banda del buscaoro. Te ayudar\225 a[ENTER]encontrar las Bolsas de monedas de los Ogros. "
gameforge.main_quest_lv96._330_say = "necesitamos 100 Monedas de oro. Pero temo que no[ENTER]todas las que encontrar\225s sirven como medio de[ENTER]invocaci\243n. As\237 pues, te espera un tedioso[ENTER]trabajo. "
gameforge.main_quest_lv96._340_say = "De acuerdo. "
gameforge.main_quest_lv96._350_sayTitle = "Cazar oro "
gameforge.main_quest_lv96._360_say = "Ded\237cate a combatir a los Ogros y re\250ne Monedas[ENTER]de oro. No todas sirven como medio de invocaci\243n,[ENTER]as\237 que mu\233straselas a Yon-I-Walker. "
gameforge.main_quest_lv96._370_say = "S\237, aqu\237 puedo sentir claramente magia oscura. "
gameforge.main_quest_lv96._380_say = "Fant\225stico, ya tenemos todas las monedas de oro[ENTER]que podr\237an servir de medio. \161Esto no le va a[ENTER]gustar a la Banshee, sin duda! Toma, ten esta[ENTER]recompensa. Angmur te dir\225 cu\225l es tu pr\243xima[ENTER]misi\243n. "
gameforge.main_quest_lv96._390_say = "A\250n faltan monedas de oro. Re\250ne %d m\225s. "
gameforge.main_quest_lv96._400_sendLetter = "Evitar la maldici\243n "
gameforge.main_quest_lv96._410_say = "El Almirante Angmur te busca. "
gameforge.main_quest_lv96._420_say = "Tenemos que encargarnos de que los Servidores de[ENTER]la oscuridad no se hagan con la Cortezas de[ENTER]\225rboles demon\237acos. "
gameforge.main_quest_lv96._430_say = "Los \193rboles demon\237acos son una de las razas m\225s[ENTER]enigm\225ticas de nuestro mundo. No est\225n al[ENTER]servicio de nadie, ni siquiera de Sung Mahi.[ENTER]En el Acantilado de Gautama hay tres variedades:[ENTER]Aku-Boku, Arboretum y Sicomoro. \161Qu\237tales su[ENTER]corteza! "
gameforge.main_quest_lv96._440_say = {}
gameforge.main_quest_lv96._450_say = "Entendido. "
gameforge.main_quest_lv96._460_sayTitle = "Descortezar \193rboles demon\237acos "
gameforge.main_quest_lv96._470_say = "Arr\225ncale la corteza a un Aku-Boku, Arboretum y[ENTER]Sicomoro. "
gameforge.main_quest_lv96._480_counterName = "(Restantes: %s %s, %s %s) "
gameforge.main_quest_lv96._490_say = {}
gameforge.main_quest_lv96._500_say = "El tiempo apremia. \161Haz le\241a de esos \193rboles[ENTER]demon\237acos y arreb\225tales su corteza antes de que[ENTER]lo hagan los Servidores de la oscuridad! "
gameforge.main_quest_lv96._510_1_notice = "Has vencido a todos los \193rboles demon\237acos, pero[ENTER]alguien se te ha adelantado: ya hab\237an arrancado[ENTER]la corteza de sus troncos. "
gameforge.main_quest_lv96._510_2_notice = "Informa de esto al Almirante Angmur. "
gameforge.main_quest_lv96._520_say = "Ve a informar al Almirante Angmur. "
gameforge.main_quest_lv96._530_say = "\161Qu\233 bien, has vuelto inc\243lume! \191Lo lograste?[ENTER]\161\191Como?! \191Que la corteza de los \193rboles[ENTER]demon\237acos ya hab\237a sido arrancada y hab\237a se\241as[ENTER]de lucha?[ENTER]Entonces est\225 claro que los Servidores de la[ENTER]oscuridad se nos han adelantado. "
gameforge.main_quest_lv96._540_say = {}
gameforge.main_quest_lv96._550_say = "Si tienen las cortezas, seguramente est\233n a punto[ENTER]de lanzar la Maldici\243n de la vida. As\237 que es[ENTER]inevitable: vamos a la guerra. La Banshee no[ENTER]puede esconderse de nosotros mucho m\225s tiempo.[ENTER]Mis hombres le siguen la pista.[ENTER]Te har\233 llamar cuando la hayamos encontrado. "
gameforge.main_quest_lv96._560_sayTitle = "La aventura continuar\225 en cuanto alcances el[ENTER]nivel 97. "
gameforge.main_quest_lv96._570_counterName = "(Restantes: %s %s, %s %s) "
gameforge.main_quest_lv96._580_sayReward = "%s: %d unidad/es "
gameforge.main_quest_lv96._590_say = "As\237 que las monedas sirven de medio. Bien,[ENTER]entonces voy a pedirle consejo a Yon-I-Walker[ENTER]sobre nuestros siguientes pasos . Me pondr\233 en[ENTER]contacto contigo enseguida. "
gameforge.main_quest_lv96._600_say = {}
gameforge.main_quest_lv96._610_say = {}
gameforge.main_quest_lv96._620_1_notice = "Has obtenido una Bolsa de monedas. "
gameforge.main_quest_lv96._620_2_notice = "Ll\233vasela a Yon-I-Walker. "
gameforge.main_quest_lv96._630_say = "Esta es una moneda normal y corriente. \161Sigue[ENTER]buscando! "
gameforge.main_quest_lv97 = {}
gameforge.main_quest_lv97._010_sendLetter = "Detener a la Banshee "
gameforge.main_quest_lv97._020_say = "\161Hemos localizado el escondrijo de la Banshee! Ve[ENTER]a ver al Almirante Angmur para obtener m\225s[ENTER]informaci\243n. "
gameforge.main_quest_lv97._030_say = "Mis hombres han localizado por fin la guarida de[ENTER]la Banshee en el Acantilado de Gautama. Se ha[ENTER]agazapado en la oscuridad de los bosques de la[ENTER]zona y desde all\237 practica su oscura magia.[ENTER]Adem\225s ha recuperado a una de las antiguas[ENTER]servidoras del templo del culto del drag\243n. Junto[ENTER]con ella querr\225 conjurar ahora la Maldici\243n de la[ENTER]vida. "
gameforge.main_quest_lv97._040_say = "Si no la tiene a su lado, la Banshee no podr\225[ENTER]prolongar la Maldici\243n. Vence a Mu-Shu, servidora[ENTER]del templo, y serena las almas de nuestros[ENTER]camaradas antes de que sus cad\225veres se alcen[ENTER]contra nosotros. "
gameforge.main_quest_lv97._050_say = "Es casi imposible acercarse sigilosamente a la[ENTER]servidora del templo para atacarla. Tendr\225s una[ENTER]oportunidad cuando est\233 absorta en su nefando[ENTER]conjuro, porque entonces entra en trance. "
gameforge.main_quest_lv97._060_say = "De acuerdo. "
gameforge.main_quest_lv97._070_say = "\161Ve con cuidado! En vida fue la principal[ENTER]guardaespaldas de la Sacerdotisa mayor, y es muy[ENTER]ducha tanto en la magia como en la esgrima. "
gameforge.main_quest_lv97._080_sayTitle = "La servidora del templo "
gameforge.main_quest_lv97._090_say = "Vence a Mu-Shu, servidora del templo de la[ENTER]Banshee, en el Acantilado de Gautama. "
gameforge.main_quest_lv97._100_notice = "Herida de muerte, la servidora del templo cae al[ENTER]suelo. "
gameforge.main_quest_lv97._110_say = "\161Necios! Hab\233is caido en la trampa que la Banshee[ENTER]os hab\237a preparado. Mientras perd\237ais el tiempo[ENTER]conmigo, mi se\241ora y Yah-ki, la verdadera[ENTER]servidora del templo, han empezado ya la[ENTER]Maldici\243n. \161Ojal\225 consigan llevarla a t\233rmino! "
gameforge.main_quest_lv97._120_say = "\161Una doble os ha desviado de vuestro objetivo![ENTER]Tras inspeccionar su cuerpo, encuentras un collar[ENTER]parecido al de Martyaxwar. En el bolsillo[ENTER]interior llevaba tambi\233n un documento. "
gameforge.main_quest_lv97._130_say = "Ve a informar al Almirante Angmur. "
gameforge.main_quest_lv97._140_say = "\161Has vuelto! \191Has vencido a la servidora del[ENTER]templo? "
gameforge.main_quest_lv97._150_say = "No, una doble consigui\243 enga\241arnos. La verdadera[ENTER]servidora del templo ha podido preparar con calma[ENTER]el conjuro para despertar a los muertos. Toma, la[ENTER]doble llevaba encima este documento. "
gameforge.main_quest_lv97._160_say = "\161Maldici\243n! \191C\243mo hemos podido ser tan ingenuos?[ENTER]A ver, ens\233\241ame ese documento. "
gameforge.main_quest_lv97._170_say = {}
gameforge.main_quest_lv97._180_say = {}
gameforge.main_quest_lv97._190_say = "Vaya, est\225 cifrado. Pero el mensaje quiz\225 nos[ENTER]revele d\243nde se encuentra su verdadera base.[ENTER]Estos signos los he visto ya en alguna parte...[ENTER]Creo que Yak-Hwan, el guardia de palacio, me[ENTER]ense\241\243 hace poco algo parecido. Ve a verle. Dile[ENTER]que le eche un vistazo. "
gameforge.main_quest_lv97._200_sendLetter = "Descifrar el documento "
gameforge.main_quest_lv97._210_say = "Ve a ver a Yak-Hwan y mu\233strale el documento[ENTER]encriptado. "
gameforge.main_quest_lv97._220_say = "\161Bienvenido! Me llamo Yak-Hwan. Es un honor[ENTER]conocerte. Tus haza\241as son ya legendarias. \191Qu\233[ENTER]puedo hacer por ti? Ah, un mensaje encriptado.[ENTER]D\233jame verlo. "
gameforge.main_quest_lv97._230_say = "S\237, no tendr\233 problemas en descifrar estos[ENTER]s\237mbolos.[ENTER]Pero para ello necesito Tierra f\243sil. El[ENTER]Alquimista deber\237a tener a\250n algunos terrones.[ENTER]P\237deselos. "
gameforge.main_quest_lv97._240_say = {}
gameforge.main_quest_lv97._250_say = {}
gameforge.main_quest_lv97._260_say = "Por supuesto. "
gameforge.main_quest_lv97._270_sayTitle = "Tierra f\243sil "
gameforge.main_quest_lv97._280_say = "Ve a ver al Alquimista y preg\250ntale por la Tierra[ENTER]f\243sil. "
gameforge.main_quest_lv97._290_say = "\191No olvidas nada? Ten\237as que traerme Tierra f\243sil. "
gameforge.main_quest_lv97._300_notice = "El Alquimista te ha hado la Tierra f\243sil. Vuelve[ENTER]con Yak-Hwan. "
gameforge.main_quest_lv97._310_say = "Ah, la Tierra f\243sil. Muy bien, pondr\233 manos a la[ENTER]obra.[ENTER]Ya le comunicar\233 al Almirante los resultados. "
gameforge.main_quest_lv97._320_sendLetter = "Por la puerta trasera "
gameforge.main_quest_lv97._330_say = "El Almirante Angmur te busca. "
gameforge.main_quest_lv97._340_say = "Hemos descubierto d\243nde se encuentra Yah-Ki, la[ENTER]servidora del templo. Pero su base es una[ENTER]aut\233ntica fortaleza: hay patrullas de vigilancia[ENTER]d\237a y noche.[ENTER]Un ataque frontal ser\237a en estos momentos un[ENTER]suicidio. "
gameforge.main_quest_lv97._350_say = "Por eso queremos atacar mediante una emboscada.[ENTER]Mis hombres buscan ahora el lugar m\225s apropiado.[ENTER]Desv\237a la atenci\243n de los guardias para[ENTER]conseguirnos algo m\225s de tiempo. "
gameforge.main_quest_lv97._360_say = {}
gameforge.main_quest_lv97._370_say = "El mayor peligro est\225 en una patrulla de[ENTER]vigilancia que se hace llamar la Brigada de[ENTER]muerte negra.[ENTER]Est\225 compuesta por Moghu, Carn\237fex y el General[ENTER]Albus, y tiene a Skeletos como l\237der. Acaba con[ENTER]ellos antes de que descubran a mis exploradores. "
gameforge.main_quest_lv97._380_say = "De acuerdo. "
gameforge.main_quest_lv97._390_sayTitle = "Brigada de la muerte negra "
gameforge.main_quest_lv97._400_say = "Acaba con los integrantes de la Brigada de la[ENTER]muerte negra: Moghu, Carn\237fex, general Albus y[ENTER]Skeletos. "
gameforge.main_quest_lv97._410_say = "Acaba con los miembros de la Brigada de la muerte[ENTER]negra antes de que descubran a los exploradores. "
gameforge.main_quest_lv97._420_say = "Ve a informar al Almirante Angmur. "
gameforge.main_quest_lv97._430_say = "\161El plan ha funcionado! Mientras t\250 distra\237as a[ENTER]la Brigada de la muerte negra, mis hombres han[ENTER]encontrado el lugar idoneo para una emboscada. En[ENTER]cuanto tengamos una estrategia de ataque te har\233[ENTER]llamar. "
gameforge.main_quest_lv97._440_sendLetter = "La servidora del templo "
gameforge.main_quest_lv97._450_say = "\161El Almirante Angmur necesita tu ayuda! "
gameforge.main_quest_lv97._460_say = "Menos mal que has venido. Skeletos, el l\237der de[ENTER]la Brigada de la muerte negra, ha sobrevivido y[ENTER]consigui\243 atacar a mis hombres cuando estos[ENTER]intentaban asaltar la base. Nadie es capaz de[ENTER]superarlo. "
gameforge.main_quest_lv97._470_say = {}
gameforge.main_quest_lv97._480_say = "Ya le has vencido una vez, y por eso te pido:[ENTER]ayuda a mis hombres en el Acantilado de Gautama.[ENTER]Enfr\233ntate a Skeletos y acto seguido asalta la[ENTER]base y da muerte a Yah-ki, la servidora del[ENTER]templo. "
gameforge.main_quest_lv97._490_say = "Entendido. "
gameforge.main_quest_lv97._500_say = {}
gameforge.main_quest_lv97._510_sayTitle = "Eliminar a Yah-ki "
gameforge.main_quest_lv97._520_say = "Acaba con la servidora del templo Yah-ki y evita[ENTER]que conjure al ej\233rcito de los muertos. "
gameforge.main_quest_lv97._530_say = "Ha llegado la hora de la verdad. Si fracasamos,[ENTER]el mundo entero est\225 perdido. Pero si triunfamos,[ENTER]nuestra haza\241a pervivir\225 por los siglos en cantos[ENTER]de alabanza. Det\233n a la servidora de la[ENTER]oscuridad.[ENTER]\161Acaba con Yah-ki, la servidora del templo! "
gameforge.main_quest_lv97._540_say = "\191Qu\233 haces aqu\237? \161La batalla no est\225 ganada[ENTER]todav\237a![ENTER]Acaba con Yah-ki, la servidora del templo. En ti[ENTER]tenemos depositadas nuestras esperanzas. "
gameforge.main_quest_lv97._550_1_notice = "Has conseguido doblegar a tu adversario. \161Tuya es[ENTER]la victoria! "
gameforge.main_quest_lv97._550_2_notice = "No tienes tiempo para descansar: Yah-Ki, la[ENTER]servidora del templo, te espera ya. "
gameforge.main_quest_lv97._560_notice = "\161Has vencido! Con un aullido estremecedor, Yah-Ki[ENTER]cae a tierra. "
gameforge.main_quest_lv97._570_say = "\161Aaaaahhh! \161No es posible! Vencida por un[ENTER]mortal...[ENTER]Oh, Banshee, \161perd\243name! Te he fallado.[ENTER]No consegu\237 cumplir mi mm... "
gameforge.main_quest_lv97._580_say = "Examinas el cuerpo ex\225nime y encuentras una carta[ENTER]sellada. Vuelve con ella junto al Almirante[ENTER]Angmur. "
gameforge.main_quest_lv97._590_say = "\161Bendito sea el Dios Drag\243n! Vuelves inc\243lume.[ENTER]\191Has vencido a la servidora del templo? "
gameforge.main_quest_lv97._600_say = "S\237, la envi\233 de vuelta al mismo infierno del que[ENTER]sali\243.[ENTER]En su agon\237a pidi\243 perd\243n a la Banshee por su[ENTER]fracaso. Llevaba esto encima. "
gameforge.main_quest_lv97._610_say = "Una carta sellada. \161D\225mela! "
gameforge.main_quest_lv97._620_sayReward = "Mi se\241ora, \161han mordido el anzuelo! Vuestro plan[ENTER]ha funcionado.[ENTER]La conjura del ej\233rcito de los muertos sigue su[ENTER]rumbo, y nadie puede detenernos ya. Cuando los[ENTER]cuerpos sin alma se alcen, marcharemos sobre el[ENTER]Cabo del Drag\243n de Fuego y sepultaremos a sus[ENTER]habitantes. A continuaci\243n saltaremos a tierra[ENTER]firme y nos reuniremos con vos en la Tierra de[ENTER]Fuego. \161La tierra arder\225 a nuestro paso![ENTER]Con la mayor reverencia, vuestra eterna servidora "
gameforge.main_quest_lv97._630_say = "\161Un mensaje para la Banshee! Efectivamente, la[ENTER]nefanda bruja espera ahora en vano a su ej\233rcito[ENTER]de las tinieblas.[ENTER]Muchas gracias. Sin tu ayuda, el ej\233rcito de los[ENTER]muertos habr\237a arrasado el Cabo y a todos sus[ENTER]habitantes. No solo nos has salvado a todos, sino[ENTER]que has devuelto la paz a nuestros antepasados.[ENTER]Te entrego esta recompensa en nombre de todo el[ENTER]fuerte. "
gameforge.main_quest_lv97._640_sayTitle = "La aventura continuar\225 tan pronto alcances el[ENTER]nivel 98. "
gameforge.main_quest_lv97._650_say = "Hemos necesitado mucho tiempo para localizar el[ENTER]fuerte. \161Por favor, no podemos perder m\225s tiempo! "
gameforge.main_quest_lv97._660_say = "\191Yak-Hwan necesita Tierra f\243sil? Suerte que a\250n[ENTER]no la he gastado toda. Toma, toma.[ENTER]Ll\233vasela y dale saludos de mi parte. "
gameforge.main_quest_lv97._670_counterName = "(Restantes: %s %s, %s %s) "
gameforge.main_quest_lv97._680_sayReward = {}
gameforge.main_quest_lv97._690_1_notice = "Has eliminado a la Brigada de la muerte negra. "
gameforge.main_quest_lv97._690_2_notice = "Ve a informar al Almirante Angmur. "
gameforge.main_quest_lv97._700_sayTitle = "\161Vence a Skeletos, l\237der de la Brigada de la[ENTER]muerte negra! "
gameforge.main_quest_lv97._710_say = "La servidora del templo solo podr\225 ser aniquilada[ENTER]por completo una vez termines con Skeletos. "
gameforge.main_quest_lv98 = {}
gameforge.main_quest_lv98._010_sendLetter = "Reconstrucci\243n del fuerte "
gameforge.main_quest_lv98._020_say = "El Almirante Angmur solicita tu ayuda. Ve a verle. "
gameforge.main_quest_lv98._030_say = "Gracias por acudir. La lucha ha dejado profundas[ENTER]huellas en todos nosotros. El fuerte ha sido[ENTER]asaltado, y el muro protector est\225 derruido en[ENTER]muchos puntos. La paz no durar\225 mucho.[ENTER]Deber\237amos aprovechar esta tregua para[ENTER]reconstruirlo. "
gameforge.main_quest_lv98._040_say = "Para afianzar el muro protector necesitamos las[ENTER]armaduras de los Crustacianos. "
gameforge.main_quest_lv98._050_say = "Entendido. \191Cu\225ntas armaduras ser\225n necesarias? "
gameforge.main_quest_lv98._060_say = "100 armaduras deber\237an ser suficientes.[ENTER]Los Crustacianos habitan todav\237a en la Bah\237a de[ENTER]Nephrit. "
gameforge.main_quest_lv98._070_say = "Vaya, estas armaduras no son suficientes.[ENTER]Por favor, ve a por m\225s. "
gameforge.main_quest_lv98._080_1_notice = "Ya tienes todas las Armaduras crust\225ceas. "
gameforge.main_quest_lv98._080_2_notice = "Ll\233vaselas al Almirante Angmur. "
gameforge.main_quest_lv98._090_say = "Muy bien. Con la Armadura crust\225cea podremos[ENTER]afianzar de nuevo el muro protector. Acepta esto[ENTER]como recompensa. Preguntar\233 a mis ingenieros si[ENTER]necesitan materiales y te comunicar\233 su[ENTER]respuesta. "
gameforge.main_quest_lv98._130_sendLetter = "Reconstrucci\243n del fuerte "
gameforge.main_quest_lv98._140_say = "El Almirante Angmur vuelve a necesitar tu ayuda.[ENTER]Ve a verle. "
gameforge.main_quest_lv98._150_say = "Para reforzar nuestra posici\243n necesitamos Lanzas[ENTER]de trit\243n. El nombre te habr\225 dado una pista de[ENTER]d\243nde encontrarlas. Por favor, tr\225eme 100[ENTER]unidades. "
gameforge.main_quest_lv98._160_say = "Entendido. "
gameforge.main_quest_lv98._170_say = "\161Ya est\225s de vuelta! Ah, pero estas Lanzas de[ENTER]trit\243n no son suficientes. Ve a obtener unas[ENTER]cuantas m\225s. "
gameforge.main_quest_lv98._180_1_notice = "Has reunido todas las Lanzas de trit\243n. "
gameforge.main_quest_lv98._180_2_notice = "Ll\233vaselas al Almirante Angmur. "
gameforge.main_quest_lv98._190_say = "\161Perfecto! Ahora s\237 podemos construir unas[ENTER]instalaciones de defensa seguras. Muchas gracias[ENTER]por tu ayuda. A todo esto: Yak-Hwan te busca. Ve[ENTER]a ver qu\233 quiere. "
gameforge.main_quest_lv98._200_sendLetter = "Estado de emergencia "
gameforge.main_quest_lv98._210_say = "Ve a ver a Yak-Hwan. Tiene para ti una tarea[ENTER]importante. "
gameforge.main_quest_lv98._220_say = "Qu\233 bien, ya est\225s aqu\237. De nuevo precisamos tu[ENTER]ayuda. "
gameforge.main_quest_lv98._230_say = {}
gameforge.main_quest_lv98._240_say = {}
gameforge.main_quest_lv98._250_say = {}
gameforge.main_quest_lv98._260_say = "La dureza del conflicto ha pasado factura a los[ENTER]habitantes del fuerte. Sufren un hambre atroz, y[ENTER]con cada d\237a que pasa aumenta su miseria.[ENTER]Si no hacemos algo pronto, sus perspectivas son[ENTER]muy, muy malas. "
gameforge.main_quest_lv98._270_say = {}
gameforge.main_quest_lv98._280_say = "Las bandas de Ogros acechan los convoyes de[ENTER]avituallamiento para asaltarlos. Tenemos que[ENTER]poner coto a tanto saqueo. Los responsables son[ENTER]el capit\225n Shrak y sus generales. Mata al capit\225n[ENTER]de los Ogros y 50 generales Ogg. "
gameforge.main_quest_lv98._290_say = {}
gameforge.main_quest_lv98._300_say = "\191Ya de vuelta? Aun quedan unos cuantos Ogros[ENTER]sueltos. Acaba con todos, por favor. "
gameforge.main_quest_lv98._310_1_notice = "Has vencido a todos los ogros. "
gameforge.main_quest_lv98._310_2_notice = "Vuelve junto a Yak-Hwan. "
gameforge.main_quest_lv98._320_say = "Los convoyes de alimentos por fin llegan al[ENTER]fuerte, y nuestros ciudadanos reciben alimento y[ENTER]medicamentos. Se termin\243 el hambre.[ENTER]Verdaderamente, eres un h\233roe. "
gameforge.main_quest_lv98._330_sendLetter = "Agradecimiento "
gameforge.main_quest_lv98._340_say = "Yak-Hwan quiere hablar contigo. "
gameforge.main_quest_lv98._350_say = "Gracias a tu ayuda se ha podido repeler, siquiera[ENTER]temporalmente, el peligro en el Pe\241asco del[ENTER]Drag\243n Oscuro. Todos sus ciudadanos quieren[ENTER]manifestarte en persona su agradecimiento. "
gameforge.main_quest_lv98._360_say = "Por favor, date una vuelta por el fuerte y habla[ENTER]con la gente. "
gameforge.main_quest_lv98._370_say = {}
gameforge.main_quest_lv98._380_say = "Gracias. Ahora ir\233 a visitar a los lugare\241os. "
gameforge.main_quest_lv98._390_say = "No todos los ciudadanos han tenido ocasi\243n de[ENTER]darte las gracias. Estar\225n muy decepcionados.[ENTER]Aseg\250rate de que no te olvidas de ninguno. "
gameforge.main_quest_lv98._400_say = "El valor y la sabidur\237a ocupan a partes iguales[ENTER]tu coraz\243n. Las generaciones venideras cantar\225n[ENTER]todav\237a tus haza\241as. Recibe mi m\225s profundo[ENTER]respeto. "
gameforge.main_quest_lv98._410_say = "\161Quiera el hado verte siempre bien pertrechado[ENTER]contra el peligro! "
gameforge.main_quest_lv98._420_say = "Siempre ocupar\225s un lugar de honor en nuestros[ENTER]corazones. "
gameforge.main_quest_lv98._430_say = "Han sido d\237as turbulentos, \191verdad? Estoy[ENTER]convencido de que el mism\237simo Dios Drag\243n gui\243[ENTER]tus pasos hasta la isla. "
gameforge.main_quest_lv98._440_1_notice = "Has hablado con todos los lugare\241os. "
gameforge.main_quest_lv98._440_2_notice = "Vuelve junto a Yak-Hwan. "
gameforge.main_quest_lv98._450_say = "Eso ha significado mucho para los habitantes del[ENTER]fuerte. El Almirante quiere hablar contigo otra[ENTER]vez. Ve a verle. "
gameforge.main_quest_lv98._460_say = {}
gameforge.main_quest_lv98._470_say = {}
gameforge.main_quest_lv98._480_sendLetter = "Agradecimiento del Almirante "
gameforge.main_quest_lv98._490_say = "El Almirante Angmur quiere manifestarte su[ENTER]agradecimiento. Ve a verlo. "
gameforge.main_quest_lv98._500_say = "De no ser por ti, los Demonios habr\237an arrasado a[ENTER]los habitantes del fuerte. Por tu ayuda en la[ENTER]lucha contra los siervos de la oscuridad quiero[ENTER]darte las gracias en nombre de mis tropas y de[ENTER]toda la poblaci\243n. En el Pe\241asco del Drag\243n[ENTER]Oscuro tendr\225s siempre tu hogar. "
gameforge.main_quest_lv98._510_say = {}
gameforge.main_quest_lv98._520_say = "Aun as\237, la Banshee y los Servidores de la[ENTER]oscuridad no descansan, y aun ahora siguen[ENTER]tramando sus negros planes.[ENTER]Tu aventura continuar\225 tan pronto alcances el[ENTER]nivel 99. "
gameforge.main_quest_lv98._530_sayTitle = {}
gameforge.main_quest_lv98._540_sayTitle = "Reconstrucci\243n del fuerte "
gameforge.main_quest_lv98._550_say = "Enfr\233ntate a los Crustacianos y re\250ne 100[ENTER]Armaduras crust\225ceas. "
gameforge.main_quest_lv98._560_say = "Habla con el Almirante Angmur. "
gameforge.main_quest_lv98._570_sayReward = {}
gameforge.main_quest_lv98._580 = "Refuerza las instalaciones de defensa "
gameforge.main_quest_lv98._590_say = "Ataca a los Tritones y hazte con 100 Lanzas de[ENTER]trit\243n. "
gameforge.main_quest_lv98._600_say = "Ve a ver al Almirante Angmur. "
gameforge.main_quest_lv98._610_sayTitle = "Ogro saqueador "
gameforge.main_quest_lv98._620_say = "Acaba con el capit\225n Shrack y con 50 de sus[ENTER]Generales Ogg y pon fin a los saqueos. "
gameforge.main_quest_lv98._630_say = "Acude junto a Yak-Hwan. "
gameforge.main_quest_lv98._640_sayTitle = "Agradecimiento "
gameforge.main_quest_lv98._650_say = "Date una vuelta por el fuerte y habla con sus[ENTER]habitantes. "
gameforge.main_quest_lv98._660_counterName = "(Restantes: %s %s, %s %s) "
gameforge.main_quest_lv98._670_sayReward = "%s: %d unidad/es "
gameforge.main_quest_lv98._680_counterName = "(Restantes: %s %s, %s %s) "
