gameforge.main_quest_lv98._710_say = "Confucio (%s)[ENTER]Vendedor Tienda Armadura (%s) "
gameforge.main_quest_lv98._720_say = "Vendedora Tienda General (%s)[ENTER]Vendedor de armas (%s) "
gameforge.manwoo = {}
gameforge.manwoo._10_npcChat = "La piscifactor\237a "
gameforge.manwoo._20_sayTitle = "Pescador: "
gameforge.manwoo._30_say = "Me gustar\237a expandir mi piscifactor\237a. Por eso,[ENTER]necesito carpas que aun esten vivas. Estos peces[ENTER]son buenos para criar y son verdaderamente[ENTER]populares entre los pescadores, pero son[ENTER]dif\237ciles de capturar. "
gameforge.manwoo._40_say = "Si me traes una carpa, te dar\233 una recompensa. He[ENTER]tenido un ba\250l en mi \225tico dando vueltas por ah\237[ENTER]durante siglos. Ni puedo recordar lo que hay[ENTER]dentro. Quiz\225 hay algo in\250til dentro, o quiz\225[ENTER]algo valioso. Incluso un monstruo podr\237a estar[ENTER]escondido ah\237. Si lo quieres tener, tr\225eme una[ENTER]carpa viva. "
gameforge.manwoo._50_npcChat = "Intercambiar carpa por ba\250l "
gameforge.manwoo._60_say = "\191Me has tra\237do una Carpa para mi cultivo de[ENTER]peces? \161Gracias! Aqu\237 tienes el Cofre que te[ENTER]promet\237. \161Mucha suerte! "
gameforge.manwoo._70_sayReward = "\161Has obtenido un Cofre![ENTER]\193brelo con un clic en el bot\243n derecho del rat\243n. "
gameforge.map_warp = {}
gameforge.map_warp._100_say = "Date prisa y dime d\243nde quieres ser[ENTER]teletransportado. Estoy cansado. "
gameforge.map_warp._10_npcChat = "Quiero viajar. "
gameforge.map_warp._110_sayReward = "Esto cuesta %s Yang. "
gameforge.map_warp._11_array = "Condado Jungrang "
gameforge.map_warp._120_sayReward = "\161Pero si sigues as\237, aumentar\233 el precio! "
gameforge.map_warp._12_array = "Condado Waryong "
gameforge.map_warp._130_say = "Como dije: S\243lo pudes teletransportarte a este[ENTER]lugar cuando hayas alcanzado el nivel 60.[ENTER]\191Todav\237a quieres teletransportarte? Si no, cierra[ENTER]la ventana. Y deja de cambiar de parecer. No[ENTER]estoy aqu\237 por diversi\243n. "
gameforge.map_warp._13_array = "Condado Imha "
gameforge.map_warp._140_sayReward = "El viaje te costar\225 %d Yang. "
gameforge.map_warp._14_array = "Castillo Milaard "
gameforge.map_warp._150_say = "Podr\237a teletransportarte gratis, pero tengo una[ENTER]familia enorme. A fin de ser capaz de mantenerla,[ENTER]necesito hacer dinero. "
gameforge.map_warp._15_array = "Castillo Listhmos "
gameforge.map_warp._160_sayReward = "Cuesta %s Yang "
gameforge.map_warp._16_array = "Castillo Dendera "
gameforge.map_warp._170_say = "Voy a teletransportarte ahora mismo. Ir\225s a un[ENTER]lugar peligroso. Ten cuidado... y buena suerte... "
gameforge.map_warp._17_array = "Condado Miryang "
gameforge.map_warp._180_select = "Yongan "
gameforge.map_warp._18_array = "Condado Songpa "
gameforge.map_warp._190_select = "Grafschaft Yayang "
gameforge.map_warp._19_array = "Condado Daeyami "
gameforge.map_warp._200_select = "Joan "
gameforge.map_warp._20_sayTitle = "Teletransportador:  "
gameforge.map_warp._210_select = "Condado Bokjung "
gameforge.map_warp._220_select = "Pyungmoo "
gameforge.map_warp._230_select = "Condado Bakra "
gameforge.map_warp._240_say = "Como lo desees. \161Atenci\243n, empezamos! "
gameforge.map_warp._250_say = "Como lo desees... \161Hasta pronto! "
gameforge.map_warp._260_npcChat = "Pe\241asco del Drag\243n Oscuro "
gameforge.map_warp._270_say = "Hace poco se descubri\243 una isla misteriosa a la[ENTER]que llaman el Pe\241asco del Drag\243n Oscuro.[ENTER]Quien quiera sobrevivir en ese lugar necesita[ENTER]tener la experiencia suficiente. Por eso[ENTER]solamente llevo all\237 a luchadores a partir del[ENTER]nivel 90.[ENTER]\191Te atreves a emprender este viaje? "
gameforge.map_warp._280_say = "Solamente se puede acceder a la isla en barco, y[ENTER]la traves\237a es larga y agotadora. Cuanto mayor[ENTER]sea tu nivel, m\225s riguroso resultar\225 el viaje.[ENTER]Por eso tengo que ofrecerte una tarifa m\225s alta. "
gameforge.map_warp._280_sayReward = "El viaje te costar\225 %d Yang. "
