gameforge.map_warp._40_say = "Hmm... Con tu nivel, no puedes resistir el viaje[ENTER]a trav\233s del tiempo y el espacio... Cuando[ENTER]alcances un nivel superior a 10, ser\225s capaz de[ENTER]resistir el viaje. "
