gameforge.neutral_warp._20_sayTitle = "Anciano: "
gameforge.neutral_warp._30_say = "\161Hola! S\233 c\243mo puedes llegar a otras regiones[ENTER]desde aqu\237. Si me das algo de Yang, puedo[ENTER]teletransportarte. "
