gameforge.neutral_warp._65_npcChat = "Quiero ir con la hermana de la Anciana. "
gameforge.neutral_warp._70_say = "La Anciana ya me dijo que vendr\237as. Dijo que no[ENTER]debo cobrarte por este viaje, porque le est\225s[ENTER]haciendo un favor. Solemos tomar t\233 juntas y me[ENTER]alegra ayudarle. \161Pero no te enga\241es a ti mismo[ENTER]pensando que esto seguir\225 siendo as\237 en el[ENTER]futuro! Ten cuidado por all\237, porque aquellos[ENTER]asociados con los reinos extranjeros no son bien[ENTER]recibidos. "
gameforge.new_christmas = {}
gameforge.new_christmas._010_npcChat = "\161Jo, jo, jo! "
gameforge.new_christmas._020_say = "\161Ah, eres t\250![ENTER]Hace tiempo que no nos ve\237amos.[ENTER]\161Ya ha pasado un a\241o, jo, jo![ENTER]Quiz\225s te preguntes por qu\233 Estoy de nuevo en el[ENTER]pueblo.[ENTER]Te lo voy a explicar... "
gameforge.new_christmas._030_say = "Son tiempos dif\237ciles. Nadie quiere comprar[ENTER]libros u otras cosas estos d\237as. Y a mi avanzada[ENTER]edad, volar por los aires en un trineo tirado por[ENTER]renos es demasiado engorroso.[ENTER]Por eso he decidido celebrar la Navidad en el[ENTER]pueblo este a\241o. "
gameforge.new_christmas._040_say = "Si a\250n tienes preguntas, puedes ir a verme en[ENTER]cualquier momento. \161Feliz Navidad! "
gameforge.new_christmas._050_npcChat = "\191Te apetece un Vino Caliente? "
gameforge.new_christmas._060_say = "\161Jo, jo, jo! Seguro que sabes qu\233 es esto,[ENTER]\191verdad? \161No hay mejor bebida para el invierno![ENTER]Mezclas un poco de vino, una pizca de canela, un[ENTER]par de clavos... \161Mmmmm! "
gameforge.new_christmas._070_say = "\161Con este fr\237o, seguro que un trago de Vino[ENTER]Caliente te vendr\225 bien! Te dar\225 fuerzas y podr\225s[ENTER]moverte m\225s deprisa. \191Quieres probarlo?[ENTER]\161Muy bien, enseguida te lo traigo! "
gameforge.new_christmas._080_say = "Parece que el Vino Caliente te gusta, \161jo, jo![ENTER]\191Sientes c\243mo te calienta por dentro?[ENTER]Y ese sabor, tan dulce y afrutado.[ENTER]\161Feliz navidad! "
gameforge.new_christmas._090_npcChat = "\161M\225s Vino Caliente, por favor! "
gameforge.new_christmas._100_say = "\161Ah, un momento! \161Se me olvida un peque\241o[ENTER]detalle! Solamente puedo preparar Vino Caliente[ENTER]una vez al d\237a, porque no tengo suficientes[ENTER]ingredientes para m\225s. Adem\225s, solamente dura 20[ENTER]horas. En una botella hay 6 porciones, y el[ENTER]efecto de un trago dura 30 minutos, \161as\237 que[ENTER]raci\243nalo bien! "
gameforge.new_christmas._110_say = "\161Aqu\237 tienes! Disculpa la larga espera.[ENTER]\161Esta maravillosa bebida te dar\225 alas![ENTER]\161Jo, jo, jo! En fin, espero que te guste.[ENTER]\161Feliz Navidad! "
gameforge.new_christmas._120_say = "\191C\243mo, a\250n quieres m\225s? Lo siento, pero ya[ENTER]bebiste bastante. Desde que tomaste tu \250ltima[ENTER]raci\243n de Vino Caliente a\250n no han pasado 24[ENTER]horas. \161Tomar demasiado no es bueno para ti![ENTER]Vuelve por aqu\237 m\225s tarde.[ENTER]\161Felices fiestas! "
gameforge.new_christmas_gift_box = {}
gameforge.new_christmas_gift_box._010_say = "De %d regalos puedes sacar a\250n %d. "
gameforge.new_christmas_gift_box._020_say = "Puedes sacar el pr\243xim regalo en %d min. "
gameforge.new_christmas_sock = {}
gameforge.new_christmas_sock._010_npcChat = "\191Para qu\233 son esos calcetines? "
gameforge.new_christmas_sock._020_say = "\161Los calcetines! \161Casi se me olvidan! Quer\237a[ENTER]esconder mis regalos en los calcetines que[ENTER]cuelgan sobre la chimenea. \161Pero criaturas muy[ENTER]poco navide\241as me los han robado![ENTER]Ay\250dame a recuperarlos. "
gameforge.new_christmas_sock._030_say = "No es sencillo encontrar calcetines. Necesitar\225s[ENTER]una Cr\237a de reno para poder encontrarlos. "
gameforge.new_christmas_sock._040_say = "\191No es mon\237simo?[ENTER]Y tiene un asombroso sentido del olfato. \161Un[ENTER]especialista en la b\250squeda de calcetines![ENTER]Se quedar\225 2 horas a tu lado y te ayudar\225 a[ENTER]buscar. Despu\233s se cansar\225 y solamente podr\225[ENTER]continuar despu\233s de 24 horas.[ENTER]Si no quieres esperar tanto tiempo, entonces mira[ENTER]abajo a la izquierda, tras la moneda que gira. He[ENTER]o\237do que ah\237 hay otra Cr\237a de reno. \161Me alegrar\233[ENTER]mucho si ma\241ana me vuelves a visitar! "
gameforge.new_christmas_sock._050_npcChat = "\161Te traigo calcetines! "
gameforge.new_christmas_sock._060_say = "Si me traes por lo menos 5 pares de calcetines,[ENTER]te dar\233 una recompensa.[ENTER]\161Ugh, el olor de calcetines usados es[ENTER]insoportable! Vuelve por aqu\237 cuando hayas[ENTER]reunido suficientes. \161Feliz Navidad! "
gameforge.new_christmas_sock._070_say = "Jo, jo, jo, has reunido suficientes calcetines.[ENTER]D\233jame ver. Uff, ese olor...[ENTER]\161Desde luego, estos son los calcetines adecuados![ENTER]\161Feliz Navidad! "
gameforge.new_christmas_sock._080_npcChat = " - Cr\237a de reno "
gameforge.new_christmas_sock._090_say = "Hoy ya te di un Sello de Cr\237a de reno. Me temo[ENTER]que el peque\241o reno primero tiene que descansar.[ENTER]A partir de ma\241ana podr\225 seguir buscando. Si no[ENTER]quieres esperar tanto tiempo, entonces mira abajo[ENTER]a la izquierda, tras la moneda que gira. He o\237do[ENTER]que ah\237 hay otra Cr\237a de reno. \161Me alegrar\233 mucho[ENTER]si ma\241ana me vuelves a visitar! "
gameforge.new_christmas_sock._100_say = "Hoy ya me diste tus calcetines.[ENTER]Recuerda que solamente me puedes traer unos[ENTER]cuantos cada 24 horas. "
gameforge.new_quest_lv17 = {}
