gameforge.new_quest_lv17._012_say_title = "Wonda-Rim: "
gameforge.new_quest_lv17._020_say_title = "El regalo para Chaegirab "
gameforge.new_quest_lv17._021_say = "Mi t\237o Chaegirab ha dedicado su vida a la ciencia[ENTER]y ha invertido todo su Yang en su investigaci\243n.[ENTER]Siempre ha sido bueno conmigo, as\237 que me[ENTER]gustar\237a sorprenderle con un regalo. \191Podr\237as ir[ENTER]con Uriel y preguntarle si tiene alguna idea de[ENTER]lo que podr\237a darle? Es el antiguo maestro de mi[ENTER]t\237o y le conoce muy bien. "
gameforge.new_quest_lv17._030_say = "\161Pero no le digas nada a mi t\237o! "
gameforge.new_quest_lv17._031_say = "\191Me ayudar\225s? "
gameforge.new_quest_lv17._039_say_title = "Uriel: "
gameforge.new_quest_lv17._040_say_title = "Habla con Uriel "
gameforge.new_quest_lv17._040_target = "Uriel: "
gameforge.new_quest_lv17._041_say = "Habla con Uriel sobre su antiguo alumno Chaegirab. "
gameforge.new_quest_lv17._042_say = "Uriel est\225 en %s. "
gameforge.new_quest_lv17._050_say_title = "Wonda-Rim quiere darle un regalo a Chaegirab... "
gameforge.new_quest_lv17._051_say = "El placer en la vida de un cient\237fico viene de su[ENTER]investigaci\243n. Es as\237 de simple. La mejor forma[ENTER]de complacer a Chaegirab es ayudarle en su[ENTER]trabajo. El Lobo Mu-Rang es un visitante raro en[ENTER]estas tierras, pero su piel tambi\233n es una rara[ENTER]delicia para todo bi\243logo. Cinco piezas de piel[ENTER]deber\237an ser suficientes. As\237 que puedes decirle[ENTER]eso a Wonda-Rim. "
gameforge.new_quest_lv17._052_say = "Estoy seguro de que esta espectacular piel[ENTER]impresionar\225 al bi\243logo. "
gameforge.new_quest_lv17._060_select = "S\237, se lo har\233 saber. "
gameforge.new_quest_lv17._065_say_title = "Vuelve con Wonda-Rim "
gameforge.new_quest_lv17._066_say = "Uriel pens\243 en un gran regalo para Chaegirab.[ENTER]Vuelve con Wonda-Rim y d\237selo. "
gameforge.new_quest_lv17._067_say = "Wonda-Rim est\225 en %s. "
gameforge.new_quest_lv17._070_say = "La sugerencia de Uriel suena bien. Como[ENTER]verdaderamente quiero preparar esto como una[ENTER]sorpresa para mi T\237o Chaegirab, tengo que[ENTER]conseguir esta piel. \191Podr\237as ir y matar 5[ENTER]Mu-Rang para mi? "
gameforge.new_quest_lv17._071_say = "Se supone que tengo que matar Lobos Mu-Rang para[ENTER]conseguir su piel. "
gameforge.new_quest_lv17._072_say = "5 son suficientes para un buen regalo. "
gameforge.new_quest_lv17._073_say = "\161Vamos! "
gameforge.new_quest_lv17._074_notice = "Has cogido algo de piel de buena calidad. "
gameforge.new_quest_lv17._075_say = "Caza Mu-Rang y coge su piel. "
gameforge.new_quest_lv17._076_say_reward = "Has recogido %s de 5 piezas de piel. "
gameforge.new_quest_lv17._081_say_title = "Piel para Wonda-Rim "
gameforge.new_quest_lv17._082_say = "Has cogido suficiente piel, ahora ll\233vasela a[ENTER]Wonda-Rim. "
gameforge.new_quest_lv17._092_say_reward = "Ya has recogido %s piezas de piel de lobo. "
gameforge.new_quest_lv17._110_say = "\201sta piel es muy bonita, gracias. \191Podr\237as[ENTER]llev\225rsela a mi t\237o? "
gameforge.new_quest_lv17._120_target = "T\237o Chaegirab "
gameforge.new_quest_lv17._121_say = "Wonda-Rim te ha pedido que lleves la Piel de Lobo[ENTER]a Chaegirab. "
gameforge.new_quest_lv17._122_say = "Chaegirab est\225 en %s. "
gameforge.new_quest_lv17._130_say = "Aja. As\237 que eso es lo que est\225 intentando hacer[ENTER]ahora. "
gameforge.new_quest_lv17._131_say = "\191De qui\233n es esta piel? \191Es de Wonda-Rim, pero t\250[ENTER]mataste a los lobos por \233l?[ENTER]Me averg\252enzo de tener un sobrino que hace que[ENTER]otros hagan su trabajo. As\237 que, lo siento, pero[ENTER]no puedo aceptar esto, incluso sabiendo que[ENTER]gastaste mucho tiempo y esfuerzo. "
gameforge.new_quest_lv17._132_say_reward = "\161Dile a Wonda-Rim que le he calado![ENTER]Si realmente quiere regalarme algo, deber\237a ir a[ENTER]cazarlo \233l mismo. "
gameforge.new_quest_lv17._140_say = "Chaegirab no acept\243 la piel y est\225 enfadado con[ENTER]Wonda-Rim por su pereza. Te ha enviado de vuelta[ENTER]con Wonda-Rim. "
gameforge.new_quest_lv17._141_say = "\191Qu\233 dijo mi t\237o? Espero que le gustase mi regalo. "
gameforge.new_quest_lv17._142_1_select = "S\237, estaba emocionado. "
gameforge.new_quest_lv17._142_2_select = "No, en absoluto. "
gameforge.new_quest_lv17._143_say = "\161Genial! Me encanta regalar cosas a otros. Y por[ENTER]supuesto te dar\233 una recompensa generosa. Toma,[ENTER]\161coge esto! "
gameforge.new_quest_lv17._144_say_reward_a = "Has recibido 20.000 puntos de experiencia.[ENTER]Has recibido 20.000 Yang.[ENTER]Has recibido un Terr\243n de Oro. "
gameforge.new_quest_lv17._144_say_reward_b = "Mentiste a Wonda-Rim y has perdido puntos del[ENTER]bien/mal. "
gameforge.new_quest_lv17._145_say = "\191No acept\243 la piel? Hmm, quiz\225 no haya sido una[ENTER]buena idea enviarte a ti a cazar en lugar de ir[ENTER]yo. Lo har\233 de otra manera la pr\243xima vez. "
gameforge.new_quest_lv17._146_say_reward = "Pero no quiero que todo tu duro trabajo se quede[ENTER]en nada: Ve con Yang-Shin. \201l te comprar\225 la piel[ENTER]a un buen precio. "
gameforge.new_quest_lv17._147_say = "Que giro de acontecimientos m\225s decepcionante.[ENTER]Bueno, al menos todav\237a tienes la piel. Ve con el[ENTER]cazador Yang-Shin en Yayang y v\233ndele la piel. "
gameforge.new_quest_lv17._148_say = "Que giro de acontecimientos m\225s decepcionante.[ENTER]Bueno, al menos todav\237a tienes la piel. Ve con el[ENTER]cazador Yang-Shin en Bokjung y v\233ndele la piel. "
gameforge.new_quest_lv17._149_say = "Que giro de acontecimientos m\225s decepcionante.[ENTER]Bueno, al menos todav\237a tienes la piel. Ve con el[ENTER]cazador Yang-Shin en Bakra y v\233ndele la piel. "
gameforge.new_quest_lv17._151_say = "\191Piel de Mu-Rang? Eso resultar\225 muy \250til. Me har\233[ENTER]algo de ropa interior con ella. Aqu\237 tienes una[ENTER]bolsa de Yang por tus esfuerzos. Oh, y encontr\233[ENTER]este libro ayer, quiz\225 puedas encontrarle alg\250n[ENTER]uso. "
gameforge.new_quest_lv17._152_say_reward = "Has recibido 40.000 puntos de experiencia.[ENTER]Has recibido 10.000 Yang.[ENTER]Has recibido un Manual de Habilidad. "
