gameforge.new_quest_lv22 = {}
gameforge.new_quest_lv22._010_target = "Guardi\225n: "
gameforge.new_quest_lv22._011_say = "El Guardi\225n tiene una misi\243n para ti. Ve a verle[ENTER]y descubre de qu\233 se trata. "
gameforge.new_quest_lv22._015_npcChat = "El hermano enfermo "
gameforge.new_quest_lv22._016_send_letter = "El guardia enfermo "
gameforge.new_quest_lv22._017_say_title = "Guardi\225n: "
gameforge.new_quest_lv22._018_say_title = "Baek-Go: "
gameforge.new_quest_lv22._019_say_title = "Guardi\225n de la Torre Demon\237aca "
gameforge.new_quest_lv22._021_say = "Estoy preocupado por mi hermano, el Guardi\225n de[ENTER]la Torre Demon\237aca. No ha estado encontr\225ndose[ENTER]muy bien \250ltimamente y ahora est\225 verdaderamente[ENTER]enfermo. Tiene un dolor de cabeza realmente malo[ENTER]y una extra\241a erupci\243n cut\225nea, pero no puede[ENTER]abandonar su puesto. \191Podr\237as conseguirle algo de[ENTER]medicina de Baek-Go? "
gameforge.new_quest_lv22._022_say = "Ir\237a yo mismo, pero la Torre Demon\237aca est\225 en el[ENTER]Templo Hwang, justo en el centro del Valle de[ENTER]Seungryong. Y el lugar entero est\225 lleno de[ENTER]criaturas peligrosas... "
gameforge.new_quest_lv22._023_say = "Aqu\237 est\225s otra vez. \191Olvidaste los s\237ntomas?[ENTER]Deber\237as tratar de escuchar cuando alguien te[ENTER]habla. Mi hermano tiene dolor de cabeza y una[ENTER]erupci\243n cut\225nea. \161Ahora ve a dec\237rselo a[ENTER]Baek-Go! "
gameforge.new_quest_lv22._024_select = "Ayudar al hermano "
gameforge.new_quest_lv22._025_say_title = "La medicina de Baek-Go "
gameforge.new_quest_lv22._026_say = "Habla con Baek-Go sobre la medicina para el[ENTER]Guardi\225n de la Torre Demon\237aca. "
gameforge.new_quest_lv22._027_say = "Baek-Go est\225 en %s. "
gameforge.new_quest_lv22._030_target = "Baek-Go: "
gameforge.new_quest_lv22._031_say = "\191As\237 que necesitas medicina? \161Es peligroso[ENTER]administrar medicina en el remoto caso de que sea[ENTER]la correcta! Tienes que decirme los s\237ntomas de[ENTER]la enfermedad. "
gameforge.new_quest_lv22._032_1_select = "Dolores de cabeza y erupciones cut\225neas "
gameforge.new_quest_lv22._032_2_select = "Dolor de garganta y calambres "
gameforge.new_quest_lv22._032_3_select = "No lo s\233. "
gameforge.new_quest_lv22._035_say = "Me parecen ara\241azos demon\237acos. Esto suele[ENTER]suceder cuando hay cerca demasiados \225caros[ENTER]infectados. Puedo producir algo que puede[ENTER]ayudarle, pero tendr\225s que ocuparte de algunos[ENTER]ingredientes. "
gameforge.new_quest_lv22._040_say = "Necesito: "
gameforge.new_quest_lv22._041_say_reward = "Tienes que cazar: "
gameforge.new_quest_lv22._042_say = "Tambi\233n necesito: "
gameforge.new_quest_lv22._043_say = "Nunca he oido sobre una enfermedad semejante.[ENTER]\191Est\225s seguro de que el Guardi\225n te dijo los[ENTER]s\237ntomas correctos? Si fuera t\250, le preguntar\237a[ENTER]de nuevo. "
gameforge.new_quest_lv22._044_say = "No puedo dar un diagn\243stico sin s\237ntomas. Vuelve[ENTER]y pregunta de nuevo. "
gameforge.new_quest_lv22._050_set_title = "Medicina "
gameforge.new_quest_lv22._056_notice = "Bien, ahora s\243lo me faltan %s manojos de hierbas. "
gameforge.new_quest_lv22._057_notice = "Esas deber\237an ser todas las hierbas que necesito.[ENTER]Ahora vuelve r\225pidamente con Baek-Go. "
gameforge.new_quest_lv22._058_notice = "Bien, s\243lo faltan %s h\237gados. "
gameforge.new_quest_lv22._060_notice = "Ah, h\237gado. Ahora s\243lo me faltan %s. "
gameforge.new_quest_lv22._061_notice = "Ese deber\237a ser todo el h\237gado que necesito.[ENTER]Ahora vuelve r\225pidamente con Baek-Go. "
gameforge.new_quest_lv22._062_notice = "Por desgracia este h\237gado no me sirve. "
gameforge.new_quest_lv22._063_say = "Necesitas otras %s x Hierbas Medicinales. "
gameforge.new_quest_lv22._064_say = "Necesitas otros %s x H\237gados de Tigre. "
gameforge.new_quest_lv22._065_say = "Ahora tienes todos los ingredientes para la[ENTER]medicina. Ve y ll\233vaselo a Baek-Go. "
gameforge.new_quest_lv22._066_say = "Recoge los ingredientes para la medicina de[ENTER]Baek-Go: "
gameforge.new_quest_lv22._070_say = "Gracias, ahora puedo hacer la medicina para los[ENTER]ara\241azos demon\237acos. "
gameforge.new_quest_lv22._071_say = "\161Terminada! Aqu\237 est\225 tu medicina. Que tenga[ENTER]ingredientes frescos significa que la medicina no[ENTER]se conserva durante mucho tiempo - as\237 que[ENTER]deber\237as entregarla a tu paciente en los pr\243ximos[ENTER]%s minutos. "
gameforge.new_quest_lv22._072_say = "Puedes encontrar al hermano del guardi\225n en el[ENTER]centro del Templo Hwang. Pero ten cuidado por el[ENTER]camino, \161el Valle de Seungryong est\225 lleno de[ENTER]criaturas peligrosas! "
gameforge.new_quest_lv22._073_say = "Eso no es suficiente. \191Has perdido los[ENTER]ingredientes de camino? No puedo hacer nada por[ENTER]ti sin el resto de los componentes. "
gameforge.new_quest_lv22._080_target = "Guardi\225n de la Torre Demon\237aca "
gameforge.new_quest_lv22._082_set_clock = "Tiempo restante "
gameforge.new_quest_lv22._083_say = "Bueno, a\250n tienes tiempo suficiente, pero tienes[ENTER]que darte prisa. \161As\237 que apres\250rate y ve con el[ENTER]guardi\225n en Seungryong ahora, antes de que la[ENTER]medicina se deteriore! "
gameforge.new_quest_lv22._084_say = "El tiempo se ha agotado porque has sido demasiado[ENTER]lento. Pero deber\237as llevar la medicina al[ENTER]Guardi\225n de la Torre Demon\237aca de todos modos.[ENTER]Puede que a\250n funcione. "
gameforge.new_quest_lv22._085_say = "Gracias por traerme la medicina. El escozor me[ENTER]est\225 matando. "
gameforge.new_quest_lv22._086_say = "Oh, esto sabe bastante bien. Ya puedo sentir como[ENTER]el escozor est\225 mejorando. "
gameforge.new_quest_lv22._087_say = "\161Te has ganado una recompensa especialmente[ENTER]generosa por hacer esto! "
gameforge.new_quest_lv22._088_say_reward = "Has recibido 50.000 puntos de experiencia.[ENTER]Has recibido 12.000 Yang.[ENTER]Has recibido unos Zapatos Adorno Oro +4.[ENTER]Has recibido 5 Pociones Moradas. "
gameforge.new_quest_lv22._089_say = "Oh, esto sabe fatal. La medicina se ha[ENTER]deteriorado - \191cu\225nto tiempo te ha llevado llegar[ENTER]hasta aqu\237? Mi lengua parece excremento de mono[ENTER]curado. "
gameforge.new_quest_lv22._090_say = "Hmm, espera un segundo... parece que est\225[ENTER]mejorando. S\237, \161funciona! Ok, en ese caso no voy[ENTER]a ser taca\241o. Tendr\225s tu recompensa despu\233s de[ENTER]todo. "
gameforge.new_quest_lv22._091_say = "Parece que has perdido la medicina. Por favor sal[ENTER]a cazar de nuevo y consigue los ingredientes para[ENTER]Baek-Go para una nueva medicina. Me convertir\233 yo[ENTER]mismo en un demonio pronto, si este escozor[ENTER]continua durante mucho tiempo. "
gameforge.new_quest_lv22._095_say_reward = "Recibes 50.000 puntos de experiencia.[ENTER]Recibes 8.000 Yang. "
gameforge.new_quest_lv22._098_say = "\191Ya has vuelto a perder la medicina? \161Jam\225s hab\237a[ENTER]visto a una persona tan despistada! Pero bueno,[ENTER]qu\233 se le va a hacer. "
gameforge.new_quest_lv22._100_say_reward = "Recibes 25.000 Puntos de experiencia. "
gameforge.new_quest_lv26 = {}
gameforge.new_quest_lv26._010_target = "Yang-Shin: "
gameforge.new_quest_lv26._020_say_title = "Yang-Shin: "
gameforge.new_quest_lv26._020_set_title = "El desertor "
gameforge.new_quest_lv26._021_say = "Yang-Shin est\225 teniendo problemas encontrando un[ENTER]buen terreno de caza. Ve a verle y averigua c\243mo[ENTER]puedes ayudarle. "
gameforge.new_quest_lv26._025_say = "Nada es como sol\237a ser desde que cayeron las[ENTER]Piedras Metin. Incluso ir de caza se ha vuelto[ENTER]imposible en muchos lugares, porque los animales[ENTER]salvajes han empezado a comportarse como si[ENTER]tuvieran la rabia. El peregrino Nakajima est\225[ENTER]viviendo ah\237 fuera en alg\250n sitio, estoy seguro[ENTER]de que sabr\225 donde hay alg\250n terreno de caza[ENTER]bueno. \191Podr\237as buscarle y preguntarle? "
gameforge.new_quest_lv26._030_target = "Nakajima: "
gameforge.new_quest_lv26._031_say = "\191As\237 que quieres saber de alg\250n lugar bueno para[ENTER]cazar? No tengas tanta prisa, si se supone que[ENTER]tengo que hacer algo por ti, tambi\233n deber\237as[ENTER]hacerme un favor. "
gameforge.new_quest_lv26._032_say = "Deber\237as saber... No vivo ah\237 fuera[ENTER]voluntariamente. Tengo que esconderme porque me[ENTER]fugu\233 de las atrocidades del ej\233rcito. S\243lo deseo[ENTER]que mi amada esposa Ah-Yu sepa que todav\237a estoy[ENTER]vivo. \191Puedes llevarle este mensaje?[ENTER]\161Pero recuerda que s\243lo debe escucharlo Ah-Yu! A[ENTER]cambio, ella te dir\225 d\243nde nos besamos por[ENTER]primera vez - Quiero encontrarme con ella all\237 y[ENTER]tambi\233n es un gran lugar para cazar. "
gameforge.new_quest_lv26._034_say_title = "Nakajima: "
gameforge.new_quest_lv26._035_say_title = "Ah-Yu: "
gameforge.new_quest_lv26._036_say_title = "Busca a Nakajima "
gameforge.new_quest_lv26._037_say = "Nakajima debe conocer algunos lugares buenos para[ENTER]cazar. B\250scale. "
gameforge.new_quest_lv26._038_say = "Nakajima est\225 en %s. "
gameforge.new_quest_lv26._040_say = "\191Eres Nakajima? \161Yang-Shin me envi\243! Est\225[ENTER]buscando alg\250n terreno para cazar, \191quiz\225 tengas[ENTER]alguna idea de donde cazar no sea tan peligroso? "
gameforge.new_quest_lv26._050_target = "Ah-Yu: "
gameforge.new_quest_lv26._051_say = "Nakajima es un desertor y ahora tiene que[ENTER]esconderse del ej\233rcito. Su mujer Ah-Yu cree que[ENTER]cay\243 en la guerra. Hazle saber que Nakajima est\225[ENTER]vivo todav\237a. "
gameforge.new_quest_lv26._052_say = "Ah-Yu est\225 en %s. "
gameforge.new_quest_lv26._057_say = "Najakima... \191est\225 vivo? \191Mi querido esposo est\225[ENTER]vivo? \161No puedo agradecerte suficiente el[ENTER]hab\233rmelo dicho! Es del Valle de Yonjang del que[ENTER]estaba hablando. Voy a ir hacia all\237[ENTER]inmediatamente y encontrarme con \233l. "
gameforge.new_quest_lv26._058_say = "Gracias por hacer posible esta reuni\243n. Ll\233vate[ENTER]esta Rosa contigo, \191quiz\225 puedas d\225rsela a[ENTER]alguien amado? Y ahora... \161por favor perd\243name,[ENTER]pero tengo prisa! "
gameforge.new_quest_lv26._061_say = "El Valle de Yonjang - donde se besaron por[ENTER]primera vez Nakajima y Ah-Yu - todav\237a es un buen[ENTER]sitio para cazar. "
gameforge.new_quest_lv26._062_say = "Yang-Shin estar\225 contento cuando oiga esto. Ve a[ENTER]%s y dale las buenas noticias. "
gameforge.new_quest_lv26._063_say = "\191El Valle de Yonjang? Eso suena convincente, ya[ENTER]que nunca he oido sobre una Piedra Metin[ENTER]contaminando ese \225rea. \161Probablemente pueda[ENTER]conseguir un gran bot\237n all\237! Toma, te mereces[ENTER]esta recompensa. "
gameforge.new_quest_lv26._064_sayReward = "Recibes 35.000 puntos de experiencia. "
gameforge.new_quest_lv26._065_sayReward = "Has recibido 17.500 Yang. "
gameforge.new_quest_lv28 = {}
gameforge.new_quest_lv28._010_target = "Yu-Hwan: "
gameforge.new_quest_lv28._011_say = "Yu-Hwan, el m\250sico, necesita tu ayuda. \161Ve r\225pido[ENTER]y averigua qu\233 est\225 pasando! "
gameforge.new_quest_lv28._015_npcChat = "Las preocupaciones de Ah-Yu "
gameforge.new_quest_lv28._016_say = "Ah-Yu parece tener algo en mente que no quiere[ENTER]decirle a Yu-Hwan. Ve a visitarla y mira si[ENTER]quiere abrirse contigo. "
gameforge.new_quest_lv28._017_say = "Ah-Yu est\225 en %s. "
gameforge.new_quest_lv28._018_select = "\161Hablar\233 enseguida con Ah-Yu! "
gameforge.new_quest_lv28._019_say_title = "Ah-Yu: "
gameforge.new_quest_lv28._020_say_title = "Yu-Hwan: "
gameforge.new_quest_lv28._021_say = "\191Conoces a Ah-Yu? Recoge hierbas para mis[ENTER]pociones. Sol\237a estar de buen humor, pero ayer[ENTER]parec\237a completamete desanimada. No me quiso[ENTER]decir lo que pasa por su mente, \191pero quiz\225 sea[ENTER]porque trabaja para mi?[ENTER]Por favor, ve a verle y averigua c\243mo est\225.[ENTER]\161Quiz\225 se abra contigo! "
gameforge.new_quest_lv28._022_say = "Es muy amable por parte de Yu-Hwan que se[ENTER]preocupe por mi. Pero s\237, hay algo en mi mente...[ENTER]No quise hablar sobre ello, \161pero lo estoy[ENTER]pasando muy mal! Es sobre Yang-Shin, el cazador.[ENTER]Me ha estado chantajeando desde que descubri\243 que[ENTER]mi marido Nakajima es un desertor.[ENTER]\161Yang-Shin est\225 amenazando con delatarle! Y[ENTER]entonces le matar\225n... "
gameforge.new_quest_lv28._023_say = "Esta vez est\225 pidiendo una Zarpa de Oso a cambio[ENTER]de su silencio. Pero no puedo salir de caza[ENTER]ahora. \191Podr\237as ayudarme y conseguir a Yang-Shin[ENTER]lo que quiere? "
gameforge.new_quest_lv28._024_set_title = "Cazando osos "
gameforge.new_quest_lv28._025_notice = "\161Vamos a cazar! Matar a Bera es la mejor forma de[ENTER]obtener Zarpas de Oso. "
gameforge.new_quest_lv28._026_notice = "\161He cogido una Zarpa de Oso! "
gameforge.new_quest_lv28._027_notice = "Esto deber\237a ser todo. \161Ir con Yang-Shin! "
gameforge.new_quest_lv28._028_notice = "Esta zarpa de oso es inservible. "
gameforge.new_quest_lv28._029_say = "Necesitas otras %s x Zarpas de Oso. "
gameforge.new_quest_lv28._031_say_reward = "Tienes que cazar: "
gameforge.new_quest_lv28._032_say = "Ah-Yu te ha pedido cumplir con la exigencia de[ENTER]Yang-Shin. "
gameforge.new_quest_lv28._032_say_reward = "Necesitas otras %s x Zarpas de Oso.[ENTER]Caza Bera para cogerlas. "
gameforge.new_quest_lv28._035_target = "Yang-Shin: "
gameforge.new_quest_lv28._036_say = "Has cogido la Zarpa de Oso requerida. Ll\233vasela a[ENTER]Yang-Shin para pagar la deuda de Ah-Yu. "
gameforge.new_quest_lv28._037_say = "Yang-Shin est\225 en %s. "
gameforge.new_quest_lv28._038_say_title = "Yang-Shin: "
gameforge.new_quest_lv28._040_npcChat = "El chantaje "
gameforge.new_quest_lv28._041_say_title = "Zarpas de Oso "
gameforge.new_quest_lv28._042_say = "\191Me has traido Zarpas de Oso? \161Por favor no[ENTER]pienses mal de mi! Vivimos en tiempos duros y[ENTER]tengo que llegar a fin de mes, ahora que la caza[ENTER]se ha vuelto tan dif\237cil y desde que las Piedras[ENTER]Metin convirtieron a los animales en bestias[ENTER]sanguinarias. La vida como cazador nunca hab\237a[ENTER]sido tan peligrosa. "
gameforge.new_quest_lv28._043_say = "Por favor, dile a Ah-Yu que no tiene nada de qu\233[ENTER]preocuparse. Puede contar con ello. Al menos[ENTER]hasta que vuelva a necesitar algo... \161jejeje! "
gameforge.new_quest_lv28._044_say = "\191Qu\233? \191Quer\237as enga\241arme sin bot\237n? \161Quer\237a[ENTER]Zarpas de Oso frescas! "
gameforge.new_quest_lv28._045_say_reward = "Est\225 bien por tu parte que ayudes a Ah-Yu. Pero[ENTER]tambi\233n significa que tienes que hacer lo que[ENTER]diga yo. \161Ahora ve a cazar y no vuelvas hasta que[ENTER]tengas dos Zarpas de Oso! "
gameforge.new_quest_lv28._046_say = "Dale a Ah-Yu el mensaje de que Yang-Shin parar\225[ENTER]de chantajearle porque le has ayudado. "
gameforge.new_quest_lv28._051_say = "\161Eres nuestro salvador! Estoy infinitamente[ENTER]agradecida. Toma, coge todo mi Yang. No es mucho,[ENTER]pero te lo mereces. "
gameforge.new_quest_lv28._055_1_select = "Gracias, \161ser\225 muy \250til! "
gameforge.new_quest_lv28._055_2_select = "No, no puedo aceptar esto. "
gameforge.new_quest_lv28._056_say = "Esto es todo lo que tengo. Pero vale la pena si[ENTER]puedo librarme de ese b\225rbaro despiadado. "
gameforge.new_quest_lv28._057_say = "Oh, \161gracias! \161Tu lugar junto al Dios Drag\243n est\225[ENTER]asegurado! "
gameforge.new_quest_lv28._058_say_reward = "Has recibido %s Yang. "
gameforge.new_quest_lv28._059_say_reward = "Has recibido %s puntos de experiencia. "
gameforge.new_quest_lv28._070_say = "Necesito: "
