gameforge.new_quest_lv29._015_npcChat = "La porcelana rota "
gameforge.new_quest_lv29._020_say_title = "Yonah: "
gameforge.new_quest_lv29._021_say = "\161Mi amada Porcelana Celadon! Ha estado en mi[ENTER]familia durante tres generaciones y ahora tres de[ENTER]mis preciosos jarrones est\225n rotos. V\237 al in\250til[ENTER]de Taurean dando vueltas por el almac\233n antes.[ENTER]\161Estoy seguro de que es culpa suya! "
gameforge.new_quest_lv29._022_say = "No ser\237a la primera estupidez que hace, pero esto[ENTER]realmente se pasa de la raya. \161Alguien deber\237a[ENTER]darle una lecci\243n! \191Tienes tiempo para hacerlo? "
gameforge.new_quest_lv29._023_1_select = "Con gusto "
gameforge.new_quest_lv29._023_2_select = "No es de mi incumbencia "
gameforge.new_quest_lv29._024_say = "No tengo tiempo de educar ni\241os malvados.[ENTER]Tendr\225s que capturarle por ti mismo. Sin embargo,[ENTER]dudo que puedas... "
gameforge.new_quest_lv29._030_target = "Taurean: "
gameforge.new_quest_lv29._031_say = "Las preciosas reliquias de familia de Yonah, tres[ENTER]jarrones hechos de porcelana celadon, est\225n[ENTER]rotas. Cree que Taurean tiene la culpa. Ve con[ENTER]Taurean y aver\237gualo. "
gameforge.new_quest_lv29._032_say = "Taurean est\225 en %s. "
gameforge.new_quest_lv29._033_say_title = "Taurean: "
gameforge.new_quest_lv29._034_say_reward = "\191Por qu\233 me est\225s mirando as\237? Yo no he hecho[ENTER]nada... "
gameforge.new_quest_lv29._035_say_reward = "\191Qu\233 has hecho con los jarrones de Yonah? "
gameforge.new_quest_lv29._036_say_reward = "\191Jarrones? \191Yonah? \161No s\233 de qu\233 me est\225s[ENTER]hablando! "
gameforge.new_quest_lv29._037_say_reward = "Entonces por favor podr\237as explicarme de nuevo,[ENTER]por qu\233 tres de ellos est\225n rotos. "
gameforge.new_quest_lv29._038_say_reward = "Juro que hoy no he estado cerca de ning\250n jarr\243n[ENTER]ni he visto a Yonah. De hecho, me he pasado el[ENTER]d\237a entero peleando con Harang. \161Incluso me[ENTER]encerr\243 en el establo durante un rato! \161Ve y[ENTER]preg\250ntale si no me crees! "
gameforge.new_quest_lv29._040_target = "Harang: "
gameforge.new_quest_lv29._041_say = "Taurean afirma ser inocente. Estuvo jugando con[ENTER]Harang todo el d\237a y no pudo romper los jarrones.[ENTER]Ve con Harang y preg\250ntale si es cierto. "
gameforge.new_quest_lv29._042_say_reward = "Harang, \191has visto a Taurean recientemente? "
gameforge.new_quest_lv29._043_say_title = "Harang: "
gameforge.new_quest_lv29._044_say_reward = "\191Taurean? S\237, jugamos durante todo el d\237a. \191Pasa[ENTER]algo? "
gameforge.new_quest_lv29._045_say_reward = "Yonah dijo que Taurean rompi\243 tres de sus[ENTER]jarrones. "
gameforge.new_quest_lv29._046_say_reward = "Yonah es mezquino. Nos ahuyenta a Taurean y a mi[ENTER]tan pronto como nos acercamos a \233l. Est\225 siempre[ENTER]tan preocupado por su porcelana. La \250nica persona[ENTER]que est\225 autorizada a tocar sus preciosos[ENTER]jarrones es su amigo el Chico del Establo.[ENTER]\161\191Quiz\225 \233l los rompi\243?! "
gameforge.new_quest_lv29._047_say = "Harang est\225 en %s. "
gameforge.new_quest_lv29._050_target = "Chico del establo: "
gameforge.new_quest_lv29._051_say = "Harang confirm\243 que Taurean es inocente. Pero[ENTER]puede que est\233n confabulados con otro.[ENTER]Antes de juzgar deber\237as preguntarle al amigo de[ENTER]Yonah el Chico del Establo. "
gameforge.new_quest_lv29._052_say = "Oh, el bueno de Yonah. Tan preocupado por su[ENTER]porcelana que culpa a los ni\241os de la aldea. No[ENTER]se da cuenta que hay que culpar a las Piedras[ENTER]Metin - desde que empezaron a envenenar nuestro[ENTER]pa\237s, nuestros recursos no son lo que sol\237an ser.[ENTER]Incluso la porcelana ha comenzado a romperse.[ENTER]Pero Yonah simplemente se niega a creerlo... "
gameforge.new_quest_lv29._053_say = "Si recogieras algo de Heno para \233l, podr\237a[ENTER]acolchar la porcelana en sus ba\250les un poco[ENTER]mejor. Estoy seguro de que ser\237a una buena forma[ENTER]de calmarle. "
gameforge.new_quest_lv29._054_say = "El Chico del Establo est\225 en[ENTER]%s o en %s. "
gameforge.new_quest_lv29._061_say = "Taurean obviamente no es culpable del jarr\243n roto[ENTER]de Yonah. Es la malvada radiaci\243n de las piedras[ENTER]Metin lo que est\225 volviendo todo quebradizo.[ENTER]\161Recoge Heno para Yonah para que pueda almacenar[ENTER]mejor su porcelana! Estoy seguro de que algunos[ENTER]de los aldeanos pueden darte algo. "
gameforge.new_quest_lv29._062_say = "Puedes encontrar a %s y %s frente a las puertas[ENTER]de la aldea. Deber\237as ser capaz de conseguir una[ENTER]cantidad decente de Heno de los sombreros de paja[ENTER]que llevan. "
gameforge.new_quest_lv29._063_notice = "Conseguir\233 un buen fardo de Heno de esto. Ahora[ENTER]s\243lo me faltan otros %s. "
gameforge.new_quest_lv29._064_notice = "Este sombrero no est\225 hecho de paja, sino de[ENTER]fibras de coco. No me sirve. "
gameforge.new_quest_lv29._065_1_say = "Veo que llevas contigo un mont\243n de Heno. Estoy[ENTER]seguro de que Yonah se calmar\225 si le das un poco. "
gameforge.new_quest_lv29._065_notice = "Este sombrero no est\225 hecho de paja, sino de[ENTER]fibras de coco. Tambi\233n est\225 bastante da\241ado... "
gameforge.new_quest_lv29._066_say = "Tambi\233n puedes cazar Soldados Infanter\237a Salvaje[ENTER]o Infanter\237a Salvaje Fuerte. Puedes conseguir[ENTER]Heno de sus sombreros de paja. "
gameforge.new_quest_lv29._067_say_reward = "Has recogido %s de %s fardos de Heno. "
gameforge.new_quest_lv29._068_notice = "Has cogido un fardo de Heno. "
gameforge.new_quest_lv29._070_npcChat = "El almiar "
gameforge.new_quest_lv29._071_say_reward = "Taurean, antes mencionaste que estuviste en el[ENTER]almiar. \191Por casualidad no coger\237as algo de Heno? "
gameforge.new_quest_lv29._072_say_reward = "Jaja, veamos... estaba todo en mi pelo y mis[ENTER]zapatos. \191Puedes verlo? \161Aqu\237 hay algo m\225s,[ENTER]c\243gelo! "
gameforge.new_quest_lv29._073_notice = "No es mucho Heno, pero deber\237a ser suficiente[ENTER]para un fardo peque\241o. Ahora s\243lo me faltan %s[ENTER]m\225s. "
gameforge.new_quest_lv29._074_say_reward = "\161No fu\237 yo, lo juro! \191No te dijo Harang que[ENTER]estuvimos peleando en el almiar? "
gameforge.new_quest_lv29._075_say_reward = "Estuviste en el almiar antes, \191no?[ENTER]\191Por casualidad no coger\237as algo de Heno de all\237? "
gameforge.new_quest_lv29._076_say_reward = "\191C\243mo sabes sobre el almiar? \191Qu\233? \191Todav\237a tengo[ENTER]Heno en mi ropa? Oh s\237, \161aqu\237 hay un poco! "
gameforge.new_quest_lv29._077_say_reward = "\191Puedo llev\225rmelo? "
gameforge.new_quest_lv29._078_say_reward = "Supongo que s\237... "
gameforge.new_quest_lv29._079_say_reward = "Ahora mismo no tengo tiempo. \161Tengo que ir a[ENTER]tranquilizra a Taurean sobre el asunto con los[ENTER]jarrones! "
gameforge.new_quest_lv29._080_npcChat = "Heno para Yonah "
gameforge.new_quest_lv29._081_say_reward = "\191Hay algo de Heno en el establo que le pueda[ENTER]llevar a Yonah? "
gameforge.new_quest_lv29._082_say_title = "Chico del establo: "
gameforge.new_quest_lv29._083_say_reward = "No tenemos mucho Heno. Los animales salvajes y[ENTER]los bandidos del exterior de la aldea nos han[ENTER]impedido cortar m\225s. "
gameforge.new_quest_lv29._084_say_reward = "\161Pero puedo darte un poco! "
gameforge.new_quest_lv29._085_notice = "No es mucho en realidad, pero al menos es[ENTER]suficiente para un fardo. Ahora s\243lo me faltan[ENTER]otros %s m\225s. "
gameforge.new_quest_lv29._086_say_reward = "Me temo que no puedo hacer nada m\225s por ti. "
gameforge.new_quest_lv29._090_send_letter = "Heno en lugar de golpes "
gameforge.new_quest_lv29._091_say = "Has recogido Heno suficiente para Yonah. Ve a[ENTER]llev\225rselo a %s. "
gameforge.new_quest_lv29._101_say_reward = "No es culpa de Taurean. La radiaci\243n de las[ENTER]Piedras Metin ha hecho fr\225gil la porcelana. "
gameforge.new_quest_lv29._102_say_title = "Yonah: "
gameforge.new_quest_lv29._103_say_reward = "\191Qu\233 has dicho? Eso es una completa tonter\237a,[ENTER]\161ese in\250til te ha mentido! "
gameforge.new_quest_lv29._104_say_reward = "Taurean jug\243 todo el d\237a con Harang en el almiar. "
gameforge.new_quest_lv29._105_say_reward = "Se supone que debo darte los mejores deseos de[ENTER]parte de tu amigo el Chico del Establo y tambi\233n[ENTER]te he tra\237do algo de Heno para ayudarte a[ENTER]proteger tus jarrones. "
gameforge.new_quest_lv29._106_say_reward = "Lo admito, estoy un poco avergonzado por mi[ENTER]reacci\243n. Pero deber\237as saber que estoy muy[ENTER]apegado a mi porcelana porque me trae buenos[ENTER]recuerdos de mi familia. Cuando se rompe un[ENTER]jarr\243n, para mi es m\225s que un simple objeto[ENTER]perdido... "
gameforge.new_quest_lv29._107_say_reward = "Tengo que disculparme contigo y con Taurean. Aqu\237[ENTER]tienes una peque\241a recompensa por tus esfuerzos. "
gameforge.new_quest_lv29._108_notice = "\161Recibes un bono de %s puntos de experiencia! "
gameforge.new_quest_lv29._109_say_reward = "Se supone que debo darte los mejores deseos de[ENTER]parte de tu amigo el Chico del Establo y tambi\233n[ENTER]te he tra\237do algo de Heno para ayudarte a[ENTER]proteger tus jarrones. "
gameforge.new_quest_lv29._110_say_reward = "Es muy amable por tu parte, \191pero podr\237as[ENTER]conseguirme otros %s fardos de Heno para que mis[ENTER]jarrones est\233n realmente seguros? "
gameforge.new_quest_lv29._111_say_reward = "Creo que ser\225 dif\237cil encontrar m\225s Heno.[ENTER]Pero mis jarrones son casi sagrados para mi.[ENTER]Estar\237a incre\237blemente agradecido si pudieras[ENTER]conseguir algo para mi y tambi\233n te dar\237a algo de[ENTER]Yang. "
gameforge.new_quest_lv29._112_say_reward = "Ese mocoso de Harang est\225 obviamente compinchado[ENTER]con Taurean. "
gameforge.new_quest_lv29._113_say_reward = "Aparentemente nadie me cree cuando digo que v\237 al[ENTER]chico dando vueltas por el almac\233n antes. "
gameforge.new_quest_lv29._114_say_reward = "Est\225 bien. Aqu\237 tienes una peque\241a compensaci\243n[ENTER]por tus esfuerzos. "
gameforge.new_quest_lv29._115_say_reward = "Toma, %s Yang. "
gameforge.new_quest_lv42 = {}
gameforge.new_quest_lv42._010_send_letter = "Ruido de tripas "
gameforge.new_quest_lv42._020_target = "Octavio: "
gameforge.new_quest_lv42._021_say = "Mi est\243mago est\225 rugiendo como un jabal\237. Quiz\225[ENTER]deber\237a visitar a Octavio. Prepara el mejor[ENTER]estofado de marisco de los alrededores. "
gameforge.new_quest_lv42._022_say_title = "Octavio: "
gameforge.new_quest_lv42._023_say = "\191Quieres un poco de estofado de marisco? \191El que[ENTER]lleva todas las cabezas? Oh, lo siento, mi cocina[ENTER]no ha visto un pescado en d\237as. Normalmente el[ENTER]pescador entrega un pescado de aguas profundas[ENTER]fant\225stico para mi estofado. "
gameforge.new_quest_lv42._024_say = "Bueno, no ha pasado por aqu\237 hace d\237as. \191Quiz\225[ENTER]podr\237as ir y preguntarle qu\233 pasa? "
gameforge.new_quest_lv42._025_say = "Octavio est\225 en %s. "
gameforge.new_quest_lv42._026_select = "\161Voy a buscar al pescador! "
gameforge.new_quest_lv42._030_target = "Pescador: "
gameforge.new_quest_lv42._031_say = "\161Los d\237as tranquilos en el mar se han terminado![ENTER]Cada d\237a est\225n desapareciendo pescadores, \161es[ENTER]terrible! Desde que las piedras Metin se[ENTER]precipitaron al mar, las una vez pac\237ficas[ENTER]ballenas se han transformado en monstruos marinos[ENTER]brutales. La pesca se ha convertido en un oficio[ENTER]peligroso. "
gameforge.new_quest_lv42._032_say = "Nuestras lanzas ya no pueden herir a las[ENTER]ballenas. \161Su piel es m\225s resistente que la piel[ENTER]de ogro! "
gameforge.new_quest_lv42._033_say = "Quiz\225 Yonah sepa qu\233 hacer. \201l sol\237a ir al lago y[ENTER]caz\243 muchas ballenas durante a\241os. "
gameforge.new_quest_lv42._034_say_title = "Pescador: "
gameforge.new_quest_lv42._035_say = "Octavio est\225 esperando su pescado de aguas[ENTER]profundas. Preg\250ntale al Pescador por qu\233 se[ENTER]retrasa la entrega. "
gameforge.new_quest_lv42._036_say = "El Pescador est\225 en %s. "
gameforge.new_quest_lv42._037_send_letter = "Monstruos Marinos Furiosos "
gameforge.new_quest_lv42._038_say = "El Pescador te ha dicho que pidas consejo a Yonah[ENTER]para saber c\243mo cazar a las ballenas malvadas. "
gameforge.new_quest_lv42._039_say = "Yonah est\225 en %s. "
gameforge.new_quest_lv42._040_target = "Yonah: "
gameforge.new_quest_lv42._041_say = "Me he enterado de lo que les pas\243 a las ballenas.[ENTER]Es un asunto grave para los pescadores. Incluso[ENTER]se si atreven a adentrarse en el mar, sus lanzas[ENTER]son demasiado d\233biles como para penetrar en la[ENTER]piel de las ballenas. Cuando trabajaba en un[ENTER]ballenero sol\237amos usar armas especiales para[ENTER]ballenas con piel vieja y rugosa. Esas s\237 que[ENTER]traspasaban lo que fuera... "
gameforge.new_quest_lv42._042_say = "Es una t\233cnica especial para endurecer arpones[ENTER]balleneros. La \250nica persona que puede hacer ese[ENTER]tipo de arp\243n es un Herrero. "
gameforge.new_quest_lv42._043_say_reward = "Ir con el herrero. "
gameforge.new_quest_lv42._044_say_title = "Yonah: "
gameforge.new_quest_lv42._045_say = "Yonah recomienda usar arpones muy robustos y[ENTER]afilados para cazar ballenas. Ve con el Herrero y[ENTER]preg\250ntale si puede hacer alguno de esos arpones. "
gameforge.new_quest_lv42._050_target = "Herrero. "
gameforge.new_quest_lv42._051_say = "S\237, he oido sobre esos arpones y tambi\233n puedo[ENTER]hacerlos. Sin embargo, para que puedan adquirir[ENTER]la durabilidad requerida, necesito una Piedra[ENTER]Diamante. "
gameforge.new_quest_lv42._052_say = "Necesito: "
gameforge.new_quest_lv42._053_say_reward = "Proceso: "
gameforge.new_quest_lv42._054_say_title = "Herrero. "
gameforge.new_quest_lv42._060_set_title = "Piedra Diamante "
gameforge.new_quest_lv42._061_notice = "Veamos. Necesito un Pico para extraer la piedra.[ENTER]\191Me pregunto si el m\237o est\225 por aqu\237 en alg\250n[ENTER]sitio o si Deokbae tiene que conseguirme uno[ENTER]nuevo? "
gameforge.new_quest_lv42._062_say = "Necesitas otras %s x Piedras Diamante. "
gameforge.new_quest_lv42._063_say = "Tienes todo lo que necesitas. Ahora ve r\225pido con[ENTER]el Herrero. "
gameforge.new_quest_lv42._064_say = "Genial, ahora tengo todo lo que necesito. Vuelve[ENTER]ma\241ana a esta misma hora para recoger los[ENTER]arpones. El hierro como este debe forjarse con[ENTER]cuidado. "
gameforge.new_quest_lv42._065_say = "Puedes conseguir una Piedra Diamante picando en[ENTER]la Veta de Diamante con un Pico. "
gameforge.new_quest_lv42._066_say = "El Herrero necesita una Piedra Diamante para[ENTER]hacer los arpones especiales para cazar ballenas.[ENTER]Busca Vetas de Diamante, para poder extraer[ENTER]Piedra Diamante. Si no tienes un Pico para[ENTER]miner\237a, puedes comprarle uno a Deokbae. "
gameforge.new_quest_lv42._067_say = "EL Herrero est\225 en %s. "
gameforge.new_quest_lv42._068_say = "Necesitamos otras %s x Piedras Diamante antes de[ENTER]poder empezar a trabajar en los arpones. "
gameforge.new_quest_lv42._070_set_title = "Los arpones "
gameforge.new_quest_lv42._071_set_clock = "Tiempo de espera "
gameforge.new_quest_lv42._072_say = "El Herrero deber\237a haber terminado ya. Ve con \233l[ENTER]y recoge los arpones especiales para cazar[ENTER]ballenas. "
gameforge.new_quest_lv42._073_say = "Los arpones no est\225n terminados todav\237a. Tienes[ENTER]que ser un poco m\225s paciente. "
gameforge.new_quest_lv42._074_say = "Aqu\237 est\225n tus arpones. Ll\233vaselos al Pescador. "
gameforge.new_quest_lv42._075_say = "Ya te he pedido que esperes hasta que los arpones[ENTER]est\233n terminados. Vuelve m\225s tarde. "
gameforge.new_quest_lv42._079_say = "Has recibido unos Arpones Balleneros del Herrero.[ENTER]Ll\233vaselos al Pescador. "
gameforge.new_quest_lv42._080_say = "\161Genial! \161Estos arpones son realmente[ENTER]impresionantes! Ahora podemos protegernos de los[ENTER]ataques de ballena. \161Por favor hazle saber a[ENTER]Octavio que pronto tendr\233 de nuevo pescado[ENTER]fresco! "
gameforge.new_quest_lv42._081_say_reward = "Has recibido 500.000 Yang. "
gameforge.new_quest_lv42._082_say_reward = "Como reconocimiento especial has recibido 3x: "
gameforge.new_quest_lv42._083_say = "No hay suficientes arpones para alejar a una[ENTER]ballena. S\243lo hay suficiente para hacerles[ENTER]cosquillas en la carne. "
gameforge.new_quest_lv42._084_say_reward = "Por favor, vuelve otra vez con el Herrero y haz[ENTER]que forje m\225s arpones. "
gameforge.new_quest_lv42._090_say = "Los pescadores ahora est\225n bien equipados y[ENTER]pueden cazar en mar abierto de nuevo. Ve con[ENTER]Octavio e intenta asegurarle que tendr\225 pronto[ENTER]una nueva entrega. "
gameforge.new_quest_lv42._095_say = "\191Qu\233 has dicho? \191Las pac\237ficas ballenas se han[ENTER]convertido en monstruos de mar agresivos? Eso es[ENTER]terrible...[ENTER]Gracias por ayudar a los pescadores. Una gran[ENTER]parte de mi men\250 depende de sus entregas. "
gameforge.new_quest_lv42._096_say = "Oh y sobre tu rugido de est\243mago: Por supuesto[ENTER]puedo ofrecerte estofado de marisco, \191pero no[ENTER]preferir\237as un poco de sushi? "
gameforge.new_quest_lv42._098_say_reward = "Recibes 750.000 puntos de experiencia.[ENTER]Recibes 2 trozos de Sushi. "
gameforge.new_quest_lv43 = {}
gameforge.new_quest_lv43._005_send_letter = "Visitando a Wonda-Rim "
gameforge.new_quest_lv43._006_send_letter = "El hu\233rfano "
gameforge.new_quest_lv43._010_target = "Wonda-Rim: "
gameforge.new_quest_lv43._011_say = "No has sabido nada de Wonda-Rim \250ltimamente. Su[ENTER]relaci\243n con su t\237o puede que haya mejorado a[ENTER]estas alturas y puede que hayan olvidado el[ENTER]episodio con la Piel de Mu-Rang. \191Por qu\233 no vas[ENTER]a visitarle? "
gameforge.new_quest_lv43._012_say = "Wonda-Rim est\225 en %s. "
gameforge.new_quest_lv43._020_say = "Es amable por tu parte que vengas por aqu\237. "
gameforge.new_quest_lv43._021_say_title = "Wonda-Rim: "
gameforge.new_quest_lv43._022_say = "Fui criado por mi t\237o Chaegirab. Siempre hemos[ENTER]tenido una buena relaci\243n... pero cuando le[ENTER]pregunto por mis padres, elude la pregunta.[ENTER]Est\225n muertos, pero eso es todo lo que me ha[ENTER]dicho. "
gameforge.new_quest_lv43._023_say_reward = "Quiero casarme y tener una familia alg\250n d\237a, as\237[ENTER]que realmente deber\237a saber de d\243nde vengo.[ENTER]\191Podr\237as hablar con mi t\237o y preguntarle sobre[ENTER]mis padres? Pero por favor, no le digas que yo te[ENTER]envi\233. "
gameforge.new_quest_lv43._024_select = "\161Yo hablar\233 con \233l! "
gameforge.new_quest_lv43._025_say = "Wonda-Rim no es el sobrino biol\243gico de[ENTER]Chaegirab, s\243lo fue criado por \233l. Ahora es[ENTER]tiempo de que averig\252e quienes son sus verdaderos[ENTER]padres. Preg\250ntale a Chaegirab sobre la[ENTER]ascendencia de Wonda-Rim. "
gameforge.new_quest_lv43._026_say = "Chaegirab est\225 en %s. "
gameforge.new_quest_lv43._030_target = "Chaegirab: "
gameforge.new_quest_lv43._031_say_title = "Chaegirab: "
gameforge.new_quest_lv43._032_say = "Wonda-Rim... no, no soy su t\237o biol\243gico. No s\233[ENTER]quienes son sus padres. Le he protegido tanto de[ENTER]la verdad porque no pens\233 que estuviera preparado[ENTER]para saberlo. Pero quiz\225 el tiempo haya llegado[ENTER]finalmente. "
gameforge.new_quest_lv43._033_say = "Le encontr\233 con una hora de Luchadores Orco en el[ENTER]Valle de Seungryong. Si todav\237a queda un modo de[ENTER]averiguar sobre la ascendencia de Wonda-Rim,[ENTER]deber\237as ser capaz de obtenerla de los Orcos. "
gameforge.new_quest_lv43._034_say = "Puedo ser estricto con \233l, pero siempre ser\233 su[ENTER]t\237o. Incluso siendo un in\250til. "
gameforge.new_quest_lv43._035_say_reward = "Ve al Valle de Seungryong y caza Luchadores Orco[ENTER]hasta que encuentres una pista sobre la[ENTER]ascendencia de Wonda-Rim. "
gameforge.new_quest_lv43._036_say = "Has descubierto una carta vieja en la bolsa sucia[ENTER]de un Luchador Orco muerto. Es apenas[ENTER]descifrable, pero puedes reconocer el nombre de[ENTER]Wonda-Rim en ella. Esta es la evidencia que[ENTER]estabas buscando, as\237 que ve a llev\225rsela a[ENTER]Wonda-Rim. "
gameforge.new_quest_lv43._041_say = "\161Vamos! La mejor oportunidad que tienes de[ENTER]averiguar algo sobre la ascendencia de Wonda-Rim[ENTER]es matar Luchadores Orco. \161Pueden llevar alguna[ENTER]evidencia! "
gameforge.new_quest_lv43._043_notice = "Pistas sobre Wonda-Rim... "
gameforge.new_quest_lv43._045_say = "Te he dicho todo lo que s\233. La \250nica pista que[ENTER]tenemos son los Luchadores Orco. Pero por[ENTER]desgracia no puedes tener una conversaci\243n[ENTER]decente con ellos... "
gameforge.new_quest_lv43._049_say = "\191Una Carta? Veamos... Los caracteres son[ENTER]realmente dif\237ciles de leer... Es sobre un[ENTER]asalto, aparentemente los Orcos incendiaron la[ENTER]granja y tuvieron que correr por sus vidas.[ENTER]Tuvieron que dejar atr\225s a su hijo... Y aqu\237 hay[ENTER]un nombre. "
gameforge.new_quest_lv43._050_say = "Gracias por traerme esto. Ahora finalmente s\233 lo[ENTER]que pas\243. "
gameforge.new_quest_lv43._051_say = "Deber\237a hablar con Chaegirab. Obviamente pas\243 por[ENTER]un mont\243n de problemas para salvarme. Voy a[ENTER]intentarlo y ser un mejor sobrino para \233l. \161Nos[ENTER]vemos pronto, amigo m\237o! "
gameforge.new_quest_lv43._052_say_title = "Informaci\243n: "
gameforge.new_quest_lv43._053_say_reward = "Has recibido 32.000 Yang. "
gameforge.new_quest_lv43._054_say_reward = "Recibes 1.250.000 puntos de experiencia. "
gameforge.new_quest_lv43._060_say = "\191Has hablado con mi t\237o Chaegirab? \191Una pista?[ENTER]\191De qu\233 me est\225s hablando? \161Si no tienes nada que[ENTER]presentar, ser\225 mejor que te guardes tus[ENTER]suposiciones![ENTER]Ve a preguntarle a mi t\237o otra vez.[ENTER]Despu\233s te pagar\233. "
gameforge.new_quest_lv52 = {}
gameforge.new_quest_lv52._010_send_letter = "Carta del Capit\225n "
gameforge.new_quest_lv52._020_say_title = "Compatriota leal "
gameforge.new_quest_lv52._021_say_reward = "Me gustar\237a que me hicieras un favor. Ya no puedo[ENTER]dormir m\225s y a pesar de la medicina de Baek-Go,[ENTER]tan s\243lo paso la noche entera dando vueltas en la[ENTER]cama. \191Podr\237as buscarle y pedirle una medicina[ENTER]para dormir m\225s fuerte? "
gameforge.new_quest_lv52._022_say = "Baek-Go est\225 en %s. "
gameforge.new_quest_lv52._030_set_title = "Un sue\241o reparador "
gameforge.new_quest_lv52._035_target = "Baek-Go: "
gameforge.new_quest_lv52._040_say = "El Capit\225n est\225 teniendo problemas para dormir.[ENTER]Ve con Baek-Go y p\237dele unos somn\237feros m\225s[ENTER]fuertes para el Capit\225n. "
gameforge.new_quest_lv52._041_say = "\191Medicina para dormir para el Capit\225n? Me temo[ENTER]que no tengo nada m\225s fuerte para darte.[ENTER]Sin embargo, Yu-Hwan podr\237a hacer algo a base de[ENTER]hierbas que podr\237a darte los resultados[ENTER]requeridos. "
gameforge.new_quest_lv52._042_say = "Ah, te lleg\243 mi carta. Ya no s\233 qu\233 hacer,[ENTER]sencillamente no puedo tener un sue\241o reparador.[ENTER]Por favor, ay\250dame y pide consejo a Baek-Go. "
gameforge.new_quest_lv52._042_select = "\161Entonces ser\225 mejor que vaya a ver a Yu-Hwan! "
gameforge.new_quest_lv52._043_say = "Baek-Go est\225 en %s. "
gameforge.new_quest_lv52._044_say_title = "Baek-Go: "
gameforge.new_quest_lv52._045_say = "Yu-Hwan est\225 en %s. "
gameforge.new_quest_lv52._046_say = "Entonces ve a ver al Capit\225n y dile que no puedes[ENTER]ayudarlo. "
gameforge.new_quest_lv52._049_say_title = "Yu-Hwan: "
gameforge.new_quest_lv52._050_target = "Yu-Hwan: "
gameforge.new_quest_lv52._051_say = "A Baek-Go no le queda ninguna medicina m\225s[ENTER]fuerte. Aunque Yu-Hwan quiz\225 pueda ayudar, si[ENTER]conoce alguna hierba que tenga los efectos[ENTER]requeridos. "
gameforge.new_quest_lv52._052_say = "Conozco bien al Capit\225n. Como puede que ya sepas,[ENTER]he estado realizando misiones secretas para \233l[ENTER]durante bastante tiempo. Pero ahora puedo decirte[ENTER]que las hierbas no solucionar\225n sus problemas. "
gameforge.new_quest_lv52._053_say = "Hay otra raz\243n por la que el Capit\225n ya no puede[ENTER]dormir. Y cr\233eme, \233l conoce exactamente la raz\243n.[ENTER]Pero es algo que tiene que resolver por s\237 mismo[ENTER]y yo no puedo hacerlo por \233l. Ve a verle y[ENTER]preg\250ntale. "
gameforge.new_quest_lv52._054_say_title = "Capit\225n "
gameforge.new_quest_lv52._055_say_reward = "Ah, te lleg\243 mi carta. Sencillamente no s\233 qu\233[ENTER]hacer. Por favor ve y pide consejo a Baek-Go para[ENTER]que finalmente pueda tener un buen sue\241o[ENTER]reparador de nuevo. "
gameforge.new_quest_lv52._055_select = "\161S\237, se\241or! "
gameforge.new_quest_lv52._056_say = "\161Muchas gracias! "
gameforge.new_quest_lv52._056_say_reward = "Ya le he visto y no tiene ninguna medicina m\225s[ENTER]fuerte para suministrar. Pero voy a buscar a[ENTER]Yu-Hwan y preguntarle si puede ayudarte. "
gameforge.new_quest_lv52._060_target = "Capit\225n "
gameforge.new_quest_lv52._061_say = "Yu-Hwan no quiere cotillear sobre los secretos de[ENTER]otro, as\237 que seguramente sea algo bastante[ENTER]desagradable. Pero es in\250til, tienes que hablar[ENTER]con el Capit\225n sobre ello. Si no conocemos la[ENTER]causa, no podremos resolver sus problemas de[ENTER]sue\241o. As\237 que ve a %s. "
gameforge.new_quest_lv52._062_say_reward = "No hay disponible ninguna medicina para el sue\241o[ENTER]m\225s fuerte. Pero Capit\225n, quiz\225 pueda ayudarte si[ENTER]averiguo la raz\243n de tu insomnio. "
gameforge.new_quest_lv52._063_say_reward = "No es algo que me gustar\237a contarle a un hombre[ENTER]joven como t\250. "
gameforge.new_quest_lv52._064_say_reward = "No es algo que me gustar\237a contarle a una mujer[ENTER]joven como t\250. "
gameforge.new_quest_lv52._065_say_reward = "Pero si no consigo dormir bien pronto, me voy a[ENTER]volver loco. Se supone que tengo que...[ENTER]Pero recuerda que esto te lo cuento s\243lo a ti:[ENTER]Soy perseguido por fantasmas cada noche. Pero eso[ENTER]no es lo peor... Soy el responsable de sus[ENTER]muertes. "
gameforge.new_quest_lv52._066_say_reward = "Son cuatro soldados. Dicen que fueron torturados[ENTER]y asesinados por requeridores y torturadores en[ENTER]el Valle de Seungryong. Fu\237 yo qui\233n les orden\243[ENTER]ir all\237 - \161les envi\233 a la muerte! "
gameforge.new_quest_lv52._067_say_reward = "\191Qu\233 podemos hacer con ese tipo de fantasmas? "
gameforge.new_quest_lv52._068_say_reward = "\161Quieren venganza! \191Qu\233 hago? Si salgo a por[ENTER]venganza, la aldea se quedar\225 sin liderazgo y[ENTER]ser\225 invadida. Y si no voy, me volver\233 loco. "
gameforge.new_quest_lv52._069_say_reward = "Si no fuera el responsable de la seguridad de la[ENTER]aldea ir\237a inmediatamente. S\243lo encuentro una[ENTER]salida: "
gameforge.new_quest_lv52._070_say_reward = "\161Alguien tendr\225 que ir a por venganza para ellos[ENTER]por mi! \191Pero c\243mo puedo mandar a m\225s hombres al[ENTER]valle y arriesgarme a enviarles a la ruina[ENTER]tambi\233n? \191No puedo pedirle eso a nadie tan s\243lo[ENTER]por el bien de mi sue\241o? "
gameforge.new_quest_lv52._071_say_reward = "Una decisi\243n como esa no es f\225cil. "
gameforge.new_quest_lv52._080_1_select = "El bien de la aldea... "
gameforge.new_quest_lv52._080_2_select = "No ser\225 f\225cil... "
gameforge.new_quest_lv52._080_3_select = "\161No puedes esperar algo como eso! "
gameforge.new_quest_lv52._081_say_reward = "... acarrea m\225s peso que tu cobard\237a. Vengar\233 a[ENTER]tus hombres. Y si no vuelvo, \161te ver\233 esta noche! "
gameforge.new_quest_lv52._082_say_reward = "... enfrentarse a esos requeridores y[ENTER]torturadores. Pero esta noche dormir\225s bien, \161lo[ENTER]prometo! "
gameforge.new_quest_lv52._083_say_reward = "\191Tienes deseos de morir? Es muy peligroso[ENTER]enfrentarse a los requeridores y torturadores.[ENTER]\161Intenta decirle a esos fantasmas lo mucho que se[ENTER]te necesita aqu\237! "
gameforge.new_quest_lv52._084_say_reward = "Tienes raz\243n. Pero todav\237a ten\237a esperanzas de[ENTER]que te ofrecieras voluntario a hacerlo, para[ENTER]prestar as\237 un gran servicio tanto a m\237 como a mi[ENTER]aldea. "
gameforge.new_quest_lv52._090_1_select = "Bien... "
gameforge.new_quest_lv52._090_2_select = "No, \161no me encargar\233 de eso! "
gameforge.new_quest_lv52._091_say_reward = "... si soy tu \250ltima esperanza, \161entonces[ENTER]eliminar\233 a esos requeridores y torturadores para[ENTER]ti! "
gameforge.new_quest_lv52._092_say_reward = "Si lo intento, te encontrar\225 otro fantasma. "
gameforge.new_quest_lv52._093_say_reward = "Ok. Bueno, d\233jame darte algo de Yang por tus[ENTER]esfuerzos. "
gameforge.new_quest_lv52._093_say_reward_exp = "Recibes 20.000 puntos de experiencia. "
gameforge.new_quest_lv52._093_say_reward_gold = "Has recibido 25.000 Yang "
gameforge.new_quest_lv52._100_notice = "La conversaci\243n ha terminado. "
gameforge.new_quest_lv52._110_say_reward = "Esperaba que dijeras eso. Pero por desgracia no[ENTER]se qu\233 torturadores o requeridores les mataron.[ENTER]Espero que lo sentir\233 cuando uno de esos[ENTER]fantasmas sea liberado. "
gameforge.new_quest_lv52._111_say_reward = "Te enviar\233 una carta. Los fantasmas me dijeron[ENTER]que la venganza tiene que tener lugar en el[ENTER]Tri\225ngulo del Dios Drag\243n. Hay tres columnas all\237[ENTER]que forman los v\233rtices del tri\225ngulo. "
gameforge.new_quest_lv52._120_set_title = "Venga a 4 de los ca\237dos "
gameforge.new_quest_lv52._125_say_title = "Carta del Capit\225n "
gameforge.new_quest_lv52._130_say_reward = "\161Hay otros 3 soldados que vengar! "
gameforge.new_quest_lv52._131_say = "Parece que has tenido \233xito. Acabo de oir la voz[ENTER]de uno de mis soldados ca\237dos. Dijo que me[ENTER]perdona ahora que su muerte ha sido vengada. \161Y[ENTER]todo es gracias a ti! "
gameforge.new_quest_lv52._132_say = "Por favor, venga tambi\233n a los otros soldados[ENTER]ca\237dos y mata Torturadores Oscuros, Requeridores[ENTER]Oscuros, Gran Torturadores y Gran Evocadores.[ENTER]Recuerda que s\243lo puedes liberarles en el[ENTER]tri\225ngulo de las tres grandes columnas del Dios[ENTER]Drag\243n. "
gameforge.new_quest_lv52._140_say_reward = "\161Otros 2 soldados para vengar! "
gameforge.new_quest_lv52._141_say = "\161Has eliminado a otro de los asesinos de mis[ENTER]soldados! En la penumbra vi a un soldado ca\237do[ENTER]levantando su mano en un saludo. "
gameforge.new_quest_lv52._150_say_reward = "\161Queda otro soldado que vengar! "
gameforge.new_quest_lv52._151_say = "\161Eres incre\237ble! El fantasma de un soldado ca\237do[ENTER]estaba junto a m\237 hace un minuto y se despidi\243 de[ENTER]m\237. Probablemente ser\225 bastante dif\237cil encontrar[ENTER]al \250ltimo asesino. "
gameforge.new_quest_lv52._160_say = "Los fantasmas que han estado mortificando al[ENTER]Capit\225n son soldados j\243venes que cayeron durante[ENTER]su misi\243n. Fueron asesinados por Torturadores[ENTER]Oscuros, Requeridores Oscuros, Gran Torturadores[ENTER]y Gran Evocadores. "
gameforge.new_quest_lv52._161_say = "Tienes que eliminar a los torturadores y[ENTER]requeridores responsables en el tri\225ngulo de las[ENTER]tres columnas del Dios Drag\243n para vengar a los[ENTER]soldados. "
gameforge.new_quest_lv52._162_say = "El tri\225ngulo del Dios Drag\243n est\225 en el centro[ENTER]del Valle de Seungryong. "
gameforge.new_quest_lv52._170_send_letter = "Primer soldado vengado "
gameforge.new_quest_lv52._171_send_letter = "Segundo soldado vengado "
gameforge.new_quest_lv52._172_send_letter = "Tercer soldado vengado "
gameforge.new_quest_lv52._173_send_letter = "Todos los soldados vengados "
gameforge.new_quest_lv52._180_say_reward = "\161Has vengado a los 4 soldados! "
gameforge.new_quest_lv52._181_say = "\161Encontraste al \250ltimo asesino! El \250ltimo de los[ENTER]cuatro soldados ca\237dos acaba de aparecer y me ha[ENTER]pedido que te diera las gracias por tu valor.[ENTER]Tambi\233n me ha dejado algo aqu\237 para ti: %s "
gameforge.new_quest_lv52._182_say = "Ven a verme para conseguir tu recompensa. Te[ENTER]estar\233 esperando en %s. "
gameforge.new_quest_lv52._183_say_reward = "Has prestado un gran servicio tanto a m\237 como a[ENTER]mi aldea. Aqu\237 est\225 la recompensa que me di\243 el[ENTER]fantasma para ti: %s "
gameforge.new_quest_lv52._184_say_reward = "Y aqu\237 tienes algo de Yang de mi parte. Ahora voy[ENTER]a retirarme y dormir algo al fin. "
gameforge.new_quest_lv52._185_say_reward = "Estoy profundamente en deuda contigo, hijo m\237o. "
gameforge.new_quest_lv52._186_say_reward = "Estoy en deuda contigo por la eternidad. "
gameforge.new_quest_lv52._190_say_title = "Informaci\243n: "
gameforge.new_quest_lv52._191_say_reward = "Has recibido 3.300.000 puntos de experiencia.[ENTER]Has recibido 270.000 Yang.[ENTER]Has recibido un Libro Maestro. "
gameforge.new_quest_lv52._85_say = "\191M\225s tarde, entonces? \161Ve a ver Baek-Go cuando[ENTER]puedas! "
gameforge.new_quest_lv54 = {}
gameforge.new_quest_lv54._010_target = "Capit\225n "
gameforge.new_quest_lv54._020_say_title = "El suministro fresco "
gameforge.new_quest_lv54._030_say = "Es dif\237cil mantener motivadas a nuestras tropas[ENTER]actualmente, especialmente por ser tan dif\237cil[ENTER]conseguir suministros frescos. La Vendedora de la[ENTER]Tienda General, una de nuestras importantes[ENTER]proveedoras, ha estado envi\225ndonos s\243lo una[ENTER]peque\241a cantidad de las pociones que necesitamos. "
gameforge.new_quest_lv54._031_say_reward = "Por favor, ve con la Vendedora de la Tienda[ENTER]General y averigua que problemas hay. "
gameforge.new_quest_lv54._032_select = "\161Yo os conseguir\233 las pociones! "
gameforge.new_quest_lv54._040_say_title = "Vendedor general: "
gameforge.new_quest_lv54._040_set_title = "Suministros Frescos "
gameforge.new_quest_lv54._050_target = "Vendedor general: "
gameforge.new_quest_lv54._051_say = "S\237, conseguir suministros frescos se ha vuelto[ENTER]realmente dif\237cil \250ltimamente. Las rutas de[ENTER]comercio se han vuelto bastante inseguras y los[ENTER]bandidos y bestias salvajes siguen apareciendo.[ENTER]Los Vendedores Ambulantes, de los que obtengo mis[ENTER]art\237culos, no tienen oportunidad contra los[ENTER]tigres. "
gameforge.new_quest_lv54._052_say = "Quiz\225 el Capit\225n y sus soldados puedan ayudar.[ENTER]Por favor, ve con \233l y preg\250ntale si puede mandar[ENTER]a sus soldados a proteger a los mercaderes. "
gameforge.new_quest_lv54._054_say = "Ve con la Vendedora de la Tienda General y[ENTER]averigua por qu\233 hay retraso en el suministro de[ENTER]pociones frescas. "
gameforge.new_quest_lv54._055_say = "La Vendedora de la Tienda General est\225 en %s. "
gameforge.new_quest_lv54._056_say_title = "Capit\225n "
gameforge.new_quest_lv54._060_say = "\191Rutas de comercio seguras? S\237... me gustar\237a[ENTER]hacerlo. Pero no tengo suficientes soldados para[ENTER]proteger a todos los Vendedores Ambulantes de[ENTER]otros reinos. "
gameforge.new_quest_lv54._061_say = "Adem\225s, nosotros los soldados no debemos cazar[ENTER]tigres. S\243lo los cazadores del gremio de[ENTER]cazadores tienen permiso para hacerlo. No har\237a[ENTER]ning\250n bien a la paz de la aldea el violar esas[ENTER]reglas. "
gameforge.new_quest_lv54._062_say_reward = "Por tanto, deber\237as hablar con Yang-Shin. Es un[ENTER]miembro del gremio de cazadores. Quiz\225 pueda[ENTER]ayudarte a mantener bajo control los problemas[ENTER]con los tigres. "
gameforge.new_quest_lv54._064_say = "Ve con el Capit\225n y trata de convencerle de[ENTER]asegurar las rutas de comercio de los tigres. "
gameforge.new_quest_lv54._065_say = "El Capit\225n est\225 en %s. "
gameforge.new_quest_lv54._070_target = "Yang-Shin: "
gameforge.new_quest_lv54._071_say = "Muchos de mis cazadores se alistaron como[ENTER]guerreros y cayeron durante la guerra. Ahora se[ENTER]ha vuelto casi imposible mantener equilibrada la[ENTER]poblaci\243n de animales salvajes. Los gatos[ENTER]salvajes son un problema particular ya que est\225n[ENTER]expandiendo su territorio y poniendo en peligro a[ENTER]los viajeros. "
gameforge.new_quest_lv54._072_say = "Si nos ayudas con esto puedo ofrecerte como[ENTER]recompensa este valioso Escudo Tigre +3 que sol\237a[ENTER]pertenecer a mi camarada muerto Mi-Son. Para[ENTER]conseguirlo tienes que reducir significativamente[ENTER]la poblaci\243n de tigres. "
gameforge.new_quest_lv54._073_say = "Particularmente, los Tigres Blancos Malditos se[ENTER]han multiplicado incontrolablemente. "
gameforge.new_quest_lv54._074_say = "Como prueba, necesito: "
gameforge.new_quest_lv54._075_say = "Tienes que cazar: "
gameforge.new_quest_lv54._076_say = "Busca a Yang-Shin e intenta convencerle para que[ENTER]asegure las rutas de comercio de los tigres. "
gameforge.new_quest_lv54._077_say_title = "Yang-Shin: "
gameforge.new_quest_lv54._078_say = "Yang-Shin est\225 en %s. "
gameforge.new_quest_lv54._080_set_title = "La Piel de Tigre "
gameforge.new_quest_lv54._081_notice = "Ah, esp\233cimen espl\233ndido. \161S\243lo otros %s! "
gameforge.new_quest_lv54._082_notice = "\161Hecho! Ahora vuelve r\225pido con Yang-Shin. "
gameforge.new_quest_lv54._083_notice = "Esta piel de tigre es inservible. "
gameforge.new_quest_lv54._084_say = "S\243lo necesitas otras %s x Piel de Tigre Brillante.  "
gameforge.new_quest_lv54._085_say = "Coge Piel de Tigre Brillante de los Tigres[ENTER]Blancos Malditos. "
gameforge.new_quest_lv54._090_npcChat = "Tengo la piel de tigre. "
gameforge.new_quest_lv54._091_say = "Esto dista mucho de ser suficiente para mi. \191C\243mo[ENTER]averiguar\233 si las calles son seguras de nuevo en[ENTER]base a estas pocas pieles? "
gameforge.new_quest_lv54._092_say = "\161Ahh al fin! Estas pieles me traer\225n un gran[ENTER]beneficio... \161er! \191Todav\237a est\225s aqu\237? \161Gracias a[ENTER]ti los caminos son seguros de nuevo! Estoy seguro[ENTER]de que el Capit\225n te dar\225 una recompensa[ENTER]generosa. "
gameforge.new_quest_lv54._093_say = "Y ahora vete. Tengo que limpiar la piel. "
gameforge.new_quest_lv54._094_say = "Oh, \191el Capit\225n no va a darte una recompensa? Ese[ENTER]no es mi problema. Y en caso de que est\233s[ENTER]intentando perseguirme por las pieles: Olv\237dalo,[ENTER]\161no voy renunciar a ellas! "
gameforge.new_quest_lv54._095_say_reward = "Pero te promet\237 un escudo y tendr\225s uno. De todos[ENTER]modos, esta cosa vieja y sucia ya no me sirve[ENTER]para nada. "
gameforge.new_quest_lv54._096_say = "Recompensa: "
gameforge.new_quest_lv54._097_say_reward = "Has recibido un Escudo Tigre +3. "
gameforge.new_quest_lv54._098_say = "\191Quieres enga\241arme con unas pocas pieles? De ese[ENTER]modo mis deudas... quiero decir... \161de ese modo[ENTER]las calles nunca ser\225n lo suficientemente[ENTER]seguras! "
gameforge.new_quest_lv54._099_say_reward = "\161Ve a cazar hasta que hayas recogido %s pieles! "
gameforge.new_quest_lv54._100_say = "Eso es todo, ahora vuelve r\225pido con Yang-Shin. "
gameforge.new_quest_lv54._101_say_reward = "Has recibido 3.750.000 puntos de experiencia. "
gameforge.new_quest_lv54._102_say_reward = "Has recibido 125.000 Yang. "
gameforge.new_quest_lv7 = {}
gameforge.new_quest_lv7._010_target = "Octavio: "
gameforge.new_quest_lv7._011_say_title = "Octavio: "
gameforge.new_quest_lv7._012_say_title = "Anciana "
gameforge.new_quest_lv7._020_say_title = "La boda de la hija "
gameforge.new_quest_lv7._021_say = "\191Tienes hijos? Entonces seguramente entender\225s[ENTER]mis preocupaciones... \161es sobre mi hija![ENTER]Ha conocido a un hombre que la ha vuelto[ENTER]totalmente loca. Y ahora se ha escapado a un[ENTER]reino diferente con su amante. "
gameforge.new_quest_lv7._022_say = "\201l es de Chunjo. \161Por supuesto yo estaba en[ENTER]contra! Pens\233 que una dama de Shinsoo no puede[ENTER]casarse con un so\241ador espiritual de Chunjo. Nos[ENTER]separamos despu\233s de una discusi\243n, se escap\243 con[ENTER]\233l a Chunjo. "
gameforge.new_quest_lv7._023_say = "\201l es de Jinno. \161Por supuesto yo estaba en[ENTER]contra! Pens\233 que una dama de Chunjo no puede[ENTER]casarse con un bruto de Jinno. Nos separamos[ENTER]despu\233s de una discusi\243n, se escap\243 con \233l a[ENTER]Jinno. "
gameforge.new_quest_lv7._024_say = "\201l es de Shinsoo. \161Por supuesto yo estaba en[ENTER]contra! Pens\233 que una dama de Jinno no puede[ENTER]casarse con un enclenque amasa-fortunas de[ENTER]Shinsoo. Nos separamos despu\233s de una discusi\243n,[ENTER]se escap\243 con \233l a Shinsoo. "
gameforge.new_quest_lv7._030_say = "Escuch\233 que quiere casarse con \233l all\237. "
gameforge.new_quest_lv7._031_say = "Ahora mi hija est\225 esperando una se\241al m\237a. \191Qu\233[ENTER]har\233? \161Es mi \250nica hija! Por supuesto voy a darle[ENTER]mi bendici\243n. Por favor ve con la Anciana y[ENTER]p\237dele que ayude con los preparativos. "
gameforge.new_quest_lv7._040_target = "Anciana "
gameforge.new_quest_lv7._041_say = "Busca a la Anciana y p\237dele que haga los[ENTER]preparativos para la boda. "
gameforge.new_quest_lv7._042_say = "La Anciana est\225 en %s. "
gameforge.new_quest_lv7._051_say = "\191Una boda dices? Bien, ese es un momento[ENTER]importante en la vida de una mujer. Todo tiene[ENTER]que estar bien, desde el vestido de boda y el[ENTER]esmoquin hasta los anillos de compromiso que la[ENTER]ceremonia convierte en anillos de boda. Cuando el[ENTER]padre de la novia ha dado su consentimiento y se[ENTER]ha pagado el Yang necesario para la boda, puede[ENTER]organizarse la celebraci\243n. "
gameforge.new_quest_lv7._052_say = "Las flores son particularmente importantes - no[ENTER]puede llevarse a cabo una boda sin un ramo[ENTER]nupcial que el novio da a su amada. El ramo debe[ENTER]tener las siguientes flores: "
gameforge.new_quest_lv7._054_say = "Necesito: "
gameforge.new_quest_lv7._055_say = "Tienes que cazar: "
gameforge.new_quest_lv7._056_say = "Todav\237a necesito: "
gameforge.new_quest_lv7._060_say = "Vuelve cuando tengas las tres flores. Comprobar\233[ENTER]si son lo suficientemente frescas y har\233 un[ENTER]bonito ramo. Entonces puedes llev\225rselo a mi[ENTER]hermana. Ella llevar\225 a cabo la ceremonia. "
gameforge.new_quest_lv7._081_say = "Recoge una flor de cada. Las conseguir\225s matando[ENTER]Lobos Alfa Hambrientos, Lobos Azules Hambrientos[ENTER]y Lobos AlfaAzules Hambrientos. "
gameforge.new_quest_lv7._082_say = "Esta flor marchita no es particularmente[ENTER]decorativa. \161Todo este trabajo y nada que merezca[ENTER]la pena! "
gameforge.new_quest_lv7._083_say = "Esta flor marchita no es particularmente[ENTER]decorativa. \161Todo este trabajo y nada que merezca[ENTER]la pena! "
gameforge.new_quest_lv7._084_say = "Esta flor marchita no es particularmente[ENTER]decorativa. \161Todo este trabajo y nada que merezca[ENTER]la pena! "
gameforge.new_quest_lv7._085_1_say_reward = "Te falta %s Flor Rojo Sangre. Puedes conseguirla[ENTER]matando Lobos Alfa Hambrientos. "
gameforge.new_quest_lv7._085_2_say_reward = "Todav\237a te falta %s Flor Anaranjada.[ENTER]Puedes conseguirla matando Lobos Azules[ENTER]Hambrientos. "
gameforge.new_quest_lv7._085_3_say_reward = "Todav\237a te falta %s Flor Arom\225tica Amarilla.[ENTER]Puedes conseguirla matando algunos Lobos[ENTER]AlfaAzules Hambrientos. "
gameforge.new_quest_lv7._085_say_reward = "Todav\237a te falta %s Flor Rojo Sangre. "
gameforge.new_quest_lv7._086_say_reward = "Todav\237a te falta %s Flor Anaranjada. "
gameforge.new_quest_lv7._087_say_reward = "Todav\237a te falta %s Flor Arom\225tica Amarilla. "
gameforge.new_quest_lv7._088_notice = "Esta flor es un esp\233cimen espl\233ndido. \161Preciosa! "
gameforge.new_quest_lv7._089_notice = "Esta flor es un esp\233cimen espl\233ndido. \161Preciosa! "
gameforge.new_quest_lv7._090_notice = "Esta flor es un esp\233cimen espl\233ndido. \161Preciosa! "
gameforge.new_quest_lv7._091_say = "\161Terminado! Esas flores deber\237an formar un ramo[ENTER]precioso. \161Ahora vuelve r\225pido con la Anciana[ENTER]antes de que las cabezas de las flores empiecen a[ENTER]mustiarse! "
gameforge.new_quest_lv7._092_say = "Recoger flores para el ramo nupcial. "
gameforge.new_quest_lv7._110_say = "Son flores bonitas, pero no son lo[ENTER]suficientemente especiales para una boda tan[ENTER]majestuosa. "
gameforge.new_quest_lv7._111_say = "Puedes conseguirlas matando Lobos Alfa[ENTER]Hambrientos, Lobos Azules Hambrientos y Lobos[ENTER]AlfaAzules Hambrientos. "
gameforge.new_quest_lv7._112_say = "Esas flores deber\237an formar un ramo precioso. "
gameforge.new_quest_lv7._115_say = "Gracias, \161es genial! Toma, coge este ramo de[ENTER]flores y ve con mi hermana. "
gameforge.new_quest_lv7._116_say_reward = "La puedes encontrar en Bokjung, en el Reino[ENTER]Chunjo. "
gameforge.new_quest_lv7._117_say_reward = "La puedes encontrar en Bakra en el Reino Jinno. "
gameforge.new_quest_lv7._118_say_reward = "La puedes encontrar en Yayang, en el Reino[ENTER]Shinsoo. "
gameforge.new_quest_lv7._120_set_title = "La hermana "
gameforge.new_quest_lv7._125_notice = "Este es el reino correcto, deber\237a poder[ENTER]encontrar a la hermana de la Anciana aqu\237. "
gameforge.new_quest_lv7._129_say = "Este es el Reino que buscaba, aqu\237 tendr\225 que[ENTER]estar Octavio. "
gameforge.new_quest_lv7._130_say = "Este parece ser el reino correcto. Ahora busca a[ENTER]la hermana de la Anciana. "
gameforge.new_quest_lv7._131_say = "Este no parece ser el reino correcto. "
gameforge.new_quest_lv7._132_say_reward = "Tienes que ir a Bokjung, en el Reino Chunjo. "
gameforge.new_quest_lv7._133_say_reward = "Tienes que ir a Bakra, en el Reino Jinno. "
gameforge.new_quest_lv7._134_say_reward = "Tienes que ir a Yayang, en el Reino Shinsoo. "
gameforge.new_quest_lv7._135_say = "Vuelve con Octavio en Yongan en el Reino Shinsoo. "
gameforge.new_quest_lv7._136_say = "Vuelve con Octavio en Joan en el Reino Chunjo. "
gameforge.new_quest_lv7._137_say = "Vuelve con Octavio en Pyungmoo en el Reino Jinno. "
gameforge.new_quest_lv7._140_say = "Aqu\237 est\225n las flores para boda venidera de la[ENTER]hija de Octavio. Deber\237an pasar a la novia con[ENTER]una bendici\243n. Ella sabr\225 de qui\233n son. "
gameforge.new_quest_lv7._141_say = "\161Son flores preciosas! Har\225n brillar a la novia.[ENTER]Esto completa los preparativos. Por favor dile a[ENTER]Octavio que est\225 invitado a la ceremonia de boda.[ENTER]S\233 que estar\225 encantado. "
gameforge.new_quest_lv7._142_say = "Ve con Octavio, \191a qu\233 esperas? "
gameforge.new_quest_lv7._143_say = "\191Trajiste las flores para la boda de Octavio?[ENTER]\161Qu\233 amable por tu parte! Pero.. \191d\243nde est\225n?[ENTER]\191Las has perdido por el camino? "
gameforge.new_quest_lv7._144_say_reward = "Vuelve a tu reino y consigue un nuevo ramo de[ENTER]flores para la boda. "
gameforge.new_quest_lv7._145_say = "Ve con la hermana de la Anciana antes de que se[ENTER]marchiten las flores. "
gameforge.new_quest_lv7._150_say = "\191Por qu\233 apestas a sopa de rana toro? Ah bien, no[ENTER]importa mientras traigas buenas noticias. "
gameforge.new_quest_lv7._151_say = "No puedo agradec\233rtelo lo suficiente. \161Estoy tan[ENTER]feliz de asistir a la boda de mi hija! "
gameforge.new_quest_lv7._152_say = "Toma, coge tu recompensa: "
gameforge.new_quest_lv7._153_say_reward = "Un arma forjada por la mano de un maestro de las[ENTER]artes marciales. \161Cu\237dala bien! "
gameforge.new_quest_lv7._154_say_reward = "Has recibido %s puntos de experiencia. "
gameforge.new_quest_lv7._155_say_reward = "Has recibido %s Yang. "
gameforge.new_quest_lv7._160_say = "Obviamente me est\225s confundiendo con un familiar[ENTER]lejano. No tengo una hija y no tengo suficiente[ENTER]Yang para poder organizar una boda. "
gameforge.new_quest_lv7._165_say = "\191Te importar\237a probar una cucharada de mi sopa de[ENTER]rana toro? La hice usando una vieja receta de mi[ENTER]t\237a. "
gameforge.new_quest_lv75 = {}
gameforge.new_quest_lv75._010_target = "Heuk-Young: "
gameforge.new_quest_lv75._020_set_title = "Diario de una Leyenda "
gameforge.new_quest_lv75._021_say = "Encontr\233 los restos de un guerrero. No s\233 si se[ENTER]trata del Sura que Heuk-Young est\225 buscando, pero[ENTER]seguro le interesar\225. "
gameforge.new_quest_lv75._022_say = "Seguramente aqu\237 ha muerto m\225s de un Sura. Yo he[ENTER]visto sus restos. \191Ser\225 que ese legendario[ENTER]guerrero est\225 entre ellos? Creo que deber\237a ir[ENTER]decirle a Heuk-Young. "
gameforge.new_quest_lv75._023_say = "Encontr\233 un antiguo pedazo de papel congelado en[ENTER]un Golem de Hielo Infernal. Apenas lo puedo leer,[ENTER]pero podr\237a tratarse de un indicio que le[ENTER]interesar\237a a Heuk-Young. "
gameforge.new_quest_lv75._024_say = "Entretanto he encontrado algo que le podr\237a[ENTER]interesar a Heuk-Young. Deber\237a ir a verla y[ENTER]llevarle este pedazo de papel. Y de una vez le[ENTER]podr\237a contar tambi\233n del cad\225ver. "
gameforge.new_quest_lv75._025_say = "Heuk-Young me pidi\243 abrir bien los ojos y captar[ENTER]cualquier indicio sobre ese legendario Sura.[ENTER]Lastimosamente no tengo ni la m\225s m\237nima idea de[ENTER]la cosa que estoy buscando... "
gameforge.new_quest_lv75._030_say = "Busca al legendario guerrero Akuma. \201l fue el[ENTER]Sura m\225s famoso de todos los tiempos - un[ENTER]guerrero casi invencible. Se dice que le desaf\237o[ENTER]incluso al emperador. Creo que este lugar es[ENTER]lugar donde Akuma desapareci\243 hace muchos siglos.[ENTER]Busca atentamente cualquier indico que pueda[ENTER]testimoniar su estancia aqu\237. "
gameforge.new_quest_lv75._040_say = "dummy "
gameforge.new_quest_lv75._050_npcChat = "Examinar guerreros ca\237dos "
gameforge.new_quest_lv75._060_say = "Se trata de los restos de un guerrero. Pero, el[ENTER]brazo izquierdo no parece ser de un humano...[ENTER]debe ser un Sura. Tengo que contarle esto a[ENTER]Heuk-Young "
gameforge.new_quest_lv75._070_notice = "Una p\225gina del libro... congelada en los restos[ENTER]de un Golem de Hielo Infernal... "
gameforge.new_quest_lv75._090_say = "No puedo decir exactamente qu\233 estamos buscando.[ENTER]Echa un vistazo alrededor y regresa cuando hayas[ENTER]encontrado algo. "
gameforge.new_quest_lv75._100_say = "\191Qu\233 tienes ah\237? \161D\233jame ver! "
gameforge.new_quest_lv75._105_say = "Una nota... \191qu\233 tipo de escritura es est\225? Debe[ENTER]ser muy antigua. Podr\237a ser que has encontrado[ENTER]algo realmente importante. Sea como sea, me[ENTER]parece ya conocer lo que est\225 escrito aqu\237.[ENTER]Pareciese como si esta p\225gina habr\237a sido una[ENTER]parte del libro. "
gameforge.new_quest_lv75._109_say = "Si encontr\225semos m\225s p\225ginas, la cosa tendr\237a[ENTER]sentido. \161Ten los ojos abiertos en busca de otros[ENTER]indicios! "
gameforge.new_quest_lv75._110_say = "Ah, regresaste. \191Encontraste algo? \161Cuentame! "
gameforge.new_quest_lv75._115_say = "Un Sura muerto... podr\237a ser que se tratede \233l, o[ENTER]de uno de sus seguidores. Pero para estar[ENTER]seguros, necesitamos de m\225s evidencias. Busca m\225s[ENTER]indicios que nos permitan reconstruir su[ENTER]identidad. Armas, ornamento... quiz\225s notas o[ENTER]algo parecido. "
gameforge.new_quest_lv75._120_say = "\191La p\225gina de un Sura y la p\225gina de un libro?[ENTER]D\233jame echar un vistazo al pergamino... hmm, al[ENTER]parecer has encontrado los restos de Akuma. No[ENTER]obstante, necesitamos m\225s evidencias. Prueba a[ENTER]ver si logras encontrar otras p\225ginas del libro. "
gameforge.new_quest_lv75._130_say = "Ya encontr\233 un indicio, pero no puedo decir con[ENTER]certeza si ese legendario Sura estuvo realmente[ENTER]aqu\237. Necesito m\225s informaciones. "
gameforge.new_quest_lv75._140_1_select = "Bien "
gameforge.new_quest_lv75._140_2_select = "Criatura de Hielo "
gameforge.new_quest_lv75._140_3_select = "Al borde de la desesperaci\243n "
gameforge.new_quest_lv75._140_4_select = "Terror oscuro "
gameforge.new_quest_lv75._140_5_select = "El rostro de la muerte "
gameforge.new_quest_lv75._140_6_select = "El destino del guerrero "
gameforge.new_quest_lv75._140_7_select = "No, no estoy interesado en eso. "
gameforge.new_quest_lv75._150_say = "Solamente logro descifrar algunas partes de las[ENTER]frases. Estas cuentan sobre una vida cortesana y[ENTER]el af\225n de aventura exagerada... "
gameforge.new_quest_lv75._160_1_say = "La escrito sobre el amarillento pergamino es[ENTER]opaco y tembloroso, como si hubiese sido escrito[ENTER]por un anciano o por alguien d\233bil: \"...[ENTER]Criatura de Hielo. Ni mis habilidades de Sura han[ENTER]bastado para derrotarlos a todos. Algunos siguen[ENTER]vagando por estas cuevas y pobre de mi si ellos[ENTER]me encuentran. Hasta ahora mi escondite es un[ENTER]lugar seguro, pero pronto...\" En este punto la[ENTER]escritura se desti\241e. "
gameforge.new_quest_lv75._160_2_say = "Esta p\225gina tambi\233n est\225 muy afectada. La fecha[ENTER]situada en la esquina de arriba deja suponer que[ENTER]se trata de una especie de diario: \" No es la[ENTER]primera vez que me arrepiento de haber decido[ENTER]buscar la Gruta. \161Culpable fue mi orgullo y[ENTER]ego\237smo! Todas estas cualidades me condujeron[ENTER]hacia aqu\237, al lugar donde me espera la[ENTER]muerte...\" La \250ltima palabra est\225 subrayada[ENTER]varias veces. "
gameforge.new_quest_lv75._160_3_say = "La p\225gina del pergamino est\225 completamente[ENTER]destruida, parece que algunos pedazos han sido[ENTER]arrancados. Se alcanza a descifrar s\243lo algunas[ENTER]partes del mensaje: \"...Corte del emperador...[ENTER]cuando los sabios me ense\241aron lo que deseaba[ENTER]saber... abrir los portales, pero... muerte y[ENTER]terror en la oscur...\" Una rotura en el pergamino[ENTER]te impide leer la \250ltima p\225gina. "
gameforge.new_quest_lv75._160_4_say = "Sobre esta p\225gina de pergamino hay un dise\241o: El[ENTER]rostro sonriente de una mujer. Bajo el dise\241o[ENTER]est\225n escritas palabras en una escritura que ya[ENTER]conoces. S\243lo que ahora \233sta parece ser m\225s[ENTER]temblorosa e inestable: \"La muerte tiene garras -[ENTER]lo s\233 desde ayer. Logr\233 ver a la criatura solo de[ENTER]pasada y tuve tanto miedo que me volv\237 a[ENTER]esconderme aqu\237. \161Oh mi amada Sunmi, si lo[ENTER]hubiese sabido antes! Si hubiese conocido antes[ENTER]la existencia de este terror atroz, nunca me[ENTER]habr\237a aventurado hasta aqu\237!\" "
gameforge.new_quest_lv75._160_5_say = "Durante la dinast\237a de Hee-Se vivi\243 un legendario[ENTER]Sura llamando Akuma. Era tal su conocimiento en[ENTER]el arte de la batalla que con el tiempo ya casi[ENTER]no quedaba ning\250n oponente con quien pueda medir[ENTER]su fuerza. De modo que segu\237a buscando desaf\237os.[ENTER]Un d\237a, se encontr\243 unos antiguos escritos que[ENTER]hablaban de un lugar sellado y removi\243 cielo y[ENTER]tierra para encontrarlo. Logr\243 aprender como[ENTER]encontrar y abrir un portal. Y le prometi\243 a su[ENTER]amada Sunmi volver con noticias sobre sus nuevos[ENTER]logros... pero \233l nunca volvi\243. "
gameforge.new_quest_lv75._170_say = "La escritura parece ser antigua... adem\225s[ENTER]temblorosa e irregular, como si el que la[ENTER]escribi\243 no hubiese tenido suficiente fuerza... "
gameforge.new_quest_lv75._171_say = "Eso no tiene sentido. Necesitamos m\225s archivos. "
gameforge.new_quest_lv75._172_say = "Estoy empezando a entender lo que sucedi\243 aqu\237.[ENTER]Pero todav\237a hay cosas que no son claras. "
gameforge.new_quest_lv75._173_say = "\191Quieres saber todos los detalles? "
gameforge.new_quest_lv75._174_say = "\161Otra p\225gina! Quienquiera que haya escrito estas[ENTER]frases, \233l debi\243 haber estado muy desesperado.[ENTER]\191Quieres que te resuma lo que est\225 escrito aqu\237? "
gameforge.new_quest_lv75._175_say = "Algunas p\225ginas est\225n totalmente malogradas que[ENTER]s\243lo puedo intentar adivinar lo que esta escrito.[ENTER]Sin embargo, poco a poco estamos reconstruyendo[ENTER]aquello que sucedi\243 en esta gruta hace mucho[ENTER]tiempo. "
gameforge.new_quest_lv75._176_say = "No falta mucho. \191Quieres saber lo que descubierto[ENTER]hasta ahora? "
gameforge.new_quest_lv75._177_say = "Parece que no faltan muchas p\225ginas. "
gameforge.new_quest_lv75._178_say = "\191Quieres saber lo que he encontrado hasta ahora? "
gameforge.new_quest_lv75._180_notice = "Encontr\233 la \250ltima p\225gina del libro en el Golem[ENTER]de Hielo Infernal. "
gameforge.new_quest_lv75._185_send_letter = "\161Ahora las p\225ginas deben estar completas! "
gameforge.new_quest_lv75._190_notice = "Encontr\233 una p\225gina del libro en el Golem de[ENTER]Hielo Infernal. "
gameforge.new_quest_lv75._195_send_letter = "\161Encontr\233 una p\225gina! "
gameforge.new_quest_lv75._200_npcChat = "Requisar guerreros ca\237dos "
gameforge.new_quest_lv75._210_say = "Junto a los restos humanos se hallan 3 p\225ginas[ENTER]del pergamino casi destrozado. Los bordes[ENTER]dentados indican que han sido sacados de un[ENTER]libro. La escrita sobre est\225 desvanecida y es[ENTER]dif\237cil de descifrar. "
gameforge.new_quest_lv75._220_say = "Creo que esto bastar\225. Ahora le llevar\233 a[ENTER]Heuk-Young las cosas que encontr\233. "
gameforge.new_quest_lv75._230_say = "Creo que s\233 de quien son estos restos ... de[ENTER]todos modos no llevaba consigo nada que me pueda[ENTER]servir ahora. "
gameforge.new_quest_lv75._240_send_letter = "\161Tengo las p\225ginas! "
gameforge.new_quest_lv75._250_say = "Deber\237a retornar a Heuk-Young. \161Quiz\225s ella pueda[ENTER]juntar el rompecabezas! "
gameforge.new_quest_lv75._270_say = "Estoy sorprendido de cuantas cosas has logrado[ENTER]encontrar en esta cueva. Est\225s p\225ginas parecen[ENTER]haber sido parte de un libro. Las cosas que est\225n[ENTER]escritas aqu\237 son muy interesantes. Si pienso en[ENTER]las otras historias que he escuchado, todo esto[ENTER]tiene sentido... si me dejas est\225s p\225ginas, te[ENTER]las encuaderno en un libro. Quiz\225s te pueda ser[ENTER]\250til si decides regresar a la Gruta del Exilio. Y[ENTER]si no te sirve m\225s, podr\237as encontrar a alguien[ENTER]que te lo compre por un precio razonable. "
gameforge.new_quest_lv75._280_say = "Encuaderne las p\225ginas en un libro y adem\225s le[ENTER]a\241ad\237 algunas de mis notas. \161Quiz\225s te sean[ENTER]\250tiles! Y si quieres te cuento el resto de la[ENTER]historia. "
gameforge.new_quest_lv75._290_1_select = "\161S\237, cu\233ntame m\225s! "
gameforge.new_quest_lv75._290_2_select = "\161No, eso no me interesa! "
gameforge.new_quest_lv75._310_say = "\191Qu\233 quieres de m\237? \191No ves que estoy meditando[ENTER]sobre un libro? "
gameforge.new_quest_lv75._320_say = "Soon: "
gameforge.new_quest_lv75._330_say = "El libro que sostienes en tus manos es muy[ENTER]interesante. \191De d\243nde proviene? \191Puedo darle una[ENTER]ojeada? "
gameforge.new_quest_lv75._340_say = "Esas son notas de la Gruta del Exilio, \191verdad?[ENTER]Se ven muy antiguos. La escritura es ins\243lita y[ENTER]la graf\237a es muy antigua... Debi\243 haber sido bien[ENTER]duro encontrar un libro como este. Como podr\225s[ENTER]imaginarte, yo soy aficionado a este tipo de[ENTER]libros. \191Estar\225s interesado en venderlo? "
gameforge.new_quest_lv75._350_1_select = "S\237 "
gameforge.new_quest_lv75._350_2_select = "No "
gameforge.new_quest_lv75._360_say = "\191Cu\225ntos Yang quieres por el libro? "
gameforge.new_quest_lv75._370_say = "Jaja... parece que te gustan los chistes. Contigo[ENTER]no se pueden hacer negocios. Te hago una[ENTER]propuesta: te doy 500.000 Yang por este diario[ENTER]legendario. \161D\233jalo o t\243malo! "
gameforge.new_quest_lv75._380_1_select = "Acepto los 500.000 Yang. "
gameforge.new_quest_lv75._380_2_select = "\161Bien, entonces, olvidemoslo! "
gameforge.new_quest_lv75._390_say = "\161Bueno, entonces olvidado! "
gameforge.new_quest_lv75._400_say = "No, cuesta mucho. \191Lo siento! "
gameforge.new_quest_lv75._410_say = "D\233jame hacerte otra oferta. Te doy %s Yang por[ENTER]este diario legendario. "
gameforge.new_quest_lv75._420_say = "\191Est\225s de acuerdo? "
gameforge.new_quest_lv75._425_say = "\161Esta es mi \250ltima oferta! "
gameforge.new_quest_lv75._430_1_select = "Acepto los %s Yang. "
gameforge.new_quest_lv75._430_2_select = "Entonces, supongo que no entramos en negocio. "
gameforge.new_quest_lv75._440_say = "Como t\250 lo quieras... "
gameforge.new_quest_lv75._450_say = "No es nada conveniente. Pero, quiero ser generoso. "
gameforge.new_quest_lv75._460_say = "Mi generosidad tiene un l\237mite. Te dar\233 500.000[ENTER]Yang por el diario legendario. "
gameforge.new_quest_lv75._470_say = "\161T\243malo o d\233jalo! "
gameforge.new_quest_lv75._480_say = "\161Bueno, entonces olvidado! "
gameforge.new_quest_lv75._490_say = "Que l\225stima. Quiz\225 cambias de opini\243n. "
gameforge.new_quest_lv80 = {}
gameforge.new_quest_lv80._010_target = "Soon: "
gameforge.new_quest_lv80._020_set_title = "La M\225scara Sombr\237a Madera "
gameforge.new_quest_lv80._030_say = "\161Llegas justo a tiempo! \191Escuche que estuviste en[ENTER]la Gruta del Exilio hace alg\250n tiempo? "
gameforge.new_quest_lv80._040_say = "Es la primera vez que escucho que alguien ha[ENTER]logrado retornar vivo de ese terrible lugar.[ENTER]Admito que tengo mucha curiosidad... "
gameforge.new_quest_lv80._050_1_say = "Tendr\237a una misi\243n para ti, pero es bastante[ENTER]peligrosa. No obstante, estoy seguro que un[ENTER]hombre con tu experiencia no tendr\225 ninguna[ENTER]dificultad de realizarla. "
gameforge.new_quest_lv80._050_2_say = "Tendr\237a una misi\243n para ti, pero es bastante[ENTER]peligrosa. Sin embargo, estoy seguro que una[ENTER]mujer con tu experiencia no tendr\225 ninguna[ENTER]dificultad de cumplirla. "
gameforge.new_quest_lv80._060_say = "Coge esta M\225scara de Madera y ve al \225rea[ENTER]Deoyyumhwan. All\237 busca a los Fantasmas Llama.[ENTER]Puede que ya los conozcas - son criaturas[ENTER]esf\233ricas que est\225n completamente cubiertas de[ENTER]llamas. "
gameforge.new_quest_lv80._070_say = "Si matas uno de ellos, la M\225scara de Madera[ENTER]reaccionar\225 y se convertir\225 en cenizas. No te des[ENTER]por vencido si no funciona la primera vez. "
gameforge.new_quest_lv80._080_say = "Entonces vuelve a traerme las cenizas. "
gameforge.new_quest_lv80._090_say = "Si vas a adentrarte en la tierra salvaje de todas[ENTER]formas, puedes traerme tambi\233n %s Pedazos de[ENTER]Hielo. Los necesito desesperadamente. "
gameforge.new_quest_lv80._100_say = "\161Los Yetis a menudo llevan Pedazos de Hielo! As\237[ENTER]que, \191a qu\233 est\225s esperando? "
gameforge.new_quest_lv80._110_say_title = "Fuego y Hielo "
gameforge.new_quest_lv80._120_say = "Soon me ha encargado... "
gameforge.new_quest_lv80._130_say = "Ya he encontrado los Pedazos de Hielo. "
gameforge.new_quest_lv80._140_say = "A\250n necesito: "
gameforge.new_quest_lv80._150_say_reward = "\161Al parecer podr\233 encontrarlo si cazo Yetis! "
gameforge.new_quest_lv80._160_say = "La M\225scara Sombr\237a de Madera ya se ha[ENTER]transformado en Cenizas Encantadas. "
gameforge.new_quest_lv80._170_say = "Necesito: "
gameforge.new_quest_lv80._180_say_reward = "Tengo que llevar "
gameforge.new_quest_lv80._190_say_reward = "conmigo. Seg\250n Soon, la m\225scara se convertir\225 en[ENTER]Cenizas Encantadas cuando luche con los Fantasmas[ENTER]Llama. "
gameforge.new_quest_lv80._200_say = "Ahora s\243lo necesito las Cenizas Encantadas y los[ENTER]Pedazos de Hielo. Genial, espera un momento... "
gameforge.new_quest_lv80._210_say = "\161Funcion\243! \161Lo que dicen los escritos antiguos es[ENTER]realmente cierto! "
gameforge.new_quest_lv80._220_say = "He creado Hielo Negro de los objetos que me has[ENTER]traido. "
gameforge.new_quest_lv80._230_say = "Sin embargo, tengo otra misi\243n para ti que est\225[ENTER]conectada a la primera. Si completas esta[ENTER]tambi\233n, \161te dar\233 todos mis ahorros! "
gameforge.new_quest_lv80._240_say = "Lleva el Hielo Negro a la Gruta del Exilio y[ENTER]sacrif\237calo en el Altar Oscuro. "
gameforge.new_quest_lv80._250_say = "Todav\237a faltan %s Pedazos de Hielo. "
gameforge.new_quest_lv80._260_notice = "Algo no est\225 bien. "
gameforge.new_quest_lv80._270_say = "Bien - Veo que tienes el hielo contigo. Ahora[ENTER]s\243lo necesito las Cenizas Encantadas. "
gameforge.new_quest_lv80._280_say = "\191Qu\233 est\225s esperando...? "
gameforge.new_quest_lv80._290_say = "Hm... \233stas parecen ser cenizas normales que no[ENTER]est\225n encantadas. "
gameforge.new_quest_lv80._300_target = "Altar Oscuro "
gameforge.new_quest_lv80._310_set_title = "El Altar Oscuro "
gameforge.new_quest_lv80._320_say = "Se supone que tengo que llevar el Hielo Negro a[ENTER]la Gruta del Exilio y sacrificarlo en el altar.[ENTER]\161El altar de sacrificios no ser\225 f\225cil de[ENTER]encontrar! "
gameforge.new_quest_lv80._330_npcChat = "\161Sacrifica el Hielo Negro! "
gameforge.new_quest_lv80._340_say = "Conforme te vas acercando m\225s al altar, la[ENTER]oscuridad parece cerrarse a tu alrededor. En la[ENTER]oscuridad, voces incorp\243reas susurran sobre su[ENTER]angustia eterna. Este es un verdadero lugar[ENTER]imp\237o. \191Realmente quieres sacrificar el Hielo[ENTER]Negro? "
gameforge.new_quest_lv80._350_1_select = "\161S\237! \191Qu\233 es lo peor que puede pasar? "
gameforge.new_quest_lv80._350_2_select = "\161No, esto acabar\225 con l\225grimas! "
gameforge.new_quest_lv80._360_say = "A\250n no estoy seguro de si he hecho lo correcto -[ENTER]sacrificando algo en la Gruta... Estoy seguro que[ENTER]el Dios Drag\243n no lo aprobar\225. Desear\237a poder[ENTER]recuperarlo. "
gameforge.new_quest_lv80._370_say = "No me gusta todo esto. El Dios Drag\243n[ENTER]probablemente no aprobar\237a llevar una v\237ctima a[ENTER]la gruta. No lo har\233. "
gameforge.new_quest_lv80._380_say = "\161Ese es el Altar equivocado! "
gameforge.new_quest_lv80._390_send_letter = "Vuelve con Soon "
gameforge.new_quest_lv80._400_set_title = "Monstruos extra\241os "
gameforge.new_quest_lv80._410_say = "Deber\237a volver con Soon a recoger mi recompensa. "
gameforge.new_quest_lv80._420_say = "He o\237do que han sido vistos monstruos extra\241os en[ENTER]algunas zonas del pa\237s. "
gameforge.new_quest_lv80._430_say = "Espero que no tenga nada que ver con el hecho de[ENTER]haber sacrificado el Hielo Negro en la Gruta del[ENTER]Exilio. "
gameforge.new_quest_lv80._440_say = "\161Bien hecho! Aqu\237 est\225 tu recompensa. "
gameforge.new_quest_lv80._450_npcChat = "\191Has visto al monstruo? "
gameforge.new_quest_lv80._460_say = "\161Un %s! Oh mi diosa... No tengo ni idea de c\243mo[ENTER]ha podido pasar algo como esto... Voy a[ENTER]investigarlo en mi libro inmediatamente. "
gameforge.new_quest_lv80._470_say = "No pude sacrificar el Hielo Negro... \161daba muy[ENTER]mala sensaci\243n! Voy a ir a ver a Soon y decirle[ENTER]que no completar\233 esta misi\243n. "
gameforge.new_quest_lv80._475_npcChat = "El Hielo Negro "
gameforge.new_quest_lv80._476_say = "Me parece que no llevas contigo el Hielo Negro.[ENTER]\191O sea que s\237 lo sacrificaste? \161Cuenta! \191Qu\233 pas\243? "
gameforge.new_quest_lv80._477_say = "Perd\243name, esto es un malentendido - todav\237a[ENTER]tengo el Hielo Negro. Voy a buscarlo y regreso[ENTER]m\225s tarde... "
gameforge.new_quest_lv80._480_say = "Ah, \161aqu\237 est\225s! \191Por qu\233 llevas a\250n contigo el[ENTER]Hielo Negro? "
gameforge.new_quest_lv80._490_say = "No puedo hacer lo que me has pedido. Ir\237a contra[ENTER]el deseo del Dios Drag\243n. \161No sacrificar\233 el[ENTER]hielo! "
gameforge.new_quest_lv80._495_say = "\161Pah, que in\250til! No es capaz de resolver ni[ENTER]siquiera las misiones m\225s simples. Debo encontrar[ENTER]a alguien que no sea tan melindroso. \161Devu\233lveme[ENTER]el Hielo! \161D\225melo de inmediato! "
gameforge.new_quest_lv80._500_say = "\191Debo darle verdadeeramente el Hielo Negro a Soon? "
gameforge.new_quest_lv80._510_1_select = "S\237, \161quiero librarme de \233l! "
gameforge.new_quest_lv80._510_2_select = "No, \161puede causar problemas! "
gameforge.new_quest_lv80._520_say = "Toma, \161coge el Hielo Negro y d\233jame s\243lo! "
gameforge.new_quest_lv80._530_say = "\191Est\225s esperando que te de las gracias? \161Fuera de[ENTER]mi vista! "
gameforge.new_quest_lv80._535_sayReward = "Obtienes 70.000.000 puntos de experiencia. "
gameforge.new_quest_lv80._540_say = "No recobrar\225s el Hielo. Lo tirar\233 al mar; as\237 no[ENTER]ser\225 peligroso para nadie. "
gameforge.new_quest_lv80._550_say = "\161No te atrevas! \161Devu\233lvemelo o te maldecir\233 a ti[ENTER]y a tu familia! "
gameforge.new_quest_lv80._560_say = "Haz lo que quieras - No dejar\233 que me dentengas. "
gameforge.new_quest_lv80._570_target_pos = "Orilla Meridional "
gameforge.new_quest_lv80._580_target_pos = "Orilla Occidental "
gameforge.new_quest_lv80._590_target_pos = "Orilla Oriental "
gameforge.new_quest_lv80._599_set_title = "Fin de un camino equivocado "
gameforge.new_quest_lv80._600_say = "Debo ir a Yongan y tirar el Hielo Negro al mar. "
gameforge.new_quest_lv80._610_say = "Debo ir a Joan y tirar el Hielo Negro al mar. "
gameforge.new_quest_lv80._620_say = "Debo ir a Pyungmoo y tirar el Hielo Negro al mar. "
gameforge.new_quest_lv80._630_say_reward = "Justo cuando quieres lanzar el Hielo Negro al[ENTER]agua, se derrite. L\237quido negro gotea de tus[ENTER]dedos sobre el suelo y se evapora antes de que[ENTER]puedas incluso tocarlo. "
gameforge.new_quest_lv80._640_say = "De repente los siguientes objetos aparecen frente[ENTER]a ti: "
gameforge.new_quest_lv80._650_say = "Mientras recoges los objetos, te sientes[ENTER]satisfecho por haber tomado la decisi\243n correcta.[ENTER]Y ahora sostienes la gratitud del Dios Drag\243n en[ENTER]tus manos. "
gameforge.new_quest_lv80._660_say = "\161Oh no, me olvid\233 de traer el Hielo Negro! No me[ENTER]queda otro remedio que ir a buscarlo y regresar[ENTER]aqu\237. "
gameforge.new_quest_lv80._670_sayReward = "Obtienes adem\225s 120.000.000 puntos de experiencia. "
gameforge.new_quest_premium_lv4 = {}
gameforge.new_quest_premium_lv4._100_npcChat = "Abrir tienda "
gameforge.new_quest_premium_lv4._100_say_reward = "Tienes que cazar: "
gameforge.new_quest_premium_lv4._10_targetVid = "Vendedor general: "
gameforge.new_quest_premium_lv4._110_say = "Busca al Vendedor de la Tienda de Armas y[ENTER]preg\250ntale por qu\233 ya no canta bajo la ventana de[ENTER]la Vendedora de la Tienda General. "
gameforge.new_quest_premium_lv4._120_qSetTitle = "Recoge Lilas "
gameforge.new_quest_premium_lv4._130_notice = "\161Has recogido un bonito ramo de Lilas! "
gameforge.new_quest_premium_lv4._140_notice = "\161Terminado! Ahora volvamos r\225pido con el Vendedor[ENTER]de la Tienda de Armas. "
gameforge.new_quest_premium_lv4._150_notice = "Lamentablemente, este ramo de Lilas ya est\225[ENTER]marchito. "
gameforge.new_quest_premium_lv4._160_say = "Necesitas la siguiente cantidad de ramos de[ENTER]Lilas: %s "
gameforge.new_quest_premium_lv4._170_say = "Esto no es suficiente. \161Esta Lila s\243lo sirve para[ENTER]unas pocas gotas! "
gameforge.new_quest_premium_lv4._180_say = "\161Ahh, lila! Ahora s\243lo necesito algo de raro[ENTER]Almizcle. S\243lo puedes encargarlo en tiendas muy[ENTER]especiales. Una moneda girando te mostrar\225 el[ENTER]camino. Necesitar\225s algunas Marcas Drag\243n, pero[ENTER]estoy seguro que tienes algunas guardadas, \191no?[ENTER]\161Estar\233 eternamente agradecido! Despu\233s, puedes[ENTER]recoger tu pedido del Almacenero. \161Entonces[ENTER]tendr\233 finalmente todos los ingredientes! "
gameforge.new_quest_premium_lv4._190_say = "Por favor, date prisa y tr\225eme el Almizcle.[ENTER]\161Obtendr\225s una recompensa por hacerlo! "
gameforge.new_quest_premium_lv4._200_say_reward = "\161Sigue cazando hasta que puedas traerme %s ramos[ENTER]de Lila! "
gameforge.new_quest_premium_lv4._20_sayTitle = "Mi amor "
gameforge.new_quest_premium_lv4._210_say = "Mata Lobos Azules para conseguirlas. "
gameforge.new_quest_premium_lv4._220_say = "Eso es todo. Ahora vuelve con el Vendedor de la[ENTER]Tienda de Armas. "
gameforge.new_quest_premium_lv4._230_qSetTitle = "El Almizcle "
gameforge.new_quest_premium_lv4._240_say = "Muchas gracias. Ahora por fin puedo generar un[ENTER]nuevo perfume. "
gameforge.new_quest_premium_lv4._250_say = "Puedes decir a mi p\225jaro cantor que estar\233[ENTER]cantando en su ventana de nuevo esta noche. Ser\225[ENTER]complacida. "
gameforge.new_quest_premium_lv4._260_say = "Te mereces una recompensa: "
gameforge.new_quest_premium_lv4._270_say_reward = "Yang: %d "
gameforge.new_quest_premium_lv4._280_say = "Sin el Almizcle no puedo producir mi perfume. Por[ENTER]favor, d\233jate guiar por la moneda que gira y[ENTER]cons\237gueme otra muestra. "
gameforge.new_quest_premium_lv4._290_say_reward = "Vuelve con %s Almizcle(s). "
gameforge.new_quest_premium_lv4._300_say = "Tengo que llevar algo de Almizcle al Vendedor de[ENTER]la Tienda de Armas. Se supone que debo dejarme[ENTER]guiar por la moneda que gira, encargar un raro[ENTER]aceite de perfume y recogerlo del Almacenero. "
gameforge.new_quest_premium_lv4._30_say = "Echo de menos a mi amor, el Vendedor de la Tienda[ENTER]de Armas. Durante semanas ha estado cantando bajo[ENTER]mi ventana cada noche y ahora no he sabido nada[ENTER]de \233l durante d\237as. Quiz\225 tenga miedo de mi[ENTER]padre. \191Puedes averiguar qu\233 le pasa? "
gameforge.new_quest_premium_lv4._310_say_title = "El Vendedor de la Tienda de Armas "
gameforge.new_quest_premium_lv4._320_say = "Oh, gracias. \191As\237 que dices que simplemente se ha[ENTER]retrasado? Que alivio. Voy a esperarle esta[ENTER]noche. "
gameforge.new_quest_premium_lv4._330_say_reward = "Por tus esfuerzos recibir\225s: %s puntos de[ENTER]experiencia. "
gameforge.new_quest_premium_lv4._340_say = "Vuelve r\225pido con la Vendedora de la Tienda[ENTER]General. "
gameforge.new_quest_premium_lv4._350_npcChat = "Lila "
gameforge.new_quest_premium_lv4._35_qSetTitle = "Habla con el Vendedor de la Tienda de Armas "
gameforge.new_quest_premium_lv4._360_npcChat = "El Almizcle "
gameforge.new_quest_premium_lv4._40_qSetTitle = "Un nuevo perfume "
gameforge.new_quest_premium_lv4._45_qSetTitle = "Caza Lobos Azules "
gameforge.new_quest_premium_lv4._50_targetVid = "Vendedor de la tienda de armas: "
gameforge.new_quest_premium_lv4._55_qSetTitle = "Vuelve con el Vendedor de la Tienda de Armas "
gameforge.new_quest_premium_lv4._60_sayTitle = "El granuja "
gameforge.new_quest_premium_lv4._65_qSetTitle = "Lleva el Almizcle al Vendedor de la Tienda de[ENTER]Armas "
gameforge.new_quest_premium_lv4._70_say = "Es cierto, no he cantado m\225s bajo su ventana[ENTER]porque... oh, bien, \161me da tanta verg\252enza hablar[ENTER]sobre eso! Mi olor corporal se est\225 volviendo[ENTER]bastante repulsivo. Me lavo a todas horas, pero[ENTER]el olor no se va. Por eso quiero hacer un aceite[ENTER]de perfume que pueda cautivar a la Vendedora de[ENTER]la Tienda General, mi peque\241o p\225jaro cantor, con[ENTER]su picante y fascinante aroma. El aspecto[ENTER]exterior es muy importante para ella. "
gameforge.new_quest_premium_lv4._75_qSetTitle = "Ve con la Vendedora de la Tienda General "
gameforge.new_quest_premium_lv4._80_say = "Realmente tengo que hacer un perfume. Es el \250nico[ENTER]modo de librarme de mi desagradable olor[ENTER]corporal. "
gameforge.new_quest_premium_lv4._90_say = "Tengo que mezclar varios ingredientes para eso.[ENTER]Estos tienen que mezclarse primero: "
gameforge.notify_test_server = {}
gameforge.notify_test_server._10_chat = "Prueba del servidor "
gameforge.npc_talk = {}
gameforge.npc_talk._100_say = "Soy un verdadero anciano, pero aun estoy en forma[ENTER]y saludable porque tengo un secreto especial.[ENTER]He descubierto que una poci\243n hecha de Raices[ENTER]Gango y Setas Tue puede prolongar tu vida. Si[ENTER]quieres intentar hacer esa poci\243n, ll\233vale los[ENTER]ingredientes a Yu-Hwan. Puede preparar la poci\243n[ENTER]para ti. "
gameforge.npc_talk._10_say = "C\225llate y conserva tu disciplina. Comp\243rtate y no[ENTER]te metas en l\237os. Debes respetar a tus[ENTER]semejantes. \191Entendido? "
gameforge.npc_talk._110_npcChat = "Pareces bastante fuerte... "
gameforge.npc_talk._120_say = "Durante muchos a\241os, el secreto de la fuerza ha[ENTER]sido transmitido en nuestra familia. Mi padre me[ENTER]dijo que si mezclas la flor campana de forma[ENTER]correcta, la poci\243n te dar\225 fuerza extra durante[ENTER]un corto periodo de tiempo. Hasta donde yo se,[ENTER]Baek-Go es capaz de preparar esta poci\243n. S\243lo[ENTER]tienes que llevarle una flor[ENTER]campana.  "
gameforge.npc_talk._130_npcChat = "Ve, dilo en la monta\241a... "
gameforge.npc_talk._140_sayTitle = "Yu-Hwan, el m\250sico: "
gameforge.npc_talk._150_say = "... Sobre las colinas y en todas partes...[ENTER]\191Tambi\233n te gusta la m\250sica? Canto todo tipo de[ENTER]canciones aqu\237 en soledad, as\237 no me involucro en[ENTER]la guerra. Pero sin un pa\237s que me proteja, no[ENTER]podr\233 seguir haciendo lo que hago. "
gameforge.npc_talk._160_npcChat = "\191Por qu\233 lees tanto? "
gameforge.npc_talk._170_sayTitle = "Soon, el rat\243n de biblioteca: "
gameforge.npc_talk._180_say = "Oh, aventurero. El mundo est\225 lleno de problemas[ENTER]y solo a trav\233s de la sabidur\237a puedes[ENTER]sobrevivir. Honra siempre tus libros. Te ayudar\225n[ENTER]en los malos momentos. \161Cr\233eme! "
gameforge.npc_talk._190_npcChat = "\191Tienes hijos? "
gameforge.npc_talk._200_say = "En realidad no quer\237a hijos, pero...[ENTER]Bueno, sigo recogiendo Flores Kaki porque si las[ENTER]preparas correctamente, puedes intensificar tu[ENTER]energ\237a m\225gica con ellas. Lo descubri\243 Baek-Go.[ENTER]S\243lo necesita una flor para hacer 100 pociones.[ENTER]Por desgracia, la Flor Kaki tambi\233n tiene un[ENTER]efecto secundario. Si una mujer lleva un collar[ENTER]hecho de esta flor, tendr\225 un hijo. Entre t\250 y[ENTER]yo, mi mujer sac\243 provecho de esto[ENTER]descaradamente. "
gameforge.npc_talk._20_npcChat = "Mmm, huele bien aqu\237... "
gameforge.npc_talk._210_npcChat = "\191Qu\233 le pasa a tu pie? "
gameforge.npc_talk._220_sayTitle = "Handu-Up: "
gameforge.npc_talk._230_say = "Va mejorando. Hace poco mientras daba un paseo,[ENTER]me tropec\233 con una Ra\237z Gango y me torc\237 el[ENTER]tobillo. Por suerte conozco al doctor Baek-Go,[ENTER]as\237 que me trat\243 y me di\243 alg\250n consejo: Para[ENTER]sanar peque\241as heridas puedes preparar una poci\243n[ENTER]de esas mismas Raices Gango. As\237 que hice t\233 de[ENTER]las raices culpables y cur\243 el da\241o que hab\237an[ENTER]hecho... "
gameforge.npc_talk._240_npcChat = "\191Qui\233n eres t\250? "
gameforge.npc_talk._250_sayTitle = "Wonda-Rim: "
gameforge.npc_talk._260_say = "Soy Wonda-Rim, el sobrino de Chaegirab. \161Mi t\237o[ENTER]es famoso! \191Le conoces? Experimenta mucho con[ENTER]pociones y hierbas. Mientras hac\237a esto,[ENTER]descubri\243 que puedes conseguri una gran cantidad[ENTER]de protecci\243n contra energ\237a m\225gica si mezclas[ENTER]100 Aguas Bo con una Mora. Por lo que s\233,[ENTER]Huahn-So puede crear la poci\243n si le llevas los[ENTER]ingredientes. "
gameforge.npc_talk._270_npcChat = "\191Por qu\233 tienes tantas cicatrices? "
gameforge.npc_talk._280_sayTitle = "Balso el traidor: "
gameforge.npc_talk._290_say = "No soy buen luchador y salgo constantemente[ENTER]herido en la guerra. En alg\250n tiempo le pregunt\233[ENTER]a Yu-Hwan si pod\237a elaborar una poci\243n para mi[ENTER]que pudiera proteger mi cuerpo de las heridas. Me[ENTER]prepar\243 algo con Jugo Harebell y Lila, pero por[ENTER]desgracia la protecci\243n no fue suficiente. O[ENTER]quiz\225 fue s\243lo mi incompetencia. Pero estoy[ENTER]seguro de que la poci\243n te ayudar\225. "
gameforge.npc_talk._300_npcChat = "\191Por qu\233 tanta gente te llama traidor? "
gameforge.npc_talk._30_sayTitle = "Octavio, el due\241o del restaurante: "
gameforge.npc_talk._310_say = "Escap\233 de la guerra y me un\237 al Clan del Viento[ENTER]Negro. Mis camaradas nunca me perdonaron por eso.[ENTER]Despu\233s descubr\237 que los Guerreros del Viento[ENTER]Negro matan gente inocente, as\237 que les dej\233[ENTER]inmediatamente. \161Era horrible! "
gameforge.npc_talk._320_say = "\191Tienes gente inocente en la conciencia? Entonces[ENTER]verdaderamente te mereces tu nombre. Les[ENTER]impediste protagonizar una buena vida. "
gameforge.npc_talk._330_say = "Vivimos en un mundo sin ley. Pero he decidido que[ENTER]no har\233 ning\250n mal nunca m\225s. No quiero que la[ENTER]gente siga describi\233ndome como un traidor.[ENTER][ENTER]\191Tienes algo de Yang para m\237? "
gameforge.npc_talk._340_npcChat = "\191Te llaman el erudito? "
gameforge.npc_talk._350_sayTitle = "Uriel el erudito: "
gameforge.npc_talk._360_say = "Hay tantas cosas que aprender en este vasto[ENTER]mundo. La ignorancia sumada al poder militar son[ENTER]una mala combinaci\243n. T\250 no quieres vivir como[ENTER]esos soldados ignorantes, \191no? \161El conocimiento[ENTER]es el poder! "
gameforge.npc_talk._370_npcChat = "\191Mis fuentes me dicen que practicas medicina? "
gameforge.npc_talk._380_say = "Hago lo que puedo. Pero hay m\225s y m\225s accidentes[ENTER]cada d\237a en este mundo peligroso. No tenemos[ENTER]suficientes medicinas ni ayudantes. \161Los tiempos[ENTER]son dif\237ciles! \191Quiz\225 puedas echarme una mano m\225s[ENTER]tarde? "
gameforge.npc_talk._390_npcChat = "\191C\243mo va el negocio de la caza? "
gameforge.npc_talk._400_sayTitle = "Yang-Shin el cazador: "
gameforge.npc_talk._40_say = "\161Bienvenido! Nuestro restaurante es parte de una[ENTER]enorme cadena internacional. Entra y pru\233balo. "
gameforge.npc_talk._410_say = "Hmm, desde que las piedras Metin cayeron, los[ENTER]animales se han vuelto realmente salvajes. Hoy en[ENTER]d\237a, ya arriesgas tu vida saliendo a cazar[ENTER]algunos pollos. Son tiempos peligrosos para los[ENTER]cazadores. Por suerte, \161soy uno de los mejores! "
gameforge.npc_talk._420_npcChat = "\191De d\243nde viene tu gran precisi\243n? "
gameforge.npc_talk._430_say = "Soy genial con un arco, porque tengo una receta[ENTER]especial, \161jeje! Cuando mezclas Jugo Flor[ENTER]Melocot\243n con Lila, obtienes una poci\243n que[ENTER]aumenta tu precisi\243n. Ll\233vale los ingredientes a[ENTER]Yu-Hwan, estoy seguro de que preparar\225 la poci\243n[ENTER]para ti. "
gameforge.npc_talk._440_npcChat = "Que corona floral tan bonita... "
gameforge.npc_talk._450_say = "Sol\237a recoger Flores Melocot\243n con mi hermano.[ENTER]Pero ahora tengo que hacerlo todo sola. No son[ENTER]muy bonitas, pero tienen un efecto especial. Si[ENTER]le llevas una Flor Melocot\243n a Baek-Go,[ENTER]\161preparar\225 una poci\243n con ella que te hace muy[ENTER]r\225pido! "
gameforge.npc_talk._460_npcChat = "\191D\243nde est\225 tu hermano? "
gameforge.npc_talk._470_say = "\218ltimamente mi hermano ha estado viajando mucho.[ENTER]Escasamente le veo y me preocupo mucho por \233l. "
gameforge.npc_talk._480_npcChat = "\191Vendes pasteles de arroz? "
gameforge.npc_talk._490_sayTitle = "Yu-Rang, el vendedor de tortas de arroz: "
gameforge.npc_talk._500_say = "A causa de la guerra, es dif\237cil vender pastel de[ENTER]arroz. Gracias a los bandidos, he perdido muchos[ENTER]clientes. Ya no s\233 que debo hacer para[ENTER]sobrevivir. "
gameforge.npc_talk._50_say = "Aunque es un gran restaurante, el mobiliario es[ENTER]sorprendentemente sencillo. "
gameforge.npc_talk._510_npcChat = "\191Qui\233n suele comprarte art\237culos? "
gameforge.npc_talk._520_say = "Vendo la mayor\237a de los pasteles a los viajeros.[ENTER]Un d\237a, un misterioso jinete vestido de negro[ENTER]vino a verme. Como pago, me dio una receta que[ENTER]puedes hacer con Agua Zin. Es una poci\243n que[ENTER]mejora tu poder de ataque. Le vend\237 la receta a[ENTER]Huahn-So. Si le llevas algo de Agua Sim y una[ENTER]Rosa Alpina a Huahn-So, crear\225 algo de Agua Zin[ENTER]para ti. "
gameforge.npc_talk._530_npcChat = "\191Por qu\233 est\225s tan triste? "
gameforge.npc_talk._540_say = "Oh, qui\233n podr\237a haber sabido que nuestros dulces[ENTER]sue\241os iban a ser hechos pedazos tan[ENTER]despiadadamente... Mi pobre marido, \161cay\243 durante[ENTER]la batalla! ... Por favor, venga su muerte. "
gameforge.npc_talk._550_npcChat = "Ha caido tanta gente en la guerra... "
gameforge.npc_talk._560_say = "Estamos perdiendo m\225s y m\225s hombres durante la[ENTER]guerra, as\237 que las mujeres de la aldea se[ENTER]juntaron y le pidieron a Huahn-So que crease una[ENTER]poci\243n curativa mejor. Despu\233s de una larga[ENTER]investigaci\243n, produjo una poci\243n que aumenta la[ENTER]defensa, para as\237 tener que usar menos pociones[ENTER]curativas. Ve a verle. Seguro que puede hacer[ENTER]para t\237 la poci\243n, que \233l llama Agua SamBo. S\243lo[ENTER]necesita algo de Agua Dok y una Rosa Alpina para[ENTER]hacerla. "
gameforge.npc_talk._570_npcChat = "Oh, que ni\241o tan guapo... "
gameforge.npc_talk._580_sayTitle = "Ah-Yu: "
gameforge.npc_talk._590_say = "Ya est\225 llorando otra vez... No s\233 si es que[ENTER]quiere caramelos o... \161ohh no! "
gameforge.npc_talk._600_npcChat = "\191C\243mo est\225is? "
gameforge.npc_talk._60_npcChat = "Cu\233ntame algo sobre alfarer\237a. "
gameforge.npc_talk._610_say = "\161Mi ni\241o! Ugh. Ahora que mi marido ha ca\237do en la[ENTER]guerra, tengo que cuidar de m\237 misma. Trato de[ENTER]mantenerme a m\237 y a mi beb\233 por mi cuenta. Con el[ENTER]agua Bo, encontr\233 la posibilidad de mejorar mi[ENTER]vida. Tengo que darle a Yu-Hwan 100 jugos de flor[ENTER]kaki y una seta Tue. De esto, \233l elabora agua Bo,[ENTER]que puedo vender realmente f\225cil. Despu\233s de todo[ENTER]la necesito para sobrevivir de alguna manera... "
gameforge.npc_talk._620_npcChat = "\191C\243mo est\225 tu marido? "
gameforge.npc_talk._630_sayTitle = "Aranyo: "
gameforge.npc_talk._640_say = "Mi as\237 llamado marido est\225 casado con sus libros.[ENTER]Apenas me mira ya. Y no soy una mujer fea. "
gameforge.npc_talk._650_npcChat = "\191C\243mo van las cosas? "
gameforge.npc_talk._660_say = "Desde que estall\243 la guerra, los negocios han ido[ENTER]realmente mal. La uni\243n de mercaderes fue una vez[ENTER]una uni\243n rica y poderosa, pero esos d\237as se han[ENTER]acabado. No podemos seguir ignorando m\225s a los[ENTER]salvajes, los soldados del juramento blanco y los[ENTER]soldados viento negro. "
gameforge.npc_talk._670_npcChat = "\191Por qu\233 est\225s tan de mal humor? "
gameforge.npc_talk._680_sayTitle = "Taurean: "
gameforge.npc_talk._690_say = "\161Harang es una mala chica! \161La odio! \161Soy d\233bil y[ENTER]me fastidia a menudo! "
gameforge.npc_talk._700_say = "T\250 eres un hombre y tienes algo de m\250sculo.[ENTER]\161Trab\225jalos de vez en cuando! "
gameforge.npc_talk._70_sayTitle = "Yonah el alfarero: "
gameforge.npc_talk._710_npcChat = "\191Qu\233 est\225s haciendo? "
gameforge.npc_talk._720_sayTitle = "Harang: "
gameforge.npc_talk._730_say = "Estoy esperando a Taurean. Solemos jugar juntos y[ENTER]tambi\233n peleamos mucho. \161Qu\233 cobarde! Si no viene[ENTER]voluntariamente, \161se lo har\233 pasar verdaderamente[ENTER]mal! "
gameforge.npc_talk._740_npcChat = "Taurean te tiene miedo. "
gameforge.npc_talk._750_say = "Taurean es verdaderamente m\225s fuerte que yo. As\237[ENTER]que ahora he pensado en una manera en la que[ENTER]poder ganarle como sea. Un Ninja blanco me dijo[ENTER]que puedes mezclar Agua Young on una Mora y hacer[ENTER]una poci\243n que te hace golpear m\225s r\225pido.[ENTER]\161Entonces podr\233 derrotar a Taurean al fin! Si t\250[ENTER]tambi\233n quieres convertirte en un atacante[ENTER]r\225pido, ll\233vale los ingredientes a Huahn-So.[ENTER]Seguro que har\225 la poci\243n para ti. "
gameforge.npc_talk._760_npcChat = "Nuevo entendimiento... "
gameforge.npc_talk._770_say_title = "Seon-Pyeong: "
gameforge.npc_talk._780_say = "Amigo m\237o, el mundo est\225 lleno de preguntas sin[ENTER]resolver. Y yo, soy un buscador de respuestas y[ENTER]un buscador de conocimiento. \191Has oido alguna vez[ENTER]sobre armas \233picas y Piedras Esp\237ritu? "
gameforge.npc_talk._790_npcChat = "\191Qu\233 est\225s haciendo? "
gameforge.npc_talk._800_say = "Posiblemente ya sepas que investigo conocimiento[ENTER]desconocido. Y actualmente estoy examinando un[ENTER]m\233todo adicional de reforzar armas y mejorar el[ENTER]poder de las Piedras Esp\237ritu. "
gameforge.npc_talk._80_say = "Me gusta ser alfarero. Es muy satisfactorio[ENTER]moldear arcilla con tus propias manos y ver como[ENTER]se crea algo... Normalmente s\243lo hago cosas[ENTER]simples. En el este, en las afueras del[ENTER]continente, los m\233todos de producci\243n est\225n mucho[ENTER]m\225s desarrollados. Una vez v\237 a algunos alfareros[ENTER]all\237 y me inspir\233 much\237simo. A veces, cuando[ENTER]tengo tiempo, trato de experimentar. Pero a\250n no[ENTER]he descubierto el truco que usan. "
gameforge.npc_talk._810_npcChat = "La investigaci\243n de las armas... "
gameforge.npc_talk._820_say = "Interesante, \191no? \191Quieres saber m\225s sobre esto?[ENTER]Entonces tr\225eme el arma +9 de nivel 65 necesaria.[ENTER]Tambi\233n necesito un Panfleto de Contenci\243n y dos[ENTER]Bendiciones. Intentar\233 hacer un arma \233pica con[ENTER]eso. "
gameforge.npc_talk._830_say = "Sin embargo, no puedo prometer que funcione. "
gameforge.npc_talk._840_npcChat = "Las Piedras Esp\237ritu... "
gameforge.npc_talk._850_say = "Las Piedras Esp\237ritu se usan generalmente, pero[ENTER]aunque se usen mucho, mucha gente no conoce[ENTER]realmente cual es su verdadero poder. Pero mi[ENTER]investigaci\243n me ha ayudado a averiguar mucho m\225s[ENTER]sobre ellas. Si me traes otra Piedra Esp\237ritu,[ENTER]puedo mejorarla para ti. "
gameforge.npc_talk._90_npcChat = "Eres muy en\233rgico para tu edad... "
gameforge.olympic_badge = {}
gameforge.olympic_badge._010_npcChat = "Medalla del H\233roe "
gameforge.olympic_badge._020_say = "\161Ayuda! "
gameforge.olympic_badge._030_say = "Miserable hatajo de ladrones...[ENTER]\161Ayer por la noche me entrarron en casa![ENTER]Se llevaron la Medalla del H\233roe. Un antepasado[ENTER]m\237o la recibi\243 en su momentom tras correr 42\160195[ENTER]quil\243metros desde el campo de batalla hasta donde[ENTER]estaba su monarca para comunicarle la victoria.[ENTER]\161Y ahora ha desaparecido! "
gameforge.olympic_badge._040_say = "Diantres... para mi familia es de un valor[ENTER]incalculable. \191Qu\233 hago ahora? "
gameforge.olympic_badge._050_say = "\191Me ayudar\225s? "
gameforge.olympic_badge._060_npcChat = "Medalla del H\233roe "
gameforge.olympic_badge._070_say = "\161Por fin! \161Has vuelto![ENTER]\191Has encontrado la Medalla del H\233roe? "
gameforge.olympic_badge._080_say = "\191Y para qu\233? \191Qu\233 quieren hacer estos bribones[ENTER]con mi medalla? \161Si para otros no tiene ning\250n[ENTER]valor! \191Me podr\237as ayudar a recuperarla? "
gameforge.olympic_badge._090_npcChat = "\161Encuentra la Medalla del H\233roe! "
gameforge.olympic_badge._100_say = "\191Vuelves con las manos vac\237as? Oh, no, estoy[ENTER]desesperado. Si t\250 no me ayudas, \191qui\233n lo har\225?[ENTER]\161Por favor, sigue buscando! "
gameforge.olympic_badge._110_say = "\161Has encontrado mi Medalla![ENTER]Pero espera... esto es s\243lo un pedazo. \161Qu\233[ENTER]infamia, la han partido en cinco![ENTER]\161Por favor, tr\225eme todos los fragmentos! Quiz\225s[ENTER]pueda recomponerla! "
gameforge.olympic_badge._120_say = "\161Estos malditos ladrones han destrozado mi[ENTER]valiosa herencia![ENTER]Muchas gracias por haber encontrado todos los[ENTER]fragmentos. Ahora puedo volver a unirlos todos. "
gameforge.olympic_badge._130_say = "\161Mil gracias! Has restablecido el honor de mi[ENTER]familia.[ENTER]Tus esfuerzos no habr\225n sido en vano. \161Aqu\237[ENTER]tienes tu merecida recompensa! "
gameforge.olympic_badge._140_say = "\191De verdad quieres rechazar este encargo?[ENTER]Si ahora escoges 'S\237' no podr\225s volver a tomarlo. "
gameforge.olympic_badge._150_say = "Entiendo que ahora no tengas tiempo.[ENTER]Vuelve cuando te venga bien. \161Pero no me hagas[ENTER]esperar mucho! "
gameforge.olympic_badge._160_say = "Me temo que has venido demasiado tarde y ya no[ENTER]puedes ayudarme. \161Te deseo todo lo mejor para tu[ENTER]camino! "
gameforge.olympic_badge._170_say = "\161Da caza a los monstruos que me robaron! Pero ten[ENTER]cuidado: eran muy fuertes, como m\237nimo de nivel[ENTER]30. \161Si me traes de vuelta la Medalla del H\233roe[ENTER]te recompensar\233 como es debido! "
gameforge.olympic_badge._180_say = "Encuentra la Medalla del H\233roe y ll\233vasela a[ENTER]Yu-Hwan. "
gameforge.olympic_badge._190_say = "Yu-Hwan necesita tu ayuda. \161Ve a verlo![ENTER]Lo encontrar\225s en el segundo poblado. "
