gameforge.pony_buy._10_npcChat = "Quiero cabalgar. "
gameforge.pony_buy._110_npcChat = "Estado de la misi\243n de mejorar el pony. "
gameforge.pony_buy._120_npcChat = "Progreso de la prueba de calificaci\243n "
gameforge.pony_buy._130_sayReward = "\161Mata 20 arqueros salvajes en menos de 30 minutos[ENTER]y vuelve! "
gameforge.pony_buy._140_select = "Cancelar "
gameforge.pony_buy._150_say = "\191Realmente deseas cancelar la prueba de[ENTER]calificaci\243n? "
gameforge.pony_buy._160_select = "No, solo bromeaba. "
gameforge.pony_buy._170_say = "Aseg\250rate de tener \233xito la pr\243xima vez. "
gameforge.pony_buy._180_sayTitle = "Chico del establo: "
gameforge.pony_buy._190_say = "No tienes tiempo de estar por aqu\237. \161Date prisa![ENTER]\161Mata esos arqueros salvajes y vuelve! "
gameforge.pony_buy._200_say = "Has terminado tu misi\243n con \233xito. Para poder[ENTER]montar a caballo, necesitas una pintura de[ENTER]caballo. Pasar\225 un tiempo hasta que pueda[ENTER]d\225rtela. Vuelve ma\241ana. No te olvides que la[ENTER]pintura de caballo cuesta 100.000 Yang. "
gameforge.pony_buy._20_say = "Necesitas alcanzar el nivel 25 para poder montar[ENTER]a caballo. En mi opini\243n, necesitas mejorar[ENTER]primero. "
gameforge.pony_buy._210_makequestbutton = "La pintura de caballo est\225 siendo creada "
gameforge.pony_buy._220_sayReward = "El Chico del Establo est\225 elaborando una Pintura[ENTER]de Caballo para ti, pero todav\237a necesita algo de[ENTER]tiempo. Ve a ver al Chico del Establo cuando la[ENTER]Pintura de Caballo est\233 lista. "
gameforge.pony_buy._230_npcChat = "\191Est\225 lista la pintura de caballo? "
gameforge.pony_buy._240_say = "Creo que tardar\225 un poco m\225s hasta que est\233[ENTER]lista. Recuerda que necesitas 100.000 Yang para[ENTER]la Pintura de Caballo. "
gameforge.pony_buy._250_makequestbutton = "Ve con el chico del establo. "
gameforge.pony_buy._260_sayReward = "\161El Chico del Estableo ha terminado la Pintura de[ENTER]Caballo! Ve a verlo y rec\243gela. "
gameforge.pony_buy._270_npcChat = "Quiero recoger la Pintura de Caballo. "
gameforge.pony_buy._280_sayTitle = "Chico del establo: "
gameforge.pony_buy._290_say = "He terminado la Pintura de Caballo. Ahora puedes[ENTER]montar un caballo de principiante y moverte m\225s[ENTER]r\225pido. La Pintura de Caballo cuesta 100.000[ENTER]Yang. \191Quieres comprarla? "
