gameforge.skill_reset2._10_npcChat = "Restablecer habilidades "
gameforge.skill_reset2._110_say = "Si cambias de opini\243n, vuelve a visitarme. "
gameforge.skill_reset2._120_say = "No tienes suficiente Yang. No puedo ayudarte;[ENTER]necesito el dinero para sobrevivir. "
gameforge.skill_reset2._130_say = "Este objeto te ofrece la posibilidad de olvidar[ENTER]tu antiguo entrenamiento y comenzar de nuevo. Sin[ENTER]embargo, tienes que haber alcanzado al menos el[ENTER]nivel 31 para usarlo.[ENTER]Entonces ser\225s libre de elegir tu destino una vez[ENTER]m\225s. \191Quieres despojarte de las habilidades que[ENTER]te han tra\237do aqu\237? "
gameforge.skill_reset2._135_say = "\161No est\225s realizando ning\250n entrenamiento y no[ENTER]tienes ning\250n punto de habilidad que pueda ser[ENTER]restablecido! "
gameforge.skill_reset2._140_say = "Este objeto solamente se puede utilizar a partir[ENTER]del nivel 31. "
gameforge.skill_reset2._20_say = "\161Todav\237a no has empezado ning\250n entrenamiento![ENTER]Mientras no gastes ning\250n punto de habilidad, no[ENTER]podr\225s restablecerlas. Vuelve cuando hayas hecho[ENTER]alg\250n error durante tu entrenamiento, entonces s\237[ENTER]estar\233 encantado de ayudarte. "
gameforge.skill_reset2._30_say = "Tu nivel es %s. No puedo ayudarte. Con este[ENTER]nivel, no puedes cambiar m\225s tus habilidades.[ENTER]S\243lo si est\225s por debajo del nivel 30 puedes[ENTER]escoger otra habilidad. "
gameforge.skill_reset2._40_say = "\161No est\225s realizando ning\250n entrenamiento y no[ENTER]tienes ning\250n punto de habilidad que pueda ser[ENTER]restablecido! "
gameforge.skill_reset2._50_say = "Hola, has venido al sitio correcto. Tus ojos[ENTER]muestran mucho dolor. Permito a las personas[ENTER]olvidar sus habilidades para que puedan empezar[ENTER]de nuevo. \191Quieres olvidar tus habilidades y[ENTER]empezar de nuevo? Cuesta %s Yang. "
gameforge.skill_reset2._60_select = "No restablecer "
gameforge.skill_reset2._70_say = "Ja ja, \191es posible que no te sientas bien? Tu[ENTER]rostro me dice que podr\237as necesitar algo de[ENTER]ayuda. \191No est\225s satisfecho con tus habilidades?[ENTER]Gracias a la magia, puedo ayudarte a olvidar tus[ENTER]habilidades. "
gameforge.skill_reset2._80_say = "Esto significa que puedes elegir nuevas[ENTER]habilidades. Pero, desafortunadamente, vas a[ENTER]perder todos los puntos que hayas obtenido[ENTER]leyendo libros. \191Est\225s seguro que quieres empezar[ENTER]de nuevo? Cuesta %s Yang. "
gameforge.skill_reset2._90_select = "Restablecer habilidades "
