gameforge.spider_dungeon_2floor._10_npcChat = "Vuelve a la primera planta "
gameforge.spider_dungeon_2floor._15_sayTitle = "Pung-Ho: "
gameforge.spider_dungeon_2floor._20_say = "\191Realmente quieres volver a la primera planta? "
gameforge.spider_dungeon_2floor._30_say = "Una decisi\243n acertada. Es demasiado peligroso[ENTER]permanecer aqu\237.[ENTER]Ve a curar tus heridas. "
gameforge.spider_dungeon_2floor._40_say = "Como quieras...[ENTER]\161Ten cuidado![ENTER]\161Lo de arriba es muy peligroso! "
gameforge.spider_dungeon_3floor_boss = {}
gameforge.spider_dungeon_3floor_boss._100_say = "No me ir\225s a contar que no te atreves a entrar en[ENTER]la Mazmorra de Ara\241as. Te cuentas entre los[ENTER]mejores guerreros y tienes una t\233cnica perfecta,[ENTER]as\237 que un par de bichos no deber\237an ser un[ENTER]problema para ti. Pero supongo que sabes que[ENTER]necesitas un Tique de entrada para acceder a[ENTER]ella, \191verdad? "
gameforge.spider_dungeon_3floor_boss._10_npcChat = "Acceso al cubil "
gameforge.spider_dungeon_3floor_boss._110_sendLetter = "Un nuevo peligro "
gameforge.spider_dungeon_3floor_boss._120_say = "Has creado una copia perfecta de la inscripci\243n.[ENTER]Mu\233strasela al Capit\225n. "
gameforge.spider_dungeon_3floor_boss._130_say = "\161Muy bien, lo has conseguido! Mu\233stramela...[ENTER]Hm, desconozco estas letras, no entiendo ni una[ENTER]palabra. Quiz\225s deber\237as pedirle consejo al sabio[ENTER]Uriel. "
gameforge.spider_dungeon_3floor_boss._140_say = "Ve con el sabio Uriel y mu\233strale la inscripci\243n.[ENTER]Seguro que \233l puede ayudarte a traducirla. "
gameforge.spider_dungeon_3floor_boss._150_say = "\191El Capit\225n quiere que descifre esta inscripci\243n[ENTER]misteriosa? Por supuesto. Me encantan los retos.[ENTER]Mu\233stramela.[ENTER]Esto es... esto es monstruoso. Aqu\237 tienes, he[ENTER]escrito la traducci\243n en este papel. Ll\233vaselo[ENTER]r\225pidamente al Capit\225n y vuelve despu\233s por aqu\237.[ENTER]Si lo que pone aqu\237 es cierto, corremos un grave[ENTER]peligro. \161Vamos, mu\233vete! "
gameforge.spider_dungeon_3floor_boss._160_say = "\191A\250n no has hablado con el Capit\225n? Date prisa,[ENTER]no tenemos tiempo que perder. \161Tiene que leer[ENTER]esta carta cuanto antes! "
gameforge.spider_dungeon_3floor_boss._170_sayTitle = "Entrega la carta de Uriel "
gameforge.spider_dungeon_3floor_boss._180_say = "Ese viejo testarudo... \191qu\233 le habr\237a costado dar[ENTER]las gracias? Pero no pasa nada. Dijo que la[ENTER]informaci\243n es extremadamente importante, as\237 que[ENTER]se la llevar\233 r\225pidamente al Capit\225n. "
gameforge.spider_dungeon_3floor_boss._190_npcChat = "Carta de Uriel "
gameforge.spider_dungeon_3floor_boss._200_say = "\161Oh, no! Un violento demonio ar\225cnido, la[ENTER]Baronesa Ara\241a, ha anidado en el tercer nivel de[ENTER]la Mazmorra de Ara\241as. Seg\250n la inscripci\243n, se[ENTER]necesita una llave especial para acceder a esa[ENTER]cueva oculta. Ve a ver a Uriel y preg\250ntale sobre[ENTER]ella. \161Despu\233s re\250ne una tropa de guerreros[ENTER]capaces y asalta el escondrijo de la Baronesa[ENTER]Ara\241a![ENTER]Toma este Tique de entrada. "
gameforge.spider_dungeon_3floor_boss._20_say = "Esta puerta solamente se puede abrir con la Llave[ENTER]Ar\225cnida. "
gameforge.spider_dungeon_3floor_boss._210_npcChat = "La Llave Ar\225cnida "
gameforge.spider_dungeon_3floor_boss._220_say = "Deber\237a buscar a Uriel cuanto antes. "
gameforge.spider_dungeon_3floor_boss._230_say = "Ah, has vuelto. Entonces, \191el Capit\225n te ha[ENTER]ordenado acabar con la Baronesa Ara\241a? Pero el[ENTER]acceso al cubil de la Baronesa est\225 cerrado, y[ENTER]solamente se puede abrir mediante la Llave[ENTER]Ar\225cnida. Fabricarla es un proceso laborioso.[ENTER]Pero si me traes un Saco de Veneno de Ara\241a, un[ENTER]Saco de Huevos de Ara\241a, una Telara\241a, Ojos de[ENTER]Ara\241a, Patas de Ara\241a y el Veneno de la Reina[ENTER]Ara\241a, podr\237a fabricarte una. "
gameforge.spider_dungeon_3floor_boss._240_say = "\191Quieres que te fabrique la Llave Ar\225cnida? Para[ENTER]eso necesitar\233 un Saco de Veneno de Ara\241a, un[ENTER]Saco de Huevos de Ara\241a, una Telara\241a, Ojos y[ENTER]Patas de Ara\241a y el Veneno de la Reina Ara\241a.[ENTER]\191Podr\237as encontrar todas esas sustancias? "
gameforge.spider_dungeon_3floor_boss._250_say = "\161Excelente! Has encontrado todos los elementos[ENTER]necesarios para fabricar la Llave Ar\225cnida.[ENTER]Espera un momento.[ENTER]Fabricarla no deber\237a durar demasiado. "
gameforge.spider_dungeon_3floor_boss._260_say = "\161Ja, lo he conseguido! Aqu\237 tienes la Llave[ENTER]Ar\225cnida. Te abrir\225 el acceso al cubil de la[ENTER]Baronesa Ara\241a. \161Te deseo a ti y a tus compa\241eros[ENTER]mucho \233xito en la lucha contra esa bestia[ENTER]zancuda! Pero tendr\233is que apresuraros: la llave[ENTER]es muy inestable. Ten\233is 24 horas antes de que se[ENTER]haga a\241icos. "
gameforge.spider_dungeon_3floor_boss._270_say = "Oh, oh... Me temo que nadie nace sabiendo. Debes[ENTER]saber que el proceso de fabricaci\243n de esta llave[ENTER]es extremadamente complicado. El m\225s m\237nimo error[ENTER]puede hacerlo fracasar. Por desgracia, he[ENTER]malgastado todas las sustancias que reuniste tan[ENTER]trabajosamente. \161Pero el pr\243ximo intento tendr\225[ENTER]\233xito, seguro! "
gameforge.spider_dungeon_3floor_boss._280_say = "A\250n me falta algo para poder fabricar la Llave[ENTER]Ar\225cnida. Te recuerdo que necesito un Saco de[ENTER]Veneno de Ara\241a, un Saco de Huevos de Ara\241a, una[ENTER]Telara\241a, Ojos de Ara\241a, Patas de Ara\241a y el[ENTER]Veneno de la Reina Ara\241a. "
gameforge.spider_dungeon_3floor_boss._300_say = "Tu l\237der de grupo ha entrado en la mazmorra.[ENTER]\191Quieres seguirlo? "
gameforge.spider_dungeon_3floor_boss._30_npcChat = "Reiniciar misi\243n MdA3 "
gameforge.spider_dungeon_3floor_boss._310_say = "Te ha llevado demasiado tiempo. La llave ya se ha[ENTER]descompuesto. Haz que te fabriquen una nueva si[ENTER]quieres entrar aqu\237. "
gameforge.spider_dungeon_3floor_boss._320_say = "Ya hay un grupo en el cubil de la Baronesa[ENTER]atacando a la Baronesa Ara\241a. "
gameforge.spider_dungeon_3floor_boss._330_say = "Podr\225s entrar cuando el grupo anterior haya[ENTER]completado su misi\243n. Vuelve en %s minutos. "
gameforge.spider_dungeon_3floor_boss._340_say = "Tiempo de espera hasta que la puerta del cubil de[ENTER]la Baronesa se pueda volver a abrir: "
gameforge.spider_dungeon_3floor_boss._350_say = "%s minutos "
gameforge.spider_dungeon_3floor_boss._360_say = "El luchador que entr\243 en la cueva antes que t\250[ENTER]podr\225 volver a moverse despu\233s de diez segundos.[ENTER]Por favor, espera un momento. "
gameforge.spider_dungeon_3floor_boss._370_say = "\191Quieres iniciar un asalto? Tienes 20 minutos.[ENTER]Antes de que concluya ese tiempo, nadie puede[ENTER]abandonar el cubil de la baronesa.[ENTER]Se podr\225 llevar a cabo otro asalto tras una hora. "
gameforge.spider_dungeon_3floor_boss._380_say = "Para abrir la entrada necesitas la Llave Ar\225cnida. "
gameforge.spider_dungeon_3floor_boss._390_say = "Solamente el l\237der del grupo puede utilizar la[ENTER]Llave Ar\225cnida. "
gameforge.spider_dungeon_3floor_boss._400_say = "\161La Baronesa Ara\241a ha muerto! En tres minutos,[ENTER]todos los guerreros ser\225n teletransportados fuera[ENTER]de la cueva. "
gameforge.spider_dungeon_3floor_boss._40_say = "Antes de crear la llave "
gameforge.spider_dungeon_3floor_boss._410_say = "No ha funcionado. \161Int\233ntalo de nuevo! "
gameforge.spider_dungeon_3floor_boss._420_notice = "Atenci\243n: \161La Baronesa Ara\241a est\225 montando en[ENTER]c\243lera! Su ataque se vuelve m\225s potente, pero[ENTER]empieza a descuidar su defensa. "
gameforge.spider_dungeon_3floor_boss._50_npcChat = "Mazmorra de Ara\241as 3 "
gameforge.spider_dungeon_3floor_boss._60_say = "Ah, me alegro de que hayas venido. Un[ENTER]destacamento de esp\237as ha descubierto un tercer[ENTER]nivel en la Mazmorra de Ara\241as. Al parecer, unas[ENTER]ara\241as enormes y malignas han anidado en esta[ENTER]cueva, hasta ahora desconocida. Adem\225s, mis[ENTER]hombres han encontrado una vieja l\225pida cuya[ENTER]inscripci\243n no lograron descifrar. Ve a buscar[ENTER]esa piedra y tr\225eme una copia de la inscripci\243n.[ENTER]Toma, este pase te permitir\225 acceder a la[ENTER]Mazmorra de Ara\241as. "
gameforge.spider_dungeon_3floor_boss._70_sendLetter = "La inscripci\243n "
gameforge.spider_dungeon_3floor_boss._80_say = "En el tercer nivel de la Mazmorra de Ara\241as se[ENTER]encuentra una vieja l\225pida con una inscripci\243n[ENTER]grabada. Haz una copia de ella y ll\233vasela al[ENTER]Capit\225n. "
gameforge.spider_dungeon_3floor_boss._90_say = "\161Perfecto, has encontrado la vieja l\225pida y has[ENTER]creado una Copia de la Inscripci\243n! Vuelve con el[ENTER]Capit\225n y mu\233strasela. "
