gameforge.subquest_01._140_sayTitle = "Yonah: "
gameforge.subquest_01._150_say = "\161Oh! \161Diablos! \161No puedo parar de toser! \191C\243mo se[ENTER]supone que voy a trabajar as\237?[ENTER]\191La vendedora de la Tienda General te env\237a?[ENTER]Tengo Botellas Vac\237as, pero no te puedo dar una[ENTER]gratis. "
gameforge.subquest_01._160_say = "Soy asm\225tico. Me dijeron que las semillas de[ENTER]melocot\243n son un buen remedio. Si puedes[ENTER]conseguirme una, te dar\233 una botella. Puedes[ENTER]conseguir las semillas de melocot\243n de los[ENTER]jabal\237es de las afueras de la ciudad. Tan pronto[ENTER]como los granjeros siembran semillas de[ENTER]melocot\243n, los jabal\237es escarban y las sacan para[ENTER]com\233rselas. "
