gameforge.subquest_01._180_sayReward = "La vendedora del almac\233n general necesita una[ENTER]botella vac\237a de Yonah el alfarero. Yonah, que es[ENTER]asm\225tico, te dar\225 una botella vac\237a si le llevas[ENTER]una semilla de melocot\243n. Puedes encontrar una[ENTER]semilla cazando jabal\237es. "
gameforge.subquest_01._190_npcChat = "Para conseguir Semillas de Melocot\243n... "
gameforge.subquest_01._200_say = "Puedes conseguir semillas de melocot\243n de los[ENTER]jabal\237es de las afueras de la aldea. Tan pronto[ENTER]como los granjeros siembran semillas de[ENTER]melocot\243n, los jabal\237es escarban y las sacan para[ENTER]com\233rselas.[ENTER]Cough, cough.[ENTER]Gracias de antemano. "
