gameforge.subquest_01._240_say = "Oh, \161la tienes! "
gameforge.subquest_01._250_say = "Gracias. Ahora puedo aliviar mi asma y volver al[ENTER]trabajo. "
gameforge.subquest_01._260_say = "Aqu\237 tienes una botella vac\237a. Ll\233vala al almac\233n[ENTER]general. "
gameforge.subquest_01._270_sendLetter = "Entrega la Botella Vac\237a. "
gameforge.subquest_01._280_sayReward = "La vendedora del almac\233n general necesita la[ENTER]botella vac\237a del alfarero. Ll\233vasela. "
