gameforge.subquest_01._300_say = "Gracias. Espero que no te haya costado mucho.[ENTER]Toma, coge esto por tus esfuerzos. De nuevo,[ENTER]\161muchas gracias! "
gameforge.subquest_01._30_say = "Disculpa, si no est\225s muy ocupado en este[ENTER]momento, \191podr\237as hacerme un favor? Necesito una[ENTER]botella vac\237a para mi poci\243n roja. "
