gameforge.subquest_02._130_say = "Gracias por conseguirme la informaci\243n tan[ENTER]r\225pido. Aqu\237 est\225 tu recompensa. "
gameforge.subquest_02._140_sayReward = "Has recibido 1000 puntos de experiencia.[ENTER]Has recibido 1500 Yang. "
gameforge.subquest_02._150_say = "Vendedora de la tienda general:[ENTER]No me sorprende, siempre hace pedidos bastante[ENTER]inusuales. \191Podr\237as, por favor, preguntarle de[ENTER]nuevo? "
gameforge.subquest_02._160_say = "Vendedora de la Tienda General:[ENTER]\191Dijo eso? \191Est\225s seguro? Eso no suena a mi[ENTER]padre... \191Podr\237as, por favor, preguntarle de[ENTER]nuevo? No creo que haya mencionado ese plato. "
gameforge.subquest_02._20_say = "Estoy segura de que conoces al vendendor de la[ENTER]tienda de armaduras. Es mi padre. Quiero[ENTER]prepararle la cena, pero no se qu\233 quiere comer.[ENTER]\191Podr\237as preguntarle qu\233 le gustar\237a? Te[ENTER]recompensar\233 por tu tiempo. "
