gameforge.subquest_02._50_say = "\161Bienvenido![ENTER][ENTER]Produzco armaduras para protegerte de los ataques[ENTER]con cuchillos y espadas. "
gameforge.subquest_02._60_say = "\161Ah! \191Mi hija ten env\237a para preguntarme por la[ENTER]cena? \191Pregunta que qu\233 quiero para cenar? D\233jame[ENTER]pensar...[ENTER]Mmmhhh, me gustar\237a tomar un estofado con venado,[ENTER]oso, col y dos huevos. \161Eso es lo que[ENTER]verdaderamente me apetece! "
