gameforge.subquest_04._100_say = "Queda un largo camino frente a ti. \161Cu\237date! Y no[ENTER]lo olvides: Tienes que usar el portal con el[ENTER]punto azul. "
gameforge.subquest_04._10_targetVid = "\191C\243mo est\225 Deokbae? "
gameforge.subquest_04._110_sayReward = "Ve y entrega la Carta del Herrero a Deokbae, el[ENTER]le\241ador. Le encontrar\225s en la segunda aldea, a la[ENTER]que s\243lo puedes llegar a trav\233s del portal. "
gameforge.subquest_04._120_sendLetter = "Una carta del herrero. "
gameforge.subquest_04._130_targetVid = "Encuentra a Deokbae el le\241ador. "
gameforge.subquest_04._140_npcChat = "Una carta del herrero. "
gameforge.subquest_04._150_sayTitle = "Deokbae el le\241ador: "
gameforge.subquest_04._160_say = "Bienvenido. Tengo algunas hachas buenas aqu\237.[ENTER]\191Quieres comprar una? \191No necesitas un hacha?[ENTER]\191Entonces por qu\233 est\225s aqu\237? Ah, una Carta del[ENTER]Herrero. Gracias. Soy un le\241ador, pero tambi\233n[ENTER]vendo hachas y otras herramientas. A veces le[ENTER]encargo algunas herramientas. As\237 es como nos[ENTER]convertimos en buenos amigos. "
gameforge.subquest_04._170_say = "Gracias por entregar la carta. Realmente deber\237a[ENTER]tomarme algo con \233l en el bar de Seo-Pyung. Mis[ENTER]mejores saludos para \233l. "
gameforge.subquest_04._180_say = "\191Una carta del herrero? Ha pasado mucho tiempo.[ENTER]\191D\243nde est\225? \191No la habr\225s perdido por el camino,[ENTER]no? "
gameforge.subquest_04._190_select = "Aqu\237 est\225. "
gameforge.subquest_04._200_select = "Oh, no la tengo. "
gameforge.subquest_04._20_say = "\161Hola aventurero! Me gustar\237a pedirte un favor.[ENTER]Hay un tipo llamado Deokbae. Es un le\241ador y un[ENTER]buen amigo m\237o. Quiz\225 sea una criatura aburrida,[ENTER]pero es uno de los \250ltimos le\241adores[ENTER]trabajadores. "
gameforge.subquest_04._210_say = "\191Cancelar la misi\243n? "
gameforge.subquest_04._220_say = "Est\225 bien. Vuelve pronto. "
gameforge.subquest_04._230_say = "\191La has perdido? Sal de mi vista. "
gameforge.subquest_04._240_say = "Ve con el herrero y c\243gela. No pierdas la carta[ENTER]otra vez. "
gameforge.subquest_04._250_sayReward = "Ve con el herrero y reclama tu recompensa. "
gameforge.subquest_04._260_targetVid = "Vuelve con el Herrero "
gameforge.subquest_04._270_npcChat = "He entregado la carta. "
gameforge.subquest_04._280_say = "As\237 pues, \191c\243mo est\225 Deokbae? Jeje, sigue siendo[ENTER]el mismo. Gracias. Toma esto como recompensa. No[ENTER]es mucho, pero puede que alg\250n d\237a lo necesites.[ENTER]Gracias de nuevo.  "
gameforge.subquest_04._290_sayReward = "Has recibido 4000 puntos de experiencia.[ENTER]Has recibido 3000 Yang. "
gameforge.subquest_04._30_say = "No le he visto desde hace tiempo. Le escrib\237 una[ENTER]carta para preguntarle si est\225 bien. Me gustar\237a[ENTER]que le entregases la carta. Estos d\237as, hay[ENTER]muchos peligros en los caminos. As\237 que ten[ENTER]cuidado. \161Y no pierdas la carta! "
gameforge.subquest_04._40_say = "Oh, \191no sabes c\243mo llegar a la siguiente aldea?[ENTER]Pulsa 'M' para ver el mini mapa. Se mostrar\225 un[ENTER]punto azul. Este punto representa el portal que[ENTER]te llevar\225 al \225rea anexa. La segunda aldea[ENTER]tambi\233n est\225 situada en esta \225rea. "
gameforge.subquest_04._50_select = "Lo hare. "
gameforge.subquest_04._60_select = "No, gracias. "
gameforge.subquest_04._70_say = "\191Quieres abandonar la misi\243n para siempre? "
gameforge.subquest_04._80_say = "Vuelve pronto. "
gameforge.subquest_04._90_say = "Muy mal. Gracias de todos modos. "
