gameforge.subquest_06._100_say = "\161Largo de aqu\237, ya! Merodeador in\250til... "
gameforge.subquest_06._10_targetVid = "Encargando armadura "
gameforge.subquest_06._110_say = "\161Gracias! Vuelve con el Herrero y preg\250ntale por[ENTER]sus progresos con la armadura. "
gameforge.subquest_06._120_sayReward = "Ve con el Herrero y preg\250ntale por sus avances[ENTER]con la armadura que encarg\243 el Vendedor de la[ENTER]Tienda de Armaduras. "
gameforge.subquest_06._130_npcChat = "Armadura para el Vendedor de la Tienda de Armaduras "
gameforge.subquest_06._140_say = "\191Qu\233 pasa ahora? \191Por qu\233 me molestas? Oh, \191el[ENTER]Vendedor de la Tienda de Armaduras te env\237a? Ese[ENTER]anciano es muy impaciente. No es que no quiera[ENTER]hacerlo. Es simplemente que no tengo los[ENTER]materiales necesarios para ello. \191Puedes[ENTER]conseguirlos para m\237? Para fabricar la armadura[ENTER]necesito Mineral de Hierro, Cuero y Carb\243n.[ENTER]Puedes conseguir el Mineral de Hierro de Uriel,[ENTER]el Cuero de Octavio y el Carb\243n de Yonah. "
gameforge.subquest_06._150_select = "Conseguir\233 los materiales para ti. "
gameforge.subquest_06._160_select = "No, a\250n no. "
gameforge.subquest_06._170_say = "\191Est\225s seguro de que quieres dejar de hacer esta[ENTER]misi\243n? "
gameforge.subquest_06._180_say = "La puedes hacer m\225s tarde tambi\233n. Pero no[ENTER]esperes demasiado, \161la misi\243n es urgente! "
gameforge.subquest_06._190_say = "Bien, entonces supongo que tendr\233 que conseguir[ENTER]esas cosas yo mismo. Ten cuidado. "
gameforge.subquest_06._200_say = "Entonces ve otra vez, para que pueda volver a[ENTER]trabajar en paz... "
gameforge.subquest_06._20_npcChat = "Encargando armadura "
gameforge.subquest_06._210_sendLetter = "Consigue materiales "
gameforge.subquest_06._220_sayReward = "Consigue los materiales para el herrero. "
gameforge.subquest_06._221_say = "Mineral de Hierro: lo obtienes de Uriel. "
gameforge.subquest_06._222_say = "Cuero: lo obtienes de Octavio. "
gameforge.subquest_06._223_say = "Carb\243n: lo obtienes de Yonah. "
gameforge.subquest_06._224_sayReward = "Uriel te ha dado Mineral de Hierro. "
gameforge.subquest_06._225_sayReward = "Octavio te ha dado el Cuero. "
gameforge.subquest_06._226_sayReward = "Yonah te ha dado el Carb\243n. "
gameforge.subquest_06._230_targetVid = "Visita a Octavio "
gameforge.subquest_06._240_targetVid = "Ve con Uriel. "
gameforge.subquest_06._250_targetVid = "Ve con Yonah. "
gameforge.subquest_06._260_npcChat = "Ich brauche Eisenerz "
gameforge.subquest_06._270_say = "\161Gracias por devolverme mi libro! Ahora puedo[ENTER]continuar mi investigaci\243n. Toma, coge algo de[ENTER]Mineral de Hierro. \218salo bien. "
gameforge.subquest_06._280_say = "\191Necesitas Mineral de Hierro? Puedo darte algo.[ENTER]Pero tengo un favor que pedirte: recientemente he[ENTER]perdido un libro mientras era perseguido por una[ENTER]jaur\237a de Perros Salvajes. Creo que esos Perros[ENTER]Salvajes deben tener mi libro. Devu\233lvemelo y te[ENTER]dar\233 algo de Mineral de Hierro. "
gameforge.subquest_06._285_say = "Uriel te dar\225 el Mineral de Hierro si le vuelves[ENTER]a traer su libro de los perros salvajes. "
gameforge.subquest_06._290_npcChat = "Ich brauche Eisenerz "
gameforge.subquest_06._300_say = "\191M\225s Mineral de Hierro? Ya te he dado algo. Ya no[ENTER]me queda m\225s. "
gameforge.subquest_06._30_say = "Gracias por ayudar a mi hija. \191Quiz\225 puedas[ENTER]ayudarme a m\237 tambi\233n? Tengo que pedirte un[ENTER]favor. Le ped\237 al herrero que pordujese unas[ENTER]armaduras, pero a\250n no tengo noticias suyas.[ENTER]\191Podr\237as ir y preguntarle por donde va? "
gameforge.subquest_06._310_npcChat = "Necesito cuero. "
gameforge.subquest_06._320_sayTitle = "Octavio: "
gameforge.subquest_06._330_say = "\161Gracias por la Bilis! Ahora al fin puedo volver[ENTER]a cocinar mis sabrosos platos. Mmm...[ENTER]Toma, ll\233vate este Cuero como recompensa. "
gameforge.subquest_06._340_say = "Puedo darte algo de Cuero.[ENTER]Sin embargo, nada en la vida es gratis.[ENTER]\191Qu\233 te parece si hacemos un trueque? Te dar\233 el[ENTER]Cuero si me consigues una Bilis.[ENTER]Suelo cocinar con Bilis.[ENTER]No pasa nada si no te interesa. "
gameforge.subquest_06._345_say = "Octavio te dar\225 Cuero si le llevas una Bilis. "
gameforge.subquest_06._350_npcChat = "Necesito cuero. "
gameforge.subquest_06._360_say = "Ya te he dado cuero. \191Lo has perdido? No tengo[ENTER]m\225s. "
gameforge.subquest_06._370_npcChat = "Necesito carb\243n. "
gameforge.subquest_06._380_say = "Gracias por la Arcilla. T\250 rascas mi espalda y yo[ENTER]rasco la tuya: Aqu\237 est\225 tu Carb\243n. \161Nos vemos[ENTER]pronto! "
gameforge.subquest_06._390_say = "\191Qu\233 pasa? \191Est\225s aqu\237 para conseguir Carb\243n?[ENTER]Tengo mucho Carb\243n. Pero no es gratis. Tienes que[ENTER]hacer algo por m\237 antes. "
gameforge.subquest_06._395_say = "Yonah te dar\225 Carb\243n si le traes Arcilla. Para[ENTER]ello tienes que cazar Jabal\237es rojos. "
gameforge.subquest_06._400_say = "Me estoy quedando sin Arcilla para mi vajilla. Si[ENTER]me traes un poco, te dar\233 algo de Carb\243n. Ser\225[ENTER]mejor si matas algunos Jaba\237es Rojos; ya que lo[ENTER]creas o no, comen Arcilla. \161Gracias por[ENTER]adelantado! "
gameforge.subquest_06._40_select = "S\237, lo har\233. "
gameforge.subquest_06._410_npcChat = "Necesito carb\243n. "
gameforge.subquest_06._420_say = "\191Qu\233? \161Ya te he dado Carb\243n! \191Est\225s intentando[ENTER]enga\241arme? "
gameforge.subquest_06._430_npcChat = "Tengo todos los materiales. "
gameforge.subquest_06._440_say = "Parece que no tienes hierro. Ve con Uriel... "
gameforge.subquest_06._450_say = "Parece que no tienes cuero. Ve con Octavio... "
gameforge.subquest_06._460_say = "No tienes Carb\243n. Hmm, \191sin Carb\243n? Consigue algo[ENTER]de Yonah. "
gameforge.subquest_06._470_makequestbutton = "Tengo todos los materiales "
