gameforge.subquest_06._510_sayReward = "Tengo todos los materiales necesarios. Ve con el[ENTER]Herrero. "
gameforge.subquest_06._520_npcChat = "Tengo tus materiales. "
gameforge.subquest_06._530_say = "\191Ya has conseguido todos los materiales?[ENTER]\161Estoy impresionado! Gracias, ahora puedo[ENTER]entregar los art\237culos encargados al Vendedor de[ENTER]la Tienda de Armaduras. \161Ve y cu\233ntale las buenas[ENTER]noticias! "
gameforge.subquest_06._540_sayReward = "Dile al Vendedor de la Tienda de Armaduras que su[ENTER]pedido estar\225 terminado pronto. "
gameforge.subquest_06._550_targetVid = "Vuelve con el vendedor de la tienda de armaduras. "
gameforge.subquest_06._560_npcChat = "\161El Herrero entregar\225 pronto! "
gameforge.subquest_06._570_say = "Oh, \191as\237 que terminar\225 pronto con la armadura?[ENTER]Gracias por hacerte cargo. Coge esto como[ENTER]recompensa. "
gameforge.subquest_06._580_sayReward = "Has recibido 26.000 puntos de experiencia.[ENTER]Has recibido 15.000 Yang.[ENTER]Has recibido una Nariz de Cerdo. "
