gameforge.subquest_07 = {}
gameforge.subquest_07._100_say = "Espera un segundo, quiero asegurarme de que \233ste[ENTER]es el libro correcto... Hmm, s\237, es realmente[ENTER]fant\225stico. \161Definitivamente voy a cocinar estos[ENTER]platos! \161Gracias! "
gameforge.subquest_07._10_targetVid = "El mejor libro de cocina "
gameforge.subquest_07._110_say = "Hmm, pero necesito... \161Espera amigo! \191Puedo[ENTER]pedirte otro favor? Tengo casi todos los[ENTER]ingredientes para este fant\225stico plato, pero[ENTER]todav\237a me faltan algunos Intestinos de Lobo.[ENTER]Este ingrediente no es f\225cil de conseguir y se[ENTER]come mejor cuando est\225 fresco. \161Por favor,[ENTER]cons\237gueme alguno! "
gameforge.subquest_07._120_sayReward = "Consigue algunos Intestinos de Lobo para Octavio.[ENTER]Los podr\225s conseguir de los Lobos Grises. "
gameforge.subquest_07._130_npcChat = "Tengo un Intestino de Lobo. "
gameforge.subquest_07._140_say = "Gracias a ti, puedo cocinar al fin este plato[ENTER]inusual. \161Esto va a ser un fest\237n! Estoy[ENTER]realmente agradecido por tu ayuda. Por favor,[ENTER]coge esta modesta recompensa. "
gameforge.subquest_07._150_sayReward = "Has recibido 12.000 puntos de experiencia.[ENTER]Has recibido 5.000 Yang.[ENTER]Has recibido una Garra de Lobo. "
gameforge.subquest_07._160_say = "Necesito los intestinos de un lobo gris. Por[ENTER]favor, tr\225eme alguno. "
gameforge.subquest_07._20_npcChat = "El mejor libro de cocina "
gameforge.subquest_07._30_say = "Hmm, \191por casualidad conoces a Soon? Es el rat\243n[ENTER]de biblioteca que gasta todo su tiempo leyendo.[ENTER]He o\237do que Soon tiene un estupendo libro de[ENTER]cocina. Por favor, averigua si es cierto. Me[ENTER]dijeron que el libro de cocina est\225 lleno de[ENTER]raras y ex\243ticas recetas y me gustar\237a[ENTER]aprenderlas. "
gameforge.subquest_07._40_targetVid = "Pregunta a Soon "
gameforge.subquest_07._50_sayReward = "Pregunta a Soon si tiene un libro de cocina[ENTER]ex\243tico. "
gameforge.subquest_07._60_npcChat = "\191Tienes un libro de cocina especial? "
gameforge.subquest_07._70_say = "Bla, bla... \161Oh! \161T\250 otra vez! \191Qu\233 quieres? S\237,[ENTER]tengo un libro de cocina que contiene platos[ENTER]ex\243ticos. Ll\233vatelo si quieres, no lo necesito.[ENTER]Pero, por favor, \161no me molestes cuando estoy[ENTER]leyendo! "
gameforge.subquest_07._80_targetVid = "Soon te ha dado el libro de cocina ex\243tico.[ENTER]Ll\233vaselo a Octavio. "
gameforge.subquest_07._90_npcChat = "\161Aqu\237 est\225 el libro de cocina! "
gameforge.subquest_08 = {}
gameforge.subquest_08._100_sayReward = "Ve con el Vendedor de la Tienda de Armas y[ENTER]preg\250ntale d\243nde puedes comprar Pasteles de[ENTER]Arroz. "
gameforge.subquest_08._10_targetVid = "Pastel de Arroz "
gameforge.subquest_08._110_npcChat = "\191Qu\233 sabes sobre el Pastel de Arroz? "
gameforge.subquest_08._120_sayTitle = "Vendedor de la tienda de armas: "
gameforge.subquest_08._130_say = "Em, \191qu\233? \191Pastel de arroz? \191Por qu\233 lo[ENTER]necesitas? \191Es un tipo de arma que no conozco? No[ENTER]entiendo nada...[ENTER][ENTER]\161Ahhh! Pastel de arroz, \161algo para comer![ENTER]Deber\237as preguntarle a Octavio, \233l sabe todo lo[ENTER]referente a la comida. "
gameforge.subquest_08._140_makequestbutton = "Pastel de Arroz "
gameforge.subquest_08._150_sayReward = "Ve con Octavio y preg\250ntale lo que sabe acerca de[ENTER]los Pasteles de Arroz. "
gameforge.subquest_08._160_say = "Hmm, \191quieres pastel de arroz? \191Ese con cerezas[ENTER]rojas y az\250car? S\237, lo conozco. Lo puedes[ENTER]conseguir del vendedor ambulante de pastel de[ENTER]arroz en la siguiente aldea. "
gameforge.subquest_08._170_select = "No, no tengo tiempo para esto. "
gameforge.subquest_08._180_say = "Te espera un largo camino. Adi\243s. "
gameforge.subquest_08._190_say = "Bien, desde luego t\250 te lo pierdes. \161Nos vemos! "
gameforge.subquest_08._200_say = "Ya ver\225s, vale la pena. \161Que tengas un buen viaje! "
gameforge.subquest_08._20_say = "Perdon, \191podr\237as, por favor, ayudarme? Mi beb\233 no[ENTER]parar\225 de llorar y ya no se qu\233 hacer para[ENTER]calmarle. A mi beb\233 le encanta el pastel de arroz[ENTER]y creo que eso ayudar\237a. Creo que el vendedor de[ENTER]la tienda de armas sabe d\243nde conseguirlo.[ENTER]\191Podr\237as ir a preguntarle? "
gameforge.subquest_08._210_makequestbutton = "Encuentra a Yu-Rang "
gameforge.subquest_08._220_targetVid = "Pastel de Arroz "
gameforge.subquest_08._230_sayReward = "Ve con la vendedora de Pastel de Arroz. La[ENTER]encontrar\225s en la siguiente aldea. "
gameforge.subquest_08._240_sayTitle = "Yu-Rang: "
gameforge.subquest_08._250_say = "\191Puedo ayudarte? \161Oh! \161Pastel de arroz! Por[ENTER]supuesto, \161puedo darte algo! Pero... \191puedes[ENTER]hacer antes algo por mi? Un chico llamado Taurean[ENTER]a veces viene aqu\237 y se burla de m\237, a pesar de[ENTER]que nunca le he hecho nada. Si castigas a Taurean[ENTER]por m\237, te dar\233 algun pastel de arroz, \191de[ENTER]acuerdo?  "
gameforge.subquest_08._260_makequestbutton = "Encuentra a Taurean "
gameforge.subquest_08._270_sayReward = "Taurean siempre le toma el pelo a Yu-Rang.[ENTER]Cast\237gale y entonces ella te dar\225 un Pastel de[ENTER]Arroz. "
gameforge.subquest_08._280_npcChat = "\191Por qu\233 te burlas de Yu-Rang? "
gameforge.subquest_08._290_say = "\191De qui\233n se supone que me burlo? Oh, \191te[ENTER]refieres a la chica que vende pastel de arroz?[ENTER]No, \161no quer\237a burlarme de ella! Estaba aburrido[ENTER]y ella parec\237a simp\225tica y sin mucho que hacer.[ENTER]As\237 que la visit\233 unas cuantas veces y quise[ENTER]jugar con ella, pero entonces se enfad\243...[ENTER]Las chicas son raras. \161Entonces supongo que no la[ENTER]visitar\233 nunca m\225s! "
gameforge.subquest_08._300_makequestbutton = "Volver con Yu-Rang "
gameforge.subquest_08._30_select = "Aceptar "
gameforge.subquest_08._310_targetVid = "Pastel de Arroz "
gameforge.subquest_08._320_sayReward = "Taurean no molestar\225 m\225s a Yu-Rang. Ve con ella y[ENTER]coge tu Pastel de Arroz. "
gameforge.subquest_08._330_say = "\161Ja, ja!, \161Castigaste a Taurean! Gracias. Ahora[ENTER]se lo pensar\225 dos veces antes de volver por aqu\237[ENTER]otra vez.[ENTER]Aqu\237 tienes tu pastel de arroz. \161Disfruta de la[ENTER]comida! "
gameforge.subquest_08._340_makequestbutton = "Vuelve con Ah-Yu "
gameforge.subquest_08._350_targetVid = "Pastel de Arroz para Ah-Yu "
gameforge.subquest_08._360_sayReward = "Has recibido un Pastel de Arroz de Yu-Rang.[ENTER]Ll\233vaselo a Ah-Yu. La encontrar\225s con su ni\241o en[ENTER]la primera aldea. "
gameforge.subquest_08._370_npcChat = "Aqu\237 est\225 el Pastel de Arroz para tu ni\241o. "
gameforge.subquest_08._380_say = "\161Me has traido el pastel de arroz! Muchas[ENTER]gracias. \161Oh! Mira, mi beb\233 ha dejado de llorar[ENTER]ahora y est\225 comiendo felizmente el pastel. Esto[ENTER]es gracias a ti. \161Gracias por tu ayuda! "
gameforge.subquest_08._390_sayReward = "Has recibido 26.000 puntos de experiencia.[ENTER]Has recibido 10.000 Yang. "
gameforge.subquest_08._40_say = "Pero... No puedo dejar este lugar y el beb\233 est\225[ENTER]aterrorizando al vecindario entero... \161No costar\225[ENTER]mucho! \191Est\225s seguro de que no tienes suficiente[ENTER]tiempo? "
gameforge.subquest_08._50_say = "Supongo que est\225s ocupado.[ENTER]Por favor, vuelve m\225s tarde.[ENTER]Shh, no llores beb\233. "
gameforge.subquest_08._60_say = "Supongo que se lo tendr\233 que pedir a otro.[ENTER]\161Buena suerte en tu viaje! "
gameforge.subquest_08._70_say = "\161Muchas gracias! Es un gran alivio para m\237. "
gameforge.subquest_08._80_makequestbutton = "Pastel de Arroz "
gameforge.subquest_08._90_targetVid = "Pastel de Arroz "
gameforge.subquest_09 = {}
gameforge.subquest_09._100_sayReward = "Encuenta al soldado del Juramento Blanco que rob\243[ENTER]el hacha dorada y devu\233lvesela al herrero. "
gameforge.subquest_09._10_targetVid = "Encuentra el Hacha Dorada "
gameforge.subquest_09._110_sendLetter = "Hacha Dorada encontrada "
gameforge.subquest_09._120_npcChat = "Aqu\237 esta el hacha dorada. "
gameforge.subquest_09._130_say = "Muchas gracias. Ya no tengo que preocuparme por[ENTER]lo que le dir\233 a Deokbae la pr\243xima vez que le[ENTER]vea. "
gameforge.subquest_09._140_sayReward = "Has recibido 36.000 puntos de experiencia.[ENTER]Has recibido 10.000 Yang.[ENTER]Has recibido una Ornamentaci\243n. "
gameforge.subquest_09._20_npcChat = "El Hacha Dorada "
gameforge.subquest_09._30_say = "\191Recuerdas a mi amigo Deokbae? Promet\237 hacerle un[ENTER]hacha. Pero ha sido robada por un soldado del[ENTER]Juramento Blanco. \191Puedes traerme de vuelta ese[ENTER]hacha? Una soldado Jura Blanca debe tenerla.[ENTER]Deber\237as ser capaz de reconocerla, ya que no[ENTER]existen muchas como esa.[ENTER]\161Te recompensar\233 por las molestias! "
gameforge.subquest_09._40_say = "\191Quieres abandonar la misi\243n para siempre? "
gameforge.subquest_09._50_sayTitle = "Herrero. "
gameforge.subquest_09._60_say = "De verdad quiero el hacha...[ENTER]\191Volver\225s?[ENTER]Nos vemos. "
gameforge.subquest_09._70_say = "Gracias por tu ayuda. Ten cuidado; el Juramento[ENTER]Blanco es muy peligroso. "
gameforge.subquest_09._80_say = "Gracias por ayudarme. Pero ten cuidado. El[ENTER]Juramento Blanco ha estado causando muchos[ENTER]problemas \250ltimamente. "
gameforge.subquest_09._90_makequestbutton = "Encuentra el Hacha Dorada "
gameforge.subquest_10 = {}
gameforge.subquest_10._100_sayReward = "Preg\250ntale al herrero d\243nde est\225 la horquilla. "
gameforge.subquest_10._10_targetVid = "Encuentra la Horquilla "
gameforge.subquest_10._110_npcChat = "La horquilla robada. "
gameforge.subquest_10._120_say = "\191Qu\233? \191Ella piensa que rob\233 su horquilla? Eso...[ENTER]\161eso es incre\237ble! \191Qu\233 piensa de mi?[ENTER]\161Estaba trabajando en mi tienda![ENTER]Hm, quiz\225 no deber\237a decirte esto, pero el[ENTER]vendedor de la tienda de armas estaba acechando[ENTER]las proximidades del almac\233n general hace un[ENTER]rato! "
gameforge.subquest_10._130_makequestbutton = "La horquilla robada. "
gameforge.subquest_10._140_sayReward = "Preg\250ntale al vendedor de la tienda de armas[ENTER]sobre el paradero de la horquilla. "
gameforge.subquest_10._150_say = "\191Qu\233? \191Crees que rob\233 la horquilla? No, nunca,[ENTER]\161no lo hice! De verdad, \161no soy culpable![ENTER][ENTER]Bien... Fui all\237 a visitar a la mujer del almac\233n[ENTER]general, \161pero no estaba ah\237! En lugar de ella,[ENTER]hab\237a una arquera del Juramento Blanco. En el[ENTER]instante en el que me vi\243, huy\243. Quiz\225 ella rob\243[ENTER]la horquilla. "
gameforge.subquest_10._160_sayReward = "\161Consigue la horquilla de la arquera del[ENTER]Juramento Blanco! "
gameforge.subquest_10._170_sendLetter = "Has encontrado la Horquilla "
gameforge.subquest_10._180_targetVid = "Ve con la vendedora del almac\233n general. "
gameforge.subquest_10._190_npcChat = "Tengo aqu\237 tu Horquilla. "
gameforge.subquest_10._200_say = "Oh, muchas gracias. Estoy muy feliz; \161finalmente[ENTER]he recuperado mi horquilla! \161Me has ayudado[ENTER]much\237simo![ENTER]\191C\243mo podr\237a demostrar mi agradecimiento? Tengo[ENTER]un Tique de monta. No es nada especial, pero no[ENTER]lo necesito, pues ya no puedo dejar la tienda as\237[ENTER]como as\237. \161T\243malo como muestra de mi gratitud! "
gameforge.subquest_10._20_say = "\161Por favor, esc\250chame! Tengo un gran problema.[ENTER]Dej\233 la tienda un momento para atender algo[ENTER]importante. Mientras estaba fuera, alguien rob\243[ENTER]mi horquilla favorita. "
gameforge.subquest_10._210_sayReward = "Has recibido 60.000 puntos de experiencia.[ENTER]Has recibido 10.000 Yang.[ENTER]Has recibido un Tique de monta. "
gameforge.subquest_10._220_say = "\191Aun no has encontrado mi horquilla? Espero que[ENTER]finalmente la encuentres. "
gameforge.subquest_10._230_select = "Abandonar "
gameforge.subquest_10._240_say = "\191Realmente quieres abandonar? "
gameforge.subquest_10._250_say = "S\237, definitivamente no son inocentes... \191Quiz\225[ENTER]deber\237as descansar y probar de nuevo m\225s tarde? "
gameforge.subquest_10._260_say = "\191D\243nde est\225 mi horquilla favorita? Ya veo...[ENTER]adi\243s. "
gameforge.subquest_10._270_say = "Muchas gracias. Realmente significa mucho para mi. "
gameforge.subquest_10._30_say = "Mi padre me dio esta maravillosa horquilla por mi[ENTER]cumplea\241os. \161Por eso es tan importante para m\237![ENTER]\161No puedo volver a dejar mi tienda! En caso[ENTER]contrario, otras cosas importantes pueden ser[ENTER]robadas. \191Podr\237as buscarla por m\237? Sospecho que[ENTER]el herrero lo ha hecho, porque una vez dijo que[ENTER]le gustaba. "
gameforge.subquest_10._40_select = "La buscar\233. "
gameforge.subquest_10._50_say = "\191Abandonar realmente la misi\243n? "
gameforge.subquest_10._60_say = "Nos veremos la pr\243xima vez. \161Divi\233rtete! "
gameforge.subquest_10._70_say = "\191D\243nde est\225 mi horquilla? Adi\243s... "
gameforge.subquest_10._80_say = "\191La buscar\225s? Oh, \161gracias! "
gameforge.subquest_10._90_targetVid = "Ve con el Herrero "
gameforge.subquest_11 = {}
gameforge.subquest_11._100_targetVid = "Pregunta a Yu-Hwan sobre el hermano de Mirine. "
gameforge.subquest_11._10_targetVid = " Encuentra a mi hermano "
gameforge.subquest_11._110_npcChat = "\191Has visto al hermano mayor de Mirine? "
gameforge.subquest_11._120_say = "Me enamor\233 sin saber lo que significa el amor...[ENTER]\191A qui\233n est\225s buscando? \191El hermano de Mirine?[ENTER]Hablamos un poco antes de que se fuera a las[ENTER]monta\241as. Quer\237a buscar hierbas raras. No se[ENTER]donde est\225 ahora. El cazador va a menudo a las[ENTER]monta\241as. Le encontrar\225s en esta aldea. \191Por qu\233[ENTER]no le preguntas?[ENTER][ENTER]La, la, la, el amor es triste pero hermoso... "
gameforge.subquest_11._130_targetVid = "Pregunta a Yang-Shin sobre el hermano de Mirine. "
gameforge.subquest_11._140_say = "\191Qui\233n? \191El hermano de Mirine dices? Estaba[ENTER]buscando hierbas en las monta\241as. Estaba tan[ENTER]feliz cuando encontr\243 algunas hierbas raras.[ENTER]Quer\237a comprar algunos vestidos nuevos para su[ENTER]hermana con los beneficios que hizo con ellas.[ENTER]Verdaderamente es un buen chico. Estoy seguro que[ENTER]volver\225 en un par de d\237as. \191No crees? "
gameforge.subquest_11._150_targetVid = "Cu\233ntale la noticias a Mirine. "
gameforge.subquest_11._160_npcChat = "Noticias sobre el hermano de Mirine. "
gameforge.subquest_11._170_say = "Mira, \161he recibido una carta de mi hermano! Ha[ENTER]escrito que encontr\243 un lugar con muchas hierbas[ENTER]y que tardar\225 un tiempo antes de que vuelva a[ENTER]casa. Lo siento, no deber\237a haberte molestado con[ENTER]esto. Toma, no es mucho, pero espero que lo[ENTER]aceptes y me perdones. Gracias por hacer un viaje[ENTER]tan largo. "
gameforge.subquest_11._180_sayReward = "Has recibido 122.000 puntos de experiencia.[ENTER]Has recibido 5.000 Yang. "
gameforge.subquest_11._20_npcChat = " Encuentra a mi hermano "
gameforge.subquest_11._30_say = "\191Puedo pedirte un favor? Mi hermano ha estado[ENTER]fuera durante mucho tiempo. No he tenido ninguna[ENTER]noticia suya. Estoy un poco preocupada. \191Puedes[ENTER]buscarle, por favor? "
gameforge.subquest_11._40_say = "Mi hermano quer\237a visitar a Yu-Hwan el m\250sico en[ENTER]la otra aldea. \191Puedes ir con Yu-Hwan y[ENTER]preguntarle por mi hermano? \191Puedes buscarle si[ENTER]tienes tiempo? "
gameforge.subquest_11._50_select = "S\237, lo har\233. "
gameforge.subquest_11._60_say = "\191Vas a abandonar esta misi\243n para siempre? "
gameforge.subquest_11._70_say = "Gracias. Por favor, b\250scale; estoy muy[ENTER]preocupada. Nos vemos. "
gameforge.subquest_11._80_say = "Muy mal que no me ayudes.[ENTER]Nos vemos. "
gameforge.subquest_11._90_say = "\191Vas a buscarle? \161Muchas gracias![ENTER]Estoy muy preocupada. \161Buena suerte! "
gameforge.subquest_12 = {}
gameforge.subquest_12._100_qSetTitle = "Mi-Jung del Juramento Blanco "
gameforge.subquest_12._10_targetVid = "Mata a Mi-Jung del Juramento Blanco "
gameforge.subquest_12._110_sayReward = "Vuelve con el guardi\225n de la plaza de la aldea. "
gameforge.subquest_12._120_sayTitle = "Mi-Jung del Juramento Blanco "
gameforge.subquest_12._130_sayReward = "Ve y mata a Mi-Jung del Juramento Blanco. Una vez[ENTER]lo hayas hecho, vuelve con el guardi\225n. "
gameforge.subquest_12._140_targetVid = "Ve con el guardi\225n. "
gameforge.subquest_12._150_sayTitle = "Has matado a Mi-Jung del Juramento Blanco "
gameforge.subquest_12._160_sayReward = "Vuelve con el guardi\225n para recibir tu recompensa. "
gameforge.subquest_12._170_npcChat = "He matado a Mi-Jung. "
gameforge.subquest_12._180_say = "\161Oh! Realmente eres tan bueno como hab\237a[ENTER]escuchado. Eres sorprendente. Gracias. Ocuparnos[ENTER]del problema que supone el Juramento Blanco, se[ENTER]ha vuelto m\225s f\225cil gracias a ti. \161Bien hecho! "
gameforge.subquest_12._190_sayReward = "Has recibido 120.000 puntos de experiencia.[ENTER]Has recibido 20.000 Yang.[ENTER]Has recibido un Brazalete de Plata. "
gameforge.subquest_12._20_say = "Ven aqu\237 un segundo. Eres un buen luchador. He[ENTER]o\237do muchas cosas de ti del Capit\225n. "
gameforge.subquest_12._30_say = "\191Puedes ir tras Mi-Jung del Juramento Blanco? Es[ENTER]dif\237cil proteger la aldea y sus habitantes de los[ENTER]ataques del Juramento Blanco. Si matamos a[ENTER]Mi-Jung, uno de sus l\237deres, cambiar\225 la[ENTER]situaci\243n. La seguridad de la aldea est\225 en tus[ENTER]manos. \161Conf\237o en que no fallar\225s! "
gameforge.subquest_12._40_select = "S\237, lo voy a hacer. "
gameforge.subquest_12._50_select = "No puedo hacerlo. "
gameforge.subquest_12._60_say = "\191Realmente no quieres ayudarnos? "
gameforge.subquest_12._70_say = "Supongo que simplemente no es el momento[ENTER]adecuado. Vuelve m\225s tarde. "
gameforge.subquest_12._80_say = "Si no quieres ayudar, no hay nada que pueda[ENTER]hacerle. Vete... "
gameforge.subquest_12._90_say = "\191Realmente no quieres ayudar? "
gameforge.subquest_13 = {}
gameforge.subquest_13._100_targetVid = "Ve con Ariyoung "
gameforge.subquest_13._10_targetVid = "Materiales para hacer armas. "
gameforge.subquest_13._110_targetVid = "Ve con Ah-Yu. "
gameforge.subquest_13._120_sayReward = "El Vendedor de la Tienda de Armas necesita tu[ENTER]ayuda. Consigue Mineral de Hierro de Uriel y Lino[ENTER]de Ariyoung para \233l. "
gameforge.subquest_13._130_npcChat = "Ich brauche Eisenerz "
gameforge.subquest_13._140_say = "\191Necesitas hierro? Puedo darte algo si me haces[ENTER]un favor. "
gameforge.subquest_13._150_say = "Se me cay\243 algo cuando tuve que correr por mi[ENTER]vida huyendo de los tigres: es un paquete que[ENTER]contiene libros importantes, sujetos con algunas[ENTER]ropas. Si no los tengo, no puedo continuar mi[ENTER]investigaci\243n sobre las Piedras Metin. Tr\225eme el[ENTER]Paquete y te dar\233 algo de mineral. "
gameforge.subquest_13._160_npcChat = "Tengo tu paquete. "
gameforge.subquest_13._170_say = "\161Gracias! Realmente te pido favores demasiado a[ENTER]menudo. Toma, aqu\237 tienes algo de hierro. Espero[ENTER]que te ayude. "
gameforge.subquest_13._180_say = "\191Qu\233? \191Aun necesitas m\225s hierro? \161No crece en los[ENTER]\225rboles, sabes! Te dar\233 algo de hierro, pero[ENTER]tienes que hacerme un favor. Los tigres han[ENTER]robado mi Paquete. Tuve que correr por mi vida y[ENTER]hab\237a documentos muy importantes ah\237. Si no los[ENTER]tengo, no puedo continuar mi investigaci\243n de las[ENTER]Piedras Metin. Por favor encuentra el Paquete que[ENTER]robaron los tigres. "
gameforge.subquest_13._190_say = "Ya te la he dado. \191Lo has olvidado? "
gameforge.subquest_13._200_sayTitle = "Paquete encontrado "
gameforge.subquest_13._20_npcChat = "Material para armas "
gameforge.subquest_13._210_say = "Has encontrado la bolsa de Uriel. Devu\233lvesela. "
gameforge.subquest_13._220_npcChat = "Necesito lino. "
gameforge.subquest_13._230_say = "\191Necesitas Lino? Se lo he dado a Ah-Yu.[ENTER]\161Espera![ENTER]Si vas a ir a verla de todos modos, puedes[ENTER]llevarle esta carta. Somos buenas amigas, pero a[ENTER]causa de su hijo no nos hemos visto en un tiempo.[ENTER]Tambi\233n le dir\233 que debe darte algo de Lino...[ENTER]Bien, \161esto ayuda a todo el mundo![ENTER]Y dale saludos de mi parte. "
gameforge.subquest_13._240_say = "Ariyoung:[ENTER]Seguro, conseguiste el lino de Ah-Yu, \191no? "
gameforge.subquest_13._250_npcChat = "La carta de Ariyoung. "
gameforge.subquest_13._260_say = "\191Una carta de Ariyoung? Que bien saber algo de[ENTER]ella despu\233s de todo este tiempo. Sol\237amos quedar[ENTER]para charlar bastante a menudo. Pero \250ltimamente,[ENTER]ha sido un tanto dif\237cil. Por favor, espera un[ENTER]momento. \191Aqu\237 dice que necesitas algo de Lino?[ENTER]Ariyoung me di\243 un poco. Puedo darte algo.[ENTER]Gracias por traerme su carta. Le responder\233 ahora[ENTER]mismo... "
gameforge.subquest_13._270_qSetTitle = "Vamos con el Vendedor de la Tienda de Armas "
gameforge.subquest_13._280_targetVid = "Ve con el vendedor de la tienda de armas. "
gameforge.subquest_13._290_sayTitle = "Dar materiales "
gameforge.subquest_13._300_sayReward = "Tengo todos los materiales.[ENTER]Ve con el vendedor de la tienda de armas. "
gameforge.subquest_13._30_say = "\161Eh, t\250! \191Puedes hacerme un favor? Estoy[ENTER]intentando hacer nuevos tipos de armas. No es[ENTER]f\225cil encontrar los materiales necesarios. Tengo[ENTER]mucho trabajo y no los puedo buscar yo mismo.[ENTER]\191Puedes conseguirlos por m\237? "
gameforge.subquest_13._310_say = "Bien hecho. Eres realmente bueno y r\225pido.[ENTER]\161Deja que trabaje ahora en esas armas![ENTER]*clank, clank*[ENTER]Aqu\237 estan los nuevos tipos de armas. Lo he hecho[ENTER]lo mejor que he podido.[ENTER]Espero que te guste la nueva arma. \161Que la[ENTER]disfrutes! "
gameforge.subquest_13._320_sayTitle = "Recompensa: "
gameforge.subquest_13._330_sayReward = "Has recibido 122.000 puntos de experiencia.[ENTER]Has recibido 20.000 Yang. "
gameforge.subquest_13._340_sayReward = "Has recibido una Espada Ancha +3. "
gameforge.subquest_13._350_sayReward = "Has recibido una Daga Tijera +3. "
gameforge.subquest_13._360_sayReward = "Has recibido un Fan Pavo Real +3. "
gameforge.subquest_13._40_say = "Por supuesto, te recompensar\233. Tan pronto como[ENTER]las armas est\233n terminadas, te dar\233 una de ellas.[ENTER]Necesito los siguientes materiales: hierro y[ENTER]lino. Puedes conseguir el hierro de Uriel y el[ENTER]lino de Ariyoung. Hazmelo saber cuando tengas[ENTER]todo. "
gameforge.subquest_13._50_say = "\191Realmente no quieres hacerlo? "
gameforge.subquest_13._60_say = "Supongo que era demasiado para ti.[ENTER]\161Vuelve cuando tengas m\225s tiempo! "
gameforge.subquest_13._70_say = "Si no quieres hacerlo, no hay nada que hacer.[ENTER]Nos vemos. "
gameforge.subquest_13._80_say = "\161Muy bien![ENTER]Tan pronto como est\233n terminadas las armas, te[ENTER]dar\233 una. Buena suerte. "
gameforge.subquest_13._90_sendLetter = "Busca materiales "
gameforge.subquest_15 = {}
gameforge.subquest_15._100_targetVid = "Vuelve con el Guardi\225n de la Ciudad "
gameforge.subquest_15._10_targetVid = "Eun-Jung del Juramento Blanco "
gameforge.subquest_15._110_sayReward = "Has matado a Eun-Jung del Juramento Blanco.[ENTER]Vuelve con el Guardi\225n de la Ciudad e inf\243rmale. "
gameforge.subquest_15._120_say = "\161Eres fant\225stico! Eres incluso mejor de lo que[ENTER]esperaba. No fuimos capaces de hacer nada con[ENTER]esas dos l\237deres del Juramento Blanco, y t\250 las[ENTER]has derrotado a ambas as\237 como as\237. "
gameforge.subquest_15._130_say = "Esto es incre\237ble. Recibir\225s una recompensa[ENTER]adecuada. Por favor, \161coge esto y continua[ENTER]trabajando por la paz de la aldea! "
gameforge.subquest_15._140_sayReward = "Has recibido 150.000 puntos de experiencia.[ENTER]Has recibido 25.000 Yang.[ENTER]Has recibido un Collar de Oro +4. "
gameforge.subquest_15._20_say = "Ven aqu\237 un momento.[ENTER]He oido mucho sobre ti del Capit\225n.[ENTER]Pareces ser valiente. Por eso necesito tu ayuda[ENTER]otra vez: El Juramento Blanco se ha estado[ENTER]comportando peor que nunca. "
gameforge.subquest_15._30_say = "Has derrotado a Mi-Jung, l\237der del Juramento[ENTER]Blanco. \161Pero todav\237a estamos en peligro! \161La[ENTER]amenaza del Juramento Blanco no ha disminuido[ENTER]sino que es peor que nunca! "
gameforge.subquest_15._40_say = "Para acabar con esto, tenemos que eliminar al[ENTER]Capit\225n Eun-Jung. El resto no deber\237an ser[ENTER]problema. \161Ve y mata a Eun-Jung! \161Nuestro destino[ENTER]est\225 en tus manos! "
gameforge.subquest_15._50_sayTitle = "Guardi\225n: "
gameforge.subquest_15._60_say = "\191Vas a volver m\225s tarde? Eres la persona ideal[ENTER]para esto. "
gameforge.subquest_15._70_say = "\191No puedes hacerlo? Me siento decepcionado de[ENTER]oirlo. "
gameforge.subquest_15._80_say = "\161Sab\237a que nos ayudar\237as! Mata a Eun-Jung y[ENTER]nosotros nos ocuparemos del resto. \161Buena suerte! "
gameforge.subquest_15._90_sayReward = "Mata a la l\237der Eun-Jung. Con suerte el Juramento[ENTER]Blanco estar\225 calmado entonces. "
gameforge.subquest_16 = {}
gameforge.subquest_16._100_qSetTitle = "Pregunta a Yu-Hwan "
gameforge.subquest_16._10_targetVid = "Buscando a la caballer\237a armada. "
gameforge.subquest_16._110_targetVid = "Ve con Yu-Hwan "
gameforge.subquest_16._120_say = "La vida es tan maravillosa - el amor es tan[ENTER]maravilloso...[ENTER]Oh, \161otra vez t\250! \191Qu\233 quieres ahora?[ENTER]\191Informaci\243n sobre la caballer\237a armada? \191Por qu\233[ENTER]me preguntas sobre ellos?[ENTER]\191El Capit\225n debe tener grandes planes? "
gameforge.subquest_16._130_sayTitle = "Yu-Hwan: "
gameforge.subquest_16._140_say = "Apenas han sobrevivido algunos textos originales[ENTER]de ese tiempo, pero conozco algunas canciones[ENTER]sobre la caballer\237a armada. Un minuto, afinar\233 mi[ENTER]instrumento...[ENTER]Oh, \191tienes prisa? Estos d\237as ya nadie se toma[ENTER]tiempo para escuchar...[ENTER]Oh bien. En t\233rminos generales, la caballer\237a de[ENTER]Isup era casi invencible. Soldados extremadamente[ENTER]bien entrenados, armadura pesada y a la vez[ENTER]r\225pida y con movilidad. "
gameforge.subquest_16._150_say = "Fue la mejor armada que este continente ha visto[ENTER]nunca. Muchos pa\237ses fracasaron porque nada pudo[ENTER]parar a la caballer\237a. Ser\237a parecido en la[ENTER]actualidad. Pero necesitas arduos m\233todos de[ENTER]entrenamiento y una gran cantidad de hierro para[ENTER]formar semejante armada.[ENTER]Deber\237as preguntar a Peddler y a Uriel el erudito[ENTER]sobre eso. Ellos probablemente sepan m\225s[ENTER]detalles. "
gameforge.subquest_16._160_makequestbutton = "Ve con Peddler "
gameforge.subquest_16._170_qSetTitle = "La caballer\237a armada. "
gameforge.subquest_16._180_targetVid = "Peddler: "
gameforge.subquest_16._190_sayReward = "Yu-Hwan el m\250sico dice que Peddler y Uriel el[ENTER]erudito pueden tener informaci\243n sobre la[ENTER]caballer\237a armada. Primero ve con Peddler. "
gameforge.subquest_16._200_sayTitle = "Peddler: "
gameforge.subquest_16._20_npcChat = "La caballer\237a armada. "
gameforge.subquest_16._210_say = "\191Qu\233 quieres de un simple Vendedor Ambulante como[ENTER]yo? \191La armadura de hierro de la caballer\237a[ENTER]armada? Eso son historias viejas. \191Qui\233n est\225[ENTER]interesado en ellas? \161Tengo que ganarme la vida y[ENTER]no puedo quedarme quieto charlando todo el d\237a! "
gameforge.subquest_16._220_say = "Es cada vez m\225s y m\225s dif\237cil llegar a fin de[ENTER]mes. Desde que esas piedras han estado cayendo[ENTER]del cielo yo... \191Qu\233 dices?[ENTER]Oh s\237, la caballer\237a.[ENTER]Hasta donde yo se, llevaban armaduras especiales[ENTER]y producirlas requer\237a conocimientos especiales.[ENTER]\161Eran las mejores armaduras nunca hechas! \161Los[ENTER]cuchillos corrientes e incluso las flechas no[ENTER]pod\237an penetrar estas armaduras perfectas! "
gameforge.subquest_16._230_say = "Puedes imaginar lo importante que eran las[ENTER]armaduras por el dinero que era necesario para[ENTER]formar la caballer\237a. \161Se dice que gastaron los[ENTER]erarios de reinos enterios! \161Si vendiera[ENTER]armaduras as\237 estar\237a cubierto de por vida! "
gameforge.subquest_16._240_say = "Actualmente, las armaduras pueden estar hechas[ENTER]incluso de piedras Metin. Con este nuevo tipo de[ENTER]armadura, ya no es s\243lo un sue\241o tener una[ENTER]caballer\237a armada como aquella de nuevo. Pero[ENTER]estoy hablando demasiado. Tengo que seguir. \161Nos[ENTER]vemos! "
gameforge.subquest_16._250_sayTitle = "La caballer\237a armada. "
gameforge.subquest_16._260_say = "Peddler sab\237a algo sobre las armaduras de hierro[ENTER]de la caballer\237a armada. Ahora ve a la siguiente[ENTER]aldea y habla con Uriel el erudito sobre el[ENTER]entrenamiento. "
gameforge.subquest_16._270_sayTitle = "Uriel: "
gameforge.subquest_16._280_say = "\191Qu\233 te trae por aqu\237? \191La caballer\237a armada? Por[ENTER]supuesto que se algo sobre ellos. Todo el mundo[ENTER]sabe algo. \161Esta armada pasar\225 a la historia como[ENTER]una de las mejores de todos los tiempos! Mucho de[ENTER]lo que se ha dicho puede ser exagerado pero esos[ENTER]soldados montados fueron muy temidos. Y[ENTER]merecidamente. "
gameforge.subquest_16._290_say = "La caballer\237a armada era superior a cualquier[ENTER]otra, principalmente por su intenso[ENTER]entrenamiento. S\243lo los mejores pudieron[ENTER]finalizar el entrenamiento, muchos murieron. Creo[ENTER]que si se siguiera el mismo entrenamiento estos[ENTER]d\237as, no quedar\237a ni un s\243lo soldado al final. "
gameforge.subquest_16._300_say = "Te dar\233 alguna informaci\243n detallada sobre el[ENTER]entrenamiento, para que no est\233s completamente[ENTER]desinformado. S\233 que se est\225n sucediendo guerras[ENTER]terribles en este momento, pero no estoy seguro[ENTER]de si es una buena idea establecer de nuevo una[ENTER]temible armada como la caballer\237a armada. "
gameforge.subquest_16._30_say = "Tengo una nueva tarea para ti. Tienes orden de[ENTER]encontrar informaci\243n sobre la caballer\237a armada.[ENTER]Fue la parte m\225s importante de la armada de Isup,[ENTER]el rey que unific\243 el continente. La caballer\237a[ENTER]armada era temida por otras naciones por su[ENTER]remarcable velocidad y poder de ataque. "
gameforge.subquest_16._310_say = "Ve con el Capit\225n y dile todo lo que has[ENTER]aprendido sobre la caballer\237a armada. "
gameforge.subquest_16._320_makequestbutton = "Ve con el Capit\225n. "
gameforge.subquest_16._330_npcChat = "Informe sobre la caballer\237a armada. "
gameforge.subquest_16._340_sayTitle = "Capit\225n "
gameforge.subquest_16._350_say = "\191Has podido averiguar algo? \161Habla! ...[ENTER]Hmm, eso es muy interesante. \191As\237 que no es m\225s[ENTER]que armadura pesada y duro entrenamiento?[ENTER]\161Entonces ser\237a posible! \161Una armada as\237 podr\237a[ENTER]reunificar los tres reinos! "
gameforge.subquest_16._360_say = "Pero necesitar\237a mucho dinero. Y un mont\243n de[ENTER]herreros buenos. \161Y reclutas que fueran[ENTER]voluntariamente a trav\233s del infierno para[ENTER]convertirse en lo mejor de lo mejor![ENTER]\161No, no! No me mires as\237. No te preocupes, por[ENTER]ahora ya has hecho suficiente. "
gameforge.subquest_16._370_say = "Toma tu recompensa y descansa.[ENTER]\161Te ver\233 m\225s tarde! "
gameforge.subquest_16._380_sayReward = "Has recibido 150.000 puntos de experiencia.[ENTER]Has recibido 30.000 Yang.[ENTER]Has recibido pendientes de oro. "
gameforge.subquest_16._40_say = "Con la informaci\243n que has recojas quiz\225 podamos[ENTER]fortalecer nuestro poder militar. Visita al[ENTER]m\250sico Yu-Hwan primero. Estoy seguro de que sabe[ENTER]bastante sobre la caballer\237a de Isup. "
gameforge.subquest_16._50_say = "Hm... como lo desees. Te veo m\225s tarde entonces. "
gameforge.subquest_16._60_say = "\191Dirigir\233 alg\250n d\237a un regimiento de caballer\237a[ENTER]como ese?[ENTER]Ten cuidado. "
gameforge.subquest_16._70_say = "Gracias. Ten cuidado. "
gameforge.subquest_16._80_sayTitle = "La caballer\237a armada. "
gameforge.subquest_16._90_sayReward = "El Capit\225n est\225 buscando informaci\243n sobre la[ENTER]caballer\237a legendaria del Rey Isup. Yu-Hwan el[ENTER]m\250sico probablemente tenga algo de informaci\243n.[ENTER]Ve y preg\250ntale. "
gameforge.subquest_17 = {}
gameforge.subquest_17._100_targetVid = "Habla con el vendedor del almac\233n general. "
gameforge.subquest_17._10_targetVid = "La historia del marido de Ariyoung "
gameforge.subquest_17._110_say = "Ve con el vendedor del almac\233n general y[ENTER]preg\250ntale sobre el marido de Ariyoung. "
gameforge.subquest_17._120_npcChat = "El marido de Ariyoung "
gameforge.subquest_17._130_say = "Esta es una historia muy triste. \191Ella no sabe[ENTER]todav\237a lo que le sucedi\243 con su marido? \201l est\225[ENTER]en un lugar del que nadie vuelve...[ENTER]Un d\237a, cuando volv\237a a la aldea, fue atacado por[ENTER]el Clan del Viento Negro, secuestrado y[ENTER]asesinado. "
gameforge.subquest_17._140_say = "Estar\225 asolada cuando se lo digas. Se amaban[ENTER]tanto el uno al otro. Pero tiene que saberlo. De[ENTER]otro modo, la incertidumbre la matar\225. "
gameforge.subquest_17._150_targetVid = "Malas noticias "
gameforge.subquest_17._160_sayTitle = "Ariyoung: "
gameforge.subquest_17._170_say = "La vendedora de la tienda general tiene malas[ENTER]noticias. Ve con Ariyoung y h\225blale sobre la[ENTER]muerte de su marido. "
gameforge.subquest_17._180_npcChat = "Tu marido ha muerto... "
gameforge.subquest_17._190_say = "Qu\233... \161\191qu\233 estas diciendo?! \201l... \191ha sido[ENTER]asesinado por el Clan del Viento Negro? Oh...[ENTER]no... est\225 muerto... No s\233 qu\233 hacer sin \233l[ENTER]*llanto* "
gameforge.subquest_17._200_say = "\191Podr\237as por favor traerme el cuerpo de mi[ENTER]marido? Por favor, as\237 al menos podr\233 decirle[ENTER]adi\243s. Si no es posible traer su cuerpo,[ENTER]cualquier cosa suya servir\225 como recuerdo.[ENTER]Cualquier cosa que puedas encontrar, mientras que[ENTER]fuera suyo. El Goo-Pae del Clan del Viento Negro[ENTER]seguro que tiene algo. Por favor, b\250scalo. "
gameforge.subquest_17._20_say = "Ha pasado mucho tiempo desde la \250ltima vez que[ENTER]escuch\233 algo sobre mi marido. Estoy preocupada;[ENTER]espero que no le haya pasado nada.[ENTER][ENTER]No creo que sea \250til estar preocupada, pero mi[ENTER]coraz\243n est\225 latiendo tan fuerte. No puedo[ENTER]tranquilizarme. "
gameforge.subquest_17._210_select = "S\237, te ayudar\233. "
gameforge.subquest_17._220_say = "Vuelve si cambias de opini\243n. Por favor... "
gameforge.subquest_17._230_say = "\191No encontraste nada? Bueno, gracias de todas[ENTER]formas... Oh, \161pobre de m\237! "
gameforge.subquest_17._240_say = "No puedo expresar cuan agradecida estoy. Ruego[ENTER]por tu seguridad. "
gameforge.subquest_17._250_sendLetter = "Mata Goo-Paes "
gameforge.subquest_17._260_say = "La Banda del Viento Negro ha robado y asesinado[ENTER]al marido de Ariyoung. Mata Goo-Paes hasta que[ENTER]encuentres un recuerdo del marido de Ariyoung. "
gameforge.subquest_17._270_npcChat = "Sobre tu marido... "
gameforge.subquest_17._280_say = "\191C\243mo fue? \191Encontraste el recuerdo de mi marido?[ENTER]\201l lo era todo para m\237. \191Nada en absoluto? "
gameforge.subquest_17._290_select = "Todav\237a no. \161Seguir\233 buscando! "
gameforge.subquest_17._300_say = "Goo-Pae del Clan del Viento Negro no es un[ENTER]enemigo f\225cil. Ve a descansar algo. Gracias por[ENTER]tu ayuda. "
gameforge.subquest_17._30_say = "Quiz\225 la vendedora del almac\233n general haya oido[ENTER]algo sobre mi marido. Tiene muchos clientes;[ENTER]quiz\225 alguien le haya dicho algo. "
gameforge.subquest_17._310_say = "Entonces tendr\233 que esperar por otro h\233roe que me[ENTER]ayude.[ENTER]Adi\243s. "
gameforge.subquest_17._320_say = "Oh, \161eres tan amable! Por favor, tr\225eme algo[ENTER]perteneciente a mi marido. "
gameforge.subquest_17._330_sendLetter = "El Anillo de Boda de Ariyoung "
gameforge.subquest_17._340_targetVid = "Ve con Ariyoung "
gameforge.subquest_17._350_sayTitle = "Ve con Ariyoung "
gameforge.subquest_17._360_say = "Has encontrado el Anillo de Boda del marido de[ENTER]Ariyoung en uno de los Goo-Paes muertos. No[ENTER]puedes imaginar un recuerdo mejor.[ENTER]Lleva el Anillo a Ariyoung. "
gameforge.subquest_17._370_npcChat = "He encontrado este Anillo. "
gameforge.subquest_17._380_say = "\201se... anillo... \161es mi anillo de boda! Ahora mi[ENTER]marido puede descansar en paz. Enterrar\233 este[ENTER]anillo junto con una carta m\237a. Desde ahora,[ENTER]vivir\233 por mi cuenta. Al menos, tengo de vuelta[ENTER]el anillo de boda. \201sta es una sensaci\243n[ENTER]agradable. No puedo agradecertelo lo suficiente. "
gameforge.subquest_17._390_sendLetter = "\161Misi\243n finalizada! "
gameforge.subquest_17._400_say = "Las noticias de tu ayuda a Ariyoung se est\225n[ENTER]propagando. Mucha gente aclama tu ayuda. "
gameforge.subquest_17._40_select = "Voy a visitar el almac\233n general. "
gameforge.subquest_17._410_sayReward = "Has recibido 300.000 puntos de experiencia. "
gameforge.subquest_17._420_sayReward = "Has recibido 10.000 Yang. "
gameforge.subquest_17._50_select = "No, no tengo tiempo para esto. "
gameforge.subquest_17._60_say = "\191Vas a abandonar esta misi\243n para siempre? "
gameforge.subquest_17._70_say = "Vuelve si cambias de opini\243n. Por favor... "
gameforge.subquest_17._80_say = "\191No tienes tiempo?[ENTER]\191No tienes tiempo para una tarea tan f\225cil?[ENTER]Bien, entonces... "
gameforge.subquest_17._90_say = "Gracias por tu amabilidad. Aaaah, d\243nde est\225 mi[ENTER]marido... "
gameforge.subquest_18 = {}
gameforge.subquest_18._100_say = "Busca a un hombre que est\225 leyendo poemas y viste[ENTER]con harapos y habla con \233l. "
gameforge.subquest_18._10_targetVid = "\191D\243nde se esconde? "
gameforge.subquest_18._110_npcChat = "\191D\243nde est\225 tu marido? "
gameforge.subquest_18._120_say = "No s\233 d\243nde puede estar escondi\233ndose.[ENTER]Se ha vuelto tan bueno en eso, que es[ENTER]verdaderamente dif\237cil encontrarle. \191Deber\237a[ENTER]realmente colgarle una campana en el cuello, tal[ENTER]y como recomend\243 el guardi\225n del almac\233n? "
gameforge.subquest_18._130_npcChat = "\161Encuentra a Soon! "
gameforge.subquest_18._140_say = "Oyes un poema maravilloso. Fascinado por las[ENTER]palabras, sigues el sonido de la voz hasta que[ENTER]encuentras a un hombre vestido con harapos.[ENTER][ENTER]\161Este debe ser el marido de Aranyo![ENTER][ENTER]Est\225s a punto de darte la vuelta y volver con[ENTER]Aranyo cuando te agarra del hombro. "
gameforge.subquest_18._150_say = "No eres de por aqu\237. \191Te envi\243 mi esposa?[ENTER][ENTER]\161Oh no! \161Sabe qui\233n soy! \191Deber\237a decirle la[ENTER]verdad? "
gameforge.subquest_18._153_select = "Por supuesto que no, s\243lo estoy de paso... "
gameforge.subquest_18._157_select = "Bien... "
gameforge.subquest_18._160_say = "Ah, encantado de conocerte. Maravilloso clima[ENTER]tenemos. \191Has le\237do alg\250n buen libro \250ltimamente?[ENTER]Actualmente estoy leyendo un libro escrito por[ENTER]Oja. Deber\237as leerlo t\250 tambi\233n. "
gameforge.subquest_18._170_say = "Estoy en lo cierto, \191no? Las burlas de mi mujer[ENTER]se est\225n poniendo tan mal que ya no puedo leer[ENTER]m\225s en mi casa. Ella simplemente no me entiende y[ENTER]sigue mandando a gente tras de mi... Me has[ENTER]encontrado aqu\237, pero puedo ir a cualquier otro[ENTER]sitio cuando quiera. \191Qu\233 tal si mantienes en[ENTER]secreto que me has visto aqu\237? Te dar\233 alg\250n buen[ENTER]consejo de caza si lo haces. "
gameforge.subquest_18._180_sendLetter = "Vuelve con Aranyo "
gameforge.subquest_18._190_say = "Vuelve con Aranyo y dile que no pudiste encontrar[ENTER]a Soon. "
gameforge.subquest_18._200_npcChat = "El secreto de Soon. "
gameforge.subquest_18._20_sayTitle = "Aranyo: "
gameforge.subquest_18._210_say = "\191No pudiste encontrarlo? Incluso coloqu\233 trampas.[ENTER]\191D\243nde diablos se esconde? Estoy tan ocupada. Qu\233[ENTER]triste destino el mio... "
gameforge.subquest_18._220_sendLetter = "Vuelve con Soon "
gameforge.subquest_18._230_say = "Vuelve con Soon y dile que has tenido \233xito. "
gameforge.subquest_18._240_npcChat = "Aqu\237 estoy. "
gameforge.subquest_18._250_say = "\191Ha ido todo bien? \161Has salvado mi vida! Coge[ENTER]esto, aventurero. Como promet\237, aqu\237 est\225 tu[ENTER]recompensa. "
gameforge.subquest_18._260_sayReward = "Has recibido 7.000 puntos de experiencia. "
gameforge.subquest_18._270_sayReward = "Has recibido 10.000 Yang. "
gameforge.subquest_18._280_say = "Vuelve con Aranyo y dile d\243nde encontraste a Soon. "
gameforge.subquest_18._290_npcChat = "Esconderse es dif\237cil "
gameforge.subquest_18._300_say = "Gracias. No descubriste mi escondite. Es dif\237cil[ENTER]esconderse de mi esposa. Yo s\243lo quiero estudiar[ENTER]aqu\237 pac\237ficamente. "
gameforge.subquest_18._30_say = "Mi marido es verdaderamente el peor dolor en el[ENTER]trasero. \161Se llama erudito a s\237 mismo! Aunque[ENTER]luchamos para tener algo que comer a diario, \233l[ENTER]s\243lo quiere leer sus libros. \191Le has visto? Por[ENTER]qu\233 me casar\237a con semejante rat\243n de[ENTER]biblioteca... "
gameforge.subquest_18._310_npcChat = "El paradero de Soon "
gameforge.subquest_18._320_say = "\191Le has encontrado?[ENTER]\161Muchas gracias! Si averigua que le has[ENTER]encontrado, puede que huya de nuevo. Ir\233 all\237[ENTER]inmediatamente. \161Esta vez le coger\233! Y tu[ENTER]consigues esto como muestra de mi gratitud.[ENTER]\161Te vas a enterar, querido...! "
gameforge.subquest_18._33_select = "Te ayudar\233 "
gameforge.subquest_18._37_select = "No tengo tiempo para esto. "
gameforge.subquest_18._40_say = "\191Quieres abandonar esta misi\243n? "
gameforge.subquest_18._50_say = "Bueno...[ENTER]Quiz\225 tengas tiempo para buscarle en otro[ENTER]momento... "
gameforge.subquest_18._60_say = "Quiz\225 le encuentre de alg\250n modo... "
gameforge.subquest_18._70_say = "Estar\237a muy agradecida. Cuando encuentres a un[ENTER]pobre escritor, h\225zmelo saber. Seguramente es el[ENTER]\250nico en la aldea de todos modos. Quiz\225 est\225[ENTER]intentando crear un poema o dos y est\225 tratando[ENTER]de esconderse por eso. Si se entera de que le[ENTER]estoy buscando, puede que escape. "
gameforge.subquest_18._80_sendLetter = "Encuentra a Soon. "
gameforge.subquest_18._90_sayTitle = "Encuentra al rat\243n de biblioteca "
gameforge.subquest_19 = {}
gameforge.subquest_19._100_sendLetter = "Consigue una Piel de Lobo. "
gameforge.subquest_19._10_npcChat = "Encuentra un plumero. "
gameforge.subquest_19._110_sayTitle = "Consigue una Piel de Lobo. "
gameforge.subquest_19._120_sayReward = "Consigue una piel de lobo para que la anciana[ENTER]pueda limpiar su casa y no tenga que toser m\225s.[ENTER]Puedes conseguir una de los Lobos Grises. "
gameforge.subquest_19._130_targetVid = "Vuelve con la anciana. "
gameforge.subquest_19._140_npcChat = "Entrega piel de lobo. "
gameforge.subquest_19._150_say = "Esto es... Oh, no. No es la piel de lobo[ENTER]correcta. Vuelve con los Lobos Grises; quiz\225 esta[ENTER]vez encuentres la correcta. "
gameforge.subquest_19._160_say = "Necesito un plumero verdadero. Lo siento, no[ENTER]puedo hacer nada con esto. "
gameforge.subquest_19._170_select = "Voy a intentarlo de nuevo. "
gameforge.subquest_19._180_select = "No quiero. "
gameforge.subquest_19._190_say = "\191Realmente deseas abandonar esta misi\243n? "
gameforge.subquest_19._200_say = "S\243lo vuelve m\225s tarde. "
gameforge.subquest_19._20_say = "\161Cough! \161Cough! Oh cielo, esta tos ser\225 mi[ENTER]muerte. No tengo nada para limpiar mi casa y por[ENTER]eso todo el polvo se queda dentro. Oh, \191por qu\233[ENTER]no tengo un plumero? Mi hijo se lo llev\243, para[ENTER]trabajar en alg\250n tipo de arma. \161Mi propia sangre[ENTER]me est\225 matando! "
gameforge.subquest_19._210_say = "S\233 que es duro pero, por favor, int\233ntalo otra[ENTER]vez. "
gameforge.subquest_19._220_say = "Gracias por hacerte cargo. "
gameforge.subquest_19._230_say = "\161T\250 eres el aventurero! Mi tos aun suena mal,[ENTER]\191no? *cough* *cough* Como puedes comprobar, aun[ENTER]tengo esta mala tos. La casa aun est\225 llena de[ENTER]polvo. Oh, \191me has tra\237do una piel de lobo? \161S\237![ENTER]\201sta es la correcta. Muchas gracias. Espera un[ENTER]momento, por favor. "
gameforge.subquest_19._240_say = "Uno, dos, uno, dos. Un pie delante del otro...[ENTER]Bien, aqu\237 estoy otra vez. \161Muchas gracias! Al[ENTER]fin puedo limpiar mi casa adecuadamente. Tambi\233n[ENTER]he encontrado algo que quiero darte. Realmente no[ENTER]s\233 si vale algo pero quiz\225 te sea \250til. Gracias[ENTER]de nuevo. \161Adi\243s! "
gameforge.subquest_19._250_sendLetter = "Algo polvoriento "
gameforge.subquest_19._260_say = "Como recompensa, has recibido un objeto que[ENTER]parece ser s\243lo basura. Con curiosidad, soplas el[ENTER]polvo que hay en \233l. "
gameforge.subquest_19._270_say = "Es una vieja y valiosa armadura; el trabajo de un[ENTER]buen herrero. \161Qu\233 suerte! "
gameforge.subquest_19._280_say = "Es una armadura. Es vieja pero a\250n puede usarse.[ENTER]Bueno, \161menos es nada! "
gameforge.subquest_19._290_say = "Es un conjunto de armadura, pero a pesar de toda[ENTER]tu esperanza, parece ser algo completamente[ENTER]in\250til. "
gameforge.subquest_19._300_sayReward = "Has recibido 15.000 puntos de experiencia. "
gameforge.subquest_19._30_select = "Te conseguir\233 una. "
gameforge.subquest_19._40_say = "*Cough* *Cough* Todo est\225 polvoriento. Necesito[ENTER]un plumero. \191Puedes ayudarme? "
gameforge.subquest_19._50_say = "Fue hace mucho, pero creo que mi marido, que en[ENTER]paz descanse, lo hizo con piel de lobo.[ENTER]\161Cough! \161Cough! \191Podr\237as conseguirle una piel de[ENTER]lobo a una anciana? Puedes conseguirla de los[ENTER]lobos grises. Me ayudar\237as mucho. "
gameforge.subquest_19._60_say = "\191Realmente deseas abandonar? "
gameforge.subquest_19._70_say = "Oh bueno... muy mal. Realmente pens\233 que me[ENTER]ayudar\237as. Vuelve si cambias de opini\243n. "
gameforge.subquest_19._80_say = "\191Qu\233 clase de recompensa podr\237a esperarse de una[ENTER]vieja y pobre mujer? "
gameforge.subquest_19._90_say = "No es f\225cil conseguir una Piel de Lobo, pero lo[ENTER]voy a intentar. Despu\233s de todo, \161quiero[ENTER]convertirme en un gran h\233roe alg\250n d\237a! "
