gameforge.subquest_20._290_npcChat = "Devolver las jabalinas del marido. "
gameforge.subquest_20._300_sayTitle = "Ah-Yu: "
gameforge.subquest_20._30_say = "Oh, por favor, no llores m\225s cielo. Mami tambi\233n[ENTER]tiene preocupaciones. Si sigues llorando as\237,[ENTER]ninguno de los dos podremos calmarnos. Por favor,[ENTER]para de llorar. "
gameforge.subquest_20._310_say = "Gracias por traerme una. \191Podr\237as buscar tambi\233n[ENTER]las otras dos? Van juntas. Gracias. "
gameforge.subquest_20._320_select = "Probar\233 de nuevo "
gameforge.subquest_20._330_select = "Abandono. "
gameforge.subquest_20._340_say = "Has abandonado la b\250squeda de las jabalinas del[ENTER]marido de Ah-Yu. "
gameforge.subquest_20._350_say = "\161Gracias por no abandonar! "
gameforge.subquest_20._360_say = "Oh, \161aqu\237 est\225n! Estoy muy feliz, gracias.[ENTER]No es mucho, pero toma, coge esto. "
gameforge.subquest_20._370_sayReward = "Has recibido 300.000 puntos de experiencia.[ENTER]Has recibido 20.000 Yang. "
gameforge.subquest_20._40_say = "Oh, ahora mismo pareces algo deprimido.[ENTER]\161Normalmente est\225s tan feliz! \191Ha pasado algo? "
gameforge.subquest_20._50_say = "Mi marido sol\237a cuidarme y se asegur\243 que no me[ENTER]sucediese nunca nada malo. Pero entonces muri\243 en[ENTER]la guerra. Lo \250nico que me queda de \233l es nuestro[ENTER]beb\233 y sus jabalinas. "
gameforge.subquest_20._60_say = "Mientras estaba trabajando, alguien rob\243 las[ENTER]jabalinas. Los vecinos dijeron que fueron los[ENTER]salvajes. No puedo buscarlas yo misma por el[ENTER]beb\233. "
gameforge.subquest_20._70_say = "\191Podr\237as devolverme las jabalinas? Estoy segura[ENTER]de que lsa tienen los salvajes. "
gameforge.subquest_20._80_select = "Voy a buscarlas. "
gameforge.subquest_20._90_select = "No tengo tiempo. "
