gameforge.subquest_21._140_sayTitle = "Consigue la medicina "
gameforge.subquest_21._150_say = "Durante su larga fuga, Balso cogi\243 una enfermedad[ENTER]desconocida. Consigue la medicina de los Hombres[ENTER]Plaga en el Monte Sohan. "
gameforge.subquest_21._160_npcChat = "\161Tengo tu Medicina! "
gameforge.subquest_21._170_say = "Oh, muchas gracias. Es terrible vivir una vida de[ENTER]fugitivo. E incluso te enfermas. Pero con esta[ENTER]cura, recuperar\233 la buena salud. Gracias. "
gameforge.subquest_21._180_sayTitle = "Recompensa: "
gameforge.subquest_21._190_sayReward = "Recibes 1.900.000 puntos de experiencia.[ENTER]Recibes 30.000 Yang. "
gameforge.subquest_21._20_npcChat = "Escuece tanto... "
gameforge.subquest_21._30_sayTitle = "Balso el traidor: "
gameforge.subquest_21._40_say = "\191Puedo pedirte un favor? Como seguramente ya[ENTER]sabes, soy conocido como el traidor y es duro[ENTER]vivir una vida como esta. He vivido buenos[ENTER]momentos tambi\233n, pero ahora es justo lo[ENTER]contrario... Desde entonces, estoy siempre a la[ENTER]fuga y nunca puedo descansar. Adem\225s, entro en[ENTER]contacto con muchas enfermedades. "
gameforge.subquest_21._50_say = "Hace unos d\237as estaba en el Monte Sohan y de[ENTER]alg\250n modo me mezcl\233 con unos cuantos Hombres[ENTER]Plaga. Por suerte pude huir, pero de alg\250n modo[ENTER]cog\237 alg\250n tipo de enfermedad de ellos tras tocar[ENTER]su piel. \191Puedes ayudarme a conseguir alguna[ENTER]medicina? Supongo que tienen alguna con ellos. No[ENTER]me gusta hacer esto, pero, \191puedes ayudarme? "
gameforge.subquest_21._60_select = "S\237, te ayudar\233. "
gameforge.subquest_21._70_say = "\191Quieres abandonar la b\250squeda? "
gameforge.subquest_21._80_say = "Bien, siempre me pasa lo mismo. Dondequiera que[ENTER]mire, hay gente a la que no le gusto. Vuelve si[ENTER]cambias de opini\243n. "
gameforge.subquest_21._90_say = "\161Vete! \161Y no vuelvas nunca m\225s! Es siempre lo[ENTER]mismo... "
