gameforge.subquest_22._50_say = "Si el Herrero lo descubre estar\225 furioso y se[ENTER]negar\225 a reparar mis hachas. Tambi\233n era un hacha[ENTER]realmente buena. \191Quiz\225 t\250 puedes recuperarla? "
gameforge.subquest_22._60_select = "Rechazar "
gameforge.subquest_22._70_say = "\191Quieres abandonar la b\250squeda? "
gameforge.subquest_22._80_say = "Oh... Vuelve si tienes m\225s tiempo. "
gameforge.subquest_22._90_say = "\191Demasiado duro para t\237? Bueno, no puedo hacerle[ENTER]nada. Pero ten cuidado; los salvajes est\225n por[ENTER]todas partes. "
gameforge.subquest_23 = {}
gameforge.subquest_23._100_sendLetter = "Busca a Yu-Hwan "
gameforge.subquest_23._10_targetVid = "\161Por favor, busca a mi hermano mayor! "
gameforge.subquest_23._110_targetVid = "Ve con Yu-Hwan "
gameforge.subquest_23._120_say = "El hermano mayor de Mirine ha desaparecido una[ENTER]vez m\225s. No ha habido noticias suyas desde hace[ENTER]tiempo. La carta que le diste hace poco fue su[ENTER]\250ltimo contacto. Ve con Yu-Hwan y busca al[ENTER]hermano mayor de Mirine. "
gameforge.subquest_23._130_npcChat = "\191Has visto al hermano mayor de Mirine? "
gameforge.subquest_23._140_say = "\191El hermano de Mirine? Me temo que no puedo[ENTER]ayudarte con eso. Tampoco he tenido ning\250n tipo[ENTER]de contacto con \233l recientemente. Apenas puedo[ENTER]recordar cu\225ndo le vi por \250ltima vez. Tambi\233n[ENTER]estoy preocupado.[ENTER]\191Quiz\225 le haya pasado algo? Ve y preg\250ntale al[ENTER]cazador Yang-Shin. \201l siempre se est\225 moviendo y[ENTER]puede que le haya visto. "
gameforge.subquest_23._150_sendLetter = "Busca a Yang-Shin "
gameforge.subquest_23._160_targetVid = "Ve con Yang-Shin el cazador "
gameforge.subquest_23._170_say = "El Cazador Yang-Shin siempre se est\225 moviendo.[ENTER]Quiz\225 \233l haya visto al hermano mayor de Mirine. "
gameforge.subquest_23._180_npcChat = "\191Has visto al hermano mayor de Mirine? "
gameforge.subquest_23._190_say = "\191Te refieres al hermano mayor de Mirine? La[ENTER]\250ltima vez que le vi estaba de camino al Valle de[ENTER]Seungryong a recoger hierbas curativas. Me[ENTER]sorprendi\243 un poco, porque ese lugar es muy[ENTER]peligroso, pero entonces no pens\233 mucho m\225s en[ENTER]eso. "
gameforge.subquest_23._200_say = "Tendr\237a que haberle detenido. Si no ha mantenido[ENTER]contacto, le debe haber pasado algo. Deber\237as ir[ENTER]al Valle de Seungryong y buscarle. "
gameforge.subquest_23._20_npcChat = "\191Por qu\233 lloras? "
gameforge.subquest_23._210_select = "Empezar a buscar "
gameforge.subquest_23._220_say = "\191Dejas de buscar? "
gameforge.subquest_23._230_say = "Mirine estaba realmente triste.[ENTER]Volver\233 m\225s tarde. "
gameforge.subquest_23._240_say = "Si un hermano mayor no se pone en contacto[ENTER]durante un tiempo, no significa necesariamente[ENTER]que le haya pasado algo. No tienes que ir a ese[ENTER]valle peligroso s\243lo porque una ni\241a peque\241a te[ENTER]lo haya pedido. "
gameforge.subquest_23._250_say = "La misi\243n no es tan insignificante como parece.[ENTER]El Valle de Seungryong es un lugar peligroso.[ENTER]Pero lo promet\237, as\237 que lo har\233. "
gameforge.subquest_23._260_sendLetter = "El hermano perdido "
gameforge.subquest_23._270_targetVid = "Busca al hermano mayor en el Valle de Seungryong. "
gameforge.subquest_23._280_sayTitle = "Busca al hermano de Mirine "
gameforge.subquest_23._290_say = "El hermano de Mirine est\225 buscando hierbas[ENTER]curativas en el Valle de Seungryong. Ve all\237 y[ENTER]mira si est\225 bien.[ENTER]El Teletransportador te ayudar\225 si est\225s buscando[ENTER]un atajo. "
gameforge.subquest_23._300_npcChat = "\161El cad\225ver! "
gameforge.subquest_23._30_say = "Un momento, por favor... Una vez me diste una[ENTER]carta de mi hermano, \191no? Estuve muy agradecida.[ENTER]Pero ahora, he vuelto a perder todo contacto con[ENTER]\233l. Mi hermano a\250n est\225 fuera. Est\225 buscando[ENTER]hierbas. "
gameforge.subquest_23._310_say = "Un hombre muerto yace ah\237. Es j\243ven y delgado y[ENTER]parece haber estado recogiendo Ginseng. Me temo[ENTER]que puede ser el hermano mayor de Mirine, al que[ENTER]estamos buscando. El cuerpo lleva un collar con[ENTER]un colgante en \233l. Lo coger\233 y se lo llevar\233 a[ENTER]Mirine. "
gameforge.subquest_23._320_sendLetter = "Ve con Mirine. "
gameforge.subquest_23._330_sayTitle = "Malas noticias "
gameforge.subquest_23._340_say = "Encontraste un colgante en un cuerpo en el Valle[ENTER]de Seungryong, en el que est\225 grabado el nombre[ENTER]de Mirine. Ve con Mirine y dale el collar y el[ENTER]colgante. "
gameforge.subquest_23._350_npcChat = "\191Reconoces este collar? "
gameforge.subquest_23._360_say = "Oh, este collar... Mi hermano sol\237a llevarlo todo[ENTER]el tiempo. Tengo uno parecido. Siempre lo[ENTER]llev\225bamos para poder recordarnos el uno al otro[ENTER]y encontrar el camino de vuelta hasta el otro.[ENTER]Pero... mi hermano ya no est\225 aqu\237... Y s\243lo el[ENTER]collar ha encontrado el camino de vuelta. "
gameforge.subquest_23._370_say = "Mi pobre hermano...[ENTER]Y todo s\243lo por culpa de esta guerra. Mi hermano[ENTER]vend\237a hierbas curativas, era lo \250nico que le[ENTER]daba algo de dinero. Nos permiti\243 comprar comida.[ENTER]Trabaj\243 muy duro para que yo pudiera tener[ENTER]suficiente para comer. Y ahora est\225 muerto. S\243lo[ENTER]por mi culpa... "
gameforge.subquest_23._380_say = "Gracias por traerme esto. Ahora s\233 qu\233 ocurri\243.[ENTER]Si no me hubieras ayudado, nunca habr\237a sabido lo[ENTER]que le ocurri\243. "
gameforge.subquest_23._390_say = "Cuidar\233 bien del colgante de mi hermano mayor.[ENTER]Puedes quedarte el collar como recompensa.[ENTER]Seguramente, ser\225 \250til.[ENTER][ENTER]Gracias por tu ayuda.[ENTER]Seguramente, ahora est\225 en el cielo, \191no crees? "
gameforge.subquest_23._400_sayReward = "Recibes 600.000 puntos de experiencia.[ENTER]Recibes 35.000 Yang. "
gameforge.subquest_23._40_say = "Estoy preocupada por el, ya que no ha contactado[ENTER]conmigo. Lo siento, pero... \191podr\237as buscar a mi[ENTER]hermano una vez m\225s? Quiz\225 Yu-Hwan sepa algo. "
gameforge.subquest_23._50_select = "Rechazar "
gameforge.subquest_23._60_say = "\191Quieres abandonar? "
gameforge.subquest_23._70_say = "Oh...[ENTER]Esperar\233 aqu\237. \191Quiz\225 m\225s tarde? \191Por favor? "
gameforge.subquest_23._80_say = "\161No tengo tiempo![ENTER]Buena suerte a tu hermano. "
gameforge.subquest_23._90_say = "Ayudar a la ni\241a es algo bueno y no requiere[ENTER]mucho trabajo. \161V\225mos! "
gameforge.subquest_24 = {}
gameforge.subquest_24._100_say = "\191Quieres abandonar la misi\243n para siempre? "
gameforge.subquest_24._10_targetVid = "El pastel de arroz de Yu-Rang "
gameforge.subquest_24._110_say = "Si tienes tiempo m\225s tarde, por favor vuelve. No[ENTER]s\233 c\243mo sobreviviremos sin vender los Pasteles de[ENTER]Arroz. "
gameforge.subquest_24._120_say = "Todo gira alrededor de la gente rica que arroja[ENTER]Yang por la ventana como si no hubiera un ma\241ana.[ENTER]\161Cuando nosotros ni siquiera sabemos si tendremos[ENTER]comida en el plato ma\241ana! \161Vete! "
gameforge.subquest_24._130_say = "Gracias. Eres muy amable. Esperar\233 aqu\237 hasta que[ENTER]vuelvas. "
gameforge.subquest_24._140_sendLetter = "El Pastel de arroz robado "
gameforge.subquest_24._150_say = "Consigue el pastel de arroz perdido de Yu-Rang de[ENTER]las ara\241as del desierto. Si eres demasiado lento,[ENTER]las ara\241as se comer\225n el pastel de arroz o se[ENTER]quedar\225 completamente seco por el sol. \161Date[ENTER]prisa! "
gameforge.subquest_24._160_sayReward = "Mata a las Cr\237a Ara\241a en el Desierto Yongbi. "
gameforge.subquest_24._170_npcChat = "Sobre tu Pastel de Arroz robado... "
gameforge.subquest_24._180_say = "\191Qu\233? \191Las ara\241as se comieron el Pastel de Arroz?[ENTER]\161Oh no! \161\191O se ha secado?! \161Por favor, no me[ENTER]digas que se ha perdido todo! "
gameforge.subquest_24._190_select = "No, todo est\225 bien. "
gameforge.subquest_24._200_select = "Abandono. "
gameforge.subquest_24._20_npcChat = "Tu Pastel de Arroz robado... "
gameforge.subquest_24._210_say = "\191No puedes quiz\225 hacerlo despu\233s de todo? El[ENTER]Pastel de Arroz es muy importante para mi. Te lo[ENTER]suplico.[ENTER][ENTER]\191Quieres abandonar la misi\243n de encontrar el[ENTER]Pastel de Arroz de Yu-Rang en el desierto? "
gameforge.subquest_24._220_select = "Voy a intentarlo de nuevo. "
gameforge.subquest_24._230_select = "Lo siento, es demasiado duro. "
gameforge.subquest_24._240_say = "No me lo puedo creer. \191Qui\233n va a ayudarnos ahora? "
gameforge.subquest_24._250_say = "\161Vamos! \161Ay\250dame por favor! "
gameforge.subquest_24._260_say = "\191As\237 que vas a continuar la b\250squeda? \161Gracias![ENTER]Por favor intenta encontrar el Pastel de Arroz[ENTER]tan r\225pido como sea posible. "
gameforge.subquest_24._270_say = "No, es demasiado tarde. Incluso si la consigues,[ENTER]estar\225 seca y no la podr\233 vender... "
gameforge.subquest_24._280_say = "Miras al suelo y ves el pastel de arroz que han[ENTER]dejado las ara\241as. Demasiado tarde. Est\225 todo[ENTER]seco. "
gameforge.subquest_24._290_sayReward = "Has malgastado demasiado tiempo. La torta de[ENTER]arroz se sec\243.[ENTER]Has fallado la misi\243n. "
gameforge.subquest_24._300_sendLetter = "Volver con Yu-Rang "
gameforge.subquest_24._30_say = "Eh, \191c\243mo est\225 tu madre? "
gameforge.subquest_24._310_targetVid = "Vuelve con Yu-Rang "
gameforge.subquest_24._320_say = "Has rescatado el Pastel de Arroz de Yu-Rang de[ENTER]las Ara\241as justo a tiempo. Ll\233vaselo. "
gameforge.subquest_24._330_npcChat = "Est\225s de suerte. Toma tu Pastel de Arroz. "
gameforge.subquest_24._340_say = "Eres realmente estupendo. No s\233 que decir, de[ENTER]verdad... Ahora la podr\233 vender ma\241ana en el[ENTER]mercado. \161Muchas gracias! "
gameforge.subquest_24._350_sayReward = "Recibes 900.000 puntos de experiencia. "
gameforge.subquest_24._360_sayReward = "Has recibido 25.000 Yang "
gameforge.subquest_24._40_say = "Oh, est\225 muy bien; gracias por preguntar. "
gameforge.subquest_24._50_say = "Parece que est\225s en problemas. \191Qu\233 pasa? "
gameforge.subquest_24._60_say = "Vendo Pastel de Arroz aqu\237 cada d\237a, pero algo[ENTER]horrible ha sucedido hoy. Aparecieron Ara\225s[ENTER]Gigantes y me lo robaron. Estaba aterrorizada y[ENTER]no pude pelear. Ahora no me queda Pastel de Arroz[ENTER]para vender. \191Pero c\243mo voy a sobrevivir? Mi[ENTER]familia no tiene ning\250n otro ingreso... "
gameforge.subquest_24._70_select = "Las encontrar\233. "
gameforge.subquest_24._80_select = "Lo siento, no tengo tiempo. "
gameforge.subquest_24._90_sayTitle = "Informaci\243n: "
gameforge.subquest_25 = {}
gameforge.subquest_25._100_npcChat = "\191Qu\233 te gusta? "
gameforge.subquest_25._10_targetVid = "Huahn-So "
gameforge.subquest_25._110_say = "Bueno, desde que perd\237 a mi marido en la guerra,[ENTER]me he sentido muy sola. Hm, \191que qu\233 me har\237a[ENTER]sentir mejor? Mi marido siempre me tra\237a flores. "
gameforge.subquest_25._120_say = "Eran flores que crec\237an muy lejos de nuestra[ENTER]aldea. Aunque era peligroso, me las tra\237a. Hace[ENTER]tiempo que no veo de esas flores, ahora que mi[ENTER]marido ha muerto. Bueno, d\237as como estos me hacen[ENTER]echarle de menos. Umm, \191qu\233 he dicho?[ENTER]Simplemente olvida lo que acabo de decir. "
gameforge.subquest_25._130_qSetTitle = "Vuelve con Huahn-So "
gameforge.subquest_25._140_makequestbutton = "Vuelve con Huahn-So "
gameforge.subquest_25._150_targetVid = "Huahn-So "
gameforge.subquest_25._160_say = "Ariyoung echa de menos las flores que siempre le[ENTER]llevaba su marido. Ve con Huahn-So y cu\233ntaselo. "
gameforge.subquest_25._170_npcChat = "El regalo para Ariyoung... "
gameforge.subquest_25._180_say = "As\237 pues, \191qu\233 le gusta? No le has dicho nada[ENTER]sobre m\237, \191no? Hm, \191le gusta la flor que siempre[ENTER]le llevaba su marido? Est\225 bastante lejos de la[ENTER]aldea. No me ser\225 f\225cil cogerla. Y puede que haya[ENTER]monstruos, como tigres. "
gameforge.subquest_25._190_say = "S\237, \191por qu\233 no me ayudas? \191Por qu\233 no coges la[ENTER]flor para m\237? Eso nos ayudar\237a a ambos. \191Eh? \191Ese[ENTER]no era el trato? Vamos, \191no ves cu\225nto intento[ENTER]conseguir su amor? \161Solo ay\250dame! Te recompensar\233[ENTER]con mucho Yang. "
gameforge.subquest_25._200_select = "Declinar "
gameforge.subquest_25._20_npcChat = "Oh mi amada Ariyoung "
gameforge.subquest_25._210_say = "\191Quieres abandonar esta misi\243n? "
gameforge.subquest_25._220_say = "Maldici\243n. \191C\243mo se supone que voy a conseguir[ENTER]esas Flores?[ENTER]Por favor, vuelve si cambias de opini\243n. "
gameforge.subquest_25._230_say = "\191Nunca has amado? \191No tienes idea de lo que[ENTER]siento por Ariyoung? Oh Ariyoung... "
gameforge.subquest_25._240_say = "\161Muchas gracias! Por favor, tr\225eme esa flor. "
gameforge.subquest_25._250_qSetTitle = "Consigue las flores "
gameforge.subquest_25._260_targetVid = "Flores "
gameforge.subquest_25._270_sayTitle = "Flores para Ariyoung "
gameforge.subquest_25._280_say = "Para ayudar a Huahn-So a decirle a Ariyoung c\243mo[ENTER]se siente, tienes que conseguir Flores[ENTER]especiales. Las flores se encuentran en la[ENTER]esquina del mapa de la primera aldea. "
gameforge.subquest_25._290_npcChat = "No he encontrado Flores. "
gameforge.subquest_25._300_say = "Hm, maldici\243n...[ENTER]Quer\237a revelarle mis sentimientos.[ENTER]Es tan dif\237cil conseguir su amor. Mi amada[ENTER]Ariyoung... "
gameforge.subquest_25._30_say = "Umm... \191Conoces a la Dama Ariyoung? Bueno, ella[ENTER]est\225 - estaba casada. Su marido muri\243 hace unos[ENTER]a\241os y desde entonces ha estado viviendo sola.[ENTER]Tiene un car\225cter espectacula y todav\237a es una[ENTER]mujer muy guapa. Se cas\243 muy j\243ven y yo llegu\233[ENTER]demasiado tarde...  "
gameforge.subquest_25._310_select = "Lo intentar\233 otra vez. "
gameforge.subquest_25._320_select = "Lo dejo. "
gameforge.subquest_25._330_say = "\191Quieres abandonar la misi\243n para siempre? "
gameforge.subquest_25._340_say = "Oh...[ENTER]Si cambias de opini\243n...[ENTER]Estar\233 esperando aqu\237.[ENTER]Por favor, ay\250dame... "
gameforge.subquest_25._350_say = "\191As\237 acabar\225 mi amor? Ariyoung... "
gameforge.subquest_25._360_say = "Tengo que agradec\233rtelo. Tienes que estar[ENTER]enamorado, tambi\233n, si puedes entender lo que[ENTER]siento por Ariyoung. "
gameforge.subquest_25._370_npcChat = "La flor preferida de Ariyoung "
gameforge.subquest_25._380_say = "\201stas flores parecen las que describi\243 Ariyoung.[ENTER]Voy a coger algunas. "
gameforge.subquest_25._390_qSetTitle = "Vuelve con Huahn-So "
gameforge.subquest_25._400_say = "He encontrado las flores favoritas de Ariyoung y[ENTER]he cogido algunas. Deber\237a llev\225rselas a Huahn-So[ENTER]para que pueda confesar su amor a Ariyoung. "
gameforge.subquest_25._40_say = "Pero su marido muri\243 en la guerra. Ahora es una[ENTER]viuda m\225s bien joven. A pesar de que estaba[ENTER]casada... quiero que sepa lo que siento. S\233 que[ENTER]esta es una petici\243n realmente extra\241a, \191pero[ENTER]podr\237as ayudarme? "
gameforge.subquest_25._410_npcChat = "Toma las flores favoritas de Ariyoung. "
gameforge.subquest_25._420_say = "Oh, \191\233stas son las Flores? \161Ahora puedo decirle a[ENTER]Ariyoung lo que siento por ella! \191Crees que es[ENTER]demasiado pronto para eso? Oh bueno, no importa[ENTER]si es demasiado pronto. Tengo que decirselo o[ENTER]estallar\233. \161Aqu\237 est\225 tu recompensa y muchas[ENTER]gracias! "
gameforge.subquest_25._430_sayReward = "Has recibido 400.000 puntos de experiencia. "
gameforge.subquest_25._440_sayReward = "Has recibido 12.000 Yang "
gameforge.subquest_25._50_say = "\191Crees que le gusta un hombre guapo? \191O ropas[ENTER]bonitas? Lo primero de todo, tengo que saber qu\233[ENTER]le gusta y as\237 podr\233 hablar con ella. \191Podr\237as[ENTER]averiguarlo por m\237, por favor? \161Pero no le digas[ENTER]nada de m\237! Te recompensar\233. "
gameforge.subquest_25._60_qSetTitle = "Ve con Ariyoung "
gameforge.subquest_25._70_makequestbutton = "Ve con Ariyoung "
gameforge.subquest_25._80_targetVid = "Ve con Ariyoung "
gameforge.subquest_25._90_say = "Huahn-So ama a la viuda Ariyoung. Para ayudar a[ENTER]Huahn-So a decirle a Ariyoung lo que siente,[ENTER]tienes que averiguar lo que le gusta. Preg\250ntale[ENTER]a Ariyoung lo que le gusta, \161pero ten cuidado de[ENTER]no decirle demasiado! "
gameforge.subquest_26 = {}
gameforge.subquest_26._100_say = "T\250 te lo pierdes. Est\225s perdiendo la oportunidad[ENTER]de tu vida. "
gameforge.subquest_26._10_targetVid = "Ir con el encargado del almac\233n. "
gameforge.subquest_26._110_say = "\161Muy bien! Sab\237a que estar\237as interesado. \161Si[ENTER]consigues algo vuelve aqu\237 y por favor comp\225rtelo[ENTER]conmigo! "
gameforge.subquest_26._120_sendLetter = "Ir con Octavio "
gameforge.subquest_26._130_targetVid = "Ok-gu "
gameforge.subquest_26._140_sayTitle = "Ir con Octavio "
gameforge.subquest_26._150_say = "El Encargado del Almac\233n te ha dado un buen[ENTER]consejo: la sopa de patas traseras de rana es un[ENTER]remedio excelente para el debilitamiento y los[ENTER]huesos cansados. Preg\250ntale a Octavio si puede[ENTER]preparar esta sopa. "
gameforge.subquest_26._160_npcChat = "\191Sopa de ancas de rana? "
gameforge.subquest_26._170_say = "Sopa de ancas de rana... S\237 bien, sol\237a[ENTER]prepararla. Pero ya no m\225s. Por aquel entonces,[ENTER]no ten\237a miedo de los monstruos, as\237 que era[ENTER]capaz de conseguir las ancas de rana f\225cilmente. "
gameforge.subquest_26._180_say = "Pero ahora... soy demasiado viejo y estoy[ENTER]cansado. Con esa sopa, podr\237a recobrar algo de[ENTER]energ\237a, pero las ranas no son f\225ciles de matar.[ENTER]Si me trajeras esas Ancas de Rana para la sopa,[ENTER]\161preparar\237a la mejor sopa de ancas de rana del[ENTER]mundo! "
gameforge.subquest_26._190_select = "Por supuesto, lo har\233. "
gameforge.subquest_26._200_select = "No, no puedo. "
gameforge.subquest_26._20_npcChat = "\191C\243mo est\225s? "
gameforge.subquest_26._210_say = "\191Quieres abandonar la misi\243n para siempre? "
gameforge.subquest_26._220_say = "\191Est\225s ocupado? Vuelve si cambias de opini\243n. "
gameforge.subquest_26._230_say = "Mi sopa no es demasiado conocida. Si la[ENTER]conocieras, lo habr\237as hecho. Ah, bueno, adi\243s. "
gameforge.subquest_26._240_say = "\161Entonces date prisa! Preparar\233 todo para la sopa[ENTER]de ancas de rana. "
gameforge.subquest_26._250_sendLetter = "Ancas de Rana recibidas "
gameforge.subquest_26._260_targetVid = "Octavio: "
gameforge.subquest_26._270_sendLetter = "Consigue Ancas de Rana "
gameforge.subquest_26._280_say = "Tienes un Anca de Rana gigante. Ve a ver a[ENTER]Octavio. "
gameforge.subquest_26._290_sayTitle = "Mata L\237deres Rana Arbor\237colas "
gameforge.subquest_26._300_say = "Octavio necesita Ancas de Rana para su sopa de[ENTER]ancas de rana. Puedes encontrarlas cazando[ENTER]L\237deres Rana Arbor\237colas en el Templo Hwang. "
gameforge.subquest_26._30_sayTitle = "Encargado del almac\233n: "
gameforge.subquest_26._310_npcChat = "No puedo hacerlo ahora. "
gameforge.subquest_26._320_say = "\191Qu\233 pasa? Cuando yo era tan joven como t\250, sol\237a[ENTER]conseguir 10 ancas al d\237a. "
gameforge.subquest_26._330_select = "Intentarlo de nuevo "
gameforge.subquest_26._340_say = "\191Est\225s cansado? \191Por qu\233 no descansas y pruebas[ENTER]de nuevo m\225s tarde? "
gameforge.subquest_26._350_say = "Podr\237a haber usado esa sopa de patas de rana.[ENTER]Pero eso no ocurrir\225. L\225stima. \161Adi\243s! "
gameforge.subquest_26._360_say = "\161Entonces no te quedes aqu\237 parado y vete! \161El[ENTER]agua ya est\225 hirviendo y todo est\225 preparado! "
gameforge.subquest_26._370_targetVid = "Ir con Octavio "
gameforge.subquest_26._380_say = "\161Eso es lo que yo llamo un Anca de Rana! Sol\237an[ENTER]ser m\225s peque\241as, pero estoy seguro de que esta[ENTER]sabr\225 bien tambi\233n. Espera un momento... Eso ya[ENTER]huele bastante bien. Otra pizca de sal... \161Bien![ENTER]Aqu\237 est\225 tu raci\243n. Jajaja, ahora tengo[ENTER]suficiente energ\237a para una semana entera de[ENTER]trabajo. "
gameforge.subquest_26._390_say = "Aseg\250rate que nadie se entera de esta sopa.[ENTER]Especialmente el encargado del almac\233n... Rara[ENTER]vez preparo esta sopa. De lo contrario, todo el[ENTER]mundo vendr\225 y me molestar\225. "
gameforge.subquest_26._400_sayReward = "Recibes 5.000.000 puntos de experiencia. "
gameforge.subquest_26._40_say = "No he estado muy bien \250ltimamente. Mi cuerpo[ENTER]realmente ya no es lo que era. Cuando era j\243ven,[ENTER]pod\237a trabajar hasta la noche, cada d\237a de la[ENTER]semana, mientras beb\237a alcohol. Ahora, incluso[ENTER]resulta demasiado trabajo levantarme por las[ENTER]ma\241anas. Necesito una gran ayuda de la sopa de[ENTER]patas de rana para recuperar mi energ\237a. "
gameforge.subquest_26._410_sayReward = "Obtienes 50.000 Yang. "
gameforge.subquest_26._50_say = "\191No sabes lo que es la sopa de patas de rana?[ENTER]Cuando te tomas un taz\243n, te espabilas[ENTER]completamente de inmediato y te llenas de[ENTER]energ\237a. \161Entonces puedes trabajar una semana[ENTER]entera seguida sin cansarte![ENTER]Octavio sol\237a preparar esta sopa, pero por alguna[ENTER]raz\243n dej\243 de hacerlo hace un tiempo. "
gameforge.subquest_26._60_select = "Ir\233 a hablar con Octavio "
gameforge.subquest_26._70_select = "Estoy ocupado. "
gameforge.subquest_26._80_say = "\191Quieres abandonar la misi\243n para siempre? "
gameforge.subquest_26._90_say = "Bien, si est\225s ocupado...[ENTER]Vuelve si tienes algo m\225s de tiempo. "
gameforge.subquest_27 = {}
gameforge.subquest_27._100_say = "\161Deber\237a estar avergonzado de denominarse a si[ENTER]mismo como padre! Si le encuentro, \161que Dios[ENTER]tenga compasi\243n de su alma! Cr\233eme, no estoy[ENTER]exagerando. Pregunta a otros en la aldea, estan[ENTER]de acuerdo conmigo. "
gameforge.subquest_27._10_targetVid = "Soon: "
gameforge.subquest_27._110_targetVid = "Vendedor general: "
gameforge.subquest_27._120_makequestbutton = "Ve con la Vendedora de la Tienda General. "
gameforge.subquest_27._130_say = "Quiz\225 la Vendedora de la Tienda General sepa lo[ENTER]que trama Soon. Ve con ella y preg\250ntale si ha[ENTER]oido algo de Soon. "
gameforge.subquest_27._140_npcChat = "\191Qu\233 pasa con Soon? "
gameforge.subquest_27._150_say = "Ayer, vino aqu\237 y pregunto por el Libro Secreto[ENTER]Temple. No ten\237a Yang, as\237 que s\243lo le ech\243 un[ENTER]vistazo. Debe ser muy importante para \233l si[ENTER]incluso descuida a su familia por \233l.[ENTER]\191Por qu\233 esta tan interesado? "
gameforge.subquest_27._160_sayTitle = "Vendedor general: "
gameforge.subquest_27._170_say = "Lo siento por Aranyo. No se cas\243 con Soon para[ENTER]trabajar d\237a y noche. Seguro que no pens\243 que[ENTER]tendr\237a que mantener a su familia ella sola.[ENTER]Quiz\225 deber\237as hablar con el otra vez. Quiz\225...[ENTER]quiz\225 lo entender\225. "
gameforge.subquest_27._180_makequestbutton = "Ve a ver a Soon "
gameforge.subquest_27._190_qSetTitle = "Ve a ver a Soon "
gameforge.subquest_27._200_targetVid = "Soon otra vez "
gameforge.subquest_27._20_npcChat = "El placer de la lectura "
gameforge.subquest_27._210_say = "Ve con Soon[ENTER]Ve con Soon y preg\250ntale sobre el libro acerca[ENTER]del templo. "
gameforge.subquest_27._220_npcChat = "\191Qu\233 es el libro del templo secreto? "
gameforge.subquest_27._230_say = "Ya sabes, he le\237do todos y cada uno de los libros[ENTER]del mundo. \218ltimamente, he estado escuchando[ENTER]sobre un libro del templo secreto. Los rumores[ENTER]cuentan que este libro posee todos los secretos[ENTER]del Templo Oscuro - y de c\243mo convertirse en[ENTER]santo. "
gameforge.subquest_27._240_say = "Tengo muchas ganas de leer este libro. \191Podr\237as[ENTER]consegu\237rmelo? Si lo haces, te dar\233 algo, incluso[ENTER]si tengo que vender mi casa. "
gameforge.subquest_27._250_select = "\161Lo har\233! "
gameforge.subquest_27._260_select = "No puedo, lo siento. "
gameforge.subquest_27._270_say = "\191Quieres abandonar la misi\243n para siempre? "
gameforge.subquest_27._280_say = "Vamos, \191no quieres ayudarme? Si no es ahora,[ENTER]vuelve m\225s tarde. Te estar\233 esperando. "
gameforge.subquest_27._290_say = "\191De verdad no quieres ayudarme? Necesitas[ENTER]vacaciones, uh. El libro es verdaderamente[ENTER]importante para m\237... \191Qu\233 hago ahora? Maldici\243n. "
gameforge.subquest_27._300_say = "Gracias, estar\233 esperando. "
gameforge.subquest_27._30_say = "\191Te gusta leer tanto como a m\237?[ENTER]Las palabras que se unen en frases y se unifican[ENTER]finalmente en un libro. \161Qu\233 maravilloso! \161Y el[ENTER]puro regocijo de escribir un libro para que otras[ENTER]personas puedan leerlo! \161No hay nada mejor que[ENTER]eso! "
gameforge.subquest_27._310_makequestbutton = "Has encontrado el libro del templo "
gameforge.subquest_27._320_qSetTitle = "Has encontrado el libro del templo. Vuelve con[ENTER]Soon. "
gameforge.subquest_27._330_targetVid = "Vuelve con Soon. "
gameforge.subquest_27._340_makequestbutton = "Derrota a los Fan\225ticos Oscuros "
gameforge.subquest_27._350_sayTitle = "Has matado a los Fan\225ticos Esot\233ricos. "
gameforge.subquest_27._360_say = "Lleva el libro secreto del templo a Soon. "
gameforge.subquest_27._370_say = "Soon tiene un profundo inter\233s en el Libro[ENTER]Secreto Temple... Si matas a los Fan\225ticos[ENTER]Oscuros, puede que encuentres el Libro Secreto[ENTER]Temple. "
gameforge.subquest_27._380_npcChat = "El libro secreto del templo. "
gameforge.subquest_27._390_say = "Oh, \161\233se es! \161Muchas gracias![ENTER]Aqu\237 est\225 tu recompensa.[ENTER]Ahora d\233jame solo, \161tengo que leer! "
gameforge.subquest_27._400_sayReward = "Recibes 850.000 puntos de experiencia. "
gameforge.subquest_27._40_say = "\161La vida late entre las p\225ginas de este libro![ENTER]\161Conocimiento j\243ven y vieja sabidur\237a viven aqu\237![ENTER]Imagina lo desolada que ser\237a mi vida sin[ENTER]libros... S\243lo desafortunadamente... mi mujer no[ENTER]lo entiende. \191Podr\237as tratar de convencerle de[ENTER]que es algo bueno? "
gameforge.subquest_27._410_sayReward = "Has recibido 20.000 Yang. "
gameforge.subquest_27._420_say = "Eh... \191A\250n no lo tienes? Si comienzas una misi\243n,[ENTER]deber\237as tratar de acabarla. Ahora, \161termina la[ENTER]misi\243n! "
gameforge.subquest_27._430_say = "Los Fan\225ticos Oscuros no deben ser[ENTER]menospreciados. Tan s\243lo int\233ntalo m\225s tarde. "
gameforge.subquest_27._440_say = "Bien, entonces tendr\233 que pedirle ayuda a otro.[ENTER]Adi\243s. "
gameforge.subquest_27._450_say = "Gracias, estar\233 esperando. No puedo esperar a[ENTER]tenerlo en mis manos y leerlo. "
gameforge.subquest_27._50_makequestbutton = "Ve con Aranyo  "
gameforge.subquest_27._60_sayTitle = "Ve con Aranyo  "
gameforge.subquest_27._70_say = "Ve con Aranyo y preg\250ntale sobre su marido. "
gameforge.subquest_27._80_npcChat = "\191Por qu\233 est\225s tan enfadada? "
gameforge.subquest_27._90_say = "\191Enfadada? \161Estoy a punto de estallar de rabia![ENTER]\191Sale mi marido a trabajar? No. \191Trae Yang a casa[ENTER]alguna vez? No. \161En lugar de eso, se est\225[ENTER]escondiendo en alg\250n lugar entre las p\225ginas de[ENTER]un libro! \191Hab\237as escuchado antes algo parecido?[ENTER]\191Puede traernos ropa un libro? \191Nos abastece de[ENTER]comida? "
