gameforge.subquest_30._100_sendLetter = "Mineral para el Herrero "
gameforge.subquest_30._10_npcChat = "\191Necesitas mineral? "
gameforge.subquest_30._110_targetVid = "Herrero. "
gameforge.subquest_30._120_sayTitle = "Vuelve con el Herrero "
gameforge.subquest_30._130_say = "Has recogido el Mineral que necesita el Herrero[ENTER]para hacer armas nuevas. Deber\237as llev\225rselo. "
gameforge.subquest_30._140_sayTitle = "Consigue mineral para armas nuevas "
gameforge.subquest_30._150_say = "El Herrero necesita mineral para producir un[ENTER]nuevo tipo de arma. Necesita 100 piezas de[ENTER]Mineral de Oro, 100 de Mineral de Plata y 100[ENTER]piezas de Mineral de \201bano. Los dep\243sitos de[ENTER]mineral pueden encontrarse en diversos lugares[ENTER]del mapa y recogidos en vetas. Pero tambi\233n[ENTER]puedes comerciar con otros jugadores y[ENTER]comprarlos. "
gameforge.subquest_30._160_npcChat = "He recogido Mineral para ti. "
gameforge.subquest_30._170_say = "Eso no es suficiente. Necesito los 100 de mineral[ENTER]de oro, 100 de mineral de plata y 100 de mineral[ENTER]de \233bano. "
gameforge.subquest_30._180_select = "Intentarlo de nuevo "
gameforge.subquest_30._190_select = "Abandonar "
gameforge.subquest_30._200_say = "\191Realmente quieres abandonar para siempre? "
gameforge.subquest_30._20_say = "\161Eh, t\250! \161S\237, me refiero a ti! Ya no eres un[ENTER]principiante. \191Y por qu\233? \161Porque te he dado[ENTER]tareas complicadas! Ha sido s\243lo por tu bien,[ENTER]jejeje. Pero ahora voy a pedirte un verdadero[ENTER]favor. "
gameforge.subquest_30._210_say = "Es dif\237cil conseguir mineral, \191no? La suerte[ENTER]viene con el trabajo duro. \191Qu\233 te parece tomar[ENTER]un peque\241o respiro e intentarlo de nuevo m\225s[ENTER]tarde? "
gameforge.subquest_30._220_say = "Maldici\243n. Era una idea brillante.[ENTER]Oh bueno, qu\233 se le va a hacer. \161Nos vemos! "
gameforge.subquest_30._230_say = "Si haces un esfuerzo, pronto tendr\225s todo. \161Buena[ENTER]suerte! "
gameforge.subquest_30._240_say = "Oh, \161ya has recogido todo! \161Jajaja! Puedo decir[ENTER]que todo va a concluir. Espera un minuto, no va a[ENTER]tardar mucho.[ENTER]\161Y all\225 vamos! "
gameforge.subquest_30._250_say = "Hmmm, es perfecto. A veces me sorprende mi propia[ENTER]maestr\237a. Aqu\237 esta tu arma. Es nueva, \161as\237 que[ENTER]cuidala bien! "
gameforge.subquest_30._260_sayReward = "Recibes 200.000 puntos de experiencia. "
gameforge.subquest_30._270_sayReward = "Has recibido 20.000 Yang. "
gameforge.subquest_30._280_sayReward = "Has recibido Espada de Plata+3. "
gameforge.subquest_30._290_sayReward = "Has recibido Fan Acu\225tico+3. "
gameforge.subquest_30._30_say = "Quiero intentar forjar un arma nueva, pero es muy[ENTER]dif\237cil conseguir los materiales. \191Podr\237as[ENTER]hacerlo por mi? Te dar\233 la primera que termine[ENTER]como recompensa. "
gameforge.subquest_30._40_say = "Necesito 100 de Mineral de Oro, 100 de Mineral de[ENTER]Plata y 100 de Mineral de \201bano. Parece m\225s de lo[ENTER]que es. Puedes conseguir mucho material en bruto[ENTER]a la vez en las vetas as\237 que puedes recogerlo[ENTER]f\225cilmente.[ENTER]Si a\250n as\237 es demasiado dif\237cil para ti, puedes[ENTER]comerciarlo con alguien. Como t\250 prefieras.[ENTER]\161Espero que lo consigas! "
gameforge.subquest_30._50_select = "Declinar "
gameforge.subquest_30._60_say = "\191Quieres abandonar la misi\243n para siempre? "
gameforge.subquest_30._70_say = "No hay prisa. Vuelve si cambias de opini\243n. "
gameforge.subquest_30._80_say = "Maldici\243n. Era una idea brillante.[ENTER]Oh bueno, qu\233 se le va a hacer. \161Nos vemos! "
gameforge.subquest_30._90_say = "\161Oh! \191Lo vas a hacer?[ENTER]\161Eres un buen amigo! "
