gameforge.subquest_31._140_sayReward = "El Herrero necesita mineral para hacer un nuevo[ENTER]tipo de armadura. Ll\233vale 100 de Mineral de[ENTER]Cobre, 100 de Mineral de \201bano y 100 Piezas de[ENTER]Perla. El Mineral puede ser encontrado por todo[ENTER]el mapa y recogido en vetas. Tambi\233n puedes[ENTER]comerciarlo con otros jugadores y comprarles[ENTER]mineral. "
gameforge.subquest_31._150_npcChat = "He recogido Mineral para ti. "
gameforge.subquest_31._160_say = "Hmmm, faltan muchos materiales. \161Dije que[ENTER]necesito 100 de Mineral de Cobre, 100 de Mineral[ENTER]de \201bano y 100 Piezas de Perla! "
gameforge.subquest_31._170_select = "Intentarlo de nuevo "
gameforge.subquest_31._180_select = "Abandonar "
gameforge.subquest_31._190_say = "\191Quieres abandonar la misi\243n para siempre? "
gameforge.subquest_31._200_say = "\191Es tan duro? Por supuesto, no es solo cuesti\243n[ENTER]de suerte, sino tambi\233n trabajo duro. \191Por qu\233 no[ENTER]lo intentas de nuevo m\225s tarde? "
gameforge.subquest_31._20_npcChat = "\191Todav\237a necesitas m\225s mineral? "
gameforge.subquest_31._210_say = "Bien, ah\237 van mis planes para una nueva armadura.[ENTER]\161Esa idea podr\237a haber cambiado el mundo! Que[ENTER]l\225stima... "
gameforge.subquest_31._220_say = "\161S\233 fuerte! \161S\233 que puedes hacerlo! "
gameforge.subquest_31._230_say = "\161Excelente! Eres realmente bueno buscando[ENTER]materiales. Ahora, presta atenci\243n.[ENTER]Aqu\237 ... y aqu\237..., y lo enfriar\233 m\225s r\225pido...[ENTER]Esto es para ti, es una recompensa por tus[ENTER]esfuerzos. \161Hasta pronto! "
gameforge.subquest_31._240_sayReward = "Recibes 200.000 puntos de experiencia. "
gameforge.subquest_31._250_sayReward = "Has recibido 20.000 Yang. "
gameforge.subquest_31._260_sayReward = "Has recibido una Armadura Placas de Le\243n +3. "
gameforge.subquest_31._270_sayReward = "Has recibido un Traje de Hormiga Roja +3. "
gameforge.subquest_31._280_sayReward = "Has recibido una Armadura Placas Fantasma +3. "
gameforge.subquest_31._290_sayReward = "Has recibido un Ropaje Amoroso +3. "
gameforge.subquest_31._30_say = "Hola, \191tienes un minuto para mi?[ENTER]Aprecio mucho que me ayudaras a hacer un arma[ENTER]nueva. Ahora me gustar\237a pedirte ayuda de nuevo.[ENTER]Esta vez quiero hacer una nueva armadura. Despu\233s[ENTER]de haber hecho un arma nueva, es obvio que[ENTER]tambi\233n necesito una buena armadura. "
gameforge.subquest_31._40_say = "Por supuesto necesito materiales para hacer la[ENTER]armadura nueva. \191Puedes consegu\237rmelos? A cambio[ENTER]recibir\225s la primera armadura completa. Esta vez[ENTER]necesito 100 de Mineral de Cobre, 100 de Mineral[ENTER]de \201bano y 100 Piezas de Perla. Ya deber\237as[ENTER]saberlo. \161Te deseo lo mejor! "
gameforge.subquest_31._50_select = "Aceptar "
gameforge.subquest_31._60_say = "\191Quieres abandonar esta misi\243n? "
gameforge.subquest_31._70_say = "\191Por qu\233 est\225s dudando? Vuelve cuando est\233s listo[ENTER]para trabajar en las minas. "
gameforge.subquest_31._80_say = "Esa peque\241a cantidad de mineral no es pedir[ENTER]mucho. Bueno, all\225 t\250. \161Pi\233rdete! "
gameforge.subquest_31._90_say = "\191Me ayudar\225s otra vez? Eres un buen amigo.[ENTER]Y no te preocupes: \161la primera armadura es tuya! "
