gameforge.subquest_32._100_sendLetter = "Pedido comercial "
gameforge.subquest_32._10_targetVid = "Elige un comerciante "
gameforge.subquest_32._110_targetVid = "Ve con Ah-Yu "
gameforge.subquest_32._120_targetVid = "Ve con la Vendedora de la Tienda General. "
gameforge.subquest_32._130_sayReward = "Materiales para el Vendedor "
gameforge.subquest_32._140_sayReward = "Peddler necesita algunos materiales para un[ENTER]collar. Cons\237guele 100 Molares del Hechicero Orco[ENTER]\201lite, una Pieza de Joyer\237a de la Vendedora de la[ENTER]Tienda General y el Hilo de Ariyoung. "
gameforge.subquest_32._150_npcChat = "Necesito Hilo. "
gameforge.subquest_32._160_say = "Producir Hilo no es una gran cosa. Pero entonces[ENTER]no puedo hacer el resto de mi trabajo. Hoy he[ENTER]arreglado las ropas rasgadas de Ah-Yu y quer\237a[ENTER]llev\225rselas... "
gameforge.subquest_32._170_say = "Qu\233 me dices: \191Le llevas la ropa a Ah-Yu mientras[ENTER]hago el Hilo para ti? \191Aceptas? "
gameforge.subquest_32._180_say = "\191Quieres abandonar para siempre? "
gameforge.subquest_32._190_say = "Verdaderamente no est\225 muy lejos. \191Por qu\233 sigues[ENTER]dudando? Vuelve cuando est\233s listo. "
gameforge.subquest_32._200_say = "Oh, esperaba que tuvieras tiempo. Entonces tengo[ENTER]que ir yo misma. \161Adi\243s! "
gameforge.subquest_32._20_npcChat = "Sobre los collares... "
gameforge.subquest_32._210_say = "Maravilloso, \161muchas gracias! Saluda a Ah-Yu de[ENTER]mi parte \161y aseg\250rate de no aplastar sus ropas[ENTER]por el camino! Te estar\233 esperando aqu\237. "
gameforge.subquest_32._220_sayTitle = "Ariyoung: "
gameforge.subquest_32._230_say = "Cuando vuelvas de la aldea vecina tendr\233[ENTER]terminado tu Hilo. No te has olvidado de llevar a[ENTER]Ah-Yu sus ropas, \191no? Se enfadar\237a conmigo por[ENTER]eso. "
gameforge.subquest_32._240_say = "\191Est\225 Ah-Yu contenta con sus ropas? Si es as\237, ha[ENTER]valido la pena trabajar tan duro. Aqu\237 estan tus[ENTER]hilos. Son fuertes y se pueden usar para muchas[ENTER]cosas. "
gameforge.subquest_32._250_say = "Ya te he dado Hilo. \191Lo has perdido? "
gameforge.subquest_32._260_npcChat = "Ariyoung te manda estas ropas. "
gameforge.subquest_32._270_sayTitle = "Ah-Yu: "
gameforge.subquest_32._280_say = "Oh, que bien. Eso ha sido realmente r\225pido.[ENTER]Tienes que cultivar antiguas amistades, \191no? Nos[ENTER]ayudamos mutuamente a menudo...[ENTER]Gracias a ti por traerme las ropas.[ENTER]Por favor, saluda a Ariyoung de mi parte. "
gameforge.subquest_32._290_npcChat = "Necesito una pieza de joyer\237a. "
gameforge.subquest_32._300_say = "\191Est\225s buscando joyer\237a?[ENTER]Puedo darte una Pieza de Joyer\237a si me ayudas.[ENTER]Actualmente estoy trabajando en una medicina[ENTER]especial contra el dolor, pero necesito un[ENTER]ingrediente: un H\237gado de Tigre. Son realmente[ENTER]dif\237ciles de conseguir. Necesito 100 H\237gados de[ENTER]Tigre. "
gameforge.subquest_32._30_say = "No es f\225cil para nosotros los Vendedores[ENTER]Ambulantes durante tiempos de guerra. La[ENTER]mercanc\237a se necesita por todas partes pero la[ENTER]demanda cambia tan r\225pidamente que nunca s\233 si[ENTER]tengo lo correcto en oferta. Sin mencionar los[ENTER]largos viajes a trav\233s de la tierra salvaje donde[ENTER]todos los monstruos acechan a los peatones[ENTER]descuidados. \191Quieres ganar algo de Yang? Puedo[ENTER]hacerlo con algo de ayuda. "
gameforge.subquest_32._310_say = "Tambi\233n necesito unas determinadas Hierbas[ENTER]Medicinales pero tambi\233n las conseguir\225s de los[ENTER]Tigres. Les gusta revolcarse sobre ellas porque[ENTER]les gusta el olor. Te dar\233 una Pieza de Joyer\237a[ENTER]por las Hierbas y los H\237gados de Tigre. "
gameforge.subquest_32._320_say = "Caza tigres o tigres blancos. "
gameforge.subquest_32._330_say = "\191Qu\233 dices? \191Hacemos un trato? "
gameforge.subquest_32._340_say = "\191Mi tarea es demasiado dif\237cil para ti? \161No puedo[ENTER]imagin\225rmelo! Vuelve a verme cuando hayas[ENTER]cambiado de opini\243n. "
gameforge.subquest_32._350_say = "\191Haces todo este viaje por el Vendedor y[ENTER]abandonas? Como quieras...[ENTER]Que tengas un buen d\237a. "
gameforge.subquest_32._360_say = "Muy bien. Esto va a ayudarnos a ambos, \191no?[ENTER]\161Gracias y buena suerte! "
gameforge.subquest_32._370_npcChat = "\191Me das ahora mi Pieza de Joyer\237a? "
gameforge.subquest_32._380_say = "D\233jame ver... 100 H\237gados de Tigre y las Hierbas[ENTER]Medicinales, est\225 todo. \161Gracias![ENTER]Aqu\237 tienes, realmente te has ganado esta Pieza[ENTER]de Joyer\237a. \161Nos vemos! "
gameforge.subquest_32._390_qSetTitle = "Vuelve con Peddler "
gameforge.subquest_32._400_targetVid = "Vuelve con Peddler "
gameforge.subquest_32._40_say = "Actualmente los collares hechos de Molares de[ENTER]Orco est\225n en demanda. Los Molares de Orco son[ENTER]grandes y duros y son buenos para hacer[ENTER]determinadas partes de joyer\237a. Los soldados[ENTER]tambi\233n creen que los molares de los Hechiceros[ENTER]Orco \201lite son amuletos de buena suerte. \191Podr\237as[ENTER]conseguirme esos Molares? 100 Molares deber\237an[ENTER]ser suficientes para empezar. "
gameforge.subquest_32._410_sayReward = "Vuelve con Peddler "
gameforge.subquest_32._420_sayReward = "Finalmente has conseguido todos los materiales[ENTER]para el collar. Ll\233vaselos a Peddler. "
gameforge.subquest_32._430_npcChat = "Tengo todos los materiales "
gameforge.subquest_32._440_sayTitle = "Peddler: "
gameforge.subquest_32._450_say = "\191Tienes todos los materiales? Veamos...[ENTER]S\237, realmente est\225 todo aqu\237. Gracias a tu ayuda[ENTER]puedo ampliar mis suministros, eso es bueno. Aqu\237[ENTER]est\225 tu parte. Divi\233rtete.[ENTER]\161Venid aqu\237, compa\241eros! \161Hay algo para todo el[ENTER]mundo! "
gameforge.subquest_32._460_sayReward = "Recibes 1.000.000 puntos de experiencia. "
gameforge.subquest_32._470_sayReward = "Consigues un Brazalete de Oro, un Collar de Oro y[ENTER]unos Pendientes de Oro. "
gameforge.subquest_32._480_say = "Hmmm, lo siento pero falta algo. No necesito[ENTER]entregas incompletas. \191Seguir\225s intent\225ndolo? "
gameforge.subquest_32._490_say = "\191Quieres abandonar la misi\243n para siempre? "
gameforge.subquest_32._500_say = "Gracias por no abandonar tan f\225cilmente.[ENTER]\161La suerte acompa\241a a aquellos que lo intentan![ENTER]Te esperar\233 aqu\237. "
gameforge.subquest_32._50_say = "Tambi\233n necesito una Pieza de Joyer\237a e Hilo. Uno[ENTER]lo conseguir\225s de la Vendedora de la Tienda[ENTER]General, el otro de Ariyoung. No es f\225cil[ENTER]conseguir tantas cosas, pero vender collares es[ENTER]un buen negocio y conseguir\225s una buena[ENTER]recompensa por los materiales. \191Qu\233 piensas?[ENTER]\191Suena interesante? "
gameforge.subquest_32._510_say = "\191La tarea es demasiado dif\237cil? Bueno, al menos[ENTER]lo has intentado. Te har\233 saber si tengo alguna[ENTER]tarea m\225s f\225cil alg\250n d\237a. \161Adi\243s! "
gameforge.subquest_32._520_say = "\191Vas a intentarlo otra vez? Gracias. Te estar\233[ENTER]esperando. "
gameforge.subquest_32._60_say = "\191Quieres abandonar la misi\243n para siempre? "
gameforge.subquest_32._70_say = "\191Est\225s ocupado? Puedo entenderlo. Pero por favor[ENTER]vuelve cuando tengas tiempo. "
gameforge.subquest_32._80_say = "Oh cielo, \191c\243mo voy a completar todas mis tareas?[ENTER]\161Nos vemos! "
gameforge.subquest_32._90_say = "Fant\225stico. Te esperar\233 aqu\237. "
gameforge.subquest_33 = {}
gameforge.subquest_33._100_sayTitle = "Mapa del tesoro encontrado "
gameforge.subquest_33._10_targetVid = "Ve con el rat\243n de biblioteca. "
gameforge.subquest_33._110_say = "Has cazado a los dioses animales en las afueras[ENTER]de la aldea y has encontrado las 4 partes del[ENTER]Mapa del Tesoro.[ENTER]Ll\233vaselas a Soon. "
gameforge.subquest_33._120_sayTitle = "Cazando a los dioses animales "
gameforge.subquest_33._130_say = "Recoge las 4 partes del Mapa del Tesoro cazando a[ENTER]los dioses animales Lykos, Scrofa, Bera y Tigris. "
gameforge.subquest_33._140_sayReward = "(Partes del mapa encontradas: %s) "
gameforge.subquest_33._150_sendLetter = "El mapa del tesoro "
gameforge.subquest_33._160_sayTitle = "\161Encontradas todas las partes! "
gameforge.subquest_33._170_say = "Vuelve con Soon y dile que has encontrado todas[ENTER]las partes del mapa del tesoro. "
gameforge.subquest_33._175_npcChat = "Tengo todas las piezas del mapa. "
gameforge.subquest_33._180_say = "\161Oh! \161Fant\225stico! Las cuatro piezas juntas...[ENTER]\161Jam\225s lo habr\237a so\241ado! Ahora tengo que juntar[ENTER]las piezas para conseguir el mapa entero...[ENTER]bien... "
gameforge.subquest_33._190_say = "Hmm... Raro. El mapa dice que el tesoro est\225[ENTER]escondido en la roca cerca del Anciano. No puedo[ENTER]imaginar que sea cierto. Ya habr\237a sido[ENTER]encontrado a estas alturas. \161Qu\233 chiquiller\237a![ENTER]\191Quieres mirar de todos modos, o simplemente[ENTER]deber\237a quemar el mapa? "
gameforge.subquest_33._200_select = "Echar\233 un vistazo. "
gameforge.subquest_33._20_npcChat = "Sobre el Mapa del Tesoro... "
gameforge.subquest_33._210_select = "Qu\233malo. "
gameforge.subquest_33._220_say = "\191Est\225s seguro de que ya no necesitas el mapa? "
gameforge.subquest_33._230_say = "\161Qu\233 pat\233tico cuento de hadas![ENTER]Siento haberte enviado a buscar esos trozos de[ENTER]mapa. Los quemar\233 ahora para que nadie m\225s caiga[ENTER]por ellos. A\250n as\237, muchas gracias.[ENTER]Adi\243s. "
gameforge.subquest_33._240_say = "\191Por qu\233 est\225s dudando? Ya has recogido los[ENTER]trozos del mapa. Entonces puedes ir y mirar.[ENTER]Toma, \161coge el mapa! "
gameforge.subquest_33._250_say = "Como quieras. Estar\237a realmente sorprendido si[ENTER]verdaderamente encontrases algo pero, de todos[ENTER]modos, \161te deseo suerte! \161Coge el mapa! "
gameforge.subquest_33._260_say = "El mapa ha sido dividido en cuatro partes.[ENTER]\161Necesitamos las cuatro partes para juntarlas de[ENTER]nuevo! "
gameforge.subquest_33._270_select = "Intentarlo de nuevo. "
gameforge.subquest_33._280_say = "\191Lo dejas? Oh bueno...[ENTER]Adi\243s. "
gameforge.subquest_33._290_say = "Sab\237a que ir\237as. \161Creo en t\237! "
gameforge.subquest_33._300_targetVid = "Roca del Anciano "
gameforge.subquest_33._30_say = "Eh, encontr\233 alguna informacion extra\241a en unos[ENTER]viejos textos, diciendo que en alg\250n sitio de[ENTER]esta aldea, puede haber mapas del tesoro...[ENTER]\191Conoces a los Dioses protectores de la ciudad?[ENTER]El Dios Perro, el Dios Oso, el Dios Tigre y el[ENTER]Dios Cerdo. "
gameforge.subquest_33._310_sayTitle = "Buscando el tesoro. "
gameforge.subquest_33._320_say = "Hmm, bajo la Roca del Anciano...[ENTER]Ni idea. Quiz\225 deber\237a preguntar al anciano. \191Por[ENTER]qu\233 estar\225 tan lejos? Maldici\243n. "
gameforge.subquest_33._330_sayTitle = "Anciano: "
gameforge.subquest_33._340_say = "\191Qu\233 est\225s buscando? \191Un tesoro? Jaja, \161buscas en[ENTER]vano! Ens\233\241ame el mapa... Hmmm. Creo que est\225 por[ENTER]ah\237. Buena suerte, jiji... "
gameforge.subquest_33._350_say = "Este debe ser el lugar. \161Hi ho![ENTER]Maldici\243n, el suelo parece ser bastante duro.[ENTER]Hmm...[ENTER]\161Eh, puedo ver una caja! "
gameforge.subquest_33._360_sendLetter = "\161El tesoro realmente existe! "
gameforge.subquest_33._370_sayTitle = "Vuelve con Soon "
gameforge.subquest_33._380_say = "\161Estabas cavando en el lugar que indicaba el Mapa[ENTER]de los Dioses Animales y de repente encontraste[ENTER]una Caja del Tesoro! Rep\243rtate con Soon e[ENTER]inf\243rmale sobre el \233xito inesperado. "
gameforge.subquest_33._390_npcChat = "\161He encontrado el tesoro! "
gameforge.subquest_33._400_say = "\161Oh! \161Que sorpresa! Veamos... Asombroso.[ENTER]As\237 es exactamente como estaba descrita la caja[ENTER]del tesoro en los textos antiguos. Ahora s\243lo[ENTER]tengo que averiguar c\243mo abrirla. Pero ese no es[ENTER]tu problema. \161Gracias, acepta esto como muestra[ENTER]de mi gratitud! "
gameforge.subquest_33._40_say = "Estos cuatro monstruos divinos dividieron el mapa[ENTER]en cuatro partes y ahora las protegen. Es un[ENTER]antiguo cuento de hadas, as\237 que no estoy[ENTER]completamente seguro... \191Qu\233 tal si lo[ENTER]compruebas? Por favor... yo no puedo hacerlo...[ENTER]Por favor, ay\250dame. "
gameforge.subquest_33._410_sayReward = "Has recibido 1.400.000 puntos de experiencia. "
gameforge.subquest_33._420_sayReward = "Has recibido 25.000 Yang "
gameforge.subquest_33._430_sayReward = "Has recibido un Sallet M\225scara Fant.+1 "
gameforge.subquest_33._440_sayReward = "Has recibido un Yelmo de Castillo+1. "
gameforge.subquest_33._450_sayReward = "Has recibido una Capilla de Acero+1. "
gameforge.subquest_33._460_sayReward = "Has recibido un Sombrero de Luz Solar+1. "
gameforge.subquest_33._470_say = "Bien, \191d\243nde est\225? \161\191Quieres reirte de mi?! En[ENTER]realidad no lo has encontrado, \191no? "
gameforge.subquest_33._50_say = "\191No estas interesado en mapas del tesoro? Eres[ENTER]raro... Voy a seguir buscando pistas en estos[ENTER]textos. Vuelve si cambias de opini\243n. "
gameforge.subquest_33._60_say = "No te gustan esas aventuras, \191no? \191C\243mo se supone[ENTER]que voy a conseguir yo las piezas del mapa?[ENTER][ENTER]Oh bueno... Adi\243s. "
gameforge.subquest_33._70_say = "Eres un verdadero amigo. Creo que los encontrar\225s. "
gameforge.subquest_33._80_sendLetter = "El mapa del tesoro del rat\243n de biblioteca. "
gameforge.subquest_33._90_targetVid = "Ve con el rat\243n de biblioteca. "
gameforge.subquest_34 = {}
gameforge.subquest_34._100_say = "El Capit\225n todav\237a tiene problemas para mantener[ENTER]bajo control al Clan del Viento Negro. Mata a los[ENTER]Generals del Clan del Viento Negro Jak-To, To-Su[ENTER]y Gu-Ryung.[ENTER]Quiz\225 se tranquilicen entonces. "
gameforge.subquest_34._10_npcChat = "\191Qu\233 est\225 haciendo el Clan Viento Negro? "
gameforge.subquest_34._110_say = "\161Los generales fueron asesinados! "
gameforge.subquest_34._120_select = "Prueba de nuevo "
gameforge.subquest_34._130_say = "\191Quieres abandonar la misi\243n para siempre? "
gameforge.subquest_34._140_say = "No es f\225cil ganar una lucha, especialmente contra[ENTER]los generales. Int\233ntalo de nuevo. "
gameforge.subquest_34._150_say = "Como dije, el Clan del Viento Negro es muy[ENTER]fuerte. Adi\243s. "
gameforge.subquest_34._160_say = "Eres realmente valiente. \161Creo que puedes[ENTER]derrotar al Clan del Viento Negro! "
gameforge.subquest_34._170_targetVid = "Informar al Capit\225n "
gameforge.subquest_34._180_say = "Vuelve con el Capit\225n e inf\243rmale de que has[ENTER]matado a los generales del Clan del Viento Negro. "
gameforge.subquest_34._185_npcChat = "\161He eliminado a todos los generales! "
gameforge.subquest_34._190_say = "Has derrotado a los generales y los otros[ENTER]miembros del clan son f\225ciles de derrotar sin los[ENTER]generales; nos ocuparemos del resto. Ten\237amos[ENTER]multitud de quebraderos de cabeza por culpa del[ENTER]Clan del Viento Negro, pero gracias a ti, lo[ENTER]haremos. Aqu\237 tienes una peque\241a recompensa.[ENTER]\161Espero volver a verte! "
gameforge.subquest_34._200_sayReward = "Recibes 1.000.000 puntos de experiencia. "
gameforge.subquest_34._20_sayTitle = "Capit\225n "
gameforge.subquest_34._210_sayReward = "Has recibido un Anillo del Idioma. "
gameforge.subquest_34._30_say = "Aunque derrotaste al Clan del Viento Negro, no[ENTER]quieren simplemente rendirse. En lugar de[ENTER]mantener un perfil bajo, se comportan como una[ENTER]horda salvaje. Si queremos derrotarlos, tenemos[ENTER]que matar a los generales del Clan del Viento[ENTER]Negro. "
gameforge.subquest_34._40_say = "Una vez que los generales sean derrotados, los[ENTER]otros miembros tambi\233n caer\225n. Ser\225 un trabajo[ENTER]duro, pero necesitamos una victoria sobre los[ENTER]generales del Clan del Viento Negro Jak-To, To-Su[ENTER]y Gu-Ryung. Si les derrotamos, no tendremos que[ENTER]preocuparnos nunca m\225s del Clan del Viento Negro.[ENTER]Buena suerte. Ruego por tu victoria. "
gameforge.subquest_34._50_say = "\191Quieres abandonar la misi\243n para siempre? "
gameforge.subquest_34._60_say = "Bien, vuelve cuando est\233s preparado. No hay mucha[ENTER]gente tan competente como tu. "
gameforge.subquest_34._70_say = "No puedes hacerlo...[ENTER]C\243mo derrotaremos ahora al Clan del Viento[ENTER]Negro... "
gameforge.subquest_34._80_say = "\161Sab\237a que pod\237a confiar en ti! Una vez que los[ENTER]generales hayan sido asesinados, los otros[ENTER]miembros del Clan del Viento Negro ya no ser\225n un[ENTER]problema nunca m\225s. \161Buena suerte! "
gameforge.subquest_34._90_sendLetter = "Mata a los generales del Clan del Viento Negro. "
gameforge.subquest_36 = {}
gameforge.subquest_36._100_sayTitle = "A ver al Chico del Establo "
gameforge.subquest_36._10_targetVid = "Yonah: "
gameforge.subquest_36._110_say = "Has recogido los 10 fardos de Heno. Ll\233vaselos al[ENTER]Chico del Establo para que pueda alimentar a los[ENTER]caballos. "
gameforge.subquest_36._120_sayTitle = "Heno para los establos "
gameforge.subquest_36._130_say = "Hay escasez de alimento en los establos.[ENTER]\161Consigue 10 Fardos de Heno y ll\233vaselos al Chico[ENTER]del Establo antes de que los caballos se mueran[ENTER]de hambre! Puedes conseguir el Heno cazando. "
gameforge.subquest_36._140_npcChat = "\191Necesitas Heno? "
gameforge.subquest_36._150_say = "\191Vienes porque te ha enviado Yonah? He oido mucho[ENTER]sobre ti. Oh, todos nuestros caballos se van a[ENTER]morir de hambre. Tenemos que salvarlos. \161Ay\250dame[ENTER]y consigue Heno para los caballos! "
gameforge.subquest_36._160_say = "Una promesa es una promesa. Tambi\233n querr\237a[ENTER]montar a caballo m\225s tarde. \161Definitivamente[ENTER]tengo que encontrar algo de Heno! "
gameforge.subquest_36._170_say = "Lo siento. Estoy buscando pero es sencillamente[ENTER]imposible encontrar Heno. "
gameforge.subquest_36._180_say = "Estoy esperando, deseando que lo puedas hacer. De[ENTER]acuerdo, no es bonito delegar mi trabajo en t\237,[ENTER]pero - \191puedes intentarlo de nuevo?[ENTER][ENTER]Conozco a una persona en el otro reino; es muy[ENTER]fuerte. Si me ayudas, le pedir\233 que te ayude. "
gameforge.subquest_36._190_select = "Intentarlo de nuevo "
gameforge.subquest_36._200_say = "Por supuesto, te ayudar\233. No tengo la fuerza. "
gameforge.subquest_36._20_npcChat = "Problemas en los establos "
gameforge.subquest_36._210_say = "No tengo suficiente energ\237a. Me gustar\237a[ENTER]ayudarte, pero no puedo. No soy lo[ENTER]suficientemente fuerte. "
gameforge.subquest_36._220_npcChat = "Tengo Heno para los caballos. "
gameforge.subquest_36._230_say = "\191Tienes el Heno? Oh, gracias. No ten\237amos[ENTER]suficiente comida para los caballos, as\237 que se[ENTER]lo dije a Yonah. Es muy buen amigo m\237o. Tuve la[ENTER]idea de que \233l pudiera preguntar por ah\237 para ver[ENTER]si alguien pod\237a ayudar. Pero no pensaba que[ENTER]pudiera resolverse tan r\225pido. \161Tan s\243lo mira con[ENTER]que entusiasmo est\225n comiendo los caballos! "
gameforge.subquest_36._240_sayReward = "Has recibido 1.800.000 puntos de experiencia. "
gameforge.subquest_36._250_sendLetter = "Vuelve con Yonah "
gameforge.subquest_36._260_sayTitle = "Vuelve con Yonah "
gameforge.subquest_36._270_say = "Le has llevado los 10 fardos de Heno para los[ENTER]caballos hambrientos al Chico del Establo. Vuelve[ENTER]con Yonah y cu\233ntale sobre tu logro. "
gameforge.subquest_36._280_npcChat = "\161Los caballos est\225n servidos! "
gameforge.subquest_36._290_say = "Hola, \161has vuelto![ENTER]Probablemente haya sido un duro trabajo el[ENTER]recoger tanto Heno. \161Gracias por no abandonar![ENTER]Aqu\237 tienes un peque\241o regalo. "
gameforge.subquest_36._300_sayReward = "Has recibido un Libro de Misi\243n. "
gameforge.subquest_36._30_say = "Eh, \161tengo una pregunta para t\237! Se que otro es[ENTER]responsable de los establos, pero hemos tenido[ENTER]muchos problemas recientemente y podr\237amos[ENTER]hacerlo con tu ayuda. Los caballos han tenido[ENTER]mucho que hacer durante la guerra, pero incluso[ENTER]un caballo adulto fuerte tiene sus l\237mites. "
gameforge.subquest_36._40_say = "Hay muchos caballos, pero no suficiente comida.[ENTER]Muchos caballos mueren. \191Puedes conseguir algo de[ENTER]comida para que los caballos puedan sobrevivir?[ENTER]Recoge 10 piezas de heno y ll\233valas. El chico del[ENTER]establo lo entender\225 si le dices que vas de mi[ENTER]parte. "
gameforge.subquest_36._50_select = "\161Salgo inmediatamente! "
gameforge.subquest_36._60_select = "No, es un trabajo sin importancia. "
gameforge.subquest_36._70_say = "Hoy en d\237a, m\225s y m\225s gente quiere un caballo.[ENTER]Pero no hay suficientes caballos para todos y[ENTER]tampoco comida suficiente para \233stos. Los[ENTER]caballos se mueren de hambre. Vuelve si cambias[ENTER]de parecer. "
gameforge.subquest_36._80_say = "Aaah, los caballos no tienen suficiente comida...[ENTER]Supongo que tendr\233 que afrontarlo... "
gameforge.subquest_36._90_say = "Se que est\225s ocupado y verdaderamente aprecio tu[ENTER]ayuda, \191pero no puedes hacer una excepci\243n? Los[ENTER]caballos son realmente importantes estos d\237as. Y[ENTER]realmente necesitamos el Heno. "
gameforge.subquest_37 = {}
gameforge.subquest_37._100_say = "Yonah est\225 dando lo mejor para producir la[ENTER]porcelana nueva pero no est\225 haciendo ning\250n[ENTER]progreso con sus experimentos. Ve con Uriel el[ENTER]erudito y preg\250ntale si sabe algo sobre la[ENTER]Porcelana Celadon. "
gameforge.subquest_37._10_targetVid = "El secreto de la porcelana Celadon "
gameforge.subquest_37._110_npcChat = "\191Conoces la Porcelana Celadon? "
gameforge.subquest_37._120_sayTitle = "Uriel: "
gameforge.subquest_37._130_say = "\191Porcelana celadon? Bien, se mucho de historia y[ENTER]ciencia, pero no estoy realmente interesado en el[ENTER]arte. No puedo decirte nada sobre porcelana[ENTER]celadon. Pero quiz\225 Soon sepa algo. No le gusta[ENTER]mucho a la gente, pero lee muchos libros[ENTER]distintos. Es bastante posible que sepa algo. "
gameforge.subquest_37._140_makequestbutton = "Ir con Soon "
gameforge.subquest_37._150_targetVid = "Ve con Soon "
gameforge.subquest_37._160_say = "Por desgracia Uriel no sabe nada sobre la[ENTER]Porcelana Celadon. Pero Soon el rat\243n de[ENTER]biblioteca lee mucho en sus libros. Ve a verle y[ENTER]preg\250ntale si sabe algo sobre su composici\243n. "
gameforge.subquest_37._170_sayTitle = "Soon: "
gameforge.subquest_37._180_say = "\191Qu\233 quieres? \161No me molestes cuando estoy[ENTER]leyendo! \191Huh? \191Porcelana Celadon? Por supuesto[ENTER]que la conozco. He le\237do casi una docena de[ENTER]libros sobre ese tema. \191Por qu\233? Bueno, \161no me[ENTER]llaman \"rat\243n de biblioteca\" por nada, sabes![ENTER]\161Puedo entender todo lo que ha sido escrito en[ENTER]libros! "
gameforge.subquest_37._190_say = "Podr\237a anotar c\243mo hacer Porcelana Celandon con[ENTER]lo que puedo recordar, \191pero por qu\233 deber\237a[ENTER]hacer eso? Hmm. Bueno, espera, tengo una idea: le[ENTER]ped\237 a Peddler en la aldea vecina un libro que me[ENTER]falta pero no tengo tiempo de ir. Por favor,[ENTER]c\243gelo por mi, entonces te ayudar\233 con la[ENTER]porcelana. \161Ve! "
gameforge.subquest_37._200_makequestbutton = "Visitar a Peddler "
gameforge.subquest_37._20_sayTitle = "Yonah: "
gameforge.subquest_37._210_targetVid = "Visita a Peddler "
gameforge.subquest_37._220_say = "Soon el rat\243n de biblioteca sabe todo acerca de[ENTER]la Porcelana Celadon. No quiere compartir su[ENTER]conocimiento sin obtener nada a cambio.[ENTER]Ve con Peddler a recoger el Libro que Soon ha[ENTER]encargado. "
gameforge.subquest_37._230_npcChat = "Soon me env\237a... "
gameforge.subquest_37._240_say = "Hey, \191vuelves a ayudarme de nuevo? Ahh. Quieres[ENTER]el libro para Soon. Habr\237a ido pronto a la ciudad[ENTER]de todos modos, pero es muy impaciente y le pide[ENTER]a otros que lo recojan. Hmm. Aqu\237 est\225. No[ENTER]entiendo qu\233 le gusta a Soon de este mont\243n de[ENTER]papeles. \161Es mucho m\225s importante ganar Yang[ENTER]r\225pidamente! "
gameforge.subquest_37._250_qSetTitle = "Volver con Soon "
gameforge.subquest_37._260_targetVid = "Volver con Soon "
gameforge.subquest_37._270_say = "Has conseguido el libro de Soon de Peddler.[ENTER]Vuelve con Soon y entr\233gale el libro para que te[ENTER]diga c\243mo hacer Porcelana Celadon. "
gameforge.subquest_37._280_npcChat = "Tengo el libro "
gameforge.subquest_37._290_say = "\161S\237! \161Al fin tengo el libro nuevo! Muchas[ENTER]gracias. No hay muchos libros que no haya[ENTER]le\237do... He escrito lo que es importante para[ENTER]hacer Porcelana Celadon. Sigue mis notas y[ENTER]producir\225s porcelana fant\225stica. Es mi hora de[ENTER]leer el libro nuevo. Adi\243s. "
gameforge.subquest_37._300_makequestbutton = "Vuelve con Yonah "
gameforge.subquest_37._30_say = "Hmm... \201ste no es bueno. Ni \233ste otro... Oh,[ENTER]\161hola! Mira: produzco porcelana sin parar, pero[ENTER]la mayor\237a se rompe inmediatamente. Creo que[ENTER]necesito un nuevo tipo de porcelana[ENTER]vanguardista... "
gameforge.subquest_37._310_targetVid = "Lleva las notas a Yonah "
gameforge.subquest_37._320_say = "Soon ha mantenido su promesa y ha escrito c\243mo[ENTER]hacer Porcelana Celadon. Ll\233vaselo a Yonah. "
gameforge.subquest_37._330_say = "\161\161\161Ooh!!![ENTER]Aqu\237 est\225 escrito todo sobre la producci\243n de[ENTER]Porcelana Celadon. Con la ayuda de estas notas[ENTER]finalmente voy a pasar a la historia como un[ENTER]maestro artesano. Gracias por tu ayuda. \161Pronto[ENTER]podr\233 ense\241arte mi mejor trabajo de cer\225mica![ENTER]\161Puedes confiar en mi! Voy a producir una[ENTER]Porcelana Celadon tan fant\225stica que va a[ENTER]perdurar por siglos. "
gameforge.subquest_37._340_sayReward = "Recibes 2.500.000 puntos de experiencia. "
gameforge.subquest_37._350_sayReward = "Has recibido 35.000 Yang. "
gameforge.subquest_37._360_sayReward = "Has recibido Zapatos de Jade+3 "
gameforge.subquest_37._40_say = "Probar\233 un nuevo m\233todo... No es f\225cil fabricar[ENTER]porcelana celadon. Por eso s\243lo unos pocos saben[ENTER]c\243mo hacerla. Sin embargo, necesito saberlo para[ENTER]mi arte. En ese caso... S\237, Uriel puede que sepa[ENTER]algo sobre ello. Por favor, visita a Uriel y[ENTER]preg\250ntale acerca de fabricar porcelana celadon.[ENTER]\161Seguro que puede ayudarte! "
gameforge.subquest_37._50_say = "\191Quieres abandonar la misi\243n para siempre? "
gameforge.subquest_37._60_say = "Hm, \191est\225s muy ocupado?[ENTER]Recuerda volver a verme cuando tengas m\225s tiempo. "
gameforge.subquest_37._70_say = "Quiero fabricar la mejor porcelana...[ENTER]Entiendo... nos vemos... "
gameforge.subquest_37._80_say = "Gracias. Uriel sabr\225 qu\233 hacer. \161Nos vemos pronto! "
gameforge.subquest_37._90_targetVid = "Vamos con Uriel "
gameforge.subquest_38 = {}
gameforge.subquest_38._100_say = "El Arco Espl\233ndidamente Adornado del cazador, que[ENTER]es una reliquia de familia, le ha sido robado. Ve[ENTER]a Sangsun Dong y recupera el Arco Adornado de los[ENTER]monos ladrones. "
gameforge.subquest_38._10_targetVid = "El tesoro del cazador "
gameforge.subquest_38._110_sendLetter = "Arco Espl\233ndidamente Adornado encontrado "
gameforge.subquest_38._120_targetVid = "Ve con el cazador Yang-Shin "
gameforge.subquest_38._125_say = "Has encontrado el Arco Espl\233ndido Adornado del[ENTER]Cazador. Ll\233valo de vuelta a Yang-Shin. "
gameforge.subquest_38._130_npcChat = "Aqu\237 est\225 el arco... "
gameforge.subquest_38._140_say = "\161Wow! \161Este es! \161Mi arco, s\237! Mi honor ha sido[ENTER]recuperado. Fiu. He estado sufriendo durante[ENTER]tanto tiempo desde que lo perd\237... Estoy[ENTER]verdaderamente agradecido por tu ayuda. Es un[ENTER]honor para m\237 darte esto. Puede que no parezca[ENTER]gran cosa, pero te lo doy de coraz\243n as\237 que[ENTER]c\243gelo. Gracias a ti, \161puedo continuar con mi[ENTER]vida en paz! "
gameforge.subquest_38._150_sayReward = "Has recibido 1.500.000 puntos de experiencia. "
gameforge.subquest_38._160_sayReward = "Has recibido 35.000 Yang. "
gameforge.subquest_38._170_sayReward = "Has recibido una Capa de valor. "
gameforge.subquest_38._180_say = "\191Has encontrado mi Arco? \191Pero d\243nde est\225? \191Lo[ENTER]has perdido otra vez? "
gameforge.subquest_38._190_select = "Seguir\233 buscando. "
gameforge.subquest_38._200_say = "Que as\237 sea.[ENTER]Cu\237date. "
gameforge.subquest_38._20_say = "Eh, \191puedes escucharme un segundo? Como puedes[ENTER]ver, soy un cazador; mi familia ha estado cazando[ENTER]durante generaciones. Todos nosotros hemos sido[ENTER]cazadores, una familia muy honorable. Pero comet\237[ENTER]un grave error que va a deshonrarme delante de[ENTER]toda mi familia... "
gameforge.subquest_38._210_say = "\191Puedes intentarlo de nuevo? Gracias.[ENTER]Con tus habilidades, ser\225s capaz de hacerlo. "
gameforge.subquest_38._30_say = "Es sobre un Arco Espl\233ndidamente Adornado que fue[ENTER]robado por monos hace un tiempo. Estaba cazando[ENTER]en la Mazmorra de los Mono entonces y solo estuve[ENTER]distraido por un segundo - tomaron ventaja de la[ENTER]situaci\243n y me lo robaron. "
gameforge.subquest_38._40_say = "Nunca me he adentrado en las profundidades[ENTER]Sangsun Dong, as\237 que realmente no conozco el[ENTER]camino y necesito tu ayuda. Unos cuantos de por[ENTER]aqu\237 me han dicho que tienes mucho talento. Por[ENTER]eso te he pedido este favor. No puedo afrontar a[ENTER]mis ancestros sin mi Arco Adornado. "
gameforge.subquest_38._50_sayTitle = "Yang-Shin: "
gameforge.subquest_38._60_say = "Oh, lo necesito de vuelta tan pronto como sea[ENTER]posible...[ENTER]Por favor, vuelve si tienes m\225s tiempo. Nos vemos. "
gameforge.subquest_38._70_say = "Entonces bien...[ENTER]Ten cuidado en tus viajes. "
gameforge.subquest_38._80_say = "Lo reconocer\225s f\225cilmente, porque es un arco[ENTER]suntuosamente decorado. \161Te recompensar\233 muy[ENTER]bien! "
gameforge.subquest_38._90_sayTitle = "Busca el Arco Espl\233ndidamente Adornado "
gameforge.subquest_39 = {}
gameforge.subquest_39._100_sayTitle = "La enfermedad de Balso "
gameforge.subquest_39._10_targetVid = "Entrega para Balso, el traidor "
gameforge.subquest_39._110_say = "La salud de Balso el Traidor ha empeorado. Ve con[ENTER]Baek-Go y preg\250ntale c\243mo podemos ayudar a Balso. "
gameforge.subquest_39._120_makequestbutton = "Ve con Baek-Go "
gameforge.subquest_39._130_qSetTitle = "Ve con Baek-Go "
gameforge.subquest_39._140_targetVid = "Visita a Baek-Go. "
gameforge.subquest_39._150_npcChat = "Tengo un paciente... "
gameforge.subquest_39._160_sayTitle = "Baek-Go: "
gameforge.subquest_39._170_say = "Oh, eres t\250, \191c\243mo est\225s? \191Est\225s tratando a un[ENTER]paciente enfermo? Dime qu\233 le ocurre...[ENTER]Hmm.. \191Y qu\233 medicina ha estado tomando?[ENTER]\161\191Qu\233?! \161No me extra\241a que est\233 empeorando! \161Esta[ENTER]medicina es totalmente inadecuada! "
gameforge.subquest_39._180_say = "\161Tiene suerte de estar vivo todav\237a! \161Es muy[ENTER]peligroso darle a una persona enferma el[ENTER]tratamiento equivocado! Pero yo s\233 lo que le[ENTER]ayudar\225. Hay una determinada hierba que libra al[ENTER]cuerpo del veneno y repondr\225 su salud.[ENTER]Sin embargo, buscarla es muy peligroso. "
gameforge.subquest_39._190_say = "Por lo que s\233, la hierba s\243lo crece en Sangsun[ENTER]dong. Pero siempre es cosechada por el Se\241or[ENTER]Mono, ya que le gusta comerla. Tendr\225s que[ENTER]matarle para conseguirla.[ENTER]Puedo hacer la medicina correcta si me traes la[ENTER]hierba. "
gameforge.subquest_39._200_select = "Bien, la conseguir\233. "
gameforge.subquest_39._20_npcChat = "Sobre tu medicina... "
gameforge.subquest_39._210_select = "No puedo hacerlo "
gameforge.subquest_39._220_say = "\191Quieres abandonar la misi\243n para siempre? "
gameforge.subquest_39._230_select = "S\237 "
gameforge.subquest_39._240_say = "Bien, quiz\225 cuando tengas algo de tiempo libre.[ENTER]Mucha gente est\225 enferma, pero solo unos pocos[ENTER]buscan una cura... "
gameforge.subquest_39._250_say = "Hmm, las cosas como son. Es una verg\252enza que[ENTER]nadie sea lo suficientemente valiente. C\243mo va a[ENTER]acabar todo esto... "
gameforge.subquest_39._260_say = "Oh, gracias. \161Va a ser un trabajo duro pero[ENTER]estar\225s ayudando a mucha gente! "
gameforge.subquest_39._270_makequestbutton = "Hierba del Se\241or Mono "
gameforge.subquest_39._280_targetVid = "Regresar con Baek-Go "
gameforge.subquest_39._290_sayTitle = "Hierba de Monos Dif\237cil encontrada "
gameforge.subquest_39._300_say = "Has cogido la Hierba de Monos Dif\237cil del Se\241or[ENTER]Mono. Ll\233vasela a Baek-Go, para que pueda hacer[ENTER]la medicina para Balso. "
gameforge.subquest_39._30_say = "Gracias por traerme la medicina la \250ltima vez.[ENTER]Pero hay un problema... La medicina ya no me[ENTER]ayuda. Creo que se ha puesto mala.[ENTER]*tos* Necesito tratamiento. "
gameforge.subquest_39._310_sayTitle = "Consigue la hierba en Sangsun Dong "
gameforge.subquest_39._320_say = "Baek-Go puede hacer una medicina para la[ENTER]enfermedad de Balso el traidor. Necesita Hierba[ENTER]de Monos Dif\237cil para ello. Puedes conseguirla[ENTER]del Se\241or Mono en la Mazmorra de Monos Experto. "
gameforge.subquest_39._330_npcChat = "Hierba de Monos Dif\237cil... "
gameforge.subquest_39._340_say = "Parece como si la enfermedad se estuviera[ENTER]extendiendo como una epidemia, pero no sabemos la[ENTER]causa. Sin embargo, la organizaci\243n de[ENTER]profesionales nos dijo que es posible hacer una[ENTER]cura con Hierba de Monos. \191Qu\233 pasa? \191Ya has[ENTER]encontrado la hierba? "
gameforge.subquest_39._350_select = "Todav\237a no. \161Pero ser\225 pronto! "
gameforge.subquest_39._360_select = "No puedo conseguir la hierba... "
gameforge.subquest_39._370_say = "\191De verdad quieres abandonar? Hmm, supongo que en[ENTER]realidad no puedes hacer nada m\225s que eso. \191Qu\233[ENTER]har\233? Esta hierba ser\237a una verdadera[ENTER]bendici\243n... "
gameforge.subquest_39._380_select = "No puedo hacerlo. "
gameforge.subquest_39._390_select = "\161Quiero ayudar! "
gameforge.subquest_39._400_say = "Los monos son demasiado fuertes para mi. No puedo[ENTER]llegar a la hierba. Lo siento. "
gameforge.subquest_39._40_say = "S\233 que hay un doctor que vive en la siguiente[ENTER]aldea. \191Podr\237as ir a verle y explicarle c\243mo me[ENTER]siento, para que te pueda decir qu\233 se puede[ENTER]hacer? Como puedes observar, no puedo abandonar[ENTER]la aldea en esta condici\243n. Me siento muy[ENTER]agradecido de que me ayudases la otra vez, y ten[ENTER]por seguro que esta vez te recompensar\233 tambi\233n. "
gameforge.subquest_39._410_say = "Rechazas ayudar a la gente que esta sufriendo de[ENTER]una enfermedad terrible y misteriosa. \161Largo de[ENTER]mi vista! "
gameforge.subquest_39._420_say = "Tienes raz\243n. Alguien tiene que conseguir esta[ENTER]hierba o toda esa gente enferma sufrir\225[ENTER]terriblemente. Me encargar\233 de esto. "
gameforge.subquest_39._430_say = "Bien pues... \161date prisa! "
gameforge.subquest_39._440_say = "\161Realmente te las has arreglado para conseguir la[ENTER]Hierba de Monos Dif\237cil! Espero que pueda curar[ENTER]esta enfermedad misteriosa de verdad. Espera un[ENTER]segundo, har\233 r\225pidamente la medicina ahora... "
gameforge.subquest_39._450_sayTitle = "Baek-Go: "
gameforge.subquest_39._460_say = "Aqu\237 est\225 la medicina. Ve r\225pido con el paciente[ENTER]y d\225sela. Entonces deber\237a mejorar pronto. Por[ENTER]favor, dile tambi\233n que siempre es mejor[ENTER]preguntar a un m\233dico qu\233 medicina es la[ENTER]correcta. "
gameforge.subquest_39._470_makequestbutton = "Lleva la medicina a Balso "
gameforge.subquest_39._480_targetVid = "Le das la medicina a Balso. "
gameforge.subquest_39._490_sayTitle = "La medicina de Balso "
gameforge.subquest_39._500_say = "Baek-Go ha hecho medicina de la Hierba de Monos[ENTER]Dif\237cil que puede curar muchas enfermedades[ENTER]raras. Ll\233vasela al Traidor Balso en la aldea[ENTER]vecina. "
gameforge.subquest_39._50_say = "\191Quieres abandonar esta misi\243n? "
gameforge.subquest_39._510_npcChat = "Aqu\237 est\225 la medicina "
gameforge.subquest_39._520_say = "\191Me traes la medicina nueva? \191Ha habido progresos[ENTER]en investigaci\243n m\233dica? Siento causarte[ENTER]molestias. Deber\237a haber pedido consejo a un[ENTER]m\233dico desde el principio. Sin embargo, tengo que[ENTER]aceptar que debo tomar esta medicina ahora. "
gameforge.subquest_39._530_say = "Gracias por ayudarme a salir de mi miserable[ENTER]condici\243n. No tengo muchos amigos. Toma, s\233 que[ENTER]no es mucho, pero te lo doy de coraz\243n. Por favor[ENTER]ac\233ptalo. Si alguna vez lo logro, nunca te[ENTER]olvidar\233. "
gameforge.subquest_39._540_sayReward = "Recibes 4.000.000 puntos de experiencia. "
gameforge.subquest_39._550_sayReward = "Has recibido 65.000 Yang. "
gameforge.subquest_39._60_say = "Si te enteras de c\243mo ayudarme, nos encontraremos[ENTER]aqu\237 de nuevo. "
gameforge.subquest_39._70_sayTitle = "Balso el traidor: "
gameforge.subquest_39._80_say = "Veo que tengo que seguir viviendo de este modo...[ENTER]Adi\243s... "
gameforge.subquest_39._90_say = "Gracias... ten cuidado. "
gameforge.subquest_40 = {}
gameforge.subquest_40._100_say = "\161Sab\237a que pod\237a contar contigo! Es un trabajo[ENTER]dif\237cil, pero estoy seguro de que podr\225s hacerlo.[ENTER]\161Buena suerte! "
gameforge.subquest_40._10_targetVid = "Dispositivo de soporte de guerra "
gameforge.subquest_40._110_targetVid = "Regresar con el Capit\225n. "
gameforge.subquest_40._120_say = "Has recogido las 5.000 Puntas de Flecha.[ENTER]Ll\233vaselas al Capit\225n. "
gameforge.subquest_40._130_say = "El ej\233rcito tiene problemas para conseguir m\225s[ENTER]flechas. Mata Arqueros Plaga en el Monte Sohan y[ENTER]consigue sus Puntas de Flecha para el Capit\225n.[ENTER]5.000 son suficientes. "
gameforge.subquest_40._140_npcChat = "Sobre las Puntas de Flecha... "
gameforge.subquest_40._150_say = "Esos Arqueros Plaga tienen una determinada[ENTER]enfermedad que se ha extendido por el continente.[ENTER]Ni los m\233dicos pueden explicarlo. Las Puntas de[ENTER]Flecha son normales por ahora, pero se estan[ENTER]volviendo m\225s y m\225s t\243xicas. "
gameforge.subquest_40._160_select = "Continuar\233. "
gameforge.subquest_40._170_say = "\191Quieres abandonar la misi\243n para siempre? "
gameforge.subquest_40._180_say = "Tienes miedo de la enfermedad. Traquil\237zate y[ENTER]vuelve m\225s tarde. "
gameforge.subquest_40._190_say = "\191Est\225s seguro de que quieres rendirte? Hmm, quiz\225[ENTER]es demasiado duro. Se lo pedir\233 a otro... Bien,[ENTER]nos vemos. "
gameforge.subquest_40._200_say = "Ya veo...[ENTER]Nunca te rindes, \191no?[ENTER]\161Vamos! "
gameforge.subquest_40._20_say = "\161Atenci\243n guerreros! Como pod\233is ver, el n\250mero[ENTER]de ataques por parte de nuestros enemigos est\225[ENTER]aumentando cada d\237a. Tambi\233n hemos recibido[ENTER]informaci\243n alarmante de Yu-Hwan. Resumiendo: \161No[ENTER]tenemos suficientes flechas! "
gameforge.subquest_40._210_npcChat = "\161Aqu\237 hay 5.000 Puntas de Flecha! "
gameforge.subquest_40._220_say = "\161Un trabajo fant\225stico! Ahora podemos prepararnos[ENTER]para el ataque. Voy a darte la orden[ENTER]inmediatamente para hacer algunas flechas. Eso ha[ENTER]sido un verdadero esfuerzo de equipo. Espero que[ENTER]podamos contar contigo m\225s tarde. "
gameforge.subquest_40._230_say = "Aqu\237 est\225 tu recompensa. La pr\243xima vez que tenga[ENTER]un trabajo importante, ser\225s el primero al que[ENTER]llame. \161Nos vemos! \161Te deseo todo lo mejor! "
gameforge.subquest_40._240_sayReward = "Recibes 4.500.000 puntos de experiencia. "
gameforge.subquest_40._250_sayReward = "Obtienes 50.000 Yang. "
gameforge.subquest_40._260_sayReward = "Has recibido 3 x Lucha Cr\237tica.[ENTER]Has recibido 3 x Lucha Perforadora. "
gameforge.subquest_40._30_say = "Los arqueros son un factor estrat\233gico importante[ENTER]en la guerra. Tan pronto como los enemigos est\225n[ENTER]a su alcance, nuestros arqueros deben[ENTER]dispararles. De ese modo podemos ahuyentarles[ENTER]inmediatamente o, al menos, reducir su n\250mero.[ENTER]Pero si hay demasiados ataques en un corto[ENTER]periodo, nos quedamos pronto sin flechas. "
gameforge.subquest_40._40_say = "\161Por eso te necesitamos! Ve al Monte Sohan y mata[ENTER]Arqueros Plaga para conseguir sus Puntas de[ENTER]Flecha. Esas Puntas de Flecha son venenosas pero[ENTER]su efecto nos ayudar\225 a derrotar al enemigo.[ENTER]Necesitamos 5.000 Puntas de Flecha. \191Qu\233 dices? "
gameforge.subquest_40._50_select = "Acepto. "
gameforge.subquest_40._60_select = "Eso es demasiado para mi. "
gameforge.subquest_40._70_say = "\191Quieres abandonar la misi\243n para siempre? "
gameforge.subquest_40._80_say = "\191El Monte Sohan est\225 demasiado lejos para ti?[ENTER]Pi\233nsalo. Esta misi\243n es de suma importancia. "
gameforge.subquest_40._90_say = "Hum, \191asustado de los arqueros plaga?[ENTER]Parece que te he sobreestimado.[ENTER]Ahora, ya no queda esperanza... "
gameforge.subquest_41 = {}
gameforge.subquest_41._015_npcChat = "\191Qu\233 est\225s leyendo? "
gameforge.subquest_41._100_say = "Has recogido los 100 Ojos de Ara\241a para la nueva[ENTER]receta de Octavio. Deber\237as llev\225rselos[ENTER]r\225pidamente. "
gameforge.subquest_41._10_targetVid = "Plato del d\237a: ojos de ara\241a "
gameforge.subquest_41._110_sayTitle = "Consigue Ojos de Ara\241a "
gameforge.subquest_41._120_say = "Octavio quiere poner en pr\225ctica su nueva receta[ENTER]llamada \"Especial Ojos de Ara\241a\". Para hacerla[ENTER]necesita 100 Ojos de Ara\241a de las ara\241as del[ENTER]desierto Yongbi. "
gameforge.subquest_41._130_targetVid = "Vuelve con Octavio "
gameforge.subquest_41._140_npcChat = "Tengo los Ojos de Ara\241a. "
gameforge.subquest_41._150_sayTitle = "Octavio: "
gameforge.subquest_41._160_say = "Ens\233\241amelas. Exactamente cien ojos, muy bien.[ENTER]Bien, veamos...[ENTER]Mmhhh, \161hecho! \191Quieres probarlo tambi\233n? No lo[ENTER]mires tan horrorizado. No te va a matar. "
gameforge.subquest_41._170_say = "Hmm, hmm... \161Qu\233 experiencia! Muy nutritivo, no[ENTER]demasiado dulce... \161un sabor incre\237ble! Sab\237a que[ENTER]valdr\237a la pena el esfuerzo. Nunca podr\237a haberlo[ENTER]hecho sin ti. \161Muchas gracias por tu ayuda! "
gameforge.subquest_41._180_sayReward = "Has recibido 2.100.000 puntos de experiencia. "
gameforge.subquest_41._190_say = "\191De qu\233 est\225s hablando? Eso no son cien ojos,[ENTER]\161puedo dec\237rtelo sin contarlos![ENTER]Por favor, consigue m\225s. "
gameforge.subquest_41._200_say = "Verdaderamente quer\237a hacerlo...[ENTER]No importa, gracias. Adi\243s. "
gameforge.subquest_41._20_say = "Eh, \191c\243mo est\225s? Ahora mismo estoy leyendo un[ENTER]libro de cocina que me di\243 Soon muy amablemente.[ENTER]Encontr\233 una receta muy interesante llamada[ENTER]\"Especial Ojos de Ara\241a\". \161Nunca hab\237a visto nada[ENTER]parecido! \191Y t\250? Parece que es un plato especial[ENTER]de otro pa\237s. "
gameforge.subquest_41._210_say = "Gracias por no dejarme en la estacada.[ENTER]\161Eres muy amable! "
gameforge.subquest_41._30_say = "Realmente me encantar\237a probar este plato, \191pero[ENTER]c\243mo se supone que voy a conseguir los Ojos de[ENTER]Ara\241a? \161Necesito tu ayuda de nuevo! Por favor,[ENTER]consigue Ojos de Ara\241a de las Ara\241as en el[ENTER]Desierto Yongbi. "
gameforge.subquest_41._40_say = "\191Podr\237as hacerlo por mi? Estar\237a muy agradecido.[ENTER]Para hacer esta receta necesito cien ojos para[ENTER]una porci\243n de tama\241o razonable. Estoy muy[ENTER]emocionado... "
gameforge.subquest_41._50_say = "\191Quieres abandonar la misi\243n para siempre? "
gameforge.subquest_41._60_say = "Verdaderamente quiero hacer esto, as\237 que si[ENTER]tienes ganas de hacerme un favor, vuelve. "
gameforge.subquest_41._70_say = "Hmmm... \191de d\243nde voy a conseguir esos ojos?[ENTER]Est\225 bien, nos vemos. "
gameforge.subquest_41._80_say = "Gracias. Sab\237a que me har\237as este favor. Te[ENTER]obsequiar\233 con una exquisita comida. "
gameforge.subquest_41._90_sayTitle = "Vuelve con Octavio "
gameforge.subquest_42 = {}
gameforge.subquest_42._100_say = "Siento o\237r eso. Escucho tantas voces de gente[ENTER]muerta, quienes no pueden descansar en paz.[ENTER]Verdaderamente tenemos que ayudarles. Pedir\233[ENTER]ayuda a otro. Adi\243s. "
gameforge.subquest_42._10_targetVid = "Por el descanso de los muertos "
gameforge.subquest_42._110_say = "Que valiente eres. Estoy seguro que los valientes[ENTER]guerreros j\243venes llegar\225n pronto al Nirvana con[ENTER]tu ayuda. "
gameforge.subquest_42._120_say = "Guerras terribles matan a hombres j\243venes. Luchan[ENTER]en primera l\237nea, peleando por ellos mismos, sus[ENTER]familias y sus pa\237ses. Pero despu\233s de la muerte,[ENTER]algunos de ellos no van al cielo y permanecen en[ENTER]este mundo. "
gameforge.subquest_42._130_say = "He oido que el Coronel Oscuro Soberbio en el[ENTER]Templo Hwang tiene aparentemente una Bufanda[ENTER]Temple y una Doctrina Temple. Por favor, ay\250danos[ENTER]a m\237 y a mis camaradas a calmar a aquellos que[ENTER]murieron por su pa\237s. "
gameforge.subquest_42._140_sayTitle = "Vuelve con el Maestro Fuerza Drag\243n "
gameforge.subquest_42._150_say = "Has encontrado una Bufanda Temple y una Doctrina[ENTER]Temple. Ll\233vaselas al Maestro Fuerza Drag\243n, para[ENTER]que los Chamanes puedan empezar su ritual para[ENTER]calmar a los muertos. "
gameforge.subquest_42._160_sayTitle = "Consigue el templo bufanda y la doctrina templo. "
gameforge.subquest_42._170_say = "Los Chamanes necesitan una Bufanda Temple y una[ENTER]Doctrina Temple para una ceremonia para calmar[ENTER]los esp\237ritus de los soldados que murieron[ENTER]durante la guerra.[ENTER]Mata al Coronel Oscuro Soberbio en el Templo[ENTER]Hwang para conseguir los objetos del ritual. "
gameforge.subquest_42._180_npcChat = "Tengo la Bufanda y la Doctrina. "
gameforge.subquest_42._190_say = "Eso ha sigo genial. Ahora podemos calmar a los[ENTER]soldados muertos. Dieron lo mejor. Ahora, pueden[ENTER]descansar en paz. D\233jame darte una recompensa por[ENTER]tu noble acci\243n. "
gameforge.subquest_42._200_sayReward = "Has recibido 1.700.000 puntos de experiencia. "
gameforge.subquest_42._20_sayTitle = "Maestro de la Fuerza Drag\243n: "
gameforge.subquest_42._210_sayReward = "Has recibido 30.000 Yang. "
gameforge.subquest_42._220_sayReward = "Has recibido 3 Diamantes. "
gameforge.subquest_42._230_say = "Eso ha sigo genial. Ahora podemos calmar a los[ENTER]soldados muertos. Dieron lo mejor. Ahora, pueden[ENTER]descansar en paz. D\233jame darte una recompensa por[ENTER]tu noble acci\243n. "
gameforge.subquest_42._30_say = "Guerras terribles matan a hombres j\243venes. Luchan[ENTER]en primera l\237nea, peleando por ellos mismos, sus[ENTER]familias y sus pa\237ses. Pero despu\233s de la muerte,[ENTER]algunos de ellos no van al cielo y permanecen en[ENTER]este mundo. "
gameforge.subquest_42._40_say = "Se dice que se volvieron resistentes a la muerte[ENTER]durante la guerra. Creen que todav\237a tienen que[ENTER]defender su pa\237s.[ENTER]Nuestros Chamanes quieren celebrar una ceremonia[ENTER]para calmar a los esp\237ritus. Para hacerlo,[ENTER]necesitamos una Bufanda Temple especial y una[ENTER]Doctrina Temple, que son dif\237ciles de encontrar[ENTER]actualmente. \191Podr\237as conseguir ambas cosas para[ENTER]nosotros? "
gameforge.subquest_42._50_say = "He oido que el Coronel Oscuro Soberbio en el[ENTER]Templo Hwang tiene aparentemente una Bufanda[ENTER]Temple y una Doctrina Temple. Por favor, ay\250danos[ENTER]a m\237 y a mis camaradas a calmar a aquellos que[ENTER]murieron por su pa\237s. "
gameforge.subquest_42._60_select = "Te ayudar\233 "
gameforge.subquest_42._70_select = "Lo siento, estoy asustado. "
gameforge.subquest_42._80_say = "\191Quieres abandonar la misi\243n para siempre? "
gameforge.subquest_42._90_say = "Ay\250danos a tranquilizar sus almas para que puedan[ENTER]descansar en paz. Te estar\233 esperando aqu\237. "
