gameforge.subquest_44._130_sendLetter = "No puedo encontrar una campana "
gameforge.subquest_44._140_sayTitle = "Muchas ara\241as, ninguna campana "
gameforge.subquest_44._150_say = "Has matado algunas ara\241as pero no has encontrado[ENTER]una campana. No puedes buscar para siempre.[ENTER]Probablemente ser\237a mejor ir con Taurean y[ENTER]preguntarle por la verdad. "
gameforge.subquest_44._160_sendLetter = "Ve con Taurean "
gameforge.subquest_44._170_targetVid = "Pregunta a Taurean sobre la campana "
gameforge.subquest_44._180_say = "Es improbable que Taurean fuera lo[ENTER]suficientemente valiente como para poner una[ENTER]campana en una ara\241a. Es mejor preguntarle[ENTER]directamente por la verdad. "
gameforge.subquest_44._190_npcChat = "Cu\233ntame, sobre tu apuesta con Yu-Rang... "
gameforge.subquest_44._200_say = "\191Conoces la apuesta con Yu-Rang? No me cree y[ENTER]piensa que no lo hice. Cree que me caer\237a muerto[ENTER]con s\243lo mirar a una ara\241a gigante. "
gameforge.subquest_44._20_npcChat = "\191Una ara\241a con una campana...? "
gameforge.subquest_44._210_say = "Para ser honesto... Tiene raz\243n. No fu\237 lo[ENTER]suficientemente valiente para cont\225rselo porque[ENTER]soy demasiado orgulloso. "
gameforge.subquest_44._220_say = "\161Pero t\250 pareces muy fuerte! \191Puedes poner la[ENTER]campana en una cr\237a ara\241a por m\237 y decir que fui[ENTER]yo? Por favor, por favor. De lo contrario se[ENTER]reir\225n de m\237 durante el resto de mi vida. "
gameforge.subquest_44._230_say = "\191Quieres abandonar la misi\243n para siempre? "
gameforge.subquest_44._240_say = "\191No quieres hacerlo? \191Pero no le vas a contar a[ENTER]Yu-Rang la verdad?[ENTER]Por favor, ay\250dame. \161Vuelve cuando tengas tiempo[ENTER]para m\237! "
gameforge.subquest_44._250_say = "\161Ahora Yu-Rang no me hablar\225 nunca m\225s![ENTER]O tan s\243lo se reir\225 de m\237... "
gameforge.subquest_44._260_say = "Ah, ten\237a raz\243n. Sab\237a que ser\237as tan simp\225tico[ENTER]como pareces. Gracias por tu ayuda. \161Buena[ENTER]suerte! "
gameforge.subquest_44._270_sendLetter = "Volver con Yu-Rang "
gameforge.subquest_44._280_say = "Volver con Yu-Rang y contarle la mentira de[ENTER]Taurean. "
gameforge.subquest_44._290_npcChat = "Yu-Rang est\225 muy decepcionada contigo. "
gameforge.subquest_44._300_say = "\161\191Se lo has contado?![ENTER]Puedo entender que ya no quiera ser mi amiga[ENTER]nunca m\225s. Pero me pone muy triste. Espero poder[ENTER]hacerle cambiar de opini\243n alg\250n d\237a. Quiz\225 pueda[ENTER]pensar en algo bonito para ella... "
gameforge.subquest_44._30_say = "Eh, \191podr\237as hacerme un favor? Mi amigo Taurean[ENTER]est\225 muy enfadado porque le llam\233 cobarde. Dice[ENTER]que en realidad es muy valiente y apost\243 conmigo[ENTER]que se las arreglar\237a para colgar una campana en[ENTER]una Cr\237a Ara\241a. Tambi\233n me dijo que ya lo hab\237a[ENTER]hecho, pero no le creo. "
gameforge.subquest_44._310_npcChat = "Taurean minti\243. "
gameforge.subquest_44._320_say = "\191Su historia no es cierta?[ENTER]Hmm, no estoy realmente enfadada porque haya[ENTER]mentido. A nadie le gusta humillarse.[ENTER]\161Aunque al menos deber\237a haber intentado hacerlo[ENTER]real! No quiero tener nunca m\225s amigos tan[ENTER]cobardes. "
gameforge.subquest_44._330_sayReward = "Yu-Rang te dar\225 una recompensa por tu honradez. "
gameforge.subquest_44._340_sayReward = "Has recibido 30.000 Yang. "
gameforge.subquest_44._350_sayReward = "Has recibido 350.000 puntos de experiencia. "
gameforge.subquest_44._360_sendLetter = "Campana para la ara\241a "
gameforge.subquest_44._370_say = "Ve al desierto con las Cr\237a Ara\241a e intenta[ENTER]colgar la campana de Taurean en una de ellas. "
gameforge.subquest_44._380_npcChat = "Sobre la campana... "
gameforge.subquest_44._390_say = "\191Todav\237a no has colgado la campana en la ara\241a?[ENTER]Entonces hazlo pronto por favor. \161Y aseg\250rate de[ENTER]que Yu-Rang no te pille! "
gameforge.subquest_44._400_sendLetter = "\161Hecho! "
gameforge.subquest_44._40_say = "S\233 que tendr\237a que confiar en mi amigo, pero[ENTER]quiero saber si realmente lo hizo. El desierto es[ENTER]demasiado peligroso para m\237. T\250 pareces muy[ENTER]fuerte. Podr\237as hacerlo f\225cilmente. \191Podr\237as ir a[ENTER]echar un vistazo por m\237? "
gameforge.subquest_44._410_say = "Fue muy dif\237cil, pero finalmente te las has[ENTER]arreglado para colgar la campana en una Cr\237a[ENTER]Ara\241a. Ahora ve con Yu-Rang y dile que lo hizo[ENTER]Taurean. "
gameforge.subquest_44._420_npcChat = "La campana ha sido colgada en la ara\241a. "
gameforge.subquest_44._430_say = "\191Lo has hecho? \161Es fant\225stico![ENTER]\161Entonces ve r\225pido a cont\225rselo a Yu-Rang para[ENTER]que finalmente me crea! "
gameforge.subquest_44._440_npcChat = "Taurean ha dicho la verdad. "
gameforge.subquest_44._450_say = "\191Vuelves? \191Has encontrado una ara\241a con una[ENTER]campana? Entonces Taurean realmente lo hizo.[ENTER]Nunca hubiera pensado que fuera posible. Quiz\225 se[ENTER]convierta en un verdadero hombre alg\250n d\237a[ENTER]despu\233s de todo. Gracias por comprobarlo por m\237.[ENTER]aqu\237 tienes una recompensa por tu ayuda. "
gameforge.subquest_44._460_sendLetter = "Vuelve con Taurean "
gameforge.subquest_44._470_targetVid = "Vuelve con Taurean "
gameforge.subquest_44._480_say = "Le has dicho a Yu-Rang que su amigo ha colgado[ENTER]una campana en una Cr\237a Ara\241a.[ENTER]Ahora vuelve con Taurean y cu\233ntale sobre el[ENTER]\233xito del enga\241o. "
gameforge.subquest_44._490_npcChat = "Yu-Rang te cree. "
gameforge.subquest_44._500_say = "Muchas gracias. Ahora Yu-Rang no me odiar\225.[ENTER]Tenemos que mantener esto en secreto para[ENTER]siempre. \191Lo prometes? \161Nos veremos pronto! "
gameforge.subquest_44._50_select = "Aceptar "
gameforge.subquest_44._510_sayReward = "Taurean te da una recompensa por ayudarle a[ENTER]mentir: has recibido 30.000 Yang. "
gameforge.subquest_44._520_sayReward = "Has recibido 700.000 puntos de experiencia. "
gameforge.subquest_44._60_say = "\191Quieres abandonar esta misi\243n? "
gameforge.subquest_44._70_say = "\191Por qu\233 no? \191Tienes miedo?[ENTER]Vis\237tame cuando hayas cambiado de opini\243n. "
gameforge.subquest_44._80_say = "Aaah, \191tienes miedo?[ENTER]\161Pero eres mucho m\225s alto y fuerte que yo![ENTER]Jaja, \161eres un cobarde! Entonces tendr\233 que[ENTER]ped\237rselo a otro. "
gameforge.subquest_44._90_say = "Las ara\241as viven en el desierto. T\250 eres fuerte.[ENTER]Seguro de que puedes hacerlo. \161Buena suerte! "
gameforge.subquest_45 = {}
gameforge.subquest_45._100_sayTitle = "Consigue la informaci\243n secreta "
gameforge.subquest_45._10_npcChat = "El asunto sobre el Templo de la Oscuridad "
gameforge.subquest_45._110_say = "Tienes la Doctrina Templo, la Bufanda Templo y la[ENTER]traducci\243n del libro de maldiciones. Ll\233vaselas a[ENTER]Soon. "
gameforge.subquest_45._120_say = "Si ayudas a Soon, el rat\243n de biblioteca, podr\225[ENTER]continuar su investigaci\243n sobre el Templo de la[ENTER]Oscuridad.[ENTER]Sin embargo, s\243lo puede hacerlo si consigue lo[ENTER]siguiente: La Doctrina Temple, la Bufanda Temple[ENTER]y la Traducci\243n del Libro Maldici\243n. Consigue[ENTER]esas cosas y ll\233vaselas a Soon. Las encontrar\225s[ENTER]en el Templo Hwang en el Valle de Seungryong. "
gameforge.subquest_45._130_npcChat = "Las cosas del Templo de la Oscuridad "
gameforge.subquest_45._140_say = "Ah, \161las tienes! Muchas gracias.[ENTER]Sobre la gente secreta en el templo, bueno, es[ENTER]muy simple: son gente peligrosa.[ENTER]Pero t\250 lo has aprendido por el camino dif\237cil.[ENTER]Tambi\233n parecen servir a los dioses malignos. No[ENTER]conozco los detalles, pero supongo que estan[ENTER]planeando algo realmente malo. "
gameforge.subquest_45._150_say = "Ahora que tengo algunas de sus cosas sagradas[ENTER]seguramente averiguar\233 m\225s. Mejor empezar con la[ENTER]Doctrina Temple.[ENTER]Veamos... Hmm... Aj\225...[ENTER]\191Por qu\233 sigues todav\237a por aqu\237? \191No tienes nada[ENTER]que hacer? "
gameforge.subquest_45._160_sayReward = "Has recibido 7.000.000 puntos de experiencia. "
gameforge.subquest_45._170_sayReward = "Has recibido 70.000 Yang. "
gameforge.subquest_45._180_sayReward = "Has recibido el Libro del L\237der. "
gameforge.subquest_45._190_say = "\191Qu\233? \191No los tienes? \161No aflojes si aceptas un[ENTER]encargo! \161Date prisa! "
gameforge.subquest_45._200_select = "Intentarlo de nuevo "
gameforge.subquest_45._20_say = "Est\225 pasando algo en el interior del Templo de la[ENTER]Oscuridad. Creo que all\237 hay criaturas peligrosas[ENTER]estudiando magia antigua.[ENTER]Los secretos del Templo de la Oscuridad son[ENTER]dif\237ciles de entender, incluso para m\237. Pero[ENTER]estoy seguro de que la agenda de esas personas es[ENTER]m\225s que dudosa. \161Tengo que averiguar m\225s sobre[ENTER]ellos! "
gameforge.subquest_45._210_say = "Entonces se lo tengo que pedir a un h\233roe m\225s[ENTER]fuerte. Adi\243s. "
gameforge.subquest_45._220_say = "Gracias.[ENTER]\161Espero que tengas m\225s \233xito esta vez! "
gameforge.subquest_45._30_say = "Necesito m\225s hechos para mis estudios. Creo que[ENTER]la Doctrina Temple, la Bufanda Temple y la[ENTER]Traducci\243n del Libro Maldici\243n pueden ser[ENTER]bastante \250tiles. \191Puedes traerme esas cosas?[ENTER]\161Estar\237a muy agradecido! Y no tardes demasiado,[ENTER]\161las necesito pronto! "
gameforge.subquest_45._40_select = "Voy inmediatamente. "
gameforge.subquest_45._50_say = "\191Quieres hacerlo? "
gameforge.subquest_45._60_say = "\161Te estoy pidiendo ayuda! Si est\225s demasiado[ENTER]ocupado ahora, vuelve m\225s tarde. Quiz\225 tengas m\225s[ENTER]tiempo entonces. Te estar\233 esperando. "
gameforge.subquest_45._70_say = "\191Te ped\237 ayuda y t\250 simplemente me das la[ENTER]espalda? Oh, bien, de todas formas no te[ENTER]necesitamos... \161ahora desaparece! "
gameforge.subquest_45._80_say = "\161Gracias! "
gameforge.subquest_45._90_makequestbutton = "Templo de la Oscuridad "
