gameforge.subquest_46._110_makequestbutton = "Porcelana Celadon "
gameforge.subquest_46._120_qSetTitle = "Porcelana Celadon "
gameforge.subquest_46._130_say = "Tienes todos los materiales que necesita Yonah[ENTER]para hacer la Porcelana Celadon. \161Ll\233vaselos a[ENTER]Yonah! "
gameforge.subquest_46._140_say = "Para que Yonah pueda fabricar porcelana celadon,[ENTER]necesita los siguientes materiales:[ENTER]Arena del Desierto de los Bandidos del Desierto[ENTER]Yongbi, mineral cristal de una mina de cristal y[ENTER]sangre de los Monos de Piedra Fuertes o Monos de[ENTER]Oro Fuertes en el \225rea Sangsun Dong. \161Consigue[ENTER]los tres materiales y ll\233vaselos a Yonah! "
gameforge.subquest_46._150_targetVid = "El secreto de la porcelana verde p\225lido "
gameforge.subquest_46._160_npcChat = "He conseguido todos los materiales. "
gameforge.subquest_46._170_say = "\161Lo has hecho! \161Gracias! Con la t\233cnica apropiada[ENTER]y los materiales correctos puedo producir[ENTER]porcelana verde p\225lido maravillosa. Las ganancias[ENTER]que voy a conseguir ser\225n una bendici\243n para mi[ENTER]bolsillo.[ENTER]Toma, coge esta recompensa. Te la has ganado.[ENTER]\161Voy a empezar a producir porcelana[ENTER]inmediatamente! "
gameforge.subquest_46._180_sayReward = "Has recibido 3.000.000 puntos de experiencia. "
gameforge.subquest_46._190_sayReward = "Has recibido 30.000 Yang. "
gameforge.subquest_46._20_say = "\161Hola aventurero! \191No me trajiste hace poco las[ENTER]notas de Soon sobre c\243mo hacer Porcelana Celadon?[ENTER]Tengo un problema... Aunque conozco la t\233cnica,[ENTER]parece que no soy capaz de fabricar aut\233ntica[ENTER]Porcelana Celadon.[ENTER]Probablemente sea porque utilic\233 mis ingredientes[ENTER]habituales en lugar del material escrito en las[ENTER]notas, que es dif\237cil de conseguir. "
gameforge.subquest_46._30_say = "Necesito Arena del Desierto molida, Mineral[ENTER]Cristal y Sangre de Mono. Si mezclas eso y lo[ENTER]a\241ades a la Arcilla se vuelve realmente dura[ENTER]cuando la pones en el fuego. El barniz tambi\233n[ENTER]toma su t\237pico color verde p\225lido que parece[ENTER]jade. \161Este color es realmente popular entre los[ENTER]clientes y realmente necesito vender m\225s! "
gameforge.subquest_46._40_say = "Puedes conseguir la Arena del Desierto de los[ENTER]Bandidos del Desierto, el Mineral Cristal de las[ENTER]vetas de cristal y para conseguir la Sangre de[ENTER]Mono, tendr\225s que matar monos en Sansung Dong.[ENTER]\191Puedes conseguir esos materiales para m\237? Lo s\233,[ENTER]no ser\225 f\225cil pero te recompensar\233 generosamente. "
gameforge.subquest_46._50_select = "Aceptar "
gameforge.subquest_46._60_select = "Declinar "
gameforge.subquest_46._70_say = "\191Quieres abandonar esta misi\243n? "
gameforge.subquest_46._80_say = "Si estas demasiado ocupado ahora, vuelve m\225s[ENTER]tarde. "
gameforge.subquest_46._90_say = "\191Lo dejas? \191En serio? Entonces supongo que tendr\233[ENTER]que buscarlo todo yo mismo. Realmente necesito[ENTER]esta porcelana. Adi\243s y buena suerte. "
