gameforge.subquest_48._120_say = "Uno de los esp\237as vive como pescador en la aldea[ENTER]Yongan en el reino Shinsoo. Intenta contactar con[ENTER]\233l discretamente y lleva su reporte al Capit\225n. "
gameforge.subquest_48._130_say = "Uno de los esp\237as vive como pescador en la aldea[ENTER]Joan en el reino Chunjo. Intenta contactar con \233l[ENTER]discretamente y lleva su reporte al Capit\225n. "
gameforge.subquest_48._140_npcChat = "\191Qu\233 est\225s haciendo? "
gameforge.subquest_48._150_say = "Sssh, \161\161guarda silencio!! Asustar\225s a todos los[ENTER]peces. De todos modos, \191por qu\233 est\225s aqu\237? Eres[ENTER]ruidoso y torpe; no puedes estar aqu\237 por la[ENTER]pesca. "
gameforge.subquest_48._160_say = "Ah, entiendo. Te he estado esperando durante[ENTER]mucho tiempo; llegas tarde. No fue f\225cil[ENTER]conseguir esta informaci\243n sin ser capturado.[ENTER]Tienes que entender que el enemigo est\225 por todas[ENTER]partes, y todo lo que hace es esperar que[ENTER]accidentalmente descubras tu tapadera. "
gameforge.subquest_48._170_say = "As\237 pues, acabemos con esto antes de que alguien[ENTER]nos vea. Aqu\237 est\225n los documentos. Vuelve[ENTER]inmediatamente y d\225selos \250nicamente al Capit\225n. "
gameforge.subquest_48._180_say = "\161Un momento, por favor! Tengo algo para ti. Un[ENTER]peque\241o regalo. De acuerdo entonces. Vete.[ENTER]\161Adi\243s! "
gameforge.subquest_48._190_sayReward = "Eres curioso y abres el paquete para ver lo que[ENTER]te ha dado el esp\237a. "
gameforge.subquest_48._200_say = "\161Genial! \161Gard\237 Asado! Obviamente el esp\237a[ENTER]realmente sabe algo sobre la pesca. "
gameforge.subquest_48._20_say = "\161Descansa, soldado![ENTER]Desde que todos los pa\237ses vecinos son enemigos,[ENTER]es importante tener amigos encubiertos all\237 que[ENTER]nos ayuden a reunir informaci\243n, para as\237 poder[ENTER]prepararnos para cualquier ataque potencial. Es[ENTER]extremadamente importante que la tapadera de esos[ENTER]esp\237as nunca sea descubierta. "
gameforge.subquest_48._210_sayReward = "Has recibido 3 Ruds asados. "
gameforge.subquest_48._220_sendLetter = "Regresar con el Capit\225n. "
gameforge.subquest_48._230_targetVid = "El Capit\225n "
gameforge.subquest_48._240_say = "El viaje peligroso a Pyungmoo en el reino Jinno[ENTER]ha tenido \233xito: Has recibido el reporte del[ENTER]esp\237a que est\225 disfrazado de pescador.[ENTER]Ahora vuelve a tu reino y ll\233vale r\225pido esa[ENTER]informaci\243n al Capit\225n. "
gameforge.subquest_48._250_say = "El viaje peligroso a Yongan en el reino Shinsoo[ENTER]ha tenido \233xito: Has recibido el reporte del[ENTER]esp\237a que est\225 disfrazado de pescador.[ENTER]Ahora vuelve a tu reino y ll\233vale r\225pido esa[ENTER]informaci\243n al Capit\225n. "
gameforge.subquest_48._260_say = "El viaje peligroso a Joan en el reino Chunjo ha[ENTER]tenido \233xito: Has recibido el reporte del esp\237a[ENTER]que est\225 disfrazado de pescador.[ENTER]Ahora vuelve a tu reino y ll\233vale r\225pido esa[ENTER]informaci\243n al Capit\225n. "
gameforge.subquest_48._270_npcChat = "\161La misi\243n ha tenido \233xito! "
gameforge.subquest_48._280_say = "\191\201stos son los documentos? \161Genial! Gracias.[ENTER]Ahora que conocemos los planes de nuestros[ENTER]enemigos, podemos prepararnos consecuentemente[ENTER]para protegernos. \161Has hecho un gran servicio[ENTER]para el reino! "
gameforge.subquest_48._290_sayReward = "Has recibido 5.500.000 puntos de experiencia. "
gameforge.subquest_48._300_sayReward = "Obtienes 50.000 Yang. "
gameforge.subquest_48._30_say = "Seguramente conoces a Yu-Hwan el m\250sico, \191no?[ENTER]Tambi\233n es un esp\237a y trabaja para nosotros.[ENTER]Aunque un \250nico esp\237a no ayuda, as\237 que tenemos[ENTER]varios por todo el mundo. Uno de ellos se[ENTER]encuentra en la primera aldea fingiendo ser un[ENTER]pescador. "
gameforge.subquest_48._40_say = "Ya que no puedo contactar directamente con \233l sin[ENTER]descubrir su tapadera, necesito ayuda de soldados[ENTER]valientes. S\237, \161me refiero a ti![ENTER]Podr\237as, por favor, ir con este Pescador y[ENTER]traerme su \250ltimo reporte.[ENTER]\161Es de vital importancia para la seguridad de[ENTER]nuestro reino! "
gameforge.subquest_48._50_say = "\191Quieres abandonar la misi\243n para siempre? "
gameforge.subquest_48._60_say = "\191Quieres prepararte primero? Est\225 bien, entonces[ENTER]vuelve m\225s tarde. Te estar\233 esperando. Pero, por[ENTER]favor date prisa; \161necesito este reporte! "
gameforge.subquest_48._70_say = "\191Qu\233 te pasa? \161La \250ltima vez hiciste un gran[ENTER]trabajo para nosotros! \191Y ahora simplemente[ENTER]quieres abandonar a nuestro pa\237s? Pero no hay[ENTER]nada que pueda hacer para evitarlo. Adi\243s. "
gameforge.subquest_48._80_say = "Sab\237a que pod\237a contar contigo. \161Buena suerte y[ENTER]ten cuidado! "
gameforge.subquest_48._90_makequestbutton = "Re\250nete con el esp\237a "
gameforge.subquest_49 = {}
gameforge.subquest_49._100_sayTitle = "\191Qu\233 es Bingsu? "
gameforge.subquest_49._10_targetVid = "\191Bingsu? "
gameforge.subquest_49._110_say = "Taurean ha tenido una pelea con Harang porque no[ENTER]cree que puedas hacer helado en verano. Ve con[ENTER]Harang y preg\250ntale que sabe sobre el Bingsu. "
gameforge.subquest_49._120_qSetTitle = "Pregunta a Harang "
gameforge.subquest_49._130_targetVid = "Pregunta a Harang "
gameforge.subquest_49._140_npcChat = "\191Qu\233 es Bingsu? "
gameforge.subquest_49._150_say = "Ese Taurean tambi\233n se las da de saberlo todo.[ENTER]\161Ni tan siquiera conoce el Bingsu! \191C\243mo no[ENTER]puedes conocer algo tan delicioso?[ENTER]\191\191T\250 tampoco sabes lo que es el Bingsu?? Bien,[ENTER]deber\237as ir con Octavio en la aldea vecina. Es un[ENTER]cocinero famoso y conoce muchas recetas buenas.[ENTER]Me hizo Bingsu una vez... mmmmh.[ENTER]\161\201l te probar\225 que tengo raz\243n! "
gameforge.subquest_49._160_makequestbutton = "Vamos a ver a Octavio "
gameforge.subquest_49._170_say = "Taurean quiere saber lo que es el Bingsu.[ENTER]Ve con el due\241o del restaurante Octavio. Estoy[ENTER]seguro de que puede ayudarte. "
gameforge.subquest_49._180_npcChat = "\191Sabes lo que es el Bingsu? "
gameforge.subquest_49._190_say = "\191Bingsu? Por supuesto que lo s\233. \161Todo buen[ENTER]cocinero sabe cpmo hacer Bingsu! Lo primero de[ENTER]todo necesitas hielo picado fino. Entonces pones[ENTER]az\250car, rodajas finas de pastel de arroz y[ENTER]finalmente fruta fresca para la decoraci\243n. "
gameforge.subquest_49._200_say = "\191Por qu\233 lo preguntas? \191Porque Taurean y Harang[ENTER]est\225n discutiendo? Eso no es nuevo. Pero Harang[ENTER]tiene raz\243n. El Bingsu es una comida[ENTER]especialmente popular en los veranos calurosos.[ENTER]Taurean es un buen chico en realidad, incluso[ENTER]siendo un poco mezquino a veces. Si consigues los[ENTER]ingredientes, podr\237a hacerle Bingsu. "
gameforge.subquest_49._20_npcChat = "\191Bingsu? "
gameforge.subquest_49._210_say = "Me gustar\237a darle un regalo a Taurean y darle[ENTER]Bingsu. \191Qu\233 piensas? \191Puedes ir a conseguir[ENTER]Hielo del Monte Sohan? "
gameforge.subquest_49._220_say = "\191Quieres abandonar esta misi\243n? "
gameforge.subquest_49._230_say = "\191No quieres helado? \191O ya has comido mucho? Es[ENTER]para Taurean, as\237 que por favor pi\233nsatelo de[ENTER]nuevo. "
gameforge.subquest_49._240_say = "L\225stima. Taurean va a estar muy decepcionado.[ENTER]Nos vemos. "
gameforge.subquest_49._250_say = "Muy bien. Necesito Pedazos de Hielo de los Hielos[ENTER]Encantados del Monte Sohan. Tr\225eme 50 Pedazos de[ENTER]Hielo. Entonces podr\233 hacer un sabroso Bingsu. "
gameforge.subquest_49._260_targetVid = "Visita a Octavio "
gameforge.subquest_49._270_say = "%s[ENTER]Has conseguido los Pedazos de Hielo para el[ENTER]Bingsu de Taurean. Ll\233vaselos a Octavio. "
gameforge.subquest_49._275_say = "Conseguidos los Pedazos de Hielo "
gameforge.subquest_49._280_say = "Octavio ha accedido a hacer Bingsu para Taurean,[ENTER]pero necesita hielo. Caza Hielos encantados en el[ENTER]Monte Sohan y recoge 50 Pedazos de hielo.[ENTER]Despu\233s, ll\233vaselos a Octavio. "
gameforge.subquest_49._285_say = "Buscando hielo "
gameforge.subquest_49._290_npcChat = "He traido los Pedazos de Hielo. "
gameforge.subquest_49._300_say = "Ah, \161muy bien! La parte m\225s dif\237cil de preparar[ENTER]Bingsu est\225 hecha. Ahora s\243lo tengo que poner un[ENTER]poco de az\250car... y algunas frutas... \161Aqu\237[ENTER]tienes! Un helado para Taurean. Ll\233vaselo ahora,[ENTER]entonces olvidar\225 pronto su enfado. "
gameforge.subquest_49._30_sayTitle = "Taurean: "
gameforge.subquest_49._310_say = "Lo siento, pero eso no es suficiente. \161Tienes que[ENTER]conseguir m\225s, de lo contrario ser\225 una porci\243n[ENTER]diminuta! "
gameforge.subquest_49._320_select = "Prueba de nuevo "
gameforge.subquest_49._330_say = "S\233 que es un largo camino y que los monstruos son[ENTER]fuertes. Si es demasiado dif\237cil para ti, no hay[ENTER]nada que podamos hacer. Nos vemos. "
gameforge.subquest_49._340_say = "Int\233ntalo de nuevo. \161Con tu valor y energ\237a[ENTER]puedes hacerlo! "
gameforge.subquest_49._350_targetVid = "\191Bingsu? "
gameforge.subquest_49._360_say = "Est\225 hecho: Octavio ha preparado Bingsu del hielo[ENTER]del Monte Sohan. Vuelve r\225pido con Taurean antes[ENTER]de que se derrita. "
gameforge.subquest_49._370_npcChat = "\161Aqu\237! \161Bingsu! "
gameforge.subquest_49._380_say = "\191Eso es Bingsu? Sabe realmente bien. Agradable y[ENTER]fresco. \161Nunca hab\237a probado algo como esto,[ENTER]gracias! As\237 que Harang tiene raz\243n. Tengo que[ENTER]disculparme... "
gameforge.subquest_49._390_sayReward = "Has recibido 6.000.000 puntos de experiencia. "
gameforge.subquest_49._400_sayReward = "Has recibido 70.000 Yang. "
gameforge.subquest_49._40_say = "Hoy tuve una pelea con Harang. Pude...[ENTER]Ella afirma que hay algo muy sabroso hecho de[ENTER]hielo picado. Se llama Bingsu. "
gameforge.subquest_49._410_sayReward = "Has recibido un Pergamino de la Guerra. "
gameforge.subquest_49._420_say = "Bingsu para m\237, \191recuerdas? "
gameforge.subquest_49._430_say = "Oh cielo, \161lo hab\237a olvidado completamente! Hmm,[ENTER]\191deber\237a seguir intent\225ndolo? \191O mejor deber\237a[ENTER]dejarlo? "
gameforge.subquest_49._440_select = "S\237, continuar\233. "
gameforge.subquest_49._450_select = "Abandono. "
gameforge.subquest_49._460_say = "No puedo hacerlo, lo siento. "
gameforge.subquest_49._50_say = "Algo como eso s\243lo es posible en invierno cuando[ENTER]verdaderamente hace fr\237o. Pero sigue afirmando[ENTER]que funcionar\225. \191Puedes averiguar si tambi\233n[ENTER]puedes preparar este Bingsu en verano? Si existe[ENTER]tal cosa... "
gameforge.subquest_49._60_say = "\161Estoy seguro de que este Bingsu es delicioso![ENTER]\191Est\225s seguro de que nunca me ayudar\225s a hacerlo? "
gameforge.subquest_49._70_say = "Si quieres intentarlo en otro momento, por favor[ENTER]dilo. "
gameforge.subquest_49._80_say = "Me encantar\237a probar el Bingsu...[ENTER]Pero tienes raz\243n. \161Harang probablemente s\243lo[ENTER]quiere alardear y el Bingsu no existe! Adi\243s. "
gameforge.subquest_49._90_say = "Gracias por tu ayuda. Hazme saber si averiguas[ENTER]algo. \161Entonces podr\233 rega\241ar a Harang! "
