gameforge.training_mount = {}
gameforge.training_mount._01_say = "Lo siento, pero a\250n no tienes la experiencia en[ENTER]equitaci\243n necesaria para mejorar a tu montura.[ENTER]Para eso necesitas, por lo menos, la licencia[ENTER]para Caballos de Batalla. "
gameforge.training_mount._02_say = "Lo siento, pero sin los documentos adecuados no[ENTER]puedo hacer nada por ti. Y como vuelvas a[ENTER]intentar buscarme las vueltas, me las pagar\225s. "
gameforge.training_mount._03_say = "\191D\243nde est\225 tu sello de equitaci\243n? Sin ese sello[ENTER]no puedo mejorar monturas. Mira detr\225s de la[ENTER]moneda que gira. Ah\237 encontrar\225s t\237tulos de[ENTER]propiedad que yo luego te puedo cambiar por[ENTER]sellos de equitaci\243n. "
gameforge.training_mount._04_say = "\161Quiero cabalgar sobre una nueva montura! "
gameforge.training_mount._05_say = "\161Hey! \191Sigues cabalgando a lomos de un caballo?[ENTER]\161No me lo puedo creer! Hoy en d\237a se pueden[ENTER]domesticar otros animales. "
gameforge.training_mount._06_say = "En cualquier caso, para poder entrenar a animales[ENTER]salvajes para el combate has de tener buenos[ENTER]conocimientos de equitaci\243n. Adem\225s, necesitas[ENTER]los siguientes objetos: el Pergamino de[ENTER]Evoluci\243n, para mejorar a tu montura y[ENTER]convertirla en un animal salvaje, y el Pergamino[ENTER]de Mutaci\243n, para transformarla en una montura[ENTER]valerosa. "
gameforge.training_mount._07_say = "Si tienes preguntas, b\250scame por aqu\237 en[ENTER]cualquier momento. Te ayudar\233 en lo que pueda. "
gameforge.training_mount._08_say = "\161Quiero mejorar mi montura! "
gameforge.training_mount._09_say = "\191As\237 que quieres mejorar a tu montura?[ENTER]\191Sabes ya c\243mo se hace? Muy bien, te lo explicar\233. "
gameforge.training_mount._10_say = "Para convertir a tu jamelgo en una montura[ENTER]salvaje tendr\225s que lanzarte a la b\250squeda del[ENTER]Pergamino de Evoluci\243n. Encuentra el Pergamino de[ENTER]Mutaci\243n para transformar a tu montura salvaje en[ENTER]una montura valerosa. \161Se dice que se pueden[ENTER]encontrar en tierras lejanas, habitadas por[ENTER]terribles gigantes! "
gameforge.training_mount._11_say = "Tr\225eme alguno de esos pergaminos y mejorar\233 tu[ENTER]montura. No los tendr\225s ya por un casual, \191no? "
gameforge.training_mount._12_say = "\161S\237, quiero mejorar mi montura! "
gameforge.training_mount._13_say = "No, a\250n no. "
gameforge.training_mount._14_say = "Ah, tienes uno de los pergaminos. \191Cu\225l de los[ENTER]dos es? Con el Pergamino de Evoluci\243n adiestras a[ENTER]tu inexperto animal para el combate. Despu\233s, con[ENTER]el Pergamino de Mutaci\243n puedes mejorarlo y[ENTER]convertirlo en una montura valerosa. "
gameforge.training_mount._15_2_say = "Tengo el Pergamino de Mutaci\243n. "
gameforge.training_mount._15_say = "Tengo el Pergamino de Evoluci\243n. "
gameforge.training_mount._16_say = "No tengo ninguno de los pergaminos. "
gameforge.training_mount._17_say = "Ah, mira... \161el Pergamino de Evoluci\243n! D\233jame[ENTER]que le eche un vistazo a tu sello de equitaci\243n.[ENTER]\161Hay muchos que intentan colarme falsificaciones![ENTER]Primero comprobar\233 su legitimidad. D\225melo. (Mueve[ENTER]el sello hasta el Chico del Establo). "
gameforge.training_mount._18_say = "\161El Pergamino de Mutaci\243n! Hasta ahora solamente[ENTER]hab\237a o\237do hablar de \233l, jam\225s lo he tenido en[ENTER]mis manos. Mu\233strame tu sello de equitaci\243n. Te[ENTER]lo cambiar\233 por uno m\225s poderoso en cuanto[ENTER]compruebe que es aut\233ntico. (Mueve el sello hasta[ENTER]el Chico del Establo). "
gameforge.training_mount._19_say = "En cuanto encuentres uno de los pergaminos,[ENTER]tr\225emelo. As\237 podr\233 cambiar tu viejo sello de[ENTER]equitaci\243n por uno m\225s poderoso. "
gameforge.training_mount._20_say = "Tu sello de equitaci\243n ha visto tiempos mejores,[ENTER]sin duda. Espera, que te lo cambio por uno nuevo.[ENTER]Aqu\237 tienes, de nada. Ahora ya puedes invocar a[ENTER]tu montura salvaje. Ven a verme en cuanto hayas[ENTER]encontrado el Pergamino de Mutaci\243n. Entonces te[ENTER]dar\233 un sello de equitaci\243n m\225s poderoso a\250n. "
gameforge.training_mount._21_say = "Este es el sello de equitaci\243n que te di hace un[ENTER]tiempo. Pero ya est\225 bastante gastado. \161D\225melo y[ENTER]te fabricar\233 un sello de equitaci\243n a\250n m\225s[ENTER]poderoso! "
gameforge.training_mount._22_say = "Con este sello puedes invocar a tu montura[ENTER]mejorada. Ten cuidado con \233l, \161tiene un valor[ENTER]incalculable! "
gameforge.training_mount._23_say = "\191Puedo utilizar habilidades de montura? "
gameforge.training_mount._24_say = "\191Quieres hacer uso de habilidades de montura?[ENTER]\161Eres exigente, desde luego! Pero confieso que a[ENTER]m\237 tambi\233n me encantar\237a... Est\225 bien. Antes de[ENTER]aprenderlas, tienes que superar un par de[ENTER]requisitos. "
gameforge.training_mount._25_say = "En primer lugar, tienes que dominar la[ENTER]equitaci\243n, o si no podr\237as hacerte da\241o. Adem\225s,[ENTER]tu montura ha de estar preparada para combatir,[ENTER]porque si no no ser\237a capaz de utilizar las[ENTER]habilidades de montura. "
gameforge.training_mount._26_say = "\191Est\225 tu montura est\233 preparada para utilizar[ENTER]habilidades de montura? Si no, no puedo permitir[ENTER]el entrenamiento. \191Qu\233 quieres hacer? "
gameforge.training_mount._27_say = "Entiendo. Ahora voy a evaluar tu fuerza y tus[ENTER]conocimientos de h\237pica. Espera un segundo. "
gameforge.training_mount._28_say = "Hm... un espinazo fuerte, extensos conocimientos[ENTER]de equitaci\243n y una montura combativa. Puedes[ENTER]utilizar habilidades de montura. "
gameforge.training_mount._29_say = "Ahora tu montura puede utilizar sus habilidades.[ENTER]Pero si adquieres una montura nueva, esta tendr\225[ENTER]que aprenderlas de nuevo. Llegado el caso, ven a[ENTER]verme de nuevo. "
gameforge.training_mount._30_say = "Venga, ya te he dicho que es demasiado peligroso[ENTER]si no sabes montar.[ENTER]Vuelve por aqu\237 cuando hayas aprendido. "
gameforge.training_mount._31_say = "Me temo que tu montura a\250n no est\225 lista.[ENTER]Vuelve por aqu\237 cuando muestre m\225s combatividad. "
gameforge.training_mount._32_say = "\191Podr\237as bajarte de tu montura mientras hablamos?[ENTER]Se me cansa el cuello si tengo que estar mirando[ENTER]hacia arriba todo el rato. "
gameforge.training_mount._33_say = "No tienes la licencia de monta adecuada para[ENTER]mejorar a tu montura. Necesitas por lo menos la[ENTER]licencia de Caballo de Batalla si quieres[ENTER]entrenar a un Reno Salvaje. Para domar a un Reno[ENTER]Valeroso necesitas la licencia de Caballo[ENTER]Militar. "
gameforge.training_mount._34_say = "Por lo que veo tienes Supercomida. Esta valiosa[ENTER]planta curativa le proporciona energ\237a pura a tu[ENTER]Supermontura, lo cual alarga su vida en unos[ENTER]d\237as. \191Qu\233 puedo hacer por ti? \191Quieres que[ENTER]alargue la vida de tu montura o que la mejore? "
gameforge.training_mount._35_select_1 = "Prorrogar "
gameforge.training_mount._35_select_2 = "Mejorar "
gameforge.training_mount._36_select_1 = "7 d\237as "
gameforge.training_mount._36_select_2 = "15 d\237as "
gameforge.training_mount._36_select_3 = "30 d\237as "
gameforge.training_mount._36_select_4 = "Pergamino de Mutaci\243n + 200\160000 Yang "
gameforge.training_mount._37_say = "Por desgracia, no posees la Supercomida necesaria[ENTER]para la duraci\243n que has seleccionado. \161Pero[ENTER]puedes encontrarla detr\225s de la moneda giratoria! "
gameforge.training_mount._38_say = "\161El Pergamino de Mutaci\243n es extremadamente[ENTER]poderoso! Puede alargar la vida de tu montura[ENTER]valerosa en hasta cuatro d\237as. Un intento te[ENTER]costar\225 200\160000 Yang. Para ello, tu montura ha de[ENTER]estar exhausta y tener menos de un d\237a de vida.[ENTER]\161Por supuesto, tambi\233n el azar influye! Si la[ENTER]pr\243rroga no tuviera \233xito, simplemente dale[ENTER]Supercomida a tu montura. Puedes encontrarla[ENTER]detr\225s de la moneda giratoria. "
gameforge.training_mount._39_say = "Tu Supermontura a\250n se encuentra muy fuerte. El[ENTER]Pergamino de Mutaci\243n no tendr\237a efecto. Vuelve[ENTER]por aqu\237 cuando tenga menos de un d\237a de vida. "
gameforge.training_mount._40_say = "No puedo ayudarte: o bien no llevas contigo el[ENTER]Pergamino de Mutaci\243n o bien no tienes los[ENTER]200\160000 Yang necesarios. "
gameforge.upgrade_refine_scroll = {}
gameforge.upgrade_refine_scroll._100_say = "Tu intento de producir el Manuscrito del Drag\243n[ENTER]fall\243 porque no ten\237as todos los materiales. "
gameforge.upgrade_refine_scroll._10_npcChat = "Fabricar pergamino del Dios de la Guerra "
gameforge.upgrade_refine_scroll._110_npcChat = "Elaborar Pergamino Drag\243n "
gameforge.upgrade_refine_scroll._120_say = "Un Pergamino Drag\243n incrementa el \237ndice de \233xito[ENTER]al mejorar un objeto. Incluso si fallas,[ENTER]solamente disminuye el nivel del objeto en uno.[ENTER]Este es un objeto misterioso que se podr\237a[ENTER]considerar como una especie de Pergamino[ENTER]Bendici\243n mejorado. "
gameforge.upgrade_refine_scroll._130_say = "Para producirlo, necesitas mineral de hierro[ENTER]m\225gico. "
gameforge.upgrade_refine_scroll._140_sayItem = "Mineral de Hierro M\225gico "
gameforge.upgrade_refine_scroll._150_say = "Para producir esto, necesitas un Pergamino[ENTER]Bendici\243n. "
gameforge.upgrade_refine_scroll._160_say = "\191Tienes todos los objetos necesarios? \191Quieres[ENTER]producir un Pergamino Drag\243n? Para ello necesitas[ENTER]un Pergamino Bendici\243n y Mineral de hierro[ENTER]m\225gico. "
gameforge.upgrade_refine_scroll._170_say = "\161Has creado un pergamino drag\243n! Es realmente m\225s[ENTER]f\225cil producir un pergamino drag\243n si usas[ENTER]mineral de hierro m\225gico. \161Me[ENTER]gusta!  "
gameforge.upgrade_refine_scroll._180_say = "Tu intento de producir el Manuscrito del Drag\243n[ENTER]fall\243 porque no ten\237as todos los materiales. "
gameforge.upgrade_refine_scroll._190_npcChat = "Producir un Manual de los Smithery "
gameforge.upgrade_refine_scroll._200_say = "\191Has o\237do hablar de la piedra llamada Piedra del[ENTER]Herrero? Es una piedra hecha de la sangre y sudor[ENTER]de un herrero. Si me traes la Piedra del Herrero[ENTER]y un Pergamino Bendici\243n, crear\233 para ti un[ENTER]manual que ha pasado en mi familia de generaci\243n[ENTER]en generaci\243n. Tiene funciones similares al[ENTER]Pergamino Drag\243n, pero el \237ndice de \233xito es[ENTER]mayor.  "
gameforge.upgrade_refine_scroll._20_say = "Estos misteriosos Pergaminos de la Guerra mejoran[ENTER]objetos desde +0 hasta +3 y tienen un porcentaje[ENTER]de \233xito del 100% Sin embargo, no funcionan en[ENTER]objetos +4 o superiores. "
gameforge.upgrade_refine_scroll._210_say = "Para producir esto, necesitas una Piedra del[ENTER]Herrero. "
gameforge.upgrade_refine_scroll._220_sayItem = "Piedra del Herrero "
gameforge.upgrade_refine_scroll._230_say = "Para producirlo, necesitas un Pergamino[ENTER]Bendici\243n.  "
gameforge.upgrade_refine_scroll._240_say = "\191Tienes todos los objetos necesarios? Entonces,[ENTER]\191quieres quie haga el manual traspasado en mi[ENTER]familia de generaci\243n en generaci\243n? "
gameforge.upgrade_refine_scroll._250_say = "\161He creado un Manual del Herrero para ti![ENTER]Ahora dispones del conocimiento antiguo de la[ENTER]dinast\237a de los herreros. \161\218salo con sensatez![ENTER]\161Ja, ja, ja! "
gameforge.upgrade_refine_scroll._260_sayItem = "Manual de los Smithery "
gameforge.upgrade_refine_scroll._270_say = "No puedo producirte el Manual del Herrero porque[ENTER]no tienes todos los materiales necesarios. "
gameforge.upgrade_refine_scroll._30_say = "Para producir estos, necesitas Hierro S\243lido. "
gameforge.upgrade_refine_scroll._40_sayItem = "Hierro s\243lido "
gameforge.upgrade_refine_scroll._50_say = "Adem\225s, necesitas un Pergamino Bendici\243n. "
gameforge.upgrade_refine_scroll._60_sayItem = "Pergamino Bendici\243n "
gameforge.upgrade_refine_scroll._70_say = "\191Tienes todos los objetos necesarios? Todav\237a[ENTER]necesitas otros 200.000 Yang. Si tienes un[ENTER]Pergamino Bendici\243n, algo de Mineral de Cobre[ENTER]M\225gico y 200.000 Yang puedes crear un Pergamino[ENTER]de la Guerra. \191Quieres crear un pergamino? "
gameforge.upgrade_refine_scroll._80_say = "\161Has creado un pergamino! \161Es realmente m\225s f\225cil[ENTER]producir un pergamino del Dios de la Guerra si[ENTER]tienes hierro s\243lido! \161Me gusta! \161Ja, ja, ja! "
gameforge.upgrade_refine_scroll._90_sayItem = "Pergamino de la Guerra "
gameforge.warehouse = {}
gameforge.warehouse._100_say = "\161Bienvenido! \191Sabes para qu\233 sirven las barras de[ENTER]oro? Si llevas Yang contigo, es como decir: \161por[ENTER]favor, m\225tame! Por eso yo le cambio a la gente[ENTER]Yang por barras de oro y las almaceno para ellos. "
gameforge.warehouse._10_npcChat = "Quiero utilizar el almac\233n. "
gameforge.warehouse._110_say = "Bueno, pido m\225s de lo que cuesta una barra de[ENTER]oro. Pero sigue siendo justo, \191no? No hay raz\243n[ENTER]para sentirse enga\241ado. Como sabes, es muy[ENTER]peligroso ah\237 fuera. "
gameforge.warehouse._120_npcChat = "Abrir tienda de art\237culos "
gameforge.warehouse._130_say = "Mmm...[ENTER]Todas las minas est\225n vac\237as.[ENTER]Es dif\237cil encontrar oro o plata.[ENTER]Mientras no se encuentre un nuevo fil\243n, no habr\225[ENTER]m\225s barras de oro o plata. "
gameforge.warehouse._140_say = "\161Bienvenido! \191Quieres ver el almac\233n de tu tienda[ENTER]de objetos? Hmm.. \191y por qu\233 vienes a verme a m\237?[ENTER]Dale una mirada a tu in inventario, all\237[ENTER]encontrar\225s un acceso directo. "
gameforge.warehouse._150_say = "Haciendo clic en este s\237mbolo podr\225s acceder al[ENTER]almac\233n de tu tienda de objetos en todo lugar y[ENTER]en todo momento. La contrase\241a es 000000, a no[ENTER]ser que la hayas cambiado. "
gameforge.warehouse._20_sayTitle = "Encargado del almac\233n: "
gameforge.warehouse._30_say = "\191Quieres usar el almac\233n?[ENTER]Tienes que pagar Yang para usar el almacen..[ENTER]Hoy estoy de buen humor - puedes usarlo por tan[ENTER]s\243lo 500 Yang.[ENTER]Entonces - \161Vamos! Es barato, \191no? Jeje. "
gameforge.warehouse._40_say = "\191Qu\233? \191No tienes suficiente Yang?[ENTER]Vuelve cuando tengas suficiente. "
gameforge.warehouse._50_say = "Tu almac\233n est\225 abierto ahora.[ENTER]Si quieres usarlo, simplemente d\237melo.[ENTER]La contrase\241a para tu almac\233n es: "
gameforge.warehouse._60_sayReward = "000000 "
gameforge.warehouse._70_say = "Deber\237as cambiarla por razones de seguridad.[ENTER][ENTER]A lo mejor piensas que 45 espacios no son[ENTER]suficientes. Pero, qui\233n sabe, quiz\225 te de m\225s[ENTER]espacio si nos llevamos bien.  "
gameforge.warehouse._80_say = "Bien, yo no quiero obligar a nadie. Si ahora no[ENTER]te apetece, vuelve m\225s tarde. "
gameforge.warehouse._90_npcChat = "Abrir Almac\233n "
